type TreeNode struct {
	val   int
	left  *TreeNode
	right *TreeNode
}

func postOrder(root *TreeNode) []int {
	if root == nil {
		return []int{}
	}

	stack := []*TreeNode{root}
	var result []int

	for len(stack) > 0 {
		node := stack[len(stack)-1]
		stack = stack[:len(stack)-1]
		result = append(result, node.val)

		if node.left != nil {
			stack = append(stack, node.left)
		}
		if node.right != nil {
			stack = append(stack, node.right)
		}
	}

	for i, j := 0, len(result)-1; i < j; i, j = i+1, j-1 {
		result[i], result[j] = result[j], result[i]
	}

	return result
}

func main() {
	tree1 := &TreeNode{1, &TreeNode{2, &TreeNode{4, nil, nil}, &TreeNode{5, nil, nil}}, &TreeNode{3, nil, nil}}
	result1 := postOrder(tree1)
	for _, v := range result1 {
		print(v, " ")
	}

	tree2 := &TreeNode{8, &TreeNode{1, nil, &TreeNode{7, &TreeNode{10, nil, nil}, nil}}, &TreeNode{5, &TreeNode{10, &TreeNode{6, nil, nil}, nil}, &TreeNode{6, nil, nil}}}
	result2 := postOrder(tree2)
	for _, v := range result2 {
		print(v, " ")
	}
}

