func calculateMaximumsCount(rawOneElementArray []string) int {
	if len(rawOneElementArray) == 0 {
		return 0
	}
	parts := make([]int, 2)
	for i, v := range rawOneElementArray[0] {
		parts[i], _ = strconv.Atoi(string(v))
	}
	currentArray := make([]int, len(rawOneElementArray[1]))
	for i, v := range rawOneElementArray[1] {
		currentArray[i], _ = strconv.Atoi(string(v))
	}
	count := 0
	for _, max := range maximums(currentArray) {
		if max > parts[1] {
			count++
		}
	}
	return count
}

