func main() {
    var n int
    fmt.Scan(&n)

    coordinates := make([]int, n)
    heights := make([]int, n)

    for i := 0; i < n; i++ {
        fmt.Scan(&coordinates[i])
    }
    for i := 0; i < n; i++ {
        fmt.Scan(&heights[i])
    }

    trees := make([]struct{ x, h int }, n)
    for i := 0; i < n; i++ {
        trees[i] = struct{ x, h int }{coordinates[i], heights[i]}
    }

    for i := 1; i < n; i++ {
        key := trees[i]
        j := i - 1
        for j >= 0 && trees[j].x > key.x {
            trees[j+1] = trees[j]
            j--
        }
        trees[j+1] = key
    }

    maxFallingCapacity := 0
    currentCapacity := 0

    for _, tree := range trees {
        newCapacity := currentCapacity + tree.h
        if newCapacity > maxFallingCapacity {
            maxFallingCapacity = newCapacity
        }
        currentCapacity = newCapacity
    }

    fmt.Println(maxFallingCapacity)
}

