func main() {
	var n, S int
	fmt.Scan(&n, &S)
	a := make([]int, n)
	for i := 0; i < n; i++ {
		fmt.Scan(&a[i])
	}

	items := make([][2]int, n)
	for i := 0; i < n; i++ {
		items[i] = [2]int{a[i], i + 1}
	}
	sort.Slice(items, func(i, j int) bool {
		return items[i][0] < items[j][0]
	})

	bestK, bestCost := 0, 0
	currentCost := 0

	for k := 1; k <= n; k++ {
		totalCost := currentCost
		for j := n - k; j < n; j++ {
			totalCost += items[j][0] + items[j][1]*k
		}
		if totalCost <= S {
			bestK, bestCost = k, totalCost
		}
		currentCost += items[k-1][0] + items[k-1][1]
	}

	fmt.Println(bestK, bestCost)
}

