    fmt.Scan(&n, &m)
    steps := []int{}
    i := m
    for {
        if i > n {
            break
        }
        steps = append(steps, i%10)
        i += m
        if contains(steps, i%10) {
            break
        }
    }
    steps = steps[:index(steps, i%10)]
    l := len(steps)
    sumSteps := sum(steps)
