func findRange(s string, n int) []int {
	maxOnes, maxOnesIdx, ones := 0, -1, 0

	for i := 0; i < n; i++ {
		if s[i] == '1' {
			ones++
		} else {
			if ones > maxOnes {
				maxOnes = ones
				maxOnesIdx = i
			}
			ones = 0
		}
	}
	if ones > maxOnes {
		maxOnes = ones
		maxOnesIdx = n
	}

	if maxOnes == 0 {
		return []int{-1}
	}
	return []int{maxOnesIdx - maxOnes + 1, maxOnesIdx}
}

