type Point struct {
	x, y, val int
}

func dist(p1, p2 Point) int {
	ret := 0
	if p1.x > p2.x {
		ret += p1.x - p2.x
	} else if p1.x < p2.x {
		ret += p2.x - p1.x
	}
	if p1.y > p2.y {
		ret += p1.y - p2.y
	} else if p1.y < p2.y {
		ret += p2.y - p1.y
	}
	return ret
}

func threat(points []Point, n, m, K int) float64 {
	if K == 0 {
		return math.Inf(1)
	}
	if K == 1 {
		return math.Max(0, float64(dist(points[0], Point{n, m, 0})))
	}

	mInf := math.Inf(1)
	for i := 0; i < K; i++ {
		for j := i + 1; j < K; j++ {
			d := dist(points[i], points[j])
			minTh := []float64{mInf, mInf, mInf, mInf}
			for _, cc := range [][2]int{{i + 1, j}, {i - 1, j}, {i, j + 1}, {i, j - 1}} {
				if cc[0] >= 0 && cc[0] < K && cc[1] >= 0 && cc[1] < K && points[cc[0]].val < points[cc[1]].val {
					kappa := float64(points[cc[0]].val)
					delta := float64(points[cc[1]].val) - kappa + float64(d)
					Tz := delta / kappa
					S1 := delta/kappa + float64(dist(points[i], Point{(int(float64(points[cc[1]].x) + Tz)), 0, 0}))
					S2 := delta/kappa + float64(dist(points[i], Point{(int(float64(points[cc[1]].x) - Tz)), m, 0}))
					S := math.Min(S1, S2)
					minTh = append(minTh, S)
				}
			}
		}
	}
	return mInf
}

func main() {
	var K int
	var n, m int
	fmt.Scan(&K)
	points := make([]Point, K)
	for i := 0; i < K; i++ {
		var x, y, val int
		fmt.Scan(&x, &y, &val)
		points[i] = Point{x, y, val}
	}

	sort.Slice(points, func(i, j int) bool {
		return points[i].x*int(N) + points[i].y < points[j].x*int(N) + points[j].y
	})

	result := threat(points, n, m, K)
	fmt.Println(result)
}

