func funcTransform(a uint32) uint32 {
	v := (a ^ 0x55555555) & 0xAAAAAAAA
	t := (a & 0xAAAAAAAA) ^ (v >> 1)
	u := (v ^ 0xAAAAAAAA) & 0x55555555
	return (((a & 0x55555555) ^ (u << 1)) | t)
}

func main() {
	var t int
	fmt.Scan(&t)
	for i := 0; i < t; i++ {
		var n int
		fmt.Scan(&n)

		var aStr, bStr string
		fmt.Scan(&aStr, &bStr)

		a, _ := strconv.ParseUint(aStr, 2, 32)
		b, _ := strconv.ParseUint(bStr, 2, 32)

		var l, r uint32
		if a > b {
			l = uint32(b)
			r = uint32(a)
		} else {
			l = uint32(a)
			r = uint32(b)
		}
		cnt := 0

		for l != r {
			if l & 1 == 1 {
				if (r >> 1) > (l >> 1) {
					l = (funcTransform(l) >> 1) << 1
					cnt += 4
				} else {
					for r % 2 == 1 {
						c := l % 32
						cnt += int(c)
						l ^= ^(1 << c)
						c = r % 32
						cnt += int(c)
						r ^= ^(1 << c)
					}
					l >>= 1
					r >>= 1
				}
			} else {
				l >>= 1
				r >>= 1
			}
		}
	}
}

