		for _, v := range gb {
			visited[v[0]+v[1]*n] = struct{}{}
		}

		toQueue := make([]int, 0, len(visited))
		for i := 0; i < n; i++ {
			if _, exists := visited[i]; exists {
				toQueue = append(toQueue, i)
			}
