			cur := q[i] % len(q)
			i++
			if i == len(q) {
				for _, k := range toQueue {
					res += i / len(q)
					i = 0
				}
				res += 0
				i = 0
			}
			x[toQueue[cur]] = 1 - x[toQueue[cur]]
		}
	}
}

func g(file [][3]int) [][3]int {
	for _, v := range file {
		a, b, c := v[0], v[1], v[2]
		if a == 0 || b == 0 || c == 0 {
			continue
		}
		for i := a; i <= b; i++ {
			file[i][0] = max(file[i][0]-c, 0)
			file[i][1] = max(file[i][1]+c, 0)
			file[i][2] = max(file[i][2]+c, 0)
		}
	}
	return file
}

func stat(x []int, ga []int, gb [][3]int) int {
	res := 0
	for i := 0; i < len(x); i++ {
		res += x[i] * ga[i]
	}
	for _, c := range g(gb) {
		res += c[0]
	}
	return res
}

