func solveBlocks(blocks []int) int {
	n := len(blocks)
	if n == 0 {
		return 0
	}

	cost := make([]int, n)
	cost[0] = 0

	for i := 1; i < n; i++ {
		minCost := math.MaxInt32
		for j := i - 1; j >= 0; j-- {
			if blocks[j] >= blocks[i] {
				cost[i] = min(cost[i], cost[j]+blocks[i]*(i-j))
				break
			}
			minCost = min(minCost, cost[j]+blocks[i]*(i-j))
		}
		cost[i] = min(cost[i], minCost)
		if minCost != math.MaxInt32 {
			cost[i] = min(cost[i], minCost)
		}
	}

	return cost[n-1]
}

