func dfs(i, j int, temp []int, words []string, puzzle string, ans *[][]int, count *int) {
	if j == len(puzzle) {
		*ans = append(*ans, append([]int(nil), temp...))
		return
	}
	if i == len(words) {
		return
	}
	if puzzle[j] == words[i][0] {
		temp = append(temp, i)
		dfs(i+1, j+1, temp, words, puzzle, ans, count)
		temp = temp[:len(temp)-1]
		dfs(i+1, j, temp, words, puzzle, ans, count)
	} else {
		dfs(i+1, j, temp, words, puzzle, ans, count)
	}
}

func findWords(words []string, puzzles []string) []int {
	ans := make([]int, len(puzzles))
	for i, puzzle := range puzzles {
		sort.Slice([]rune(puzzle), func(a, b int) bool {
			return puzzle[a] < puzzle[b]
		})
		count := 0
		for _, word := range words {
			if len(word) >= 2 {
				temp := []int{}
				if word[0] == puzzle[0] {
					ansTemp := [][]int{}
					dfs(0, 1, temp, words, puzzle, &ansTemp, &count)
				}
			}
		}
		ans[i] = count
	}
	return ans
}

