func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var n, m, s int
	fmt.Fscanf(reader, "%d %d %d\n", &n, &m, &s)

	graph := make([][]int, n+1)
	undirectedEdges := []Edge{}

	for i := 0; i < m; i++ {
		var t, u, v int
		fmt.Fscanf(reader, "%d %d %d\n", &t, &u, &v)
		if t == 1 {
			graph[u] = append(graph[u], v)
		} else {
			graph[u] = append(graph[u], v)
			graph[v] = append(graph[v], u)
			undirectedEdges = append(undirectedEdges, Edge{u, v, false})
		}
	}

	maxReachable := calculateReachable(graph, s)
	orientationMax := orientUndirectedEdges(undirectedEdges, graph, s, true)

	minReachable := calculateReachable(graph, s)
	orientationMin := orientUndirectedEdges(undirectedEdges, graph, s, false)

	fmt.Fprintln(writer, maxReachable)
	for _, edge := range orientationMax {
		fmt.Fprintf(writer, "%d %d\n", edge.u, edge.v)
	}

	fmt.Fprintln(writer, minReachable)
	for _, edge := range orientationMin {
		fmt.Fprintf(writer, "%d %d\n", edge.u, edge.v)
	}
}

func calculateReachable(graph [][]int, start int) int {
	reachable := make([]bool, len(graph))
	dfs(graph, start, reachable)
	count := 0
	for _, r := range reachable {
		if r {
			count++
		}
	}
	return count
}

func dfs(graph [][]int, node int, reachable []bool) {
	reachable[node] = true
	for _, neighbor := range graph[node] {
		if !reachable[neighbor] {
			dfs(graph, neighbor, reachable)
		}
	}
}

func orientUndirectedEdges(edges []Edge, graph [][]int, start int, maximize bool) []Edge {
	reachable := make([]bool, len(graph))
	dfs(graph, start, reachable)
	var result []Edge

	for _, edge := range edges {
		if maximize {
			if reachable[edge.u] && !reachable[edge.v] {
				result = append(result, Edge{edge.u, edge.v, true})
				graph[edge.u] = append(graph[edge.u], edge.v)
			} else {
				result = append(result, Edge{edge.v, edge.u, true})
				graph[edge.v] = append(graph[edge.v], edge.u)
			}
		} else {
			if reachable[edge.v] && !reachable[edge.u] {
				result = append(result, Edge{edge.v, edge.u, true})
				graph[edge.v] = append(graph[edge.v], edge.u)
			} else {
				result = append(result, Edge{edge.u, edge.v, true})
				graph[edge.u] = append(graph[edge.u], edge.v)
			}
		}
	}
	return result
}

