package main

type Node struct {
	val       int
	nextNode  []*Node
}

func NewNode(value int) *Node {
	return &Node{val: value, nextNode: []*Node{}}
}

func (n *Node) setIdx(idx int, val int) {
	if idx == 0 {
		n.val = val
	} else {
		if idx >= len(n.nextNode) {
			n.nextNode = append(n.nextNode, NewNode(0))
			n.nextNode[idx-1].setIdx(idx-1, val)
		} else {
			n.nextNode[idx-1].setIdx(idx-1, val)
		}
	}
}

func (n *Node) getI(idx int) int {
	if idx == 0 {
		return n.val
	} else {
		var elem int
		if idx >= len(n.nextNode) {
			elem = 0
		} else if idx <= len(n.nextNode) {
			val := n.nextNode[idx-1].getI(idx - 1)
			elem = (val + n.val) % 1000
		} else {
			return -1
		}
		return elem
	}
}

func (n *Node) setTop(val int) {
	n.nextNode[len(n.nextNode)-1].setIdx(len(n.nextNode), val)
}

type Cell struct {
	nodes []Node
	size  int
}

func NewCell(numRows int, numColumns int) *Cell {
	size := max(numRows, numColumns) * 2
	nodes := make([]Node, 1)
	nodes[0] = *NewNode(0)
	for i := range nodes {
		nodes[i].nextNode = make([]*Node, max(1, size))
		for j := range nodes[i].nextNode {
			nodes[i].nextNode[j] = NewNode(0)
		}
	}
	return &Cell{nodes: nodes, size: size}
}

func (c *Cell) push(val int) {
	if len(c.nodes) > c.size-1 {
		return
	}
	c.nodes[len(c.nodes)-1].setIdx(len(c.nodes[len(c.nodes)-1].nextNode)+1, val)
}

func (c *Cell) pop() int {
	if len(c.nodes) < 1 {
		return -1
	}
	topNode := &c.nodes[len(c.nodes)-1]
	topVal := topNode.getI(1)
	topNode.nextNode = topNode.nextNode[:len(topNode.nextNode)-1]
	return topVal
}

func (c *Cell) inc(x int, k int, val int) {
	if len(c.nodes) > c.size-1 {
		return
	}
	if x > len(c.nodes) || k > len(c.nodes) {
		return
	}
	var topNextNodes []*Node
	topNextNodes = append(topNextNodes, NewNode(0))

	if x < len(c.nodes) {
		for i := 0; i < k; i++ {
			leftMinusOne := topNextNodes[len(topNextNodes)-1].getI(1) - val
			if leftMinusOne < 0 {
				topNextNodes[0].setIdx(i, leftMinusOne)
				for j := 0; j < k-1; j++ {
					topNextNodes[len(topNextNodes)-1].setIdx(i+j+1, topNextNodes[j].getI(i+j))
				}
				topNextNodes[0].nextNode = topNextNodes
				break
			} else {
				topNextNodes[0].setIdx(i, leftMinusOne)
				elem := 0
				for j := 0; j < k-1; j++ {
					topNextNodes[len(topNextNodes)-1].setIdx(i+j+1, topNextNodes[j].getI(i+j))
					elem += topNextNodes[j].getI(i+j)
				}
				elem %= 1000
				topNextNodes[0].nextNode = topNextNodes
				topNextNodes[0].setIdx(len(topNextNodes), elem)
			}
		}
		c.nodes[len(c.nodes)-1] = *topNextNodes[0]
	}
}

