func solve(n, m, k int, edges [][]int) int {
	graph := make([][][]int, n)
	for _, edge := range edges {
		u, v, w, t := edge[0], edge[1], edge[2], edge[3]
		graph[u] = append(graph[u], []int{v, w, t})
		graph[v] = append(graph[v], []int{u, w, t})
	}

	dijkstra := func(src int) int {
		dist := make([][]int, n)
		for i := range dist {
			dist[i] = make([]int, k+1)
			for j := 0; j <= k; j++ {
				dist[i][j] = int(^uint(0) >> 1) // max int
			}
		}
		dist[src][k] = 0
		pq := &PriorityQueue{}
		heap.Push(pq, &Item{value: 0, node: src, tickets: k})

		for pq.Len() > 0 {
			item := heap.Pop(pq).(*Item)
			d, u, tickets := item.value, item.node, item.tickets

			if u == n-1 {
				return d
			}
			if d > dist[u][tickets] {
				continue
			}
			for _, neighbor := range graph[u] {
				v, w, t := neighbor[0], neighbor[1], neighbor[2]
				if tickets > 0 {
					alt := d + w - t
					if alt < dist[v][tickets-1] {
						dist[v][tickets-1] = alt
						heap.Push(pq, &Item{value: alt, node: v, tickets: tickets - 1})
					}
				}
				alt = d + w
				if alt < dist[v][tickets] {
					dist[v][tickets] = alt
					heap.Push(pq, &Item{value: alt, node: v, tickets: tickets})
				}
			}
		}
		return -1
	}

	return dijkstra(0)
}

type Item struct {
	value   int
	node    int
	tickets int
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int {
	return len(pq)
}

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].value < pq[j].value
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

