}

func eventualSafeNodes(graph [][]int) []int {
    N := len(graph)
    states := make([]int, N) // 0 = unvisited, 1 = visiting, 2 = safe, 3 = unsafe

    var dfs func(int) bool
    dfs = func(u int) bool {
        if states[u] == 2 {
            return true
        }
        if states[u] == 3 {
            return false
        }
        if states[u] == 1 {
            return false // detected cycle
        }

        states[u] = 1 // mark as visiting
        for _, v := range graph[u] {
            if !dfs(v) {
                states[u] = 3 // mark as unsafe
                return false
            }
        }

        states[u] = 2 // mark as safe
        return true
    }

    for i := 0; i < N; i++ {
        if states[i] == 0 { // unvisited
            dfs(i)
        }
    }

    safeNodes := []int{}
    for i := 0; i < N; i++ {
        if states[i] == 2 {
            safeNodes = append(safeNodes, i)
        }
    }
    return safeNodes
}

