func longestConsecutive(nums []int) int {
    numMap := make(map[int]int)
    numSet := make(map[int]struct{})

    longest := 0
    for _, num := range nums {
        numMap[num] = 0
        numSet[num] = struct{}{}
    }

    for _, num := range nums {
        if numMap[num] == 0 {
            longest = max(longest, dfs(numMap, numSet, num))
        }
    }

    return longest
}

func dfs(numMap map[int]int, numSet map[int]struct{}, x int) int {
    if _, exists := numMap[x]; !exists {
        return 0
    }

    if numMap[x] != 0 {
        return numMap[x]
    }

    left, right := 0, 0

    if _, exists := numSet[x-1]; exists {
        left = dfs(numMap, numSet, x-1)
    }

    if _, exists := numSet[x+1]; exists {
        right = dfs(numMap, numSet, x+1)
    }

    delete(numSet, x)

    consecutive := left + right + 1
    numMap[x] = consecutive

    return consecutive
}

