	table := make([][]int, n)
	for i := range table {
		table[i] = make([]int, n)
		for j := range table[i] {
			table[i][j] = 1
		}
	}
	for i := 1; i < n; i++ {
		for j := 1; j < n; j++ {
			table[i][j] = table[i-1][j] + table[i][j-1]
		}
	}
	maxVal := 0
	for _, row := range table {
		for _, val := range row {
			if val > maxVal {
				maxVal = val
			}
		}
	}
	return maxVal
}

