func rangeBitwiseOr(N int, L int, R int) int {
    mask := (1 << R) - 1 // Create a mask with bits from 0 to R set to 1

    // Set the bits from L to R in N
    return N | (mask ^ ((1 << (L - 1)) - 1))
}

