func minRepeats(A string, B string) int {
    sizeA := len(A)
    sizeB := len(B)
    times := sizeB/sizeA + 1

    for i := 0; i < times; i++ {
        repeated := A
        for j := 0; j < i+1; j++ {
            repeated += A
        }
        if len(repeated) >= sizeB && repeated[:sizeB] == B {
            return i + 1
        }
    }
    return -1
}

func main() {
    fmt.Println(minRepeats("abcd", "cdabcdab")) // Output: 3
    fmt.Println(minRepeats("ab", "cab"))        // Output: -1
}

