func splitByStep(s string, step int) []string {
    words := []string{}
    for i := 0; i < len(s); i += step {
        words = append(words, string(s[i]))
    }
    return words
}

func isUnique(d []string) bool {
    seen := make(map[string]struct{})
    for _, word := range d {
        if _, exists := seen[word]; exists {
            return false
        }
        seen[word] = struct{}{}
    }
    return true
}

func hasSingleCharacter(word string) bool {
    firstChar := word[0]
    for i := 1; i < len(word); i++ {
        if word[i] != firstChar {
            return false
        }
    }
    return true
}

func areAdjacentDifferent(d []string) bool {
    for i := 0; i < len(d)-1; i++ {
        if d[i] == d[i+1] {
            return false
        }
    }
    return true
}

func totalFruit(tree []int) int {
    windowStart := 0
    maxLength := 0
    fruitCount := make(map[int]int)

    for windowEnd := 0; windowEnd < len(tree); windowEnd++ {
        rightFruit := tree[windowEnd]
        fruitCount[rightFruit]++

        for len(fruitCount) > 2 {
            leftFruit := tree[windowStart]
            fruitCount[leftFruit]--
            if fruitCount[leftFruit] == 0 {
                delete(fruitCount, leftFruit)
            }
            windowStart++
        }
        if currentLength := windowEnd - windowStart + 1; currentLength > maxLength {
            maxLength = currentLength
        }
    }

    return maxLength
}

func maxKForSortPermutation(testCases []struct {
	n          int
	permutation []int
}) []int {
	results := make([]int, len(testCases))
	for idx, testCase := range testCases {
		n := testCase.n
		permutation := testCase.permutation
		k := 1
		for k < n && hasGreater(permutation, k, n) {
			k++
		}
		results[idx] = k - 1
	}
	return results
}

func hasGreater(permutation []int, k, n int) bool {
	for i := 0; i < n-k; i++ {
		if permutation[i] > permutation[i+k] {
			return true
		}
	}
	return false
}

// Example usage
func main() {
	testCases := []struct {
		n          int
		permutation []int
	}{
		{4, []int{4, 2, 3, 1}},
		{5, []int{1, 4, 3, 2, 5}},
		{2, []int{2, 1}},
	}
	results := maxKForSortPermutation(testCases)
	for _, res := range results {
		fmt.Println(res)
	}
}

