		parent: make([]int, size),
		rank:   make([]int, size),
	}
	for i := 0; i < size; i++ {
		uf.parent[i] = i
		uf.rank[i] = 1
	}
	return uf
}

func (uf *UnionFind) Find(node int) int {
	if uf.parent[node] != node {
		uf.parent[node] = uf.Find(uf.parent[node]) // Path compression
	}
	return uf.parent[node]
}

func (uf *UnionFind) Union(node1, node2 int) {
	root1 := uf.Find(node1)
	root2 := uf.Find(node2)

	if root1 != root2 {
		if uf.rank[root1] > uf.rank[root2] {
			uf.parent[root2] = root1
		} else if uf.rank[root1] < uf.rank[root2] {
			uf.parent[root1] = root2
		} else {
			uf.parent[root2] = root1
			uf.rank[root1]++
		}
	}
}

func main() {
	var n, m int
	reader := bufio.NewReader(os.Stdin)
	fmt.Scan(&n, &m)

	edges := make(map[int][][]int)

	for i := 0; i < m; i++ {
		var a, b, c int
		fmt.Fscanf(reader, "%d %d %d", &a, &b, &c)
		edges[c] = append(edges[c], []int{a - 1, b - 1}) // Store edges 0-indexed
	}

	var q int
	fmt.Scan(&q)
	queries := make([][2]int, q)

	for i := 0; i < q; i++ {
		var u, v int
		fmt.Fscanf(reader, "%d %d", &u, &v)
		queries[i] = [2]int{u - 1, v - 1} // Store queries 0-indexed
	}

	for _, query := range queries {
		u, v := query[0], query[1]
		count := 0

		for _, colorEdges := range edges {
			uf := NewUnionFind(n)
			for _, edge := range colorEdges {
				uf.Union(edge[0], edge[1])
			}
			if uf.Find(u) == uf.Find(v) {
				count++
			}
		}
		fmt.Println(count)
	}
}

