func spheresContact(a1, a2, pos1, pos2, r1, r2 [3]float64) bool {
	relativePos := [3]float64{pos2[0] - pos1[0], pos2[1] - pos1[1], pos2[2] - pos1[2]}
	relativeAcc := [3]float64{a2[0] - a1[0], a2[1] - a1[1], a2[2] - a1[2]}

	A := relativeAcc[0]*relativeAcc[0] + relativeAcc[1]*relativeAcc[1] + relativeAcc[2]*relativeAcc[2]

	B := 2 * (relativePos[0]*relativeAcc[0] + relativePos[1]*relativeAcc[1] + relativePos[2]*relativeAcc[2])

	C := relativePos[0]*relativePos[0] + relativePos[1]*relativePos[1] + relativePos[2]*relativePos[2] - (r1+r2)*(r1+r2)

	if A == 0 {
		return B == 0 && C <= 0
	}

	discriminant := B*B - 4*A*C

	return discriminant >= 0
}

