func getStrongest(arr []int, k int) []int {
    sort.Ints(arr)
    n := len(arr)

    if n == 1 {
        return []int{arr[0]}
    }

    m := arr[(n-1)/2]

    customSort := func(i, j int) bool {
        absI := abs(arr[i] - m)
        absJ := abs(arr[j] - m)
        if absI == absJ {
            return arr[i] > arr[j]
        }
        return absI > absJ
    }

    indices := make([]int, n)
    for i := range indices {
        indices[i] = i
    }

    sort.Slice(indices, customSort)

    result := make([]int, k)
    for i := 0; i < k; i++ {
        result[i] = arr[indices[i]]
    }

    return result
