func iceCreamDistributions(n int, x int, operations []string) (int, int) {
	distressedKids := 0

	for _, operation := range operations {
		parts := strings.Split(operation, " ")
		sign := parts[0]
		d, _ := strconv.Atoi(parts[1])

		if sign == "+" {
			x += d
		} else if sign == "-" {
			if x >= d {
				x -= d
			} else {
				distressedKids++
			}
		}
	}

	return x, distressedKids
}

