            } else {
                newVictims = append(updatedVictims[:2], updatedVictims[3:]...)
            }
        }

        killerStrategy = append(killerStrategy, []string{updatedVictims[0], updatedVictims[1]})
        currentVictims = newVictims
    }

    killerStrategy = append(killerStrategy, findNextVictims(currentVictims))

    for _, victims := range killerStrategy {
        fmt.Println(victims[0], victims[1])
    }
