func step(q []int, ans []int) ([]int, error) {
	if len(q) == 0 {
		return ans, nil
	}
	n := q[0]
	q = q[1:]
	fin := []int{n}
	ml := len(fin)

	if len(ans) > 0 && n <= max(ans) {
		return ans, nil
	}

	nl := make([]int, len(q))
	for i, v := range q {
		nl[i] = v
	}
	sort.Ints(nl)

	for z := 0; z < len(q); z++ {
		sdt := 0
		for bs := 0; bs < len(fin); bs++ {
			sdt = abs(fin[bs] - fin[len(fin)-1])
			nmb := abs(nl[z] - nl[bs])
			if sdt == nmb {
				ans = nil
				return append(ans, nlIndex(q[z])+1, bs+1), nil
			} else if abs(sdt-nl[z]) < abs(sdt-nl[bs]) {
				return nil, nil
			}
		}
		fin = append(fin, q[z])
		ans, err := step(q[ml:], fin)
		if err != nil {
			return nil, err
		}
	}
	return ans, nil
}

