func minThrows(N, M, K int) int {
	if K == 0 {
		return -1
	}
	for i := N % M; i < N; i += K {
		if (N-i)%M == 0 {
			if (N%M)%K != 0 {
				return (N % M) / K + 1
			}
			return (N % M) / K
		}
	}
	return -1
}

func main() {
	var T int
	fmt.Scan(&T)
	results := make([]int, T)
	for i := 0; i < T; i++ {
		var N, M, K int
		fmt.Scan(&N, &M, &K)
		results[i] = minThrows(N, M, K)
	}
	for _, result := range results {
		fmt.Println(result)
	}
}

