func solution(s string) bool {
	if len(s)%2 != 0 {
		mid := len(s) / 2
		s = s[:mid] + "1" + s[mid+1:]
	}

	for len(s) > 0 {
		if len(s) < 2 {
			return false
		}
		if s[0] == s[1] || s[0] == s[len(s)-1] || s[len(s)-2] == s[len(s)-1] {
			s = s[2:] + s[:2]
		} else {
			return false
		}
	}
	return true
}

func cleoRoof(n int, a []int) int {
	i := 0
	for sumSlice(a[i:]) >= i+1 {
		added := 0
		j := 1
		for j+i < len(a) && sumSlice(a[i:i+j+1]) >= j+1+i {
			added++
			j++
		}
		i += added
	}
	return i
}

func sumSlice(slice []int) int {
	sum := 0
	for _, value := range slice {
		sum += value
	}
	return sum
}

func maxSquareSide(lengths []int) int {
	totalLength := sumSlice(lengths)
	maxSide := int(math.Sqrt(float64(totalLength)))

	if maxSide*maxSide == totalLength {
		return maxSide
	}

	for maxSide > 0 {
		squareArea := maxSide * maxSide
		if squareArea <= totalLength {
			return maxSide
		}
		maxSide--
	}
	return 0
}

func main() {
