	fmt.Scan(&k)
	for i := 0; i < k; i++ {
		var n int
		fmt.Scan(&n)
		a := make([]int, n)
		for j := 0; j < n; j++ {
			fmt.Scan(&a[j])
		}
		fmt.Println(maxSquareSide(a))
	}
}

