func exploreHorizontalRight(a [][]rune, i, j, n, k int, visited map[[2]int]bool, isFilled bool) bool {
	if j >= n || (!isFilled && a[i][j] != '.') || (a[i][j] != 'X' && isFilled) || visited[[2]int{i, j}] {
		return false
	}
	if j == k-1 {
		return true
	}
	visited[[2]int{i, j}] = true
	return exploreHorizontalRight(a, i, j+1, n, k, visited, isFilled)
}

func exploreHorizontalLeft(a [][]rune, i, j, n, k int, visited map[[2]int]bool, isFilled bool) bool {
	if j < 0 || (!isFilled && a[i][j] != '.') || (a[i][j] != 'X' && isFilled) || visited[[2]int{i, j}] {
		return false
	}
	if j == n-k {
		return true
	}
	visited[[2]int{i, j}] = true
	return exploreHorizontalLeft(a, i, j-1, n, k, visited, isFilled)
}

func exploreVerticalDown(a [][]rune, i, j, n, k int, visited map[[2]int]bool, isFilled bool) bool {
	if i >= n || (!isFilled && a[i][j] != '.') || (a[i][j] != 'X' && isFilled) || visited[[2]int{i, j}] {
