		return true
	}
	visited[[2]int{i, j}] = true
	return exploreVerticalDown(a, i+1, j, n, k, visited, isFilled)
}

func exploreVerticalUp(a [][]rune, i, j, n, k int, visited map[[2]int]bool, isFilled bool) bool {
