func nextRank(participants []int, kthPlaceFinishers int) (int, error) {
	kFinisherIdx := -1
	for idx, score := range participants {
		if idx+1 == kthPlaceFinishers {
			kFinisherIdx = idx
		}
	}
	if kFinisherIdx == -1 {
		return 0, fmt.Errorf("kth place finisher not found")
