func optimizeBF(bf string) string {
	patterns := []struct {
		pattern string
		repl    string
	}{
		{`[\+\-]+\$`, ""},
		{`<\-\$|^\-`, ""},
		{`\]((?=\])\1)+`, "]"},
		{`\[\d+\[\d+]\d+`, `[`},
	}

	for _, pat := range patterns {
		re := regexp.MustCompile(pat.pattern)
		bf = re.ReplaceAllString(bf, pat.repl)
	}
	return bf
}

