import "fmt"

func countWays(S1, S2 string) int {
	n, m := len(S1), len(S2)
	dp := make([][]int, n+1)
	for i := range dp {
		dp[i] = make([]int, m+1)
	}

	for i := 0; i <= n; i++ {
		for j := 0; j <= m; j++ {
			if i == 0 {
				dp[i][j] = 1
			} else if j == 0 {
				dp[i][j] = 0
			} else if S1[i-1] == S2[j-1] {
				dp[i][j] = dp[i-1][j-1] + dp[i-1][j]
			} else {
				dp[i][j] = dp[i-1][j]
			}
		}
	}
	return dp[n][m]
}

