func solve(n int, a []int) int {
    sort.Ints(a)
    l := make([]int, n+1)
    r := make([]int, n+1)

    for i := 0; i < n; i++ {
        l[i+1] = max(l[i], a[i])
    }

    for i := n - 1; i >= 0; i-- {
        r[i] = max(r[i+1], a[i])
    }

    res := 0
    for i := 0; i < n; i++ {
        res = max(res, l[i] + r[i+1])
    }

    return res * res
}

