func NumberOfPath(A, B int) int {
    dp := make([][]int, A+1)
    for i := range dp {
        dp[i] = make([]int, B+1)
    }
    dp[0][0] = 1

    for i := 1; i <= A; i++ {
        for j := 1; j <= B; j++ {
            dp[i][j] = dp[i-1][j] + dp[i][j-1]
        }
    }
    return dp[A][B]
}

func totalTime(n int, arr []int, penalty []int) int {
    time := 0
    seen := make(map[int]struct{})

    for i := 0; i < n; i++ {
        if _, ok := seen[arr[i]]; ok {
            time += penalty[arr[i]-1]
        } else {
            time++
            seen[arr[i]] = struct{}{}
        }
    }

    return time
}

func shortestPath(S string) string {
    stack := make([]rune, 0)
    opposites := map[rune]rune{'N': 'S', 'S': 'N', 'E': 'W', 'W': 'E'}

    for _, direction := range S {
        if len(stack) > 0 && stack[len(stack)-1] == opposites[direction] {
            stack = stack[:len(stack)-1]
        } else {
            stack = append(stack, direction)
        }
    }

    return string(sortStack(stack))
}

func sortStack(stack []rune) []rune {
    // Simple implementation of sort
    sort.Slice(stack, func(i, j int) bool {
        return stack[i] < stack[j]
    })
    return stack
}

func maxExpectedValue(N, K int, p []int) float64 {
    sort.Sort(sort.Reverse(sort.IntSlice(p)))
    maxSum, total := 0, 0

    for _, v := range p[:K] {
        total += v
    }

    maxSum = total

    for i := 1; i <= N-K; i++ {
        total += p[i+K-1] - p[i-1]
        if total > maxSum {
            maxSum = total
        }
    }

    return float64(maxSum) / float64(K)
}

func main() {
    var N, K int
    fmt.Scan(&N, &K)
    p := make([]int, N)

    for i := 0; i < N; i++ {
        fmt.Scan(&p[i])
    }

    result := maxExpectedValue(N, K, p)
    fmt.Printf("%.10f\n", result)
}

