type Tokenizer struct {
    str   string
    index int
}

func NewTokenizer(s string) *Tokenizer {
    return &Tokenizer{str: s, index: 0}
}

func (t *Tokenizer) readUntil(c byte) string {
    result := ""
    for t.index < len(t.str) && t.str[t.index] != c {
        result += string(t.str[t.index])
        t.index++
    }
    return result
}

func (t *Tokenizer) read(c byte) (byte, int) {
    char := t.str[t.index]
    return char, t.index + 1
}

func (t *Tokenizer) consumeRandom(length int) {
    for i := 0; i < length; i++ {
        t.read(' ')
    }
}

func (t *Tokenizer) readAbsX() (int, error) {
    i, _ := t.read('(')
    sign := 1
    if i == '-' {
        sign = -1
    }
    number := ""
    for {
        c, _ := t.read(')')
        if c == ')' {
            break
        }
        number += string(c)
    }
    var num int
    _, err := fmt.Sscanf(number, "%d", &num)
    if err != nil {
        return 0, fmt.Errorf("parse error at index %d", t.index-1)
    }
    return sign * num, nil
}

func (t *Tokenizer) readAbsY() (int, error) {
    i, _ := t.read('(')
    sign := 1
    if i == '-' {
        sign = -1
    }
    number := ""
    for {
        c, _ := t.read(')')
        if c == ')' {
            break
        }
        number += string(c)
    }
    var num int
    _, err := fmt.Sscanf(number, "%d", &num)
    if err != nil {
        return 0, fmt.Errorf("parse error at index %d", t.index-1)
    }
    return sign * num, nil
}

func (t *Tokenizer) readNodeTuple() (Tuple, error) {
    x, err := t.readAbsX()
    if err != nil {
        return Tuple{}, err
    }
    y, err := t.readAbsY()
    if err != nil {
        return Tuple{}, err
    }
    _, _ = t.read('(')
    _, _ = t.read('(')
    t.consumeRandom(3)
    power, err := t.readNodeTuple()
    if err != nil {
        return Tuple{}, err
    }
    return Tuple{x, y, power}, nil
}

func (t *Tokenizer) readFloor() (Floor, error) {
    _, _ = t.read('(')
    x, err := t.readAbsX()
    if err != nil {
        return Floor{}, err
    }
    y, err := t.readAbsY()
    if err != nil {
        return Floor{}, err
    }
    _, _ = t.read('(')
    _, _ = t.read('(')
    t.consumeRandom(3)
    node, err := t.readNodeTuple()
    if err != nil {
        return Floor{}, err
    }
    _, _ = t.read(')')
    _, _ = t.read(')')
    power, err := t.readNodeTuple()
    if err != nil {
        return Floor{}, err
    }
    return Floor{x, y, node, power}, nil
}

type Tuple struct {
    x, y   int
    power  Tuple
}

type Floor struct {
    x, y   int
    node   Tuple
    power  Tuple
}

