func calculateStrength(n int, q int, A []int, B []int, L_values []int, R_values []int) []int {
    sums := make([]int, n+1)
    for i := 1; i <= n; i++ {
        sums[i] = sums[i-1] + A[i-1]*B[i-1]
    }

    result := make([]int, q)
    for i := 0; i < q; i++ {
        l, r := L_values[i], R_values[i]
        if l > 1 {
            result[i] = sums[r] - sums[l-1]
        } else {
            result[i] = sums[r]
        }
    }

    return result
}

