package main

import (
	"fmt"
	"math"
)

const inf = 1001
const MAXN = 2018

func dist(a, b []int) float64 {
	return math.Sqrt(math.Pow(float64(a[0]-b[0]), 2) + math.Pow(float64(a[1]-b[1]), 2))
}

func leftSector(sum, yMin float64) float64 {
	return math.Sqrt(math.Pow(sum, 2) - math.Pow(yMin, 2))
}

func rightSector(sum, xMax float64) float64 {
	return math.Sqrt(math.Pow(sum, 2) - math.Pow(xMax, 2))
}

func checkSector(left, right, yMin float64) bool {
	return math.Sqrt(math.Pow(left, 2)+math.Pow(right, 2)) > yMin
}

func main() {
	var n, x1, y1, x2, y2 int
	fmt.Scan(&n, &x1, &y1, &x2, &y2)

	floors := make([][]int, n)
	for i := 0; i < n; i++ {
		floors[i] = make([]int, 2)
		fmt.Scan(&floors[i][0], &floors[i][1])
	}

	fi := make([]float64, n)
	se := make([]float64, n)

	for i := 0; i < n; i++ {
		fi[i] = dist([]int{x1, y1}, floors[i])
		se[i] = dist([]int{x2, y2}, floors[i])
	}

	yMin := math.Min(min(fi), min(se))
	xMax := math.Max(max(fi), max(se))

	f, b := xMax*xMax, -xMax*xMax
	ans := inf

	for f-b >= 1e-6 {
		m := (b + f) / 2
		left := leftSector(m, yMin)
		right := rightSector(m, xMax)

		if checkSector(left, right, yMin) {
			ans = m
			f = m
		} else {
			b = m
		}
	}

	fmt.Println(int(ans))
}

