	for i := 0; i < m; i++ {
		var u, v, w int
		fmt.Scan(&u, &v, &w)
		graph[u] = append(graph[u], Pair{v, w})
		graph[v] = append(graph[v], Pair{u, w})
	}

	start := 0
	dist := dijkstra(graph, start)
	for _, d := range dist {
		fmt.Println(d)
	}
}

func dijkstra(graph [][]Pair, src int) []int {
	n := len(graph)
	dist := make([]int, n)
	for i := 0; i < n; i++ {
		dist[i] = math.MaxInt
	}
	dist[src] = 0

	pq := &PriorityQueue{}
	heap.Push(pq, &Item{value: src, priority: 0})

	for pq.Len() > 0 {
		item := heap.Pop(pq).(*Item)
		u := item.value

		for _, edge := range graph[u] {
			v := edge.first
			w := edge.second
			if dist[u]+w < dist[v] {
				dist[v] = dist[u] + w
				heap.Push(pq, &Item{value: v, priority: dist[v]})
			}
		}
	}
	return dist
}

type Item struct {
	value    int
	priority int
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].priority < pq[j].priority
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	*pq = append(*pq, x.(*Item))
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

