    indices := make([][]int, n+1)
    for i := 0; i < n*2; i++ {
        indices[a[i]] = append(indices[a[i]], i+1)
    }

    totalDistance := 0
    for i := 1; i <= n; i++ {
        minIndex := indices[i][0]
        maxIndex := indices[i][0]
        for _, index := range indices[i] {
            if index < minIndex {
                minIndex = index
            }
            if index > maxIndex {
                maxIndex = index
            }
