func prize(n, guess int, sum float64) float64 {
	if n == 0 && guess == 1 {
		return sum
	}
	sum /= float64(n + 1 - guess)
	temp := guess
	for n > 0 {
		sum = math.Max(sum, prize(n-1, temp, sum*float64(n)))
		n--
		temp++
	}
	return sum
}

func computePrize(n int) float64 {
	prize := 0.0
	for i := 0; i <= int(math.Log2(float64(n)))+1; i++ {
		prize += float64(comb(n, i)) * math.Pow(0.5, float64(i))
	}
	return prize
}

func comb(n, k int) int {
	if k > n {
		return 0
	}
	if k == 0 || k == n {
		return 1
	}
	k = int(math.Min(float64(k), float64(n-k)))
	c := 1
	for i := 0; i < k; i++ {
		c *= n - i
		c /= i + 1
	}
	return c
}

func main() {
	var n int
	fmt.Scan(&n)
	fmt.Printf("%.9f\n", computePrize(n))
}

func fib(x, y, n int) int {
	const MOD = 1000000007
	a, b, c, d := x, y, 1, 0

	for n > 0 {
		if n&1 == 1 {
			a, b = b, (a+b)%MOD
		}
		n >>= 1
		c, d = (c*a+d*b)%MOD, (c*d+d*a+c*b)%MOD
	}
	return a
}

