type Stack struct {
	values []int
}

func (s *Stack) Push(value int) {
	s.values = append(s.values, value)
}

func (s *Stack) Pop() int {
	if len(s.values) == 0 {
		return -1
	}
	value := s.values[len(s.values)-1]
	s.values = s.values[:len(s.values)-1]
	return value
}

func solution(n, m int, a []int) int {
	maxAddedHappiness := 0
	singles := make([]int, n)
	for i := range singles {
		singles[i] = i
	}

	for x := 0; x < n; x++ {
		if x == 0 {
			if a[x] > a[x+1] {
				a[x], a[x+1] = a[x+1], a[x]
			}
		} else {
			if a[x-1] > a[x] {
				a[x-1], a[x] = a[x], a[x-1]
			}
		}
	}

	chirinos := Stack{}
	sort.Ints(singles)

	for unusedHands := 0; unusedHands < m; unusedHands++ {
		for _, y := range chirinos.values {
			var hand int
			if y+1 < m {
				hand = y + 1
			} else if y-1 >= 0 {
				hand = y - 1
			} else {
				hand = 0
			}
			left, right := singles[y], singles[hand]
			if left > right {
				left, right = right, left
			} else {
				maxAddedHappiness += a[left] + a[right]
			}
		}
		chirinos.Push(right)
		singles = append(singles[:right], singles[right+1:]...)
	}
	return maxAddedHappiness
}

