        ai, bi, di := cmd[0]-1, cmd[1]-1, cmd[2]
        subMatrix := make([][]int, di)
        for j := 0; j < di; j++ {
            subMatrix[j] = make([]int, di)
            for i := 0; i < di; i++ {
                subMatrix[j][i] = knights[ai+j][bi+i]
            }
        }
        newSubMatrix := make([][]int, di)
        for j := 0; j < di; j++ {
            newSubMatrix[j] = make([]int, di)
            for i := 0; i < di; i++ {
                newSubMatrix[j][i] = subMatrix[di-1-i][j]
            }
        }
        for i := 0; i < di; i++ {
            for j := 0; j < di; j++ {
                knights[ai+i][bi+j] = newSubMatrix[i][j]
            }
        }
