func SmallestOnLeft(a []int) []int {
	n := len(a)
	leftMin := make([]int, n)
	stack := make([][2]int, 0)

	stack = append(stack, [2]int{a[0], 0})

	for i := 1; i < n; i++ {
		if a[i] < stack[len(stack)-1][0] {
			leftMin[i] = a[i]
		} else if a[i] == stack[len(stack)-1][0] {
			leftMin[i] = leftMin[stack[len(stack)-1][1]]
		} else {
			for len(stack) > 0 && a[i] >= stack[len(stack)-1][0] {
				stack = stack[:len(stack)-1]
			}
			if len(stack) == 0 {
				leftMin[i] = 0
			} else if stack[len(stack)-1][0] < a[i] {
				leftMin[i] = stack[len(stack)-1][0]
			} else {
				leftMin[i] = -1
			}
		}
		stack = append(stack, [2]int{a[i], i})
	}
	return leftMin
}

