func calculateDifference(a []int) int {
	if len(a) == 1 {
		return 0
	}

	minVal := math.MaxInt64
	maxVal := math.MinInt64

	for _, val := range a {
		if val < minVal {
			minVal = val
		}
		if val > maxVal {
			maxVal = val
		}
	}

	sliceWithoutMinMax := []int{}
	for _, val := range a {
		if val != maxVal && val != minVal {
			sliceWithoutMinMax = append(sliceWithoutMinMax, val)
		}
	}
	return maxVal - minVal
}

