func maxSets(k, a, b int) int {
	if a < k || b < k {
		return -1
	}
	fullSetsA := a / (k * 2)
	fullSetsB := b / (k * 2)
	maxSets := min(fullSetsA, fullSetsB)
	remainingA := a % (k * 2)
	remainingB := b % (k * 2)

	if remainingA >= k && remainingB >= k {
		maxSets++
	} else if remainingA >= k || remainingB >= k {
		if remainingA >= k && remainingB < k {
			maxSets++
		} else if remainingB >= k && remainingA < k {
			maxSets++
		}
	}
	return maxSets
}

func min(x, y int) int {
	if x < y {
		return x
	}
	return y
}

