func maxFollowers(n, k int, a []int) int {
    allCombinations := generateCombinations(n, k)
    followersSum := make([]int, len(allCombinations))

    for idx, combo := range allCombinations {
        sum := 0
        for _, i := range combo {
            sum += a[i]
        }
        followersSum[idx] = sum
    }

    maxSum := followersSum[0]
    count := 0

    for _, sum := range followersSum {
        if sum > maxSum {
            maxSum = sum
            count = 1
        } else if sum == maxSum {
            count++
        }
    }

    return count
}

func generateCombinations(n, k int) [][]int {
    result := [][]int{}
    var helper func(start int, combo []int)

    helper = func(start int, combo []int) {
        if len(combo) == k {
            newCombo := make([]int, len(combo))
            copy(newCombo, combo)
            result = append(result, newCombo)
            return
        }

        for i := start; i < n; i++ {
            helper(i+1, append(combo, i))
        }
    }

    helper(0, []int{})
    return result
}

