const MOD = 100000007

func whilePow(x, y int) int {
	res := 1
	x %= MOD
	for y > 0 {
		if y&1 == 1 {
			res = (res * x) % MOD
		}
		y >>= 1
		x = (x * x) % MOD
	}
	return res
}

func factorise(n int) ([]int, error) {
	if n < 2 {
		return nil, errors.New("input must be greater than or equal to 2")
	}

	fac := []int{}
	for i := 2; i*i <= n; i++ {
		for n%i == 0 {
			fac = append(fac, i)
			n /= i
		}
	}
	if n > 1 {
		fac = append(fac, n)
	}
	return fac, nil
}

func solve(x, n int) (int, error) {
	if x < 2 {
		return 0, errors.New("x must be greater than or equal to 2")
	}
	if n <= 0 {
		return 0, errors.New("n must be positive")
	}

	fac, err := factorise(x)
	if err != nil {
		return 0, err
	}

	ans := 1
	for _, p := range fac {
		gg := p
		tmp := x
		for tmp > 0 {
			tmp /= p
			exp := tmp
			ans = (ans * whilePow(gg, exp)) % MOD
		}
	}

	ans = whilePow(ans, n)
	return ans, nil
}

func main() {
	x, n := 30, 2 // Example inputs
	result, err := solve(x, n)
	if err != nil {
		log.Fatalf("Error: %v", err)
	}
	fmt.Printf("Result: %d\n", result)
}

