func getInput() (int, []int, error) {
	var nStr string
	if _, err := fmt.Scan(&nStr); err != nil {
		return 0, nil, fmt.Errorf("failed to read n: %w", err)
	}
	n, err := strconv.Atoi(nStr)
	if err != nil || n < 1 {
		return 0, nil, fmt.Errorf("invalid number of friends: %s", nStr)
	}

	var piStr string
	if _, err := fmt.Scan(&piStr); err != nil {
		return 0, nil, fmt.Errorf("failed to read pi: %w", err)
	}
	pi, err := parseToIntSlice(strings.Fields(piStr))
	if err != nil || len(pi) != n {
		return 0, nil, fmt.Errorf("invalid or mismatched pi length")
	}

	return n, pi, nil
}

func parseToIntSlice(strs []string) ([]int, error) {
	ints := make([]int, len(strs))
	for i, s := range strs {
		val, err := strconv.Atoi(s)
		if err != nil {
			return nil, fmt.Errorf("invalid integer in slice: %s", s)
		}
		ints[i] = val
	}
	return ints, nil
}

func findGifts(n int, pi []int) {
	friends := make([]int, n+1)
	for _, friend := range pi {
		if friend < 1 || friend > n {
			log.Printf("Warning: friend %d is out of bounds", friend)
			continue
		}
		friends[friend] = friend
	}
	for i := 1; i <= n; i++ {
		fmt.Print(friends[i], " ")
	}
	fmt.Println()
}

