func main() {
	if err := processQueries(); err != nil {
		fmt.Fprintf(os.Stderr, "Error processing queries: %v\n", err)
		os.Exit(1)
	}
}

func processQueries() error {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	data, err := readInput(reader)
	if err != nil {
		return err
	}

	index := 0
	t, err := strconv.Atoi(data[index])
	if err != nil {
		return fmt.Errorf("invalid test case count: %v", err)
	}
	index++

	var results []string

	for i := 0; i < t; i++ {
		n, err := strconv.Atoi(data[index])
		if err != nil {
			return fmt.Errorf("invalid array size: %v", err)
		}
		index++

		array := make([]int, n)
		for j := 0; j < n; j++ {
			value, err := strconv.Atoi(data[index+j])
			if err != nil {
				return fmt.Errorf("invalid array value: %v", err)
			}
			array[j] = value
		}
		index += n

		q, err := strconv.Atoi(data[index])
		if err != nil {
			return fmt.Errorf("invalid query count: %v", err)
		}
		index++

		queries := make([][2]int, q)
		for j := 0; j < q; j++ {
			x, err := strconv.Atoi(data[index])
			if err != nil {
				return fmt.Errorf("invalid query x: %v", err)
			}
			k, err := strconv.Atoi(data[index+1])
			if err != nil {
				return fmt.Errorf("invalid query k: %v", err)
			}
			queries[j] = [2]int{x - 1, k}
			index += 2
		}

		result, err := queryAnswer(n, array, queries)
		if err != nil {
			return err
		}
		results = append(results, result...)
	}

	_, err = writer.WriteString(fmt.Sprintln(results))
	return err
}

func readInput(reader *bufio.Reader) ([]string, error) {
	var lines []string
	for {
		line, err := reader.ReadString('\n')
		if err != nil {
			break
		}
		lines = append(lines, line)
	}
	return lines, nil
}

func queryAnswer(n int, array []int, queries [][2]int) ([]string, error) {
	result := make([]string, len(queries))
	countHistory := make([]map[int]int, n)
	stepCount := make(map[int][]int)
	currentCounts := make([]int, n)

	for i := 0; i < n; i++ {
		currentCounts[array[i]-1]++
		countHistory[i] = make(map[int]int)
	}

	for step, query := range queries {
		x, k := query[0], query[1]
		if k == 0 {
			result[step] = strconv.Itoa(array[x])
			continue
		}
		countHistory[step][array[x]]++

		if k == 1 {
			result[step] = strconv.Itoa(countHistory[step][array[x]])
			continue
		}

		for value := 1; value <= n; value++ {
			if currentCounts[value-1] > 0 {
				stepCount[value] = append(stepCount[value], step)
			}
		}

		if currentCounts[array[x]-1] > 0 {
			stepCount[array[x]] = stepCount[array[x]][1:]
		}

		var nextStep, beforeNextStep int = -1, -1
		if steps, exists := stepCount[array[x]]; exists && len(steps) > 0 {
			nextStep = steps[len(steps)-1]
			if len(steps) > 1 {
				beforeNextStep = steps[len(steps)-2]
			}
		}

		result[step] = strconv.Itoa(nextStep - beforeNextStep)
	}

	return result, nil
}

