const mod = 1e9 + 7

func longestDupSubstring(s string) (string, error) {
	if len(s) == 0 {
		return "", fmt.Errorf("input string cannot be empty")
	}
	N := len(s)
	A := make([]int, N)
	for i := 0; i < N; i++ {
		A[i] = int(s[i]) - int('a')
	}
	P := int(math.Pow(26, float64(N-1))) % int(mod)
	fTable := make([]int, N)
	for i := range fTable {
		fTable[i] = (i * P) % int(mod)
	}

	fTable[0] = fTable[0] % int(mod)
	for i := 1; i < N; i++ {
		fTable[i] = (fTable[i-1] * 26) % int(mod)
	}

	hashTable := make([]int, N)
	hash := 0
	for i := 0; i < N; i++ {
		hash = (hash*26 + A[i]) % int(mod)
		hashTable[i] = hash
		if i != 0 {
			hashTable[i] = (hashTable[i] - hashTable[i-1]*fTable[i]) % int(mod)
		}
	}

	d, start := binarySearch(hashTable, n, fTable)

	if d == 0 {
		return "", nil
	}

	return s[start : start+d], nil
}

func binarySearch(hashTable []int, n int, fTable []int) (int, int) {
	left, right := 1, n
	start := -1

	for left <= right {
		mid := left + (right-left)/2
		if check(mid, hashTable, n, fTable) {
			start = findStart(mid, hashTable, n, fTable)
			left = mid + 1
		} else {
			right = mid - 1
		}
	}

	return right, start
}

func check(i int, hashTable []int, n int, fTable []int) bool {
	occs, cnt := 0, 0
	for j := 0; j <= n-i; j++ {
		if compareHashes(hashTable, j, j+i-1) {
			cnt++
		} else {
			occs = max(occs, cnt)
			cnt = 0
		}
	}
	return i <= occs+1
}

func compareHashes(hashTable []int, j, k int) bool {
	return (hashTable[k] - (hashTable[j-1] * fTable[k-j+1])) % int(mod) == 0
}

func findStart(i int, hashTable []int, n int, fTable []int) int {
	for j := 0; j <= n-i; j++ {
		if compareHashes(hashTable, j, j+i-1) {
			return j
		}
	}
	return -1
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

