	var n int
	_, err := fmt.Scan(&n)
	if err != nil {
		return nil, err
	}

	numbers := make([]int, n)
	for i := 0; i < n; i++ {
		if _, err := fmt.Scan(&numbers[i]); err != nil {
			return nil, err
		}
	}
	return numbers, nil
}

func findValidIndices(numbers []int) []int {
	var results []int
	n := len(numbers)

	for i := 1; i <= n; i++ {
		if numbers[i-1]%2 == 0 {
			if countEvens(numbers[:i-1]) == 0 && countEvens(numbers[i:]) == 0 {
				results = append(results, i)
			}
		} else {
			if countEvens(numbers[:i]) > 0 && countEvens(numbers[i:]) > 0 {
				results = append(results, i)
			}
		}
	}
	return results
}

func countEvens(slice []int) int {
	count := 0
	for _, x := range slice {
		if x%2 == 0 {
			count++
		}
	}
	return count
}

func shortestDistance(matrix [][]int) int {
	n := len(matrix)
	if n == 0 || len(matrix[0]) == 0 {
		return -1
	}

	ans := make([][]int, n)
	for i := range ans {
		ans[i] = make([]int, n)
	}

	cells := [][]int{}
	for i := 0; i < n; i++ {
		for j := 0; j < n; j++ {
			if matrix[i][j] != 0 {
				cells = append(cells, []int{i, j, 1})
			}
		}
	}

	directions := [][]int{
		{-1, 0}, {1, 0}, {0, -1}, {0, 1},
	}

	for len(cells) > 0 {
		currentCell := cells[0]
		cells = cells[1:]

		for _, dir := range directions {
			newRow, newCol := currentCell[0]+dir[0], currentCell[1]+dir[1]
			if newRow >= 0 && newRow < n && newCol >= 0 && newCol < n {
				if ans[newRow][newCol] == 0 && (matrix[newRow][newCol] == 0) {
					ans[newRow][newCol] = currentCell[2] + 1
					cells = append(cells, []int{newRow, newCol, ans[newRow][newCol]})
				}
			}
		}
	}

	if ans[n-1][n-1] == 0 {
		return -1
	}

	return ans[n-1][n-1] + 1
}

