// countRemainingEmpires calculates the number of remaining empires after takeovers
func countRemainingEmpires(N int, K int, takeovers [][]int) (int, error) {
	if N <= 0 {
		return 0, errors.New("N must be a positive integer")
	}
	if K < 0 {
		return 0, errors.New("K cannot be negative")
	}
	if len(takeovers) != K {
		return 0, fmt.Errorf("expected %d takeovers, got %d", K, len(takeovers))
	}

	existingEmpires := make(map[int]struct{})
	for i := 1; i <= N; i++ {
		existingEmpires[i] = struct{}{}
	}

	for _, takeover := range takeovers {
		if len(takeover) != 2 {
			return 0, errors.New("each takeover must consist of two empires")
		}

		i, j := takeover[0], takeover[1]

		if _, exists := existingEmpires[j]; exists {
			delete(existingEmpires, j)
		}
		existingEmpires[i] = struct{}{}
	}

	return len(existingEmpires), nil
}

