func reverseInteger(n int) (int, error) {
	nStr := strconv.Itoa(n)
	reversedStr := reverseString(nStr)
	reversedInt, err := strconv.Atoi(reversedStr)
	if err != nil {
		return 0, fmt.Errorf("failed to convert reversed string to integer: %v", err)
	}
	return reversedInt, nil
}

func reverseString(s string) string {
	runes := []rune(s)
	for i, j := 0, len(runes)-1; i < j; i, j = i+1, j-1 {
		runes[i], runes[j] = runes[j], runes[i]
	}
	return string(runes)
}

