	graph := NewGraph()
	for _, edge := range edges {
		graph.AddEdge(edge[0], edge[1])
	}

	labels := make([]int, n-1)
	visited := make([]bool, n+1)
	visited[1] = true
	queue := []int{1}
	mexCounter := make([]int, n-1)

	for len(queue) > 0 {
		u := queue[0]
		queue = queue[1:]

		for _, edge := range graph.edges[u] {
			v := edge.node
			i := edge.index
			if !visited[v] {
				visited[v] = true
				mexValue := mexCounter[mexCounter[u]]
				labels[i] = mexValue
				mexCounter[mexValue]++
				mexCounter[v] = mexCounter[mexCounter[u]]
				queue = append(queue, v)
			}
		}
	}

	return labels, nil
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	data, err := reader.ReadString('\n')
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error reading input: %v\n", err)
		return
	}

	var n int
	var edges [][]int

	_, err = fmt.Sscanf(data, "%d", &n)
	if err != nil || n < 2 {
		fmt.Fprintf(os.Stderr, "Invalid input for n: %v\n", err)
		return
	}

	for i := 0; i < n-1; i++ {
		var u, v int
		_, err = fmt.Fscanf(reader, "%d %d", &u, &v)
		if err != nil {
			fmt.Fprintf(os.Stderr, "Error reading edge data: %v\n", err)
			return
		}
		edges = append(edges, []int{u, v})
	}

	labels, err := solve(n, edges)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error solving the graph: %v\n", err)
		return
	}

	for _, label := range labels {
		fmt.Println(label)
	}
}

