func maxCandies(status []int, candies []int, keys [][]int, containedBoxes [][]int, initialBoxes []int) int {
	stack := []int{}
	total := 0
	cnt := 0

	for _, box := range initialBoxes {
		stack = append(stack, box)
		candies[box]--

		for len(stack) > 0 {
			check := stack[len(stack)-1]
			stack = stack[:len(stack)-1]

			if status[check] == 0 || len(keys[check]) > 0 {
				stack = append(stack, check)
				continue
			}

			for _, j := range containedBoxes[check] {
				cnt++
				containedBoxes[j] = removeBox(containedBoxes[j], check)

				if len(containedBoxes[j]) == 0 {
					total += candies[j]
					cnt--
					if !contains(stack, j) {
						cnt++
						stack = append(stack, j)
					}
				} else {
					stack = append(stack, j)
				}
			}
		}
	}
	return total
}

func removeBox(boxes []int, box int) []int {
	for i, b := range boxes {
		if b == box {
			return append(boxes[:i], boxes[i+1:]...)
		}
	}
	return boxes
}

func contains(slice []int, item int) bool {
	for _, i := range slice {
		if i == item {
			return true
		}
	}
	return false
}

