type Duck struct {
    Color int
    Count int
}

func solve(N, K int, ducks []int) {
    duckList := make([]Duck, len(ducks))
    for i, count := range ducks {
        duckList[i] = Duck{Color: i, Count: count}
    }

    sort.Slice(duckList, func(i, j int) bool {
        return duckList[i].Count > duckList[j].Count
    })

    boxes := make([][2]int, N)
    boxCounts := make([][2]int, N)

    for _, duck := range duckList {
        count := duck.Count
        for i := 0; i < N && count > 0; i++ {
            if boxCounts[i][0] < K && (boxes[i][0] == 0 || boxes[i][0] == duck.Color) {
                boxes[i][0] = duck.Color
                boxCounts[i][0]++
                count--
            }
            if boxCounts[i][1] < K && (boxes[i][1] == 0 || boxes[i][1] == duck.Color) {
                boxes[i][1] = duck.Color
                boxCounts[i][1]++
                count--
            }
        }
    }

    for i := 0; i < N; i++ {
        c1, c2 := boxes[i][0], boxes[i][1]
        if c1 == c2 {
            c2 = 0
        }
        fmt.Printf("%d %d %d %d\n", c1, boxCounts[i][0], c2, boxCounts[i][1])
    }
}

