import (
	"fmt"
	"sort"
)

type Swap struct {
	From, To int
}

func solve(A []int, size int) ([]Swap, error) {
	if size <= 0 {
		return nil, fmt.Errorf("size must be greater than zero")
	}
	if len(A) != size {
		return nil, fmt.Errorf("length of A must be equal to size")
	}

	type Pair struct{ Index, Value int }
	pairs := make([]Pair, size)
	for i := range A {
		pairs[i] = Pair{i, A[i]}
	}
	sort.Slice(pairs, func(i, j int) bool { return pairs[i].Value < pairs[j].Value })

	cycleCount := make(map[int]int)
	ans := 0
	result := []Swap{}
	visited := make(map[int]bool)

	for i := 0; i < size; i++ {
		if !visited[i] {
			cycleSize := 0
			j := i

			for !visited[j] {
				visited[j] = true
				j = pairs[j].Index
				cycleSize++
			}

			cycleCount[cycleSize]++
			if cycleSize >= 2 {
				ans += cycleSize - 1
				sortedVisited := []int{}
				for k := range visited {
					sortedVisited = append(sortedVisited, k)
				}
				sort.Ints(sortedVisited)
				for _, x := range sortedVisited[1:] {
					result = append(result, Swap{From: i, To: x})
				}
			}
		}
	}

	if ans > size/2 {
		return nil, fmt.Errorf("-1")
	}

	sort.Slice(result, func(i, j int) bool {
		if result[i].From == result[j].From {
			return result[i].To < result[j].To
		}
		return result[i].From < result[j].From
	})

	ans, i := 0, 0
	var j int

	for len(A)-ans-i > 0 && i < len(result) {
		if pairs[i].Index == i {
			i++
		} else {
			i = len(result)
		}
	}

	for j < size && !visited[j] {
		visited[j] = true
		j = pairs[j].Index
		result = append(result, Swap{From: pairs[i].Value, To: j})
		i++
	}
	return result, nil
}

func main() {
	var n int
	if _, err := fmt.Scan(&n); err != nil {
		fmt.Println("Failed to read input size")
		return
	}

	A := make([]int, n)
	for i := 0; i < n; i++ {
		if _, err := fmt.Scan(&A[i]); err != nil {
			fmt.Println("Failed to read input values")
			return
		}
	}

	result, err := solve(A, n)
	if err != nil {
		fmt.Println(err)
		return
	}

	for _, swap := range result {
		fmt.Printf("Swap: %d with %d\n", swap.From, swap.To)
	}
}

