func precomp(input string) []string {
	var list []string
	var beg int

	for ind, ch := range input {
		if strings.ContainsRune("bcdfghjklmnpqrstvxzy", ch) {
			if ind != beg {
				list = append(list, input[beg+1:ind])
			}
			beg = ind + 1
		} else {
			if ind > 0 && (input[ind-1] == 'm' || input[ind-1] == 'n') &&
				ind+1 < len(input) && strings.ContainsRune("tvwxyz", input[ind+1]) {
				if ind+2 < len(input) && input[ind+2] == 't' {
					list = append(list, input[ind+2:])
				}
			} else {
				if ind != beg {
					list = append(list, input[beg+1:ind])
				}
			}
			beg = ind + 1
		}
	}

	if beg < len(input) && beg+1 != len(input) && strings.ContainsRune("tvwxyz", input[beg]) {
		list = append(list, input[beg+1:])
	}

	if len(list) == 0 || countOccurrences(list, list[0]) != len(list[1:]) {
		list = []string{input}
	}
	sort.Strings(list)
	return list
}

func countOccurrences(list []string, item string) int {
