func parseCode(input string) ([]string, error) {
	if input == "" {
		return nil, errors.New("input cannot be empty")
	}

	parts := strings.Split(input, "=")
	if len(parts) == 0 {
		return nil, errors.New("invalid input format")
	}

	code := parts[0]
	myList := strings.FieldsFunc(code, func(r rune) bool {
		return r == '[' || r == ']' || r == ','
	})

	res := []string{}
	i := 0

	for i < len(myList) {
		if strings.Contains(myList[i], "[[") {
			for a := i; a < len(myList); a++ {
				if strings.Contains(myList[a], "],") {
					myList[a] = ""
					break
				} else if myList[a] == "[" || myList[a] == "]" || myList[a] == "," {
					continue
				} else {
					res = append(res, myList[a])
					myList[a] = ""
					i = a + 1
					break
				}
			}
		}
		i++
	}

	for len(res) > 0 {
		i = 0
		for i < len(myList) {
			if myList[i] == res[0] {
				myList[i-1] = "," + myList[i-1]
				myList[i] = ""
			}
			if myList[i] == "," {
				myList[i] = ""
			}
			i++
		}
	}

	if len(myList) == 0 {
		return []string{";"}, nil
	}

	for i := range myList {
		if myList[i] == "" {
			myList[i] = " "
		}
	}

	if len(myList) == 0 {
		return []string{"[]"}, nil
	}
	return res, nil
}

func main() {
	testList := []string{"[[a, ad, 123,[]], [[d,e,f],f],asdf"}
	for _, test := range testList {
		result, err := parseCode(test)
		if err != nil {
			log.Fatalf("Error parsing code: %v", err)
		}
		fmt.Println(result)
	}
}

