	}

	var dfs func(n, color int) bool
	dfs = func(n, color int) bool {
		if _, exists := colors[n]; !exists {
			colors[n] = color
		} else if colors[n] != color {
			return false
		}

		for _, v := range graph.adjacencyList[n] {
			if !dfs(v, 1-color) {
				return false
			}
		}
		return true
	}

	for node := 1; node <= N; node++ {
		if _, visited := colors[node]; !visited {
			if !dfs(node, 1) {
				return false, nil
			}
		}
	}

	return true, nil
}

func main() {
	dislikes := [][]int{{1, 2}, {1, 3}, {2, 4}}
	N := 4

	canBeBipartitioned, err := possibleBipartition(N, dislikes)
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Can be bipartitioned:", canBeBipartitioned)
	}
}

