func minPathCost(testCases []TestCase) []int {
	results := make([]int, len(testCases))
	for i, testCase := range testCases {
		n, costs := testCase.N, testCase.Costs
		dpH := make([]float64, n+1)
		dpV := make([]float64, n+1)

		for j := 1; j <= n; j++ {
			dpH[j] = math.Inf(1)
			dpV[j] = math.Inf(1)
		}
		dpH[0], dpV[0] = 0, 0

		for j := 1; j <= n; j++ {
			dpH[j] = math.Min(dpH[j-1]+float64(j)*float64(costs[2*j-3]), dpV[j-1]+float64(j)*float64(costs[2*j-3]))
			dpV[j] = math.Min(dpV[j-1]+float64(j)*float64(costs[2*j-2]), dpH[j-1]+float64(j)*float64(costs[2*j-2]))
		}

		results[i] = int(math.Min(dpH[n], dpV[n]))
	}
	return results
}

type TestCase struct {
	N     int
	Costs []int
}

func readInput() ([]TestCase, error) {
	input, err := os.ReadFile("input.txt")
	if err != nil {
		return nil, fmt.Errorf("failed to read input: %w", err)
	}

	data := strings.Fields(string(input))
	t, err := strconv.Atoi(data[0])
	if err != nil {
		return nil, fmt.Errorf("invalid number of test cases: %w", err)
	}

	testCases := make([]TestCase, t)
	index := 1
	for i := 0; i < t; i++ {
		n, err := strconv.Atoi(data[index])
		if err != nil || n <= 0 {
			return nil, fmt.Errorf("invalid n: %v", err)
		}
		index++
		costs := make([]int, n*2)
		for j := 0; j < n*2; j++ {
			costs[j], err = strconv.Atoi(data[index+j])
			if err != nil {
				return nil, fmt.Errorf("invalid cost at index %d: %v", index+j, err)
			}
		}
		testCases[i] = TestCase{N: n, Costs: costs}
		index += n * 2
	}
	return testCases, nil
}

func main() {
	testCases, err := readInput()
	if err != nil {
		log.Fatalf("input error: %v\n", err)
	}

	results := minPathCost(testCases)
	for _, result := range results {
		fmt.Println(result)
	}
}

