func scoreOfParentheses(s string) (int, error) {
    if len(s) == 0 {
        return 0, errors.New("input string cannot be empty")
    }

    for _, char := range s {
        if char != '(' && char != ')' {
            return 0, errors.New("input string can only contain '(' and ')' characters")
        }
    }

    stk := []int{0}
    for _, char := range s {
        if char == '(' {
            stk = append(stk, 0)
        } else {
            if len(stk) == 0 {
                return 0, errors.New("unmatched closing parenthesis")
            }
            score := 0
            for len(stk) > 0 && stk[len(stk)-1] != 0 {
                score += stk[len(stk)-1]
                stk = stk[:len(stk)-1]
            }

            if len(stk) == 0 {
                return 0, errors.New("unmatched closing parenthesis")
            }

            stk = append(stk[:len(stk)-1], 2*score)
            stk = append(stk, 1)
        }
    }

    totalScore := 0
    for len(stk) > 0 {
        totalScore += stk[len(stk)-1]
        stk = stk[:len(stk)-1]
    }

    return totalScore, nil
}

func main() {
    input := "(()())"
    score, err := scoreOfParentheses(input)
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Println("Score:", score)
    }
}

