// Interval represents a time interval with a start and end
type Interval struct {
	Start int
	End   int
}

// Helper function to sort intervals by start time
func sortIntervals(intervals []Interval) {
	sort.Slice(intervals, func(i, j int) bool {
		return intervals[i].Start < intervals[j].Start
	})
}

// Function to find employee free time based on provided schedules
func employeeFreeTime(schedule [][]Interval) ([]Interval, error) {
	if len(schedule) == 0 {
		return nil, errors.New("schedule cannot be empty")
	}
	for _, intervals := range schedule {
		if len(intervals) == 0 {
			return nil, errors.New("each employee must have intervals")
		}
	}

	var result []Interval
	prePos := 0

	for i := 0; i < len(schedule); i++ {
		sortIntervals(schedule[i])
		if i > 0 {
			prePos = findNextPosition(schedule[i-1], prePos, schedule[i][0].Start)
			for j := findNextPosition(schedule[i], 0, schedule[i-1][prePos].End); j < len(schedule[i]) && prePos < len(schedule[i-1]); prePos++ {
				if prePos < len(schedule[i-1]) && j < len(schedule[i]) {
					result = append(result, Interval{schedule[i-1][prePos].End, schedule[i][j].Start})
				}
				j++
			}
		}
	}
	return result, nil
}

// Helper function to find the next valid position in the interval
func findNextPosition(intervals []Interval, pos int, time int) int {
	for pos < len(intervals) && intervals[pos].End <= time {
		pos++
	}
	return pos
}

func main() {
	// Example usage
	schedule := [][]Interval{
		{{1, 3}, {4, 6}, {7, 9}, {9, 10}},
		{{2, 5}, {8, 9}},
	}

	freeTime, err := employeeFreeTime(schedule)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	for _, interval := range freeTime {
		fmt.Printf("Free Time: (%d, %d)\n", interval.Start, interval.End)
	}
}

