type Graph struct {
	adj map[int]map[int]struct{}
}

func NewGraph() *Graph {
	return &Graph{adj: make(map[int]map[int]struct{})}
}

func (g *Graph) AddEdge(a, b int) {
	if g.adj[a] == nil {
		g.adj[a] = make(map[int]struct{})
	}
	g.adj[a][b] = struct{}{}
}

func countOddDegrees(adj map[int]map[int]struct{}) int {
	odds := 0
	for _, neighbors := range adj {
		if len(neighbors)%2 != 0 {
			odds++
		}
	}
	return odds
}

func isPossible(n int, edges [][]int) bool {
	graph := NewGraph()
	for _, edge := range edges {
		graph.AddEdge(edge[0], edge[1])
	}

	odds := countOddDegrees(graph.adj)

	if odds == 0 || odds == 2 {
		return true
	}
	if odds == 4 {
		return false
	}

	for v := range graph.adj {
		if len(graph.adj[v]) == 0 {
			graph.AddEdge(v, n+1)
			n++
		}
	}

	for _, neighbors := range graph.adj {
		if len(neighbors)%2 != 0 {
			return true
		}
	}

	return false
}

