func shellSort(cusl []int, n int) {
	indsw := 1
	for i := (n - 1) / 2; i >= 0; i-- {
		for j := indsw; j < n; j++ {
			insertionSort(cusl, j, i, n)
		}
		indsw *= 3
	}
}

func insertionSort(cusl []int, j, i, n int) {
	x := cusl[j]
	l := j - i
	for l >= 0 {
		if cusl[l] <= x {
			break
		}
		cusl[l+i] = cusl[l]
		l--
	}
	cusl[l+i] = x
}

