	}
	return strings.TrimSpace(input), nil
}

func findOperations(n int, a, b string) []int {
	var operations []int

	for j := 1; j <= n; j++ {
		prefixA := a[:j]
		invertedPrefixA := reverseString(prefixA)

		if invertedPrefixA == b[:j] {
			a = a[j:]
			b = b[j:]
			operations = append(operations, j)
		}
	}

	return operations
}

func reverseString(s string) string {
	runes := []rune(s)
	for i, j := 0, len(runes)-1; i < j; i, j = i+1, j-1 {
		runes[i], runes[j] = runes[j], runes[i]
	}
	return string(runes)
}

