// findWinner determines the winning candidate based on city votes.
func findWinner(n int, m int, votes [][]int) (int, error) {
	if n <= 0 || m <= 0 || len(votes) != m {
		return 0, errors.New("invalid input: n and m must be positive and match the length of votes")
	}

	for _, cityVotes := range votes {
		if len(cityVotes) != n {
			return 0, errors.New("invalid input: each city must have votes for n candidates")
		}
	}

	cityWinners := make([]int, n)
	cityCounts := make([]int, n)

	for _, cityVotes := range votes {
		maxVotes := findMax(cityVotes)
		for i, candidateVotes := range cityVotes {
			if candidateVotes == maxVotes {
				cityWinners[i]++
			}
		}
	}

	maxCityCount := findMax(cityWinners)
	candidatesWithMaxCityCount := findMinCandidates(cityWinners, maxCityCount)

	if len(candidatesWithMaxCityCount) == 0 {
		return 0, errors.New("no candidates found")
	}

	return candidatesWithMaxCityCount[0] + 1, nil
}

// findMax returns the maximum value in a slice of integers.
func findMax(arr []int) int {
	max := arr[0]
	for _, value := range arr {
		if value > max {
			max = value
		}
	}
	return max
}

// findMinCandidates returns indices of candidates with the maximum count.
func findMinCandidates(counts []int, maxCount int) []int {
	var candidates []int
	for i, count := range counts {
		if count == maxCount {
			candidates = append(candidates, i)
		}
	}
	return candidates
}

