	vowelCountB := countVowels(b)

	return vowelCountA == vowelCountB, nil
}

func validateInput(s string) error {
	if len(s)%2 != 0 {
		return errors.New("input string must have even length")
	}
	return nil
}

func countVowels(s string) int {
	vowelSet := "aeiouAEIOU"
	count := 0

	for _, char := range s {
		if unicode.ContainsRune([]rune(vowelSet), char) {
			count++
		}
	}

	return count
}

