const (
	xMax = 1000
	yMax = 1000
)

func isBlocked(blocked [][]int, x, y int) bool {
	for _, b := range blocked {
		if b[0] == x && b[1] == y {
			return true
		}
	}
	return false
}

func possible(blocked [][]int, source []int, target []int) bool {
	if !validateInput(source) || !validateInput(target) {
		return false
	}
	if source[0] == target[0] && source[1] == target[1] {
		return true
	}

	x, y := source[0], source[1]
	tx, ty := target[0], target[1]

	for x != tx || y != ty {
		if x < 0 || y < 0 || x >= xMax || y >= yMax || isBlocked(blocked, x, y) {
			return false
		}

		xMovements := []int{x + 1, x, x - 1, x}
		yMovements := []int{y + 1, y, y - 1}

		for i := 0; i < 4; i++ {
			if isBlocked(blocked, xMovements[i], yMovements[i]) {
				return false
			}
		}

		x, y = xMovements[yMovements[y]-y], y+yMovements[x-xMovements[x]]
	}

	return true
}

func validateInput(coord []int) bool {
	return coord[0] >= 0 && coord[0] < xMax && coord[1] >= 0 && coord[1] < yMax
}

