func gcd(x, y int) int {
	for y != 0 {
		x, y = y, x%y
	}
	return x
}

func validateInputs(args []string) ([]int, error) {
	if len(args) < 2 {
		return nil, fmt.Errorf("insufficient input")
	}
	N, err := strconv.Atoi(args[0])
	if err != nil || N <= 0 {
		return nil, fmt.Errorf("invalid number of elements: %s", args[0])
	}
	A := make([]int, N)
	for i, v := range strings.Split(args[1], " ") {
		if i >= N {
			break
		}
		num, err := strconv.Atoi(v)
		if err != nil {
			return nil, fmt.Errorf("invalid integer: %s", v)
		}
		A[i] = num
	}
	return A, nil
}

func main() {
	args := os.Args[1:]

	A, err := validateInputs(args)
	if err != nil {
		log.Fatalf("Error validating inputs: %v", err)
	}
	N := len(A)

	isPairwiseCoprime := true
	isSetwiseCoprime := true

	for i := 0; i < N; i++ {
		for j := i + 1; j < N; j++ {
			if gcd(A[i], A[j]) != 1 {
				isPairwiseCoprime = false
			}
		}
	}

	setwiseGCD := A[0]
	for _, a := range A {
		setwiseGCD = gcd(setwiseGCD, a)
	}

	if setwiseGCD != 1 {
		isSetwiseCoprime = false
	}

	switch {
	case isPairwiseCoprime:
		fmt.Println("pairwise coprime")
	case isSetwiseCoprime:
		fmt.Println("setwise coprime")
	default:
		fmt.Println("not coprime")
	}
}

