	}
	defer logFile.Close()
	log.SetOutput(logFile)

	var q int
	if _, err := fmt.Scan(&q); err != nil {
		log.Println("Input error:", err)
		return
	}
	for i := 0; i < q; i++ {
		var n int
		if _, err := fmt.Scan(&n); err != nil {
			log.Println("Input error:", err)
			return
		}
		a := make([]int, 2*n)
		for j := 0; j < n; j++ {
			if _, err := fmt.Scan(&a[j]); err != nil {
				log.Println("Input error:", err)
				return
			}
			a[j+n] = a[j]
		}
		ans := calculateSum(a, n)
		fmt.Println(ans)
	}
}

func calculateSum(a []int, n int) int64 {
	var ans int64
	s := make([]pair, 0)
	s = append(s, pair{a[0], 1})

	for i := 1; i < 2*n; i++ {
		p := pair{a[i], 0}
		if len(s) > 0 && s[len(s)-1].second > 1 {
			p.first = s[len(s)-1].first
		}
		for len(s) > 0 && s[len(s)-1].first >= p.first {
			s = s[:len(s)-1]
		}
		s = append(s, p)
		ans += int64(s[len(s)-1].first)
	}
	return ans
}

