func findKthSmallest(n, k int) (int, error) {
	if n <= 0 || k <= 0 {
		return -1, errors.New("n and k must be greater than 0")
	}
	frequencies := make([]int, n+1)

	for i := 0; i < n; i++ {
		var a, b int
		if _, err := fmt.Scan(&a, &b); err != nil {
			return -1, fmt.Errorf("input error: %w", err)
		}
		if a < 1 || a > n || b < 0 {
			return -1, errors.New("input values out of bounds")
		}
		frequencies[a] += b
	}

	count := 0
	for i := 1; i <= n; i++ {
		count += frequencies[i]
		if count >= k {
			return i, nil
		}
	}
	return -1, errors.New("k is larger than the total frequencies")
}

func main() {
	n, k := 0, 0
	fmt.Print("Enter n and k: ")
	if _, err := fmt.Scan(&n, &k); err != nil {
		log.Fatalf("Failed to read input: %v", err)
	}

	result, err := findKthSmallest(n, k)
	if err != nil {
		log.Fatalf("Error finding k-th smallest: %v", err)
	}

	fmt.Printf("The k-th smallest integer is: %d\n", result)
}

