// ValidateInput checks the validity of input values
func ValidateInput(n int, cards []int) error {
	if n <= 0 {
		return fmt.Errorf("invalid number of cards: %d", n)
	}
	if len(cards) != n {
		return fmt.Errorf("number of cards provided (%d) does not match expected (%d)", len(cards), n)
	}
	return nil
}

// GameScore calculates the scores of two players based on cards
func GameScore(n int, cards []int) (int, int, error) {
	if err := ValidateInput(n, cards); err != nil {
		return 0, 0, err
	}

	serejaScore := 0
	dimaScore := 0
	left := 0
	right := n - 1

	for left <= right {
		if cards[left] >= cards[right] {
			serejaScore += cards[left]
			left++
		} else {
			serejaScore += cards[right]
			right--
		}
		if left <= right {
			if cards[left] >= cards[right] {
				dimaScore += cards[left]
				left++
			} else {
				dimaScore += cards[right]
				right--
			}
		}
	}

	return serejaScore, dimaScore, nil
}

func main() {
	testCases := [][]int{
		{4, 1, 2, 10},
		{7, 1, 2, 3, 4, 5, 6, 7},
	}

	for _, testCase := range testCases {
		n := testCase[0]
		cards := testCase[1:]

		serejaScore, dimaScore, err := GameScore(n, cards)
		if err != nil {
			log.Printf("Error calculating scores for n=%d: %v", n, err)
			continue
		}
		log.Printf("Scores for n=%d, cards=%v: Sereja=%d, Dima=%d", n, cards, serejaScore, dimaScore)
	}
}

