const mod = 1e9 + 7

type Item struct {
	distance int
	node     int
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int {
	return len(pq)
}

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].distance < pq[j].distance
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(n, m int, s string) string {
	slice := make([]int, n+1)
	for i, c := range s {
		slice[i+1] = int(c - '0')
	}

	dist := make([]int, n+1)
	for i := range dist {
		dist[i] = math.MaxInt32
	}
	dist[0] = 0
	prev := make([]int, n+1)
	queue := &PriorityQueue{{0, 0}}
	heap.Init(queue)

	for queue.Len() > 0 {
		item := heap.Pop(queue).(*Item)
		d, u := item.distance, item.node
		if d > dist[u] {
			continue
		}

		for x := 1; x <= m; x++ {
			v := u + x
			if v > n || slice[v] != 0 {
				continue
			}
			if dist[v] > dist[u]+1 {
				dist[v] = dist[u] + 1
				prev[v] = u
				heap.Push(queue, &Item{dist[v], v})
			}
		}
	}

	if dist[n] == math.MaxInt32 {
		return "-1"
	}

	var sequence []int
	u := n
	for u > 0 {
		v := prev[u]
		sequence = append(sequence, u-v)
		u = v
	}

	var result strings.Builder
	for i := len(sequence) - 1; i >= 0; i-- {
		result.WriteString(strconv.Itoa(sequence[i]))
		if i > 0 {
			result.WriteString(" ")
		}
	}
	return result.String()
}

func main() {
	var n, m int
	if _, err := fmt.Scanf("%d %d", &n, &m); err != nil {
		log.Fatal("Error reading n and m:", err)
	}

	var s string
	if _, err := fmt.Scan(&s); err != nil {
		log.Fatal("Error reading s:", err)
	}

	if n <= 0 || m <= 0 || len(s) < n {
		log.Fatal("Invalid input parameters")
	}

	result := solve(n, m, s)
	fmt.Println(result)
}

