// OrderlyQueue calculates the lexicographically smallest string
// given the constraints on the moves allowed.
func OrderlyQueue(s string, k int) (string, error) {
	if k <= 0 {
		return "", fmt.Errorf("k must be greater than 0")
	}

	if k > 1 {
		return sortedString(s), nil
	}
	return smallestRotation(s), nil
}

// sortedString returns the sorted version of the string.
func sortedString(s string) string {
	runes := []rune(s)
	sort.Slice(runes, func(i, j int) bool {
		return runes[i] < runes[j]
	})
	return string(runes)
}

// smallestRotation finds the smallest lexicographical rotation.
func smallestRotation(s string) string {
	n := len(s)
	if n == 0 {
		return s
	}

	minRotation := s
	for i := 0; i < n; i++ {
		rotation := s[i:] + s[:i]
		if rotation < minRotation {
			minRotation = rotation
		}
	}
	return minRotation
}

