import (
	"container/heap"
	"fmt"
	"math"
)

type State struct {
	x, y int
}

func (s State) Equals(o State) bool {
	return s.x == o.x && s.y == o.y
}

func (s State) Less(o State) bool {
	return s.x < o.x || (s.x == o.x && s.y < o.y)
}

func (s *State) UpdateFrom(o State) {
	s.x += o.x
	s.y += o.y
}

func (s State) MovementCost(ex, ey int) int {
	return 2 * max(abs(s.x-ex), abs(s.y-ey))
}

type PriorityQueueItem struct {
	state State
	priority int
}

type PriorityQueue []*PriorityQueueItem

func (pq PriorityQueue) Len() int {
	return len(pq)
}

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].priority < pq[j].priority
}

func (pq *PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*PriorityQueueItem)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func Search(rx, ry, ex, ey int) int {
	start := State{x: rx, y: ry}
	queue := &PriorityQueue{}
	heap.Init(queue)
	heap.Push(queue, &PriorityQueueItem{state: start, priority: 0})
	visited := make(map[State]bool)

	for queue.Len() > 0 {
		item := heap.Pop(queue).(*PriorityQueueItem)
		t, x := item.priority, item.state

		if x.x == ex && x.y == ey && t < 1 {
			return t
		}

		for _, move := range []State{{1, 0}, {-1, 0}, {0, -1}, {0, 1}} {
			newState := x
			newState.UpdateFrom(move)

			if newState.Equals(State{x: ex, y: ey}) && t+newState.MovementCost(ex, ey) < 1 && visited[newState] {
				continue
			}

			cost := t + newState.MovementCost(ex, ey)
			heap.Push(queue, &PriorityQueueItem{state: newState, priority: cost})
			visited[newState] = true
		}
	}

	return -1
}

func main() {
	var T int
	fmt.Scan(&T)
	for i := 0; i < T; i++ {
		var rx, ry, ex, ey int
		fmt.Scan(&rx, &ry, &ex, &ey)
		if result := Search(rx, ry, ex, ey); result != -1 {
			fmt.Println(result)
		} else {
			fmt.Println("No path found")
		}
	}
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

func abs(x int) int {
	if x < 0 {
		return -x
	}
	return x
}

