)

func solve(edges [][2]int) (int, error) {
	if len(edges) == 0 {
		return 0, errors.New("edges cannot be empty")
	}

	L := make([]int, len(edges))
	R := make([]int, len(edges))

	for i, edge := range edges {
		L[i] = edge[0]
		R[i] = edge[1]
	}

	sort.Ints(L)
	sort.Ints(R)

	start, end := 0, len(R)
	maxRange := L[0]

	check := func(start, end int) bool {
		i := indexOf(L, maxRange)
		count := 0

		for count < end-1 {
			cur := R[i]
			if cur < edges[start][1] {
				// Do nothing, keep current count
			} else {
				count++
			}
			i = indexOf(L, cur)
		}

		return count == end-1
	}

	for end-start > 1 {
		mid := (end + start) / 2
		if check(start, mid) {
			end = mid
		} else {
			start = mid
		}
	}

	if start == end {
		return 0, nil
	}

	for start+1 < end {
		mid := (start + end) / 2
		if check(start, mid) {
			start = mid
		} else {
			end = mid
		}
	}

	return start, nil
}

func indexOf(slice []int, target int) int {
	for i, v := range slice {
		if v == target {
			return i
		}
	}
	log.Printf("Warning: value %d not found in slice\n", target)
	return -1 // or handle error
}

func main() {
	edges := [][2]int{{1, 4}, {2, 3}, {4, 5}, {6, 7}}
	result, err := solve(edges)

	if err != nil {
		log.Fatalf("Error solving edges: %v", err)
	}
	fmt.Printf("Result: %d\n", result)
}

