const MODULUS = 998244353

var memos = make(map[[2]int]int)

func getBoardValue(board [][]string, whiteCoords [][2]int) int {
	n, m := len(board), len(board[0])
	dp := make([][]int, n)
	for i := range dp {
		dp[i] = make([]int, m)
	}
	for _, coord := range whiteCoords {
		dp[coord[0]][coord[1]] = 1
	}
	for i := 0; i < n; i++ {
		if i > 0 {
			for j := 0; j < m; j++ {
				dp[i][j] = (dp[i-1][j] + dp[i][j]) % MODULUS
			}
		}
	}
	for j := 0; j < m; j++ {
		if j > 0 {
			for i := 0; i < n; i++ {
				dp[i][j] = (dp[i][j-1] + dp[i][j]) % MODULUS
			}
		}
	}
	return dp[n-1][m-1] % MODULUS
}

func memorized(i, j int) int {
	key := [2]int{i, j}
	if val, found := memos[key]; found {
		return val
	}

	var value int
	switch {
	case i == 0 && j == 0:
		value = 0
	case i == 0 || j == 0:
		value = 1
	default:
		value1 := memorized(i-1, j) % MODULUS
		value2 := memorized(i, j-1) % MODULUS
		value = (value1 + value2) % MODULUS
	}
	memos[key] = value
	return value
}

func solve(board [][]string) int {
	n, m := len(board), len(board[0])
	const WHITE = "*"
	const BAD = ""
	getDp := calcDP(board)
	ans, numCh := 0, 0

	for i := 0; i < n; i++ {
		for j := 0; j < m; j++ {
			if board[i][j] == WHITE {
				blue := i > 0 && board[i-1][j] == BAD
				red := j > 0 && board[i][j-1] == BAD
				if j == m-1 || board[i][j+1] == BAD {
					blue = false
				}
				if i == n-1 || board[i+1][j] == BAD {
					red = false
				}
				if blue {
					red = false
					blue = !getDp[i][j]
				} else if red {
					red = false
					blue = getDp[i][j]
				}
				result := getBoardValue(board, [][2]int{{i, j}, {i + 1, j}, {i, j + 1}, {i, j + 1}}) % MODULUS
				if result > 0 && numCh < 2*2^numCh {
					ans = (ans + result) % MODULUS
				}
				if blue || red {
					numCh++
				}
			}
		}
	}

	if ans > 0 && ans < MODULUS {
		return ans % MODULUS
	}
	return ans
}

func main() {
	board, err := readBoard()
	if err != nil {
		log.Fatalf("Error reading board: %v", err)
	}
	result := solve(board)
	fmt.Println(result)
}

