func factors(n int) ([]int, error) {
	if n < 1 {
		return nil, errors.New("input must be a positive integer")
	}
	factorSet := make(map[int]struct{})
	for i := 1; i <= int(math.Sqrt(float64(n))); i++ {
		if n%i == 0 {
			factorSet[i] = struct{}{}
			factorSet[n/i] = struct{}{}
		}
	}

	factorList := make([]int, 0, len(factorSet))
	for k := range factorSet {
		factorList = append(factorList, k)
	}
	return factorList, nil
}

type SortedList struct {
	values     [][]int
	listLens   []int
	mins       []int
	fenTree    []int
	load       int
	rebuild    bool
}

func NewSortedList(iterable []int, load int) *SortedList {
	if load <= 0 {
		log.Fatalf("load must be a positive integer")
	}
	sort.Ints(iterable)
	_len := len(iterable)
	lists := make([][]int, 0)

	for i := 0; i < _len; i += load {
		end := i + load
		if end > _len {
			end = _len
		}
		lists = append(lists, iterable[i:end])
	}

	mins := make([]int, len(lists))
	for i, list := range lists {
		mins[i] = list[0]
	}

	return &SortedList{
		values:  lists,
		load:    load,
		listLens: make([]int, len(lists)),
		mins:    mins,
		fenTree: nil,
		rebuild: true,
	}
}

func (s *SortedList) fenBuild() {
	s.fenTree = make([]int, len(s.listLens))
	copy(s.fenTree, s.listLens)

	for i := range s.fenTree {
		if i|i+1 < len(s.fenTree) {
			s.fenTree[i|i+1] += s.fenTree[i]
		}
	}
	s.rebuild = false
}

func (s *SortedList) fenUpdate(index int, value int) {
	if !s.rebuild {
		for index < len(s.fenTree) {
			s.fenTree[index] += value
			index |= index + 1
		}
	}
}

func (s *SortedList) fenQuery(end int) int {
	if s.rebuild {
		s.fenBuild()
	}

	x := 0
	for end > 0 {
		x += s.fenTree[end-1]
		end &= end - 1
	}
	return x
}

