func encrypt(message string, key int) (string, error) {
	if key < 0 {
		return "", errors.New("key must be non-negative")
	}

	var encryptedMessage strings.Builder
	for _, ch := range message {
		if unicode.IsLetter(ch) {
			alpha := int(unicode.ToLower(ch) - 'a' + 1)
			encryptedAlpha := (alpha + key) % 26
			if encryptedAlpha == 0 {
				encryptedAlpha = 26
			}
			if unicode.IsUpper(ch) {
				encryptedMessage.WriteRune(rune(encryptedAlpha + 'A' - 1))
			} else {
				encryptedMessage.WriteRune(rune(encryptedAlpha + 'a' - 1))
			}
		} else {
			encryptedMessage.WriteRune(ch)
		}
	}

	return encryptedMessage.String(), nil
}

func decrypt(message string, key int) (string, error) {
	if key < 0 {
		return "", errors.New("key must be non-negative")
	}

	var decryptedMessage strings.Builder
	for _, ch := range message {
		if unicode.IsLetter(ch) {
			alpha := int(unicode.ToLower(ch) - 'a' + 1)
			decryptedAlpha := (alpha - key) % 26
			if decryptedAlpha <= 0 {
				decryptedAlpha += 26
			}
			if unicode.IsUpper(ch) {
				decryptedMessage.WriteRune(rune(decryptedAlpha + 'A' - 1))
			} else {
				decryptedMessage.WriteRune(rune(decryptedAlpha + 'a' - 1))
			}
		} else {
			decryptedMessage.WriteRune(ch)
		}
	}

	return decryptedMessage.String(), nil
}

