// Calculate XOR value for a list of integers
func xorSum(nums []int) int {
	xorValue := 0
	for _, num := range nums {
		xorValue ^= num
	}
	return xorValue
}

// Implement the Nim game logic
func nimGame(nimValues [][]int) (int, error) {
	information := make(map[int]int)
	for i, nimValue := range nimValues {
		information[i] = xorSum(nimValue)
	}
	xorTotal := xorSum(information)

	if xorTotal == 0 {
		return 0, nil
	}

	minima := int(^uint(0) >> 1) // Max int
	for _, val := range information {
		if val < minima {
			minima = val
		}
	}

	return minima, nil
}

