func isGoodArray(arr []int) bool {
	if len(arr) < 2 {
		return true
	}
	for len(arr) > 1 {
		if arr[0] <= arr[len(arr)-1] {
			if arr[0] <= arr[1] {
				arr = arr[1:]
			} else {
				arr = arr[:len(arr)-1]
			}
		} else {
			if arr[len(arr)-1] >= arr[len(arr)-2] {
				arr = arr[:len(arr)-1]
			} else {
				arr = arr[1:]
			}
		}
	}
	return true
}

func findShortestPrefix(arr []int) int {
	for i := range arr {
		if isGoodArray(arr[i:]) {
			return i
		}
	}
	return len(arr)
