		return packages[i].x < packages[j].x
	})

	var path strings.Builder
	currentX, currentY := 0, 0

	for _, pkg := range packages {
		if pkg.x < currentX || pkg.y < currentY {
			return false, ""
		}
		path.WriteString(strings.Repeat("R", pkg.x-currentX))
		path.WriteString(strings.Repeat("U", pkg.y-currentY))
		currentX, currentY = pkg.x, pkg.y
	}
	return true, path.String()
}

func solve(testCases int) []string {
	results := make([]string, 0)

	for i := 0; i < testCases; i++ {
		var n int
		if _, err := fmt.Scan(&n); err != nil {
			log.Fatalf("Failed to read number of packages: %v", err)
		}

		packages := make([]packagePoint, n)
		for j := 0; j < n; j++ {
			if _, err := fmt.Scan(&packages[j].x, &packages[j].y); err != nil {
				log.Fatalf("Failed to read package coordinates: %v", err)
			}
		}

		possible, path := canCollect(packages)
		if possible {
			results = append(results, "YES", path)
		} else {
			results = append(results, "NO")
		}
	}
	return results
}

func main() {
	var t int
	if _, err := fmt.Scan(&t); err != nil {
		log.Fatalf("Failed to read number of test cases: %v", err)
	}

	results := solve(t)
	for _, result := range results {
		fmt.Println(result)
	}
}

