// Capitalization error messages
const (
	ErrHumanCapitalize = -1
	ErrStartWithNumber  = -2
)

// ValidateAndProcess takes a string input and validates it based on specified conditions.
func ValidateAndProcess(input string) (string, error) {
	if err := validateInput(input); err != nil {
		return "", err
	}

	if !hasHumanCapitalization(input) {
		return "", errors.New("input lacks human capitalization")
	}

	if startsWithNumber(input) {
		return "", errors.New("input starts with a number")
	}

	return input, nil
}

// validateInput checks if the input string is empty.
func validateInput(input string) error {
	if strings.TrimSpace(input) == "" {
		return errors.New("input cannot be empty")
	}
	return nil
}

// hasHumanCapitalization checks if there is at least one capital letter following some lowercase letters.
func hasHumanCapitalization(input string) bool {
	re := regexp.MustCompile(`[a-z]+[A-Z]`)
	return re.MatchString(input)
}

// startsWithNumber checks if the input starts with any digits.
func startsWithNumber(input string) bool {
	re := regexp.MustCompile(`^\d`)
	return re.MatchString(input)
}

// LogError logs error messages for failed validation.
func LogError(err error) {
	if err != nil {
		log.Printf("Error: %s", err)
	}
}

func main() {
	input := "ExampleInput"

	result, err := ValidateAndProcess(input)
	LogError(err)

	if err == nil {
		log.Printf("Successful validation: %s", result)
	}
}

