const maxInt = math.MaxInt32

func traverseDiagonal(matrix [][]int, startI, startJ int) map[int]int {
	i, j := startI, startJ
	countDict := make(map[int]int)
	directionUp := true

	for i < len(matrix) && j >= 0 {
		countDict[matrix[i][j]]++
		if directionUp && i > 0 && j > 0 {
			i--
			j--
		} else if !directionUp && i < len(matrix)-1 && j > 0 {
			i++
			j--
		}

		if !directionUp && (j == 0 || i == len(matrix)-1) {
			directionUp = true
		} else if directionUp && (i == 0 || j == 0) {
			directionUp = false
		}
	}

	return countDict
}

func paintHouses(houses []int, cost [][]int, m, n, target int) (int, error) {
	for i, color := range houses {
		if color == 0 {
			houses[i] = 0
		} else {
			cost[i][houses[i]-1] = -maxInt
		}
	}

	minCost := make([][]int, m)
	for i := range minCost {
		minCost[i] = []int{maxInt, maxInt}
	}

	for i := 0; i < m; i++ {
		if houses[i] != 0 {
			minCost[i][houses[i]-1] = cost[i][houses[i]-1]
		} else {
			minCost[i][0] = 0
		}
		for j := 1; j < n; j++ {
			if houses[i] != j {
				minCost[i][j-1] = cost[i][j-1]
			}
		}
		for j := range minCost[i] {
			for k := 0; k < n; k++ {
				if i > 0 && k != j {
					if minCost[i][j] > minCost[i-1][k]+minCost[i][j] {
						minCost[i][j] = minCost[i-1][k] + minCost[i][j]
					}
				}
			}
		}
	}

	result := minCost[m-1][n-1] * target
	if result > (1<<31)-1 {
		return -1, nil
	}
	return result, nil
}

func main() {
	tests := []struct {
		houses []int
		cost   [][]int
		m, n, target int
		expected int
	}{
		{[]int{0, 0, 0, 0, 0}, [][]int{{1, 10}, {10, 1}, {10, 1}, {1, 10}, {5, 1}}, 5, 2, 3, 9},
		{[]int{0, 2, 1, 2, 0}, [][]int{{1, 10}, {10, 1}, {10, 1}, {1, 10}, {5, 1}}, 5, 2, 3, 11},
		{[]int{0, 0, 0, 0, 0}, [][]int{{1, 10}, {10, 1}, {1, 10}, {10, 1}, {1, 10}}, 5, 2, 5, -1},
	}

	for _, test := range tests {
		result, err := paintHouses(test.houses, test.cost, test.m, test.n, test.target)
		if err != nil {
			fmt.Printf("Error: %v\n", err)
			continue
		}
		if result != test.expected {
			fmt.Printf("Test failed: expected %d, got %d\n", test.expected, result)
		} else {
			fmt.Println("Test passed!")
		}
	}
}

