func minDeletionsToGoodString(s string) int {
    n := len(s)
    if n == 1 || strings.Count(s, ">") == n || strings.Count(s, "<") == n {
        return 0
    }

    leftCount, rightCount := 0, 0

    for _, char := range s {
        if char == '<' {
            leftCount++
        } else {
            break
        }
    }

    for i := n - 1; i >= 0; i-- {
        if s[i] == '>' {
            rightCount++
        } else {
            break
        }
    }

    return n - max(leftCount, rightCount)
}

func max(a, b int) int {
    if a > b {
        return a
    }
    return b
}

