func validateInput(s string, n, k int) error {
	if len(s) != n {
		return fmt.Errorf("length of string does not match n")
	}
	if n <= 0 || k < 0 {
		return fmt.Errorf("n must be greater than 0 and k must be non-negative")
	}
	return nil
}

func checker(s string) int {
	if len(set(s)) == 1 {
		return len(s)
	}
	k := len(s) / 2
	if len(s)%2 == 0 {
		if s[:k] == s[k:] {
			return len(s)
		}
		leftMax := checker(s[:k])
		rightMax := checker(s[k:])
		return max(leftMax, rightMax)
	} else {
		if s[:k] == s[k+1:] {
			return len(s)
		}
		leftMax := checker(s[:k])
		rightMax := checker(s[k+1:])
		return max(leftMax, rightMax)
	}
}

func checker2(s string) int {
	if len(set(s)) == 1 {
		return len(s)
	}
	count := 0
	for i := 0; i < len(s); i++ {
		for j := i + 1; j <= len(s); j++ {
			substring := s[i:j]
			if substring == reverse(substring) {
				count = max(count, len(substring))
			} else {
				n := len(substring)
				if n == 2 {
					count = max(count, n)
				} else {
					validFound := false
					if n%2 == 0 {
						validFound = checkValidity(n, true)
					} else {
						validFound = checkValidity(n, false)
					}
					if validFound {
						count = max(count, n)
					} else {
						count = max(count, n-1)
					}
				}
			}
		}
	}
	return count
}

func reverse(s string) string {
	r := []rune(s)
	for i, j := 0, len(r)-1; i < j; i, j = i+1, j-1 {
		r[i], r[j] = r[j], r[i]
	}
	return string(r)
}

func checkValidity(n int, isEven bool) bool {
	for k := 1; k < 102; k++ {
		if isEven && (n/k)%2 == 0 {
			return true
		} else if !isEven && (n/k)%2 == 1 {
			return true
		}
	}
	return false
}

func set(s string) map[rune]struct{} {
	m := make(map[rune]struct{})
	for _, ch := range s {
		m[ch] = struct{}{}
	}
	return m
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

