func preprocess(s string) [][]int {
	n := len(s)
	freq := make([][]int, n+1)
	for i := range freq {
		freq[i] = make([]int, 26)
	}
	for i := 0; i < n; i++ {
		for j := 0; j < 26; j++ {
			freq[i+1][j] = freq[i][j]
		}
		freq[i+1][s[i]-'a']++
	}
	return freq
}

func isIrreducible(freq [][]int, l, r int) bool {
	if l < 0 || r < 0 || l > r || r >= len(freq)-1 {
		log.Println("Invalid range")
		return false
	}

	numDistinct := 0
	charCount := make([]int, 26)

	for i := 0; i < 26; i++ {
		charCount[i] = freq[r+1][i] - freq[l][i]
		if charCount[i] > 0 {
			numDistinct++
		}
	}

	if len(charCount) == 1 {
		return true
	}
	if numDistinct > 2 {
		return true
	}
	if numDistinct == 2 {
		firstChar := charCount[0] > 0
		lastChar := charCount[25] > 0
		return firstChar != lastChar
	}

	return false
}

func checkIrreducibleAnagram(s string, queries [][]int) []bool {
	freq := preprocess(s)
	results := make([]bool, len(queries))

	for i, query := range queries {
		results[i] = isIrreducible(freq, query[0], query[1])
	}

	return results
}

func main() {
	s := "abcabc"
	queries := [][]int{{0, 5}, {0, 3}, {1, 4}, {2, 2}}
	results := checkIrreducibleAnagram(s, queries)

	for i, result := range results {
		fmt.Printf("Query %d: %v\n", i, result)
	}
}

