func findFourthRobbery(n, m int, grid []string) (int, int, error) {
	if n < 1 || m < 1 || len(grid) != n {
		return 0, 0, errors.New("invalid grid dimensions")
	}

	var asterisks [][2]int
	for i := 0; i < n; i++ {
		if len(grid[i]) != m {
			return 0, 0, errors.New("inconsistent row length")
		}
		for j := 0; j < m; j++ {
			if grid[i][j] == '*' {
				asterisks = append(asterisks, [2]int{i, j})
			}
		}
	}

	if len(asterisks) != 3 {
		return 0, 0, errors.New("expected three asterisks")
	}

	a, b := asterisks[0][0], asterisks[0][1]
	c, d := asterisks[1][0], asterisks[1][1]
	e, f := asterisks[2][0], asterisks[2][1]

	if a == c {
		if b == e {
			return a, f, nil
		} else if b == f {
			return a, e, nil
		}
	} else if b == d {
		if a == e {
			return c, f, nil
		} else if a == f {
			return c, e, nil
		}
	}

	if b == d {
		return e, f, nil
	} else if a == c {
		return f, e, nil
	} else if b == e {
		return f, d, nil
	} else if b == f {
		return e, d, nil
	} else if a == e {
		return c, f, nil
	} else if a == f {
		return c, e, nil
	}

	return 0, 0, errors.New("unable to determine fourth point")
}

func main() {
	n, m := 3, 2
	grid1 := []string{
		".",
		"..",
		"**",
	}
	result1, err := findFourthRobbery(n, m, grid1)
	if err != nil {
		log.Println("Error:", err)
		return
	}
	fmt.Println(result1) // Output: (1, 1)

	n, m = 3, 3
	grid2 := []string{
		"*.*",
		".*.",
		"...",
	}
	result2, err := findFourthRobbery(n, m, grid2)
	if err != nil {
		log.Println("Error:", err)
		return
	}
	fmt.Println(result2) // Output: (2, 3)
}

