func validateInput(args []string) (int, int, []int, error) {
	if len(args) < 2 {
		return 0, 0, nil, fmt.Errorf("not enough arguments")
	}

	n, err := strconv.Atoi(args[0])
	if err != nil {
		return 0, 0, nil, fmt.Errorf("invalid n: %v", err)
	}

	k, err := strconv.Atoi(args[1])
	if err != nil {
		return 0, 0, nil, fmt.Errorf("invalid k: %v", err)
	}

	if len(args)-2 != n {
		return 0, 0, nil, fmt.Errorf("expected %d numbers, got %d", n, len(args)-2)
	}

	a := make([]int, n)
	for i, val := range args[2:] {
		num, err := strconv.Atoi(val)
		if err != nil {
			return 0, 0, nil, fmt.Errorf("invalid number %s: %v", val, err)
		}
		a[i] = num
	}

	return n, k, a, nil
}

func calculate(a []int, n int) int {
	n--
	s := 0
	for _, value := range a[:n+1] {
		s += value
	}

	for j := 0; j <= len(a)-n-1; j++ {
		for x := n; x > j; x-- {
			if a[n+j] > s && n+j > len(a)-1-j {
				return n - j - 1
			}
			a[n+j] = a[len(a)-1-x+j]
		}
	}

	return n - 2
}

func main() {
	if len(os.Args) < 3 {
		fmt.Println("Usage: <program> <n> <k> <numbers>")
		return
	}

	n, k, a, err := validateInput(os.Args[1:])
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	for i := n - 1; i > 0; i-- {
		a = append(a[:0], calculate(a[:i+1], n))
	}

	a = append(a, k-n)
	for i, j := range reverseSlice(a) {
		if j != a[len(a)-1-i] {
			fmt.Println(i + 1)
			break
		}
	}
}

func reverseSlice(a []int) []int {
	n := len(a)
	reversed := make([]int, n)
	for i := 0; i < n; i++ {
		reversed[i] = a[n-1-i]
	}
	return reversed
}

