func canRepresentBST(arr []int) (bool, error) {
	n := len(arr)
	if n == 0 {
		return false, errors.New("array cannot be empty")
	}
	if n == 1 {
		return true, nil
	}

	stack := []int{}
	root := math.MinInt

	for _, value := range arr {
		if value < root {
			return false, nil
		}

		for len(stack) > 0 && stack[len(stack)-1] < value {
			root = stack[len(stack)-1]
			stack = stack[:len(stack)-1]
		}

		stack = append(stack, value)
	}

	return true, nil
}

