// maxLength calculates the length of the longest increasing subsequence in a given string.
func maxLength(S string) (int, error) {
	if len(S) == 0 {
		return 0, errors.New("input string is empty")
	}

	n := len(S)
	dp := make([]int, n)

	// Initialize dp with 1, as every character is an increasing subsequence of length 1
	for i := range dp {
		dp[i] = 1
	}

	// Compute the longest increasing subsequence
	for i := 1; i < n; i++ {
		for j := 0; j < i; j++ {
			if S[i] > S[j] {
				if dp[i] < dp[j]+1 {
					dp[i] = dp[j] + 1
				}
			}
		}
	}

	// Find the maximum value in dp
	maxLen := dp[0]
	for _, length := range dp {
		if length > maxLen {
			maxLen = length
		}
	}

	return maxLen, nil
}

func main() {
	input := "abcde"
	length, err := maxLength(input)
	if err != nil {
