}

func increasingBinaryPatternCounterArray(pat string) (bool, error) {
	if len(pat) == 0 {
		return false, fmt.Errorf("input pattern cannot be empty")
	}

	if !isValidPattern(pat) {
		return false, fmt.Errorf("invalid characters in pattern")
	}

	n := len(pat)
	flipped := false

	for i := 0; i < n; i++ {
		if pat[i] == 'D' {
			break
		}

		if pat[i] != 'I' && pat[i] != 'D' {
			return false, fmt.Errorf("pattern contains unsupported character: %c", pat[i])
		}
	}

	maxCount := 0

	for j := 0; j < n; j++ {
		if pat[j] == 'I' {
			maxCount++
		}
	}

	if maxCount == n {
		return true, nil
	}

	return false, nil
}

func isValidPattern(pat string) bool {
	for _, char := range pat {
		if char != 'I' && char != 'D' {
			return false
		}
	}
	return true
}

