func findMaxValueOfEquation(points [][]int, k int) (int, error) {
    if len(points) == 0 {
        return 0, fmt.Errorf("points array is empty")
    }

    res, mx := 0, math.MinInt
    for j := 0; j < len(points); j++ {
        if j > 0 && points[j][0]-points[j-1][0] > k {
            return res, fmt.Errorf("points too far apart at index %d", j)
        }
        mx = max(mx, points[j][0]-points[j][1])
        res = max(res, mx+points[j][0]+points[j][1])
    }
    return res, nil
}

