// gcd computes the greatest common divisor of two integers using the Euclidean algorithm.
func gcd(a, b int) int {
	for b != 0 {
		a, b = b, a%b
	}
	return a
}

// validateInputs checks if the inputs are in valid ranges.
func validateInputs(n, x1, y1, x2, y2 int) error {
	if n <= 0 {
		return errors.New("n must be a positive integer")
	}
	return nil
}

// findShortestDistance calculates the shortest distance based on given coordinates.
func findShortestDistance(n, x1, y1, x2, y2 int) int {
	u1 := x1 + y1*n
	u2 := x2 + y2*n

	div := gcd(int(math.Abs(float64(u1-u2))), n*n)
	return div
}

