func getPins(pin string) ([]string, error) {
	if len(pin) < 1 || len(pin) > 5 {
		return nil, errors.New("PIN must be between 1 and 5 characters")
	}

	res := make([]string, 0)
	for _, c := range pin {
		switch string(c) {
		case "1":
			res = append(res, "2", "4")
		case "2":
			res = append(res, "1", "3", "5")
		case "3":
			res = append(res, "2", "6")
		case "4":
			res = append(res, "1", "5", "7")
		case "5":
			res = append(res, "2", "4", "6", "8")
		case "6":
			res = append(res, "3", "5", "9")
		case "7":
			res = append(res, "4", "8")
		case "8":
			res = append(res, "5", "7", "9")
		case "9":
			res = append(res, "6", "8")
		case "0":
			res = append(res, "1", "2", "3", "5", "7")
		default:
			log.Printf("Invalid character: %s", string(c))
			return nil, errors.New("invalid character in PIN")
		}
	}

	return generateCombinations(res), nil
}

func generateCombinations(digits []string) []string {
	result := make([]string, 0)
	var combine func(current string, currentIndex int)
	combine = func(current string, currentIndex int) {
		if currentIndex == len(digits) {
			result = append(result, current)
			return
		}
		for _, digit := range digits[currentIndex] {
			combine(current+string(digit), currentIndex+1)
		}
	}

	combine("", 0)
	return result
}

