func processScores(scores []int) (int, error) {
	if len(scores) != 4 {
		return -1, fmt.Errorf("expected 4 scores, got %d", len(scores))
	}

	listSort := make([]int, len(scores))
	copy(listSort, scores)
	sort.Sort(sort.Reverse(sort.IntSlice(listSort)))

	score := listSort[0]
	idx := -1

	for j := range scores {
		if scores[j] == score {
			if idx == -1 {
				idx = j
			} else {
				scores[j] = max(scores)
				scores = removeMax(scores)
			}
		}
	}

	return idx, nil
}

func removeMax(scores []int) []int {
	maxVal := max(scores)
	for i := 0; i < len(scores); i++ {
		if scores[i] == maxVal {
			return append(scores[:i], scores[i+1:]...)
		}
	}
	return scores
}

