// countTriplets counts the triplets in the array that satisfy the condition
func countTriplets(arr []int) (int, error) {
	if len(arr) < 3 {
		return 0, errors.New("array must have at least three elements")
	}

	count := 0
	size := len(arr)

	for i := 0; i < size; i++ {
		for j := i + 1; j < size; j++ {
			if arr[i] < arr[j] {
				for k := j + 1; k < size; k++ {
					if arr[j] < arr[k] {
						count++
					}
				}
			}
		}
	}

	return count, nil
}

