func countSubsequences(m int, s string) (int, error) {
	if len(s) < 3 {
		return 0, errors.New("input string must have at least 3 characters")
	}

	baseMod := int(1e9 + 7)
	k := strings.Count(s, "?")
	var a, b, c int

	if k == 3 {
		possibleStrsWith3Qms := "abc"
		a, b, c = 3, 3, 3
		return a + b + c, nil
	}

	baseCaseCnt := 1
	for i := 0; i < len(s); i++ {
		if s[i] == 'a' || s[i] == '?' {
			if i == 0 {
				baseCaseCnt *= 4
			}
		}
		if s[i] == 'b' || s[i] == '?' {
			if i == 1 {
				baseCaseCnt *= 4
			}
		}
		if s[i] == 'c' || s[i] == '?' {
			if i == 2 {
				baseCaseCnt *= 4
			}
		}
	}

	if baseCaseCnt == 0 {
		return 0, nil
	}

	possibleStrsWith3Qms := filterPossibleCharacters(s, "abc")
	prevA, prevB, prevC := 1, 1, 1
	a, b, c = 0, 0, 0

	for _, letter := range possibleStrsWith3Qms {
		switch letter {
		case 'a':
			a = (prevA + a + b + c) % baseMod
			prevA = (prevA*3 + prevB*3 + prevC*3) % baseMod
			prevB, prevC = 1, 1
		case 'b':
			b = (prevB + a + c) % baseMod
			prevA = (prevA*3 + prevB*3 + prevC*3) % baseMod
			prevB = (prevB*3 + prevA*3 + prevC*3) % baseMod
			prevC = 1
		case 'c':
			c = (prevC + a + b) % baseMod
			prevA = (prevA*3 + prevB*3 + prevC*3) % baseMod
			prevB = (prevB * 3) % baseMod
		}
	}

	result := (a + b + c) % baseMod
	return result, nil
}

func filterPossibleCharacters(s, allow string) string {
	var filtered []rune
	for _, char := range s {
		if strings.ContainsRune(allow, char) || char == '?' {
			filtered = append(filtered, char)
		}
	}
	return string(filtered)
}

func main() {
	m := 5
	s := "a??bc"

	result, err := countSubsequences(m, s)
	if err != nil {
		log.Fatalf("Error counting subsequences: %v", err)
	}
	fmt.Println("Count of subsequences:", result)
}

