func minimumRobots(n int, connections [][]int) (int, error) {
	if n <= 0 {
		return 0, errors.New("n must be a positive integer")
	}
	if len(connections) == 0 {
		return 0, nil
	}

	graph := make(map[int][]int)
	for _, conn := range connections {
		if len(conn) != 2 {
			return 0, errors.New("each connection must have exactly two nodes")
		}
		a, b := conn[0], conn[1]
		graph[a] = append(graph[a], b)
		graph[b] = append(graph[b], a)
	}

	robots := 0
	for i := 0; i < n; i++ {
		if !isNodeExist(graph, i) {
			continue
		}
		visited := make(map[int]struct{})
		visited[i] = struct{}{}
		queue := []pair{{city: i, steps: 0}}

		for len(queue) > 0 {
			current := queue[0]
			queue = queue[1:]

			for _, neighbor := range graph[current.city] {
				if _, ok := visited[neighbor]; !ok {
					visited[neighbor] = struct{}{}
					queue = append(queue, pair{city: neighbor, steps: current.steps + 1})
					if len(visited) == n {
						return robots + 1, nil
					}
				}
			}

			if current.steps == n-1 {
				robots++
				break
			}
		}
	}

	return robots, nil
}

func isNodeExist(graph map[int][]int, node int) bool {
	_, exists := graph[node]
	return exists
}

type pair struct {
	city  int
	steps int
}

func main() {
	n := 5
	connections := [][]int{{0, 1}, {1, 2}, {2, 3}, {3, 4}}
	result, err := minimumRobots(n, connections)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println("Minimum robots needed:", result)
}

