func main() {
	reader := bufio.NewReader(os.Stdin)
	testCases, err := readInt(reader)
	if err != nil {
		fmt.Println("Error reading number of test cases:", err)
		return
	}

	for i := 0; i < testCases; i++ {
		n, err := readInt(reader)
		if err != nil {
			fmt.Println("Error reading array size:", err)
			continue
		}

		arr, err := readIntSlice(reader, n)
		if err != nil {
			fmt.Println("Error reading array values:", err)
			continue
		}

		result, err := calculateDifference(arr)
		if err != nil {
			fmt.Println(err)
		} else {
			fmt.Println(result)
		}
	}
}

func readInt(reader *bufio.Reader) (int, error) {
	line, err := reader.ReadString('\n')
	if err != nil {
		return 0, err
	}
	var number int
	_, err = fmt.Sscanf(line, "%d", &number)
	return number, err
}

func readIntSlice(reader *bufio.Reader, size int) ([]int, error) {
	line, err := reader.ReadString('\n')
	if err != nil {
		return nil, err
	}
	parts := strings.Fields(line)
	if len(parts) != size {
		return nil, fmt.Errorf("expected %d integers, got %d", size, len(parts))
	}

	arr := make([]int, size)
	for i, part := range parts {
		if _, err := fmt.Sscanf(part, "%d", &arr[i]); err != nil {
			return nil, fmt.Errorf("error converting input to integer: %v", err)
		}
	}
	return arr, nil
}

func calculateDifference(arr []int) (int, error) {
	if len(arr) == 0 {
		return 0, fmt.Errorf("array cannot be empty")
	}

	minVal, maxVal := findMinMax(arr)
	if countOccurrences(arr, minVal) == 1 {
		arr = removeElementAtIndex(arr, indexOf(arr, minVal))
		return findMax(arr) - findMin(arr), nil
	} else if countOccurrences(arr, maxVal) == 1 {
		arr = removeElementAtIndex(arr, indexOf(arr, maxVal))
		return findMax(arr) - findMin(arr), nil
	}
	return maxVal - minVal, nil
}

func findMinMax(arr []int) (int, int) {
	minVal, maxVal := arr[0], arr[0]
	for _, value := range arr {
		if value < minVal {
			minVal = value
		}
		if value > maxVal {
			maxVal = value
		}
	}
	return minVal, maxVal
}

func countOccurrences(arr []int, value int) int {
	count := 0
	for _, v := range arr {
		if v == value {
			count++
		}
	}
	return count
}

func indexOf(arr []int, value int) int {
	for i, v := range arr {
		if v == value {
			return i
		}
	}
	return -1
}

func removeElementAtIndex(arr []int, index int) []int {
	if index < 0 || index >= len(arr) {
		return arr
	}
	return append(arr[:index], arr[index+1:]...)
}

func findMin(arr []int) int {
	minVal := arr[0]
	for _, value := range arr {
		if value < minVal {
			minVal = value
		}
	}
	return minVal
}

func findMax(arr []int) int {
	maxVal := arr[0]
	for _, value := range arr {
		if value > maxVal {
			maxVal = value
		}
	}
	return maxVal
}

