func processString(s string, k int) string {
	if len(s) < 3*k {
		return "-1"
	}

	tt1 := s[k : 2*k]
	tt2 := s[2*k : 3*k]
	tr := s

	for tt1 == tt2 {
		if len(tr) <= 2*k {
			return "-1"
		}
		tr = tr[:len(tr)-(2*k)]
		tt1 = tr[k : 2*k]
		tt2 = tr[2*k : 3*k]
	}

	return fmt.Sprintf("%s%s", s[k:2*k], s[:k])
}

