func maxWidthRamp(A []int) int {
    if len(A) == 0 {
        return 0
    }

    stack := []int{}
    n := len(A)

    for i := 0; i < n; i++ {
        if len(stack) == 0 || A[stack[len(stack)-1]] > A[i] {
            stack = append(stack, i)
        }
    }

    maxWidth := 0
    for j := n - 1; j >= 0; j-- {
        for len(stack) > 0 && A[stack[len(stack)-1]] <= A[j] {
            i := stack[len(stack)-1]
            stack = stack[:len(stack)-1]
            if width := j - i; width > maxWidth {
                maxWidth = width
            }
        }
    }

    return maxWidth
}

