func countTuples(t int, testCases [][]interface{}) ([]int, error) {
	if t <= 0 {
		return nil, fmt.Errorf("number of test cases must be positive")
	}

	results := make([]int, t)

	for caseIdx, caseData := range testCases {
		n, ok1 := caseData[0].(int)
		a, ok2 := caseData[1].([]int)
		if !ok1 || !ok2 || n <= 0 || len(a) != n {
			return nil, fmt.Errorf("invalid input for test case %d", caseIdx+1)
		}

		results[caseIdx] = countValidTuples(n, a)
	}

	return results, nil
}

func countValidTuples(n int, a []int) int {
	beforeJ := make([]map[int]int, n)
	for j := range beforeJ {
		beforeJ[j] = make(map[int]int)
	}

	for j := 1; j < n; j++ {
		for i := 0; i < j; i++ {
			beforeJ[j][a[i]]++
		}
	}

	afterK := make([]map[int]int, n)
	for k := range afterK {
		afterK[k] = make(map[int]int)
	}

	for k := n - 2; k >= 0; k-- {
		for l := n - 1; l > k; l-- {
			afterK[k][a[l]]++
		}
	}

	totalCount := 0
	for j := 1; j < n-1; j++ {
		for k := j + 1; k < n; k++ {
			totalCount += beforeJ[j][a[k]] * afterK[k][a[j]]
		}
	}

	return totalCount
}

