func maxDamage(R, C, N int, targets [][]int) (int, error) {
	if R <= 0 || C <= 0 || N < 0 {
		return 0, fmt.Errorf("invalid input values: R=%d, C=%d, N=%d", R, C, N)
	}

	rows := make([]int, R)
	cols := make([]int, C)

	for _, target := range targets {
		if len(target) != 2 {
			return 0, fmt.Errorf("invalid target format: %v", target)
		}
		r, c := target[0], target[1]
		if r < 0 || r >= R || c < 0 || c >= C {
			return 0, fmt.Errorf("target out of bounds: r=%d, c=%d", r, c)
		}
		rows[r]++
		cols[c]++
	}

	maxRow, maxCol := findMax(rows), findMax(cols)

	maxRowIndexes := findIndexes(rows, maxRow)
	maxColIndexes := findIndexes(cols, maxCol)

	for _, target := range targets {
		r, c := target[0], target[1]
		if contains(maxRowIndexes, r) || contains(maxColIndexes, c) {
			return N, nil
		}
	}

	return N - 1, nil
}

func findMax(slice []int) int {
	max := slice[0]
	for _, value := range slice {
		if value > max {
			max = value
		}
	}
	return max
}

func findIndexes(slice []int, value int) []int {
	var indexes []int
	for i, v := range slice {
		if v == value {
			indexes = append(indexes, i)
		}
	}
	return indexes
}

func contains(slice []int, value int) bool {
	for _, v := range slice {
		if v == value {
			return true
		}
	}
	return false
}

