// MinRotationsToPrint calculates the minimum rotations needed to print a given name
func MinRotationsToPrint(name string) (int, error) {
	if len(name) == 0 {
		return 0, errors.New("input name must not be empty")
	}

	totalRotations := 0
	currentLetter := 'a'

	for _, targetLetter := range name {
		clockwiseDistance := abs(int(targetLetter) - int(currentLetter))
		counterclockwiseDistance := 26 - clockwiseDistance
		minDistance := min(clockwiseDistance, counterclockwiseDistance)

		totalRotations += minDistance
		currentLetter = targetLetter
	}

	return totalRotations, nil
}

func abs(value int) int {
	if value < 0 {
		return -value
	}
	return value
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

func main() {
	names := []string{"zeus", "map", "ares"}

	for _, name := range names {
		rotations, err := MinRotationsToPrint(name)
		if err != nil {
			log.Printf("Error calculating rotations for '%s': %v", name, err)
			continue
		}
		fmt.Printf("Minimum rotations to print '%s': %d\n", name, rotations)
	}
}

