// Function to determine the minimum number of swaps to order soldiers
func minSwapsToOrderSoldiers(n int, heights []int) (int, error) {
	if n <= 0 || len(heights) != n {
		return 0, errors.New("invalid input: n must be positive and match the length of heights")
	}

	maxHeight, minHeight := heights[0], heights[0]
	maxIndex, minIndex := 0, 0

	// Identify max and min heights with their indices
	for i, height := range heights {
		if height > maxHeight {
			maxHeight = height
			maxIndex = i
		}
		if height < minHeight {
			minHeight = height
			minIndex = i
		}
	}

	// Find last occurrence of minHeight
	for i := n - 1; i >= 0; i-- {
		if heights[i] == minHeight {
			minIndex = i
			break
		}
	}

	// Calculate swaps needed
	totalSwaps := maxIndex + (n - 1 - minIndex)
	if maxIndex > minIndex {
		totalSwaps--
	}

	return totalSwaps, nil
}

func main() {
	heights := []int{5, 3, 1, 4, 2}
	n := len(heights)

	swaps, err := minSwapsToOrderSoldiers(n, heights)
	if err != nil {
		log.Fatalf("Error: %v", err)
	}

	fmt.Printf("Minimum swaps required: %d\n", swaps)
}

