func countOccurrences(number, digit int) int {
	count := 0
	for i := 1; i <= number; i++ {
		powerResult := strconv.Itoa(int(math.Pow(float64(number), float64(i))))
		count += strings.Count(powerResult, strconv.Itoa(digit))
	}
	return count
}

