func main() {
	A, err := readSet("Enter the elements of the first set:")
	if err != nil {
		log.Fatal(err)
	}

	B, err := readSet("Enter the elements of the second set:")
	if err != nil {
		log.Fatal(err)
	}

	symmetricDifference := symmetricDiff(A, B)

	if len(symmetricDifference) == 1 && symmetricDifference[0] == -1 {
		fmt.Println("Same")
	} else {
		sort.Ints(symmetricDifference)
		for _, element := range symmetricDifference {
			fmt.Println(element)
		}
	}
}

func readSet(prompt string) ([]int, error) {
	fmt.Println(prompt)

	var input string
	if _, err := fmt.Scanln(&input); err != nil {
		return nil, fmt.Errorf("failed to read input: %w", err)
	}

	stringsSlice := strings.Fields(input)
	intSet := make(map[int]struct{})

	for _, str := range stringsSlice {
		num, err := strconv.Atoi(str)
		if err != nil {
			return nil, fmt.Errorf("invalid number %s: %w", str, err)
		}
		intSet[num] = struct{}{}
	}

	result := make([]int, 0, len(intSet))
	for num := range intSet {
		result = append(result, num)
	}

	return result, nil
}

func symmetricDiff(setA, setB []int) []int {
	setMap := make(map[int]struct{})

	for _, num := range setA {
		setMap[num] = struct{}{}
	}
	for _, num := range setB {
		if _, exists := setMap[num]; exists {
			delete(setMap, num)
		} else {
			setMap[num] = struct{}{}
		}
	}

	result := make([]int, 0, len(setMap))
	for num := range setMap {
		result = append(result, num)
	}

	return result
}

