func constructSubsets(N int) ([][]int, error) {
	if N <= 0 {
		return nil, fmt.Errorf("invalid input: N must be positive")
	}

	var subsets [][]int

	if N%2 == 1 {
		for i := 1; i <= N; i++ {
			subset := []int{i, (i+1)%N + 1}
			subsets = append(subsets, subset)
		}
		subset := []int{1, 2, 3}
		subsets = append(subsets, subset)
	} else {
		for i := 1; i <= N; i += 2 {
			subset := []int{i, i + 1}
			subsets = append(subsets, subset)
		}
		for i := 1; i <= N; i += 2 {
			subset := []int{i, (i + 2) % N + 1}
			subsets = append(subsets, subset)
		}
	}
	return subsets, nil
}

func main() {
	var N int
	if _, err := fmt.Scan(&N); err != nil {
		log.Fatalf("failed to read input: %v", err)
	}

	subsets, err := constructSubsets(N)
	if err != nil {
		log.Fatalf("error constructing subsets: %v", err)
	}

	if len(subsets) == 0 {
		fmt.Println("No")
		return
	}

	fmt.Println("Yes")
	fmt.Println(len(subsets))
	for _, subset := range subsets {
		fmt.Print(len(subset), " ")
		for _, elem := range subset {
			fmt.Print(elem, " ")
		}
		fmt.Println()
	}
}

