import (
	"container/heap"
	"fmt"
	"sort"
)

const mod = 1_000_000_007

type Engineer struct {
	efficiency int
	speed      int
}

type MinHeap []int

func (h MinHeap) Len() int           { return len(h) }
func (h MinHeap) Less(i, j int) bool { return h[i] < h[j] }
func (h MinHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *MinHeap) Push(x interface{}) {
	*h = append(*h, x.(int))
}

func (h *MinHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func maxPerformance(n int, speed []int, efficiency []int, k int) int {
	engineers := make([]Engineer, n)
	for i := 0; i < n; i++ {
		engineers[i] = Engineer{efficiency[i], speed[i]}
	}
	sort.Slice(engineers, func(i, j int) bool {
		return engineers[i].efficiency > engineers[j].efficiency
	})

	minHeap := &MinHeap{}
	heap.Init(minHeap)

	speedSum := 0
	maxPerformance := 0

	for i := 0; i < n; i++ {
		if minHeap.Len() >= k {
			speedSum -= heap.Pop(minHeap).(int)
		}
		speedSum += engineers[i].speed
		heap.Push(minHeap, engineers[i].speed)

		currentPerformance := speedSum * engineers[i].efficiency % mod
		if currentPerformance > maxPerformance {
			maxPerformance = currentPerformance
		}
	}

	return maxPerformance
}

func main() {
	n := 6
	speed := []int{2, 10, 3, 1, 5, 8}
	efficiency := []int{5, 4, 3, 9, 7, 2}
	k := 3

	result := maxPerformance(n, speed, efficiency, k)
	fmt.Println(result)
}

