func canFormConsecutiveSegment(points []int) string {
    n := len(points)
    if n == 1 {
        return "YES"
    }

    for i := 1; i < n-1; i++ {
        if points[i]-points[i-1] > 2 || points[i+1]-points[i] > 2 {
            return "NO"
        }
    }

    if points[1]-points[0] > 2 || points[n-1]-points[n-2] > 2 {
        return "NO"
    }

    return "YES"
}

func main() {
    reader := bufio.NewReader(os.Stdin)
    firstLine, err := reader.ReadString('\n')
    if err != nil {
        fmt.Fprintln(os.Stderr, "Error reading input:", err)
        os.Exit(1)
    }

    t, err := strconv.Atoi(firstLine[:len(firstLine)-1])
    if err != nil {
        fmt.Fprintln(os.Stderr, "Invalid number of test cases:", err)
        os.Exit(1)
    }

    results := make([]string, 0, t)

    for i := 0; i < t; i++ {
        line, err := reader.ReadString('\n')
        if err != nil {
            fmt.Fprintln(os.Stderr, "Error reading input:", err)
            return
        }

        parts := splitStringToInts(line)
        if len(parts) == 0 {
            fmt.Fprintln(os.Stderr, "Invalid point data")
            return
        }

        result := canFormConsecutiveSegment(parts)
        results = append(results, result)
    }

    for _, result := range results {
        fmt.Println(result)
    }
}

func splitStringToInts(input string) []int {
    values := make([]int, 0)
    strValues := bufio.NewScanner(strings.NewReader(input))
    for strValues.Scan() {
        val, err := strconv.Atoi(strValues.Text())
        if err != nil {
            fmt.Fprintln(os.Stderr, "Invalid input, not a number:", strValues.Text())
            continue
        }
        values = append(values, val)
    }
    return values
}

