func onlyFirstAndLastAreSet(n int) (int, error) {
	if n < 0 {
		return 0, errors.New("input must be a non-negative integer")
	}

	c := 0
	ln := n

	// Count set bits
	for n != 0 {
		if n&1 != 0 {
			c++
			if c > 1 {
				break
			}
		}
		n >>= 1
	}

	if c != 2 {
		return 0, nil
	}

	n = ln
	c = 0

	// Ensure only first and last bits are set
	for n != 0 {
		if n&1 != 0 {
			if n != 1 && n&2 != 0 {
				return 0, nil
			}
		}
		n >>= 1
	}

	return 1, nil
}

func main() {
	testCases := []int{1100101, 2, 12, 1, 15, 10, 2, 3}

	for _, n := range testCases {
		result, err := onlyFirstAndLastAreSet(n)
		if err != nil {
			log.Printf("Error processing %d: %v\n", n, err)
			continue
		}
		fmt.Printf("Input: %d, Output: %d\n", n, result)
	}
}

