func maxAlternatingSum(t int, n int, a []int) (int, error) {
    if t <= 0 || n <= 0 || len(a) != n {
        return 0, errors.New("invalid input parameters")
    }

    sum := 0
    currentMax := a[0]

    for i := 1; i < n; i++ {
        if i%2 == 0 {
            sum += currentMax
            if a[i] > currentMax {
                currentMax = a[i]
            }
        } else {
            sum -= a[i]
        }
    }

    sum += currentMax
    return sum, nil
}

func main() {
    t := 1
    n := 5
    a := []int{1, 2, 3, 4, 5}

    result, err := maxAlternatingSum(t, n, a)
    if err != nil {
        log.Fatalf("Error: %v", err)
    }
    fmt.Printf("Maximum Alternating Sum: %d\n", result)
}

