)

func ans(n int, a []int) int {
	if n == 0 {
		return 0
	}

	sort.Ints(a)
	i := 0
	for i < n && a[i] == 0 {
		i++
	}
	if i == n {
		return 0
	}

	j := i
	for j < n && a[j] == a[i] {
		j++
	}
	return a[i] + ans(n-j, a[j:])
}

func main() {
	var t int
	if _, err := fmt.Scan(&t); err != nil {
		log.Fatalf("Failed to read number of test cases: %v", err)
	}

	for i := 0; i < t; i++ {
		var n int
