			log.Fatalf("Failed to read n for test case %d: %v", i+1, err)
		}

		a := make([]int, n)
		for j := 0; j < n; j++ {
			if _, err := fmt.Scan(&a[j]); err != nil {
				log.Fatalf("Failed to read element a[%d] for test case %d: %v", j, i+1, err)
			}
		}

		result := ans(n, a)
		fmt.Println(result)
	}
}

