func minimumCoins(coins []int) (int, error) {
	if len(coins) == 0 {
		return 0, errors.New("coin list cannot be empty")
	}

	sort.Sort(sort.Reverse(sort.IntSlice(coins)))
	yourSum, twinSum, coinsTaken := 0, sum(coins), 0

	for _, coin := range coins {
		yourSum += coin
		twinSum -= coin
		coinsTaken++
		if yourSum > twinSum {
			return coinsTaken, nil
		}
	}

	return coinsTaken, nil
}

func sum(coins []int) int {
	total := 0
	for _, coin := range coins {
		total += coin
	}
	return total
}

func main() {
	var n int
	_, err := fmt.Scan(&n)
	if err != nil || n <= 0 {
		log.Fatal("invalid input for number of coins")
	}

	coins := make([]int, n)
	for i := 0; i < n; i++ {
		_, err := fmt.Scan(&coins[i])
		if err != nil {
			log.Fatal("invalid input for coins")
		}
	}

	coinsTaken, err := minimumCoins(coins)
	if err != nil {
		log.Fatal(err)
	}

	fmt.Println(coinsTaken)
}

