// processKeystrokes processes a string of keystrokes
func processKeystrokes(s string) (string, error) {
	if !isValidInput(s) {
		return "", fmt.Errorf("invalid input: only '0', '1', and 'B' are allowed")
	}

	var result []rune
	for _, char := range s {
		switch char {
		case '0', '1':
			result = append(result, char)
		case 'B':
			if len(result) > 0 {
				result = result[:len(result)-1]
			}
		default:
			return "", fmt.Errorf("unexpected character: %c", char)
		}
	}
	return string(result), nil
}

// isValidInput checks if the input string contains valid characters
func isValidInput(s string) bool {
	for _, char := range s {
		if !strings.ContainsRune("01B", char) {
			return false
		}
	}
	return true
}

func main() {
	var input string
	fmt.Print("Enter keystrokes: ")
	if _, err := fmt.Scan(&input); err != nil {
		log.Fatalf("Error reading input: %v", err)
	}

	output, err := processKeystrokes(input)
	if err != nil {
		log.Fatalf("Error processing keystrokes: %v", err)
	}

	fmt.Println(output)
}

