import (
    "bufio"
    "fmt"
    "os"
    "strconv"
)

const inf = 1e18

func main() {
    scanner := bufio.NewScanner(os.Stdin)
    scanner.Split(bufio.ScanLines)

    if !scanner.Scan() {
        fmt.Println("Error reading input")
        return
    }

    t, err := strconv.Atoi(scanner.Text())
    if err != nil {
        fmt.Println("Invalid number of test cases")
        return
    }

    for ; t > 0; t-- {
        if !scanner.Scan() {
            fmt.Println("Error reading string")
            return
        }

        s := scanner.Text()
        l := len(s)
        si := reverseString(s)

        ans := calculateScore(s, l)

        book := make([]int, l+1)
        j := 0
        for i := 0; i < l; i++ {
            book[j] = 1
            j++
            if si[i] == '1' {
                break
            }
        }
        j = l
        for i := 0; i < l; i++ {
            book[j] = 1
            j--
            if s[i] == '1' {
                break
            }
        }

        pred := make([]int, l+1)
        pred[l] = l + 1
        book = append([]int{0}, book...)

        for i := l; i >= 0; i-- {
            pred[i] = pred[i+1]
            if book[i] == 0 {
                pred[i] = i
            }
        }

        lpo := make([]bool, l+2)
        for i := 1; i <= l; i++ {
            mul := l + 2 - i
            mex := i - 1
            for j := 0; j < i; j++ {
                if lpo[j] && lpo[j+1] {
                    x := i - 1 - j
                    if x < pow(2, mul) {
                        mex = x
                        break
                    }
                }
            }
            if mex == 0 {
                lpo[i] = true
            } else {
                lpo[i] = false
            }
        }
    }
}

func calculateScore(s string, l int) int {
    ans := 0
    for i, x := range s {
        if x == '1' {
            ans += pow(2, l-i)
        }
    }
    return ans
}

func reverseString(s string) string {
    runes := []rune(s)
    for i, j := 0, len(runes)-1; i < j; i, j = i+1, j-1 {
        runes[i], runes[j] = runes[j], runes[i]
    }
    return string(runes)
}

func pow(base, exp int) int {
    if exp == 0 {
        return 1
    }
    result := 1
    for exp > 0 {
        result *= base
        exp--
    }
    return result
}

