	"math"
	"strconv"
	"strings"
)

func main() {
	X := `4 6
1 3 2
7 13 10
18 20 13
3 4 2
0
1
2
3
5
8`

	inputLines := strings.Split(strings.TrimSpace(X), "\n")
	if len(inputLines) < 2 {
		log.Fatal("Input must contain at least roadwork and distance information")
	}

	firstLine := strings.Fields(inputLines[0])
	if len(firstLine) != 2 {
		log.Fatal("First line must contain two integers")
	}

	readingCases, err := strconv.Atoi(firstLine[0])
	if err != nil {
		log.Fatalf("Invalid number of reading cases: %v", err)
	}

	numQueries, err := strconv.Atoi(firstLine[1])
	if err != nil {
		log.Fatalf("Invalid number of queries: %v", err)
	}

	roadwork := make(map[int]int)
	roadworksT := make(map[int]struct{})

	for i := 1; i <= readingCases; i++ {
		roadworkData := strings.Fields(inputLines[i])
		if len(roadworkData) != 3 {
			log.Fatalf("Invalid roadwork data on line %d", i+1)
		}

		start, err := strconv.Atoi(roadworkData[0])
		if err != nil {
			log.Fatalf("Invalid start position: %v", err)
		}

		end, err := strconv.Atoi(roadworkData[1])
		if err != nil {
			log.Fatalf("Invalid end position: %v", err)
		}

		roadwork[start] = end
		roadworksT[end] = struct{}{}
	}

	results := []int{}

	for _, queryStr := range inputLines[readingCases+1:] {
		D, err := strconv.Atoi(queryStr)
		if err != nil {
			log.Fatalf("Invalid query distance: %v", err)
		}

		x := D
		T := math.Inf(-1)
		roadworks := false

		for start, end := range roadwork {
			startF := float64(start) + 0.5
			roadworkActive := (end > D && start < D+1) || (end > start && end > D && end <= D+1)

			if roadworkActive {
				if x < D {
					x = D + D
				}
				if T < startF {
					T = startF + float64(end)
				}
				roadworks = true
			} else {
				x = roadworkAdjustment(x, startF, T, D)
				if T < 0 {
					T = float64(start) + float64(end)
				}
			}
		}

		if x < 0 || !roadworks {
			results = append(results, -1)
		} else {
			results = append(results, x)
		}
	}

	for _, result := range results {
		fmt.Println(result)
	}
}

func roadworkAdjustment(x, start, T, D float64) float64 {
	if !(D+0.5 > start && start > D-0.5) {
		return x
	}
	if start > D+1 {
		return T
	}
	if T < x && start < x && x < T {
		return T
	}
	if D <= start-0.5 {
		return x + D
	} 
	if x < start-0.5 && start-0.5 < x+D {
		return x - D
	}
	return x
}

