func permutationEquation(p []int) ([]int, error) {
    length := len(p)
    result := make([]int, length)
    indexMap := make(map[int]int)

    for i, v := range p {
        indexMap[v] = i + 1
    }

    for i := 1; i <= length; i++ {
        if pos, exists := indexMap[i]; exists {
            result[i-1] = indexMap[pos]
        } else {
            return nil, fmt.Errorf("value %d not found in permutation array", i)
        }
    }
    return result, nil
}

func main() {
    reader := bufio.NewReader(os.Stdin)
    writer := bufio.NewWriter(os.Stdout)
    defer writer.Flush()

    var n int
    if _, err := fmt.Fscan(reader, &n); err != nil {
        fmt.Fprintf(os.Stderr, "error reading n: %v\n", err)
        return
    }

    p := make([]int, n)
    for i := 0; i < n; i++ {
        if _, err := fmt.Fscan(reader, &p[i]); err != nil {
            fmt.Fprintf(os.Stderr, "error reading permutation value at index %d: %v\n", i, err)
            return
        }
    }

    result, err := permutationEquation(p)
    if err != nil {
        fmt.Fprintf(os.Stderr, "error calculating permutation equation: %v\n", err)
        return
    }

    for _, val := range result {
        fmt.Fprintln(writer, val)
    }
}

