// isPrime checks if a number is prime
func isPrime(num int) bool {
	if num <= 1 {
		return false
	}
	if num <= 3 {
		return true
	}
	if num%2 == 0 || num%3 == 0 {
		return false
	}
	for i := 5; i*i <= num; i += 6 {
		if num%i == 0 || num%(i+2) == 0 {
			return false
		}
	}
	return true
}

// lastDigitOfSum calculates the last digit of the sum of primes up to n
func lastDigitOfSum(n int) int {
	if n < 2 {
		return 0
	}
	primeSum := 0
	for i := 2; i <= n; i++ {
		if isPrime(i) {
			primeSum += i
		}
	}
	return primeSum % 10
}

