func checkInflation(prices []int, k, n int) int {
	totalPrice := sum(prices)
	for i := 0; i < n; i++ {
		if prices[i] / (totalPrice - sum(prices[:i])) * 100 > k {
			inflation := (totalPrice - sum(prices[:i])) / ((100 / k) - 1)
			prices[i] += inflation - prices[i]
		}
	}
	return sum(prices) - totalPrice
}

