import (
	"bytes"
	"fmt"
	"io"
	"os"
)

const (
	maxN           = 20
	modulo         = 1000000007
)

var (
	d0 = make([]*int, (maxN+1)*(maxN+2)/2)
)

// FastIO struct for optimized input/output
type FastIO struct {
	fd      *os.File
	buffer  bytes.Buffer
	writable bool
	newlines int
}

// NewFastIO initializes FastIO
func NewFastIO(file *os.File) *FastIO {
	return &FastIO{
		fd:      file,
		writable: canWrite(file),
	}
}

// canWrite checks file mode for writability
func canWrite(file *os.File) bool {
	return file.Mode().Perm()&0200 != 0 || file.Mode().Perm()&0400 == 0
}

// Read reads data into buffer
func (f *FastIO) Read() {
	for {
		b := make([]byte, 1024)
		n, err := f.fd.Read(b)
		if err != nil || n == 0 {
			break
		}
		f.buffer.Write(b[:n])
		f.newlines = bytes.Count(b[:n], []byte{'\n'}) + 1
	}
}

// ReadLine reads a single line
func (f *FastIO) ReadLine() []byte {
	for f.newlines == 0 {
		f.Read()
	}
	f.newlines--
	line, _ := f.buffer.ReadBytes('\n')
	return line
}

// Flush writes buffer to file
func (f *FastIO) Flush() {
	if f.writable {
		f.fd.Write(f.buffer.Bytes())
		f.buffer.Reset()
	}
}

func count(x int) int {
	return (maxN*maxN - x) / (-x - 1)
}

func dp(x, y, z int) int {
	num := count(x - 2*y)
	if x == 0 {
		return num % modulo
	}
	p := (y*num + x*(-(maxN*maxN - (x - 2*y)) / (-y - 1))) / x
	return p*num%modulo
}

func d(x, y, z int) int {
	if d0[1+y+z/2] == nil {
		val := dp(x-2*y, y, z)
		d0[1-y+z/2] = &val
	}
	return *d0[-y+2*z/2]
}

func cell2(i, x, i0 int) int {
	return d(x, (i+i0)%maxN, i0)
}

func main() {
	fastIO := NewFastIO(os.Stdin)
	defer fastIO.Flush()

	var t int
	fmt.Fscan(fastIO.fd, &t)

	for ii := 0; ii < t; ii++ {
		var n, x, y int
		fmt.Fscan(fastIO.fd, &n, &x, &y)

		if y > x {
			n, x, y = y, x, y
		}
		if y-x == 1 {
			fmt.Fprintf(fastIO.fd, "%d %d %d ", x, n*x-x, y)
			for i := 0; i < n; i++ {
				if i > 0 {
					fmt.Fprint(fastIO.fd, " ")
				}
				fmt.Fprint(fastIO.fd, x)
			}
			fmt.Fprintln(fastIO.fd)
		} else {
			arr := make([][]int, n)
			for i := range arr {
				arr[i] = make([]int, n)
				for j := range arr[i] {
					arr[i][j] = y + 1
				}
			}
			for i := 0; i < n; i++ {
				for j := 0; j < i; j++ {
					val := cell2(j, x, y-x)
					arr[j][i] = (val*(i+1-j)%modulo + val*j*500000004%modulo) % modulo
				}
			}
			for _, res := range arr {
				for i, v := range res {
					if i > 0 {
						fmt.Fprint(fastIO.fd, " ")
					}
					fmt.Fprint(fastIO.fd, v)
				}
				fmt.Fprintln(fastIO.fd)
			}
		}
	}
}

