func solve(t string) (string, error) {
    m := len(t)
    if m == 0 {
        return "", errors.New("input string is empty")
    }

    for k := 1; k < m; k++ {
        pattern := fmt.Sprintf(".*%s{%d,}", t[k:], m-k)
        matched, err := regexp.MatchString(pattern, t)
        if err != nil {
            log.Printf("Error matching pattern: %v", err)
            return "", err
        }
        if matched {
            return t[k:], nil
        }
    }
    return string(t[0]) * m, nil
}

