import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
)

// Invert function inverts the values of the provided slice.
func Invert(lst []int) ([]int, error) {
	if lst == nil {
		return nil, fmt.Errorf("input slice cannot be nil")
	}

	result := make([]int, len(lst))
	for i, v := range lst {
		result[i] = -v
	}
	return result, nil
}

// Input structure for the HTTP handler.
type Input struct {
	Numbers []int `json:"numbers"`
}

// Response structure for the HTTP handler.
type Response struct {
	Inverted []int `json:"inverted"`
}

// InvertHandler handles the HTTP request to invert a list of numbers.
func InvertHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Invalid request method", http.StatusMethodNotAllowed)
		return
	}

	var input Input
	if err := json.NewDecoder(r.Body).Decode(&input); err != nil {
		http.Error(w, "Bad request: invalid input", http.StatusBadRequest)
		return
	}
	defer r.Body.Close()

	inverted, err := Invert(input.Numbers)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	response := Response{Inverted: inverted}
	w.Header().Set("Content-Type", "application/json")
	if err := json.NewEncoder(w).Encode(response); err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/invert", InvertHandler)
	log.Println("Server started at :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}

