func minCost(s string, cost []int) (int, error) {
	n := len(s)
	if n == 0 || len(cost) != n {
		return 0, errors.New("input string and cost slice must be non-empty and of the same length")
	}
	if n == 1 {
		return 0, nil
	}

	dp := make([]int, n)
	dp[0] = cost[0]

	for i := 1; i < n; i++ {
		if s[i] == s[i-1] {
			dp[i] = dp[i-2] + 2*cost[i]
		} else {
			dp[i] = min(dp[i-1]+cost[i], dp[i-2]+cost[i])
		}
	}

	return dp[n-1], nil
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

