	for i, s := range strs {
		num, err := strconv.Atoi(s)
		if err != nil {
			return nil, fmt.Errorf("parse error: %w", err)
		}
		ints[i] = num
	}
	return ints, nil
}

func countMatches(S []int, T []int) int {
	count := 0
	for _, val := range T {
		if binarySearch(S, val) {
			count++
		}
	}
	return count
}

func binarySearch(lst []int, val int) bool {
	left, right := 0, len(lst)-1
	for left <= right {
		mid := (left + right) / 2
		if lst[mid] == val {
			return true
		} else if lst[mid] < val {
			left = mid + 1
		} else {
			right = mid - 1
		}
	}
	return false
}

