func iq(r, c, k int) int {
	rEven := r%2 == 0
	cEven := c%2 == 0

	newR := (r/2)*2 + boolToInt(!rEven)
	newC := (c/2)*2 + boolToInt(!cEven)

	total := ((newR * newC) + (r * c) - (newR * newC)) * k

	return total + r + c + 2
}

func boolToInt(b bool) int {
	if b {
		return 1
	}
	return 0
}

