		log.Fatalf("Error reading number of messages: %v", err)
	}

	for i := 0; i < n; i++ {
		var message string
		if _, err := fmt.Scan(&message); err != nil {
			log.Printf("Error reading message: %v", err)
			continue
		}
		decoded := decodeString(message)
		fmt.Println(decoded)
	}
}

func decodeString(message string) string {
	n := len(message)
	if n == 1 {
		return message
	}

	decoded := make([]byte, n)
	for j := 0; j < n; j++ {
		var index int
		if j < n/2 {
			index = n - (j + 1)
		} else if j == n/2 {
			if n%2 != 0 {
				index = j
			} else {
				index = j - 1
			}
		} else {
			index = n - (j-n/2) - 2
		}
		decoded[j] = message[index]
	}
	return string(decoded[n-1 : -1])
}

