func getSplitIndices(A []int) []int {
	splitIndex := []int{}
	for i := 1; i < len(A); i++ {
		if A[i] != A[i-1] {
			splitIndex = append(splitIndex, i)
		}
	}
	return splitIndex
}

func countZeros(A []int) int {
	count := 0
	for _, a := range A {
		if a == 0 {
			count++
		}
	}
	return count
}

func calculateTotal(A []int, splitIndex []int) int {
	total := 0
	for i := range splitIndex {
		var index int
		if splitIndex[i] != 0 {
			index = splitIndex[i] - 1
		} else {
			index = splitIndex[i]
		}
		total += A[index]
		if index+1 < len(A) {
			total += A[index+1]
		}
	}
	return total
}

