// Stop represents a stop with its capacity.
type Stop struct {
	ID       int
	Capacity int
}

// CalcMinCapacity calculates the maximum capacity required at stops.
func CalcMinCapacity(stops []Stop) (int, error) {
	if len(stops) == 0 {
		return 0, errors.New("no stops provided")
	}

	maxCapacity := 0

	for _, stop := range stops {
		if stop.Capacity < 0 {
			return 0, errors.New("invalid capacity value: cannot be negative")
		}
		if stop.Capacity > maxCapacity {
			maxCapacity = stop.Capacity
		}
	}

	return maxCapacity, nil
}

