// ValidateInput checks if N and M are positive integers.
func ValidateInput(N, M int) error {
	if N <= 0 || M <= 0 {
		return fmt.Errorf("N and M must be positive integers")
	}
	return nil
}

// GCD computes the greatest common divisor of a and b.
func GCD(a, b int) int {
	if b == 0 {
		return a
	}
	return GCD(b, a%b)
}

// CalculateS calculates the final sum based on the algorithm.
func CalculateS(N, M int) int {
	count := 0
	ll := N * M
	a := make([][]int, M)
	b := make([][]int, M)

	for i := range a {
		a[i] = make([]int, N)
		b[i] = make([]int, N)
		for j := 0; j < N; j++ {
			a[i][j] = M*j + i
			b[i][j] = M*j + i
		}
	}

	S := 0
	for i := 0; i < ll/2; i++ {
		for j := 0; j <= i; j++ {
			count += GCD(a[i][j], b[i][j])
			if a[i][j] <= N && b[i][j] <= N {
				S++
			}
		}
	}
	l, r := 0, ll/2
	for k := 0; k < (ll/2-1)*2; k++ {
		S += (r - l) * count
		l++
		r++
	}
	return S / 4
}

func main() {
	var N, M int
	_, err := fmt.Scan(&N, &M)
	if err != nil {
		log.Fatalf("Error reading input: %v", err)
		os.Exit(1)
	}

	if err := ValidateInput(N, M); err != nil {
		log.Fatalf("Validation Error: %v", err)
		os.Exit(1)
	}

	result := CalculateS(N, M)
	fmt.Println(result)
}

