func largestSumCycle(N int, Edge []int) (int, error) {
	if N <= 0 {
		return -1, errors.New("N must be a positive integer")
	}
	if len(Edge) != N {
		return -1, errors.New("Edge length must match N")
	}

	adj := make([][]int, N)
	for i, v := range Edge {
		if v >= 0 {
			adj[i] = append(adj[i], v)
		}
	}

	color := make([]int, N)
	parent := make([]int, N)
	for i := range parent {
		parent[i] = -1
	}
	largestSumCycle := -1 << 63 // min int

	var dfs func(cur, prev, curSum int) 
	dfs = func(cur, prev, curSum int) {
		color[cur] = 1
		for _, nxt := range adj[cur] {
			if nxt == prev {
				continue
			}
			if nxt == -1 || nxt == parent[cur] {
				if nxt != -1 {
					largestSumCycle = max(largestSumCycle, curSum+nxt)
				}
			} else if color[nxt] == 0 {
				parent[nxt] = cur
				dfs(nxt, cur, curSum+cur)
			} else if color[nxt] == 1 {
				largestSumCycle = max(largestSumCycle, curSum+nxt)
			}
		}
		color[cur] = 2
	}

	for i := 0; i < N; i++ {
		if color[i] == 0 {
			parent[i] = i
			dfs(i, -1, i)
		}
	}

	if largestSumCycle == -1<<63 {
		return -1, nil
	}
	return largestSumCycle, nil
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

func main() {
	edge := []int{1, 2, -1, 4, 5}
	result, err := largestSumCycle(5, edge)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println("Largest Sum Cycle:", result)
}

