type Solution struct{}

func (s *Solution) NextGreaterNums(nums []int) ([]int, error) {
	if nums == nil {
		return nil, fmt.Errorf("input cannot be nil")
	}

	res := make([]int, len(nums))
	for i := range res {
		res[i] = -1
	}

	for i, num := range nums {
		stack := []pair{{num, i}}
		nextNum := -1

		for len(stack) > 0 {
			cur, idx := stack[len(stack)-1].value, stack[len(stack)-1].index
			stack = stack[:len(stack)-1]
			nextNum = -1

			for nextNum == -1 && len(stack) > 0 && stack[len(stack)-1].value <= cur {
				nextNum, idx = stack[len(stack)-1].value, stack[len(stack)-1].index
				stack = stack[:len(stack)-1]
			}

			if nextNum == -1 {
				res[idx] = -1
			} else {
				res[idx] = nextNum
			}

			stack = append(stack, pair{cur, idx})
			if nextNumIndex, err := s.findLargerNumberAndIndex(cur, nums, idx+1, len(nums)-1); err == nil {
				stack = append(stack, nextNumIndex)
			}
		}

		if res[i] != -1 {
			for len(stack) > 0 {
				nextNum, idx := stack[len(stack)-1].value, stack[len(stack)-1].index
				stack = stack[:len(stack)-1]

				cur := nextNum
				for nextNum != -1 && len(stack) > 0 && stack[len(stack)-1].value < cur {
					stack = stack[:len(stack)-1]
					if len(stack) > 0 {
						cur = stack[len(stack)-1].value
					}
				}
				res[idx] = cur
				stack = append(stack, pair{cur, idx})
			}
		}
	}

	return res, nil
}

func (s *Solution) findLargerNumberAndIndex(targetNumber int, arr []int, right, left int) (pair, error) {
	if right > len(arr) || left < 0 {
		return pair{}, fmt.Errorf("index out of bounds")
	}

	for index := left; index >= right; index-- {
		if arr[index] > targetNumber {
			return pair{arr[index], index}, nil
		}
	}
	return pair{-1, -1}, nil
}

type pair struct {
	value int
	index int
}

func main() {
	solution := &Solution{}

	cases := [][]int{
		{1, 2, 3, 2, 2, 1},
		{1, 3, 2, 4, 3, 6, 5},
		{1},
		{1, 2, 3, 4, 5, 4},
	}

	for _, n := range cases {
