	end   int
}

func chaptersToRead(chapters []Chapter, page int) int {
	notReadChapters := 0
	for _, chapter := range chapters {
		if chapter.end < page {
			notReadChapters++
		} else {
			break
		}
	}
	return len(chapters) - notReadChapters
}

