// Validate input and convert to integer slice
func parseInput(input string) ([]int, error) {
	var nums []int
	strs := strings.Fields(input)
	for _, str := range strs {
		num, err := strconv.Atoi(str)
		if err != nil {
			return nil, fmt.Errorf("invalid input: %s", str)
		}
		nums = append(nums, num)
	}
	return nums, nil
}

// Sort in decreasing order
func sortDescending(nums []int) []int {
	sort.Sort(sort.Reverse(sort.IntSlice(nums)))
	return nums
}

// Calculate result based on the sorted slice
func calculateResult(nums []int) (int, error) {
	if len(nums) < 2 {
		return 0, fmt.Errorf("not enough elements in the slice")
	}
	half := len(nums) / 2
	greatest := nums[:half]
	smallest := nums[half:]

	topmost := greatest[0]
	bottommost := smallest[0]
	return nums[1] - (topmost - bottommost), nil
}

func main() {
	var input string
	fmt.Print("Enter numbers separated by space: ")
	_, err := fmt.Scanln(&input)
	if err != nil {
		log.Fatalf("Input error: %v", err)
	}

	nums, err := parseInput(input)
	if err != nil {
		log.Println(err)
		return
	}

	nums = sortDescending(nums)

	result, err := calculateResult(nums)
	if err != nil {
		log.Println(err)
		return
	}

	fmt.Println(result)
}

