// maxTeamSize calculates the maximum size of a team that can be formed.
func maxTeamSize(n int, a []int) (int, error) {
	if n <= 0 {
		return 0, fmt.Errorf("n must be a positive integer")
	}
	if len(a) != n {
		return 0, fmt.Errorf("length of array 'a' must equal 'n'")
	}

	sort.Ints(a)
	ans := 0

	for i, x := range a {
		y := upperBound(a, x+5, i)
		ans = max(ans, y-i)
	}
	return ans, nil
}

// upperBound finds the index of the first element greater than upper.
func upperBound(a []int, upper int, start int) int {
	left, right := start, len(a)
	for left < right {
		mid := (left + right) / 2
		if a[mid] > upper {
			right = mid
		} else {
			left = mid + 1
		}
	}
	return left
}

// max returns the greater of two integers.
func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

