type HTMLParser struct {
	Tag     string
	Attrs   []string
}

func (p *HTMLParser) HandleStartTag(tag string, attrs map[string]string) {
	p.Tag = tag
	for k, v := range attrs {
		p.Attrs = append(p.Attrs, fmt.Sprintf("-> %s > %s", k, v))
	}
	p.PrintAttributes()
}

func (p *HTMLParser) PrintAttributes() {
	if len(p.Attrs) > 0 {
		fmt.Println(p.Tag)
		fmt.Println(strings.Join(p.Attrs, "\n"))
	} else {
		fmt.Println(p.Tag)
	}
}

func FeedHTML(input string) error {
	decoder := html.NewTokenizer(strings.NewReader(input))
	for {
		tt := decoder.Next()
		switch tt {
		case html.ErrorToken:
			return nil
		case html.StartTagToken, html.SelfClosingTagToken:
			t := decoder.Token()
			attrs := make(map[string]string)
			for _, attr := range t.Attr {
				attrs[attr.Key] = attr.Val
			}
			parser := &HTMLParser{}
			parser.HandleStartTag(t.Data, attrs)
		}
	}
}

func IsStr(input any) bool {
	switch v := input.(type) {
	case string:
		return true
	case []byte:
		return false
	default:
		s, err := ToString(v)
		return err == nil && utf8.ValidString(s)
	}
}

func ToString(input any) (string, error) {
	switch v := input.(type) {
	case string:
		return v, nil
	case []byte:
		return string(v), nil
	default:
		return "", fmt.Errorf("unsupported type")
	}
}

func Solution(args any) string {
	if IsStr(args) {
		if err := FeedHTML(args.(string)); err != nil && err != io.EOF {
			log.Printf("Error feeding HTML: %v", err)
			return "thymine"
		}
		return "analysis is successful"
	}
	return "thymine"
}

func main() {
	var input string
	fmt.Print("Enter HTML: ")
	fmt.Scanln(&input)
	result := Solution(input)
	fmt.Println(result)
}

