// Spell Cast Functions
func voidAbsorption(hp, add int) int {
	return int(math.Floor(float64(hp)/2)) + add
}

func lightningStrike(hp, subtract int) int {
	return hp - subtract
}

// Check if dragon can be defeated
func canDefeatDragon(hitPoints, voidAbsorbAdd, lightningSubtract int) bool {
	for hp := hitPoints; hp > 0; {
		hp = voidAbsorption(hp, voidAbsorbAdd)
		if hp <= 0 {
			return true
		}
		hp = lightningStrike(hp, lightningSubtract)
		if hp <= 0 {
			return true
		}
	}
	return false
}

// Process inputs and generate results
func processCases(cases [][]int) []string {
	results := make([]string, len(cases))

	for i, c := range cases {
		if len(c) != 3 {
			log.Printf("Invalid input case length at index %d", i)
			results[i] = "NO"
			continue
		}

		hitPoints, voidAbsorbAdd, lightningSubtract := c[0], c[1], c[2]
		if canDefeatDragon(hitPoints, voidAbsorbAdd, lightningSubtract) {
			results[i] = "YES"
		} else {
			results[i] = "NO"
		}
	}
	return results
}

