func requiredSteps(a1, m1, a2, m2, a3, m3 int) int {
	lcmAB := lcm(a1, m1)
	lcmABC := lcm(lcmAB, a2)
	lcmAll := lcm(lcmABC, m2)
	lcmAll = lcm(lcmAll, a3)
	lcmAll = lcm(lcmAll, m3)

	minStepsX := abs(lcmAll/a1-1)%m1 + 1
	minStepsY := abs(lcmAll/a2-1)%m2 + 1
	minStepsZ := abs(lcmAll/a3-1)%m3 + 1

	return min(minStepsX, min(minStepsY, minStepsZ))
}

