import (
	"fmt"
	deque "github.com/gammazero/deque"
)

func helpAterp(matrix [][]int) int {
	R := len(matrix)
	C := len(matrix[0])
	directions := [][2]int{{0, 1}, {0, -1}, {1, 0}, {-1, 0}}
	q := deque.New[int]()

	for i := 0; i < R; i++ {
		for j := 0; j < C; j++ {
			if matrix[i][j] == 2 {
				q.PushBack(i*C + j)
				matrix[i][j] = 0
			}
		}
	}

	time := 0
	for q.Len() > 0 && time < 10000 {
		for size := q.Len(); size > 0; size-- {
			idx := q.PopFront()
			x, y := idx/C, idx%C
			for _, dir := range directions {
				a, b := x+dir[0], y+dir[1]
				if a >= 0 && a < R && b >= 0 && b < C && matrix[a][b] == 1 {
					q.PushBack(a*C + b)
					matrix[a][b] = 0
				}
			}
		}
		time++
	}

	for i := 0; i < R; i++ {
		for j := 0; j < C; j++ {
			if matrix[i][j] == 1 {
				if time < 10000 {
					return time
				}
				return -1
			}
		}
	}
	return time
}

