func kClosest(points [][]int, k int) [][]int {
	n := len(points)
	dist := make([]struct {
		index int
		d     float64
	}, n)

	for i := range points {
		dist[i].index = i
		dist[i].d = math.Sqrt(float64(points[i][0]*points[i][0] + points[i][1]*points[i][1]))
	}

	sort.Slice(dist, func(i, j int) bool {
		return dist[i].d < dist[j].d
	})

	result := make([][]int, k)
	for i := 0; i < k; i++ {
		result[i] = points[dist[i].index]
	}

	return result
}

