func modularInverse(n int, mod int) int {
	return pow(n, mod-2, mod)
}

func pow(base, exp, mod int) int {
	result := 1
	base = base % mod
	for exp > 0 {
		if exp&1 == 1 {
			result = (result * base) % mod
		}
		exp >>= 1
		base = (base * base) % mod
	}
	return result
}

func factorial(n int, mod int) int {
	if n == 1 {
		return 1
	}
	return (n * factorial(n-1, mod)) % mod
}

func solve(A []int, N int) int {
	f := make([]int, 2*N+2)
	f[0], f[N+1] = 1, 1

	for i := 1; i <= 2*N; i++ {
		if contains(A, i-1) {
			f[i] = (f[i] + f[i-2]) % (1e9 + 7)
		}
		if contains(A, i+1) {
			f[i] = (f[i] + f[i+2]) % (1e9 + 7)
		}
	}

	result := 0
	for i := 1; i <= N; i++ {
		result = (result + f[2*i-N-1]) % (1e9 + 7)
	}

	if result == 0 {
		return 0
	}

	return factorial(N, 1e9+7) * result % (1e9 + 7)
}

func contains(arr []int, value int) bool {
	for _, v := range arr {
		if v == value {
			return true
		}
	}
	return false
}

