func maxScore(n, k, z int, a []int) int {
    dp := make([][][]int, n)
    for i := range dp {
        dp[i] = make([][]int, k+1)
        for j := range dp[i] {
            dp[i][j] = make([]int, z+1)
        }
    }

    // Base case
    for i := 1; i <= n; i++ {
        dp[i-1][1][0] = a[i-1]
    }

    for i := 2; i <= n; i++ {
        for j := 1; j <= k; j++ {
            for l := 0; l <= z; l++ {
                dp[i-1][j][l] = dp[max(i-2, 0)][j-1][l]
                if j > 0 && l < z {
                    dp[i-1][j][l] = max(dp[i-1][j][l], dp[max(i-3, 0)][j-1][l+1]+a[i-1])
                }
            }
        }
    }

    return dp[n-1][k][0]
}

