type Solution struct{}

func (s *Solution) findNth(N int) int {
	isDigit9 := func(n int) bool {
		for n > 0 {
			if n%10 == 9 {
				return true
			}
			n /= 10
		}
		return false
	}

	countDigit9 := func(n int) int {
		count := 0
		for n > 0 {
			if n%10 == 9 {
				count++
			}
			n /= 10
		}
		return count
	}

	findNthNumber := func(n int) int {
		count := 0
		for count < n {
			if !isDigit9(count) {
				count++
			} else {
				count += int(pow(10, float64(countDigit9(count)-1)))
			}
		}
		return count
	}

	return findNthNumber(N)
}

func pow(x, y float64) float64 {
	return float64(int64(powInternal(x, y)))
}

func powInternal(x, y float64) float64 {
	result := 1.0
	for y > 0 {
		if int(y)%2 == 1 {
			result *= x
		}
		x *= x
		y /= 2
	}
	return result
}

