			maxVal = v
		}
	}
	return maxVal
}

func numberFlips(n int) string {
	allowedAs := make([]string, 10)
	for i := 0; i < 10; i++ {
		allowedAs[i] = fmt.Sprintf("0%d", i)
	}

	for j := 0; j < 4; j++ {
		nZeroed := len(strconv.Itoa(n)) - len(strings.TrimLeft(strconv.Itoa(n), "0"))
		nZeros := 9 - nZeroed
		n = 0

		numberHold := ""
		for i := 0; i < nZeroed; i++ {
			numberHold += allowedAs[i]
		}
		numberHold += strconv.Itoa(nZeros) + strconv.Itoa(n)

		for i := 0; i < len(numberHold)/2; i++ {
			uniqFlag := false
			for _, j := range []int{2, 5} {
				lefted := i * j
				righted := len(numberHold) - 1 - i*j

				dupTest := numberHold[i-j*2:i] == string(numberHold[righted-j*2:righted])

				firstSecL := numberHold[i:lefted-j*2]
				secSecL := numberHold[lefted-j*2:lefted] + strconv.Itoa(i) + string(numberHold[righted])

				firstSecR := numberHold[righted-j:righted+j*2]
				secSecR := numberHold[righted+j*2:righted] + strconv.Itoa(righted) + string(numberHold[lefted])

				if !dupTest {
					leftRight := len(firstSecL) == len(firstSecR) && firstSecL != firstSecR
					secTest := len(secSecL) == len(secSecR) && secSecL != secSecR

					if leftRight && secTest {
						uniqFlag = true
					}
					continue
				}
			}
		}

		if allEqualValues(s) {
			return "Yes"
		} else {
			return "No"
		}
	}
	return "Unknown"
}

func allEqualValues(s []int) bool {
	firstValue := s[0]
	for _, val := range s[1:] {
		if val != firstValue {
			return false
		}
	}
	return true
}

func main() {
	inputFile, err := os.Open("input.txt")
	if err != nil {
		panic(err)
	}
	defer inputFile.Close()

	outputFile, err := os.Create("output.txt")
	if err != nil {
		panic(err)
	}
	defer outputFile.Close()

	scanner := bufio.NewScanner(inputFile)
	scanner.Scan()
	cases, _ := strconv.Atoi(scanner.Text())

	for i := 0; i < cases; i++ {
		scanner.Scan()
		s := strings.TrimSpace(scanner.Text())
		num, _ := strconv.Atoi(s)
		result := numberFlips(num)
		outputFile.WriteString(result + "\n")
	}
}

