func mergeArrays(arr1, arr2 []int) []int {
	// Create a map to hold unique elements
	unique := make(map[int]bool)

	// Insert elements from the first array
	for _, v := range arr1 {
		unique[v] = true
	}

	// Insert elements from the second array
	for _, v := range arr2 {
		unique[v] = true
	}

	// Prepare a slice for the result
	result := make([]int, 0, len(unique))

	// Collect unique elements into the result slice
	for k := range unique {
		result = append(result, k)
	}

	// Sort the result slice
	sort.Ints(result)

	return result
