func solve(n int, points [][]int) int {
	neighbors := make([]int, n)
	for i := 0; i < n; i++ {
		x1, y1 := points[i][0], points[i][1]
		for j := 0; j < n; j++ {
			if i == j {
				continue
			}
			x2, y2 := points[j][0], points[j][1]
			if x1 == x2 && y1 == y2 {
				continue
			}
			if x1 == x2 && ((y1 < y2) || (y1 > y2)) {
				neighbors[i]++
			} else if y1 == y2 && ((x1 < x2) || (x1 > x2)) {
				neighbors[i]++
			}
		}
	}

	supercentralCount := 0
	for _, count := range neighbors {
		if count == 3 {
			supercentralCount++
		}
	}
	return supercentralCount
