// romanToInt converts a Roman numeral string to an integer
func romanToInt(s string) int {
	roman := map[rune]int{
		'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000,
	}
	integer := roman[rune(s[0])]
	length := len(s)

	for i := 0; i < length-1; i++ {
		if roman[rune(s[i])] < roman[rune(s[i+1])] {
			integer -= roman[rune(s[i])]
		} else {
			integer += roman[rune(s[i])]
		}
	}

	return integer + roman[rune(s[length-1])]
}

