import (
	"container/heap"
	"fmt"
)

type SeatHeap []int

func (h SeatHeap) Len() int           { return len(h) }
func (h SeatHeap) Less(i, j int) bool { return h[i] < h[j] }
func (h SeatHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *SeatHeap) Push(x interface{}) {
	*h = append(*h, x.(int))
}

func (h *SeatHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

type SeatManager struct {
	available *SeatHeap
}

func NewSeatManager(n int) *SeatManager {
	seats := SeatHeap{}
	for i := 1; i <= n; i++ {
		seats = append(seats, i)
	}
	heap.Init(&seats)
	return &SeatManager{available: &seats}
}

func (sm *SeatManager) Reserve() int {
	return heap.Pop(sm.available).(int)
}

func (sm *SeatManager) Unreserve(seatNumber int) {
	heap.Push(sm.available, seatNumber)
}

func main() {
	// Example usage
	sm := NewSeatManager(5)
	fmt.Println("Reserved Seat:", sm.Reserve())
	sm.Unreserve(3)
	fmt.Println("Reserved Seat:", sm.Reserve())
}

