func pointDifference(a, b []int) int {
	diff := sum(a) - sum(b)
	if diff == 0 {
		return 0
	}
	if diff > 0 {
		return 1
	}
	return 2
}

func optimalStrategy(a, b []int) int {
	if pointDifference(a, b) == 1 {
		snell := make([]int, len(b))
		copy(snell, b)
		sort.Ints(snell)
		n := len(snell)
		if snell[n/2-1]-a[len(a)-1] <= a[len(a)-n/2] && a[len(a)-n/2] >= snell[n/2] {
			return 1
		}
		return 2
	}

	if pointDifference(a, b) == 2 {
		snell := make([]int, len(a))
		copy(snell, a)
		sort.Ints(snell)
		n := len(snell)
		if snell[n/2-1]-b[len(b)-1] <= b[len(b)-n/2] && b[len(b)-n/2] >= snell[n/2] {
			return 2
		}
		return 1
	}
	return 0
}

