func nextArray(a []int, n int, facts [][3]int) bool {
	segment := make([][3]int, 0)
	for _, fact := range facts {
		tr, l, r := fact[0], fact[1], fact[2]
		segment = append(segment, [3]int{l, 0, false})
		if tr == 1 {
			for i := l; i < r; i++ {
				segment = append(segment, [3]int{i, 0, true})
			}
		} else {
			for i := l; i < r; i++ {
				segment = append(segment, [3]int{i, 0, false})
			}
		}
	}
	for i := 0; i < n; i++ {
		segment = append(segment, [3]int{n + 1, 0, false})
	}
	nums := make([]int, n+2)
	nums[0] = 1_000_000_000
	pos := 1
	sort.Slice(segment, func(i, j int) bool {
		return segment[i][0] < segment[j][0]
	})
	for _, entry := range segment {
		i, sortFlag, _ := entry[0], entry[1], entry[2]
		if sortFlag {
			nums[i] = nums[i-1]
		} else {
			nums[i-1] = nums[i]
			for pos <= i {
				nums[pos] = nums[pos-1] - pos + 1
				pos++
			}
		}
	}
	if nums[n] != 1_000_000_000 {
		return false
	}
	for i := range a {
		if a[i] != nums[i] {
			return false
		}
	}
	return true
}

