func minSquareSide(n int) float64 {
    /*
       Calculate the minimum side length of a square that can embed a regular polygon with 2n vertices.

       Args:
       n (int): The number of pairs of vertices in the polygon.

       Returns:
       float64: The minimum side length of the square.
    */
    // Calculate the side length of the square
    // The radius of the circumcircle is 1 / (2 * sin(pi / (2 * n)))
    // The diameter is twice the radius
    sideLength := 2 / math.Sin(math.Pi/float64(n))

    return sideLength
}

