func isPalindrome(s string) bool {
	for i := 0; i < len(s)/2; i++ {
		if s[i] != s[len(s)-1-i] {
			return false
		}
	}
	return true
}

func minTroops(seq string) (int, int) {
	n := len(seq)

	if n == 0 {
		return 0, 0
	}

	subSeq := ""
	for i := 0; i < n; i++ {
		for j := i; j < n; j++ {
			currSub := seq[i : j+1]
			if len(currSub) > len(subSeq) && isPalindrome(currSub) {
				subSeq = currSub
			}
		}
	}

	deleteLength := len(subSeq)
	if deleteLength == 0 {
		return n, 0
	}

	remainingSize := n - deleteLength
	troops := 0
	if remainingSize > 0 {
		troops = (remainingSize + 1) / 2
	}

	return deleteLength, troops
}

