func compressString(s string, m int) string {
	var t strings.Builder
	c := 1
	for i := 0; i < m; i++ {
		if i == m-1 || s[i] != s[i+1] {
			t.WriteString(strings.Repeat(string(s[i]), c))
			c = 1
		} else {
			c++
		}
	}
	return t.String()
}

func decryptDigits(s string) string {
	var decryptedDigits []rune
	lastChar := rune(s[0])
	for c := 0; c < len(s); c++ {
		for t := 0; t <= c; t++ {
			if c+t >= len(s) {
				decryptedDigits = append(decryptedDigits, lastChar)
				break
			}
			if rune(s[c+t]) == lastChar {
				continue
			} else {
				decryptedDigits = append(decryptedDigits, lastChar)
				lastChar = rune(s[c+t])
				break
			}
		}
	}
	return string(decryptedDigits)
}

func characterizeString(s string) string {
	numChar := len(s)
	var ans strings.Builder
	count := 0
	for idx := 0; idx < numChar; idx++ {
		if idx+1 < numChar && s[idx] == s[idx+1] {
			count++
		} else {
			ans.WriteRune(rune(s[idx]))
			count = 0
		}
	}
	return ans.String()
}

