func minTimeToEvenSums(n int, dominoes [][2]int) int {
    upperSum, lowerSum := 0, 0

    for _, d := range dominoes {
        upperSum += d[0]
        lowerSum += d[1]
    }

    if upperSum%2 == 0 && lowerSum%2 == 0 {
        return 0
    }

    if (upperSum + lowerSum)%2 != 0 {
        return -1
    }

    minTime := int(^uint(0) >> 1) // equivalent to math.MaxInt32
    for _, d := range dominoes {
        if (upperSum-d[0]+d[1])%2 == 0 && (lowerSum-d[1]+d[0])%2 == 0 {
            minTime = 1
            break
        }
    }

    if minTime == int(^uint(0)>>1) {
        return -1
    }
    return minTime
}

