            evenChests++
        } else {
            oddChests++
        }
    }

    // Count even and odd keys
    for _, key := range keys {
        if key%2 == 0 {
            evenKeys++
        } else {
            oddKeys++
        }
    }

    // Calculate maximum chests that can be opened
    maxOpened := min(evenChests, oddKeys) + min(oddChests, evenKeys)
    return maxOpened
}

