func smallestBeautifulInteger(n, k int, digits string) string {
	period := digits[:k]

	// Construct the beautiful integer
	beautiful := strings.Repeat(period, n/k)
	if n%k != 0 {
		beautiful += period[:n%k]
	}

	// If the beautiful integer is greater than or equal to x, return it
	if beautiful >= digits {
		return beautiful
	} else {
		// Otherwise, increment the period and try again
		periodInt, _ := strconv.Atoi(period)
		period = strconv.Itoa(periodInt + 1)
		beautiful = strings.Repeat(period, n/k)
		if n%k != 0 {
			beautiful += period[:n%k]
		}
		return beautiful
	}
}

