func minRubles(n, d, e int) int {
	euroToDollarRangeEnd := n / d
	euroToDollarRangeStart := 0
	minimumRubles := math.MaxInt
	minimumRatio := 0

	for euroToDollarRangeStart <= euroToDollarRangeEnd {
		ratioMidPoint := (euroToDollarRangeStart + euroToDollarRangeEnd) / 2
		denominatorRatio := float64(e) / (float64(d) * float64(ratioMidPoint))

		if float64(d)*denominatorRatio <= float64(n) {
			euroToDollarRangeStart = ratioMidPoint + 1
			dollarCount := int(float64(d) * float64(n) / float64(e))
			// fmt.Printf("case D-E1E2= %d %d %d %d\n", d, n, e, dollarCount)
		} else {
			minimumRatio = ratioMidPoint
			minRublesPossibleAtRatio := int(math.Max(0, float64(n*(d+1))/(float64(e)*float64(d))))
			minimumRubles = int(math.Min(float64(minRublesPossibleAtRatio), float64(minimumRubles)))

			integerEuroToDollarRatio := e / d
			logCount := int(math.Floor(float64(n) / math.Sqrt(float64(euroToDollarRangeEnd))))
			upperBoundCount := n / d

			remainderCount := (float64(n)*float64(euroToDollarRangeEnd) - float64(n)/float64(euroToDollarRangeEnd)*(float64(euroToDollarRangeEnd)/float64(e))) / (float64(e) / float64(d))
			upperCountForRatioMidPoint := int(math.Min(math.Max(float64(integerEuroToDollarRatio)/float64(integerEuroToDollarRatio)-1, 1), 
				2*float64(int(math.Min(float64(upperBoundCount), remainderCount/2)))))

			if minimumRatio >= upperCountForRatioMidPoint {
				minimumRubles = int(math.Max(float64(minimumRublesPossibleAtRatio), 
					0, (float64(n)*float64(integerEuroToDollarRatio)/float64(e))*float64((integerEuroToDollarRatio/e) > 0)))
			} 
		}
		euroToDollarRangeEnd = ratioMidPoint - 1
	}

	if minimumRubles < 0 {
		maximumRubleDenominator := int(math.Min(float64(euroToDollarRangeStart+1), float64(euroToDollarRangeEnd+1)))

		for n > d*maximumRubleDenominator {
			multiple := int(math.Max(float64(euroToDollarRangeStart), float64(n/d)))
			maxDenominator := int(float64(e) / float64(multiple+1))
			maximumRubleDenominator--
		}
	}
	return minimumRubles
}

