func optimalStonesGame(N int, K int, A []int) string {
    // If the initial number of stones is less than zero after Taro's current move,
    // Jiro wins because there are no stones left to remove.
    if K-N < 0 {
        return "Second"
    }

    // Initialize the dynamic programming (DP) table with -1.
    dp := make([][]int, K+1)
    for i := range dp {
        dp[i] = make([]int, N+1)
        for j := range dp[i] {
            dp[i][j] = -1
        }
    }

    // Fill the DP table based on moves available for Taro.
    for i := 1; i <= K; i++ {
        for j := 1; j <= min(i, N); j++ {
            // Case when Taro cannot make any move
            if i < A[j-1] {
                dp[i][j] = dp[i][j-1]
            } else {
                // If Taro's j-th move is possible, update the DP table.
                dp[i][j] = min(dp[i-A[j-1]][j-1], dp[i-A[j-1]][j-1]+1)
            }
        }
    }

    // Determine the winner based on the final state.
    if A[N-1] < K || dp[K][N] <= N {
        return "First"
    }
    return "Second"
}

