// Reverse an integer
func reverse(x int) int {
	sign := 1
	if x < 0 {
		sign = -1
		x = -x
	}
	reversed := 0
	for x > 0 {
		remainder := x % 10
		reversed = reversed*10 + remainder
		x /= 10
	}
	reversed *= sign
	if reversed < math.MinInt32 || reversed > math.MaxInt32 {
		return 0
	}
	return reversed
}

// Check if an integer is a palindrome
func isPalindrome(x int) bool {
	if x < 0 {
		return false
	}
	rev := 0
	temp := x
	for temp > 0 {
		rev = rev*10 + temp%10
		temp /= 10
	}
	return rev == x
}

// Remove adjacent duplicates from a string
func removeDuplicates(s string, k int) string {
	stack := [][]interface{}{{'#', 0}}
	for _, c := range s {
		if stack[len(stack)-1][0] == c {
			stack[len(stack)-1][1] = stack[len(stack)-1][1].(int) + 1
			if stack[len(stack)-1][1].(int) == k {
				stack = stack[:len(stack)-1]
			}
		} else {
			stack = append(stack, []interface{}{c, 1})
		}
	}
	result := ""
	for _, pair := range stack {
		char := pair[0].(rune)
		freq := pair[1].(int)
		for i := 0; i < freq; i++ {
			result += string(char)
		}
	}
	return result
}

// Recursive function to find the minimum value
func findMinimum(a []int, i int, vmin int) int {
	if a[i] < vmin {
		vmin = a[i]
	}
	if i == 0 {
		return vmin
	}
	return findMinimum(a, i-1, vmin)
}

