const mod = 1000000007

func pow(base, exp, m int) int {
	result := 1
	base = base % m
	for exp > 0 {
		if exp%2 == 1 {
			result = (result * base) % m
		}
		exp = exp >> 1
		base = (base * base) % m
	}
	return result
}

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	scanner.Split(bufio.ScanWords)

	var t int
	fmt.Scan(&t)

	if t == 1 {
