		fmt.Scan(&c1)

		a := make([]string, c1)
		b := make([]string, c1)
		d := make([]string, c1)

		for i := 0; i < c1; i++ {
			scanner.Scan()
			a[i] = scanner.Text()
		}
		for i := 0; i < c1; i++ {
			scanner.Scan()
			b[i] = scanner.Text()
		}
		for i := 0; i < c1; i++ {
			scanner.Scan()
			d[i] = scanner.Text()
		}

		p1 := pow((c1 - 1), c1 - 2, mod)
		p2 := pow(1-(c1-1), mod-2, mod)
		ans := ((2*p1)+(2*(c1-2)*pow(p1, 2, mod)-(c1-1)*p1)*p2) % mod

		// Count occurrences
		countA := make(map[string]int)
		countB := make(map[string]int)
		countD := make(map[string]int)

		for _, val := range a {
			countA[val]++
