		}
		for _, val := range d {
			countD[val]++
		}

		// Check conditions
		for _, val := range d {
			if val != "0" && countA[val] == 0 && countB[val] == 0 {
				fmt.Println(0 % mod)
				return
			}
		}

		d1 := make(map[string]int)
		d2 := make(map[string]string)

		for val, cnt := range countD {
			if cnt != 0 {
				d1[val] = cnt
				d2[val] = val
			}
		}

		// Perform reductions
		for i := 0; i < c1; i++ {
			if _, ok := d2[a[i]]; ok {
				delete(d1, a[i])
			} else if _, ok := d2[b[i]]; ok {
				delete(d1, b[i])
			}
		}

		var r1, r2 int = 1, 1
		for _, val := range d1 {
			r1 = (r1 * val) % mod
		}
		for _, val := range d2 {
			num, _ := strconv.Atoi(val)
			r2 = (r2 * num) % mod
		}

		fmt.Println((ans * r1 % mod * r2 % mod) % mod)
	}
}

