	}

	sort.Slice(s, func(i, j int) bool {
		return len(s[i]) < len(s[j])
	})

	resLen := 0
	var res [][]string

	for _, stringVal := range s {
		for _, subString := range stringVal {
			subList := make([]string, 0)

			for len(subList) > 0 {
				delChar := subList[0]
				subList = subList[1:]

				for _, str := range s {
					if strings.Contains(stringVal, string(delChar)) && strings.Index(str, string(delChar)) != -1 {
						subString = stringVal[0]
						break
					}
				}
			}

			subList = append(subList, string(subString))
			if len(subList) >= resLen {
				if len(subList) > resLen {
					res = [][]string{}
					resLen = len(subList)
				}

				if !contains(res, subList) {
					res = append(res, subList)
				}
			}
		}
	}

	if len(res) < 1 && stringJoin(res) != "" {
		if stringJoin(res) < stringJoin(append(res, s[len(s)-1])) {
			res = append(res, []string{""})
		} else {
			if !contains(res, append(res, s[len(s)-1])) {
				res = append(res, subList)
			}
		}
	}

	if containsString(res, "") {
		res = removeLast(res)
	}

	if len(res) == 2 {
		if len(stringJoin(res)) > 0 {
			// Do nothing
		} else if contains(res, stringJoin(res)) {
			res = append(res, []string{""})
		} else {
			if !contains(res, stringJoin(res)) {
				res = res[:len(res)-1]
			}
		}
	}

	resString := stringJoin(res)
	resString = normalizeString(resString)
	resRunes := []rune(resString)
	sort.Slice(resRunes, func(i, j int) bool {
		return resRunes[i] > resRunes[j]
	})

	fmt.Println("The longest string is:", string(resRunes))
}

func stringJoin(res [][]string) string {
	var sb strings.Builder
	for _, r := range res {
		sb.WriteString(strings.Join(r, ""))
	}
	return sb.String()
}

func contains(res [][]string, subList []string) bool {
	for _, r := range res {
		if reflect.DeepEqual(r, subList) {
			return true
		}
	}
	return false
}

func containsString(res [][]string, str string) bool {
	for _, r := range res {
		for _, s := range r {
			if s == str {
				return true
			}
		}
	}
	return false
}

func removeLast(res [][]string) [][]string {
	return res[:len(res)-1]
}

func normalizeString(s string) string {
	runes := []rune(s)
	for i, r := range runes {
		if i != 0 {
			runes[i] = r
		}
	}
	return string(runes)
}

func calculateCost(s string, queries [][]int) []interface{} {
	alphabet := []rune{'a', 'b', 'c'}
	visited := make([][]bool, len(s)+1)
	for i := range visited {
		visited[i] = make([]bool, len(alphabet))
	}
	costs := []int{}

	// Preprocess the string
	for i, char := range s {
		visited[i+1][char-'a'] = true
	}

	// Function to check if a substring will become a palindrome
	willBecomePalindrome := func(endIndex int) bool {
		startIndex := max(0, endIndex-2)
		sliceStr := s[startIndex:endIndex+1]
		for _, c := range sliceStr {
			if !visited[startIndex][c-'a'] {
				return false
			}
		}
		return true
	}

	for _, query := range queries {
		l, r := query[0], query[1]

		if willBecomePalindrome(r) {
			costs = append(costs, 0)
		} else {
			hashValue := s[l-1] - 'a'
			occurrences := 0
			for i := l; i <= min(r, len(s)); i++ {
				if visited[l][hashValue] && visited[i][hashValue] && s[i-1] == s[i-l] {
					occurrences++
				}
			}
			if occurrences < min(4, r-l+1) {
				costs = append(costs, 1)
			} else {
				costs = append(costs, 2-(occurrences/(r-l+1)))
			}
		}
	}

	return []interface{}{"", costs}
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

