type DisjointSet struct {
	parent []int
	rank   []int
}

func NewDisjointSet(n int) *DisjointSet {
	ds := &DisjointSet{
		parent: make([]int, n+1),
		rank:   make([]int, n+1),
	}
	for i := range ds.parent {
		ds.parent[i] = i
	}
	return ds
}

func (ds *DisjointSet) Find(x int) int {
	if ds.parent[x] != x {
		ds.parent[x] = ds.Find(ds.parent[x]) // Path compression
	}
	return ds.parent[x]
}

func (ds *DisjointSet) Union(x, y int) {
	xRoot := ds.Find(x)
	yRoot := ds.Find(y)

	if xRoot != yRoot {
		if ds.rank[xRoot] < ds.rank[yRoot] {
			ds.parent[xRoot] = yRoot
		} else if ds.rank[yRoot] < ds.rank[xRoot] {
			ds.parent[yRoot] = xRoot
		} else {
			ds.parent[yRoot] = xRoot
			ds.rank[xRoot]++
		}
	}
}

func smallestGoodNumber(fronts, backs []int) int {
	n := len(fronts)
	dsu := NewDisjointSet(n)

	for i := 0; i < n; i++ {
		dsu.Union(fronts[i], backs[i])
		dsu.parent[fronts[i]] = -1 // Mark front as unavailable
	}

	for i := 0; i < n; i++ {
		if dsu.Find(backs[i]) == -1 {
			return backs[i]
		}
	}

	return 0
}

