func countSubArrayProductLessThanK(a []int, n int, k int) int {
    finalCount := 0
    zeros := 0
    prod := 1

    for _, num := range a {
        if prod == 1 {
            prod *= num
        } else if prod < k {
            finalCount += n - zeros
            if num < k {
                prod *= num
            } else {
                zeros++
            }
        } else {
            break
        }
    }

    count := 0
    zeros = 0

    if prod < k {
        count++
    }

    if zeros > 0 {
        count += zeros
    }

    return finalCount + count
}

