type Solution struct{}

func (s *Solution) gcd(a, b int) int {
	if b == 0 {
		return a
	}
	return s.gcd(b, a%b)
}

func (s *Solution) lcm(a, b int) int {
	return a / s.gcd(a, b) * b
}

func (s *Solution) solve(sStr, tStr string) string {
	counterS := countChars(sStr)
	counterT := countChars(tStr)

	if (counterS['a']+counterS['b'])%2 != (counterT['a']+counterT['b'])%2 {
		return "-1"
	}

	x := (counterS['a'] + counterS['b']) / 2
	y := (counterT['a'] + counterT['b']) / 2

	if s.gcd(x, y)*2 > min(counterS['a'], counterT['a'])+min(counterS['b'], counterT['b']) {
		return "-1"
	}

	if x >= y {
		return sStr
	}
	return tStr
}

func countChars(s string) map[rune]int {
	counter := make(map[rune]int)
	for _, char := range s {
		counter[char]++
	}
	return counter
}

