type Item struct {
	coins int
	num   int
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool { return pq[i].coins < pq[j].coins }

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	*pq = append(*pq, x.(*Item))
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func minCoins(n, a, b, c, d int) int {
	pq := &PriorityQueue{}
	heap.Push(pq, &Item{0, 0})
	visited := make(map[int]struct{})

	for pq.Len() > 0 {
		item := heap.Pop(pq).(*Item)
		coins := item.coins
		num := item.num

		if num == n {
			return coins
		}
		if _, ok := visited[num]; ok {
			continue
		}
		visited[num] = struct{}{}

		for _, opCost := range [][2]int{{2, a}, {3, b}, {5, c}, {1, d}} {
			newNum := num * opCost[0]
			newCoins := coins + opCost[1]
			if newNum <= n {
				heap.Push(pq, &Item{newCoins, newNum})
			}
		}
	}
	return -1
}

func main() {
	var t int
	fmt.Fscan(os.Stdin, &t)
	for i := 0; i < t; i++ {
		var n, a, b, c, d int
		fmt.Fscan(os.Stdin, &n, &a, &b, &c, &d)
		result := minCoins(n, a, b, c, d)
		fmt.Println(result)
	}
}

