func stoneGameIV(stones []int) int {
	N := len(stones)
	F := make([][][]int, 1<<N+1)
	for i := range F {
		F[i] = make([][]int, 6)
		for j := range F[i] {
			F[i][j] = make([]int, 6)
		}
	}

	for s := 0; s <= N; s++ {
		F[0][0][0] = 0
	}

	stoneSum := 0
	for _, stone := range stones {
		stoneSum += stone
	}

	for s := 1; s <= (1 << N); s++ {
		if s > 0 {
			for s4 := s - 1; s4 >= 0; s4-- {
				F[s][0][0] = F[s-s4][0][3] + stones[s-1]
			}
		}
		for t := 1; t <= 3; t++ {
			for s4 := s - 1; s4 >= 0; s4-- {
				F[s][t][t] = max(F[s-s4][t-1][t-1], F[s-s4][t-1][t]) + stones[s-1]
			}
			for tt := 1; tt < t; tt++ {
				for s4 := s - 1; s4 >= 0; s4-- {
					F[s][t][t] = max(F[s][t][t], max(F[s-s4][t][tt-1], F[s-s4][tt][t]) + stones[s-1])
				}
			}
		}
	}

	aliceScore := max(F[(1<<N)-1][1][3], F[(1<<N)-1][2][3])
	bobScore := stoneSum - aliceScore

	if bobScore == aliceScore {
		return 0
	} else if bobScore < aliceScore {
		return 1
	} else {
		return 2
	}
}

