func minimumCostOfConnectingPoints(cost [][]int) int {
	n := len(cost)
	graph := make([][]int, n)
	for i := range graph {
		graph[i] = make([]int, n)
	}

	parent := make([]int, n)
	rank := make([]int, n)

	for i := range parent {
		parent[i] = i
		rank[i] = 1
	}

	var find func(x int) int
	find = func(x int) int {
		if parent[x] != x {
			parent[x] = find(parent[x])
		}
		return parent[x]
	}

	var union func(x, y int)
	union = func(x, y int) {
		rootX := find(x)
		rootY := find(y)
		if rootX != rootY {
			if rank[rootX] > rank[rootY] {
				parent[rootY] = rootX
			} else {
				parent[rootX] = rootY
				if rank[rootX] == rank[rootY] {
					rank[rootY]++
				}
			}
		}
	}

	edges := []struct {
		u, v, cost int
	}{}

	for i := 0; i < n; i++ {
		for j := 0; j < n; j++ {
			edges = append(edges, struct {
				u, v, cost int
			}{i, j, cost[i][j]})
		}
	}

	// Sort edges by cost
	// TODO: Implement sorting

	totalCost := 0
	for _, edge := range edges {
		if find(edge.u) != find(edge.v) {
			totalCost += edge.cost
			union(edge.u, edge.v)
		}
	}

	return totalCost
}

