func solve(l, r int64) {
	if l == r {
		fmt.Println("NO")
		return
	}
	fmt.Println("YES")

	n := (l + r - 1) / 2
	var ans int64 = 0

	for i := l; i <= n; i++ {
		if ans*2+1 <= r {
			ans = ans*2 + 1
		} else {
			ans = i
			break
		}
	}

	if ans <= r {
		fmt.Println("NO")
		return
	}

	for i := n + 1; i <= r; i++ {
		if ans*2+3 <= r {
			ans = ans*2 + 3
		} else {
			ans = i
			break
		}
	}

	if ans <= r {
		fmt.Println("NO")
		return
	}
	fmt.Println("YES")

	if l <= ans && ans <= r {
		ans = 0
	} else {
		ans = l - 1
	}
	fmt.Printf("%d\n", ans)
}

