func minimumMountainTripletSum(nums []int) int {
	n := len(nums)
	minSum := math.MaxInt32

	// Iterate over each possible peak
	for j := 1; j < n-1; j++ {
		left := j - 1
		right := j + 1

		// Find the smallest number to the left of j that is less than nums[j]
		for left >= 0 && nums[left] >= nums[j] {
			left--
		}

		// Find the smallest number to the right of j that is less than nums[j]
		for right < n && nums[right] >= nums[j] {
			right++
		}

		// Check if a valid mountain triplet is found
		if left >= 0 && right < n {
			minSum = min(minSum, nums[left]+nums[j]+nums[right])
		}
	}

	if minSum == math.MaxInt32 {
		return -1
	}
	return minSum
}

