func maxTotalFruits(fruits [][]int, startPos, k int) int64 {
	n := len(fruits)
	psum := make([]int64, n)
	psum[0] = int64(fruits[0][1])
	for i := 1; i < n; i++ {
		psum[i] = psum[i-1] + int64(fruits[i][1])
	}
	res := int64(-1)
	var cnt int64

	for x := 0; x <= k/2; x++ {
		if k%2 == 0 && x == k/2 {
			continue
		}
		y := k - 2*x
		lt := startPos - min(fruits[0][0], x)
		rt := min(fruits[n-1][0], startPos+y)
		lb := lowerBound(fruits, []int{lt, 0})
		rb := lowerBound(fruits, []int{rt + 1, 0}) - 1

		if lb > rb {
			continue
		}
		cnt = psum[rb]
		if lb > 0 {
			cnt -= psum[lb-1]
		}
		res = max(res, cnt)
	}

	for x := 0; x <= k/2; x++ {
		if k%2 == 1 && x == k/2 {
			continue
		}
		y := k - 2*x
		lt := startPos - min(fruits[0][0], y)
		rt := min(fruits[n-1][0], startPos+x)
		lb := lowerBound(fruits, []int{lt, 0})
		rb := lowerBound(fruits, []int{rt + 1, 0}) - 1

		if lb > rb {
			continue
		}
		cnt = psum[rb]
		if lb > 0 {
			cnt -= psum[lb-1]
		}
		res = max(res, cnt)
	}
	return res
}

func lowerBound(arr [][]int, target []int) int {
	low, high := 0, len(arr)
	for low < high {
		mid := (low + high) / 2
		if arr[mid][0] < target[0] {
			low = mid + 1
		} else {
			high = mid
		}
	}
	return low
}

