func minimumTimeToFloorZero(n int, s int, passengers [][2]int) int {
	// Sort passengers by their arrival time
	sort.Slice(passengers, func(i, j int) bool {
		return passengers[i][1] < passengers[j][1]
	})

	currentPosition := s
	currentTime := 0
	index := 0

	for index < n || currentPosition > 0 {
		var nextPosition int

		if index < n && passengers[index][0] >= currentPosition {
			nextPosition = passengers[index][0]
			// Go to the floor where the next passenger is
			currentTime += currentPosition - nextPosition
			currentPosition = nextPosition
		} else {
			// Move directly down to floor 0 if no more passengers are on the way
			currentTime += currentPosition
			currentPosition = 0
		}

		// Pick up passengers waiting on the current floor
		for index < n && passengers[index][0] == currentPosition {
			// If the elevator arrives before the passenger, wait
			if passengers[index][1] > currentTime {
				currentTime = passengers[index][1]
			}
			// Move index to the next passenger
			index++
		}
	}

	// Final move to floor 0 if not already there
	currentTime += currentPosition

	return currentTime
}

