// isPrime checks if n is a prime number.
func isPrime(n int) bool {
	if n < 2 {
		return false
	}
	for i := 2; i <= int(math.Sqrt(float64(n))); i++ {
		if n%i == 0 {
			return false
		}
	}
	return true
}

// primeNumbers returns a slice of all prime numbers up to n.
func primeNumbers(n int) []int {
	primes := []int{}
	for i := 2; i <= n; i++ {
		if isPrime(i) {
			primes = append(primes, i)
		}
	}
	return primes
}

// findPrimes checks for the existence of k sets of twin primes.
func findPrimes(k, n int) bool {
	primes := primeNumbers(n)
	count := 0
	for i := 0; i < len(primes)-2; i++ {
		if primes[i]+2 == primes[i+1] && primes[i+1]+2 == primes[i+2] && primes[i]+1 == primes[i+2] {
			count++
			if count == k {
				return true
			}
		}
	}
	return false
}

