func isTreeConnected(n int, edges [][]int) bool {
	adjList := make([][]int, n)
	for _, edge := range edges {
		u, v := edge[0]-1, edge[1]-1
		adjList[u] = append(adjList[u], v)
		adjList[v] = append(adjList[v], u)
	}

	visited := make([]bool, n)
	var dfs func(int)
	dfs = func(node int) {
		visited[node] = true
		for _, neighbor := range adjList[node] {
			if !visited[neighbor] {
				dfs(neighbor)
			}
		}
	}

	dfs(0)
	for _, v := range visited {
		if !v {
			return false
		}
	}
	return true
}

func countWinningGames(n int, edges [][]int, g, k int) *big.Rat {
	if !isTreeConnected(n, edges) {
		return big.NewRat(0, 1)
	}

	prob := big.NewRat(1, int64(n))
	correctGuessProb := big.NewRat(1, int64(g))
	winningProb := big.NewRat(0, 1)

	for i := 0; i < k; i++ {
		winningProb.Add(winningProb, new(big.Rat).Mul(prob, new(big.Rat).Exp(correctGuessProb, big.NewRat(int64(g), 1), nil)))
	}

	return winningProb
}

func main() {
	var q int
	fmt.Scan(&q)
	for i := 0; i < q; i++ {
		var n int
		fmt.Scan(&n)
		edges := make([][]int, n-1)
		for j := 0; j < n-1; j++ {
			var u, v int
			fmt.Scan(&u, &v)
			edges[j] = []int{u, v}
		}
		var g, k int
		fmt.Scan(&g, &k)
		result := countWinningGames(n, edges, g, k)
		fmt.Println(result.RatString())
	}
}

