// uniqueSortDescending removes duplicates and sorts the slice in descending order
func uniqueSortDescending(nums []int) []int {
	set := make(map[int]struct{})
	for _, num := range nums {
		set[num] = struct{}{}
	}
	uniqueNums := make([]int, 0, len(set))
	for num := range set {
		uniqueNums = append(uniqueNums, num)
	}
	sort.Sort(sort.Reverse(sort.IntSlice(uniqueNums)))
	return uniqueNums
}

