func minimumLength(s string) int {
	start := 0
	end := len(s)

	p1, p2 := 0, 0
	s1, s2 := 0, 0

	ans := end

	for {
		for p1 < end && countChar(s[p1], s) == 1 {
			p1++
		}
		if p1 >= end {
			end = 0
			break
		}

		for s1 < end && countChar(s[s1], s) == 1 {
			s1++
		}
		if s1 >= end {
			end = 0
			break
		}

		for p2 < end && countChar(s[p2], s) == 1 {
			p2++
		}
		for s2 < end && countChar(s[s2], s) == 1 {
			s2++
		}

		for p1 < p2 && p2 < s1 && s1 < s2 &&
			s[p1] == s[p2] && s[s1] == s[s2] &&
			s[p1:p2] == s[p2:s1] && s[p2:s1] == s[s1:s2] {

			p1++
			s1++
			p2++
			s2++
		}
		if (p1, s1, p2, s2) > (0, 0, end, end) {
			break
		}

		ans = min(ans, end-(s2-s1))

		for i := p1; i < end; i++ {
			if s[i] != s[i+1] {
				start = i + 1
				end = min(end, start+end-start-1)
				break
			}
		}
	}

	return ans
}

func countChar(c byte, s string) int {
	count := 0
	for i := 0; i < len(s); i++ {
		if s[i] == c {
			count++
		}
	}
	return count
}

