func solve() {
	import (
		"bufio"
		"fmt"
		"os"
		"strings"
	)

	reader := bufio.NewReader(os.Stdin)
	data, _ := reader.ReadString('\n')
	lines := strings.Split(strings.TrimSpace(data), "\n")

	index := 0
	T := parseInt(lines[index])
	index++
	result := []string{}

	characters := "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"

	for ; T > 0; T-- {
		r := parseInt(lines[index])
		c := parseInt(lines[index+1])
		k := parseInt(lines[index+2])
		index += 3

		farm := make([]string, r)
		riceCount := 0

		for i := 0; i < r; i++ {
			farm[i] = lines[index]
			riceCount += countRice(farm[i])
			index++
		}

		baseRice := riceCount / k
		extraRice := riceCount % k

		assignment := make([][]string, r)
		for i := range assignment {
			assignment[i] = make([]string, c)
		}

		chickenIndex := 0
		cellsAssigned, riceAssigned := 0, 0

		for i := 0; i < r; i++ {
			var rangeFunc []int
			if i%2 == 0 {
				rangeFunc = generateRange(0, c)
			} else {
				rangeFunc = generateRange(c-1, -1)
			}

			for _, j := range rangeFunc {
				if chickenIndex >= k {
					break
				}

				assignment[i][j] = string(characters[chickenIndex])
				cellsAssigned++

				if farm[i][j] == 'R' {
					riceAssigned++
				}

				if riceAssigned == baseRice + conditionallyAddExtra(chickenIndex, extraRice) {
					chickenIndex++
					cellsAssigned, riceAssigned = 0, 0
				}
			}
		}

		for _, row := range assignment {
			result = append(result, strings.Join(row, ""))
		}
		result = append(result, "") // Blank line between test cases
	}

	fmt.Println(strings.Join(result, "\n"))
}

func parseInt(s string) int {
	val, _ := strconv.Atoi(s)
	return val
}

func countRice(row string) int {
	riceCount := 0
	for _, ch := range row {
		if ch == 'R' {
			riceCount++
		}
	}
	return riceCount
}

func generateRange(start, end int) []int {
	var result []int
	if start < end {
		for i := start; i < end; i++ {
			result = append(result, i)
		}
	} else {
		for i := start; i > end; i-- {
			result = append(result, i)
		}
	}
	return result
}

func conditionallyAddExtra(index, extra int) int {
	if index < extra {
		return 1
	}
	return 0
}

