func minGold(n, m int, c []int, friends [][]int) int {
    // Create a graph to represent the friendships
    graph := make([][]int, n)
    for _, pair := range friends {
        x, y := pair[0]-1, pair[1]-1
        graph[x] = append(graph[x], y)
        graph[y] = append(graph[y], x)
    }

    // Initialize the gold spent and the number of characters who know the rumor
    goldSpent := 0
    charactersKnowRumor := 0

    // Perform a depth-first search to find the number of characters who know the rumor
    var dfs func(node int)
    dfs = func(node int) {
        charactersKnowRumor++
        goldSpent += c[node]
        for _, neighbor := range graph[node] {
            dfs(neighbor)
        }
    }

    // Start the DFS from each character who wants to spread the rumor
    for i := 0; i < n; i++ {
        if c[i] > 0 {
            dfs(i)
        }
    }

