func sieveOfEratosthenes(n int) []bool {
	primes := make([]bool, n+1)
	primes[0] = false
	primes[1] = false
	for i := 2; i < len(primes); i++ {
		primes[i] = true
	}
	for i := 2; i*i <= n; i++ {
		if primes[i] {
			for j := 2 * i; j <= n; j += i {
				primes[j] = false
			}
		}
	}
	return primes
}

