// isDangerous checks if there are at least 7 consecutive players from the same team
func isDangerous(situation string) bool {
	maxCount := 0    // Track the max count of consecutive players
	count := 1       // Track the current count of consecutive players

	// Loop through the input string starting from the second character
	for i := 1; i < len(situation); i++ {
		if situation[i] == situation[i-1] {
			count++
			if count > maxCount {
				maxCount = count // Update maxCount if current count exceeds it
			}
		} else {
			count = 1 // Reset count if different player encountered
		}
	}

	// Return true if a dangerous situation exists
	return maxCount >= 7
}

// GenerateSituation creates a random football field situation
func GenerateSituation(dangerLevel int) string {
	rand.Seed(time.Now().UnixNano()) // Initialize random seed
	situation := ""
	dangerAchieved := false

	for !dangerAchieved {
		team1Length := rand.Intn(100-dangerLevel) + 1
		team1 := strings.Repeat("1", team1Length)
		remainingLength := 100 - team1Length

		if remainingLength < dangerLevel {
			break
		}

		team2Length := rand.Intn(remainingLength-dangerLevel+1) + 1
		team2 := strings.Repeat("0", team2Length)

		// Prepare the complete situation with random remaining characters
		remainingChars := make([]string, remainingLength-team2Length)
		for i := range remainingChars {
			if rand.Intn(2) == 0 {
				remainingChars[i] = "0"
			} else {
				remainingChars[i] = "1"
			}
		}
		situation = team1 + team2 + strings.Join(remainingChars, "")

		// Check if danger level is achieved
		if strings.Count(situation, "1") > dangerLevel || strings.Count(situation, "0") > dangerLevel {
			dangerAchieved = true
		}
	}

	return situation
}

