namespace ProblemSolver;

class BallGame {
    public static function solve(int $n, int $k, array $a): string {
        rsort($a);
        $h = new \SplPriorityQueue();

        foreach ($a as $value) {
            $h->insert($value, -$value);
        }

        while ($h->count() > 1) {
            $x = $h->extract();
            $y = $h->extract();

            if ($x < $y) {
                [$x, $y] = [$y, $x];
            }

            if ($x - $y > $k) {
                return "IMPOSSIBLE";
            }

            $h->insert($x - $y, -($x - $y));
        }

        return $h->isEmpty() || $h->top() !== $k ? "IMPOSSIBLE" : "POSSIBLE";
    }
}

