namespace GraphSearch;

class KenKenPa {
    private array $graph;
    private int $N;
    private int $M;
    private int $S;
    private int $T;

    public function __construct(int $N, int $M, array $edges, int $S, int $T) {
        $this->N = $N;
        $this->M = $M;
        $this->S = $S;
        $this->T = $T;
        $this->buildGraph($edges);
    }

    private function buildGraph(array $edges): void {
        $this->graph = [];
        foreach ($edges as [$u, $v]) {
            $this->graph[$u][] = $v;
        }
    }

    public function minKenKenPa(): int {
        $queue = new \SplQueue();
        $queue->enqueue([$this->S, 0, 0]);
        $visited = [];
        $visited[$this->S][0] = true;

        while (!$queue->isEmpty()) {
            [$current, $step, $count] = $queue->dequeue();

            if ($step === 0 && $current === $this->T) {
                return $count;
            }

            if ($step < 2) {
                foreach ($this->graph[$current] ?? [] as $next) {
                    if (!isset($visited[$next][$step + 1])) {
                        $visited[$next][$step + 1] = true;
                        $queue->enqueue([$next, $step + 1, $count]);
                    }
                }
            } elseif ($step === 2) {
                foreach ($this->graph[$current] ?? [] as $next) {
                    if (!isset($visited[$next][0])) {
                        $visited[$next][0] = true;
                        $queue->enqueue([$next, 0, $count + 1]);
                    }
                }
            }
        }

        return -1;
    }
}

