class UF {
    private int $n;
    private array $parent;

    public function __construct(int $cnt) {
        $this->n = $cnt;
        $this->parent = range(0, $cnt - 1);
    }

    public function connect(int $i, int $j): void {
        $this->unionSet($this->find($i), $this->find($j));
    }

    public function find(int $i): int {
        if ($this->parent[$i] === $i) {
            return $i;
        } else {
            $this->parent[$i] = $this->find($this->parent[$i]);
            return $this->parent[$i];
        }
    }

    public function getSize(int $i): int {
        return 1;
    }

    private function unionSet(int $i, int $j): void {
        $this->parent[$i] = $this->parent[$j];
    }
}

class Solution {
