        $lastIndex = -1;
        $n = count($arr);
        $uf = new UF($n);
        $nums = array_fill(0, $n, 0);

        for ($i = 0; $i < $n; ++$i) {
            $nums[$arr[$i] - 1] = 1;
            if ($arr[$i] - 2 >= 0 && $nums[$arr[$i] - 2] === 1) {
                $uf->connect($arr[$i] - 1, $arr[$i] - 2);
            }
            if ($arr[$i] < $n && $nums[$arr[$i]] === 1) {
