namespace TileCounter;

class TileProcessor
{
    private array $suites = [
        'm' => '123456789',
        'p' => '123456789',
        's' => '123456789'
    ];

    private int $count = 0;

    public function processTiles(array $tiles): int
    {
        $this->validateTiles($tiles);
        $this->countDecrement($tiles);

        return $this->calculateOutput($tiles);
    }

    private function validateTiles(array $tiles): void
    {
        if (empty($tiles) || !is_array($tiles)) {
            throw new \InvalidArgumentException("Invalid tiles input.");
        }
    }

    private function countDecrement(array $tiles): void
    {
        foreach ($tiles as $tile) {
            foreach ($this->suites as $suite) {
                if (substr_count($this->suites[$suite], $tile[0]) >= 3) {
                    $this->count--;
                }
                if (substr_count($this->suites[$suite], $tile[1]) >= 3) {
                    $this->count--;
                }
            }
        }
    }

    private function calculateOutput(array $tiles): int
    {
        $out = 0;

        foreach ($tiles as $tile) {
            $count2 = 0;
            foreach ($this->suites as $suite) {
                if (strpos($this->suites[$suite], $tile[0]) !== false) {
                    $count2++;
                }
                if (strpos($this->suites[$suite], $tile[1]) !== false) {
                    $count2++;
                }
            }
            $out += $count2;
        }

        return $out + $this->count;
    }
}

