class ArrayProcessor
{
    private array $data;

    public function __construct(array $data)
    {
        if (empty($data) || !is_array($data)) {
            throw new \InvalidArgumentException('Input must be a non-empty array');
        }
        $this->data = $data;
    }

    public function process(): int
    {
        sort($this->data);
        $absDifferences = [];
        $uniqueDifferences = [];

        for ($i = 0; $i < count($this->data); $i++) {
            for ($j = $i + 1; $j < count($this->data); $j++) {
                $diff = abs($this->data[$i] - $this->data[$j]);
                $absDifferences[] = $diff;
                $uniqueDifferences[$diff] = true; // Using keys to ensure uniqueness
            }
        }

        $sortedDifferences = array_keys($uniqueDifferences);
        rsort($sortedDifferences);

        return $this->findSecondLargestCount($sortedDifferences);
    }

    private function findSecondLargestCount(array $sortedDifferences): int
    {
        if (count($sortedDifferences) < 2) {
            return 0; // Not enough unique differences for second largest
        }

        $largest = $sortedDifferences[0];
        $count = 0;

        foreach ($sortedDifferences as $difference) {
            if ($difference !== $largest) {
                $count++;
                if ($count === 1) {
                    break;
                }
            }
        }

        return $count;
    }
}

