    public function processInput(string $filePath): array
    {
        $input = $this->readInput($filePath);
        $result = $this->evening2($input);
        return $result;
    }

    protected function readInput(string $filePath): array
    {
        if (!file_exists($filePath)) {
            throw new \Exception("File not found: $filePath");
        }

        $content = file($filePath, FILE_IGNORE_NEW_LINES | FILE_SKIP_EMPTY_LINES);
        return array_map(fn($line) => array_map('intval', explode(' ', $line)), $content);
    }

    protected function getAns(int $cadetsSize, int $nextSize, int $maxSize1, int $maxSize2, int $maxInorto): array
    {
        $asks = [3, 2, 1];
        $ask = array_slice($asks, 0, $maxSize1);
        $a1 = min($nextSize, $maxSize2);
        $a2 = min($cadetsSize, $maxInorto);
        $adags = [];

        for ($i = 0; $i < $a1; $i++) {
            for ($j = 0; $j < $a2; $j++) {
                $adags[] = [$i, $j];
            }
        }

        $ansDsc = [];

        for ($d = 0; $d <= $maxSize2 - $cadetsSize; $d++) {
            foreach ($ask as $g) {
                if ($g * $d + $cadetsSize <= $maxSize2 - $d) {
                    $ansDsc[] = [$cadetsSize, $d, $g];
                }
            }
        }

        if (array_sum(array_map(fn($pair) => $pair[0] < $cadetsSize && $pair[1] > $cadetsSize, $adags)) > 0) {
            usort($ansDsc, fn($a, $b) => $a[0] <=> $b[0]);
            foreach ($ansDsc as $i => $entry) {
                if ($entry[0] === $cadetsSize) {
                    return $ansDsc[$i];
                }
            }
        }

        $tmpAdags = $adags;
        for ($i = 1; $i <= $maxSize2 - $cadetsSize + 1; $i++) {
            $tmpAdags = array_filter($tmpAdags, fn($pair) => $pair[1] < $i && $pair[1] <= $i);
        }

        if (array_sum(array_map(fn($pair) => $pair[0] < $cadetsSize && $pair[1] > $cadetsSize, $tmpAdags)) > 0) {
            usort($ansDsc, fn($a, $b) => $a[0] <=> $b[0]);
            return $ansDsc[0];
        }

        // Additional logic
        if (false) {
            foreach ($adags as [$i, $j]) {
                if (max($i, $j) > $cadetsSize && min($i, $j) <= $cadetsSize) {
                    if ($j - $i === $maxSize2 - max($i, $cadetsSize)) {
                        return [$cadetsSize - $i, $cadetsSize - $j, $maxSize1];
                    }
                }
            }
        }

        return [-1, -1, -1];
    }

    protected function evening2(array $inputArr): array
    {
        for ($i = 1; $i < 3; $i++) {
            for ($j = 0; $j < 2 - $i; $j++) {
                $k = 2 - $i - $j;
                if ($k < 1) {
                    continue;
                }

                $curTries = 1;

                while ($curTries < $this->maxTries) {
                    $ans = $this->getAns(1 + $i, array_reverse($inputArr)[0] + $j, array_reverse($inputArr)[1] + $k, $k, $inputArr[3][0]);

                    if ($ans === [-1, -1, -1]) {
                        break;
                    }

                    $otherDigs = ($i === 1) ? array_slice($inputArr[3], 1) : $inputArr[3];
                    $curTries++;
                }

                if ($ans !== [-1, -1, -1]) {
                    return $ans;
                }
            }
        }

        return [-1, -1, -1];
    }
}

