namespace Solution;

class Matrix
{
    private array $matrix;

    public function __construct(array $matrix)
    {
        $this->validateMatrix($matrix);
        $this->matrix = $matrix;
    }

    private function validateMatrix(array $matrix): void
    {
        foreach ($matrix as $row) {
            if (!is_array($row)) {
                throw new \InvalidArgumentException("Each row must be an array.");
            }
        }
        if (empty($matrix) || empty($matrix[0])) {
            throw new \InvalidArgumentException("Matrix cannot be empty.");
        }
    }

    public function getMaximumArea(): int
    {
        $result = 0;
        for ($i = 0; $i < count($this->matrix); $i++) {
            if ($this->matrix[$i][0] === 1) {
                $result = 1;
                break;
            }
        }
        for ($i = 0; $i < count($this->matrix[0]); $i++) {
            if ($this->matrix[0][$i] === 1) {
                $result = 1;
                break;
            }
        }
        for ($i = 1; $i < count($this->matrix); $i++) {
            for ($j = 1; $j < count($this->matrix[0]); $j++) {
                $this->matrix[$i][$j] *= min($this->matrix[$i - 1][$j], $this->matrix[$i][$j - 1], $this->matrix[$i - 1][$j - 1]);
                if ($this->matrix[$i][$j] > $result) {
                    $result = $this->matrix[$i][$j];
                }
            }
        }
        return $result * $result;
    }
}

