namespace BrickGame;

class Game
{
    private int $n;

    public function __construct(int $n)
    {
        if ($n <= 0 || $n % 2 !== 0) {
            throw new \InvalidArgumentException("Input must be a positive even integer.");
        }
        $this->n = $n;
    }

    public function play(): void
    {
        for ($i = 0; $i < $this->n; $i++) {
            $input = $this->getInput();
            [$openingBricks, $closingBricks] = $this->parseBricks($input);
            $totalBricks = strlen($openingBricks) + strlen($closingBricks);

            if ($totalBricks === $this->n && empty($openingBricks) && empty($closingBricks)) {
                echo "0\n";
            } else {
                $moves = $totalBricks / 2 + ($totalBricks % 2) + ($totalBricks && !empty($openingBricks) || $totalBricks && !empty($closingBricks));
                echo "{$moves}\n";
            }
        }
    }

    private function getInput(): string
    {
        $input = trim(fgets(STDIN));
        if (empty($input)) {
            throw new \RuntimeException("Input cannot be empty.");
        }
        return $input;
    }

    private function parseBricks(string $s): array
    {
        $lastOpeningBricks = '';
        $lastClosingBricks = '';

        for ($i = 0; $i < strlen($s); $i++) {
            if ($s[$i] === '(') {
                $lastOpeningBricks = $s[$i] . $lastOpeningBricks;
            }
        }
        for ($i = strlen($s) - 1; $i >= 0; $i--) {
            if ($s[$i] === ')') {
                $lastClosingBricks = $s[$i] . $lastClosingBricks;
            }
        }
        return [$lastOpeningBricks, $lastClosingBricks];
    }

    public function lazyApproach(string $s): void
    {
        $bricks = [];
        for ($i = 0; $i < $this->n / 2; $i++) {
            $bricks[] = '(';
        }
        for ($i = 0; $i < $this->n / 2; $i++) {
            $bricks[] = ')';
        }
        $bricks = $this->processBricks($s, $bricks);
        $this->calculateMoves($s, $bricks);
    }

    private function processBricks(string $s, array $bricks): array
    {
        for ($i = $this->n - 1; $i >= $this->n / 2; $i--) {
            $bricks[] = $s[$i];
        }
        return $bricks;
    }

    private function calculateMoves(string $s, array $bricks): void
    {
        $sum = strlen($s) - 2 * count($bricks);
        echo ($sum % 2 === 0) ? ($sum / 2) . "\n" : (($sum + 1) / 2) . "\n";
    }
}

