function countGoodNodes(?TreeNode $root): int {
    $debug = false; // TODO: Set to true for debugging

    $helper = function (?TreeNode $node, int $maxVal) use (&$helper, $debug) {
        if ($node === null) {
            return true;
        }
        $isGood = $node->val >= $maxVal;
        $maxVal = max($maxVal, $node->val);
        if ($debug) {
            echo "Visiting Node: {$node->val}, IsGood: " . ($isGood ? 'true' : 'false') . "\n";
        }
        $isGood &= $helper($node->left, $maxVal);
        $isGood &= $helper($node->right, $maxVal);
        return $isGood;
    };

    $dfs = function (?TreeNode $node) use (&$dfs, $helper, $debug) {
        if ($node === null) {
            return 0;
        }
        $goodNodes = $dfs($node->left) + $dfs($node->right);
        $goodNodes += $helper($node, $node->val);
        if ($debug) {
            echo "At Node: {$node->val}, GoodNodes: $goodNodes\n";
        }
        return $goodNodes;
    };

    return $dfs($root);
}

