class CommonSubsequenceFinder
{
    private array $results = [];

    public function findCommonSubsequence(array $a, array $b): array
    {
        $n = count($a);
        $m = count($b);
        $bIndices = [];

        foreach ($b as $index => $value) {
            $bIndices[$value][] = $index;
        }

        // Helper function to check if a list is a subsequence in another list
        $isSubsequence = function (array $x, array $y): bool {
            $it = new \ArrayIterator($y);
            foreach ($x as $element) {
                $found = false;
                foreach ($it as $t) {
                    if ($element === $t) {
                        $found = true;
                        break;
                    }
                }
                if (!$found) {
                    return false;
                }
            }
            return true;
        };

        // Try to find the shortest common subsequence
        for ($length = 1; $length <= min($n, $m); $length++) {
            for ($i = 0; $i < $n; $i++) {
                $j = $i + $length;
                if ($j > $n) {
                    break;
                }
                $subseq = array_slice($a, $i, $length);
                if ($isSubsequence($subseq, $b)) {
                    return [true, $subseq];
                }
            }
        }

        return [false, []];
    }

    public function solveTestCases(array $testCases): array
    {
        foreach ($testCases as [$n, $m, $a, $b]) {
            [$exists, $subseq] = $this->findCommonSubsequence($a, $b);
            if ($exists) {
                $this->results[] = "YES";
                $this->results[] = count($subseq) . ' ' . implode(' ', $subseq);
            } else {
                $this->results[] = "NO";
            }
        }
        return $this->results;
    }
}

