class MajorityElementFinder {
    private ?int $candidate = null;
    private int $count = 0;

    public function majorityElement(array $A): int {
        foreach ($A as $num) {
            if ($this->count === 0) {
                $this->candidate = $num;
            }
            $this->count += ($num === $this->candidate) ? 1 : -1;
        }

        return $this->validateCandidate($A) ? $this->candidate : -1;
    }

    private function validateCandidate(array $A): bool {
        $occurrences = 0;

        foreach ($A as $num) {
            if ($num === $this->candidate) {
                $occurrences++;
            }
        }

        return $occurrences > count($A) / 2;
    }
}

