namespace MathTools;

class GCD_LCM {
    public static function gcd(int $x, int $y): int {
        if ($x === 0) return $y;
        if ($y === 0) return $x;

        if ($x === $y) return $x;
        if ($x === 1 || $y === 1) return 1;

        while ($y !== 0) {
            [$x, $y] = [$y, $x % $y];
        }
        return $x;
    }

    public static function lcm(int $x, int $y): int {
        return intdiv($x * $y, self::gcd($x, $y));
    }
