class BitManipulation {
    public static function n2b(int $num, int $kbits): array {
        $res = array_fill(0, 31, '0');
        for ($i = 0; $i < 31; $i++) {
            if ($num & (1 << (30 - $i))) {
                $res[$i] = '1';
            }
        }
        return array_slice($res, 0, $kbits);
    }

    public static function b2n(array $bitsArray): int {
        $res = 0;
        $bitsArray = array_filter($bitsArray, fn($v) => $v !== '');
        $bitsArray = array_map(fn($v) => $v > 0 ? '1' : '0', $bitsArray);
        $size = count($bitsArray);
        for ($i = 0; $i < $size; $i++) {
            $res |= (int)$bitsArray[$size - $i - 1] << $i;
        }
        return $res;
    }
