class SubsetSum
{
    private array $points;
    private int $count;

    public function __construct(array $points)
    {
        $this->points = $points;
        $this->count = count($points);
    }

    public function calculate(): int
    {
        $results = [];
        for ($i = 1; $i < (1 << $this->count); $i++) {
            $subset = [];
            foreach ($this->points as $index => $point) {
                if ($i & (1 << $index)) {
                    $subset[] = $point;
                }
            }
            $results[] = $this->f($subset);
        }

        return array_sum($results);
    }

    private function f(array $subset): int
    {
        $sum = 0;
        foreach ($subset as $point) {
            $sum += max(0, $point[0] + $point[1]);
        }
        return $sum;
    }
}

