        $componentSizes = array_map(function ($user) {
            return $this->size[$this->find($user)];
        }, array_keys($this->parent));

        foreach (array_keys($this->parent) as $user) {
            $componentSize = $componentSizes[$user];
            $blockedCount = 0;

            foreach ($this->blockedPairs[$user] ?? [] as $blockedUser => $_) {
                $blockedCount++;
            }

            $candidates[$user] = $componentSize - $blockedCount - 1;
        }

