    }

    public function execute() {
        if ($this->flag === 'rejudge') {
            exec('poj ' . implode(' ', array_slice($_SERVER['argv'], 1)), $output);
            exit(0);
        } else {
            $this->process();
        }
    }

    private function process() {
        $inputFile = fopen('in', 'r');
        $outputFile = fopen('out', 'w');
        $this->globalAnswer = $this->inOrOut();

        $testCaseCount = (int)fgets($inputFile);
        for ($t = 0; $t < $testCaseCount; $t++) {
            $line = ($t === ($testCaseCount - 1)) ? "\n" : '';
            fwrite($outputFile, $this->globalAnswer . $line);
        }

        fclose($inputFile);
        fclose($outputFile);
    }

    private function inOrOut() {
        $ans = [];
        for ($a = 1; $a <= 1e6; $a++) {
            for ($b = 1; $b <= 1e6; $b++) {
                for ($c = 1; $c <= 1e6; $c++) {
                    $x = max($a, $b, $c);
                    $y = max($a, $c, $b);
                    $z = max($b, $a, $c);
                    if ($x === $y && $y === $z && $x === $a) {
                        $ans[] = [$a, $b, $c];
                    }
                }
            }
        }

        if (!empty($ans)) {
            usort($ans, function($a, $b) {
                return $a <=> $b;
            });
            // Flatten the answers for output
            return implode(',', array_map(function($triplet) {
                return implode(' ', $triplet);
            }, $ans));
        } else {
            return 'NO';
        }
    }
}

