    private array $list_clear_list = [];

    public function listInput() {
        $s = explode(" ", trim(fgets(STDIN)));
        while ($s) {
            $this->f_list[] = array_shift($s);
            usort($this->f_list, fn($a, $b) => strlen($b) - strlen($a));
        }
    }

    private function listConvert(): bool {
        for ($index = 0; $index < count($this->f_list) - 1; $index++) {
            $one = $this->f_list[$index];
            $you = $this->f_list[$index + 1];
            foreach (str_split($you) as $i) {
                if (stripos($one, $i) !== false) {
                    return true;
                }
            }
        }
        return false;
    }

    private function listClear(): void {
        for ($index = 0; $index < count($this->f_list) - 1; $index++) {
            $one = $this->f_list[$index];
            $you = $this->f_list[$index + 1];
            if (in_array($you, $one)) {
                unset($this->f_list[$index]);
            } elseif ($index > 0) {
                $x = $this->f_list[$index - 1];
                $this->f_list[$index - 1] = $x . $one;
                unset($this->f_list[$index]);
            }
        }
        $this->f_list = array_values($this->f_list); // Reset keys
    }

    private function textProcess(): array {
        $volume_list = [];
        foreach ($this->f_list as $word) {
            $vol = 0;
            foreach (str_split($word) as $letter) {
                if (stripos($letter, $letter) !== false) {
                    $vol++;
                }
            }
            if ($vol > 0) {
                $volume_list[] = $vol;
            }
        }
        return $volume_list;
    }

    private function textConvert(): void {
        $volume_list = $this->textProcess();
        $max_volume = max($volume_list);
        echo $max_volume . PHP_EOL; // Debug print
    }

    public function run(): void {
        $this->listInput();
        $this->listClear();
        while (count($this->f_list) > 1) {
            if ($this->listConvert()) {
                $this->listClear();
            } else {
                $this->textConvert();
                break;
            }
        }
    }
}

