class CostCalculator {
    private int $testCases;
    private array $results = [];

    public function __construct(int $testCases) {
        $this->testCases = $testCases;
    }

    public function calculateCosts(array $inputs) {
        foreach ($inputs as $case) {
            [$x, $y] = $case['coordinates'];
            [$a, $b] = $case['costs'];
            $totalCost = $this->computeTotalCost($x, $y, $a, $b);
            $this->results[] = $totalCost;
            echo "Total Cost: $totalCost\n"; // Debug print
        }
    }

    private function computeTotalCost(int $x, int $y, int $a, int $b): int {
        $totalCost = 0;
        if ($a < $b / 2) {
            $totalCost = (abs($x) + abs($y)) * $a;
        } else {
            $minAbs = min(abs($x), abs($y));
            $totalCost = $minAbs * $b;
            $x = abs($x) - $minAbs;
            $y = abs($y) - $minAbs;
            $totalCost += $x * $a + $y * $a;
        }
        return $totalCost;
    }

    public function getResults(): array {
        return $this->results;
    }
}

