using System;
using System.Collections.Generic;
using System.Threading.Tasks;

class DecomposeSquareTenTree
{
    static int GetLevelLength(int level)
    {
        return (int)Math.Pow(10, Math.Pow(2, level - 1));
    }

    static List<int> Decompose(int L, int R, int level = 0)
    {
        if (L > R) return new List<int>();
        if (L == R) return new List<int> { 0 };

        int levelLength = GetLevelLength(level);
        if (R - L + 1 <= levelLength)
            return new List<int> { level };

        var result = new List<int>();
        while (L <= R)
        {
            int segmentLength = Math.Min(levelLength, R - L + 1);
            result.Add(level);
            L += segmentLength;
            if (L <= R)
            {
                result.AddRange(Decompose(L, R, level + 1));
                break;
            }
        }

        return result;
    }

    static async Task CompressAndPrint(int L, int R)
    {
        var sequence = Decompose(L, R);
        var compressedSequence = new List<(int level, int count)>();
        int currentLevel = sequence[0];
        int count = 1;

        foreach (var level in sequence[1..])
        {
            if (level == currentLevel)
                count++;
            else
            {
                compressedSequence.Add((currentLevel, count));
                currentLevel = level;
                count = 1;
            }
        }

        compressedSequence.Add((currentLevel, count));

        Console.WriteLine(compressedSequence.Count);
        foreach (var (level, count) in compressedSequence)
        {
            Console.WriteLine(level + " " + count);
        }
    }

    public static async Task Main()
    {
        int L = 1;
        int R = 10;
        await CompressAndPrint(L, R);
    }
}

