using System;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    const int MOD = 1000000007;

    static long[] Solve(int n, (int, int)[] s)
    {
        Array.Sort(s, (x, y) => y.Item1 != x.Item1 ? y.Item1.CompareTo(x.Item1) : x.Item2.CompareTo(y.Item2));
        long[] fact = new long[n + 1];
        long[] inv = new long[n + 1];

        fact[0] = 1;
        for (int i = 1; i <= n; i++)
        {
            fact[i] = fact[i - 1] * i % MOD;
        }

        inv[n] = Power(fact[n], MOD - 2, MOD);
        for (int i = n - 1; i > 0; i--)
        {
            inv[i] = inv[i + 1] * (i + 1) % MOD;
        }

        long[] dp = new long[1 << n];
        dp[0] = fact[n];
        for (int mask = 0; mask < (1 << n); mask++)
        {
            int b = CountBits(mask);
            for (int i = 0; i < n; i++)
            {
                if ((mask >> i & 1) == 0 && s[i].Item2 <= b)
                {
                    dp[mask | (1 << i)] += dp[mask] * inv[n - b] % MOD * fact[b - 1] % MOD;
                    dp[mask | (1 << i)] %= MOD;
                }
            }
        }

        long[] ans = new long[n + 1];
        for (int mask = 0; mask < (1 << n); mask++)
        {
            int b = CountBits(mask);
            ans[b] = Math.Max(ans[b], dp[mask]);
        }
        return ans;
    }

    static int CountBits(int mask)
    {
        int count = 0;
        while (mask > 0)
        {
            count += mask & 1;
            mask >>= 1;
        }
        return count;
    }

    static long Power(long x, long y, long p)
    {
        long res = 1;
        x %= p;
        while (y > 0)
        {
            if ((y & 1) == 1)
            {
                res = res * x % p;
            }
            y >>= 1;
            x = x * x % p;
        }
        return res;
    }

    static async Task Main(string[] args)
    {
        int t = int.Parse(Console.ReadLine());
        while (t-- > 0)
        {
            int n = int.Parse(Console.ReadLine());
            var s = Console.ReadLine().Split().Select(int.Parse)
                .Select((x, i) => (x, i + 1)).ToArray();
            var result = Solve(n, s);
            Console.WriteLine(result.Max());
        }
    }
}

