using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        int k = 3; // Example values
        int m = 4;
        int n = 5;
        List<int> V = new List<int> { 1, 2, 3, 4, 5 };

        int result = await Calculate(k, m, n, V);
        Console.WriteLine(result);
    }

    static async Task<int> Calculate(int k, int m, int n, List<int> V)
    {
        return await Task.Run(() =>
        {
            var dp = new int[m + 1, k + 1];
            for (int i = 0; i <= m; i++)
            {
                for (int j = 0; j <= k; j++)
                {
                    if (j == 0 || i == 0)
                        dp[i, j] = 0;
                    else if (i >= V[j - 1])
                        dp[i, j] = Math.Max(dp[i, j - 1], dp[i - V[j - 1], j - 1] + V[j - 1]);
                    else
                        dp[i, j] = dp[i, j - 1];
                }
            }
            return dp[m, k];
        });
    }
}

