    {
        var stack = new Stack<int>();
        stack.Push(8);
        stack.Push(7);
        stack.Push(11);
        stack.Push(5);
        stack.Push(1);

        Console.WriteLine("The original stack is : " + string.Join(", ", stack));
        Console.WriteLine("Reversing the stack.");

        await Task.Run(() => Reversing(stack));

        Console.WriteLine("The reversed stack is : " + string.Join(", ", stack));
    }

    static void Reversing(Stack<int> stack)
    {
        if (stack.Count > 0)
        {
            int temp = stack.Pop();
            Reversing(stack);
            InsertAtBottom(stack, temp);
        }
    }

    static void InsertAtBottom(Stack<int> stack, int temp)
    {
        if (stack.Count == 0)
        {
            stack.Push(temp);
        }
        else
        {
            int top = stack.Pop();
            InsertAtBottom(stack, temp);
            stack.Push(top);
        }
    }
}

