using System.Threading.Tasks;

class Program
{
    static async Task<int> MinOperationsToWriteY(int[][] grid)
    {
        int n = grid.Length;
        int mid = n / 2;

        int[] yCount = new int[3];
        int[] notYCount = new int[3];

        for (int r = 0; r < n; r++)
        {
            for (int c = 0; c < n; c++)
            {
                if ((r <= mid && (r == c || r == n - 1 - c)) || (r > mid && c == mid))
                {
                    yCount[grid[r][c]]++;
                }
                else
                {
                    notYCount[grid[r][c]]++;
                }
            }
        }

        int minOps = int.MaxValue;
        for (int yVal = 0; yVal < 3; yVal++)
        {
            for (int notYVal = 0; notYVal < 3; notYVal++)
            {
                if (yVal != notYVal)
                {
                    int ops = yCount.Sum() - yCount[yVal] + notYCount.Sum() - notYCount[notYVal];
                    minOps = Math.Min(minOps, ops);
                }
            }
        }

        return minOps;
    }

    static async Task Main(string[] args)
    {
        int[][] grid1 = new int[][] { new int[] { 1, 2, 2 }, new int[] { 1, 1, 0 }, new int[] { 0, 1, 0 } };
        Console.WriteLine(await MinOperationsToWriteY(grid1));  // Output: 3

        int[][] grid2 = new int[][] { new int[] { 0, 1, 0, 1, 0 }, new int[] { 2, 1, 0, 1, 2 }, new int[] { 2, 2, 2, 0, 1 }, new int[] { 2, 2, 2, 2, 2 }, new int[] { 2, 1, 2, 2, 2 } };
        Console.WriteLine(await MinOperationsToWriteY(grid2));  // Output: 12
    }
}

