class Interval
{
    public int Start { get; }
    public int End { get; }

    public Interval(int start, int end)
    {
        Start = start;
        End = end;
    }
}

class Solution
{
    public IList<Interval> OverlappedInterval(IList<Interval> intervals)
    {
        if (intervals.Count == 0) return new List<Interval>();

        var sortedIntervals = intervals.OrderBy(i => i.Start).ToList();
        var mergedIntervals = new List<Interval> { sortedIntervals[0] };

        for (int i = 1; i < sortedIntervals.Count; i++)
        {
            var current = sortedIntervals[i];
            var lastMerged = mergedIntervals.Last();

            if (current.Start <= lastMerged.End)
            {
                lastMerged.End = Math.Max(lastMerged.End, current.End);
            }
            else
            {
                mergedIntervals.Add(current);
            }
        }

        return mergedIntervals;
    }
}

