class Solution {
    static int LargestPowerOf2InRange(int n) {
        return 1 << (int)Math.Floor(Math.Log(n) / Math.Log(2));
    }

    public int CountSetBits(int n) {
        n++;
        int count = 0;
        while (n > 0) {
            int largest2InRange = LargestPowerOf2InRange(n);
            int totalOnesIn1To2RaisedPower = largest2InRange * (largest2InRange / 2);
            int msbCount = n - largest2InRange + 1;
            count += totalOnesIn1To2RaisedPower + msbCount;
            n -= largest2InRange;
        }
        return count;
    }

    static void Main() {
        Solution sol = new Solution();
        Console.WriteLine(sol.CountSetBits(4));  // Output: 5
        Console.WriteLine(sol.CountSetBits(17)); // Output: 35
    }
}

