int Time0(uint nr1, uint nr2, byte b1, byte b2, int type) {
    if (type == int.MaxValue) {
        return b1 > b2 ? (int)nr1 : (int)nr2;
    } else if (type != int.MinValue) {
        uint max;
        if (b1 > b2) {
            max = nr1 * b1 + nr2 * b1;
            nr1 *= b1;
            nr2 *= b1;
        } else {
            max = nr1 * b2 + nr2 * b2;
            nr1 *= b2;
            nr2 *= b2;
        }
        return (int)max;
    } else {
        return (int)(b1 > b2 ? nr1 * b1 + nr2 * b1 : nr1 * b2 + nr2 * b2);
    }
}

uint Time1(uint nr1, uint nr2, byte b1, byte b2) {
    uint first = nr1 * b1;
    uint second = nr2 * b2;
    int time = Time0(nr1, nr2, b1, b2, time);
    first += nr1 * b1;
    second += nr2 * b2;

    if (first > second) {
        time += Time0(nr1, nr2, b1, b2, int.MinValue);
    } else {
        time += Time0(nr1, nr2, b1, b2, int.MaxValue);
    }
    return time;
}

async Task<uint> Time2(uint nr1, uint nr2, byte b1, byte b2) {
    uint nr1_, nr2_, nr2_half;
    int halfTime;
    bool fc;

    if (nr1 > nr2) {
        fc = b1 > b2;
        if (b1 < b2) {
            nr1_ = nr2_ = nr2 / 2;
            nr2_half = nr2 - nr2_;
            halfTime = await Time1(nr2_, nr2_half, b1, b2);
        } else {
            nr1_ = nr2 / 2;
            nr2_half = nr2 - nr1_;
            halfTime = await Time1(nr1_, nr2_half, b1, b2);
        }

        if (fc) {
            nr1_ *= b1;
            nr1_ += nr2 - nr1_;
            nr2_ *= b1;
            nr2_ += nr1 - nr2_;
        }

        if (halfTime > Time0(nr1, nr2, b1, b2, int.MaxValue)) {
            halfTime = await Time2(nr1, nr1_, b1, b2);
        }
    }

    return halfTime;
}

