        var days = n % 7;

        for (var i = 0; i < weeks; i++) {
            total += (i + 1) * 7 + (1 + 7) * 7 / 2;
        }

        var start = weeks + 1;
        for (var i = 0; i < days; i++) {
            total += start + i;
        }

        return total;
    }
}

