    static int Solve(int n, int[] a)
    {
        int count = 0, b = 0, policeCount = 0, crimeCount = n;

        for (int i = 0; i < n; i++)
        {
            if (a[i] < 0)
                b++;
        }

        if (b < n)
        {
            int warriors = n;
            for (int i = 0; i <= n; i++)
            {
                if (warriors != 0 && a[i] != 0)
                {
                    warriors--;
                    b++;
                }
            }
        }

        while (policeCount != 0 && crimeCount != 0)
        {
            if (policeCount == 0)
            {
                count++;
                policeCount--;
            }

            if (policeCount > 0)
            {
                crimeCount--;
                policeCount++;
            }
            else
            {
                count = count;
                policeCount += b;
                b = 0;
            }
        }
        return count;
    }

