using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    static int MaxBouquetBeauty(int n, int k, List<int> beauties, List<string> colors)
    {
        if (k == n && colors.Distinct().Count() == 1)
            return -1;

        var colorGroups = new Dictionary<string, List<int>>();

        for (int i = 0; i < n; i++)
        {
            var color = colors[i];
            if (!colorGroups.ContainsKey(color))
                colorGroups[color] = new List<int>();
            colorGroups[color].Add(beauties[i]);
        }

        int maxBeauty = -1;

        // Best single color bouquet
        foreach (var roses in colorGroups.Values)
        {
            if (roses.Count >= k)
                maxBeauty = Math.Max(maxBeauty, roses.OrderByDescending(x => x).Take(k).Sum());
        }

        // Best two-color bouquet
        if (colorGroups.ContainsKey("W") && colorGroups.ContainsKey("O"))
        {
            for (int i = 1; i <= Math.Min(k, colorGroups["W"].Count); i++)
            {
                int wBeauty = colorGroups["W"].OrderByDescending(x => x).Take(i).Sum();
                int oBeauty = colorGroups["O"].OrderByDescending(x => x).Take(k - i).Sum();
                maxBeauty = Math.Max(maxBeauty, wBeauty + oBeauty);
            }
        }

        if (colorGroups.ContainsKey("R") && colorGroups.ContainsKey("O"))
        {
            for (int i = 1; i <= Math.Min(k, colorGroups["R"].Count); i++)
            {
                int rBeauty = colorGroups["R"].OrderByDescending(x => x).Take(i).Sum();
                int oBeauty = colorGroups["O"].OrderByDescending(x => x).Take(k - i).Sum();
                maxBeauty = Math.Max(maxBeauty, rBeauty + oBeauty);
            }
        }

        return maxBeauty;
    }

    static async Task Main()
    {
        var input = await System.IO.File.ReadAllTextAsync("input.txt");
        var data = input.Split();
        int n = int.Parse(data[0]);
        int k = int.Parse(data[1]);
        var beauties = data.Skip(2).Take(n).Select(int.Parse).ToList();
        var colors = data.Skip(2 + n).Take(n).ToList();
        Console.WriteLine(MaxBouquetBeauty(n, k, beauties, colors));
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    static Tuple<double, double> GetVector(double x1, double x2, double y1, double y2)
    {
        double xDiff = x1 - x2;
        double yDiff = y1 - y2;

        xDiff = xDiff <= 0 ? -xDiff : xDiff;
        yDiff = yDiff <= 0 ? -yDiff : yDiff;

        return Tuple.Create(xDiff, yDiff);
    }

    static async Task<int> GetQuantityByAsync(List<string[]> input, int tryNum = 0)
    {
        var vectors = new HashSet<Tuple<double, double>>();
        var lengthVectors = new HashSet<Tuple<double, double, double, double, double, double>>();

        for (int i = 1; i < input.Count; i++)
        {
            double x1 = double.Parse(input[0][1]);
            double y1 = double.Parse(input[0][2]);
            double x2 = double.Parse(input[i][1]);
            double y2 = double.Parse(input[i][2]);

            var (xDiff, yDiff) = GetVector(x1, x2, y1, y2);

            if (xDiff == 0) xDiff = double.PositiveInfinity;
            if (yDiff == 0) yDiff = double.PositiveInfinity;

            vectors.Add(Tuple.Create(xDiff, yDiff));
            lengthVectors.Add(Tuple.Create(xDiff, yDiff, x1, y1, x2, y2));
        }

        var prevVectors = new HashSet<Tuple<double, double, double, double, double, double>>(lengthVectors);

        for (int i = 0; i < prevVectors.Count * prevVectors.Count; i++)
        {
            foreach (var j in prevVectors)
            {
                for (int item = 1; item < input.Count; item++)
                {
                    double x1 = double.Parse(input[item][1]);
                    double y1 = double.Parse(input[item][2]);
                    double x2 = j.Item4;
                    double y2 = j.Item5;

                    var (xDiff, yDiff) = GetVector(x1, x2, y1, y2);

                    if (xDiff == 0) xDiff = double.PositiveInfinity;
                    if (yDiff == 0) yDiff = double.PositiveInfinity;

                    lengthVectors.Add(Tuple.Create(xDiff, yDiff, x1, y1, x2, y2));
                    vectors.Add(Tuple.Create(xDiff, yDiff));
                }
            }
        }

        int total = vectors.Count;
        tryNum++;

        if (lengthVectors.Count >= total || tryNum > 3)
            return total;
        else
            return await GetQuantityByAsync(input, tryNum);
    }

    static async Task Main(string[] args)
    {
        int n = int.Parse(Console.ReadLine());
        var input = new List<string[]>();

        for (int i = 0; i < n; i++)
        {
            string strg = Console.ReadLine();
            input.Add(strg.Split());
        }

        if (input[0].Length > 3)
            Console.WriteLine(1);
        else
            Console.WriteLine(await GetQuantityByAsync(input));
    }
}

using System;
using System.Collections.Generic;
using System.Linq;

class Solution
{
    public string Exercise(int N, int M, int[][] A, int src, int dest, int X)
    {
        var adj = new Dictionary<int, List<(int neighbor, int weight)>>();
        for (int i = 0; i < M; i++)
        {
            int u = A[i][0], v = A[i][1], w = A[i][2];
            if (!adj.ContainsKey(u))
                adj[u] = new List<(int, int)>();
            adj[u].Add((v, w));

            if (!adj.ContainsKey(v))
                adj[v] = new List<(int, int)>();
            adj[v].Add((u, w));
        }

        var distance = Enumerable.Repeat(int.MaxValue, N).ToArray();
        distance[src] = 0;
        var toExplore = new Queue<int>();
        toExplore.Enqueue(src);

        while (toExplore.Count > 0)
        {
            int node = toExplore.Dequeue();
            foreach (var (neighbor, weight) in adj[node])
            {
                if (distance[node] + weight < distance[neighbor])
                {
                    distance[neighbor] = distance[node] + weight;
                    toExplore.Enqueue(neighbor);
                }
            }
        }

        int resultDistance = distance[dest];
        return resultDistance > X ? "Neeman's Wool Joggers" : "Neeman's Cotton Classics";
    }

    static void Main()
    {
        int N = 4;
        int M = 3;
        int src = 0;
        int dest = 3;
        int X = 3;
        int[][] A = new int[][]
        {
            new int[] { 0, 1, 2 },
            new int[] { 1, 2, 3 },
            new int[] { 2, 3, 1 }
        };

        var solution = new Solution();
        var result = solution.Exercise(N, M, A, src, dest, X);
        Console.WriteLine(result);
    }
}

using System;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        string input = Console.ReadLine();
        int result = CalculateRotations(input);
        Console.WriteLine(result);
    }

    static int CalculateRotations(string s)
    {
        int totalRotations = 0;
        int currentPosition = 0;

        foreach (char c in s)
        {
            int targetPosition = c - 'a';

            int clockwiseRotation = (targetPosition - currentPosition + 26) % 26;
            int counterclockwiseRotation = (currentPosition - targetPosition + 26) % 26;

            totalRotations += Math.Min(clockwiseRotation, counterclockwiseRotation);
            currentPosition = targetPosition;
        }

        return totalRotations;
    }
}

