using System.Linq;
using System.Threading.Tasks;

public class ProteinAnalyzer
{
    private static readonly HashSet<char> HydrophobicAminoAcids = new HashSet<char> { 'I', 'L', 'M', 'F', 'W', 'Y', 'V' };

    private static bool IsAllResidues(string residues)
    {
        return residues.All(x => HydrophobicAminoAcids.Contains(x));
    }

    private static void PrintResult(string pro, double val)
    {
        if (val >= 0.05)
            Console.WriteLine($"{pro} with a frequency of {Math.Round(val, 3)} %");
        else
            Console.WriteLine($"{pro} NOT with a frequency of {Math.Round(val, 3)} %");
    }

    public static async Task SolveProb(IEnumerable<string> probChain, string[] residues)
    {
        var chainList = probChain.ToList();
        for (int i = 1; i < chainList.Count; i++)
        {
            var p1 = chainList[i];
            var p2 = chainList[i - 1];

            if (p1 == "LI" && IsAllResidues(new string(p1.Where(x => x != 'F' && x != 'W' && x != 'Y').ToArray())))
            {
                PrintResult(p2, CalculateFrequency(chainList, p1, p2));
            }
            else if (p1 != "LI" && p1 != "M" && IsAllResidues(p1))
            {
                if (IsAllResidues(new string(p1.Where(x => x != 'F' && x != 'W' && x != 'Y').ToArray())))
                {
                    PrintResult(p2, CalculateFrequency(chainList, p1, p2));
                }
            }
        }
        await Task.CompletedTask;
    }

    private static double CalculateFrequency(List<string> chain, string p1, string p2)
    {
        return Math.Round(p1.Count(x => x == p2[0]) * 2 * 100.0 / chain.Count - p2.Count(x => x == p2[0]) * 100.0 / chain.Count, 3);
    }

    public static void Main(string[] args)
    {
        var testInput = new[]
        {
            "LMLYYVWIFQYEVLLLGGGGYFFGKKFWHKWWLHHHKHFWQYFFGYGVWGWHVVYLYLFLHLYHVWQKHLVLNKKHWY",
            "LGLFVVVVVVVWLLLHHHHWWWIWYVVWVVVVVV",
            "WFYFFFVVVVVVVVV",
            "LLWYVVWVVVVVVVVVV",
            "WVWYWYWVVVVVVVVV"
        };

        var results = new[]
        {
            new[] { "I", "W" },
            new[] { "I" },
            Array.Empty<string>(),
            Array.Empty<string>(),
            Array.Empty<string>()
        };

        for (int i = 0; i < testInput.Length; i++)
            SolveProb(testInput[i].ToCharArray().Select(c => c.ToString()), results[i]).Wait();
    }
}

