                            int x = Math.Min((p + 1 - 3 * i2) * ((i2) % (4 * n + 2) - 4 * n + 3) + Convert.ToInt32((p + 1 - 3 * i2) * ((i2) % (4 * n + 2) - 4 * n + 3) > 0),
