using System;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    static async Task<int> ProcessAsync(int n, int m, int[] arr)
    {
        var board = new int[arr.Max() + 1][];
        for (int i = 0; i < board.Length; i++)
        {
            board[i] = new int[n];
        }

        for (int i = 0; i < m; i++)
        {
            board[arr[i]][i] = 1;
        }

        int points = 0;

        while (true)
        {
            var newRow = new int[n];
            for (int col = 0; col < n; col++)
            {
                while (board[^1][col] == 1)
                {
                    newRow[col] = 1;
                    board[^1][col] = 0;
                    Array.Resize(ref board[^1], board[^1].Length - 1);
                }
                newRow[col] += board[^1][col];
            }
            if (newRow.All(x => x == 0))
            {
                break;
            }
            board = board.Append(newRow.ToArray()).ToArray();
            points++;
        }
        return points;
    }

    static async Task Main()
