IEnumerable<string> GenPas(int ind, int aC, int bC, int lp, int rp) {
    if (lp < aC || rp - lp < bC - aC) yield break;

    if (lp == 0 && rp == bC) yield return string.Empty;

    for (int d = 0; d < 2; d++) {
        if (d == 1 && lp > aC) {
            yield return "(" + (bC >= aC + 1 && rp >= 1 ? ")" : "") + GenPas((0, d != 1 ? -bC + lp : lp) + 1, aC + d, 2 + lp, -rp + 1);
        } else if (lp + 1 < rp && rp >= bC) {
            yield return GenPas(ind, aC, bC, lp + 1, rp);
        }
    }
}

