int ThanosSort(int[] arr)
{
    int n = arr.Length;
    if (n == 1)
        return 1;

    int[] sortedArr = (int[])arr.Clone();
    Array.Sort(sortedArr);

    if (StructuralComparisons.StructuralEqualityComparer.Equals(arr, sortedArr))
        return n;

    return Math.Max(ThanosSort(arr[..(n / 2)]), ThanosSort(arr[(n / 2)..]));
}

