public class Solution {
    public int MinCost(string source, string target, string[] original, string[] changed, int[] cost) {
        int n = source.Length;
        int m = original.Length;
        int[,] dp = new int[n + 1, m + 1];

        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= m; j++) {
                if (i == 0 && j == 0) {
                    dp[i, j] = 0;
                } else if (i == 0 || j == 0) {
                    dp[i, j] = int.MaxValue;
                } else {
                    dp[i, j] = Math.Min(dp[i, j - 1], dp[i - 1, j]) + cost[i - 1];
                    if (i > 0 && j > 0) {
                        dp[i, j] = Math.Min(dp[i, j], dp[i - 1, j - 1] + cost[i - 1]);
                    }
                }
            }
        }
        return dp[n, m];
    }
}

int MaximizeAccountBalance(int n) 
{
    if (n >= 0) 
        return n;

    string nStr = n.ToString();
    int removeLast = int.Parse(nStr.Substring(0, nStr.Length - 1));
    int removeBeforeLast = int.Parse(nStr.Substring(0, nStr.Length - 2) + nStr[nStr.Length - 1]);

    return Math.Max(n, Math.Max(removeLast, removeBeforeLast));
}

