int LongestAwesome(string s) {
    int ans = 0, prefix = 0;
    Dictionary<int, int> seen = new Dictionary<int, int> { { 0, -1 } };

    for (int i = 0; i < s.Length; i++) {
        prefix ^= 1 << (s[i] - '0');
        ans = Math.Max(ans, seen.ContainsKey(prefix) ? i - seen[prefix] : i + 1);

        for (int k = 0; k < 10; k++) {
            int x = prefix ^ (1 << k);
            if (seen.ContainsKey(x)) {
                ans = Math.Max(ans, i - seen[x]);
            }
        }

        if (!seen.ContainsKey(prefix)) {
            seen[prefix] = i;
        }
    }

    return ans;
}

