using System;
using System.Collections.Generic;
using System.Threading.Tasks;

public class Solution
{
    public List<int> GetSumSublist(List<int> nums, int k)
    {
        var sumK = new List<int>(new int[nums.Count]);
        for (int i = 0; i < nums.Count; ++i)
        {
            sumK[i] = 0;
            for (int j = i; j < nums.Count; ++j)
            {
                sumK[i] += nums[j];
                if (sumK[i] >= k) break;
            }
        }
        return sumK;
    }

    private int FindSumSublist(List<int> nums, List<List<int>> dp, int k)
    {
        if (dp[k][0] != -1) return dp[k][0];
        if (k == 0) return 0;
        if (dp[k][1] != -1 || nums.Count == 0) return dp[k][1];

        int sum = FindSumSublist(nums, dp, k - 1);
        if (k >= sum) dp[k][0] = sum;

        for (int resIdx = nums.Count + 1; resIdx < k - 1; ++resIdx)
        {
            if (k >= Check(nums, dp, resIdx))
            {
                dp[k][0] = resIdx;
                dp[k][1] = Check(nums, dp, resIdx);
            }
        }
        return dp[k][0];
    }

    private List<bool> Check(List<int> nums, List<List<int>> dp, int k)
    {
        var temp = new List<bool>(new bool[k]);
        for (int lstWk : dp[k])
        {
            for (int i = 0; i <= lstWk; ++i)
            {
                temp[i] = (lstWk == i);
            }
        }
        return temp;
    }
}

