public class Solution
{
    private readonly SortedSet<int> maxHeap = new SortedSet<int>(Comparer<int>.Create((x, y) => y.CompareTo(x)));
    private readonly SortedSet<int> minHeap = new SortedSet<int>();

    public void InsertHeap(int x)
    {
        maxHeap.Add(x);
        BalanceHeaps();
    }

    private void BalanceHeaps()
    {
        if (maxHeap.Count > minHeap.Count + 1)
        {
            minHeap.Add(maxHeap.Max);
            maxHeap.Remove(maxHeap.Max);
        }
        else if (minHeap.Count > maxHeap.Count)
        {
            maxHeap.Add(minHeap.Min);
            minHeap.Remove(minHeap.Min);
        }
    }

    public double GetMedian()
    {
        if (maxHeap.Count == minHeap.Count)
        {
            return (maxHeap.Max + minHeap.Min) / 2.0;
        }
        return maxHeap.Max;
    }
}

