    static Task<string> DetermineWinner(int n, int m, int[,] matrix)
    {
        int[] rows = new int[n];
        int[] cols = new int[m];

        for (int i = 0; i < n; i++)
        {
            for (int j = 0; j < m; j++)
            {
                if (matrix[i, j] == 1)
                {
                    rows[i] = 1;
                    cols[j] = 1;
                }
            }
        }

        int availableRows = n - rows.Sum();
        int availableCols = m - cols.Sum();

        if (availableRows == 0 || availableCols == 0 || (availableRows * availableCols) % 2 == 0)
        {
            return Task.FromResult("Vivek");
        }

        return Task.FromResult("Ashish");
    }
}

