class Solution
{
    public string PredictPartyVictory(string senate)
    {
        var qR = new Queue<int>();
        var qD = new Queue<int>();
        int n = senate.Length;

        for (int i = 0; i < n; i++)
        {
            if (senate[i] == 'R')
                qR.Enqueue(i);
            else
                qD.Enqueue(i);
        }

        while (qD.Count > 0 && qR.Count > 0)
        {
            int iD = qD.Dequeue();
            int iR = qR.Dequeue();

            if (iD < iR)
                qD.Enqueue(iD + n);
            else
                qR.Enqueue(iR + n);
        }

        return qR.Count > 0 ? "Radiant" : "Dire";
    }
}

