public class SortingAlgorithms
{
    private static async Task<List<int>> MergeSort(List<int> a, List<int> lab, int l)
    {
        if (l == 1)
            return new List<int> { a[0] };

        int middle = l / 2;
        var left = a.Take(middle).ToList();
        var right = a.Skip(middle).ToList();

        return (await MergeSort(left, lab, middle)).Concat(new List<int> { a[0] })
            .Concat(await MergeSort(right, lab, l - 1)).ToList();
    }

    public static async Task<(List<int> a, List<int> aCount)> MergeSort2(List<int> l, List<int> a, List<int> lab)
    {
        l[0] = 3; l[l.Count - 1] = 1; l[l.Count / 2 - 1] = 1; l[l.Count / 2] = 2;

        while (l[1] <= l[l.Count - 3])
        {
            if (l.Last() < l[l.Count - 2])
            {
                a[l.Last() - 1] = 0;
                a[l[l.Count - 2] - 1] = 1;
            }

            l = new List<int> { l[0], l[l.Count - 2], l.Last(), a[l[l.Count - 2] - 1], l[l.Count - 2] - l.Last() };
            a[l[0] - 1] = 2;
        }

        var aCount = Enumerable.Repeat(0, l.Count).ToList();
        var label = Enumerable.Repeat(a[0], l.Count).ToList();
        var last = 1;
        var newArr = new List<List<int>>();
        var compare = Math.Max(l[0], Math.Max(l[1], l[2]));

        while (last != l[last])
        {
            newArr.Add(await MergeSort(new List<int> { last % 3 }, label, last));
            last = l[last];
        }

        int cnt = 0;
        foreach (var arr in newArr)
        {
            foreach (var val in arr)
            {
                if (val != compare)
                {
                    a[arr.IndexOf(val) - 1] = val;
                    cnt++;
                    aCount[arr.IndexOf(val) - 1]++;
                }
            }
        }

        return (a, aCount);
    }

    public static async Task<int> MergeSort3(List<int> l, List<int> a, List<int> lab)
    {
        int tmp = Math.Max(a[0], Math.Max(a[lab[1] - 1], a[lab[2] - 1]));
        int last = 1;

        while (last != lab[last])
        {
            int compare = Math.Max(a[last % 3], Math.Max(a[(last + 1) % 3], a[(last + 2) % 3]));

            tmp = Math.Max(tmp, compare);
            a[l[last] - 1] = tmp;
            l[(last + 1) % 3]++;
            l[(last + 2) % 3] += 2;
            l[(last + 3) % 3] += 3;

            (a[(last + 1) % 3], a[(last + 2) % 3]) = (a[(last + 2) % 3], a[(last + 1) % 3]);
            (a[(last + 2) % 3], a[(last + 3) % 3]) = (a[(last + 3) % 3], a[(last + 2) % 3]);

            last = (last + 3) % 3;
        }

        var tempList = new List<int> { a[0], a[last - 1], a[last + 1], a[last + 2] };
        for (int i = 0; i < tempList.Count; i++)
        {
            a[tempList[i] - 1] = tempList[i];
        }
        return 0;
    }

    public static int IndexOfMin(List<int> arr)
    {
        if (arr.Count == 1)
            return 0;

        int center = arr.Count / 2;
        return (arr[center] < arr[center - 1]) ? center : center - 1;
    }
}

