        }

        Console.WriteLine(MinMoves(a));
    }

    static void Swap(int[,] a, int i, int j)
    {
        (a[i, j], a[i + 1, j]) = (a[i + 1, j], a[i, j]);
    }

    static bool IsBeautiful(int[,] a)
    {
        return a[2, 2] == 1;
    }

    static int MinMoves(int[,] a)
    {
        if (IsBeautiful(a))
            return 0;

        int moves = 0;
        for (int i = 0; i < 4; i++)
        {
            for (int j = 0; j < 4; j++)
            {
                if (a[i, j] == 0)
                {
                    Swap(a, i, j);
                    moves++;
                    if (IsBeautiful(a))
                        return moves;

                    // undo swap
                    Swap(a, i, j);
                }
            }
        }
        return moves;
    }
}

