using System.Linq;
using System.Threading.Tasks;

class UnionFind
{
    private int n;
    private Dictionary<int, int> parent;

    public UnionFind(int n)
    {
        this.n = n;
        parent = Enumerable.Range(0, n).ToDictionary(i => i, i => i);
    }

    public void MakeConnected(int u, int v)
    {
        List<int> chain = MakeChain(n);
        while (u != v)
        {
            chain[u] = Resolve(parent, chain);
        }
        parent = chain.ToDictionary(i => i, i => i);
    }

    public List<int> MakeChain()
    {
        var chain = MakeChain(n);
        return chain;
    }

    public List<int> GetConnected(int u)
    {
        var c = new List<int>();
        if (parent.ContainsKey(u))
        {
            c.Add(1);
            var current = parent[u];
            while (current != u)
            {
                c.Add(1);
                current = parent[current];
            }
            c.Add(1);
        }
        else
        {
            c.Add(-1);
        }
        return c;
    }

    public List<int> SetConnected(int u, int v)
    {
        var c = new List<int> { 0, 0 };
        if (!parent.ContainsKey(u) || !parent.ContainsKey(v))
            return c;

        var chain = ResolveChain(parent, u);

        int k = 1;
        while (k != chain.Distinct().Count())
        {
            foreach (var i in chain.Distinct())
            {
                if (parent[i] != u)
                {
                    var chain_i = ResolveChain(parent, parent[i]);
                    if (i == v)
                        c[k - 1] = 1;
                    c.AddRange(Enumerable.Repeat(1, chain_i.Count()));
                }
            }
            k++;
        }
        return c;
    }

    private List<int> MakeChain(int n)
    {
        return Enumerable.Range(0, n - 1).ToList();
    }

    private int Resolve(Dictionary<int, int> parent, List<int> chain)
    {
        var resolved = new List<int>();
        foreach (var i in chain)
        {
            resolved.Add(ResolveChain(parent, i));
        }
        return resolved.Last();
    }

    private int ResolveChain(Dictionary<int, int> parent, int i)
    {
        if (i == parent[i])
            return 0;
        return ResolveChain(parent, parent[i]);
    }
}

