        { 'd', "dfghjkl;" },
        { 'f', "fghjkl;" },
        { 'g', "ghjkl;" },
        { 'h', "hjkl;" },
        { 'j', "jkl;" },
        { 'k', "kl;" },
        { 'l', "l;" },
        { 'z', "zxcvbnm,./" },
        { 'x', "xcvbnm,./" },
        { 'c', "cvbnm,./" },
        { 'v', "vbnm,./" },
        { 'b', "bnm,./" },
        { 'n', "nm,./" },
        { 'm', "m,./" },
        { ',', ",./" },
        { '.', "./" },
        { '/', "/" }
    };

    private static Dictionary<string, char> Special;

    static MessageFinder()
    {
        Special = Keyboard.ToDictionary(kvp => kvp.Value, kvp => kvp.Key);
    }

    public static async Task<string> FindMessageAsync(char direction, string secret)
    {
        return await Task.Run(() => FindMessage(direction, secret));
    }

    private static string FindMessage(char direction, string secret)
    {
        var result = new List<char>();

        if (direction == 'R')
        {
            result.AddRange(Keyboard
                .Where(kvp => kvp.Value.Contains("]m"))
                .Select(kvp => kvp.Key)
                .SelectMany(item => item.ToString()));
        }
        else
        {
            result.AddRange(Keyboard
                .Where(kvp => kvp.Value.Contains("["))
                .Select(kvp => kvp.Key)
                .SelectMany(item => item.ToString()));
        }

        var keyboardMapping = direction == 'R' ? Keyboard : Special;
        var message = new List<char>();

        foreach (char ch in secret)
        {
            var mappedKey = keyboardMapping.FirstOrDefault(kvp => kvp.Value.Contains(ch)).Key;
            message.Add(mappedKey);
        }

        return new string(message.ToArray());
    }
}

