class Solution {
    public int MinStringLen(string pattern, string s) {
        int m = s.Length;
        int[][] dp = new int[m][];
        for (int i = 0; i < m; i++)
            dp[i] = new int[10];

        int oo = 1000000000 + 1;

        for (int dpIdx = 0; dpIdx < 10; dpIdx++) {
            for (int i = 0; i < m; i++) {
                if (pattern[i] == 'I') {
                    dp[i][dpIdx] = dp[s[i] - '0' - 1][0] + (1 << (dp[int.Parse(s[i + 1].ToString()) - 1][0] - dpIdx)) - 1;
                } else if (pattern[i] == 'D') {
                    dp[i][dpIdx] = Convert.ToInt32(string.Join("", new int[] { (1 << dp[int.Parse(s[i + 1].ToString()) - 1][0] - dpIdx) }));
                }
            }
        }

        int result = oo;
        for (int dpIdx = 0; dpIdx < 10; dpIdx++) {
            if (dp[0][dpIdx] < oo) {
                result = Math.Min(result, dpIdx);
            }
        }

        return result;
    }
}

