class StationVisits
{
    private Dictionary<int, int> horizon1;
    private Dictionary<int, int> horizon2;
    private HashSet<int> stations1;
    private HashSet<int> stations2;
    private int current1;
    private int current2;

    public StationVisits(int n, int a, int x, int b, int y)
    {
        horizon1 = new Dictionary<int, int>();
        horizon2 = new Dictionary<int, int>();

        for (int i = 1; i <= n; i++)
        {
            horizon1[i] = (i < n) ? (i + 1) : 1;
            horizon2[i] = (i > 1) ? (i - 1) : n;
        }

        stations1 = new HashSet<int> { a, x };
        stations2 = new HashSet<int> { b, y };
        current1 = a;
        current2 = b;
    }

    public string CheckSameStation()
    {
        while (stations1.Contains(current1) && stations2.Contains(current2))
        {
            int visitNext1 = horizon1[current1];
            int visitNext2 = horizon2[current2];

            if (visitNext1 == visitNext2)
                return "YES";

            if (stations1.Contains(current1))
                current1 = visitNext1;
            else
                break;

            if (stations2.Contains(current2))
                current2 = visitNext2;
            else
                break;
        }

        return "NO";
    }
}

