    static List<(string, string)> GetPosition(double a, double d, int n)
    {
        var positions = new List<(string, string)>();
        for (int i = 1; i <= n; i++)
        {
            double distance = i * d;
            int numLaps = (int)(distance / (4 * a));
            double remainingDistance = distance - numLaps * 4 * a;

            double x, y;
            if (remainingDistance < a)
            {
                x = remainingDistance;
                y = 0;
            }
            else if (remainingDistance < 2 * a)
            {
                x = a;
                y = remainingDistance - a;
            }
            else if (remainingDistance < 3 * a)
            {
                x = 3 * a - remainingDistance;
                y = a;
            }
            else
            {
                x = 0;
                y = 4 * a - remainingDistance;
            }

            positions.Add((x.ToString("F10", CultureInfo.InvariantCulture), y.ToString("F10", CultureInfo.InvariantCulture)));
        }
        return positions;
    }
}

public class Solution {
    public int MaxDistance(int[] nums) {
        int maxDist = (nums.Length - 1) - 1;
        int dist = 1;

        for (int i = 1; i < nums.Length; i++) {
            dist += Math.Min(nums[i] - nums[i - 1], nums[i] - (i + 1));
            maxDist = Math.Max(maxDist, dist);
        }
        return maxDist;
    }

    public static int MaxDistanceBruteForce(int[] nums) {
        return GetMinNumFromRight(nums) * nums[0] - GetNumFromLeft(nums);
    }

    private static int GetNumFromLeft(int[] nums) {
        int leftSum = 0;
        int maxLeft = -1;

        foreach (int num in nums) {
            if (num + leftSum > maxLeft) {
                maxLeft = num + leftSum;
            }
            leftSum += num;
        }
        return maxLeft;
    }

    private static int GetMinNumFromRight(int[] nums) {
        int rightSum = 1;
        int maxLeft = Math.Max(nums[0], 1);

        for (int i = nums.Length - 1; i >= 0; i--) {
            rightSum *= nums[0];
            maxLeft = Math.Min(nums[i] - i, rightSum);
        }
        return maxLeft;
    }

    public int MaxDistanceDivideConquer(int[] nums) {
        int minDist = nums[nums.Length - 1] * nums[0] + nums[nums.Length - 2];
        int res = 0;

        for (int i = 0; i < nums.Length; i++) {
            res = Math.Max(res, 
                (Math.Min(nums[i], (nums[i] - 1) * (i < nums.Length - 1 ? nums[i + 1] : 0)) + 
                 Math.Min(nums[nums.Length - i - 1], nums[nums.Length - i - 1] * nums[i]) - 
                 Math.Min(nums[i], nums[nums.Length - i - 1])));
        }
        return res;
    }
}

