    {
        int count = 0;
        int powerOf2 = 1;

        while (powerOf2 <= r)
        {
            int powerOf3 = 1;
            while (powerOf2 * powerOf3 <= r)
            {
                if (l <= powerOf2 * powerOf3)
                {
                    count++;
