class Node
{
    public int Data;
    public Node Left;
    public Node Right;

    public Node(int data)
    {
        Data = data;
        Left = null;
        Right = null;
    }
}

public class Solution
{
    public Node ConvertToDLL(Node root)
    {
        (Node head, Node tail) = Helper(root);
        return head;
    }

    private (Node, Node) Helper(Node node)
    {
        if (node == null)
            return (null, null);

        if (node.Left == null && node.Right == null)
            return (node, node);

        (Node leftHead, Node leftTail) = Helper(node.Left);
        (Node rightHead, Node rightTail) = Helper(node.Right);

        if (leftHead != null)
        {
            leftTail.Right = rightHead;
            if (rightHead != null)
                rightHead.Left = leftTail;
            node.Left = null;
        }
        else
        {
            leftHead = rightHead;
        }

        if (rightTail != null)
            rightTail.Left = leftTail;
        else
            rightTail = leftTail;

        node.Right = null;
        return (leftHead, rightTail);
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class Solution
{
    public async Task<int> MinJumps(int[] arr)
    {
        var done = new HashSet<int>();
        var lastSeen = new Dictionary<int, int>();

        for (int i = 0; i < arr.Length; i++)
        {
            lastSeen[arr[i]] = i;
        }

        done.Add(arr[0]);

        var queue = new Queue<int>();
        queue.Enqueue(arr[0]);
        var visited = new Dictionary<int, int> { [arr[0]] = 0 };
        int moves = 0;

        while (queue.Count > 0)
        {
            int length = queue.Count;
            for (int j = 0; j < length; j++)
            {
                int current = queue.Dequeue();

                if (current == arr[^1])
                {
                    return moves;
                }

                visited[current] = moves;
                foreach (var a in new[] { current - 1, current + 1, arr.SkipWhile(x => x != current).Skip(1).FirstOrDefault() })
                {
                    if (lastSeen.TryGetValue(a, out int index) && index >= moves + 1 && index != lastSeen[current])
                    {
                        lastSeen[a] = moves;
                        done.Add(a);
                        if (a != current - 1 && a != current + 1)
                        {
                            queue.Enqueue(a);
                        }
                    }
                }
            }
            moves++;
        }

        return -1;
    }
}

class TreeNode {
    public int val;
    public TreeNode left;
    public TreeNode right;

    public TreeNode(int x) {
        val = x;
    }
}

public class Solution {
    public int MaxProduct(TreeNode root) {
        int totalSum = GetTotalSum(root);
        int maxProduct = 0;
        DuplicateNode(root);
        Stack<TreeNode> stack = new Stack<TreeNode>();
        stack.Push(root);

        while (stack.Count > 0) {
            var currentNode = stack.Pop();
            if (currentNode.left != null) {
                stack.Push(currentNode.left);
            }
            if (currentNode.right != null) {
                stack.Push(currentNode.right);
            }
            int currentSum = GetSubtreeSum(currentNode);
            int currentProduct = currentSum * (totalSum - currentSum);
            maxProduct = Math.Max(maxProduct, currentProduct);
        }

        return maxProduct % 1000000007;
    }

    private int GetTotalSum(TreeNode node) {
        if (node == null) return 0;
        return node.val + GetTotalSum(node.left) + GetTotalSum(node.right);
    }

    private int GetSubtreeSum(TreeNode node) {
        if (node == null) return 0;
        return node.val + GetSubtreeSum(node.left) + GetSubtreeSum(node.right);
    }

    private TreeNode DuplicateNode(TreeNode node) {
        if (node == null) return null;
        TreeNode newNode = new TreeNode(node.val);
        newNode.left = DuplicateNode(node.left);
        newNode.right = DuplicateNode(node.right);
        return newNode;
    }
}

