    static int ComputeFinalNumber(List<int> a, int modulo)
    {
        string op = "add";

        Func<int[], int> operation = x => (x.Length == 2) ? x[0] + x[1] : x[0] - x[1];

        List<int> AddOrSubtract(List<int> nums, string operation)
        {
            return operation == "add"
                ? Enumerable.Range(0, nums.Count - 1).Select(i => operation(new[] { nums[i], nums[i + 1] })).ToList()
                : Enumerable.Range(1, nums.Count - 1).Select(i => operation(new[] { nums[i], nums[i - 1] })).ToList();
        }

        int ReduceModulo(List<int> nums, string operation, int modulo)
        {
            while (nums.Count > 1)
            {
                nums = AddOrSubtract(nums, operation);
                nums[0] %= modulo;
                operation = (operation == "add") ? "sub" : "add";
            }
            return nums[0] % modulo;
        }

        return ReduceModulo(a, op, modulo);
    }

