class Program
{
    static void Main()
    {
        int n = int.Parse(Console.ReadLine());
        Console.WriteLine(CalculateRoundDances(n));
    }

    static BigInteger CalculateRoundDances(int n)
    {
        BigInteger chooseFirstDance = Combinations(n, n / 2);
        BigInteger arrangeFirstDance = Factorial((n / 2) - 1);
        BigInteger arrangeSecondDance = Factorial((n / 2) - 1);

        BigInteger totalWays = chooseFirstDance * arrangeFirstDance * arrangeSecondDance;
        totalWays /= 2;

        return totalWays;
    }

    static BigInteger Combinations(int n, int k)
    {
        return Factorial(n) / (Factorial(k) * Factorial(n - k));
    }

    static BigInteger Factorial(int x)
    {
        BigInteger result = 1;
        for (int i = 2; i <= x; i++)
        {
            result *= i;
        }
        return result;
    }
}

