    {
        int compareBound = int.Parse(Console.ReadLine());
        var primeList = await FindPrime(compareBound);
        var primes = primeList.Where(x => x != 0 && x < compareBound).ToArray();
        Console.WriteLine($"{primes.Last()}, {primes.Max()}");
    }

    static Task<int[]> FindPrime(int upperBound)
    {
        upperBound++;
        int[] primeList = Enumerable.Range(0, upperBound).ToArray();
        int n = 2;

        while (n * n <= upperBound)
        {
            if (primeList[n] != 0)
            {
                for (int i = 2 * n; i < primeList.Length; i += n)
                {
                    if (primeList[i] != 0)
                    {
                        primeList[i] = 0;
                    }
                }
            }
            n++;
        }

        return Task.FromResult(primeList);
    }
}

