    {
        var depth = 5; // Example depth
        var result = await Pascal(depth);
        Console.WriteLine(string.Join(", ", result));
    }

    static async Task<List<string>> Pascal(int depth, string path = "[1]")
    {
        if (depth < 1)
            return new List<string>();

        if (depth == 1)
            return new List<string> { path };

        var previousRow = await Pascal(depth - 1, path);
        var lastRow = previousRow.Last();
        var numbers = lastRow.Trim('[', ']').Split(' ').Select(int.Parse).ToArray();
        var newValue = numbers[^1] + numbers[^2]; // Use -2 and -1 for last two values

        return previousRow.Append($"[{lastRow[1]} {newValue} {lastRow[^1]}").ToList();
    }

    static List<int> GetNthRow(int n)
    {
        var row = new List<int> { 1 };
        for (int k = 1; k < n; k++)
        {
            row.Add(row[k - 1] * (n - k) / k);
        }
        return row;
    }
}

