class CakeCutting
{
    static void CutCake(int H, int W, int K, char[][] grid)
    {
        int[][] result = new int[H][];
        for (int i = 0; i < H; i++)
            result[i] = new int[W];

        int pieceNumber = 1;

        for (int i = 0; i < H; i++)
        {
            int startPiece = (i > 0) ? result[i - 1].Where(x => x > 0).Min() : pieceNumber;

            for (int j = 0; j < W; j++)
            {
                if (grid[i][j] == '#')
                {
                    result[i][j] = pieceNumber;
                    pieceNumber++;

                    for (int k = j; k < W; k++)
                    {
                        if (grid[i][k] == '.')
                        {
                            result[i][k] = result[i][j];
                        }
                        else
                        {
                            result[i][k] = pieceNumber;
                            pieceNumber++;
                            break;
                        }
                    }
                }
                else if (j > 0)
                {
                    result[i][j] = result[i][j - 1];
                }
            }
        }

        for (int j = 0; j < W; j++)
        {
            for (int i = 1; i < H; i++)
            {
                if (grid[i][j] == '#')
                {
                    result[i][j] = pieceNumber;
                    pieceNumber++;
                }
                else
                {
                    result[i][j] = result[i - 1][j];
                }
            }
        }

        foreach (var row in result)
        {
            Console.WriteLine(string.Join(" ", row));
        }
    }

    static void Main()
    {
        int H = int.Parse(Console.ReadLine());
        int W = int.Parse(Console.ReadLine());
        int K = int.Parse(Console.ReadLine());

        char[][] grid = new char[H][];
        for (int i = 0; i < H; i++)
        {
            grid[i] = Console.ReadLine().ToCharArray();
        }

        CutCake(H, W, K, grid);
    }
}

