    static (int, int, List<(int, int)>) MinInstability(int n, int k, int[] a)
    {
        var dp = new int[1 << (n + 1)];
        Array.Fill(dp, int.MaxValue);
        dp[0] = 0;

        for (int op = 0; op < k; op++)
        {
            var nextDp = new int[1 << (n + 1)];
            Array.Fill(nextDp, int.MaxValue);

            for (int state = 0; state < (1 << (n + 1)); state++)
            {
                if (dp[state] == int.MaxValue) continue;

                for (int target = 0; target < n; target++)
                {
                    if (NeedMove(state, target))
                    {
                        int nextState = state | (1 << target);
                        nextDp[nextState] = Math.Min(nextDp[nextState], dp[state] + Cost(state, target));
                    }
                }
            }

            dp = nextDp;
        }

        int minInstability = dp.Min();
        int minOperations = Array.IndexOf(dp, minInstability);

        var operations = new List<(int, int)>();
        for (int state = 0; state < (1 << (n + 1)); state++)
        {
            if (dp[state] == minInstability)
            {
                for (int target = 0; target < n; target++)
                {
                    if (NeedMove(state, target))
                    {
                        operations.Add((state ^ (1 << target), target + 1));
                        break;
                    }
                }
            }
        }

        operations.Sort();
        return (minInstability, operations.Count, operations);
    }

