class Solution
{
    public static int MaxScore(int[] a, int k, int z)
    {
        int n = a.Length;
        int[] rightScore = new int[n]; // Score if moving only to the right from index i
        int[] leftScore = new int[n]; // Score if the last move was to the left and we're at index i
        int[] leftCount = new int[n]; // Number of left moves made previously

        rightScore[0] = a[0];

        for (int i = 1; i < n; i++)
        {
            rightScore[i] = rightScore[i - 1] + a[i];

            if (i > 1 && leftCount[i - 2] < z)
            {
                leftScore[i] = Math.Max(leftScore[i - 1], (rightScore[i - 2] - rightScore[i - 1] + a[i]));
                leftCount[i] = leftCount[i - 1] + 1;
            }
        }

        return Math.Max(rightScore[n - 1], leftScore[n - 1]);
    }

    public static void Main()
    {
        int numCases = int.Parse(Console.ReadLine());
        for (int i = 0; i < numCases; i++)
        {
            var inputs = Console.ReadLine().Split();
            int n = int.Parse(inputs[0]);
            int k = int.Parse(inputs[1]);
            int z = int.Parse(inputs[2]);
            int[] a = Array.ConvertAll(Console.ReadLine().Split(), int.Parse);
            Console.WriteLine(MaxScore(a, k, z));
        }
    }
}

