using System;
using System.Collections.Generic;
using System.Threading.Tasks;

public class Program
{
    public static int CountVisitedCells(int[,] grid)
    {
        int m = grid.GetLength(0), n = grid.GetLength(1);
        int best = 0;

        for (int r = 0; r < m; r++)
        {
            for (int c = 0; c < n; c++)
            {
                best = Math.Max(best, Dfs(grid, r, c, r, c, new HashSet<(int, int)>()));
            }
        }
        return best;
    }

    private static int Dfs(int[,] grid, int startR, int startC, int r, int c, HashSet<(int, int)> visited)
    {
        if (visited.Contains((r, c))) return 0;

        visited.Add((r, c));
        int count = 1;

        if (c > startC && r > 0 && grid[r - 1, c] > grid[r, c - 1])
        {
            count += Dfs(grid, startR, startC, r - 1, c, visited);
        }

        if (c < grid.GetLength(1) - 1 && grid[r, c + 1] > grid[r, c])
        {
            count += Dfs(grid, startR, startC, r, c + 1, visited);
        }

        if (r < grid.GetLength(0) - 1 && grid[r + 1, c] > grid[r, c])
        {
            count += Dfs(grid, startR, startC, r + 1, c, visited);
        }

        if (r > startR && grid[r - 1, c] < grid[r, c])
        {
            count += Dfs(grid, startR, startC, r - 1, c, visited);
        }

        if (c < grid.GetLength(1) - 1 && grid[r, c + 1] < grid[r, c])
        {
            count += Dfs(grid, startR, startC, r, c + 1, visited);
        }

        if (r < grid.GetLength(0) - 1 && grid[r + 1, c] < grid[r, c])
        {
            count += Dfs(grid, startR, startC, r + 1, c, visited);
        }

        return count;
    }

    public static async Task Main(string[] args)
    {
        Console.WriteLine(CountVisitedCells(new int[,] { { 3, 1, 6 }, { -9, 5, 7 } }) == 4);
        Console.WriteLine(CountVisitedCells(new int[,] { { 3, 1 }, { 3, 4 } }) == 2);
        Console.WriteLine(CountVisitedCells(new int[,] { { 1, 1 }, { 1, 1 } }) == 1);
        Console.WriteLine(CountVisitedCells(new int[,] { { 1 }, { 4 }, { 3 }, { 2 }, { 1 } }) == 3);
        Console.WriteLine(CountVisitedCells(new int[,] { { 1 }, { 2 }, { 3 }, { 4 }, { 5 } }) == 3);
    }
}

int[] KnightsOfAPolygonalTable(int n, int k, int[] powers, int[] coins)
{
    int[][] dp = new int[n][];

    for (int i = 0; i < n; i++)
        dp[i] = new int[k + 1];

    for (int i = 0; i < n; i++)
    {
        dp[i][0] = coins[i]; // Base case: keep coins if 0 knights killed

        for (int j = 1; j <= k; j++)
        {
            for (int l = 0; l < i; l++)
            {
                if (powers[i] > powers[l]) // i can kill l
                {
                    dp[i][j] = Math.Max(dp[i][j], dp[l][j - 1] + coins[l]);
                }
            }
        }
    }

    int[] maxCoins = new int[n];
    for (int i = 0; i < n; i++)
    {
        for (int j = k; j >= 0; j--)
        {
            if (dp[i][j] > maxCoins[i])
            {
                maxCoins[i] = dp[i][j];
                break;
            }
        }
    }

    return maxCoins;
}

