class Program
{
    static async Task Main()
    {
        var (n, m) = await ReadIntsAsync();
        var a = await ReadIntsAsync();
        var result = Solve(n, m, a);
        Console.WriteLine(string.Join(" ", result));
    }

    static async Task<int[]> ReadIntsAsync()
    {
        var line = await Console.In.ReadLineAsync();
        return line.Split().Select(int.Parse).ToArray();
    }

    static int[] Solve(int n, int m, int[] a)
    {
        var ans = new int[n + 1];
        for (int i = 1; i <= n; i++)
        {
            for (int j = i; j <= n; j++)
            {
                ans[j] = Math.Min(ans[j], ans[j - 1] + a[i - 1] * (j - i + 1));
            }
        }
        return ans;
    }
