using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

class CustomAlphabetFinder
{
    public static async Task<string> FindCustomAlphabetAsync(string[] names)
    {
        int n = names.Length;
        var graph = new Dictionary<char, HashSet<char>>();
        var indegree = new Dictionary<char, int>();

        for (char c = 'a'; c <= 'z'; c++)
        {
            indegree[c] = 0;
            graph[c] = new HashSet<char>();
        }

        for (int i = 0; i < n - 1; i++)
        {
            for (int j = i + 1; j < n; j++)
            {
                int minLength = Math.Min(names[i].Length, names[j].Length);
                bool foundDiff = false;

                for (int k = 0; k < minLength; k++)
                {
                    if (names[i][k] != names[j][k])
                    {
                        if (!graph[names[i][k]].Contains(names[j][k]))
                        {
                            graph[names[i][k]].Add(names[j][k]);
                            indegree[names[j][k]]++;
                        }
                        foundDiff = true;
                        break;
                    }
                }
                if (!foundDiff && names[i].Length > names[j].Length)
                {
                    return "Impossible";
                }
            }
        }

        var sortedOrder = new List<char>();
        var queue = new Queue<char>(indegree.Where(x => x.Value == 0).Select(x => x.Key));

        while (queue.Count > 0)
        {
            char currentChar = queue.Dequeue();
            sortedOrder.Add(currentChar);

            foreach (var neighbor in graph[currentChar])
            {
                indegree[neighbor]--;
                if (indegree[neighbor] == 0)
                {
                    queue.Enqueue(neighbor);
                }
            }
        }

        return sortedOrder.Count == 26 ? new string(sortedOrder.ToArray()) : "Impossible";
    }

    public static async Task Main(string[] args)
    {
        var input = await System.IO.File.ReadAllLinesAsync("input.txt");
        int n = int.Parse(input[0]);
        var names = input.Skip(1).ToArray();

        string result = await FindCustomAlphabetAsync(names);
        Console.WriteLine(result);
    }
}

