int BadDaysInMopes(int[] a)
{
    int n = a.Length;

    // Initialize the memoization table for buying with minimum amount of money
    int[,] memo = new int[n, 2];

    // The first day, he can buy at the minimum price he can
    memo[0, 0] = a[0];
    int lastMin = a[0];

    for (int i = 1; i < n; i++)
    {
        memo[i, 0] = Math.Min(memo[i - 1, 0], memo[i - 1, 1]);  // Minimum buy with M-1 is persistent

        // If the minimum buy with M-1 is more than the current price, we don't care to buy at all
        if (memo[i - 1, 0] > a[i])
        {
            memo[i, 1] = a[i];
            lastMin = a[i];
        }
        else
        {
            memo[i, 1] = Math.Min(memo[i - 1, 1], memo[i - 1, 0] + a[i]);
            if (i < n - 1 && memo[i, 1] > a[i + 1])
            {
                lastMin = a[i];
            }
        }
    }

    // The second day is easier
    return n - Enumerable.Range(0, n)
        .Count(i => a[i] < lastMin || memo[i, 1] <= a[i]);
}

