int MinMovesToMakeBeautiful(int[][] matrix)
{
    int currentRow = 0, currentColumn = 0;

    for (int i = 0; i < matrix.Length; i++)
    {
        for (int j = 0; j < matrix[i].Length; j++)
        {
            if (matrix[i][j] == 1)
            {
                currentRow = i + 1; // Convert to 1-based index
                currentColumn = j + 1; // Convert to 1-based index
                break;
            }
        }
    }

    int horizontalDistance = Math.Abs(3 - currentRow);
    int verticalDistance = Math.Abs(3 - currentColumn);

    return horizontalDistance + verticalDistance;
}

