using System;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    const int MOD = 998244353;

    static long ModPow(long baseNum, long exp)
    {
        long result = 1;
        baseNum %= MOD;
        while (exp > 0)
        {
            if (exp % 2 == 1)
                result = (result * baseNum) % MOD;
            exp >>= 1;
            baseNum = (baseNum * baseNum) % MOD;
        }
        return result;
    }

    static void DpIterate(long[] frequencies, long n, long[][] dp)
    {
        for (int x = 0; x < 26; ++x)
        {
            dp[x][0] = 0;
            dp[x][1] = frequencies[x] > 0 ? 1 : 0;
        }

        for (long currLen = 2; currLen <= n; ++currLen)
        {
            for (int x = 0; x < 26; ++x)
            {
                for (long prevLen = 1; prevLen < currLen; ++prevLen)
                {
                    dp[x][currLen] = (dp[x][currLen] + dp[x][prevLen] * frequencies[x]) % MOD;
                }
                dp[x][currLen] = (dp[x][currLen] + dp[x][currLen - 1]) % MOD;
            }
        }
    }

    static async Task Main()
    {
        long n = long.Parse(Console.ReadLine());
        long[] frequencies = Console.ReadLine().Split().Select(long.Parse).ToArray();
        long[][] dp = new long[26][];

        for (int i = 0; i < 26; ++i)
        {
            dp[i] = new long[n + 1];
        }

        DpIterate(frequencies, n, dp);

        long answer = 0;
        for (int i = 0; i < 26; ++i)
        {
            answer = (answer + dp[i][n]) % MOD;
        }

        Console.WriteLine(answer);
    }
}

