using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.Extensions.Logging;

public class SpectatorCounter
{
    private readonly ILogger<SpectatorCounter> _logger;

    public SpectatorCounter(ILogger<SpectatorCounter> logger)
    {
        _logger = logger;
    }

    public async Task<int> CalculateStandingSpectatorsAsync(int n, int k, int t)
    {
        ValidateInputs(n, k, t);
        int standingSpectators;

        if (t >= n)
        {
            standingSpectators = n - t;
            _logger.LogInformation($"Time exceeds or equals total spectators. Standing spectators: {standingSpectators}");
        }
        else
        {
            standingSpectators = k - (t - k) + t;
            _logger.LogInformation($"Processed with input values. Standing spectators: {standingSpectators}");
        }

        return standingSpectators;
    }

    public async Task<int> CalculateStandingSpectatorsModAsync(int n, int t)
    {
        ValidateInputs(n, 0, t);
        int standingSpectators = n - (t % n);
        _logger.LogInformation($"Calculated standing spectators using modulo. Result: {standingSpectators}");
        return standingSpectators;
    }

    private void ValidateInputs(int n, int k, int t)
    {
        if (n <= 0)
            throw new ArgumentException("Total spectators must be greater than zero.", nameof(n));
        if (k < 0 || k > n)
            throw new ArgumentException("Seated spectators must be between 0 and total spectators.", nameof(k));
        if (t < 0)
            throw new ArgumentException("Time cannot be negative.", nameof(t));
    }

    public async Task MainAsync()
    {
        try
        {
            var input = Console.ReadLine();
            var inputData = input?.Split(' ').Select(int.Parse).ToArray();

            if (inputData == null || inputData.Length != 3)
            {
                _logger.LogError("Invalid input. Please provide three integers.");
                return;
            }

            int n = inputData[0];
            int k = inputData[1];
            int t = inputData[2];

            var standingCountTask1 = CalculateStandingSpectatorsAsync(n, k, t);
            var standingCountTask2 = CalculateStandingSpectatorsModAsync(n, t);

            await Task.WhenAll(standingCountTask1, standingCountTask2);

            Console.WriteLine(await standingCountTask1);
            Console.WriteLine(await standingCountTask2);
        }
        catch (Exception ex)
        {
            _logger.LogError($"An error occurred: {ex.Message}");
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class SignalProcessor
{
    private readonly int _m;
    private readonly List<int> _signal;
    private readonly List<int> _mark;

    public SignalProcessor(int m, List<int> signal, List<int> mark)
    {
        ValidateInput(m, signal, mark);

        _m = m;
        _signal = signal;
        _mark = mark;
    }

    public async Task<List<(int Start, int End)>> FindSignalLinesAsync()
    {
        return await Task.Run(() => FindSignalLines());
    }

    private List<(int Start, int End)> FindSignalLines()
    {
        var states = IdentifyStates();
        var signalLines = new List<(int Start, int End)>();

        for (int i = 0; i < _mark.Count; i++)
        {
            if (_mark[i] == 1)
            {
                var start = FindStart(i, states);
                var end = FindEnd(i, states);

                if (start != -1 && end != -1)
                {
                    signalLines.Add((start, end));
                }
                i = end; // Move index past this found line
            }
        }
        return signalLines;
    }

    private List<int> IdentifyStates()
    {
        return _mark.Select(x => x == 0 ? 0 : 1).ToList();
    }

    private int FindStart(int index, List<int> states)
    {
        int startPoint = 0;
        while (index - startPoint >= 0 && states[index - startPoint] == 1)
        {
            startPoint++;
        }
        return index - startPoint + 1; // Return the start index
    }

    private int FindEnd(int index, List<int> states)
    {
        int endPoint = 0;
        while (index + endPoint < states.Count && states[index + endPoint] == 1)
        {
            endPoint++;
        }
        return index + endPoint - 1; // Return the end index
    }

    private void ValidateInput(int m, List<int> signal, List<int> mark)
    {
        if (m <= 0 || m >= signal.Count)
        {
            throw new ArgumentException("Window size must be positive and less than signal length.");
        }

        if (signal.Count != mark.Count)
        {
            throw new ArgumentException("Signal and mark lists must be of the same length.");
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class IslandCounter
{
    public async Task<int> CountDistinctIslandsAsync(int[][] grid)
    {
        if (grid == null || grid.Length == 0 || grid[0].Length == 0)
        {
            throw new ArgumentException("Invalid grid input.");
        }

        HashSet<string> distinctIslands = new HashSet<string>();

        for (int x = 0; x < grid.Length; x++)
        {
            for (int y = 0; y < grid[0].Length; y++)
            {
                if (grid[x][y] == 1)
                {
                    List<(int, int)> path = new List<(int, int)>();
                    await DfsAsync(grid, x, y, x, y, path);
                    distinctIslands.Add(string.Join(",", path.OrderBy(p => p).Select(p => $"{p.Item1},{p.Item2}")));
                }
            }
        }

        return distinctIslands.Count;
    }

    private async Task DfsAsync(int[][] grid, int i, int j, int x, int y, List<(int, int)> path)
    {
        if (i < 0 || i >= grid.Length || j < 0 || j >= grid[0].Length || grid[i][j] != 1)
            return;

        grid[i][j] = 0;
        path.Add((i - x, j - y));

        await DfsAsync(grid, i - 1, j, x, y, path);
        await DfsAsync(grid, i + 1, j, x, y, path);
        await DfsAsync(grid, i, j - 1, x, y, path);
        await DfsAsync(grid, i, j + 1, x, y, path);
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.Extensions.Logging;

public class VarianceCalculator
{
    private readonly ILogger<VarianceCalculator> _logger;

    public VarianceCalculator(ILogger<VarianceCalculator> logger)
    {
        _logger = logger ?? throw new ArgumentNullException(nameof(logger));
    }

    public async Task<int> LargestVarianceAsync(string s)
    {
        if (string.IsNullOrWhiteSpace(s))
        {
            _logger.LogWarning("Input string is null or empty.");
            return 0;
        }

        var uniqueChars = s.Distinct().ToList();
        int maxVariance = 0;

        for (int i = 0; i < uniqueChars.Count; i++)
        {
            for (int j = 0; j < uniqueChars.Count; j++)
            {
                if (i == j) continue;

                int variance = await CalculateVarianceAsync(s, uniqueChars[i], uniqueChars[j]);
                maxVariance = Math.Max(maxVariance, variance);
            }
        }

        _logger.LogInformation("Largest variance found: {Variance}", maxVariance);
        return maxVariance;
    }

    private async Task<int> CalculateVarianceAsync(string s, char a, char b)
    {
        int countA = 0, countB = 0, variance = 0;

        foreach (char c in s)
        {
            if (c == a) countA++;
            if (c == b) countB++;

            if (countB > 0)
            {
                variance = Math.Max(variance, countA - countB);
            }
            else if (countA > 0)
            {
                variance = Math.Max(variance, countA - countB);
            }

            if (countA < countB)
            {
                countA = 0;
                countB = 0;
            }
        }

        await Task.CompletedTask; // Placeholder for potential async operations
        return variance;
    }
}

