using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        Console.Write("Enter a number: ");
        string input = Console.ReadLine()?.Trim();

        if (!int.TryParse(input, out int n) || n <= 0)
        {
            Console.WriteLine("Invalid input. Please enter a positive integer.");
            return;
        }

        try
        {
            int position = await Task.Run(() => Solve(n));
            Console.WriteLine(position);
        }
        catch (Exception ex)
        {
            Console.WriteLine($"An error occurred: {ex.Message}");
        }
    }

    private static int Solve(int n)
    {
        var results = new List<string>();

        for (int i = 1; i <= 9; i++)
        {
            var combinations = GenerateCombinations(i);
            results.AddRange(combinations);
        }

        results.Sort();
        int index = results.IndexOf(n.ToString()) + 1;

        if (index == 0)
        {
            throw new InvalidOperationException("Number not found in combinations.");
        }

        return index;
    }

    private static IEnumerable<string> GenerateCombinations(int length)
    {
        var characters = new[] { '4', '7' };
        return GetCombinations("", characters, length);
    }

    private static IEnumerable<string> GetCombinations(string prefix, char[] characters, int length)
    {
        if (length == 0)
        {
            yield return prefix;
            yield break;
        }

        foreach (var character in characters)
        {
            foreach (var combination in GetCombinations(prefix + character, characters, length - 1))
            {
                yield return combination;
            }
        }
    }
}

using System;
using System.Threading.Tasks;

public class StringDeletionProblem
{
    public static async Task Main(string[] args)
    {
        try
        {
            int testCases = GetInput("Enter number of test cases:");

            for (int i = 0; i < testCases; i++)
            {
                string inputString = GetInputString("Enter the string:");
                char character = GetCharacterInput("Enter the character:");

                if (CanReachSingleChar(inputString, character))
                {
                    Console.WriteLine("YES");
                }
                else
                {
                    Console.WriteLine("NO");
                }
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
        }
    }

    private static int GetInput(string message)
    {
        Console.WriteLine(message);
        if (int.TryParse(Console.ReadLine(), out int result))
        {
            return result;
        }
        throw new ArgumentException("Invalid input. Please enter a valid integer.");
    }

    private static string GetInputString(string message)
    {
        Console.WriteLine(message);
        string input = Console.ReadLine();
        if (string.IsNullOrWhiteSpace(input))
        {
            throw new ArgumentException("Input cannot be empty.");
        }
        return input;
    }

    private static char GetCharacterInput(string message)
    {
        Console.WriteLine(message);
        string input = Console.ReadLine();
        if (input.Length != 1)
        {
            throw new ArgumentException("Input must be a single character.");
        }
        return input[0];
    }

    private static bool CanReachSingleChar(string s, char c)
    {
        int matchCount = 0;

        foreach (char ch in s)
        {
            if (ch == c)
            {
                matchCount++;
            }
        }

        return matchCount > 0 && matchCount <= s.Length / 2;
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class PermutationCalculator
{
    public static async Task Main(string[] args)
    {
        if (args.Length < 2)
        {
            Console.WriteLine("Usage: <string> <k>");
            return;
        }

        string inputString = args[0];
        if (!int.TryParse(args[1], out int k) || k <= 0)
        {
            Console.WriteLine("The second argument must be a positive integer.");
            return;
        }

        try
        {
            long result = await CalculatePermutationsAsync(inputString, k);
            Console.WriteLine($"{inputString} is {result}");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"An error occurred: {ex.Message}");
        }
    }

    private static Task<long> CalculatePermutationsAsync(string input, int k)
    {
        return Task.Run(() =>
        {
            var uniquePermutations = GetUniquePermutations(input);
            return uniquePermutations.Count / k;
        });
    }

    private static HashSet<string> GetUniquePermutations(string input)
    {
        var results = new HashSet<string>();
        GeneratePermutations("", input, results);
        return results;
    }

    private static void GeneratePermutations(string prefix, string remaining, HashSet<string> results)
    {
        int n = remaining.Length;
        if (n == 0)
        {
            results.Add(prefix);
        }
        else
        {
            for (int i = 0; i < n; i++)
            {
                string newPrefix = prefix + remaining[i];
                string newRemaining = remaining.Substring(0, i) + remaining.Substring(i + 1);
                GeneratePermutations(newPrefix, newRemaining, results);
            }
        }
    }
}

