        catch (Exception ex)
        {
            Console.WriteLine($"An error occurred: {ex.Message}");
        }
    }

    private static async Task<int[]> ReadInputAsync()
    {
        Console.WriteLine("Enter integers separated by spaces:");
        var input = await Task.Run(() => Console.ReadLine());
        return input.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries)
                    .Select(int.Parse)
                    .OrderByDescending(i => i)
                    .ToArray();
    }

    private static int Solve(int[] t)
    {
        int n = t.Length;
        if (n == 0) return 0;

        var dp = new int[n + 1];
        dp[0] = 0;

        for (int i = 1; i <= n; i++)
        {
            dp[i] = Math.Max(t[i - 1] + (i >= 2 ? dp[i - 2] : 0), dp[i - 1]);
        }

        return dp[n];
    }
}

