using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class BerloggingGame
{
    public static async Task<string> FindBerloggingWinnerAsync(string[] rounds)
    {
        if (rounds == null || rounds.Length == 0)
        {
            throw new ArgumentException("Rounds cannot be null or empty.");
        }

        var pointsHistory = new List<(string Name, int Score)>();
        var scores = new Dictionary<string, int>();

        try
        {
            foreach (var entry in rounds)
            {
                var parts = entry.Split();
                if (parts.Length != 2 || !int.TryParse(parts[1], out var score))
                {
                    throw new ArgumentException($"Invalid entry format: {entry}");
                }

                var name = parts[0];

                if (scores.ContainsKey(name))
                {
                    scores[name] += score;
                }
                else
                {
                    scores[name] = score;
                }

                pointsHistory.Add((name, scores[name]));
            }

            var maxScore = scores.Values.Max();
            var potentialWinners = scores
                .Where(pair => pair.Value == maxScore)
                .Select(pair => pair.Key)
                .ToList();

            foreach (var (name, score) in pointsHistory)
            {
                if (potentialWinners.Contains(name))
                {
                    var tempScores = new Dictionary<string, int>();

                    foreach (var (pname, pscore) in pointsHistory)
                    {
                        if (!tempScores.ContainsKey(pname))
                        {
                            tempScores[pname] = 0;
                        }
                        tempScores[pname] += pscore;

                        if (pname == name && tempScores[pname] >= maxScore)
                        {
                            return name;
                        }
                    }
                }
            }

            throw new Exception("No winner found.");
        }
        catch (Exception ex)
        {
            LogError(ex);
            throw;
        }
    }

    private static void LogError(Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}");
    }
}

