class Program
{
    static async Task Main(string[] args)
    {
        try
        {
            int n = ReadInput();
            int[] a = ReadPrizePositions(n);
            long result = CalculateMinTime(n, a);
            Console.WriteLine(result);
        }
        catch (Exception ex)
        {
            LogError("An error occurred: " + ex.Message);
        }
    }

    static int ReadInput()
    {
        Console.Write("Enter number of prizes: ");
        if (!int.TryParse(Console.ReadLine(), out int n) || n < 1)
        {
            throw new ArgumentException("Invalid number of prizes. It must be a positive integer.");
        }
        return n;
    }

    static int[] ReadPrizePositions(int n)
    {
        Console.Write($"Enter {n} prize positions: ");
        int[] a = Console.ReadLine()
                        .Split(' ')
                        .Select(int.Parse)
                        .ToArray();

        if (a.Length != n || a.Any(x => x < 1 || x > 1000000))
        {
            throw new ArgumentException("Invalid prize positions. Ensure all values are between 1 and 1000000.");
        }
        return a;
    }

    static long CalculateMinTime(int n, int[] a)
    {
        if (n == 1)
        {
            return Math.Min(Math.Abs(1 - a[0]), Math.Abs(1000000 - a[0]));
        }

        long timeViaStart = Math.Abs(1 - a[0]) + Math.Abs(a[n - 1] - a[0]);
        long timeViaEnd = Math.Abs(1000000 - a[n - 1]) + Math.Abs(a[n - 1] - a[0]);
        return Math.Max(timeViaStart, timeViaEnd);
    }

    static void LogError(string message)
    {
        Console.WriteLine(message);
    }
}

