public class TreeConfiguration
{
    public async Task<string> CanAchieveAnyConfigurationAsync(int n, List<Tuple<int, int>> edges)
    {
        if (n <= 0 || edges == null)
        {
            LogError("Invalid input: n must be positive and edges cannot be null.");
            return "NO";
        }

        var graph = BuildGraph(n, edges);

        return await Task.FromResult(CheckNodeDegrees(n, graph));
    }

    private Dictionary<int, List<int>> BuildGraph(int n, List<Tuple<int, int>> edges)
    {
        var graph = new Dictionary<int, List<int>>();

        foreach (var edge in edges)
        {
            AddEdge(graph, edge.Item1, edge.Item2);
        }

        return graph;
    }

    private void AddEdge(Dictionary<int, List<int>> graph, int u, int v)
    {
        if (!graph.ContainsKey(u))
        {
            graph[u] = new List<int>();
        }
        if (!graph.ContainsKey(v))
        {
            graph[v] = new List<int>();
        }

        graph[u].Add(v);
        graph[v].Add(u);
    }

    private string CheckNodeDegrees(int n, Dictionary<int, List<int>> graph)
    {
        for (int node = 1; node <= n; node++)
        {
            if (graph.ContainsKey(node) && graph[node].Count >= 3)
            {
                return "YES";
            }
        }
        return "NO";
    }

    private void LogError(string message)
    {
        // Implement a logging mechanism or use Console for demonstration
        Console.WriteLine($"Error: {message}");
    }
