public class SubarrayCounter
{
    public async Task<int> CountDistinctSubarrayAsync(int[] arr)
    {
        if (arr == null)
        {
            throw new ArgumentNullException(nameof(arr), "Input array cannot be null.");
        }

        int n = arr.Length;
        if (n == 0)
        {
            return 0;
        }

        HashSet<int> distinctElements = new HashSet<int>(arr);
        int distinctCount = distinctElements.Count;
        int totalSubarrays = 0;

        for (int i = 0; i < n; i++)
        {
            for (int j = i; j < n; j++)
            {
                if (HasAllDistinctElements(arr, i, j, distinctCount))
                {
                    totalSubarrays++;
                }
            }
        }

        return await Task.FromResult(totalSubarrays);
    }

    private bool HasAllDistinctElements(int[] arr, int start, int end, int expectedDistinctCount)
    {
        HashSet<int> currentSet = new HashSet<int>();
        for (int k = start; k <= end; k++)
        {
            currentSet.Add(arr[k]);
        }
        return currentSet.Count == expectedDistinctCount;
    }
}

