public class Solution
{
    public async Task<List<List<int>>> GetPathsAsync(TreeNode root)
    {
        if (root == null)
        {
            Log("Root is null, returning empty list.");
            return new List<List<int>>();
        }

        var paths = await Task.Run(() => Helper(root, new List<int>()));
        return paths;
    }

    private List<List<int>> Helper(TreeNode node, List<int> path)
    {
        if (node == null)
        {
            return new List<List<int>>();
        }

        var currentPath = new List<int>(path) { node.Data };

        if (node.Left == null && node.Right == null)
        {
            return new List<List<int>> { currentPath };
        }

        var leftPaths = Helper(node.Left, currentPath);
        var rightPaths = Helper(node.Right, currentPath);

        leftPaths.AddRange(rightPaths);
        return leftPaths;
    }

