using System.Threading.Tasks;

public class DivisorFinder
{
    public async Task<List<List<List<int>>>> ClosestDivisorsAsync(long num)
    {
        if (num < 0)
        {
            throw new ArgumentOutOfRangeException(nameof(num), "Input must be a non-negative number.");
        }

        var pathsToNum1 = new List<List<List<int>>>();

        // Start the search with num + 1 and num + 2
        for (long i = num + 1; i <= num + 2; i++)
        {
            var finalPaths = await DfsAsync(i);
            var answer = new List<List<int>>();
            foreach (var path in finalPaths)
            {
                answer.Add(path[0][0] == -1 ? new List<int>() : path[0]);
            }
            pathsToNum1.Add(answer);
        }

        return pathsToNum1;
    }

    private async Task<List<List<List<int>>>> DfsAsync(long n)
    {
        var result = new List<List<List<int>>>();
        await Task.Yield();  // Simulate async operation

        if (n <= 2)
        {
            return new List<List<List<int>>> { new List<List<int>> { new List<int> { -1 } }, new List<List<int>>() };
        }

        // Try factors up to the square root
        for (long i = 2; i * i <= n; i++)
        {
            if (n % i == 0)
            {
                var subPath1 = await DfsAsync(n / i);
                result.Add(new List<List<int>> { new List<int> { (int)i }, subPath1[0], new List<int> { (int)(n / i) } });
                result.Add(new List<List<int>> { new List<int> { (int)i, (int)(n / i) }, subPath1[1] });
            }
        }

        // Handle unpaired factors for odd numbers
        if (Math.Sqrt(n) % 1 == 0)
        {
            var subPath = await DfsAsync(n / (long)Math.Sqrt(n));
            result.Add(new List<List<int>> { new List<int>(), subPath[0], new List<int> { (int)n } });
        }

        return result;
    }
}

