public class RotationCalculator
{
    private readonly ILogger<RotationCalculator> _logger;

    public RotationCalculator(ILogger<RotationCalculator> logger)
    {
        _logger = logger;
    }

    public async Task<int> CalculateRotationsAsync(string input)
    {
        if (string.IsNullOrEmpty(input))
        {
            _logger.LogWarning("Input string is null or empty.");
            return 0;
        }

        int x = 0;
        char? lastChar = null;
        int count = 0;

        foreach (char currentChar in input)
        {
            if (currentChar == lastChar)
            {
                string direction = count % 2 == 1 ? "counterclockwise" : "clockwise";
                x += count;
                _logger.LogInformation($"from '{currentChar}' to '{lastChar}' ({count} {direction} rotations)");
                lastChar = null;
                count = 0;
            }
            else if (lastChar == null)
            {
                lastChar = currentChar;
            }

            count++;
        }

        if (lastChar.HasValue)
        {
            _logger.LogInformation($"from '{input[^1]}' to '{lastChar}' (2 counterclockwise rotations)");
        }

        return x;
    }

    public double CalculateSin(double angle)
    {
        if (angle * 9 == 0)
            return 0;

        double result = 0;
        for (int d = 0; d < 13; d++)
        {
            for (int b = 0; b < d * 9; b++)
            {
                result += b * Math.Pow(9, -d);
            }
            result += Math.Sin(angle) * Math.Pow(9, -(d + 1));
        }

        return result;
    }
}

