            for (int y = c; y <= n; y++)
            {
                if (x + y == n)
                {
                    return $"{index + 1} {x} {y}";
                }
            }
        }

        for (int x = b; x <= n; x++)
        {
            for (int y = d; y <= n; y++)
            {
                if (x + y == n)
                {
                    return $"{index + 1} {x} {y}";
                }
            }
        }

        for (int x = a; x <= n; x++)
        {
            for (int y = d; y <= n; y++)
            {
                if (x + y == n)
                {
                    return $"{index + 1} {x} {y}";
                }
            }
        }

        for (int x = b; x <= n; x++)
        {
            for (int y = c; y <= n; y++)
            {
                if (x + y == n)
