    private static async Task<int> UpdateCostAsync(int value, int a, int b, ref int cnt, int currentCost)
    {
        if (value == 0)
        {
            currentCost += a + b;
            cnt++;
        }
        else
        {
            if (cnt % 2 == 0)
            {
                cnt++;
                currentCost += (a >> 1) + b + a;
            }
            else
            {
                currentCost += (a * 2) + b;
            }
        }

        return await Task.FromResult(currentCost);
    }

    private static void ValidateInputs(int T, int n, int a, int b, int[] s)
    {
        if (T <= 0) throw new ArgumentException("T must be greater than 0.");
        if (n <= 0) throw new ArgumentException("n must be greater than 0.");
        if (a < 0) throw new ArgumentException("a must not be negative.");
        if (b < 0) throw new ArgumentException("b must not be negative.");
        if (s == null || s.Length != n) throw new ArgumentException("s must be a valid array of length n.");
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class KnapsackSolver
{
    public int CalculateMaxValue(int N, int W, List<int> weights, List<int> values)
    {
        ValidateInputs(N, W, weights, values);

        int maxValue = 0;

        for (int mask = 0; mask < (1 << N); mask++)
        {
            int totalWeight = 0;
            int totalValue = 0;
            for (int i = 0; i < N; i++)
            {
                if ((mask & (1 << i)) != 0)
                {
                    totalWeight += weights[i];
                    totalValue += values[i];
                }
            }
            if (totalWeight <= W && totalValue > maxValue)
            {
                maxValue = totalValue;
            }
        }

        return maxValue;
    }

    private void ValidateInputs(int N, int W, List<int> weights, List<int> values)
    {
        if (N <= 0 || W <= 0)
        {
            throw new ArgumentException("N and W must be greater than zero.");
        }
        if (weights.Count != N || values.Count != N)
        {
            throw new ArgumentException("Weights and values list must match the number of items N.");
        }
    }

    public static async Task Main(string[] args)
    {
        try
        {
            var input = await ReadInputAsync();
            var N = int.Parse(input[0]);
            var W = int.Parse(input[1]);
            List<int> weights = new List<int>();
            List<int> values = new List<int>();

            for (int i = 2; i < input.Length; i += 2)
            {
                weights.Add(int.Parse(input[i]));
                values.Add(int.Parse(input[i + 1]));
            }

            var solver = new KnapsackSolver();
            int result = solver.CalculateMaxValue(N, W, weights, values);
            Console.WriteLine(result);
        }
