public class SubsetCounter
{
    public static int FindNumberOfSubsets(int[] nums, int s)
    {
        if (nums == null || nums.Length == 0)
            throw new ArgumentException("The input array must not be null or empty.");

        if (s < 0)
            throw new ArgumentOutOfRangeException(nameof(s), "Subset sum must be non-negative.");

        int n = nums.Length;
        var dp = new int[n + 1, s + 1];

        for (int i = 0; i <= n; i++)
            dp[i, 0] = 1; // Initialization: one way to make sum 0

        for (int numIdx = 1; numIdx <= n; numIdx++)
        {
            for (int sum = 1; sum <= s; sum++)
            {
                int num = nums[numIdx - 1];
                if (num <= sum)
                {
                    dp[numIdx, sum] = dp[numIdx - 1, sum] + dp[numIdx - 1, sum - num];
                }
                else
                {
                    dp[numIdx, sum] = dp[numIdx - 1, sum];
                }
            }
        }

        return dp[n, s];
    }
}

