class Program
{
    static async Task Main(string[] args)
    {
        try
        {
            var input = await ReadInputAsync();
            var results = new List<int>();

            foreach (var caseData in input)
            {
                var result = MinOperationsToEvenSum(caseData);
                results.Add(result);
            }

            PrintResults(results);
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
        }
    }

    private static async Task<List<List<int>>> ReadInputAsync()
    {
        var input = await System.IO.File.ReadAllTextAsync("input.txt"); // Adjust file reading as necessary
        var lines = input.Split(Environment.NewLine, StringSplitOptions.RemoveEmptyEntries);
        var testCases = new List<List<int>>();

        int T = int.Parse(lines[0]);
        for (int i = 1; i <= T; i++)
        {
            var caseData = lines[i].Split(' ').Select(int.Parse).ToList();
            testCases.Add(caseData.Skip(1).ToList()); // Skip count, keep only the numbers
        }

        return testCases;
    }

    private static int MinOperationsToEvenSum(List<int> A)
    {
        try
        {
            int totalSum = A.Sum();
            int oddCount = A.Count(a => a % 2 != 0);
            int evenCount = A.Count - oddCount;

            if (IsEven(totalSum))
                return 0;

            if (oddCount == 0)
                return -1;

            foreach (var value in A)
            {
                if (value % 2 != 0)
                {
                    int newValue = Transform(value);
                    if (IsEven(newValue))
                        return 1;
                }
            }

            return -1;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error processing operation: {ex.Message}");
            return -1;
        }
    }

    private static int Transform(int a) => a * Math.Max(0, (a + 1) / 2 - 1);

    private static bool IsEven(int n) => n % 2 == 0;

    private static void PrintResults(List<int> results)
    {
        foreach (var result in results)
        {
            Console.WriteLine(result);
        }
    }
}

