public class Program
{
    public static async Task Main(string[] args)
    {
        if (!int.TryParse(Console.ReadLine(), out int testCases) || testCases <= 0)
        {
            Console.WriteLine("Invalid number of test cases.");
            return;
        }

        for (int t = 0; t < testCases; t++)
        {
            if (!int.TryParse(Console.ReadLine(), out int n) || n <= 0)
            {
                Console.WriteLine("Invalid input for n.");
                continue;
            }

            var inputArray = Console.ReadLine().Split(' ').Select(int.Parse).ToList();
            ProcessArray(n, inputArray);
        }
    }

    private static void ProcessArray(int n, List<int> array)
    {
        var evenList = new List<int>();
        var oddCount = 0;
        var evenCount = 0;

        foreach (var number in array)
        {
            if (number % 2 == 0)
            {
                evenCount++;
                evenList.Add(number);
            }
            else
            {
                oddCount++;
            }
        }

        var difference = Math.Abs(oddCount - evenCount);
        var i = 0;
        var j = 0;

        while (difference != 0)
        {
            j = i + 1;

            if (i == evenCount - 1)
            {
                i = 0;
            }
            else
            {
                i++;
            }

            if (j == evenCount)
            {
                j++;
            }
            else
            {
                j++;
            }

            if (i < evenList.Count && j < evenList.Count)
            {
                var K = evenList[i];
                var L = evenList[j];

                if (K % 2 == 0 && L % 2 != 0)
                {
                    Swap(ref evenList[i], ref evenList[j]);
                }
                else if (K % 2 != 0 && L % 2 == 0)
                {
                    Swap(ref evenList[i], ref evenList[j]);
                }
            }
        }

        Console.WriteLine(difference);
    }

    private static void Swap(ref int a, ref int b)
    {
        var temp = a;
        a = b;
        b = temp;
    }
}

