    private static bool IsValidLine(string line, out string errorMessage)
    {
        errorMessage = string.Empty;

        if (string.IsNullOrWhiteSpace(line))
        {
            errorMessage = "Line is empty or whitespace.";
            return false;
        }

        var pattern = @"^word~([a-zA-Z]+)\((\d+),(\d+)\),""([A-Z]*)""\*([\d]+),$";
        var match = Regex.Match(line, pattern);

        if (!match.Success)
        {
            errorMessage = "Line does not match expected pattern.";
            return false;
        }

        string name = match.Groups[1].Value;
        int firstNum, secondNum, repeatCount;

        if (!int.TryParse(match.Groups[2].Value, out firstNum) ||
            !int.TryParse(match.Groups[3].Value, out secondNum) ||
            !int.TryParse(match.Groups[5].Value, out repeatCount))
        {
            errorMessage = "Conversion to number failed.";
            return false;
        }

        if (firstNum <= 0 || secondNum <= 0 || repeatCount <= 0)
        {
            errorMessage = "Numbers must be greater than zero.";
            return false;
        }

        return true;
    }

