            int t = GetTestCases();
            for (int i = 0; i < t; i++)
            {
                var (n, k) = GetInputs();
                n = await ProcessValuesAsync(n, k);
                Console.WriteLine(n);
            }
        }
        catch (Exception ex)
        {
            LogError("An error occurred: " + ex.Message);
        }
    }

    private static int GetTestCases()
    {
        Console.Write("Enter number of test cases: ");
        return int.Parse(Console.ReadLine());
    }

    private static (int, int) GetInputs()
    {
        Console.Write("Enter n and k: ");
        var inputs = Console.ReadLine()?.Split(' ');
        if (inputs?.Length != 2 || 
            !int.TryParse(inputs[0], out int n) || 
            !int.TryParse(inputs[1], out int k) || 
            k < 0)
        {
            throw new ArgumentException("Invalid input for n or k.");
        }
        return (n, k);
    }

    private static async Task<int> ProcessValuesAsync(int n, int k)
    {
        while (k > 0)
        {
            int r = await Task.Run(() => MaxDivisor(n));
            n = (n + r) % Modulus;
            k--;
        }
        return n;
    }

    private static int MaxDivisor(int n)
    {
        var divisors = GetDivisors(n).Where(d => d > 1).ToList();
        return divisors.Any() ? divisors.Max() : 1;
    }

    private static IEnumerable<int> GetDivisors(int number)
    {
        for (int i = 1; i <= Math.Sqrt(number); i++)
        {
            if (number % i == 0)
            {
                yield return i;
                if (i != number / i)
                {
                    yield return number / i;
                }
            }
        }
    }

