class Program
{
    static async Task Main(string[] args)
    {
        try
        {
            var data = await ReadInputAsync();
            var results = ProcessData(data);
            PrintResults(results);
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"An error occurred: {ex.Message}");
        }
    }

    static async Task<string[]> ReadInputAsync()
    {
        return await Task.Run(() => Console.ReadLine().Split());
    }

    static List<int> ProcessData(string[] data)
    {
        if (data.Length < 1 || !int.TryParse(data[0], out int t))
        {
            throw new ArgumentException("Invalid input format for number of test cases.");
        }

        var results = new List<int>();
        int index = 1;

        for (int i = 0; i < t; i++)
        {
            if (index + 3 >= data.Length || 
                !int.TryParse(data[index], out int a) || 
                !int.TryParse(data[index + 1], out int b) || 
                !int.TryParse(data[index + 2], out int c) || 
                !int.TryParse(data[index + 3], out int d))
            {
                throw new ArgumentException("Invalid input format for case parameters.");
            }
            index += 4;

            if (a <= b)
            {
                results.Add(b);
                continue;
            }

            results.Add(CalculateResult(a, b, c, d));
        }

        return results;
    }

    static int CalculateResult(int a, int b, int c, int d)
    {
        int remainingSleepNeeded = a - b;
        int sleepCount = 0;

        while (remainingSleepNeeded > 0)
        {
            if (sleepCount % 2 == 0)
            {
                remainingSleepNeeded -= d;
            }
            else
            {
                remainingSleepNeeded -= c;
            }
            sleepCount++;
        }

        return b + sleepCount * c;
    }

    static void PrintResults(List<int> results)
    {
        foreach (var res in results)
        {
            Console.WriteLine(res);
        }
    }
}

