using System;
using System.Collections.Generic;

public class Solution
{
    public bool ContainsCycle(char[][] grid)
    {
        if (grid == null || grid.Length == 0 || grid[0].Length == 0)
        {
            throw new ArgumentException("Invalid grid input.");
        }

        int m = grid.Length, n = grid[0].Length;
        bool[,] visited = new bool[m, n];
        bool[,] visitedLast = new bool[m, n];

        for (int i = 0; i < m; i++)
        {
            for (int j = 0; j < n; j++)
            {
                if (visited[i, j]) continue;

                Queue<(int, int)> queue = new Queue<(int, int)>();
                queue.Enqueue((i, j));
                visited[i, j] = true;
                var path = new List<(int, int)> { (i, j) };

                while (queue.Count > 0)
                {
                    var (x, y) = queue.Dequeue();

                    for (int dx = -1; dx <= 1; dx++)
                    {
                        for (int dy = -1; dy <= 1; dy++)
                        {
                            if (Math.Abs(dx) + Math.Abs(dy) != 1) continue;

                            int nx = x + dx, ny = y + dy;

                            if (IsOutOfBounds(nx, ny, m, n) || grid[nx][ny] != grid[x][y])
                            {
                                continue;
                            }

                            if (visitedLast[nx, ny])
                            {
                                return true;
                            }

                            if (!visited[nx, ny])
                            {
                                queue.Enqueue((nx, ny));
                                visited[nx, ny] = true;
                                path.Add((nx, ny));
                                visitedLast[nx, ny] = true;
                            }
                        }
                    }

                    if (path.Count >= 4) return true;

                    foreach (var p in path)
                    {
                        visitedLast[p.Item1, p.Item2] = false;
                    }
                }
            }
        }

        return false;
    }

    private bool IsOutOfBounds(int x, int y, int m, int n)
    {
        return x < 0 || x >= m || y < 0 || y >= n;
    }
}

