public class ChapterTimeCalculator
{
    public static async Task Main(string[] args)
    {
        try
        {
            var inputs = await ReadInputAsync();
            if (inputs == null) return;

            int n = inputs.Item1;
            int x = inputs.Item2;
            List<int> chapters = inputs.Item3;

            long totalTime = CalculateMinHours(n, x, chapters);
            Console.WriteLine(totalTime);
        }
        catch (Exception ex)
        {
            LogError("An error occurred while calculating minimum hours.", ex);
        }
    }

    private static async Task<Tuple<int, int, List<int>>> ReadInputAsync()
    {
        Console.WriteLine("Enter number of chapters and x value:");
        var firstLine = await Console.In.ReadLineAsync();
        var values = firstLine.Split(' ').Select(int.Parse).ToArray();

        if (values.Length != 2)
        {
            LogError("Invalid input for number of chapters and x value.");
            return null;
        }

        int n = values[0];
        int x = values[1];

        Console.WriteLine("Enter chapter times:");
        var secondLine = await Console.In.ReadLineAsync();
        var chapterTimes = secondLine.Split(' ').Select(int.Parse).ToList();

        if (chapterTimes.Count != n)
        {
            LogError("The number of chapter times does not match the specified number of chapters.");
            return null;
        }

        return Tuple.Create(n, x, chapterTimes);
    }

    private static long CalculateMinHours(int n, int x, List<int> chapters)
    {
        chapters.Sort();

        long totalTime = 0;

        for (int i = 0; i < n; i++)
        {
            int timeForSubject = Math.Max(1, x - i) * chapters[i];
            totalTime += timeForSubject;
        }

        return totalTime;
    }

