    {
        Console.WriteLine($"{DateTime.Now}: {message}");
        if (ex != null)
        {
            Console.WriteLine($"Error details: {ex.Message}");
        }
    }
}

using System;

public class Solution
{
    private static readonly int[,] Directions = { { 0, 1 }, { 1, 0 }, { 0, -1 }, { -1, 0 } };
    private int m, n, startCount, endX, endY, nonObstacleCount;

    public int UniquePathsIII(int[][] grid)
    {
        if (grid == null || grid.Length == 0 || grid[0].Length == 0)
        {
            throw new ArgumentException("Grid cannot be null or empty.");
        }

        m = grid.Length;
        n = grid[0].Length;

        InitializeGridParameters(grid);

        return Dfs(grid, 0, 0, startCount);
    }

    private void InitializeGridParameters(int[][] grid)
    {
        startCount = 0;
        endX = 0;
        endY = 0;
        nonObstacleCount = 0;

        for (int i = 0; i < m; i++)
        {
            for (int j = 0; j < n; j++)
            {
                if (grid[i][j] == -1) continue;

                nonObstacleCount++;
                if (grid[i][j] == 1) startCount = nonObstacleCount;
                if (grid[i][j] == 2)
                {
                    endX = i;
                    endY = j;
                }
            }
        }
    }

    private int Dfs(int[][] grid, int currentX, int currentY, int steps)
    {
        if (IsOutOfBounds(currentX, currentY) || grid[currentX][currentY] == -1 || grid[currentX][currentY] == -2)
        {
            return 0;
        }

        if (currentX == endX && currentY == endY && steps == nonObstacleCount)
        {
            return 1;
        }

        grid[currentX][currentY] = -2;

        int count = 0;
        for (int i = 0; i < Directions.GetLength(0); i++)
        {
            count += Dfs(grid, currentX + Directions[i, 0], currentY + Directions[i, 1], steps + 1);
        }

        RestoreGridCell(grid, currentX, currentY, steps);

        return count;
    }

    private bool IsOutOfBounds(int x, int y)
    {
        return x < 0 || x >= m || y < 0 || y >= n;
    }

    private void RestoreGridCell(int[][] grid, int x, int y, int steps)
    {
        grid[x][y] = steps == 0 ? 1 : steps == nonObstacleCount - 1 ? 2 : 0;
    }
}

