public class FractionComparer
{
    public async Task<string> CompareFractionsAsync(string input)
    {
        try
        {
            ValidateInput(input);
            var (frac1, frac2) = SplitFractions(input);
            var (a, b) = ParseFraction(frac1);
            var (c, d) = ParseFraction(frac2);

            return DetermineGreaterFraction(a, b, c, d, frac1, frac2);
        }
        catch (Exception ex)
        {
            LogError(ex);
            return "Error in comparison";
        }
    }

    private void ValidateInput(string input)
    {
        if (string.IsNullOrWhiteSpace(input) || !input.Contains(", "))
        {
            throw new ArgumentException("Input must be two fractions separated by a comma and a space.");
        }
    }

    private (string frac1, string frac2) SplitFractions(string input)
    {
        return input.Split(", ").Select(frac => frac.Trim()).ToArray();
    }

    private (int numerator, int denominator) ParseFraction(string fraction)
    {
        var parts = fraction.Split('/');
        if (parts.Length != 2 || !int.TryParse(parts[0], out var numerator) || !int.TryParse(parts[1], out var denominator) || denominator == 0)
        {
            throw new FormatException("Each fraction must be in the form 'numerator/denominator' and denominator cannot be zero.");
        }
        return (numerator, denominator);
    }

    private string DetermineGreaterFraction(int a, int b, int c, int d, string frac1, string frac2)
    {
        if (a * d > c * b)
        {
            return frac1;
        }
        else if (a * d < c * b)
        {
            return frac2;
        }
        return "equal";
    }

    private void LogError(Exception ex)
    {
        // Replace with a proper logging framework in production
        Console.WriteLine($"Error: {ex.Message}");
    }
}

