public class TramCapacityCalculator
{
    public static async Task<int> MinimumTramCapacityAsync(int numberOfStops, List<(int, int)> stops)
    {
        if (numberOfStops <= 0)
            throw new ArgumentException("Number of stops must be greater than zero.");

        if (stops == null || stops.Count != numberOfStops)
            throw new ArgumentException("Stops list must match the number of stops.");

        int currentPassengers = 0;
        int maxCapacity = 0;

        foreach (var stop in stops)
        {
            var (boarding, alighting) = stop;
            ValidateStop(boarding, alighting);

            currentPassengers -= boarding;
            currentPassengers += alighting;

            maxCapacity = Math.Max(maxCapacity, currentPassengers);
        }

        return maxCapacity;
    }

    private static void ValidateStop(int boarding, int alighting)
    {
        if (boarding < 0)
            throw new ArgumentOutOfRangeException(nameof(boarding), "Number of passengers alighting cannot be negative.");
        if (alighting < 0)
            throw new ArgumentOutOfRangeException(nameof(alighting), "Number of passengers boarding cannot be negative.");
