using System;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        try
        {
            await SolveAsync();
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
        }
    }

    static async Task SolveAsync()
    {
        long n = ReadLong("Enter a number: ");
        long[] ans = new long[3];
        long gt = 1;

        for (int i = 1; gt < n; i++)
        {
            gt = GCD(n, gt);
            if (gt >= ans[0]) continue;

            ans[2] = n;
            ans[0] = gt;
            n /= gt;
            ans[1] = n;
        }

        bool can = IsPythagorean(ans[0], ans[1]);

        if (!can)
        {
            ans[0] = -1;
            ans[1] = 0;
            ans[2] = 0;
        }

        PrintArray(ans);
    }

    static long ReadLong(string prompt)
    {
        Console.Write(prompt);
        if (!long.TryParse(Console.ReadLine(), out long result))
        {
            throw new ArgumentException("Invalid input, please enter a valid number.");
        }
        return result;
    }

    static long GCD(long a, long b)
    {
        while (b != 0)
        {
            long temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }

    static bool IsPythagorean(long m, long t)
    {
        return m < t && t * t == m + m;
    }

    static void PrintArray(long[] array)
    {
        Console.WriteLine(string.Join(", ", array));
    }
}

public class TurbulenceCalculator
{
    public int MaxTurbulenceSize(int[] array)
    {
        ValidateInput(array);

        int less = 1, more = 1, maxTurbulence = 1;

        for (int i = 1; i < array.Length; i++)
        {
            if (array[i - 1] < array[i])
            {
                less = more + 1;
                more = 1;
            }
            else if (array[i - 1] > array[i])
            {
                more = less + 1;
                less = 1;
            }
            else
            {
                less = 1;
                more = 1;
            }

            maxTurbulence = Math.Max(maxTurbulence, Math.Max(less, more));
        }

        return maxTurbulence;
    }

    private void ValidateInput(int[] array)
