using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class GarlandColoring
{
    public static (int, List<char>) MinRecolorsToDiverse(string garland)
    {
        ValidateInput(garland);

        int n = garland.Length;
        var dp = new int[n, 3];

        for (int i = 0; i < n; i++)
        {
            for (int color = 0; color < 3; color++)
            {
                dp[i, color] = int.MaxValue; // Initialize to infinity
                if (i == 0) dp[i, color] = (garland[i] != GetColor(color)) ? 1 : 0;

                if (i > 0)
                {
                    dp[i, color] = Math.Min(dp[i, color], dp[i - 1, (color + 1) % 3]);
                    if (i >= 2)
                    {
                        dp[i, color] = Math.Min(dp[i, color], Math.Min(dp[i - 1, (color + 2) % 3], dp[i - 2, (color + 1) % 3]) << 1);
                    }
                }
            }
        }

        int bestColor = (dp[n - 1, 1] < dp[n - 1, 2]) ? 0 : 1; // Choose the best color based on min recolors
        var diversifiedGarland = CreateDiversifiedGarland(garland, n, bestColor);

        return (dp[n - 1, bestColor], diversifiedGarland);
    }

    private static string GetColor(int index)
    {
        return index switch
        {
            0 => "R",
            1 => "B",
            _ => "G"
        };
    }

    private static List<char> CreateDiversifiedGarland(string garland, int n, int bestColor)
    {
        var result = new List<char>(new char[n]);
        for (int i = 0; i < n; i++)
        {
            result[i] = GetColor(bestColor)[0];
