using System;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

public class Program
{
    private const int Mod = 1000000007;

    public static async Task Main(string[] args)
    {
        try
        {
            using var reader = new StreamReader(Console.OpenStandardInput());
            using var writer = new StreamWriter(Console.OpenStandardOutput()) { AutoFlush = true };

            int testCount = int.Parse(await reader.ReadLineAsync());
            for (int i = 1; i <= testCount; i++)
            {
                await SolveAsync(i, reader, writer);
            }
        }
        catch (Exception ex)
        {
            LogError(ex);
        }
    }

    private static async Task SolveAsync(int testNumber, StreamReader reader, StreamWriter writer)
    {
        try
        {
            var tokens = (await reader.ReadLineAsync()).Split(' ').Select(int.Parse).ToArray();
            if (tokens.Length < 3) throw new ArgumentException("Invalid input format.");

            int n = tokens[0];
            int l = tokens[1];
            int r = tokens[2];

            long answer = n;
            int[] countArray = new int[n];
            int countTracker = l - 1;

            Array.Fill(countArray, -1);

            for (int i = l; i <= r; i++)
            {
                int start = i % n;
                countTracker = (++countTracker) % n;
                countArray[start == 0 ? n - 1 : start - 1] = countTracker;
            }

            if (countTracker < 0)
            {
                for (int j = 0; j < n - 1; j++)
                {
                    if (countArray[j] != j) 
                    {
                        throw new InvalidOperationException("Mismatch in counting logic.");
                    }
                }
            }

            await writer.WriteLineAsync(answer);
        }
        catch (Exception ex)
        {
            LogError(ex);
            await writer.WriteLineAsync($"Error in test case {testNumber}: {ex.Message}");
        }
    }

    private static void LogError(Exception ex)
    {
        // Light logging to console or file
        Console.Error.WriteLine($"Error: {ex.Message}");
    }
}

