    private static async Task<string[]> ReadInputsAsync()
    {
        Console.WriteLine("Please enter the number of letters followed by the string:");
        string input = await Task.Run(() => Console.ReadLine());
        return input?.Split() ?? Array.Empty<string>();
    }

    private static int LargestDiffLetters(string s)
    {
        int maxDiff = 0;
        HashSet<char> charSet;

        for (int i = 1; i < s.Length; i++)
        {
            string x = s.Substring(0, i);
            string y = s.Substring(i);
            charSet = new HashSet<char>(x.Union(y));
            maxDiff = Math.Max(maxDiff, charSet.Count);
        }

        return maxDiff;
    }

