using System;
using System.Collections.Generic;
using System.Threading.Tasks;
using System.Text.RegularExpressions;

public class StatementExecutor
{
    private static readonly Regex StatementRegex = new Regex(@"(?<command>\w+)\s+(?<args>.+)", RegexOptions.Compiled);

    public async Task ExecuteStatementsAsync(IEnumerable<string> statements)
    {
        foreach (var statement in statements)
        {
            try
            {
                await ExecuteStatementAsync(statement);
            }
            catch (Exception ex)
            {
                LogError($"Error executing statement '{statement}': {ex.Message}");
            }
        }
    }

    private async Task ExecuteStatementAsync(string statement)
    {
        ValidateStatement(statement);
        var match = StatementRegex.Match(statement);

        if (!match.Success)
        {
            throw new InvalidOperationException($"Statement '{statement}' is invalid.");
        }

        var command = match.Groups["command"].Value;
        var args = match.Groups["args"].Value.Split(' ', StringSplitOptions.RemoveEmptyEntries);
        await ProcessCommandAsync(command, args);
    }

    private void ValidateStatement(string statement)
    {
        if (string.IsNullOrWhiteSpace(statement))
        {
            throw new ArgumentException("Statement cannot be null or empty.");
        }
    }

    private async Task ProcessCommandAsync(string command, string[] args)
    {
        switch (command.ToLower())
        {
            case "print":
                await PrintAsync(args);
                break;
            case "add":
                await AddAsync(args);
                break;
            default:
                throw new NotSupportedException($"Command '{command}' is not supported.");
        }
    }

    private Task PrintAsync(string[] args)
    {
        if (args.Length == 0)
        {
            throw new ArgumentException("Print command requires at least one argument.");
        }

        Console.WriteLine(string.Join(" ", args));
        return Task.CompletedTask;
    }

    private async Task AddAsync(string[] args)
    {
        if (args.Length < 2)
        {
            throw new ArgumentException("Add command requires at least two arguments.");
        }

        var sum = 0;
        foreach (var arg in args)
        {
            if (int.TryParse(arg, out var number))
            {
                sum += number;
            }
            else
            {
                throw new ArgumentException($"Invalid number '{arg}'.");
            }
        }

        Console.WriteLine($"Sum: {sum}");
        await Task.CompletedTask;
    }

    private void LogError(string message)
    {
        // Implement light logging logic here
        Console.Error.WriteLine(message);
    }
}

using System;
using System.Collections.Generic;
using System.IO;
using System.Threading.Tasks;

class Program
{
    static async Task Main()
    {
        try
        {
            var (N, M) = ReadInput();
            var adList = BuildAdjacencyList(M);
            var indegreeDict = GetIndegree(adList);
            var outdegreeDict = GetOutdegree(adList);
            var finalArray = GetFinalArray(indegreeDict);
            var answer = new List<int>();
            var travelledNodes = new List<int>();

            foreach (var node in adList.Keys)
            {
                if (!travelledNodes.Contains(node))
                {
                    await DFSRecursion(adList, node, finalArray, answer, travelledNodes);
                }
            }

            PrintResults(answer);
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
        }
    }

    static (int, int) ReadInput()
    {
        var input = Console.ReadLine().Split(' ');
        return (int.Parse(input[0]), int.Parse(input[1]));
    }

    static Dictionary<int, List<int>> BuildAdjacencyList(int edgesCount)
    {
        var adList = new Dictionary<int, List<int>>();

        for (int i = 0; i < edgesCount; i++)
        {
            var edgeInput = Console.ReadLine().Split(' ');
            var start = int.Parse(edgeInput[0]);
            var end = int.Parse(edgeInput[1]);

            if (!adList.ContainsKey(start))
                adList[start] = new List<int>();
            adList[start].Add(end);

            if (!adList.ContainsKey(end))
                adList[end] = new List<int>();
            adList[end].Add(start);
        }

        return adList;
    }

    static Dictionary<int, int> GetIndegree(Dictionary<int, List<int>> adList)
    {
        var indegDict = new Dictionary<int, int>();
        foreach (var node in adList.Keys)
        {
            foreach (var neighbor in adList[node])
            {
                if (!indegDict.ContainsKey(neighbor))
                    indegDict[neighbor] = 0;
                indegDict[neighbor]++;
            }
        }
        return indegDict;
    }

    static Dictionary<int, int> GetOutdegree(Dictionary<int, List<int>> adList)
    {
        var outdegDict = new Dictionary<int, int>();
        foreach (var node in adList.Keys)
        {
            outdegDict[node] = adList[node].Count;
        }
        return outdegDict;
    }

    static Dictionary<int, int> GetFinalArray(Dictionary<int, int> indegreeDict)
    {
        var nNodesDict = new Dictionary<int, int>();
        foreach (var node in indegreeDict.Keys)
        {
            nNodesDict[node] = nNodesDict.TryGetValue(node, out var count) ? count + 1 : 1;
        }
        return nNodesDict;
    }

    static async Task DFSRecursion(Dictionary<int, List<int>> adList, int node, Dictionary<int, int> nNodesDict, List<int> answer, List<int> travelledNodes)
    {
        if (!adList.ContainsKey(node)) return;

        nNodesDict[node] -= 1;

        foreach (var nextNode in adList[node])
        {
            if (node == nextNode) return;
            if (!travelledNodes.Contains(nextNode))
            {
                answer.Add(node);
                travelledNodes.Add(node);

                await DFSRecursion(adList, nextNode, nNodesDict, answer, travelledNodes);

                nNodesDict[node] += 1;
                answer.RemoveAt(answer.Count - 1);
                travelledNodes.RemoveAt(travelledNodes.Count - 1);
            }
        }
        answer.Add(node);
        travelledNodes.Add(node);
    }

    static void PrintResults(List<int> answer)
    {
        Console.WriteLine(string.Join(" ", answer));
    }
}

