        else
        {
            if (IsEvenLetter(t[0]))
            {
                r3 = int.Parse(t[index + 1]);
                r4 = int.Parse(t[index + 2]);
                r5 = int.Parse(t[index - 1]);
                r6 = int.Parse(t[index - 2]);
                r7 = r1;
                r8 = r1;
            }
            else
            {
                r3 = r1;
                r4 = int.Parse(t[index - 1]);
                r5 = int.Parse(t[index - 2]);
