using System;
using System.Collections.Generic;
using System.IO;
using System.Threading.Tasks;

public class CityRoadsProcessor
{
    public async Task ProcessInputAsync(StreamReader reader)
    {
        try
        {
            var firstLine = await reader.ReadLineAsync();
            if (string.IsNullOrEmpty(firstLine))
                throw new ArgumentException("Input cannot be null or empty.");

            var parameters = firstLine.Split(' ');
            if (parameters.Length < 2 
                || !int.TryParse(parameters[0], out int N) 
                || !int.TryParse(parameters[1], out int M))
                throw new FormatException("Invalid format for number of cities or roads.");

            var cityToRoads = new List<List<int>>(N);
            for (int i = 0; i < N; i++)
            {
                cityToRoads.Add(new List<int>());
            }

            for (int i = 0; i < M; i++)
            {
                var line = await reader.ReadLineAsync();
                if (string.IsNullOrEmpty(line))
                    throw new ArgumentException("Road input cannot be null or empty.");

                var road = line.Split(' ');
                if (road.Length < 2 
                    || !int.TryParse(road[0], out int a) 
                    || !int.TryParse(road[1], out int b)
                    || a < 1 || a > N || b < 1 || b > N)
                    throw new FormatException("Invalid road data.");

                cityToRoads[a - 1].Add(b - 1);
                cityToRoads[b - 1].Add(a - 1);
            }

            Console.WriteLine(N);
            Console.WriteLine(M);

            foreach (var city in cityToRoads)
            {
                Console.WriteLine(city.Count);
            }
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"Error processing input: {ex.Message}");
        }
    }
}

