public class SubsequenceChecker
{
    public static async Task Main(string[] args)
    {
        try
        {
            int testCases = ReadInteger();
            var results = new List<string>();

            for (int i = 0; i < testCases; i++)
            {
                int length = ReadInteger();
                string inputString = ReadString();

                if (IsValidString(inputString, length))
                {
                    results.Add(CheckSubsequence(inputString) ? "YES" : "NO");
                }
                else
                {
                    LogError($"Invalid input for test case {i + 1}. Length: {length}, String: \"{inputString}\".");
                    results.Add("NO");
                }
            }

            OutputResults(results);
        }
        catch (Exception ex)
        {
            LogError($"Unexpected error: {ex.Message}");
        }
    }

    private static int ReadInteger()
    {
        int result;
        while (true)
        {
            string input = Console.ReadLine();
            if (int.TryParse(input, out result) && result > 0)
            {
                return result;
            }
            LogError("Invalid integer input. Please enter a positive integer.");
        }
    }

    private static string ReadString()
    {
        return Console.ReadLine().Trim();
    }

    private static bool IsValidString(string input, int length)
    {
        return input.Length == length && (input.All(char.IsLetter) || input.All(char.IsDigit));
    }

    private static bool CheckSubsequence(string s)
    {
        bool foundLetter = false;
        bool foundDigit = false;

        foreach (char c in s)
        {
            if (char.IsLetter(c))
            {
                foundLetter = true;
                if (foundDigit) return true; // Found digit after letter
            }
            else if (char.IsDigit(c))
            {
                foundDigit = true;
            }
        }

        return false;
    }

    private static void OutputResults(IEnumerable<string> results)
    {
        foreach (var result in results)
        {
            Console.WriteLine(result);
        }
    }

