using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class NumberRotator
{
    public async Task<(int, int)> RotateAsync(int number, int rotationCount)
    {
        ValidateInputs(number, rotationCount);

        var binaryString = Convert.ToString(number, 2);
        if (binaryString.Length > 16)
        {
            LogError("Input exceeds 16 bits in binary representation.");
            throw new ArgumentOutOfRangeException(nameof(number), "Input exceeds 16 bits.");
        }

        int length = binaryString.Length;
        rotationCount = rotationCount % length;

        string rotatedBinary = RotateBinaryString(binaryString, rotationCount);
        return (Convert.ToInt32(rotatedBinary, 2), Convert.ToInt32(rotatedBinary.Substring(length - rotationCount) + rotatedBinary.Substring(0, length - rotationCount), 2));
    }

    private void ValidateInputs(int number, int rotationCount)
    {
        if (number < 0)
        {
            LogError("Number must be non-negative.");
            throw new ArgumentOutOfRangeException(nameof(number), "Number must be non-negative.");
        }
        if (rotationCount < 0)
        {
            LogError("Rotation count must be non-negative.");
            throw new ArgumentOutOfRangeException(nameof(rotationCount), "Rotation count must be non-negative.");
        }
    }

    private string RotateBinaryString(string binaryString, int rotationCount)
    {
        int length = binaryString.Length;
        return binaryString.Substring(length - rotationCount) + binaryString.Substring(0, length - rotationCount);
    }

    private void LogError(string message)
    {
        Console.WriteLine($"Error: {message}");
    }
}

using System;
using System.Linq;
using System.Threading.Tasks;
using System.Collections.Generic;

public class CoinSolver
{
    public async Task<int> SolveAsync(int n, List<int> coins)
    {
        ValidateInput(n, coins);

        coins.Sort((a, b) => b.CompareTo(a));
        int total = coins.Sum();
        int partialSum = 0;

        for (int i = 0; i < coins.Count; i++)
        {
            partialSum += coins[i];
            if (partialSum > total - partialSum)
            {
                return i + 1;
            }
        }

        return coins.Count;
    }

    private void ValidateInput(int n, List<int> coins)
    {
        if (n <= 0)
        {
            throw new ArgumentException("The number of coins must be greater than zero.");
        }
        if (coins == null || coins.Count != n)
        {
            throw new ArgumentException("The number of coins provided does not match the expected count.");
        }
        if (coins.Any(coin => coin < 0))
        {
            throw new ArgumentException("All coin values must be non-negative.");
        }
    }

    public async Task ExecuteAsync()
    {
        try
        {
            Console.Write("Enter number of coins: ");
            if (!int.TryParse(Console.ReadLine(), out int n))
            {
                Console.WriteLine("Invalid input for number of coins.");
                return;
            }

            Console.Write("Enter coin values (space-separated): ");
            var input = Console.ReadLine();
            var coinStrings = input?.Split(' ', StringSplitOptions.RemoveEmptyEntries);

            if (coinStrings == null || !coinStrings.Any())
            {
                Console.WriteLine("No coin values provided.");
                return;
            }

            var coins = coinStrings.Select(int.Parse).ToList();
            var result = await SolveAsync(n, coins);
            Console.WriteLine($"Minimum number of coins needed: {result}");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
        }
    }
}

