public class Sorter
{
    public static async Task<Tuple<int, int, int, int>> SortValuesAsync(int a, int b, int c, int d)
    {
        ValidateInputs(a, b, c, d);

        try
        {
            (a, d) = SwapIfLess(a, d);
            (b, c) = SwapIfLess(b, c);
            (a, b) = SwapIfLess(a, b);
            (a, c) = SwapIfLess(a, c);
            (a, d) = SwapIfLess(a, d);
            (b, c) = SwapIfLess(b, c);
            (b, d) = SwapIfLess(b, d);
            (c, d) = SwapIfLess(c, d);
            (a, b) = SwapIfLess(a, b);
            (a, c) = SwapIfLess(a, c);
            (a, d) = SwapIfLess(a, d);
            (b, c) = SwapIfLess(b, c);
            (b, d) = SwapIfLess(b, d);
            (c, d) = SwapIfLess(c, d);
            (a, b) = SwapIfLess(a, b);
            (a, c) = SwapIfLess(a, c);
            (a, d) = SwapIfLess(a, d);
            (b, c) = SwapIfLess(b, c);
            (b, d) = SwapIfLess(b, d);
            (c, d) = SwapIfLess(c, d);
            (a, b) = SwapIfLess(a, b);
            (a, c) = SwapIfLess(a, c);
            (a, d) = SwapIfLess(a, d);
            (b, c) = SwapIfLess(b, c);
            (b, d) = SwapIfLess(b, d);
            (c, d) = SwapIfLess(c, d);
            (a, b) = SwapIfLess(a, b);
            (a, c) = SwapIfLess(a, c);
            (a, d) = SwapIfLess(a, d);
            (b, c) = SwapIfLess(b, c);
            (b, d) = SwapIfLess(b, d);
            (c, d) = SwapIfLess(c, d);

            return await Task.FromResult(Tuple.Create(a, b, c, d));
        }
        catch (Exception ex)
        {
            LogError(ex);
            throw;
        }
    }

    private static void ValidateInputs(int a, int b, int c, int d)
    {
        if (a < int.MinValue || a > int.MaxValue || 
            b < int.MinValue || b > int.MaxValue || 
            c < int.MinValue || c > int.MaxValue || 
            d < int.MinValue || d > int.MaxValue)
        {
            throw new ArgumentOutOfRangeException("Input values must be within the valid range of integers.");
        }
    }

    private static (int, int) SwapIfLess(int x, int y)
    {
        return x < y ? (y, x) : (x, y);
    }

    private static void LogError(Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}");
    }
}

