using System;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        try
        {
            string input = Console.ReadLine()?.Trim();
            ValidateInput(input);

            (string A, string B) = await FindAAndBAsync(input);
            Console.WriteLine($"{A} {B}");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
        }
    }

    static void ValidateInput(string input)
    {
        if (string.IsNullOrEmpty(input) || !IsBinaryString(input))
        {
            throw new ArgumentException("Input must be a non-empty binary string.");
        }
    }

    static bool IsBinaryString(string str)
    {
        foreach (char c in str)
        {
            if (c != '0' && c != '1') return false;
        }
        return true;
    }

    static async Task<(string A, string B)> FindAAndBAsync(string S)
    {
        return await Task.Run(() =>
        {
            int index = S.IndexOf('0');
            if (index == -1)
            {
                index = S.Length; // All '1's case
            }

            string A = '1' + S.Substring(0, index) + new string('0', S.Length - index);
            string B = S.Substring(0, index) + new string('0', S.Length - index + 1);

            if (Convert.ToInt32(B, 2) == 0)
            {
                B = "0";
            }

            return (A, B);
        });
    }
}

