using System.Linq;
using System.Threading.Tasks;

public class DijkstraWithFueling
{
    private readonly List<Tuple<int, int>>[] graph;

    public DijkstraWithFueling(int n, int m, List<Tuple<int, int, int>> roads)
    {
        graph = Enumerable.Range(0, n).Select(_ => new List<Tuple<int, int>>()).ToArray();
        foreach (var road in roads)
        {
            int A = road.Item1 - 1;
            int B = road.Item2 - 1;
            int C = road.Item3;
            graph[A].Add(new Tuple<int, int>(B, C));
            graph[B].Add(new Tuple<int, int>(A, C));
        }
    }

    public int FindMinRefills(int start, int end, int fuelCapacity)
    {
        start--;
        end--;
        var priorityQueue = new PriorityQueue<(int cost, int node, int fuel)>();
        priorityQueue.Enqueue((0, start, fuelCapacity));
        var visited = new HashSet<(int node, int fuel)>();

        while (priorityQueue.Count > 0)
        {
            var (cost, node, fuel) = priorityQueue.Dequeue();
            if (node == end) return cost;

            if (visited.Contains((node, fuel))) continue;
            visited.Add((node, fuel));

            foreach (var neighbor in graph[node])
            {
                int neighborNode = neighbor.Item1;
                int roadLength = neighbor.Item2;

                if (roadLength > fuel)
                {
                    priorityQueue.Enqueue((cost + 1, neighborNode, fuelCapacity - roadLength));
                }
                else
                {
                    priorityQueue.Enqueue((cost, neighborNode, fuel - roadLength));
                }
            }
        }
        return -1;
    }

    public List<int> ProcessQueries(int queriesCount, List<Tuple<int, int>> queries, int fuelCapacity)
    {
        var results = new List<int>();
        foreach (var query in queries)
        {
            results.Add(FindMinRefills(query.Item1, query.Item2, fuelCapacity));
        }
        return results;
    }
}

public class Program
{
    public static async Task Main()
    {
        try
        {
            var inputLines = await System.IO.File.ReadAllLinesAsync("input.txt");
            var firstLine = inputLines[0].Split().Select(int.Parse).ToArray();
            int N = firstLine[0];
            int M = firstLine[1];
            int L = firstLine[2];

            var roads = new List<Tuple<int, int, int>>();
            for (int i = 1; i <= M; i++)
            {
                var roadParams = inputLines[i].Split().Select(int.Parse).ToArray();
                roads.Add(new Tuple<int, int, int>(roadParams[0], roadParams[1], roadParams[2]));
            }

            int Q = int.Parse(inputLines[M + 1]);
            var queries = new List<Tuple<int, int>>();
            for (int i = 0; i < Q; i++)
            {
                var queryParams = inputLines[M + 2 + i].Split().Select(int.Parse).ToArray();
                queries.Add(new Tuple<int, int>(queryParams[0], queryParams[1]));
            }

            var fueling = new DijkstraWithFueling(N, M, roads);
            var results = fueling.ProcessQueries(Q, queries, L);

            foreach (var result in results)
            {
                Console.WriteLine(result);
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
        }
    }
}

