public class EvenOddProcessor
{
    public async Task<(string even, string odd)> ProcessEvenOddAsync(int a, int b)
    {
        if (a < 0 || b < 0)
        {
            throw new ArgumentException("Parameters must be non-negative");
        }

        string odd = string.Empty;
        string even = string.Empty;
        int r = a;
        a = a - (b / 2);

        for (int i = 0; i < a; i++)
        {
            if (a % 2 != 0)
            {
                odd += "odd\n";
            }
            a -= 1;
            a /= 2;

            if (b % 2 != 0 && r != b)
            {
                even += "even\n";
            }
        }

        return (even, odd);
    }
}

public class StringNumberDisplay
{
    public async Task DisplayNumbersAsync(string inputString, int n)
    {
        if (string.IsNullOrWhiteSpace(inputString) || n < 0)
        {
            Console.WriteLine("Invalid input.");
            return;
        }

        var numbers = ParseInput(inputString);
        if (numbers.Count == 0)
        {
            Console.WriteLine("No numbers found.");
            return;
        }

        var result = new List<string>();

        // Prepare numbers to display
        result.Add(numbers.First().ToString());
        result.Add(numbers.Last().ToString());

        for (int i = 0; i < numbers.Count; i++)
        {
            if (i + n < numbers.Count)
            {
                result.Add(numbers[i + n].ToString());
            }
            else
            {
                result.Add("N/A");
            }

            if (i - n >= 0)
            {
                result.Add(numbers[i - n].ToString());
            }
            else
            {
                result.Add("N/A");
            }
        }

        Console.WriteLine(string.Join(" ", result));
    }

    private List<int> ParseInput(string inputString)
    {
        var numbers = new List<int>();
        var stringNumbers = inputString.Split(new[] { ' ', ',' }, StringSplitOptions.RemoveEmptyEntries);

        foreach (var s in stringNumbers)
        {
            if (int.TryParse(s, out int number))
            {
                numbers.Add(number);
            }
        }

        return numbers;
    }
}

