    public static int KLengthPref(string[] arr, int n, int k, string s)
    {
        if (arr == null || arr.Length == 0 || n <= 0 || k <= 0 || s == null || s.Length < k)
        {
            Console.WriteLine("Invalid input.");
            return 0;
        }

        string strk = s.Substring(0, k);
        int count = 0;

        foreach (var item in arr)
        {
            if (item.Length >= k && item.Substring(0, k) == strk)
            {
                count++;
            }
        }

        return count;
    }

