using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        try
        {
            var (N, M) = await ReadInputAsync();
            var specialFriends = await ReadSpecialFriendsAsync(N);
            var posts = await ReadPostsAsync(M);

            var sortedPosts = SortPosts(posts);
            OutputSortedPosts(sortedPosts);
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
        }
    }

    private static async Task<(int, int)> ReadInputAsync()
    {
        var input = await Console.In.ReadLineAsync();
        var parts = input.Split(' ').Select(int.Parse).ToArray();

        if (parts.Length != 2)
            throw new InvalidOperationException("Invalid input format for N and M.");

        return (parts[0], parts[1]);
    }

    private static async Task<List<int>> ReadSpecialFriendsAsync(int N)
    {
        var input = await Console.In.ReadLineAsync();
        var specialFriends = input.Split(' ').Select(int.Parse).ToList();

        if (specialFriends.Count != N)
            throw new InvalidOperationException("Number of special friends does not match N.");

        return specialFriends;
    }

    private static async Task<List<Post>> ReadPostsAsync(int M)
    {
        var posts = new List<Post>();

        for (int i = 0; i < M; i++)
        {
            var input = await Console.In.ReadLineAsync();
            var parts = input.Split(' ').ToArray();

            if (parts.Length != 3 || !int.TryParse(parts[1], out int p))
                throw new InvalidOperationException("Invalid post format.");

            char firstChar = parts[2][0];
            char lastChar = parts[2][^1];

            posts.Add(new Post(parts[0], p, firstChar, lastChar));
        }

        return posts;
    }

    private static List<Post> SortPosts(List<Post> posts)
    {
        return posts.OrderByDescending(x => x.Popularity)
                    .ThenByDescending(x => (int)x.LastChar)
                    .ThenBy(x => x.Author)
                    .ToList();
    }

    private static void OutputSortedPosts(List<Post> sortedPosts)
    {
        var output = new StringBuilder();

        foreach (var post in sortedPosts)
        {
            output.Append(post.FirstChar);
        }

        Console.Write(output.ToString());
    }
}

