        {
            if (!(1 <= Math.Abs(a[i] - a[i - 1]) && Math.Abs(a[i] - a[i - 1]) <= 10))
            {
                return false;
            }
        }
        return true;
    }

    private static bool Check(int n, List<int> a)
    {
        for (int i = 0; i < n - 1; i++)
        {
            if (a[i] % 2 != 0)
            {
                return false;
            }
        }
        return true;
    }

    private static async Task<int> SolveAsync(int n, List<int> a)
    {
