        var sol = new List<int>();
        var add = new List<(int, int)>();

        for (int i = 0; i < a.Count - 1; i++)
        {
            if (a[i + 1] <= a[i])
            {
                if (Math.Abs(a[i + 1] - a[i]) > 10)
                    return -1;

                add.Add((a[i], (a[i] + a[i + 1]) / 2));
                if (add.Count % 2 == 0)
                {
                    add.Add((-100000000, 0));
                }
            }

            foreach (var (first, second) in add)
            {
                sol.Add(first);
                sol.Add(second);
            }
        }

        if (n <= 10)
        {
            int t = -1;
            for (int i = 0; i < n - 1; i++)
            {
                int v = (a[i] == a[i + 1]) ? 1 : 0;

                if (a[i] - a[i + 1] > 20)
                    return -1;

                t = (v == 1) ? 2 : (a[i] < a[i + 1]) ? -(a[i] + a[i + 1] - a[i]) : a[i + 1] - a[i];
                sol.Add((a[i] + a[i + 1]) / 2);

                if (t <= 0)
                    return -1;
            }
        }

        if (sol.Count == 1)
            return 0;

        return (Check(n, sol) && Check(n, revSol)) ? 0 : -1;
    }

    public static async Task MainAsync()
    {
        int tt = int.Parse(Console.ReadLine());
        for (int i = 0; i < tt; i++)
        {
            int n = int.Parse(Console.ReadLine());
            var a = Console.ReadLine().Split(' ').Select(int.Parse).ToList();

            if (SortCheck(a))
            {
                Console.WriteLine("0");
                continue;
            }

            int result = await SolveAsync(n, a);
            Console.WriteLine(result);
        }
    }

    public static void Main(string[] args)
    {
        MainAsync().GetAwaiter().GetResult();
    }
}

using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

public class StreamChecker
{
    private readonly TrieNode root;
    private readonly Queue<char> buffer;
    private const int BufferLimit = 2000;

    public StreamChecker(IEnumerable<string> words)
    {
        root = new TrieNode();
        foreach (var word in words)
        {
            AddWord(word);
        }
        buffer = new Queue<char>();
    }

    private void AddWord(string word)
    {
        var currentNode = root;
        foreach (char c in word.Reverse())
        {
            if (!currentNode.Children.ContainsKey(c))
            {
                currentNode.Children[c] = new TrieNode();
            }
            currentNode = currentNode.Children[c];
        }
        currentNode.IsEnd = true;
    }

    public bool Query(char letter)
    {
        if (buffer.Count >= BufferLimit)
        {
            buffer.Dequeue();
        }
        buffer.Enqueue(letter);
        return CheckForWords();
    }

    private bool CheckForWords()
    {
        var currentNode = root;
        foreach (var c in buffer.Reverse())
        {
            if (currentNode.Children.ContainsKey(c))
            {
                currentNode = currentNode.Children[c];
                if (currentNode.IsEnd)
                {
                    return true;
                }
            }
            else
            {
                break;
            }
        }
        return false;
    }
}

public class TrieNode
{
    public Dictionary<char, TrieNode> Children { get; }
    public bool IsEnd { get; set; }

    public TrieNode()
    {
        Children = new Dictionary<char, TrieNode>();
        IsEnd = false;
    }
}

