using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        try
        {
            var inputs = await ReadInputAsync();
            if (inputs == null || !inputs.Any())
            {
                Console.WriteLine("Invalid input.");
                return;
            }

            int index = 0;
            int N = int.Parse(inputs[index++]);
            int M = int.Parse(inputs[index++]);

            int[] A = new int[N];
            int[] B = new int[N];

            for (int i = 0; i < N; i++)
            {
                A[i] = int.Parse(inputs[index++]);
                B[i] = int.Parse(inputs[index++]);
            }

            var cords = new List<(int L, int R)>();

            for (int i = 0; i < M; i++)
            {
                int L = int.Parse(inputs[index++]);
                int R = int.Parse(inputs[index++]);
                cords.Add((L, R));
            }

            var bombIndices = Enumerable.Range(0, N).OrderBy(i => A[i]).ToArray();
            Array.Sort(A);

            var operations = new List<(int index, int op)>[N];
            for (int i = 0; i < N; i++)
                operations[i] = new List<(int, int)>();

            foreach (var (L, R) in cords)
            {
                int leftIndex = Array.BinarySearch(A, L);
                if (leftIndex < 0) leftIndex = ~leftIndex;
                int rightIndex = Array.BinarySearch(A, R);
                if (rightIndex < 0) rightIndex = ~rightIndex - 1;

                if (leftIndex <= rightIndex)
                {
                    operations[leftIndex].Add((Array.IndexOf(cords.ToArray(), (L, R)), 1));
                    if (rightIndex + 1 < N)
                    {
                        operations[rightIndex + 1].Add((Array.IndexOf(cords.ToArray(), (L, R)), -1));
                    }
                }
            }

            var currentOps = new HashSet<int>();
            var activeBombs = (int[])B.Clone();
            var cutCords = new HashSet<int>();

            foreach (var i in bombIndices)
            {
                foreach (var (j, op) in operations[i])
                {
                    if (op == 1)
                        currentOps.Add(j);
                    else
                        currentOps.Remove(j);
                }

                foreach (var j in currentOps)
                {
                    if (activeBombs[i] == 1)
                    {
                        activeBombs[i] = 0;
                        cutCords.Add(j);
                    }
                    else
                    {
                        activeBombs[i] = 1;
                        cutCords.Remove(j);
                    }
                }
            }

            if (activeBombs.All(state => state == 0))
            {
                Console.WriteLine(cutCords.Count);
                Console.WriteLine(string.Join(" ", cutCords.OrderBy(x => x)));
            }
            else
            {
                Console.WriteLine(-1);
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
        }
    }

    private static async Task<string[]> ReadInputAsync()
    {
        try
        {
            return await Task.Run(() => Console.ReadLine()?.Split());
        }
        catch
        {
            return null;
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Text.RegularExpressions;
using System.Threading.Tasks;

public class IPAddressGenerator
{
    public static async Task<List<string>> GenerateIPAddressesAsync(string input)
    {
        if (!IsInputValid(input))
        {
            return new List<string> { "-1" };
        }

        var result = new List<string>();
        await Task.Run(() => Backtrack(new List<string>(), 0, input, result));
        return result.Count > 0 ? result : new List<string> { "-1" };
    }

    private static bool IsInputValid(string input)
    {
        return input.Length >= 4 && input.Length <= 12 && Regex.IsMatch(input, @"^\d+$");
    }

    private static void Backtrack(List<string> parts, int index, string input, List<string> result)
    {
        if (parts.Count == 4)
        {
            if (index == input.Length)
            {
                result.Add(string.Join(".", parts));
            }
            return;
        }

        for (int length = 1; length <= 3; length++)
        {
            if (index + length <= input.Length)
            {
                string segment = input.Substring(index, length);
                if (IsValidSegment(segment))
                {
                    parts.Add(segment);
                    Backtrack(parts, index + length, input, result);
                    parts.RemoveAt(parts.Count - 1);
                }
            }
        }
    }

    private static bool IsValidSegment(string segment)
    {
        if (segment.Length > 1 && segment[0] == '0')
        {
            return false;
        }
        if (int.TryParse(segment, out int value))
        {
            return value >= 0 && value <= 255;
        }
        return false;
    }
}

