public class NumberConverter
{
    public static string Base11To10(string s)
    {
        int n = 0;
        foreach (char c in s)
        {
            n *= 11;
            if (char.IsDigit(c))
            {
                n += c - '0';
            }
            else
            {
                n += char.ToUpper(c) - 'A' + 10;
            }
        }
        return n.ToString();
    }

    public static string Base10To8(int n)
    {
        string s = string.Empty;
        while (n > 0)
        {
            s = (n % 8).ToString() + s;
            n /= 8;
        }
        return s;
    }

    public static string Base8To7(string s)
    {
        int n = Convert.ToInt32(s, 8);
        return Base10To8(n);
    }

    public static async Task ProcessInputsAsync()
    {
        try
        {
            int t = int.Parse(Console.ReadLine());
            for (int index = 0; index < t; index++)
            {
                int n = int.Parse(Console.ReadLine());
                string inputString = Console.ReadLine();
                n = int.Parse(Base11To10(inputString));
                string base8Result = Base10To8(n);
                string finalResult = Base8To7(base8Result);
                Console.Write(finalResult + " ");
            }
        }
        catch (FormatException ex)
        {
            Console.WriteLine("Input format is invalid: " + ex.Message);
        }
        catch (Exception ex)
        {
            Console.WriteLine("An error occurred: " + ex.Message);
        }
    }
}

