using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.Extensions.Logging;

public class PairCounter
{
    private readonly ILogger<PairCounter> _logger;

    public PairCounter(ILogger<PairCounter> logger)
    {
        _logger = logger;
    }

    public int[] CountOfPairs(int n, int x, int y)
    {
        ValidateInputs(n, x, y);
        if (x > y) (x, y) = (y, x);

        var result = new int[n];

        for (int k = 1; k <= n; k++)
        {
            int count = 0;

            // Count direct connection pairs
            count += Math.Max(0, n - k);

            // Count pairs involving the special path (x, y)
            count += CountSpecialPathPairs(n, x, y, k);

            // Adjust for overcounted pairs
            count += AdjustOvercountedPairs(n, x, y, k);

            result[k - 1] = count;
        }

        return result;
    }

    private void ValidateInputs(int n, int x, int y)
    {
        if (n < 1) throw new ArgumentOutOfRangeException(nameof(n),"n must be greater than 0.");
        if (x < 1 || x > n) throw new ArgumentOutOfRangeException(nameof(x), "x must be within the range of 1 to n.");
        if (y < 1 || y > n) throw new ArgumentOutOfRangeException(nameof(y), "y must be within the range of 1 to n.");
    }

    private int CountSpecialPathPairs(int n, int x, int y, int k)
    {
        if (y - x + 1 < 3) return 0;

        int count = 0;
        int halfLen = (y - x - 1) / 2;

        for (int i = 0; i <= Math.Min(x - 1, n - y, k - 1); i++)
        {
            if (i <= halfLen) count += 2 * (x - i - 1) + 1;
            if ((k - i - 1) <= halfLen) count += 2 * (n - y - (k - i - 1)) + 1;
            if (i < halfLen && (k - i - 1) < halfLen) count += 2;
        }

        return count;
    }

    private int AdjustOvercountedPairs(int n, int x, int y, int k)
    {
        int count = 0;

        for (int i = 1; i <= n; i++)
        {
            for (int j = i + 1; j <= n; j++)
            {
                int dist = Math.Min(Math.Abs(i - j), Math.Abs(i - x) + Math.Abs(j - y) + 1, Math.Abs(i - y) + Math.Abs(j - x) + 1);
                if (dist == k) count++;
            }
        }

        return count;
    }
}

