            List<int> a = GetInputArray(n);
            int result = await MinOperationsAsync(a);
            Console.WriteLine(result);
        }
        catch (Exception ex)
        {
            LogError("An error occurred: " + ex.Message);
        }
    }

    static int GetInputLength()
    {
        Console.Write("Enter the number of elements: ");
        if (!int.TryParse(Console.ReadLine(), out int n) || n <= 0)
        {
            throw new ArgumentException("Invalid number of elements.");
        }
        return n;
    }

    static List<int> GetInputArray(int length)
    {
        Console.Write($"Enter {length} integers separated by spaces: ");
        var input = Console.ReadLine().Split(' ').Select(int.Parse).ToList();
        if (input.Count != length)
        {
            throw new ArgumentException("Input length does not match the specified number.");
        }
        return input;
    }

    static async Task<int> MinOperationsAsync(List<int> a)
    {
        return await Task.Run(() => MinOperations(a));
    }

    static int MinOperations(List<int> a)
    {
        var stack = new Stack<int>();

        foreach (var i in a)
        {
            if (i == 0 && stack.Count > 0)
            {
                while (stack.Count > 0 && stack.Peek() > i)
                {
                    a[stack.Pop()] = 1;
                }
                stack.Push(i);
            }
            else if (i == 0)
            {
                stack.Push(i);
            }
        }

        return stack.Count;
    }

    static void LogError(string message)
    {
        // Simple logging for demonstration; can be replaced with a proper logging framework
        Console.WriteLine("[ERROR] " + message);
    }
}

