public class NiceStaircases
{
    public static async Task Main(string[] args)
    {
        try
        {
            Console.WriteLine("Enter number of test cases:");
            int t = int.Parse(Console.ReadLine());

            if (t <= 0)
            {
                throw new ArgumentException("Number of test cases must be greater than zero.");
            }

            List<int> cells = new List<int>();

            Console.WriteLine("Enter the cell values:");
            for (int i = 0; i < t; i++)
            {
                if (int.TryParse(Console.ReadLine(), out int cellValue) && cellValue > 0)
                {
                    cells.Add(cellValue);
                }
                else
                {
                    Console.WriteLine("Invalid input. Please enter a positive integer.");
                    i--;
                }
            }

            foreach (var cell in cells)
            {
                int result = await Task.Run(() => MaximalDifferentStaircases(cell));
                Console.WriteLine(result);
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"An error occurred: {ex.Message}");
        }
    }

    private static int MaximalDifferentStaircases(int n)
    {
        int result = 0;
        int p = 1;
        n -= 1;

        while (n >= p)
        {
            result += n / p;
            p += 2;
            n -= p;
        }

        if (p % 2 == 0)
        {
            result += 1;
        }

        return result;
    }
}

