    {
        ValidateInput(numRows, bus);

        int numOccupiedSeats = CountOccupiedSeats(bus);

        if (numOccupiedSeats % 2 == 0)
        {
            var configuration = await FindSeatPairsAsync(bus);
            return configuration;
        }
        return null;
    }

    private static void ValidateInput(int numRows, List<string> bus)
    {
        if (numRows <= 0)
        {
            throw new ArgumentException("Number of rows must be greater than zero.");
        }
        if (bus.Count != numRows)
        {
            throw new ArgumentException("Bus configuration must match the specified number of rows.");
        }
    }

    private static int CountOccupiedSeats(List<string> bus)
    {
        return bus.Sum(row => row.Count(c => c == 'X'));
    }

    private static async Task<List<string>> FindSeatPairsAsync(List<string> bus)
    {
        return await Task.Run(() =>
        {
            for (int i = 0; i < bus.Count; i++)
            {
                if (bus[i].Count(c => c == 'O') >= 2)
                {
                    bus[i] = bus[i].Replace("O", "+", 2);
                    return bus;
                }
                else if (bus[i].Count(c => c == 'X') == 2)
                {
                    bus[i] = bus[i].Replace("X", "+", 2);
                    return bus;
                }
            }
            return null;
        });
    }
