using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class TaxiRiderCounter
{
    public static async Task<int[]> CountRidersForTaxiAsync(int n, int m, List<int> coordinates, List<int> taxiDrivers)
    {
        if (coordinates == null || taxiDrivers == null)
        {
            throw new ArgumentNullException("Coordinates or taxi drivers cannot be null.");
        }

        if (coordinates.Count != taxiDrivers.Count)
        {
            throw new ArgumentException("Coordinates and taxi drivers must have the same length.");
        }

        if (m <= 0)
        {
            return Array.Empty<int>();
        }

        coordinates.Sort();
        int[] countRiders = new int[m];

        for (int i = 0; i < m; i++)
        {
            List<Tuple<double, int>> neighbors = new List<Tuple<double, int>>();
            for (int j = 0; j < m; j++)
            {
                if (j != i)
                {
                    double dist = Math.Abs(coordinates[j] - coordinates[i]);
                    neighbors.Add(new Tuple<double, int>(dist, taxiDrivers[j]));
                }
            }

            neighbors = neighbors.OrderBy(n => n.Item1).ToList();

            double totalDist = 0;
            foreach (var driver in neighbors)
            {
                totalDist += driver.Item2;
            }

            double avgDist = neighbors.Count > 0 ? totalDist / neighbors.Count : 0;

            foreach (var driver in neighbors)
            {
                if (driver.Item2 <= avgDist)
                {
                    countRiders[i]++;
                }
            }
        }

        return countRiders;
    }

    public static async Task Main(string[] args)
    {
        int n = 1, m = 4;
        List<int> coordinates = new List<int> { 2, 4, 6, 10, 15 };
        List<int> taxiDrivers = new List<int> { 1, 1, 1, 1, 0 };

        try
        {
            int[] riders = await CountRidersForTaxiAsync(n, m, coordinates, taxiDrivers);
            Console.WriteLine($"Riders count: [{string.Join(", ", riders)}]");
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"Error: {ex.Message}");
        }
    }
}

