public class CostCalculator
{
    public async Task<double> CalculateCostAsync(List<double> B)
    {
        try
        {
            ValidateInput(B);
            return await Task.Run(() => ComputeCost(B));
        }
        catch (Exception ex)
        {
            LogError("Error calculating cost", ex);
            throw new ApplicationException("Failed to calculate cost.", ex);
        }
    }

    private void ValidateInput(List<double> B)
    {
        if (B == null)
        {
            LogWarning("Input list B is null.");
            throw new ArgumentNullException(nameof(B), "Input list cannot be null.");
        }

        if (B.Count == 0)
        {
            LogWarning("Input list B is empty.");
            throw new ArgumentException("Input list cannot be empty.", nameof(B));
        }

        foreach (var number in B)
        {
            if (number < 0)
            {
                LogWarning($"Input value {number} is negative.");
                throw new ArgumentOutOfRangeException(nameof(B), "All values must be non-negative.");
            }
        }
    }

    private double ComputeCost(List<double> B)
    {
        var lastElement = B[^1];
        double cost = lastElement * B.Count - lastElement * (lastElement - (B[0] + 1) / 2);
        return cost;
    }

    private void LogError(string message, Exception ex)
    {
        Console.Error.WriteLine($"{message}: {ex.Message}");
    }

    private void LogWarning(string message)
    {
        Console.WriteLine($"Warning: {message}");
    }
}

