public class NumberDivisor
{
    public static int[] GetDivCounts(int number)
    {
        if (number <= 0)
        {
            throw new ArgumentOutOfRangeException(nameof(number), "Number must be greater than 0.");
        }

        var div3 = new List<int>();
        var div5 = new List<int>();
        var divAll = new List<int>();

        for (int i = 0; i < number; i++)
        {
            int current = number - i;

            if (current % 3 == 0 && current % 5 != 0)
            {
                div3.Add(current);
            }
            if (current % 5 == 0 && current % 3 != 0)
            {
                div5.Add(current);
            }
            if (current % 5 == 0 && current % 3 == 0)
            {
                divAll.Add(current);
            }
        }

        return new[] { div3.Count, div5.Count, divAll.Count };
    }
}

