using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class Minesweeper
{
    private readonly char[,] _board;
    private readonly int _rows;
    private readonly int _cols;

    public Minesweeper(char[,] board)
    {
        _board = board ?? throw new ArgumentNullException(nameof(board));
        _rows = board.GetLength(0);
        _cols = board.GetLength(1);
    }

    public async Task<char[,]> CalculateHintsAsync()
    {
        ValidateBoard();
        return await Task.Run(() => CalculateHints());
    }

    private void ValidateBoard()
    {
        if (_rows < 1 || _cols < 1)
            throw new ArgumentException("Board dimensions must be greater than 0.");
        if (_board.Cast<char>().Any(c => c != '.' && c != '#'))
            throw new ArgumentException("Board can only contain '.' for empty squares and '#' for bomb squares.");
    }

    private char[,] CalculateHints()
    {
        char[,] hints = new char[_rows, _cols];

        for (int i = 0; i < _rows; i++)
        {
            for (int j = 0; j < _cols; j++)
            {
                if (_board[i, j] == '#')
                {
                    hints[i, j] = '#';
                }
                else
                {
                    int bombCount = CountAdjacentBombs(i, j);
                    hints[i, j] = bombCount > 0 ? (char)(bombCount + '0') : '0';
                }
            }
        }

        return hints;
    }

    private int CountAdjacentBombs(int row, int col)
    {
        int count = 0;
        for (int r = row - 1; r <= row + 1; r++)
        {
            for (int c = col - 1; c <= col + 1; c++)
            {
                if (IsInBounds(r, c) && _board[r, c] == '#')
                {
                    count++;
                }
            }
        }
        return count;
    }

    private bool IsInBounds(int row, int col)
    {
        return row >= 0 && row < _rows && col >= 0 && col < _cols;
    }
}

