using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class StringMatcher
{
    private static void Swap(ref char a, ref char b)
    {
        char temp = a;
        a = b;
        b = temp;
    }

    private static bool MatchString(ref string S, int ind1, int N)
    {
        int ind = -1;

        for (int i = ind1 + 1; i < N; i++)
        {
            if (S[i] == S[ind1])
            {
                ind = i;
                break;
            }
        }

        if (ind == -1)
            return false;

        // Swap characters
        Swap(ref S[ind1], ref S[ind]);

        // Sort the second half of the string
        var secondHalf = S.Substring(ind + 1).ToCharArray();
        Array.Sort(secondHalf);
        S = S.Substring(0, ind + 1) + new string(secondHalf);

        return true;
    }

    public static async Task<List<string>> FindAllSolutionsAsync(string X, int k)
    {
        if (string.IsNullOrEmpty(X) || k <= 0)
        {
            throw new ArgumentException("Input string cannot be null or empty, and k must be greater than 0.");
        }

        List<string> results = new List<string>();
        char[] chars = X.ToCharArray();
        Array.Sort(chars);
        X = new string(chars);

        do
        {
            string curr = X;
            List<int> done = new List<int>(new int[X.Length]);
            int i = 0;

            while (i < done.Count)
            {
                if (done[i] == 1)
                {
                    i++;
                    continue;
                }

                if (curr.IndexOf(X[i]) != -1)
                {
                    char[] substring = curr.Skip(i + 1).ToArray();
                    Array.Sort(substring);
                    curr = new string(substring);
                    results.Add(curr);
                    done[i] = 1;
                }
                else
                {
                    break;
                }

                i++;
            }

            if (!string.IsNullOrEmpty(curr) && results.Count(x => x == curr) == 1)
            {
                results.Add(curr);
            }
        } while (NextPermutation(ref X));

        return results;
    }

    private static bool NextPermutation(ref string str)
    {
        char[] chars = str.ToCharArray();
        int i = chars.Length - 2;

        while (i >= 0 && chars[i] >= chars[i + 1])
            i--;

        if (i < 0)
            return false;

        int j = chars.Length - 1;
        while (chars[j] <= chars[i])
            j--;

        Swap(ref chars[i], ref chars[j]);
        Array.Reverse(chars, i + 1, chars.Length - i - 1);
        str = new string(chars);

        return true;
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    static async Task Main()
    {
        int N = 0, M = 0;

        // Input validation
        if (!int.TryParse(Console.ReadLine(), out N) || N < 2)
        {
            Console.WriteLine("Invalid input for N. Must be an integer greater than 1.");
            return;
        }

        if (!int.TryParse(Console.ReadLine(), out M) || M < 0)
        {
            Console.WriteLine("Invalid input for M. Must be a non-negative integer.");
            return;
        }

        var outMatrix = new double[N][];
        var inList = new List<int>[N];

        for (int i = 0; i < N; i++)
        {
            outMatrix[i] = new double[N];
            inList[i] = new List<int>();
        }

        // Read edges and populate matrices
        for (int i = 0; i < M; i++)
        {
            var edgeInput = Console.ReadLine().Split().Select(int.Parse).ToArray();
            if (edgeInput.Length < 2 || edgeInput[0] < 1 || edgeInput[0] > N || edgeInput[1] < 1 || edgeInput[1] > N)
            {
                Console.WriteLine("Invalid edge input. Ensure values are within the correct range.");
                return;
            }

            int s = edgeInput[0] - 1;
            int t = edgeInput[1] - 1;
            outMatrix[s][t] += 1.0;
            inList[t].Add(s);
        }

        // Process matrices to calculate eats
        double eat = await CalculateEatsAsync(outMatrix, inList, N);
        Console.WriteLine(eat + 1);
    }

    static async Task<double> CalculateEatsAsync(double[][] outMatrix, List<int>[] inList, int N)
    {
        double eat = 0.0;

        for (int i = 0; i < N - 1; i++)
        {
            if (outMatrix[i][i + 1] > 0) continue;

            var valid = GetValidNodes(outMatrix, i);
            await UpdateNodesAsync(outMatrix, inList, valid, i);
        }

        for (int i = 0; i < N - 1; i++)
        {
            if (outMatrix[i][i + 1] > 0) continue;

            var valid = GetValidNodes(outMatrix, i);
            await UpdateNodesAsync(outMatrix, inList, valid, i);
        }

        for (int i = 0; i < N - 1; i++)
        {
            var spec = outMatrix[i];
            eat += spec.Sum() / (spec.Length * inList[i].Count);
        }

        return eat;
    }

    static List<int> GetValidNodes(double[][] outMatrix, int level)
    {
        return Enumerable.Range(0, outMatrix.Length)
                         .Where(j => outMatrix[j].Count(d => d > 0) == level + 1)
                         .ToList();
    }

    static async Task UpdateNodesAsync(double[][] outMatrix, List<int>[] inList, List<int> validNodes, int level)
    {
        foreach (var n in validNodes)
        {
            foreach (var nv in inList[n])
            {
                outMatrix[nv][n] /= validNodes.Count;
                outMatrix[n][nv] = 1.0;
            }
        }
    }
}

