public class SubrectangleCounter
{
    public static async Task<int> CountSubrectanglesAsync(int n, int m, int k, int[] a, int[] b)
    {
        ValidateInputs(n, m, k, a, b);

        return await Task.Run(() => CountRectanglesOfAreaK(n, m, k, a, b));
    }

    private static void ValidateInputs(int n, int m, int k, int[] a, int[] b)
    {
        if (n < 1 || m < 1 || k < 1) 
            throw new ArgumentException("Dimensions and area must be greater than zero.");
        if (a.Length != n || b.Length != m) 
            throw new ArgumentException("Array dimensions must match provided sizes.");
    }

    private static int CountRectanglesOfAreaK(int n, int m, int k, int[] a, int[] b)
    {
        var aCounts = new Dictionary<int, int>();
        var bCounts = new Dictionary<int, int>();

        CountSubarrays(a, n, aCounts);
        CountSubarrays(b, m, bCounts);

        int result = 0;

        foreach (var height in aCounts.Keys)
        {
            if (k % height == 0)
            {
                int width = k / height;
                if (bCounts.ContainsKey(width))
                {
                    result += aCounts[height] * bCounts[width];
                }
            }
        }

        return result;
    }

    private static void CountSubarrays(int[] arr, int length, Dictionary<int, int> counts)
    {
        int currentLength = 0;

        for (int i = 0; i < length; i++)
        {
            if (arr[i] == 1)
            {
                currentLength++;
                if (!counts.ContainsKey(currentLength))
                {
                    counts[currentLength] = 0;
                }
                counts[currentLength]++;
            }
            else
            {
                currentLength = 0;
            }
        }
    }
}

