public class ShortestDominatedSubarrayFinder
{
    public List<int> FindShortestDominatedSubarrays(List<(int N, int[] A)> testCases)
    {
        var results = new List<int>();

        foreach (var testCase in testCases)
        {
            try
            {
                int result = FindShortestDominatedSubarray(testCase.N, testCase.A);
                results.Add(result);
            }
            catch (Exception ex)
            {
                LogError(ex);
                results.Add(-1);
            }
        }

        return results;
    }

    private int FindShortestDominatedSubarray(int n, int[] a)
    {
        if (n < 2 || a == null || a.Length < 2)
        {
            throw new ArgumentException("Invalid input: array must have at least two elements.");
        }

        int minLength = int.MaxValue;
        var lastOccurrence = new Dictionary<int, int>();

        for (int i = 0; i < n; i++)
        {
            if (lastOccurrence.TryGetValue(a[i], out int lastIndex))
            {
                int subarrayLength = i - lastIndex + 1;
                var subarray = a.Skip(lastIndex).Take(subarrayLength).ToArray();
                int countNum = subarray.Count(x => x == a[i]);
                int maxCount = countNum;

                foreach (var element in subarray.Distinct())
                {
                    if (element != a[i])
                    {
                        maxCount = Math.Max(maxCount, subarray.Count(x => x == element));
                    }
                }

                if (countNum > maxCount && subarrayLength >= 2)
                {
                    minLength = Math.Min(minLength, subarrayLength);
                }
            }

            lastOccurrence[a[i]] = i;
        }

        return minLength == int.MaxValue ? -1 : minLength;
    }

    private void LogError(Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}");
    }
}

