public class Solution
{
    public int MaxLen(int n, int[] arr)
    {
        if (arr == null || n <= 0)
        {
            throw new ArgumentException("Input array is null or empty.");
        }

        int sum = 0;
        int maxLen = 0;
        var indexMap = new Dictionary<int, int>
        {
            { sum, -1 }
        };

        for (int index = 0; index < n; index++)
        {
            sum += arr[index];

            if (!indexMap.ContainsKey(sum))
            {
                indexMap[sum] = index;
            }
            else
            {
                maxLen = Math.Max(maxLen, index - indexMap[sum]);
            }
        }
        return maxLen;
    }
}

