public class BinaryTree
{
    private Dictionary<int, int> leftViewMap;

    public List<int> LeftView(Node root)
    {
        leftViewMap = new Dictionary<int, int>();
        LeftViewHelper(root, 1);
        return leftViewMap.OrderBy(k => k.Key).Select(k => k.Value).ToList();
    }

    private void LeftViewHelper(Node node, int level)
    {
        if (node == null)
            return;

        if (!leftViewMap.ContainsKey(level))
        {
            leftViewMap[level] = node.Data;
        }

        LeftViewHelper(node.Left, level + 1);
        LeftViewHelper(node.Right, level + 1);
    }
}

public class TreeBuilder
{
    public static Node BuildTree(string input)
    {
        if (string.IsNullOrEmpty(input) || input == "N")
            return null;

        var values = input.Split(' ').Select(x => x == "N" ? (int?)null : int.Parse(x)).ToArray();
        Node root = new Node(values[0]);
        Queue<Node> queue = new Queue<Node>();
        queue.Enqueue(root);

        for (int i = 1; i < values.Length; i++)
        {
            Node currentNode = queue.Dequeue();
            if (values[i].HasValue)
            {
                currentNode.Left = new Node(values[i].Value);
                queue.Enqueue(currentNode.Left);
            }

            if (++i < values.Length && values[i].HasValue)
            {
                currentNode.Right = new Node(values[i].Value);
                queue.Enqueue(currentNode.Right);
            }
        }

        return root;
    }
}

