using System.Linq;
using System.Threading.Tasks;

public class EllipsoidGenerator
{
    private const int SampleCount = 1000;
    private static readonly Random random = new Random();

    public async Task<(List<double> x, List<double> y)> GenerateEllipsoidAsync(double U, double V, double R)
    {
        ValidateInputs(U, V, R);

        var x = new List<double> { 0 };
        var y = new List<double> { 0 };

        await Task.Run(() =>
        {
            for (int i = 1; i <= SampleCount; i++)
            {
                double u = 2 * U * Math.Acos(random.NextDouble()) - U;
                double v = 2 * V * Math.Asin(Math.Sqrt(random.NextDouble()));
                double r = R * (1 - random.NextDouble());
                double c = (Math.Pow(r, 2) * Math.Pow(Math.Sin(v), 2)) / Math.Pow(1 - Math.Pow(r * Math.Sin(v), 2), 2);
                x.Add(c * Math.Cos(u) * Math.Cos(v));
                y.Add(c * Math.Cos(u) * Math.Sin(v));
            }
        });

        return (x, y);
    }

    private void ValidateInputs(double U, double V, double R)
    {
        if (U <= 0 || V <= 0 || R <= 0)
        {
            throw new ArgumentOutOfRangeException("Parameters U, V, and R must be positive.");
        }
    }
}

