    private static async Task SolveAsync()
    {
        Console.WriteLine("Enter number of nodes and edges:");
        var input = Console.ReadLine();
        if (string.IsNullOrWhiteSpace(input) || !TryParseInput(input, out int n, out int m))
        {
            Console.WriteLine("Invalid input for number of nodes or edges.");
            return;
        }

        var adjMatrix = InitializeAdjacencyMatrix(n);

        Console.WriteLine("Enter edges:");
        for (int i = 0; i < m; i++)
        {
            input = Console.ReadLine();
            if (!TryParseEdgeInput(input, out int a, out int b))
            {
                Console.WriteLine("Invalid edge input.");
                return;
            }
            AddEdge(adjMatrix, a, b);
        }

        var visited = new bool[n];
        visited[0] = true;

        int count = CalculatePermutations(adjMatrix, 0, visited, 1, n);
        Console.WriteLine($"Total permutations: {count}");
    }

    private static int CalculatePermutations(int[][] adjMatrix, int current, bool[] visited, int visitedCount, int n)
    {
        if (visitedCount == n)
            return 1;

        int count = 0;
        for (int i = 0; i < n; i++)
        {
            if (adjMatrix[current][i] == 1 && !visited[i])
            {
                visited[i] = true;
                count += CalculatePermutations(adjMatrix, i, visited, visitedCount + 1, n);
                visited[i] = false;
            }
        }

        return count;
    }

    private static int[][] InitializeAdjacencyMatrix(int size)
    {
        var matrix = new int[size][];
        for (int i = 0; i < size; i++)
            matrix[i] = new int[size];
        return matrix;
    }

    private static void AddEdge(int[][] adjMatrix, int a, int b)
    {
        if (a < 1 || b < 1 || a > adjMatrix.Length || b > adjMatrix.Length)
        {
            throw new ArgumentOutOfRangeException("Edge indices are out of bounds.");
        }
        adjMatrix[a - 1][b - 1] = 1;
        adjMatrix[b - 1][a - 1] = 1;
    }

    private static bool TryParseInput(string input, out int n, out int m)
    {
        var parts = input.Split(' ', StringSplitOptions.RemoveEmptyEntries);
        return parts.Length == 2 && int.TryParse(parts[0], out n) && int.TryParse(parts[1], out m);
    }

    private static bool TryParseEdgeInput(string input, out int a, out int b)
    {
        var parts = input.Split(' ', StringSplitOptions.RemoveEmptyEntries);
        return parts.Length == 2 && int.TryParse(parts[0], out a) && int.TryParse(parts[1], out b);
    }
}

