                        if (T.Contains(string.Join(",", val)))
                        {
                            prev.Add(string.Join(",", val));
                        }
                    }
                }

                var ans = inputList.Skip(1).Select(x => (int.Parse(x))).Select(x => x * x).ToList();
                for (int j = 0; j < arr.Count - 1; j++)
                {
                    var vals = new List<int>();
                    foreach (var jValue in ans)
                    {
                        vals.Add(jValue + arr[j + 1]);
                    }
                    ans = vals;
                }

                Console.WriteLine(string.Join(",", ans));
            }
        }
        catch (FormatException ex)
        {
            Console.WriteLine($"Input format error: {ex.Message}");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"An error occurred: {ex.Message}");
        }
    }

    private static IEnumerable<IEnumerable<int>> GetPermutations(List<int> list, int length)
    {
        if (length == 1) return list.Select(t => new[] { t });

        return GetPermutations(list, length - 1)
            .SelectMany(t => list.Where(e => !t.Contains(e)),
                        (t1, t2) => t1.Concat(new[] { t2 }));
    }

    private static IEnumerable<IEnumerable<int>> GetProduct(List<int> list, int count)
    {
        if (count == 1) return list.Select(t => new[] { t });

        return GetProduct(list, count - 1)
            .SelectMany(t => list, (t1, t2) => t1.Concat(new[] { t2 }));
    }
}

using System;

public class Solver
{
    public (int, int) Solve(int N, int A, int B)
    {
        ValidateInputs(N, A, B);

        int sum = A + B;
        if (N % sum == 0)
        {
            return (N / sum, 0);
        }

        int odd = N - N % sum + sum;
        int N1 = N / sum;
        int N2 = odd / sum;

        if (N1 > N2)
        {
            return (N1, N1 - N * N1 + N2 * (N2 - N1));
        }
        else
        {
            return (N2, N2 - N * N2 + N1 * (N1 - N2));
        }
    }

    private void ValidateInputs(int N, int A, int B)
    {
        if (N < 0)
        {
            LogError("N must be non-negative.");
            throw new ArgumentOutOfRangeException(nameof(N), "N must be non-negative.");
        }

        if (A <= 0 || B <= 0)
        {
            LogError("A and B must be positive integers.");
            throw new ArgumentOutOfRangeException(nameof(A), "A and B must be positive integers.");
        }
    }

    private void LogError(string message)
    {
        // Lightweight logging can be replaced with a more robust logging framework
        Console.WriteLine($"Error: {message}");
    }
}

