        }
        throw new FormatException("Input must be an integer.");
    }

    static async Task<double[]> ReadDoublesAsync()
    {
        string input = await Task.Run(() => Console.ReadLine());
        var parts = input.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);
        double[] numbers = new double[parts.Length];

        for (int i = 0; i < parts.Length; i++)
        {
            if (!double.TryParse(parts[i], NumberStyles.Any, CultureInfo.InvariantCulture, out numbers[i]))
            {
                throw new FormatException("Coordinates must be valid numbers.");
            }
