    static string CheckParallel(double x1, double y1, double x2, double y2, double x3, double y3, double x4, double y4)
    {
        double? slopeAB = CalculateSlope(x1, y1, x2, y2);
        double? slopeCD = CalculateSlope(x3, y3, x4, y4);

        if (slopeAB.HasValue && slopeCD.HasValue && slopeAB.Value == slopeCD.Value)
        {
            return "YES";
        }
        return "NO";
    }

    static double? CalculateSlope(double x1, double y1, double x2, double y2)
    {
        if (x2 - x1 == 0) return null; // handle vertical line case
        return (y2 - y1) / (x2 - x1);
