public class TreeNode
{
    public int Val { get; set; }
    public TreeNode Left { get; set; }
    public TreeNode Right { get; set; }

    public TreeNode(int val = 0, TreeNode left = null, TreeNode right = null)
    {
        Val = val;
        Left = left;
        Right = right;
    }
}

public class Solution
{
    private readonly char[] chars = "abcdefghijklmnopqrstuvwxyz".ToCharArray();
    private string ans = "~";

    public string SmallestFromLeaf(TreeNode root)
    {
        if (root == null)
        {
            throw new ArgumentNullException(nameof(root), "The tree root cannot be null.");
        }

        ExploreTree(root, new Stack<char>());
        return ans;
    }

    private void ExploreTree(TreeNode node, Stack<char> path)
    {
        if (node == null)
        {
            return;
        }

        path.Push(chars[node.Val]);

        if (node.Left == null && node.Right == null)
        {
            // Construct string from path and compare
            string currentPath = new string(path.Reverse().ToArray());
            ans = string.Compare(currentPath, ans, StringComparison.Ordinal) < 0 ? currentPath : ans;
        }

        ExploreTree(node.Left, path);
        ExploreTree(node.Right, path);
        path.Pop();
    }
}

