    private static T GetInput<T>(string prompt)
    {
        Console.WriteLine(prompt);
        string input = Console.ReadLine();
        ValidateInput(input);
        return (T)Convert.ChangeType(input, typeof(T));
    }

    private static void ValidateInput(string input)
    {
        if (string.IsNullOrWhiteSpace(input))
        {
            throw new ArgumentException("Input cannot be null or empty.");
        }
    }

    private static string FindLongestPalindrome(string s)
    {
        int n = s.Length;
        int maxLen = 1;
        int start = 0;

        for (int i = 1; i < n; i++)
        {
            CheckPalindrome(s, i - 1, i, ref start, ref maxLen);
            CheckPalindrome(s, i - 1, i + 1, ref start, ref maxLen);
        }

        return s.Substring(start, maxLen);
    }

    private static void CheckPalindrome(string s, int low, int high, ref int start, ref int maxLen)
    {
        while (low >= 0 && high < s.Length && s[low] == s[high])
        {
            if (high - low + 1 > maxLen)
            {
                start = low;
                maxLen = high - low + 1;
            }
            low--;
            high++;
        }
    }
}

