using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class GameLevel
{
    private int _n;
    private int _r1, _r2, _r3, _d;
    private List<int> _a;
    private const int MaxTimeMultiplier = 100;

    public GameLevel(int n, int r1, int r2, int r3, int d, List<int> a)
    {
        _n = n;
        _r1 = r1;
        _r2 = r2;
        _r3 = r3;
        _d = d;
        _a = a;
    }

    public async Task<int> MinTimeAsync()
    {
        int maxTime = Math.Max(_r1, Math.Max(_r2, _r3));
        var dp = InitializeDP(maxTime);

        dp[_n][0] = 0;

        for (int t = 1; t <= maxTime; t++)
        {
            await GetNextGun(t, dp);
            if (t <= _r1)
            {
                await GetNextGun(0, dp);
            }
            else if (t <= _r1 + _r3 - _d)
            {
                await GetNextGun(t, dp);
            }
        }

        return dp[1][_r1];
    }

    private int[][][] InitializeDP(int maxTime)
    {
        var dp = new int[_n + 1][][];
        for (int i = 0; i <= _n; i++)
        {
            dp[i] = new int[maxTime + 1][];
            for (int j = 0; j <= maxTime; j++)
            {
                dp[i][j] = Enumerable.Repeat(int.MaxValue, maxTime).ToArray();
            }
        }
        return dp;
    }

    private async Task GetNextGun(int currentReload, int[][][] dp)
    {
        for (int i = 0; i < _n; i++)
        {
            await Task.Run(() =>
            {
                for (int gunReload = 1; gunReload <= MaxTimeMultiplier; gunReload++)
                {
                    int totalTime = gunReload + currentReload;
                    UpdateDP(i, totalTime, dp, gunReload);
                }
            });
        }
    }

    private void UpdateDP(int i, int totalTime, int[][][] dp, int gunReload)
    {
        if (gunReload + _d <= _r1)
        {
            totalTime += _a[i];
        }
        else if (gunReload + _d <= _r2)
        {
            totalTime += _a[i] + _a[i + 1] + 1;
        }
        else
        {
            totalTime += _a[i] + _a[i + 1] + 2;
        }
        dp[i + 1][totalTime % (_r1 + 1)][gunReload] = Math.Min(dp[i + 1][totalTime % (_r1 + 1)][gunReload], totalTime);
    }

    private bool IsLoaded(int reload, int position)
    {
        return reload <= _r1 + (position > 1) &&
               (reload > _r1 && reload <= _r1 + (position - 2) || reload > _r1 + _r3 - (position - 2) * _d + 1);
    }
}

