using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class Solution
{
    public async Task<int> LongestSubarrayAsync(int[] nums)
    {
        if (nums == null || nums.Length == 0)
        {
            LogError("Input array is null or empty.");
            return 0;
        }

        int n = nums.Length;

        if (n <= 1)
        {
            return n - 1;
        }

        if (!nums.Any(num => num == 1))
        {
            return 0;
        }

        return await Task.Run(() => FindLongestSubarray(nums));
    }

    private int FindLongestSubarray(int[] nums)
    {
        int left = 0;
        int maxLength = 0;
        int zeroCount = 0;

        for (int right = 0; right < nums.Length; right++)
        {
            if (nums[right] == 0)
            {
                zeroCount++;
            }

            while (zeroCount > 1)
            {
                if (nums[left] == 0)
                {
                    zeroCount--;
                }
                left++;
            }

            maxLength = Math.Max(maxLength, right - left);
        }

        return maxLength;
    }

    private void LogError(string message)
    {
        Console.WriteLine($"Error: {message}");
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    private const string Alphabet = "abcdefghijklmnopqrstuvwxyz";

    static async Task Main(string[] args)
    {
        try
        {
            var input = Console.ReadLine();

            if (!ValidateInput(input, out int n, out List<int> s))
            {
                Console.WriteLine("Invalid input.");
                return;
            }

            bool isValid = CheckSequence(n, s);

            Console.WriteLine(isValid ? "Yes" : "No");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"An error occurred: {ex.Message}");
        }
    }

    private static bool ValidateInput(string input, out int n, out List<int> s)
    {
        s = new List<int>();
        n = 0;
        var parts = input.Split(' ');

        if (parts.Length < 1 || !int.TryParse(parts[0], out n) || n < 1)
        {
            return false;
        }

        for (int i = 1; i <= n; i++)
        {
            if (i >= parts.Length || !int.TryParse(parts[i], out int value) || value < 0 || value > 26)
            {
                return false;
            }
            s.Add(value);
        }

        return true;
    }

    private static bool CheckSequence(int n, List<int> s)
    {
        int A = 0;

        for (int i = 0; i < n; i++)
        {
            if (s[i] > 26)
                return false;

            if (s[i] == Alphabet[A] - 'a')
            {
                A++;
                if (A == Alphabet.Length) A = 0;
            }
            else if (s[i] != Alphabet[A] - 'a')
            {
                return false;
            }
        }

        return ProcessResults(n, s, A);
    }

    private static bool ProcessResults(int n, List<int> s, int A)
    {
        if (s[0] < 26)
            s[0] = Alphabet[0..A].ToCharArray()[0] - 'a';
        else
        {
            int setIndex = 0;

            for (int i = 0; i < s[0]; i++)
            {
                while (setIndex < n)
                {
                    if (s[setIndex] > 26) break;

                    if (s[setIndex] >= Alphabet.IndexOf((char)(s[0] + 'a')) + A)
                    {
                        s[setIndex] = Alphabet[0..(s[0] - Alphabet.IndexOf((char)(s[setIndex] + 'a')) - A)].ToCharArray()[0] - 'a';
                    }

                    setIndex++;
                    if (setIndex == n)
                    {
                        s[setIndex] = Alphabet[0..(s[0] - Alphabet.IndexOf((char)(s[setIndex] + 'a')) - A)].ToCharArray()[0] - 'a';
                    }
                }
            }
        }

        for (int loc = 1; loc < n; loc++)
        {
            while (Alphabet.IndexOf((char)(s[loc] + 'a')) < A)
            {
                s[loc] += Alphabet[0..(s[loc] - Alphabet.IndexOf((char)(s[loc] + 'a')) - A)];
            }
        }

        return true;
    }
}

