        using (var reader = new System.IO.StreamReader(Console.OpenStandardInput()))
        {
            return (await reader.ReadToEndAsync()).Split(new[] { ' ', '\n' }, StringSplitOptions.RemoveEmptyEntries);
        }
    }

    private static int ProcessSnacks(string[] data)
    {
        if (data.Length < 2) throw new ArgumentException("Insufficient input data.");

        if (!int.TryParse(data[0], out int N) || !int.TryParse(data[1], out int K))
            throw new FormatException("Invalid format for N and K.");

        int index = 2;
        var snacks = new int[N + 1];

        for (int i = 0; i < K; i++)
        {
            if (index >= data.Length) throw new InvalidOperationException("Data ended unexpectedly.");
            if (!int.TryParse(data[index], out int d)) throw new FormatException("Invalid snack count.");

            index++;
            for (int j = 0; j < d; j++)
            {
                if (index >= data.Length) throw new InvalidOperationException("Data ended unexpectedly.");
                if (!int.TryParse(data[index], out int snackIndex) || snackIndex < 1 || snackIndex > N)
                    throw new ArgumentOutOfRangeException($"Snack index {snackIndex} is out of range.");

                snacks[snackIndex] = 1;
                index++;
            }
        }

        return N - snacks.Sum();
    }
}

