using System.Threading.Tasks;
using Microsoft.Extensions.Logging;

public class Program
{
    private static readonly ILogger<Program> logger = LoggerFactory.Create(builder => 
    {
        builder.AddConsole();
    }).CreateLogger<Program>();

    public static async Task Main(string[] args)
    {
        try
        {
            Console.Write("Enter the number of elements: ");
            if (!int.TryParse(Console.ReadLine(), out int n) || n <= 0)
            {
                logger.LogError("Invalid number of elements.");
                return;
            }

            Console.Write("Enter the elements (space-separated): ");
            var input = Console.ReadLine();
            var s = input?.Split(' ').Select(int.Parse).ToList();

            if (s == null || s.Count != n)
            {
                logger.LogError("Input count does not match the declared number of elements.");
                return;
            }

            var result = await GetSwapsAsync(s);
            foreach (var entry in result)
            {
                Console.WriteLine($"{entry.Key}: {string.Join(", ", entry.Value)}");
            }
        }
        catch (Exception ex)
        {
            logger.LogError(ex, "An unexpected error occurred.");
        }
    }

    private static string GetJump(int m, List<int> c)
    {
        return string.Join("/", c.Select(x => (x % m).ToString()));
    }

    private static async Task<Dictionary<string, List<int>>> GetSwapsAsync(List<int> c)
    {
        var n = c.Count;
        var result = new Dictionary<string, List<int>>();

        for (int i = 0; i < n; i++)
        {
            int m = 0;

            for (int j = i; j < n; j++)
            {
                Swap(c, i, j);
                var jumpValue = GetJump(m, c);

                if (!result.ContainsKey(jumpValue))
                {
                    result[jumpValue] = new List<int>(c);
                }

                m++;
                c = new List<int>(result[jumpValue]);
                ResetSwaps(c, i, j);
            }
        }

        return result;
    }

    private static void Swap(List<int> c, int i, int j)
    {
        var temp = c[i];
        c[i] = c[j];
        c[j] = temp;
    }

    private static void ResetSwaps(List<int> c, int i, int j)
    {
        Swap(c, i, j);
    }
}

