class RedBlackTree
{
    public Node Root { get; private set; }
    private List<int> BlackNodes { get; } = new List<int>();
    private const int GreenColorValue = 1;
    private int Count { get; set; } = 0;

    public void Insert(int data)
    {
        try
        {
            var newNode = new Node(data);
            if (Root == null)
            {
                Root = newNode;
                BlackNodes.Add(Root.Data);
                Count++;
                return;
            }
            InsertNode(Root, newNode);
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"Error during insertion: {ex.Message}");
        }
    }

    private void InsertNode(Node current, Node newNode)
    {
        if (current == null) return;

        if (newNode.Data < current.Data)
        {
            if (current.Left == null)
            {
                current.Left = newNode;
                return;
            }
            InsertNode(current.Left, newNode);
        }
        else
        {
            if (current.Right == null)
            {
                current.Right = newNode;
                return;
            }
            InsertNode(current.Right, newNode);
        }
    }

    public void TraverseAndColor()
    {
        TraverseAndColor(Root, string.Empty);
    }

    private void TraverseAndColor(Node node, string prefix)
    {
        if (node == null) return;

        TraverseAndColor(node.Left, prefix);
        Console.WriteLine($"{prefix}{node.Data} - Color: {(IsGreen(node) ? "Green" : "Red")}");
        TraverseAndColor(node.Right, prefix);
    }

    private bool IsGreen(Node node)
    {
        return node != null && (node.Data & GreenColorValue) != 0;
    }

    public override string ToString()
    {
        return $"RBTree(root={Root?.Data})";
    }
}

