    {
        try
        {
            var n = await ReadIntegerAsync();
            if (n <= 0) throw new ArgumentException("Array size must be positive");

            var arr = new int[n];
            for (int i = 0; i < n; i++)
            {
                arr[i] = await ReadIntegerAsync();
            }

            var ans = CalculateAdjustedValues(arr);
            PrintArray(ans);
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
        }
    }

    private static async Task<int> ReadIntegerAsync()
    {
        var input = await Console.In.ReadLineAsync();
        if (int.TryParse(input, out int result))
        {
            return result;
        }
        throw new InvalidDataException("Invalid integer input");
    }

    private static int[] CalculateAdjustedValues(int[] arr)
    {
        var n = arr.Length;
        var ans = new int[n];

        for (int i = 0; i < n; i++)
        {
            ans[i] = arr[i] - i;
        }

        int min = ans.Min();
        for (int i = 0; i < n; i++)
        {
            ans[i] -= min;
        }

        return ans;
    }

    private static void PrintArray(int[] arr)
    {
        Console.WriteLine(string.Join(" ", arr));
    }
}

