public class PalindromeHelper
{
    public static void ProcessString(string input)
    {
        if (string.IsNullOrEmpty(input))
        {
            LogError("Input cannot be null or empty.");
            return;
        }

        try
        {
            var result = FindPalindrome(input);
            Console.WriteLine(result);
        }
        catch (Exception ex)
        {
            LogError($"An error occurred: {ex.Message}");
        }
    }

    private static string FindPalindrome(string s)
    {
        int n = s.Length;
        string prefix = string.Empty;
        string suffix = string.Empty;
        int pt = 0;
        int st = n - 1;

        while (st > pt && s[pt] == s[st])
        {
            pt++;
            st--;
            prefix += s[pt - 1];
            suffix = s[st] + suffix;
        }

        if (st < pt)
        {
            return st > pt ? s.Substring(pt, st - pt + 1) : "Just a legend";
        }
        else
        {
            string middle = s.Substring(st + 1, n - pt - st - 1);

            for (int i = 0; i < middle.Length; i++)
            {
                char j = middle[middle.Length - i - 1];
                if (prefix.Length > 0 && prefix[^1] == j && middle.Substring(0, i + 1) == middle.Substring(i))
                {
                    return prefix + middle.Substring(0, i + 1) + suffix;
                }
            }
        }

        return "Just a legend";
    }

    private static void LogError(string message)
    {
        // Implement logging logic (e.g., to console, file, or logging framework)
        Console.WriteLine("Error: " + message);
    }
}

