class SubstringFinder
{
    public static async Task Main(string[] args)
    {
        try
        {
            string inputString = await ReadInputAsync("Enter the string (S): ");
            string searchPattern = await ReadInputAsync("Enter the substring pattern (k): ");

            var indices = FindSubstringIndices(inputString, searchPattern);
            LogResults(indices);
        }
        catch (Exception ex)
        {
            LogError("An error occurred: " + ex.Message);
        }
    }

    private static async Task<string> ReadInputAsync(string prompt)
    {
        Console.Write(prompt);
        return await Task.Run(() => Console.ReadLine()?.Trim() ?? string.Empty);
    }

    private static List<(int start, int end)> FindSubstringIndices(string inputString, string pattern)
    {
        ValidateInputs(inputString, pattern);

        var matches = Regex.Matches(inputString, pattern);
        var indices = new List<(int, int)>();

        foreach (Match match in matches)
        {
            indices.Add((match.Index, match.Index + match.Length - 1));
        }

        if (indices.Count == 0)
        {
            indices.Add((-1, -1));
        }

        return indices;
    }

    private static void ValidateInputs(string inputString, string pattern)
    {
        if (string.IsNullOrEmpty(inputString))
        {
            throw new ArgumentException("Input string (S) cannot be null or empty.");
        }

        if (string.IsNullOrEmpty(pattern))
        {
            throw new ArgumentException("Pattern (k) cannot be null or empty.");
        }
    }

