            inputLines.Add(await Task.Run(() => Console.ReadLine()));
        }

        return inputLines.ToArray();
    }

    private static List<string> ProcessInputs(string[] inputs)
    {
        var processedLines = new List<string>();

        foreach (var line in inputs)
        {
            var wordsWithSums = line.Split(' ')
                                    .Select(word => new
                                    {
                                        Word = word,
                                        Sum = CalculateDigitSum(word)
                                    })
                                    .OrderBy(w => w.Sum)
                                    .Select(w => FormatOutput(w.Word, w.Sum))
                                    .ToList();

            processedLines.Add(string.Join(" ", wordsWithSums));
