class RectangleAreaCalculator
{
    private const int Mod = 1000000007;

    public static async Task<long> SolveAsync(int n, int m, int[] x, int[] y)
    {
        ValidateInputs(n, m, x, y);

        var freqX = new Dictionary<int, int>();

        foreach (var xi in x)
        {
            if (freqX.ContainsKey(xi))
                freqX[xi]++;
            else
                freqX[xi] = 1;
        }

        long totalArea = 0;

        for (int i = 0; i < m; i++)
        {
            for (int j = i + 1; j < m; j++)
            {
                int xI = x[i];
                int xJ = x[j];

                for (int k = 0; k < n; k++)
                {
                    for (int l = k + 1; l < n; l++)
                    {
                        int yI = y[k];
                        int yL = y[l];

                        long area = (long)(xJ - xI) * (yL - yI);
                        totalArea = (totalArea + area) % Mod;
                    }
                }
            }
        }

        return totalArea;
    }

    private static void ValidateInputs(int n, int m, int[] x, int[] y)
    {
        if (n <= 0 || m <= 0)
            throw new ArgumentException("n and m must be greater than zero.");
        if (x.Length != m || y.Length != n)
            throw new ArgumentException("The lengths of x and y must match m and n respectively.");
    }

    static async Task Main(string[] args)
    {
        try
        {
            var inputs = Console.ReadLine().Split();
            int n = int.Parse(inputs[0]);
            int m = int.Parse(inputs[1]);

            int[] x = Array.ConvertAll(Console.ReadLine().Split(), int.Parse);
            int[] y = Array.ConvertAll(Console.ReadLine().Split(), int.Parse);

            long result = await SolveAsync(n, m, x, y);
