using System;
using System.Collections.Generic;
using System.Threading.Tasks;

public class QuerySum
{
    public static async Task<List<long>> GetQuerySumAsync(int n, long[] arr, int q, int[] queries)
    {
        if (n <= 0 || arr.Length != n)
        {
            throw new ArgumentException("Invalid array size.");
        }

        if (queries.Length != 2 * q)
        {
            throw new ArgumentException("Invalid queries size.");
        }

        long[] prefixSum = CreatePrefixSumArray(arr);
        return await ProcessQueriesAsync(prefixSum, queries, q);
    }

    private static long[] CreatePrefixSumArray(long[] arr)
    {
        int n = arr.Length;
        long[] prefixSum = new long[n + 1];

        for (int i = 1; i <= n; i++)
        {
            prefixSum[i] = prefixSum[i - 1] + arr[i - 1];
        }

        return prefixSum;
    }

    private static async Task<List<long>> ProcessQueriesAsync(long[] prefixSum, int[] queries, int q)
    {
        var result = new List<long>();

        for (int i = 0; i < 2 * q; i += 2)
        {
            int l = queries[i];
            int r = queries[i + 1];

            if (l < 1 || r < 1 || l > prefixSum.Length - 1 || r > prefixSum.Length - 1 || l > r)
            {
                throw new ArgumentOutOfRangeException("Query indices are out of bounds.");
            }

            long sum = await Task.Run(() => prefixSum[r] - prefixSum[l - 1]);
            result.Add(sum);
        }

        return result;
    }
}

