public class Solution
{
    public bool Check(string s)
    {
        if (string.IsNullOrEmpty(s))
        {
            Log("Input string is null or empty.");
            return false;
        }

        return s.Distinct().Count() == 1;
    }

    public async Task<int[]> TwoSumAsync(int[] nums, int target)
    {
        ValidateInput(nums);

        var dic = new Dictionary<int, int>();

        for (int i = 0; i < nums.Length; i++)
        {
            int complement = target - nums[i];
            if (!dic.ContainsKey(complement))
            {
                dic[nums[i]] = i;
            }
            else
            {
                Log($"Solution found: indices {dic[complement]} and {i}");
                return new[] { dic[complement], i };
            }
        }

        Log("No solution found.");
        return Array.Empty<int>();
    }

    public string ReversePrefix(string word, char ch)
    {
        if (string.IsNullOrEmpty(word) || !word.Contains(ch))
        {
            Log("Invalid input for reversing prefix.");
            return word;
        }

        int idx = word.IndexOf(ch);
        var reversedPrefix = new string(word.Take(idx + 1).Reverse().ToArray());
        var suffix = word.Substring(idx + 1);

        return reversedPrefix + suffix;
    }

    public int[] SearchRange(int[] nums, int target)
    {
        if (nums == null || nums.Length == 0)
        {
            Log("Array is null or empty.");
            return new[] { -1, -1 };
        }

        int left = 0, right = nums.Length - 1;

        while (left <= right)
        {
            int mid = left + (right - left) / 2;

            if (nums[mid] == target)
            {
                int start = FindStart(nums, target, mid);
                int end = FindEnd(nums, target, mid);
                return new[] { start, end };
            }
            else if (nums[mid] > target)
            {
                right = mid - 1;
            }
            else
            {
                left = mid + 1;
            }
        }

        Log("Target not found.");
        return new[] { -1, -1 };
    }

    private int FindStart(int[] nums, int target, int mid)
    {
        while (mid > 0 && nums[mid - 1] == target)
        {
            mid--;
        }
        return mid;
    }

    private int FindEnd(int[] nums, int target, int mid)
    {
        while (mid < nums.Length - 1 && nums[mid + 1] == target)
        {
            mid++;
        }
        return mid;
    }

    private void ValidateInput(int[] nums)
    {
        if (nums == null || nums.Length == 0)
        {
            throw new ArgumentException("Input array cannot be null or empty.");
        }
    }

    private void Log(string message)
    {
        // Simple logging. In production, consider using a logging framework.
        Console.WriteLine($"Log: {message}");
    }
}

