    {
        int count = 0;
        for (int i = 0; i < n; i++)
        {
            if (i % 3 == 0 && s[i] != 'R') count++;
            else if (i % 3 == 1 && s[i] != 'G') count++;
            else if (i % 3 == 2 && s[i] != 'B') count++;
        }
        return count;
    }

