public class FriendsTShirtSorter
{
    public async Task<List<string>> CanSortWithSwapsAsync(int t, List<(int n, int[] a)> testCases)
    {
        var results = new List<string>();

        foreach (var caseData in testCases)
        {
            try
            {
                results.Add(await ProcessTestCaseAsync(caseData.n, caseData.a));
            }
            catch (Exception ex)
            {
                Console.Error.WriteLine($"Error processing case: {ex.Message}");
                results.Add("NO");
            }
        }

        return results;
    }

    private async Task<string> ProcessTestCaseAsync(int n, int[] a)
    {
        ValidateInput(n, a);

        var evenIndices = a.Where((value, index) => index % 2 == 0).ToList();
        var oddIndices = a.Where((value, index) => index % 2 == 1).ToList();

        evenIndices.Sort();
        oddIndices.Sort();

        var merged = MergeSortedLists(evenIndices, oddIndices);
        return IsNonDecreasing(merged) ? "YES" : "NO";
    }

    private void ValidateInput(int n, int[] a)
    {
        if (n < 1 || a == null || a.Length != n)
        {
            throw new ArgumentException("Invalid input parameters.");
        }
    }

    private List<int> MergeSortedLists(List<int> even, List<int> odd)
    {
        var merged = new List<int>();

        int i = 0, j = 0;
        while (i < even.Count || j < odd.Count)
        {
            if (i < even.Count)
            {
                merged.Add(even[i++]);
            }
            if (j < odd.Count)
            {
                merged.Add(odd[j++]);
            }
        }

        return merged;
    }

    private bool IsNonDecreasing(List<int> sequence)
    {
        for (int i = 1; i < sequence.Count; i++)
        {
            if (sequence[i] < sequence[i - 1])
                return false;
        }
        return true;
    }
}

