public class CandyDistribution
{
    public static async Task Main(string[] args)
    {
        try
        {
            int t = int.Parse(Console.ReadLine().Trim());
            var results = new List<int>();

            for (int i = 0; i < t; i++)
            {
                var inputs = Console.ReadLine().Trim().Split();
                if (inputs.Length != 2 || !int.TryParse(inputs[0], out int n) || !int.TryParse(inputs[1], out int k))
                {
                    Console.WriteLine("Invalid input. Please provide two integers.");
                    continue;
                }
                results.Add(await MaxCandiesAsync(n, k));
            }

            foreach (var result in results)
            {
                Console.WriteLine(result);
            }
        }
        catch (FormatException)
        {
            Console.WriteLine("Input format is incorrect.");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"An error occurred: {ex.Message}");
        }
    }

    private static async Task<int> MaxCandiesAsync(int n, int k)
    {
        return await Task.Run(() => BinarySearch(0, n, n, k));
    }

    private static int BinarySearch(int left, int right, int n, int k)
    {
        while (left < right)
        {
            int mid = (left + right + 1) / 2;
            if (Check(mid, ref n, k))
            {
                left = mid;
            }
            else
            {
                right = mid - 1;
            }
        }
        return left;
    }

    private static bool Check(int mid, ref int n, int k)
    {
        int low = 0;
        int high = mid;
        int children = 0;

        while (children < k)
        {
            int candies = Math.Min(mid, n);
            if (candies < low)
            {
                return false;
            }

            children++;
            n -= candies;

            if (children > (k / 2) && mid - candies < low)
            {
                return false;
            }

            high = Math.Max(high, candies);
            low += mid - candies;
        }

        return high - low <= 1;
    }
}

