public class Dhoom4
{
    public static async Task Main(string[] args)
    {
        try
        {
            var input = Console.ReadLine()?.Split(' ').Select(int.Parse).ToArray();
            if (input == null || input.Length < 2)
            {
                throw new ArgumentException("Invalid input for N and M.");
            }

            int N = input[0];
            int M = input[1];

            var keysInput = Console.ReadLine()?.Split(' ').Select(int.Parse).ToArray();
            if (keysInput == null || keysInput.Length != N)
            {
                throw new ArgumentException("Invalid input for keys.");
            }

            Console.WriteLine(await FindStrongestKeyAsync(N, M, keysInput));
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
        }
    }

    private static async Task<int> FindStrongestKeyAsync(int N, int M, IEnumerable<int> keys)
    {
        var graph = new Dictionary<int, List<int>>();
        foreach (var key in keys)
        {
            if (!graph.ContainsKey(1)) graph[1] = new List<int>();
            if (!graph.ContainsKey(key)) graph[key] = new List<int>();
            graph[1].Add(key);
            graph[key].Add(1);
        }

        return await Task.Run(() => Bfs(graph, N, M));
    }

    private static int Bfs(Dictionary<int, List<int>> graph, int N, int M)
    {
        var visited = new Dictionary<int, bool>();
        var distance = new Dictionary<int, int>();

        for (int i = 1; i <= N; i++)
        {
            visited[i] = false;
            distance[i] = 0;
        }

        var queue = new Queue<int>();
        distance[1] = 0;
        visited[1] = true;
        queue.Enqueue(1);

        while (queue.Count > 0)
        {
            var node = queue.Dequeue();
            foreach (var neighbor in graph[node])
            {
                if (!visited[neighbor])
                {
                    visited[neighbor] = true;
                    if (M % neighbor == 0)
                    {
                        return distance[node] + 1;
                    }
                    distance[neighbor] = distance[node] + 1;
                    queue.Enqueue(neighbor);
                }
            }
        }

        return -1;  // Target not reachable
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class SequenceCounter
{
    private const int MOD = 998244353;

    public static long CountSequences(int n, int k, int[] a, int[] b)
    {
        var positions = new Dictionary<int, List<int>>();
        for (int i = 0; i < a.Length; i++)
        {
            if (!positions.ContainsKey(a[i]))
                positions[a[i]] = new List<int>();
            positions[a[i]].Add(i);
        }

        if (!positions.ContainsKey(b[0]) || positions[b[0]].Count == 0)
            return 0;

        var dp = new long[k + 1][];
        for (int i = 0; i <= k; i++)
            dp[i] = new long[n + 1];

        dp[0][positions[b[0]][0]] = 1;

        for (int i = 1; i < k; i++)
        {
            var added = new HashSet<int>();
            foreach (var j in Enumerable.Range(0, n))
            {
                foreach (var p in positions[b[i]])
                {
                    if (p - 1 == j)
                    {
                        dp[i][p] = (dp[i][p] + Enumerable.Range(0, p).Sum(x => dp[i - 1][x])) % MOD;
                        added.Add(p);
                    }
                    else if (p + 1 == j)
                    {
                        dp[i][p] = (dp[i][p] + Enumerable.Range(p + 1, n - (p + 1)).Sum(x => dp[i - 1][x])) % MOD;
                        added.Add(p);
                    }
                }

                foreach (var p in added)
                {
                    positions[b[i]].Remove(p);
                }
            }
            positions[b[i]].Clear();
        }

        var lastPos = positions[b[^1]][0];
        long result = (lastPos > 0) 
            ? (dp[k - 1][lastPos] + dp[k - 1][lastPos - 1]) % MOD 
            : dp[k - 1][lastPos];

        return result;
    }

    public static async Task Main(string[] args)
    {
        try
        {
            int n = int.Parse(args[0]);
            int k = int.Parse(args[1]);
            int[] a = Array.ConvertAll(args[2..(2 + n)], int.Parse);
            int[] b = Array.ConvertAll(args[(2 + n)..], int.Parse);

            ValidateInputs(n, k, a, b);
            long result = await Task.Run(() => CountSequences(n, k, a, b));
            Console.WriteLine(result);
        }
        catch (FormatException)
        {
            Console.WriteLine("Invalid input format. Please ensure all inputs are integers.");
        }
        catch (IndexOutOfRangeException)
        {
            Console.WriteLine("Insufficient input parameters provided.");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"An unexpected error occurred: {ex.Message}");
        }
    }

    private static void ValidateInputs(int n, int k, int[] a, int[] b)
    {
        if (n <= 0 || k <= 0)
            throw new ArgumentOutOfRangeException("n and k must be greater than zero.");
        if (a.Length != n || b.Length != k)
            throw new ArgumentException("Input array lengths do not match the specified sizes.");
    }
}

