    {
        var matrix = new List<List<int>>();
        for (int i = 0; i < height; i++)
        {
            Console.WriteLine($"Enter row {i + 1} for {color} matrix:");
            var row = Console.ReadLine()!.Split().Select(int.Parse).ToList();
            if(row.Count != width) throw new Exception($"Row must have exactly {width} integers.");
            matrix.Add(row);
