    {
        for (int i = 0; i < H; i++)
        {
            for (int j = 0; j < W; j++)
            {
                ValidateIndices(i, j, H, W);

                if (Math.Abs(red[i][j] - blue[i][j]) <= k)
                {
                    red0.Add((i, j));
                }

                if ((red[i][j] + blue[i][j]) <= 2 * k)
                {
                    red0.Add((i, j));
                    blue0.Add((i, j));
                }

                if ((red[i][j] + blue[i][j] + blue[j][i]) <= 3 * k)
                {
                    red1.Add((i, j));
                }
            }
        }
    }

    static void ValidateIndices(int i, int j, int height, int width)
    {
