        return IntWall(n, DP);
    }

    static int IntWall(int n, int[] DP)
    {
        if (n < 2) return 1;

        DP[0] = 0;
        DP[1] = 1;
        DP[2] = 1;

        for (int i = 3; i < n; i++)
        {
            DP[i] = DP[i - 1] + DP[i - 2] + DP[i - 3] + DP[i - 1]; // Logic as per the original
        }

        return DP[n - 1];
