class Program
{
    static async Task Main(string[] args)
    {
        int[] arr = { 4, 3, 1, 1, 3, 3, 2 };
        int k = 3;
        Console.WriteLine(await FindLeastNumOfUniqueInts(arr, k)); // Output: 2
    }

    static async Task<int> FindLeastNumOfUniqueInts(int[] arr, int k)
    {
        // Count the frequency of each number
        var count = arr.GroupBy(x => x)
                       .ToDictionary(g => g.Key, g => g.Count());

        // Use a min-heap (priority queue) to store the frequencies
        var heap = new SortedList<int, List<int>>();

        foreach (var kvp in count)
        {
            if (!heap.ContainsKey(kvp.Value))
            {
                heap[kvp.Value] = new List<int>();
            }
            heap[kvp.Value].Add(kvp.Key);
        }

        // Remove k elements from the heap
        while (heap.Count > 0 && k > 0)
        {
            var minFreq = heap.Keys[0];
            var numbersToRemove = heap[minFreq];

            if (k >= minFreq)
            {
                k -= minFreq;
                heap.Remove(minFreq);
            }
            else
            {
                break;
            }
        }

        // The number of unique integers left in the heap
        return heap.Sum(x => x.Value.Count);
    }
}

