int LowerBound(int n)
{
    int lowerBound = 0;
    int upperBound = n;
    int k = (lowerBound + upperBound) / 2;
    bool notFound = true;

    while (notFound)
    {
        long summ = k * (k + 1) / 2;

        if (summ < n)
        {
            lowerBound = k;
        }
        else if (summ > n)
        {
            upperBound = k;
        }
        else
        {
            return k;
        }

        if (upperBound - lowerBound <= 1)
        {
            return upperBound;
        }

        k = (lowerBound + upperBound) / 2;
    }

    return k + 1;
}

