public class TripletCounter
{
    public static int CountValidTriplets(List<int> nums1, List<int> nums2)
    {
        List<int> r1 = new List<int>();
        List<int> r2 = new List<int>();
        int cnt = 0;

        r1.Add(nums1[0]);
        for (int i = 1; i < nums1.Count; i++)
        {
            int r1i = r1.BinarySearch(nums1[i]);
            if (r1i < 0) r1i = ~r1i;

            if (r1i != 0)
            {
                r1.Insert(r1i, nums1[i]);
                if (r1[r1i - 1] * r1[r1i - 1] == nums2[i] * nums2[r1i - 1])
                {
                    cnt++;
                }
            }
            r2.Add(nums2[i]);
        }

        r2.Sort();
        for (int i = 0; i < r2.Count; i++)
        {
            cnt += r2.Count(x => x <= r1[i] * r1[i] / r2[i]);
        }

        return cnt;
    }

    public static async Task Main(string[] args)
    {
        // TODO: Benchmarking
        var nums1 = new List<int> { 1, 1 };
        var nums2 = new List<int> { 1, 1, 1 };

        // Debug print
        Console.WriteLine("Starting CountValidTriplets...");

        int result = await Task.Run(() => CountValidTriplets(nums1, nums2));

        Console.WriteLine($"Total valid triplets: {result}");
    }
}

