using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    private static List<int> CyclicShift(List<int> lst)
    {
        return new List<int> { lst.Last() }.Concat(lst.Take(lst.Count - 1)).ToList();
    }

    private static async Task<int> MinimumMovesAsync(int n, int m, int[,] matrix)
    {
        int initialShiftIndex = 0;

        for (int i = 0; i < n; i++)
        {
            for (int j = 0; j < m; j++)
            {
                if (matrix[i, j] != (i - 1) * m + j + 1)
                {
                    initialShiftIndex = (i - 1) * m + j;
                    break;
                }
            }

            if (initialShiftIndex != 0)
                break;
        }

        int shifts = 0;

        while (shifts < m)
        {
            for (int i = 0; i < n; i++)
            {
                for (int j = 0; j < m; j++)
                {
                    if (matrix[i, j] != (i - 1) * m + j + 1 + shifts * m)
                    {
                        matrix[i, j] = (i - 1) * m + j + 1 + shifts * m;
                    }
                }
            }

            var rows = new List<List<int>>();

            for (int j = 0; j < m; j++)
            {
                var row = new List<int>();
                for (int i = 0; i < n; i++)
                {
                    row.Add(matrix[i, j]);
                }

                rows.Add(CyclicShift(row));
            }

            for (int i = 0; i < n; i++)
            {
                for (int j = 0; j < m; j++)
                {
                    matrix[i, j] = rows[j][i];
                }
            }

            shifts++;
        }

        return shifts - 1;
    }

    static async Task Main(string[] args)
    {
        var inputs = Console.ReadLine().Split(' ').Select(int.Parse).ToArray();
        int n = inputs[0];
        int m = inputs[1];

        int[,] matrix = new int[n, m];

        for (int i = 0; i < n; i++)
        {
            var rowInputs = Console.ReadLine().Split(' ').Select(int.Parse).ToArray();
            for (int j = 0; j < m; j++)
            {
                matrix[i, j] = rowInputs[j];
            }
        }

        int result = await MinimumMovesAsync(n, m, matrix);
        Console.WriteLine(result);
    }
}

