        {
            ("hello", "hello"),
            ("hello", "helloo"),
            ("hello", "hlllloo"),
            ("codeforces", "codeforce"),
            ("polycarp", "poolycarpp"),
            ("aaaa", "aaaab"),
            ("zabcdefghijklmnopqrstuvwxyz", "zabcdefghijklmnopqrstuvwxyz"),
        };

        var results = await CheckKeyboardTypingAsync(pairs);
        Console.WriteLine(string.Join(Environment.NewLine, results));
    }

    static async Task<List<string>> CheckKeyboardTypingAsync(List<(string s, string t)> pairs)
    {
        var results = new List<string>();

        foreach (var (s, t) in pairs)
        {
            var sCounts = GetCharacterCounts(s);
            var tCounts = GetCharacterCounts(t);

            bool match = true;
            foreach (var kvp in tCounts)
            {
                char charT = kvp.Key;
                int countT = kvp.Value;

                if (!sCounts.TryGetValue(charT, out int countS) || countS < countT)
                {
                    match = false;
                    break;
                }
            }
            results.Add(match ? "YES" : "NO");
        }

        return await Task.FromResult(results);
    }

    static Dictionary<char, int> GetCharacterCounts(string str)
    {
        var counts = new Dictionary<char, int>();
        foreach (var c in str)
        {
            counts[c] = counts.GetValueOrDefault(c, 0) + 1;
        }
        return counts;
    }
}

