public class UnimodalChecker
{
    public static async Task<string> IsUnimodal(int[] array)
    {
        bool peakFound = false;
        int n = array.Length;

        if (n < 2)
            return "YES";

        // Find the peak
        for (int i = 1; i < n - 1; i++)
        {
            if (array[i - 1] < array[i] && array[i] > array[i + 1])
            {
                peakFound = true;
                break;
            }
        }

        if (!peakFound)
            return "YES";

        // Check conditions after the peak
        int index = Array.IndexOf(array, Math.Max(array[n - 1], array[n - 2])); // Peak position

        while (index + 1 < n)
        {
            if (array[index] > array[index + 1])
                return "YES";
            index++;
        }

        return "YES";
    }

