    static async Task<int> MaxValue(int n)
    {
        int[,] dp = new int[n, n];
        for (int i = 0; i < n; i++)
        {
            dp[i, 0] = 1;
        }
        for (int j = 0; j < n; j++)
        {
            dp[0, j] = 1;
