                dp[i, j] = Math.Min(dp[i, j], dp[i - 1, j] + 1);
                dp[i, j] = Math.Min(dp[i, j], dp[i, j - 1] + 1);
            }
        }

        // Benchmarking the maximum retrieval
        var maxVal = await Task.Run(() => dp.Cast<int>().Max());
        return maxVal;
    }
}

