public class TowerAnalyzer
{
    public int[] NearestSmallerTower(int[] arr)
    {
        int n = arr.Length;
        int[] result = new int[n];
        Array.Fill(result, -1);
        Stack<int> stack = new Stack<int>();

        // Find nearest smaller to the left
        for (int i = 0; i < n; i++)
        {
            while (stack.Count > 0 && arr[i] <= arr[stack.Peek()])
            {
                stack.Pop();
            }

            if (stack.Count > 0)
            {
                result[i] = stack.Peek();
            }

            stack.Push(i);
        }

        stack.Clear();

        // Find nearest smaller to the right
        for (int i = n - 1; i >= 0; i--)
        {
            while (stack.Count > 0 && arr[i] <= arr[stack.Peek()])
            {
                stack.Pop();
            }

            if (stack.Count > 0 && 
                (result[i] == -1 || arr[stack.Peek()] < arr[result[i]] || 
                (arr[stack.Peek()] == arr[result[i]] && stack.Peek() < result[i])))
            {
                result[i] = stack.Peek();
            }

            stack.Push(i);
        }

        return result;
    }
}

