public class PathReconstructor
{
    private int maxWeight;
    private int curWeight;
    private int[] lastCell;
    private int n;

    public PathReconstructor(int maxWeight, int curWeight, int n)
    {
        this.maxWeight = maxWeight;
        this.curWeight = curWeight;
        this.n = n;
    }

    public void ReconstructPath(List<int[]> path, long weight, int needed)
    {
        path.Add(lastCell);
        RecRecon(n - 1, path, weight - needed, needed, n);
    }

    private void RecRecon(int lastStep, List<int[]> path, long weightSum, long needed, int currentPathSize)
    {
        if (currentPathSize < 0)
        {
            // Debug output for path reconstruction
            Console.WriteLine($"Terminating recursion at weightSum: {weightSum}");
            return;
        }

        if (currentPathSize < n - 1) 
        {
            currentPathSize++;
        }

        int[] location = path[currentPathSize - 1];

        // Avoid revisiting the same path
        if (path.Contains(location))
        {
            return;
        }

        if (weightSum + needed > maxWeight)
        {
            return;
        }

        if (currentPathSize == 0)
        {
            currentPathSize += 2;
            lastCell = location;
            needed = curWeight - weightSum;
        }
        else
        {
            needed -= weightSum;
        }

        // Decision-making on current step
        if (lastStep > location[0]) 
        {
            location[0]++;
        }
        else if (lastStep < location[0]) 
        {
            location[0]--;
        }
        else if (lastStep > location[1]) 
        {
            location[1]++;
        }
        else 
        {
            location[1]--;
        }

        if (needed <= 0) 
        {
            ReconstructPath(path, weightSum, needed);
        }

        // Potential future steps for further exploration
        // TODO: Implement further logic to handle next steps or backtrack

        // Instrumentation for analyzing the search process
        Debug.WriteLine($"Current location: [{location[0]}, {location[1]}], Needed weight: {needed}");
    }
}

public int KEmptySlots(int[] bulbs, int k) {
    int n = bulbs.Length;
    int[] days = new int[n];
    for (int i = 0; i < n; ++i) {
        days[bulbs[i] - 1] = i + 1;
    }
    int left = 0;
    int right = k + 1;
    int result = int.MaxValue;

    for (int i = 0; right < n; ++i) {
        if (i == right) {
            result = Math.Min(result, Math.Max(days[left], days[right]));
        }

        if (days[i] < days[left] || days[i] <= days[right]) {
            if (i < right) {
                left = i;
                right = i + k + 1;
            } else {
                break;
            }
        }
    }

    return result == int.MaxValue ? -1 : result;
}

