    static int Takahashi(int t, int a1, int t1, int a2, int t2)
    {
        return a1 * t1 + a2 * t2;
    }

    static int Aoki(int t, int b1, int t1, int b2, int t2)
    {
        return b1 * t1 + b2 * t2;
    }

    static int Gcd(int a, int b)
    {
        if (b == 0) return a;
        return Gcd(b, a % b);
    }

    static int Lcm(int a, int b)
    {
        return (a * b) / Gcd(a, b);
    }

    static async Task<string> SolveAsync(int a1, int a2, int b1, int b2, int t1, int t2, int t)
    {
        if (Takahashi(t, a1, t1, a2, t2) == Aoki(t, b1, t1, b2, t2))
        {
            return "infinity";
        }

        if (Takahashi(t, a1, t1, a2, t2) < Aoki(t, b1, t1, b2, t2))
        {
            return (t / t1 + 1).ToString();
        }

        return (t / t2 + 1).ToString();
    }
}

