using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class DataProcessor
{
    public int RemoveDuplicate(int[] A, int N)
    {
        int i = 0;
        for (int j = 1; j < N; j++)
        {
            if (A[j] != A[i])
            {
                i++;
                A[i] = A[j];
            }
        }
        return i + 1;
    }

    public int[] CountSort(int[] arr)
    {
        int[] res = new int[arr.Length];
        foreach (var i in arr)
        {
            res[i]++;
        }
        return res;
    }

    public int[] Unique(int[] arr)
    {
        int[] temp = CountSort(arr);
        int j = 0;
        for (int i = 0; i < temp.Length; i++)
        {
            for (int _ = 0; _ < temp[i]; _++)
            {
                arr[j] = i;
                j++;
            }
        }
        return arr.Take(j).ToArray();
    }

    public int FindCount(int[] arr, int ele)
    {
        int left = 0, right = arr.Length - 1;
        if (ele <= arr[left] || ele >= arr[right])
        {
            return 0;
        }

        int ans = -1; // Adjusted for possible failure
        while (left <= right)
        {
            int mid = (left + right) / 2;
            if (arr[mid] == ele)
            {
                while (mid - 1 >= 0 && arr[mid - 1] == ele)
                {
                    mid--;
                }
                ans = mid;
                right = mid - 1;
            }
            else if (arr[mid] < ele)
            {
                left = mid + 1;
            }
            else
            {
                right = mid - 1;
            }
        }

        return ans;
    }

    public List<int[]> ThreeNumbers(int[] A)
    {
        Array.Sort(A);
        List<int[]> ans = new List<int[]>();

        for (int i = 0; i < A.Length - 2; i++)
        {
            int ele = A[i];
            if (ele <= 0) continue;
            int left = i + 1;
            int right = A.Length - 1;

            while (left < right)
            {
                int temp = A[left] + A[right];
                if (Math.Abs(temp) > Math.Abs(ele)) right--;
                else if (Math.Abs(temp) < Math.Abs(ele)) left++;
                else
                {
                    if (temp > ele) right--;
                    else if (temp < ele) left++;
                    else
                    {
                        while (left <= right && A[left] == A[left + 1]) left++;
                        ans.Add(new int[] { A[i], A[left], -ele });
                        break;
                    }
                }
            }
            while (left <= right && A[left] == A[left + 1]) left++;
        }

        return ans;
    }

    public async Task<int> MaximumNumberAsync(int N, int[] arr)
    {
        var A = new List<int>();
        for (int i = 0; i < arr.Length; i++)
        {
            A.Add(Math.Abs(arr[i]) % 4);
        }
        return await Task.FromResult(A.Max());
    }
}

