using System.Diagnostics;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        await BenchmarkAsync(() => ProcessQueries(new int[] { 3, 1, 2, 1 }, 5)); // [2,1,2,1]
        await BenchmarkAsync(() => ProcessQueries(new int[] { 4, 1, 2, 2 }, 4)); // [3,1,2,0]
        await BenchmarkAsync(() => ProcessQueries(new int[] { 7, 5, 5, 8, 3 }, 8)); // [6,5,0,7,5]
    }

    static async Task<List<int>> ProcessQueries(int[] queries, int m)
    {
        List<int> P = Enumerable.Range(1, m).ToList();
        List<int> result = new List<int>();

        foreach (var q in queries)
        {
            var index = P.IndexOf(q);
            result.Add(index);
            P.RemoveAt(index);
            P.Insert(0, q); // Move to front
        }
        return await Task.FromResult(result);
    }

    static async Task BenchmarkAsync(Func<Task> function)
    {
        Stopwatch stopwatch = Stopwatch.StartNew();
        await function();
        stopwatch.Stop();
        Console.WriteLine($"Elapsed time: {stopwatch.ElapsedMilliseconds} ms");
    }
}

using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    static async Task Main()
    {
        // Read input from standard input
        var input = await new StreamReader(Console.OpenStandardInput()).ReadToEndAsync();
        var lines = input.Split(new[] { '\n' }, StringSplitOptions.RemoveEmptyEntries);

        // Extract n and m
        var nm = lines[0].Split(' ').Select(int.Parse).ToArray();
        int n = nm[0], m = nm[1];

        // Extract x values
        var xValues = lines[1].Split(' ').Select(int.Parse).ToArray();

        // Calculate T(x) for each x in xValues
        var tValues = new List<int>(n);
        foreach (var x in xValues)
        {
            tValues.Add(CalculateT(x));
        }

        // Calculate cumulative sum y_i
        var cumulativeSums = new List<int>(n);
        int sum = 0;
        for (int i = 0; i < n; i++)
        {
            sum += tValues[i];
            cumulativeSums.Add(sum);
        }

        // Process each query
        for (int i = 2; i < lines.Length; i++)
        {
            if (int.TryParse(lines[i], out int q))
            {
                int result = GetResultForQuery(cumulativeSums, q);
                Console.WriteLine(result);
            }
        }
    }

    static int CalculateT(int x)
    {
        int count = 0;
        while (true)
        {
            count++;
            x = SumOfDigits(x);
            if (x < 10) break; // Exit if x becomes a single digit
        }
        return count;
    }

    static int SumOfDigits(int number)
    {
        int sum = 0;
        while (number > 0)
        {
            sum += number % 10;
            number /= 10;
        }
        return sum;
    }

    static int GetResultForQuery(List<int> cumulativeSums, int query)
    {
        // Binary search for the first index where cumulative sum >= query
        int low = 0, high = cumulativeSums.Count - 1;
        while (low <= high)
        {
            int mid = (low + high) / 2;
            if (cumulativeSums[mid] < query)
            {
                low = mid + 1;
            }
            else
            {
                high = mid - 1;
            }
        }

        // Return the result, adjusting for zero-based index
        return low + 1; // Turning the index into 1-based count
    }
}

