    static Task<List<string>> SolveAsync(List<(int n, int a, int b)> testCases)
    {
        return Task.Run(() =>
        {
            var results = new List<string>();
            foreach (var (n, a, b) in testCases)
            {
                var result = ConstructString(n, a, b);
                results.Add(result);
            }
            return results;
        });
    }

    static string ConstructString(int n, int a, int b)
    {
        // Create a sequence of the first b letters
        var sequence = Enumerable.Range(0, b)
                                 .Select(i => (char)('a' + i))
                                 .ToArray();

        // Repeat the sequence enough times to cover the length n
        var fullSequence = new StringBuilder(n);
        for (int i = 0; i < n; i++)
        {
            fullSequence.Append(sequence[i % b]);
        }

        // Return the constructed string
        return fullSequence.ToString();
    }
}

