        var inputs = Console.ReadLine().Split(' ').Select(int.Parse).ToArray();
        int k = inputs[0];
        int m = inputs[1];

        var lists = new List<List<int>>();

        for (int i = 0; i < k; i++)
        {
            var line = Console.ReadLine().Split(' ').Select(int.Parse).ToArray();
            int n = line[0]; // Read number, not used directly
            var lst = line.Skip(1).ToList();
            lists.Add(lst);
        }

        int result = await Task.Run(() => Solve(k, m, lists));
        Console.WriteLine(result);
    }

    static int Solve(int k, int m, List<List<int>> lists)
    {
        int maxS = 0;

        // Generate all combinations
        foreach (var elements in GetCombinations(lists))
        {
            int s = elements.Sum(x => x * x) % m;
            maxS = Math.Max(maxS, s);
        }

        return maxS;
    }

    static IEnumerable<List<int>> GetCombinations(List<List<int>> lists)
    {
        return lists.Aggregate(new List<List<int>> { new List<int>() }, (acc, list) =>
            acc.SelectMany(a => list.Select(item => { var newList = new List<int>(a) { item }; return newList; })).ToList()
        );
    }
}

