public class TreeNode {
    public int val;
    public TreeNode left;
    public TreeNode right;

    public TreeNode() {
        val = 0;
        left = null;
        right = null;
    }

    public TreeNode(int x) {
        val = x;
        left = null;
        right = null;
    }

    public TreeNode(int x, TreeNode left, TreeNode right) {
        val = x;
        this.left = left;
        this.right = right;
    }
}

public class Solution {
    public int CountPairs(TreeNode root, int distance) {
        var count = 0;
        var nodeDepths = new List<List<int>>();
        TraverseTree(root, nodeDepths);

        for (int i = 0; i < nodeDepths.Count; i++) {
            for (int j = i + 1; j < nodeDepths.Count; j++) {
                count += CountPairsWithDistance(nodeDepths[i], nodeDepths[j], distance);
            }
        }

        return count;
    }

    private void TraverseTree(TreeNode node, List<List<int>> nodeDepths, int depth = 0) {
        if (node == null) return;

        if (nodeDepths.Count <= depth) {
            nodeDepths.Add(new List<int>());
        }

        nodeDepths[depth].Add(node.val);
        TraverseTree(node.left, nodeDepths, depth + 1);
        TraverseTree(node.right, nodeDepths, depth + 1);
    }

    private int CountPairsWithDistance(List<int> leftDepths, List<int> rightDepths, int maxDistance) {
        int count = 0;
        foreach (int left in leftDepths) {
            foreach (int right in rightDepths) {
                if (Math.Abs(left - right) <= maxDistance) {
                    count++;
                }
            }
        }
        return count;
    }
}

