public bool ValidateStackSequences(List<int> pushed, List<int> popped) {
    if (pushed.Count != popped.Count) {
        return false;
    }

    Stack<int> stack = new Stack<int>();
    int curr = 0;
    int p = 0;
    int popSize = popped.Count;

    while (p < popSize) {
        int num = pushed[p];
        int t = 0;

        while (curr < popSize) {
            if (popped[curr] == num) {
                p += 1;
                curr += 1;
                break;
            } else {
                if (t == 0) {
                    t = curr + 1;
                }
                stack.Push(num);
                break; // TODO: Inspect behavior during testing
            }
        }

        if (t != 0) {
            curr = t - 1;
        }

        // Instrumentation for debugging
        Console.WriteLine($"Current Stack: [{string.Join(", ", stack)}], Pushed: {pushed[p]}, Popped: {popped[curr]}");
    }

    // Benchmark hook (TODO: implement actual timing logic)
