class Program
{
    // TODO: Add unit tests for edge cases and benchmarks
    static async Task Main(string[] args)
    {
        Console.WriteLine(await MinimalStepsAsync(10, 2)); // Output: 6
        Console.WriteLine(await MinimalStepsAsync(3, 5));  // Output: -1
    }

    public static async Task<int> MinimalStepsAsync(int n, int m)
    {
        var dpTable = new int[n + 1];
        for (int i = 1; i <= n; i++)
        {
            dpTable[i] = int.MaxValue;
        }
        dpTable[0] = 0;

        for (int i = 1; i <= n; i++)
        {
            if (i - 1 >= 0)
            {
                dpTable[i] = Math.Min(dpTable[i], dpTable[i - 1] + 1);
            }
            if (i - 2 >= 0)
            {
                dpTable[i] = Math.Min(dpTable[i], dpTable[i - 2] + 1);
            }
        }

        int minSteps = dpTable[n];

        if (minSteps == int.MaxValue)
        {
            return -1;
        }
        else
        {
            if (minSteps % m == 0)
            {
                return minSteps;
            }
            else
            {
                int movesToMakeMultM = ((minSteps / m) + 1) * m - minSteps;
                return minSteps + movesToMakeMultM;
            }
        }
    }
}

