using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

class DijkstraAlgorithm
{
    public static List<int> Dijkstra(int n, List<(int, int, int)> edges, int start)
    {
        var graph = new List<(int, int)>[n];
        for (int i = 0; i < n; i++)
            graph[i] = new List<(int, int)>();

        foreach (var (s, t, d) in edges)
            graph[s].Add((t, d));

        var dist = Enumerable.Repeat(int.MaxValue, n).ToArray();
        dist[start] = 0;
        var pq = new PriorityQueue<(int, int), int>();
        pq.Enqueue((0, start), 0);

        while (pq.Count > 0)
        {
            var (d, cur) = pq.Dequeue();
            if (d > dist[cur])
                continue;

            foreach (var (t, w) in graph[cur])
            {
                if (dist[cur] + w < dist[t])
                {
                    dist[t] = dist[cur] + w;
                    pq.Enqueue((dist[t], t), dist[t]);
                }
            }
        }

        return dist.ToList();
    }

    public static async Task Main(string[] args)
    {
        var input = Console.ReadLine().Split().Select(int.Parse).ToArray();
        int n = input[0], m = input[1], start = input[2];
        var edges = new List<(int, int, int)>();

        for (int i = 0; i < m; i++)
        {
            var edgeInput = Console.ReadLine().Split().Select(int.Parse).ToArray();
            edges.Add((edgeInput[0], edgeInput[1], edgeInput[2]));
        }

        var dist = Dijkstra(n, edges, start);

        foreach (var d in dist)
        {
            if (d == int.MaxValue)
                Console.WriteLine("INF");
            else
                Console.WriteLine(d);
        }
    }
}

