        var readline = input.Split();
        int H = int.Parse(readline[0]);
        int W = int.Parse(readline[1]);
        var G = new List<string>();

        for (int i = 0; i < H; i++)
        {
            G.Add(Console.ReadLine().Trim());
        }

        var queue = new Queue<(int, int)>();
        queue.Enqueue((1, 1));
        var visited = new HashSet<(int, int)>();
        visited.Add((1, 1));

        while (queue.Count > 0)
        {
            var (r, c) = queue.Dequeue();
            if (r == H && c == W)
            {
                break;
            }

            var directions = new[] { (-1, 0), (0, 1) };
            foreach (var (dr, dc) in directions)
            {
                int nr = r + dr;
                int nc = c + dc;

                if (1 <= nr && nr <= H && 1 <= nc && nc <= W && !visited.Contains((nr, nc)) && G[nr][nc] != '#' && G[nr][nc] != '.')
                {
                    visited.Add((nr, nc));
                    queue.Enqueue((nr, nc));
                }
            }
        }

        int k = 0;
        while (true)
        {
            var reversedVisited = visited.Select(x => (H - x.Item1, W - x.Item2)).ToHashSet();
            visited = new HashSet<(int, int)>(reversedVisited);
            if (visited.All(x => !reversedVisited.Contains(x)) && reversedVisited.All(x => !visited.Contains((H - x.Item1, W - x.Item2))))
            {
                break;
            }
            k++;
        }

        Console.WriteLine(k);
    }
}

