public class NumWaysCalculator
{
    private const int Mod = 998244353;

    public static long NumWays(int n, int k, List<(int, int)> intervals)
    {
        long[,] dp = new long[k + 1, n + 1];
        dp[0, 1] = 1;

        for (int i = 1; i <= k; i++)
        {
            for (int j = 1; j <= n; j++)
            {
                foreach (var (l, r) in intervals)
                {
                    if (l <= j && j <= r)
                    {
                        dp[i, j] += dp[i - 1, j - l];
                        dp[i, j] %= Mod;
                    }
                }
                // TODO: Add debug print for dp[i, j]
            }
        }
        return dp[k, n];
    }

    public static async Task Main(string[] args)
    {
