        {
            if (number % dividers == 0)
            {
                result.Add(dividers);
                number /= dividers;
                dividers = 2; // Reset dividers to start from the smallest
            }
            else
            {
                dividers++;
            }
        }

        if (number > 1) result.Add(number); // Include the last prime factor

        return result;
    }
