public class CleanRowsMaximizer
{
    public static int MaxCleanRows(int n, string[] grid)
    {
        // Dictionary to count occurrences of each row configuration
        var rowCount = new Dictionary<string, int>();

        // Count each row configuration
        foreach (var row in grid)
        {
            if (rowCount.ContainsKey(row))
            {
                rowCount[row]++;
            }
            else
            {
                rowCount[row] = 1;
            }
        }

        int maxClean = 0;

        // Try each row as a target configuration
        foreach (var target in rowCount.Keys)
        {
            int currentCount = 0;

            // Count how many rows can be transformed into this target
            foreach (var row in grid)
            {
                // Calculate the difference needed to transform `row` to `target`
                var diff = new bool[n];
                for (int i = 0; i < n; i++)
                {
                    diff[i] = target[i] != row[i];
                }

                // A row can be transformed to target if the pattern of differences
                // is constant across all columns
                if (diff.All(d => d) || !diff.Any())
                {
                    currentCount++;
                }
            }

            // Update the maximum number of clean rows
            maxClean = Math.Max(maxClean, currentCount);
        }

        return maxClean;
    }

    public static async Task Main(string[] args)
    {
        int n1 = 4;
        string[] grid1 = {
            "0101",
            "1000",
            "1111",
            "0101"
        };
        var result1 = MaxCleanRows(n1, grid1);
        Console.WriteLine(result1);  // Output: 2

        int n2 = 3;
        string[] grid2 = {
            "111",
            "111",
            "111"
        };
        var result2 = MaxCleanRows(n2, grid2);
        Console.WriteLine(result2);  // Output: 3 (expected)
    }
}

