        for (int i = 0; i < T; i++)
        {
            var parameters = Console.ReadLine().Split(' ').Select(int.Parse).ToArray();
            int n = parameters[0], x = parameters[1], k = parameters[2];

            var preferences = Console.ReadLine().Split(' ').Select(int.Parse).ToArray();

            // Finding positions of Alice (p_a) and Bob (p_b)
            int a = Array.IndexOf(preferences, preferences.Min());
            int b = Array.IndexOf(preferences, preferences.Max());

            // Ensure that a is always less than b for consistency
            if (a > b)
            {
                int temp = a;
                a = b;
                b = temp;
            }

            // Calculate the maximum distance considering constraints
            int maxDistance = CalculateMaxDisparity(n, x, k, a, b);
            Console.WriteLine(maxDistance);
        }
    }

    static int CalculateMaxDisparity(int n, int x, int k, int a, int b)
    {
        // Determine the limits for movement
        int leftMove = Math.Max(1, a - x);
        int rightMove = Math.Min(n, b + x);

        // Calculate possible positions for Alice and Bob
        int newAlicePosition = Math.Max(leftMove, b - k);
        int newBobPosition = Math.Min(rightMove, a + k);

        // Ensure Alice doesn't move beyond Bob's new limit
        return Math.Max(0, newBobPosition - newAlicePosition);
    }
}

