        Console.WriteLine(await MinMoves(3, 5));  // Expected Output: -1
    }

    static async Task<int> MinMoves(int n, int m)
    {
        var dp = new Dictionary<int, int> { { 0, 0 } };

        for (int i = 1; i <= n; i++)
        {
            var newDp = new Dictionary<int, int>();

            foreach (var kvp in dp)
            {
                int steps = kvp.Key;
                int moves = kvp.Value;

                if (steps + 1 <= i)
                {
                    if (!newDp.ContainsKey(steps + 1))
                        newDp[steps + 1] = moves + 1;
                    else
                        newDp[steps + 1] = Math.Min(newDp[steps + 1], moves + 1);
                }

                if (steps + 2 <= i)
                {
                    if (!newDp.ContainsKey(steps + 2))
                        newDp[steps + 2] = moves + 1;
                    else
                        newDp[steps + 2] = Math.Min(newDp[steps + 2], moves + 1);
                }
            }

            dp = newDp;
        }

        int result = dp.ContainsKey(n) ? dp[n] : int.MaxValue;
        return (result % m == 0) ? result : -1;
    }
}

