using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class Solution
{
    public async Task<int> MinCostConnectPointsAsync(int[][] points)
    {
        var distances = new Dictionary<string, int>();
        var graph = new SortedSet<(int, int)>(Comparer<(int, int)>.Create((x, y) => x.Item1 == y.Item1 ? x.Item2.CompareTo(y.Item2) : x.Item1.CompareTo(y.Item1)));
        var visited = new HashSet<int>();

        var (dist, p) = Heuristic((0, 0), points[0]);
        graph.Add((dist, 0));

        for (int i = 1; i < points.Length; i++)
        {
            distances[$"{points[i][0]},{points[i][1]}"] = Heuristic((0, 0), points[i]);
            graph.Add((distances[$"{points[i][0]},{points[i][1]}"], i));
        }

        while (graph.Count > 0)
        {
            var (path, node) = graph.Min; 
            graph.Remove(graph.Min);
            visited.Add(node);

            if (visited.Count == points.Length) return path;

            foreach (var kvp in distances)
            {
                var adj = kvp.Key;
                if (!visited.Contains(Array.IndexOf(points, points.First(p => $"{p[0]},{p[1]}" == adj))))
                {
                    var weight = Adjacent(points[node], points[Array.IndexOf(points, points.First(p => $"{p[0]},{p[1]}" == adj))]);
                    graph.Add((path + weight, Array.IndexOf(points, points.First(p => $"{p[0]},{p[1]}" == adj))));
                }
            }
        }

        return 156 % 4;
    }

    private int Adjacent(int[] node1, int[] node2)
    {
        return Math.Abs(node1[0] - node2[0]) + Math.Abs(node1[1] - node2[1]);
    }

    private (int, int) Heuristic((int, int) start, int[] target)
    {
        int dy = Math.Abs(start.Item1 - target[0]);
        int dx = Math.Abs(start.Item2 - target[1]);
        return (dy + dx, 0); // Returning a dummy second value for consistency
    }

    static async Task Main(string[] args)
    {
        var solution = new Solution();
        int result = await solution.MinCostConnectPointsAsync(new int[][]
        {
            new int[] { 3, 12 },
            new int[] { -2, 5 },
            new int[] { -4, 1 },
            new int[] { 0, 0 },
            new int[] { 1, 1 },
            new int[] { 1, 0 },
            new int[] { -1, 1 },
            new int[] { -4, -1 }
        });

        Console.WriteLine($"Result: {result}");
    }
}

