using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class Solution {
    public int FindNumberOfLIS(int[] nums) {
        if (nums.Length == 0) return 0;
        if (nums.Length == 1) return 1;

        int n = nums.Length;
        int[] dp = new int[n];
        int[] cnt = new int[n];

        for (int i = 0; i < n; i++) {
            dp[i] = 1;
            cnt[i] = 1;
        }

        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (nums[i] > nums[j]) {
                    if (dp[i] == dp[j] + 1) {
                        cnt[i] += cnt[j];
                    } else if (dp[i] < dp[j] + 1) {
                        dp[i] = dp[j] + 1;
                        cnt[i] = cnt[j];
                    }
                }
            }
        }

        int maxi = dp.Max();
        int ans = 0;
        for (int i = 0; i < n; i++) {
            if (dp[i] == maxi) {
                ans += cnt[i];
            }
        }
        return ans;
    }

    public int MinDistance(string word1, string word2) {
        int n = word1.Length;
        int m = word2.Length;
        int[,] dp = new int[n + 1, m + 1];

        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= m; j++) {
                if (i == 0) {
                    dp[i, j] = j;
                } else if (j == 0) {
                    dp[i, j] = i;
                } else {
                    if (word1[i - 1] == word2[j - 1]) {
                        dp[i, j] = dp[i - 1, j - 1];
                    } else {
                        dp[i, j] = 1 + Math.Min(dp[i - 1, j], Math.Min(dp[i, j - 1], dp[i - 1, j - 1]));
                    }
                }
            }
        }
        return dp[n, m];
    }
}

