using System.Threading.Tasks;

class Program
{
    static HashSet<int> F = new HashSet<int> { 1 };
    static bool[] vis;
    static HashSet<int>[] G;
    static Dictionary<int, int> W;
    static List<int>[] l;

    static void Main()
    {
        int n, w;
        var input = Console.ReadLine().Split(' ').Select(int.Parse).ToArray();
        n = input[0];
        w = input[1];

        G = new HashSet<int>[n + 1];
        vis = new bool[n + 1];
        l = new List<int>[n + 1];
        W = new Dictionary<int, int>();
        for (int i = 0; i <= n; i++)
            l[i] = new List<int>();

        for (int i = 0; i < w; i++)
        {
            var edge = Console.ReadLine().Split(' ').Select(int.Parse).ToArray();
            AddEdge(edge[0], edge[1]);
        }

        int MAX = 0, m = 0;

        for (int i = 2; i <= n; i++)
        {
            ResetSets(n);
            F.Clear();
            F.Add(1);
            F.Add(i);
            if (W.ContainsKey(i)) F.Add(W[i]);

            if (DFS(new HashSet<int> { 1, i, W[i] }) == 1)
            {
                Console.WriteLine(1);
                PrintSet(F[W[i]]);
                MAX = m = 1;
                break;
            }
            else if (F[W[i]].Count > m)
            {
                MAX = F[W[i]].Count;
                m = F[W[i]].Count;
            }
        }

        if (m == MAX)
        {
            Console.WriteLine(MAX);
            Console.WriteLine(string.Join(" ", F));
        }
        else
        {
            Console.WriteLine(-1);
        }

        Console.WriteLine(-1);
    }

    static void AddEdge(int U, int V)
    {
        if (G[U] == null) G[U] = new HashSet<int>();
        if (G[V] == null) G[V] = new HashSet<int>();
        G[U].Add(V);
        G[V].Add(U);

        if (!W.ContainsKey(U))
            W[U] = V;
        else if (!W.ContainsKey(V))
            W[V] = U;
        else
        {
            l[U].Add(V);
            foreach (var j in l[U])
                W[j] = V;
        }

        if (W.ContainsKey(V))
        {
            G[V].Add(W[V]);
            G[W[V]].Add(V);
        }
    }

    static void ResetSets(int n)
    {
        for (int j = 1; j <= n; j++)
            F.Add(j);
    }

    static int DFS(HashSet<int> C)
    {
        vis[1] = true;
        foreach (var node in C)
        {
            if (vis[node]) continue;
            if (G[1].Contains(node))
            {
                foreach (var son in G[node])
                {
                    if (!C.Contains(son))
                        return 1;
                }
                continue;
            }
            if (DFSRecursive(node, C, true) == 1)
                return 1;
        }
        return 0;
    }

    static int DFSRecursive(int node, HashSet<int> X, bool seayer)
    {
        if (!seayer && X.Contains(node)) return 0;
        if (X.Contains(node))
        {
            X.ExceptWith(F);
            if (G[node].Contains(node))
            {
                foreach (var son in G[node])
                {
                    if (DFSRecursive(son, X, false) == 1)
                        return 1;
                }
            }
            else
            {
                foreach (var son in G[node])
                {
                    if (!F.Contains(son) && DFSRecursive(node, X, true) == 1)
                        return 1;
                }
            }
            return 0;
        }
        X.Add(node);
        foreach (var son in G[node])
        {
            if (X.Contains(son))
            {
                if (DFSRecursive(son, X, seayer) == 1)
                    return 1;
            }
            else
            {
                if (DFSRecursive(son, X, true) == 1)
                    return 1;
            }
        }
        return 0;
    }

    static void PrintSet(IEnumerable<int> set)
    {
        Console.WriteLine("{" + string.Join(", ", set) + "}");
    }
}

