                maxIdx = i;
            }
            else if (a[i] < minVal)
            {
                minVal = a[i];
                minIdx = i;
            }
        }

        // Swap indices if necessary
        if (minIdx > maxIdx)
        {
            (minIdx, maxIdx) = (maxIdx, minIdx);
        }

        int cnt = 0;

