    {
        int n = int.Parse(Console.ReadLine());
        string s = Console.ReadLine();
        Console.WriteLine(Solve(n, s).Result);
    }

    static async Task<int> Solve(int n, string s)
    {
        var characterCounts = CountCharacters(s);
        int result = 1;

        foreach (var count in characterCounts.Values)
        {
            result *= (count + 1);
        }

        return await Task.FromResult(result - 1);
    }

    static Dictionary<char, int> CountCharacters(string s)
    {
        var counts = new Dictionary<char, int>();
        foreach (char c in s)
        {
            if (counts.ContainsKey(c))
            {
                counts[c]++;
            }
            else
            {
                counts[c] = 1;
            }
        }
        return counts;
    }
}

