    {
        static async Task Main(string[] args)
        {
            var testCases = new List<(int, int)>
            {
                (6, 13),
                (9, 11),
                (16, 24),
                (19, 25)
            };

            foreach (var (x, y) in testCases)
            {
                bool result = await CheckVampireAsync(x, y);
                Console.WriteLine($"vampire({x}, {y}) => {result}");
            }
        }

        private static Task<bool> CheckVampireAsync(int x, int y)
        {
            return Task.Run(() => IsVampire(x, y));
        }

        private static bool IsVampire(int x, int y)
        {
            if (x == 0 || y == 0) return false;
            if ((x % 10 == 0 && y % 10 == 0)) return false;

            int product = x * y;
            var digitsX = GetDigits(x).Concat(GetDigits(y)).ToList();
            var digitsProduct = GetDigits(product).ToList();

            // Debug info
            Console.WriteLine($"Checking: {x} * {y} = {product}");

            digitsX.Sort();
            digitsProduct.Sort();

            return digitsX.SequenceEqual(digitsProduct);
        }

        private static IEnumerable<int> GetDigits(int number)
        {
            while (number > 0)
            {
                yield return number % 10;
                number /= 10;
            }
        }
    }
}

