class Program
{
    // Function to generate the required string
    static string GenerateString(int n, int a, int b)
    {
        if (a == 1) 
            return new string('a', n);

        HashSet<char> distinctLetters = new HashSet<char>();
        for (int i = 0; i < b; i++)
        {
            distinctLetters.Add((char)('a' + i));
        }

        if (n % a == 0)
        {
            return new string(string.Join("", distinctLetters).ToCharArray(), 0, n / a * distinctLetters.Count);
        }
        else
        {
            int remainder = n % a;
            StringBuilder prefix = new StringBuilder();
            StringBuilder suffix = new StringBuilder();
            foreach (var letter in distinctLetters)
            {
                if (prefix.Length < remainder)
                    prefix.Append(letter);
                else if (suffix.Length < a - remainder)
                    suffix.Append(letter);
            }
            return prefix.ToString() + suffix.ToString();
        }
    }

    // Main function to handle multiple test cases
    static async Task Main(string[] args)
    {
        string input = await System.IO.File.ReadAllTextAsync("input.txt");
        string[] data = input.Split();

        int t = int.Parse(data[0]);
