            int a = int.Parse(data[index + 1]);
            int b = int.Parse(data[index + 2]);
            index += 3;

            // Generate result for each test case
            string result = GenerateString(n, a, b);
            results.Add(result);
        }

        // Output results
        foreach (var result in results)
        {
            Console.WriteLine(result);
        }
    }
}

