using System;
using System.Threading.Tasks;

class Program
{
    const int MOD = 998244353;
    const int MAXN = 200005;
    static long[] fac = new long[MAXN];
    static long[] rev = new long[MAXN];
    static long[] inv = new long[MAXN];

    static void Main()
    {
        Init();
        int t = 2;
        // TODO: Handle multiple test cases if necessary
        // E.g., while (t > 0) { ... }
    }

    static long Power(long a, long b)
    {
        long c = 1;
        while (b > 0)
        {
            if (b % 2 == 1)
                c = c * a % MOD;
            b /= 2;
            a = a * a % MOD;
        }
        return c;
    }

    static void Init()
    {
        fac[0] = 1;
        rev[0] = 1;
        for (int i = 1; i < MAXN; i++)
        {
            fac[i] = fac[i - 1] * i % MOD;
            rev[i] = Power(fac[i], MOD - 2);
        }
        long[] p2 = new long[MAXN];
        p2[0] = 1;
        for (int i = 1; i < MAXN; i++)
        {
            p2[i] = p2[i - 1] * 2 % MOD;
        }
    }

    static long C(int n, int m)
    {
        if (m < 0 || m > n)
            return 0;
        return fac[n] * rev[m] % MOD * rev[n - m] % MOD;
    }

    static long Solve(int n, long[] a)
    {
        long[] dp = new long[n + 1];
        long[] s = new long[n + 1];
        dp[1] = 1;
        s[1] = 1;

        long[] delta = new long[n + 1];
        for (int i = 2; i <= n; i++)
        {
            for (int j = 1; j < i; j++)
            {
                delta[j] = s[j] * C(i - 1, j - 1) % MOD;
            }
            s[i] = delta[1];
            for (int j = 2; j <= i; j++)
            {
                s[i] = (s[i] + delta[j]) % MOD;
            }
            dp[i] = (dp[i] + a[i] * s[i] % MOD) % MOD;
        }
        return dp[n];
    }
}

