    static async Task<string> CanMakeNonDecreasing(int n, int[] a)
    {
        int minVal = a.Min();

        // Collect elements that are divisible by minVal
        var divisibleElements = a.Where(x => x % minVal == 0).ToList();

        // Sort these divisible elements
        divisibleElements.Sort();

        // Create a new array following the rules
        int[] sortedA = new int[n];
        int divIndex = 0;

        for (int i = 0; i < n; i++)
        {
            if (a[i] % minVal == 0)
            {
                // Replace with the next sorted element from divisibleElements
                sortedA[i] = divisibleElements[divIndex];
                divIndex++;
            }
            else
            {
                // Keep the element as it is if not divisible by minVal
                sortedA[i] = a[i];
            }
        }

        // Validation: Check if the array is non-decreasing
        for (int i = 1; i < n; i++)
        {
            if (sortedA[i] < sortedA[i - 1])
            {
                return "NO";
            }
        }

        return "YES";
    }
