using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class TVSubscriptionSolver
{
    public async Task<List<int>> MinSubscriptionsAsync(int t, List<Tuple<Tuple<int, int, int>, List<int>>> testCases)
    {
        var results = new List<int>();

        foreach (var caseTuple in testCases)
        {
            var (config, schedule) = caseTuple;
            int n = config.Item1, k = config.Item2, d = config.Item3;

            // Initialize the set for the first window
            HashSet<int> currentWindow = new HashSet<int>(schedule.Take(d));
            int minSubscriptions = currentWindow.Count;

            // Slide the window across the schedule
            for (int i = 1; i <= n - d; i++)
            {
                // Remove the outgoing day's show and add the incoming day's show
                int outgoingShow = schedule[i - 1];
                int incomingShow = schedule[i + d - 1];

                // Update the set as necessary
                currentWindow.Remove(outgoingShow);
                currentWindow.Add(incomingShow);

                // Update the minimum subscriptions needed
                minSubscriptions = Math.Min(minSubscriptions, currentWindow.Count);
            }

            results.Add(minSubscriptions);
        }

        return await Task.FromResult(results);
    }
}

