    static long Pow(int baseNum, long exp, long mod)
    {
        long result = 1;
        baseNum %= (int)mod;

        while (exp > 0)
        {
            if ((exp & 1) == 1)
            {
                result = (result * baseNum) % mod;
            }
            baseNum = (baseNum * baseNum) % mod;
            exp >>= 1;
        }

        return result;
    }
}

