class Program
{
    const int MOD = 1000000007;

    static async Task Main(string[] args)
    {
        // TODO: Add input validation
        Console.Write("Enter N: ");
        int N = int.Parse(Console.ReadLine());

        Console.Write("Enter string s: ");
        string s = Console.ReadLine().Trim();

        int result = await CountWays(N, s);
        Console.WriteLine(result);
    }

    static async Task<int> CountWays(int N, string s)
    {
        int[,] dp = new int[N + 1, N + 1];
        dp[0, 0] = 1;

        for (int i = 1; i <= N; i++)
        {
            for (int j = 0; j <= i; j++)
            {
                dp[i, j] = dp[i - 1, j];  // Backspace
                if (j > 0 && s[j - 1] == '0')
                {
                    dp[i, j] = (dp[i, j] + dp[i - 1, j - 1]) % MOD;
                }
                if (j > 0 && s[j - 1] == '1')
                {
                    dp[i, j] = (dp[i, j] + dp[i - 1, j - 1]) % MOD;
                }
            }
            // Debug print for intermediate state
            Console.WriteLine($"After processing {i}: {string.Join(", ", dp[i, 0..(i + 1)])}");
        }

        return dp[N, s.Length];
    }
}

