using System;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    static int LongestCommonSubstring(string t, string s)
    {
        int m = t.Length;
        int n = s.Length;
        int[,] dp = new int[m + 1, n + 1];
        int result = 0;

        for (int i = 1; i <= m; i++)
        {
            for (int j = 1; j <= n; j++)
            {
                if (t[i - 1] == s[j - 1])
                {
                    dp[i, j] = dp[i - 1, j - 1] + 1;
                    result = Math.Max(result, dp[i, j]);
                }
            }
        }

        return result;
    }

    static async Task RunAsync()
    {
        Console.Write("Enter string t: ");
        string t = Console.ReadLine();
        Console.Write("Enter string s: ");
        string s = Console.ReadLine();

        int[,] dp = new int[t.Length + 1, s.Length + 1];
        int[,] flip = new int[s.Length + 1, t.Length + 1];
        int minCopies = int.MaxValue;
        int start = 0, end = 0;

        for (int i = 1; i <= t.Length; i++)
        {
            for (int j = 1; j <= s.Length; j++)
            {
                if (t[i - 1] == s[j - 1])
                {
                    dp[i, j] = dp[i - 1, j - 1] + 1;
                    flip[i, j] = flip[i - 1, j - 1] + 1;
                }
                else
                {
                    dp[i, j] = 0;
                    flip[i, j] = 0;
                }

                if (dp[i, j] < minCopies) continue;

                minCopies = dp[i, j];
                start = i - minCopies;
                end = j - minCopies;
            }
        }

        if (minCopies == 0)
        {
            Console.WriteLine(-1);
        }
        else
        {
            Console.WriteLine(minCopies);
            int iIdx = end, jIdx = start;
            for (int k = 0; k < minCopies; k++)
            {
                Console.WriteLine($"Index in t: {iIdx}, Index in s: {jIdx}");
                iIdx++;
                jIdx--;
            }
        }
    }

    static async Task Main(string[] args)
    {
        await RunAsync();
    }
}

