class StockMaxProfit
{
    public static int CalculateMaxProfit(List<int> prices)
    {
        int n = prices.Count;
        int profit = 0;
        Stack<int> stack = new Stack<int>();

        for (int i = 0; i < n; i++)
        {
            while (stack.Count > 0 && stack.Peek() < prices[i])
            {
                profit += prices[i] - stack.Pop();
            }
            stack.Push(prices[i]);
        }

        return profit;
    }

