            }
        }
    }

    static async Task MaxDemodogsAsync(int k)
    {
        long first = (k * (k + 1) % mod * (2 * k + 1) % mod) * Inverse(6) % mod;
        long second = first; // Reuse the first calculation
        long third = ((k * (k + 1) / 2) % mod * (k * (k + 1) / 2) % mod) % mod;

        long result = (2022 * (2 * first + second - third + mod) % mod) % mod;

        // Debug Print
        Console.WriteLine($"k: {k}, first: {first}, second: {second}, third: {third}, result: {result}");

        // Simulating some delay, e.g., in an I/O bound operation 
        await Task.Delay(10);
    }

    static long Inverse(long x)
    {
        // Fermat's Little Theorem for modulo inverse
        // mod is prime, so we can use pow(x, mod-2)
        long result = 1;
        long exp = mod - 2;
        while (exp > 0)
        {
            if ((exp & 1) == 1)
            {
                result = (result * x) % mod;
            }
            x = (x * x) % mod;
            exp >>= 1;
        }
        return result;
    }
}

