using System.Linq;
using System.Threading.Tasks;

public class Solution
{
    public List<int> SubsetSums(int[] arr, int N)
    {
        List<int> result = new List<int>();

        void Backtrack(int index, int currentSum)
        {
            if (index == N)
            {
                result.Add(currentSum);
                return;
            }
            Backtrack(index + 1, currentSum + arr[index]); // Include the current element
            Backtrack(index + 1, currentSum); // Exclude the current element
        }

        Backtrack(0, 0);
        return result.OrderBy(x => x).ToList();
    }

    // TODO: Benchmarking and debugging tools can be added here.
    public async Task BenchmarkSubsetSumsAsync(int[] arr, int N)
    {
        var start = DateTime.Now;
        var sums = SubsetSums(arr, N);
        var end = DateTime.Now;

        Console.WriteLine($"Execution Time: {end - start}");
        Console.WriteLine($"Unique Subset Sums Count: {sums.Count}");
        // Additional debug prints can be added here if necessary.
