    static List<string> FindPalindromes(string sentence)
    {
        List<string> words = new List<string>
        {
            sentence[0].ToString(),
            sentence[1].ToString(),
            sentence[0] + sentence[1].ToString()
        };
        for (int i = 2; i < sentence.Length - 2; i++)
        {
            words.Add(sentence.Substring(i, sentence.Length - 2 - i) + sentence[sentence.Length - 2] + sentence[i]);
        }
        return words;
