class RobotPathOptimizer
{
    public static async Task Main(string[] args)
    {
        var testCases = new List<string>
        {
            "URULLDD", // Testcase 1
            "RU",      // Testcase 2
            "UUUUDDL", // Testcase 3
            "LLUUUUD"  // Testcase 4
        };

        foreach (var path in testCases)
        {
            var finalPosition = await OptimizePath(path);
            Console.WriteLine($"Final position for path '{path}': ({finalPosition.X}, {finalPosition.Y})");
        }
    }

    private static async Task<Position> OptimizePath(string path)
    {
        var position = new Position(0, 0);
        var optimizedPath = RemoveUselessMoves(path);
        position = CalculateFinalPosition(optimizedPath);

        // TODO: Add more logic to handle different optimization cases.
        return await Task.FromResult(position);
    }

    private static string RemoveUselessMoves(string path)
    {
        Stack<char> moves = new Stack<char>();

        foreach (char move in path)
        {
            if (moves.Count > 0 && IsUselessMove(moves.Peek(), move))
                moves.Pop();
            else
                moves.Push(move);
        }

        char[] result = moves.ToArray();
        Array.Reverse(result);
        return new string(result);
    }

    private static bool IsUselessMove(char lastMove, char currentMove)
    {
        return (lastMove == 'U' && currentMove == 'D') || 
               (lastMove == 'D' && currentMove == 'U') ||
               (lastMove == 'R' && currentMove == 'L') ||
               (lastMove == 'L' && currentMove == 'R');
    }

    private static Position CalculateFinalPosition(string path)
    {
        int x = 0, y = 0;
        foreach (char move in path)
        {
            switch (move)
            {
                case 'U': y++; break;
                case 'D': y--; break;
                case 'L': x--; break;
                case 'R': x++; break;
                default: throw new ArgumentException("Invalid move");
            }
        }
        return new Position(x, y);
    }

    private struct Position
    {
        public int X { get; }
        public int Y { get; }

        public Position(int x, int y)
        {
            X = x;
            Y = y;
        }
    }
}

