    static async Task<int?> Solve(int n, int[] a, int[] b, int m)
    {
        var modCounts = a.GroupBy(x => x)
                         .Select(group => new
                         {
                             Value = group.Key,
                             CountA = group.Count(),
                             CountB = b.Count(x => x == group.Key)
                         })
                         .OrderBy(x => x.CountA - x.CountB)
                         .ThenByDescending(x => x.CountA)
                         .ThenByDescending(x => x.CountB)
                         .ToList();

        var common = a.Where((x, i) => b[i] == x).DefaultIfEmpty().Min();
        var commonMod = common % m;
        modCounts.FirstOrDefault(x => x.Value == common)?.CountA--;

        if (modCounts.FirstOrDefault(x => x.Value == common)?.CountA < 0)
        {
            modCounts.Remove(modCounts.FirstOrDefault(x => x.Value == common));
        }

        foreach (var x in modCounts.OrderByDescending(x => x.Value).Select(x => x.Value))
        {
            if (modCounts.FirstOrDefault(y => y.Value == x).CountA > 0 && 
                (modCounts.Any(y => (m - (x % m)) % m == y.Value) || 
                 modCounts.Any(y => (x - (x % m)) % m == y.Value)))
            {
                return (m - (x % m)) % m == modCounts.FirstOrDefault(y => (m - (x % m)) % m == y.Value).Value ? 
                       x % m : x - (x % m);
            }
        }
        return null;
    }

