using System;

public class Solution
{
    public int MinPoints(int M, int N, int[,] arr)
    {
        // TODO: Implement validation for M, N and arr dimensions

        var currentPoints = new int[M, N]; // Create array to store the current number of points 
        var pointsNeeded = new int[M, N]; // Create array to store the points needed to reach current cell 

        // Check the first cell
        if (arr[0, 0] <= 0) 
            return -1;

        currentPoints[0, 0] = arr[0, 0];
        pointsNeeded[0, 0] = 0;

        // Validate second cell in row
        if (N > 1 && arr[0, 1] <= 0) 
            return -1;

        // Initialize the first row
        for (int i = 0; i < Math.Min(M, N); i++) 
        {
            currentPoints[0, i] = arr[0, i];
        }

        // Validate second cell in column
        if (M > 1 && arr[1, 0] <= 0) 
            return -1;

        // Initialize the first column
        for (int i = 0; i < Math.Min(M, N); i++) 
        {
            currentPoints[i, 0] = arr[i, 0];
        }

        if (M < N) 
        {
            for (int i = 1; i < M; i++) 
            {
                for (int j = 1; j < N; j++) 
                {
                    if (arr[i, j] <= 0) 
                        continue;

                    if (currentPoints[i - 1, j] >= 0) 
                        pointsNeeded[i, j] = Math.Max(pointsNeeded[i, j], pointsNeeded[i - 1, j]);

                    if (currentPoints[i, j - 1] >= 0) 
                        pointsNeeded[i, j] = Math.Max(pointsNeeded[i, j], pointsNeeded[i, j - 1]);

                    if (currentPoints[i - 1, j] > 0 && currentPoints[i, j - 1] > 0) 
                    {
                        currentPoints[i, j] = Math.Min(currentPoints[i - 1, j], currentPoints[i, j - 1]);
                    }

                    if (currentPoints[i, j] > 0) 
                    {
                        currentPoints[i, j] += arr[i, j];
                    }

                    if (currentPoints[i, j] > 0 && pointsNeeded[i, j] == 0) 
                    {
                        pointsNeeded[i, j] = 1;
                    }
                }
            }
        }

        return pointsNeeded[M - 1, N - 1];
    }
}

