public class LongestSegment
{
    private int maxLength = 0;
    private int start = 0;
    private int end = 0;

    public void LongestSegmentMain(int n, int k, List<int> colors)
    {
        var dp = new int[n];
        for (int i = 0; i < n; i++)
        {
            dp[i] = 1;
        }

        for (int i = 1; i < n; i++)
        {
            if (colors[i] != colors[i - 1])
            {
                dp[i] = dp[i - 1] + 1;
                if (dp[i] > maxLength)
                {
                    maxLength = dp[i];
                    end = i;
                }
            }
        }

        FindMaxSegment(colors);
    }

    private void FindMaxSegment(List<int> colors)
    {
        for (int i = end - maxLength + 1; i >= 0; i--)
        {
            var segmentColors = colors.Skip(i).Take(maxLength).ToList();
            int distinctColors = segmentColors.Distinct().Count();
            if (distinctColors == maxLength)
            {
                start = i;
                PrintMaxSegment(colors);
            }
        }
    }

    public override string ToString()
    {
        if (maxLength != 0)
        {
            return $"The longest segment of houses has a length of {maxLength}, starting at house {start + 1} and ending at house {start + maxLength}";
        }
        return "No segment was found that meets the criteria.";
    }

    private void PrintMaxSegment(List<int> colors)
    {
        var segmentColors = colors.Skip(start).Take(maxLength).ToList();
        Console.WriteLine(string.Join(" ", segmentColors));
    }
}

