using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public class RLEProcessor
{
    public static async Task<string> EdgeDetectionAsync(string rle)
    {
        var (width, pixels) = DecodeRle(rle);
        int height = pixels.Count / width;

        List<int> edgePixels = new List<int>();

        for (int y = 0; y < height; y++)
        {
            for (int x = 0; x < width; x++)
            {
                int val = pixels[y * width + x];
                List<int> neighbors = new List<int>();

                for (int dy = -1; dy <= 1; dy++)
                {
                    for (int dx = -1; dx <= 1; dx++)
                    {
                        if (dx == 0 && dy == 0) continue;

                        int nx = x + dx, ny = y + dy;
                        if (nx >= 0 && nx < width && ny >= 0 && ny < height)
                        {
                            neighbors.Add(pixels[ny * width + nx]);
                        }
                    }
                }

                int edgeValue = neighbors.Any() ? neighbors.Max(n => Math.Abs(val - n)) : 0;
                edgePixels.Add(edgeValue);
            }
        }

        return await Task.FromResult(EncodeRle(edgePixels, width));
    }

    private static (int width, List<int> pixels) DecodeRle(string rle)
    {
        List<int> pixels = new List<int>();
        var values = rle.Split().Select(int.Parse).ToList();
        int width = values[0];

        for (int i = 1; i < values.Count; i += 2)
        {
            pixels.AddRange(Enumerable.Repeat(values[i], values[i + 1]));
        }

        return (width, pixels);
    }

    private static string EncodeRle(List<int> edgePixels, int width)
    {
        List<int> rle = new List<int> { width };
        int count = 1;

        for (int i = 1; i < edgePixels.Count; i++)
        {
            if (edgePixels[i] == edgePixels[i - 1])
            {
                count++;
            }
            else
            {
                rle.Add(edgePixels[i - 1]);
                rle.Add(count);
                count = 1;
            }
        }

        rle.Add(edgePixels.Last());
        rle.Add(count);

        return string.Join(" ", rle);
    }
}

