} Pair;

void push(Pair* heap, int* size, Pair element) {
    heap[*size] = element;
    (*size)++;
    // Heapify up (not implemented to keep short)
}

Pair pop(Pair* heap, int* size) {
    Pair top = heap[0];
    heap[0] = heap[--(*size)];
    // Heapify down (not implemented to keep short)
