int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m, k;
        scanf("%d %d %d", &n, &m, &k);
        int c[n][2], t[n], w[m + 1], fl[m + 1];
        Pair qe[n];

        for (int i = 0; i < n; i++) {
            scanf("%d %d", &c[i][0], &c[i][1]);
            t[i] = c[i][1];
        }

        int size = 0;
        push(qe, &size, (Pair){t[0], (c[0][1], 0)});

        for (int i = 1; i < n; i++) {
            Pair last = qe[size - 1];
            push(qe, &size, (Pair){c[i][0], (c[i][1] + last.first, last.second + 1)});
        }

        fl[0] = 0;
        for (int i = 0; i <= m; i++) {
            int uk = qe[0].second.first;
            int vk = qe[size - 1].second.first;

            if (uk <= t[i] + k) {
                int uqk = uk - t[i];
                int vu = uqk * w[i];
                if (vu > fl[size]) {
                    fl[size++] = vu;
                }
            } else {
                Pair popped = pop(qe, &size);
                int uqs = popped.second.first - t[i] - k;
                int vu = (vk == 0) ? 0 : uqs * w[i];
                if (vu > fl[size]) {
                    fl[size++] = vu;
                }
            }
            uqk -= w[i];
            if (uqk > fl[size]) {
                fl[size++] = uqk;
            }
        }
        int sumFl = 0;
        for (int i = 0; i < size; i++) {
            sumFl += fl[i];
        }
        printf("%d\n", sumFl);
    }
