}

#include <stdio.h>
#include <stdlib.h>

int* int_to_bits(int n, int* size) {
    int* bits = (int*)malloc(64 * sizeof(int));
    *size = 0;
    for (int i = 0; i < 64; i++) {
        if (n & (1 << i)) {
            bits[(*size)++] = i;
        }
    }
    return bits;
}

int findConnectedComponents(int* d, int n) {
    int total = 0;
    for (int mask = 0; mask < (1 << n); mask++) {
        int edges = 0;
        int* bits = (int*)malloc(64 * sizeof(int));
        int bitCount = 0;

        for (int i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                int size;
                int* tempBits = int_to_bits(d[i], &size);
                for (int j = 0; j < size; j++) {
                    bits[bitCount++] = tempBits[j];
                }
                free(tempBits);
            }
        }

        for (int i = 0; i < bitCount; i++) {
            for (int j = 0; j < bitCount; j++) {
                if (i != j) {
                    for (int k = 0; k < n; k++) {
                        if (mask & (1 << k) && (d[k] & (1 << bits[i])) && (d[k] & (1 << bits[j]))) {
                            edges++;
                            break;
                        }
                    }
                }
            }
        }

        total += 64 - bitCount + 1;
        if (edges > 0) {
            total--;
        }

        free(bits);
    }
    return total;
}

