#define MAX_VERTICES 1000

typedef struct {
    int vertex;
    int weight;
} Edge;

typedef struct {
    Edge* edges[MAX_VERTICES];
    int edge_count[MAX_VERTICES];
} UndirectedGraph;

void init_graph(UndirectedGraph* graph, int num_vertices) {
    for (int i = 1; i <= num_vertices; i++) {
        graph->edge_count[i] = 0;
    }
}

void add_edge(UndirectedGraph* graph, int start, int end, int weight) {
    graph->edges[start][graph->edge_count[start]].vertex = end;
    graph->edges[start][graph->edge_count[start]].weight = weight;
    graph->edge_count[start]++;

    graph->edges[end][graph->edge_count[end]].vertex = start;
    graph->edges[end][graph->edge_count[end]].weight = weight;
    graph->edge_count[end]++;
}

int bfs(UndirectedGraph* graph, int vertex, bool* visited, int max_sum) {
    int queue[MAX_VERTICES], front = -1, rear = -1;
    queue[++rear] = vertex;
    visited[vertex] = true;

    int path_weight = 0, log_power = 0;

    while (front != rear) {
        vertex = queue[++front];

        for (int i = 0; i < graph->edge_count[vertex]; i++) {
            Edge child = graph->edges[vertex][i];
            if (!visited[child.vertex]) {
                visited[child.vertex] = true;
                queue[++rear] = child.vertex;

                path_weight += child.weight;
                log_power = 0;

                while ((path_weight & 1) == 0 && (path_weight > max_sum)) {
                    path_weight >>= 1;
                    log_power++;
                }

                if (path_weight <= max_sum) {
                    return log_power;
                }
            }
        }
    }
    fprintf(stderr, "Incorrect graph for this problem\n");
    exit(EXIT_FAILURE);
}

int solve(int num_vertices, int max_sum, UndirectedGraph* graph) {
    bool visited[MAX_VERTICES] = {false};

    return bfs(graph, 1, visited, max_sum);
}

