#define MOD 1000000007

long long num_strings(const char *s) {
    int n = strlen(s);
    long long dp[n + 1];
    memset(dp, 0, sizeof(dp));
    dp[0] = 1;

    for (int i = 1; i <= n; i++) {
        if (s[i - 1] != 'u' && s[i - 1] != 'n') {
            dp[i] = dp[i - 1];
        } else if (s[i - 1] == 'u') {
            dp[i] = (i == 1 || s[i - 2] != 'u') ? dp[i - 1] : dp[i - 2];
        } else if (s[i - 1] == 'n') {
            dp[i] = (i == 1 || s[i - 2] != 'n') ? 2 * dp[i - 1] : 2 * dp[i - 2];
        }
        dp[i] %= MOD;
    }

    return dp[n];
}

