    DSU* dsu = create_dsu(max_val + 1);

    for (int i = 0; i < count; i++) {
        union_sets(dsu, pairs[i][0], pairs[i][1]);
    }

    int unique_roots = 0;
    int* roots = (int*)calloc(dsu->size, sizeof(int));

    for (int i = 0; i < count; i++) {
        int root = find(dsu, pairs[i][0]);
        if (!roots[root]) {
            unique_roots++;
            roots[root] = 1;
        }
    }

    free(roots);
    free(dsu->p);
    free(dsu);
    return unique_roots == count;
}

