int cmp(const void *a, const void *b) {
    return (*(int *)a - *(int *)b);
}

int main() {
    int n;
    scanf("%d", &n);
    int *A = (int *)malloc(n * sizeof(int));

    for (int i = 0; i < n; i++) {
        scanf("%d", &A[i]);
    }

    qsort(A, n, sizeof(int), cmp);
    int k = (int)(sqrt(n)) + 1;

    long long S = 0;
    long long T = 0;

    for (int x = 0; x < n; x += k) {
        int y = (x + k < n) ? x + k : n;
        for (int i = 0; i < y - x; i++) {
            S += (A[x + i]);
        }

        for (int i = -k; i < k; i++) {
            if (x + i >= 0 && x + i < y) {
                T += (x + i) * (x + i);
            }
        }
    }

    printf("%d %lld\n", k, S);
    printf("%lld\n", T);

    free(A);
    return 0;
}

