typedef struct {
    char suit;
    int value;
} Card;

void bubble_sort(Card cards[], int n) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (cards[j].value < cards[j + 1].value) {
                Card temp = cards[j];
                cards[j] = cards[j + 1];
                cards[j + 1] = temp;
            }
        }
    }
}

int is_stable(Card cards[], int n) {
    int last_occurrence[10] = {0};
    for (int i = 0; i < n; i++) {
        if (last_occurrence[cards[i].value] > 0 && last_occurrence[cards[i].value] > i) {
            return 0;
        }
        last_occurrence[cards[i].value] = i + 1;
    }
    return 1;
}

