bool isPrime(int num) {
    if (num <= 1) return false;
    if (num == 2) return true;
    if (num % 2 == 0) return false;
    for (int i = 3; i * i <= num; i += 2) {
        if (num % i == 0) return false;
    }
    return true;
}

bool primeIncrease(int* nums, int size) {
    if (size == 1) return 1;
    if (nums[0] == 2) return 0;
    if (nums[0] >= nums[1]) return 0;

    int* primes = (int*)malloc(size * sizeof(int));
    int count = 0;
    for (int i = 2; count < size; i++) {
        if (isPrime(i)) {
            primes[count++] = i;
        }
    }

    for (int i = 0; i < size - 1; i++) {
        if (nums[i] <= nums[i + 1] || primes[i] >= nums[i + 1] || nums[i] >= nums[i - 1] || primes[i - 1] >= nums[i]) {
            free(primes);
            return 0;
        }
        primes[i] = (i == 0) ? 2 : (primes[i - 1] < nums[i - 1] + 1 ? primes[i - 1] : nums[i - 1] + 1);
    }
    free(primes);
    return 1;
}

