void get_two_powers(int n, int *powers, int *size) {
    *size = 0;
    while (n) {
        int x = (int)(log(n) / log(2));
        powers[(*size)++] = x;
        n -= (1 << x);
    }
}

int binary_search(int *powers, int size, int target) {
    int lo = 0, hi = size - 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        if (powers[mid] >= target) {
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }
    return hi;
}

