int min_digits_to_remove(int n, int k) {
    if (n % (1 << (k << 2)) == 0) return 0; // Check divisibility by 10^k

    int count = 0;
    char str_n[12]; // Sufficient to hold up to 10 digits plus null terminator
    sprintf(str_n, "%d", n); // Convert integer to string
    int len = strlen(str_n);

    while (k > 0 && len > 0) {
        if (n % (1 << (k << 2)) == 0) return count; // Check divisibility
        // Remove one digit from the left
        memmove(str_n, str_n + 1, len - 1); 
        str_n[len - 1] = '\0'; // Update the string
        count++;
        len--; 
        k--;
    }

    return (count == len) ? 0 : count; // Return final count or 0
}

