#include <string.h>

char* minInteger(char* num, int k) {
    int length = strlen(num);
    char* result = malloc(length + 1);
    char* temp = malloc(length + 1);
    strcpy(temp, num);

    // Sort the characters in num
    for (int i = 0; i < length - 1; i++) {
        for (int j = i + 1; j < length; j++) {
            if (temp[i] > temp[j]) {
                char swap = temp[i];
                temp[i] = temp[j];
                temp[j] = swap;
            }
        }
    }

    int count = 0;
    for (int i = length - 1; i >= 0; i--) {
        char current = num[i];
        int pos = i;

        for (int j = i - 1; j >= 0; j--) {
            if (temp[j] < current) {
                pos = j;
                break;
            }
        }
        if (i - pos <= k) {
            char swap = num[pos];
            num[pos] = num[i];
            num[i] = swap;
            k -= (i - pos);
            count += (i - pos);
        }
    }

    strcpy(result, num);
    free(temp);
    return result;
}

