typedef struct TrieNode {
    struct TrieNode *children[26];
    bool isEndOfWord;
} TrieNode;

typedef struct StreamChecker {
    TrieNode *trie;
    TrieNode **pointers;
    int size;
} StreamChecker;

TrieNode* createNode() {
    TrieNode *node = (TrieNode*)malloc(sizeof(TrieNode));
    for (int i = 0; i < 26; i++) {
        node->children[i] = NULL;
    }
    node->isEndOfWord = false;
    return node;
}

StreamChecker* streamCheckerCreate(char **words, int wordsSize) {
    StreamChecker *sc = (StreamChecker*)malloc(sizeof(StreamChecker));
    sc->trie = createNode();
    sc->pointers = (TrieNode**)malloc(sizeof(TrieNode*) * wordsSize);
    sc->size = 0;

    for (int i = 0; i < wordsSize; i++) {
        TrieNode *node = sc->trie;
        for (int j = 0; words[i][j] != '\0'; j++) {
            int index = words[i][j] - 'a';
            if (!node->children[index]) {
                node->children[index] = createNode();
            }
            node = node->children[index];
        }
        node->isEndOfWord = true;
    }

    return sc;
}

bool streamCheckerQuery(StreamChecker *sc, char letter) {
    TrieNode **newPointers = (TrieNode**)malloc(sizeof(TrieNode*) * (sc->size + 1));
    int newSize = 0;
    bool found = false;

    for (int i = 0; i < sc->size; i++) {
        if (sc->pointers[i]->children[letter - 'a']) {
            newPointers[newSize++] = sc->pointers[i]->children[letter - 'a'];
            if (sc->pointers[i]->children[letter - 'a']->isEndOfWord) {
                found = true;
            }
        }
    }

    if (sc->trie->children[letter - 'a']) {
        newPointers[newSize++] = sc->trie->children[letter - 'a'];
        if (sc->trie->children[letter - 'a']->isEndOfWord) {
            found = true;
        }
    }

    free(sc->pointers);
    sc->pointers = newPointers;
    sc->size = newSize;

    return found;
}

void streamCheckerFree(StreamChecker *sc) {
    free(sc->pointers);
    // Trie cleanup omitted for brevity, consider adding freeTrie() function
    free(sc);
}

