void to_string(int binary_str, char *result) {
    char buffer[12]; 
    int index = 0;
    if (binary_str == 0) {
        result[index++] = '0';
    } else {
        while (binary_str > 0) {
            buffer[index++] = (binary_str % 10) + '0';
            binary_str /= 10;
        }
        for (int i = index - 1; i >= 0; i--) {
            result[strlen(result)] = buffer[i];
        }
    }
    result[index] = '\0';
}

