void solve(int s, int n, int dp[], int dp_sum[], int x[], int y[]) {
    sort(y, n);
    memset(dp_sum, 0, n * sizeof(int));
    for (int i = 0; i < n; ++i) {
        dp_sum[i] = (i == 0) ? y[i] : (y[i] + dp_sum[i - 1] < s ? y[i] + dp_sum[i - 1] : s);
    }
    int last = dp_sum[n - 1] + (x[n - 1] < s);
    if (last >= s) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }
}

