int minMaxGame(int* nums, int numsSize) {
    if (numsSize == 0) return 0;
    if (numsSize == 1) return nums[0];

    int *temp = (int*)malloc(numsSize / 2 * sizeof(int));

    while (numsSize > 1) {
        for (int i = 0; i < numsSize / 2; i++) {
            if (i % 2 == 0)
                temp[i] = nums[2 * i] < nums[2 * i + 1] ? nums[2 * i] : nums[2 * i + 1];
            else
                temp[i] = nums[2 * i] > nums[2 * i + 1] ? nums[2 * i] : nums[2 * i + 1];
        }
        numsSize /= 2;
        memcpy(nums, temp, numsSize * sizeof(int));
    }

    free(temp);
    return nums[0];
}

int maxNonOverlapping(int** events, int eventsSize) {
    int maxValue = 0;
    for (int i = 0; i < eventsSize; i++) {
        for (int j = i + 1; j < eventsSize; j++) {
            if (events[i][1] < events[j][0] || events[j][1] < events[i][0]) {
                int sum = events[i][2] + events[j][2];
                if (sum > maxValue) {
                    maxValue = sum;
                }
            }
        }
    }
    return maxValue;
}

