int polywordmatch(char *p, char *h) {
    int len_p = strlen(p), len_h = strlen(h);
    if (len_p != len_h) return 0;

    char *temp = malloc(len_p + 1);
    for (int i = 0; i < len_p; i++) {
        strncpy(temp, p + i, len_p - i);
        strncpy(temp + len_p - i, p, i);
        temp[len_p] = '\0';

