int count_criminals_caught(int n, int a, int t[]) {
    a -= 1;  // Convert to 0-based index
    int caught = 0;

    // Check Limak's city for criminals
    if (t[a] == 1) {
        caught += 1;
    }

    // Check distances from Limak's city
    for (int distance = 1; distance < n; distance++) {
        int left_city = a - distance;
        int right_city = a + distance;
        int count = 0;

        if (left_city >= 0 && t[left_city] == 1) {
            count++;
        }
        if (right_city < n && t[right_city] == 1) {
            count++;
        }

        // If count equals the number of cities at this distance
        if (count == 1) {
            caught += count;  // Exactly one criminal can be caught
        } else if (count == 2) {
            caught += 2;  // Two criminals, one from each city
        }
    }

    return caught;
}

