void find_operations(const char *s, int *min_removal, int *operation_count) {
    int stack[100];
    int top = -1;
    *min_removal = INT_MAX;

    for (int i = 0; s[i] != '\0'; i++) {
        if (s[i] == '(') {
            stack[++top] = i;
        } else {
            if (top != -1) {
                top--;
                *min_removal = *min_removal < top ? *min_removal : top;
            } else {
                stack[++top] = i;
            }
        }
    }
    *operation_count = top + 1;
}

