#include <stdio.h>
#include <math.h>

long long ok(int p, long long L) {
    long long F = 0;
    int k = 0, m = 2;

    while (m * p <= L) {
        k++;
        m *= p;
    }
    m /= p;
    int kk = k;

    while (kk > 0) {
        k -= kk;
        kk /= 2;
        F += ((kk + 1) * k) * (kk + 1);
    }
    F += (k + 1) * kk * (kk + 1);
    F += (k + 1) * (kk + 1);
    F -= kk * (kk + 1) * (2 * kk + 1);
    F /= 2;

    return F;
}

int main() {
    int T;
    scanf("%d", &T);

    while (T-- > 0) {
        long long L;
        scanf("%lld", &L);

        int p = 2;
        while (p * p <= L && p <= 5000) {
            if (ok(p, L) == L) break;
            p++;
        }

        if (p * p > L) {
            printf("%lld\n", L);
            continue;
        }

        long long G = ok(p, L);
        int T = 2;

        while (T <= (int)sqrt(p)) {
            if (p % T == 0) {
                G *= (ok(T, L) / T + 1);
            }
            T++;
        }
        printf("%lld\n", G);
    }

    return 0;
}

