void convert_case(char *word, char *result) {
    int uppercase_count = 0, lowercase_count = 0;
    int length = strlen(word);

    for (int i = 0; i < length; i++) {
        if (isupper(word[i])) {
            uppercase_count++;
        } else if (islower(word[i])) {
            lowercase_count++;
        }
    }

    if (uppercase_count > lowercase_count) {
        for (int i = 0; i < length; i++) {
            result[i] = toupper(word[i]);
        }
    } else {
        for (int i = 0; i < length; i++) {
            result[i] = tolower(word[i]);
        }
    }
    result[length] = '\0'; // Null terminate the result string
}

