#include <stdio.h>

int factorial(int n) {
    if (n == 0 || n == 1) {
        return 1;
    }
    int result = 1;
    for (int i = 2; i <= n; ++i) {
        result *= i;
    }
    return result;
}

int gcd_factorial(int a, int b) {
    int min_num = a < b ? a : b;
    return factorial(min_num);
}

