void solve(int n, int *a, int *k, char *sequence) {
    int left = 0;
    int right = n - 1;
    int last_picked = -1;
    int index = 0;

    while (left <= right) {
        if (a[left] > last_picked && (a[right] <= last_picked || a[left] < a[right])) {
            sequence[index++] = 'L';
            last_picked = a[left];
            left++;
        } else if (a[right] > last_picked) {
            sequence[index++] = 'R';
            last_picked = a[right];
            right--;
        } else {
            break;
        }
    }
    sequence[index] = '\0';
    *k = index;
}

