#define MAX_LEN 100

typedef struct {
    int position;
    char sequence[MAX_LEN];
} Beat;

int compare(const void *a, const void *b) {
    Beat *beatA = (Beat *)a;
    Beat *beatB = (Beat *)b;
    if (beatA->position != beatB->position) {
        return beatA->position - beatB->position;
    }
    return strcmp(beatA->sequence, beatB->sequence);
}

void generateBeats(const char *str, int startIndex, int maxLen, Beat *beats, int *count) {
    int len = strlen(str);
    char temp[MAX_LEN];
    for (int i = startIndex; i <= maxLen; i++) {
        for (int j = 0; j < (1 << len); j++) {
            int index = 0;
            for (int k = 0; k < len; k++) {
                if (j & (1 << k)) {
                    temp[index++] = str[k];
                }
            }
            temp[index] = '\0';
            if (index > 0) {
                beats[*count].position = i;
                strcpy(beats[*count].sequence, temp);
                (*count)++;
            }
        }
    }
}

int main() {
    char first[MAX_LEN], last[MAX_LEN];
    fgets(first, sizeof(first), stdin);
    fgets(last, sizeof(last), stdin);

    first[strcspn(first, "\n")] = 0;
    last[strcspn(last, "\n")] = 0;

    Beat beats[MAX_LEN * MAX_LEN];
    int count = 0;

    generateBeats(first, 1, strlen(first), beats, &count);
    generateBeats(last, strlen(first) + 1, strlen(last), beats, &count);

    for (int j = 0; j < (1 << strlen(first)); j++) {
        char temp[MAX_LEN];
        int index = 0;
        for (int k = 0; k < strlen(first); k++) {
            if (j & (1 << k)) {
                temp[index++] = first[k];
            }
        }
        temp[index] = '\0';
        if (index > 0) {
            beats[count].position = strlen(first);
            strcpy(beats[count].sequence, temp);
            count++;
        }
    }

    qsort(beats, count, sizeof(Beat), compare);

    char *ans = "";
    for (int i = 0; i < count; i++) {
        if (strlen(ans) == 0) {
            ans = beats[i].sequence;
            break;
        }
    }

    printf("%s\n", ans);
    return 0;
}

