#define MOD 1000000007

long long count_possible_strings(const char *s) {
    int n = strlen(s);
    long long dp[n + 1][2];

    dp[1][0] = (s[0] == '0') ? 1 : 0;
    dp[1][1] = (s[0] == '1') ? 1 : 0;

    for (int i = 1; i < n; i++) {
        if (s[i] == '0') {
            dp[i + 1][0] = (dp[i][0] + dp[i][1]) % MOD;
            dp[i + 1][1] = dp[i][1];
        } else {
            dp[i + 1][0] = dp[i][0];
            dp[i + 1][1] = (dp[i][0] + dp[i][1]) % MOD;
        }
    }

    return (dp[n][0] + dp[n][1]) % MOD;
}

