    long long remainder = 0;
    long long rest = bigInteger2; // Assuming bigInteger2 is the initial rest
    long long decimal_range = 100; // Adjust this according to your requirements

    while (power >= 1) {
        long long reminderIntermediate = 0;
        for (long long module = power / 2; module < decimal_range; module++) {
            if (module * (bigInteger1 - 1 - power) <= rest && 
                rest < module * bigInteger1 && 
