int* intersect(int** nums, int numsSize, int* returnSize) {
    int* intersection = NULL;
    *returnSize = 0;

    if (numsSize == 0) return intersection;

    if (numsSize == 1) {
        *returnSize = sizeof(nums[0]) / sizeof(nums[0][0]);
        return nums[0];
    }

    intersection = nums[0];
    int intersectionSize = sizeof(nums[0]) / sizeof(nums[0][0]);

    for (int i = 1; i < numsSize; i++) {
        int* temp = (int*)malloc(intersectionSize * sizeof(int));
        int tempSize = 0;

        for (int j = 0; j < intersectionSize; j++) {
            for (int k = 0; k < sizeof(nums[i]) / sizeof(nums[i][0]); k++) {
                if (intersection[j] == nums[i][k]) {
                    temp[tempSize++] = intersection[j];
                    break;
                }
            }
        }

        free(intersection);
        intersection = temp;
        intersectionSize = tempSize;
    }

    intersection = (int*)realloc(intersection, intersectionSize * sizeof(int));
    *returnSize = intersectionSize;
    qsort(intersection, intersectionSize, sizeof(int), compare);

    return intersection;
