#define MOD 1000000007
#define MAX_SIZE 1000

void increment(char c, char *result) {
    int d = c - 'a';
    *result = (c != 'z') ? d + 1 + 'a' : 'a';
}

int dp(int x) {
    int ans = 0;
    while (x) {
        ans = (3 * ans + 1) / 2;
        char str[20];
        sprintf(str, "%d", x);
        if (strchr(str, '2')) return ans;
        x /= 2;
    }
    return ans;
}

int fib(int n) {
    long long dp[MAX_SIZE];
    memset(dp, -1, sizeof(dp));
    dp[2] = 0;
    for (int i = 3; i <= n; i++) {
        dp[i] = (i % 2 ? 0 : 2) + dp[i - 1] + dp[i - 2];
        dp[i] %= MOD;
    }
    return dp[n];
}

void zigzag(int z[], int n) {
    int dp[n][2];
    for (int i = 0; i < n; i++) {
        dp[i][0] = INT_MAX;
        dp[i][1] = INT_MAX;
    }

    int col = 0;
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (z[j] < z[i] && z[j] > 0 && z[j] != z[i]) {
                dp[i][col] = (dp[i][col] < dp[j][1 - col] + 1) ? dp[i][col] : dp[j][1 - col] + 1;
            }
        }
        dp[i][col] = (dp[i][col] == INT_MAX) ? 1 : dp[i][col];
        dp[i][1 - col] = dp[i][col] + z[i];
        col = 1 - col;
    }
}

