int gcd(int a, int b) {
    while (b) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int main() {
    int n;
    scanf("%d", &n);

    int *A = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &A[i]);
    }

    int *nums = (int *)malloc(200 * sizeof(int));
    int num_count = 0;

    for (int i = 0; i < n; i++) {
        int e = A[i];
        for (int k = 1; k <= sqrt(e); k++) {
            if (e % k == 0) {
                int found = 0;
                for (int j = 0; j < num_count; j++) {
                    if (nums[j] == k) {
                        found = 1;
                        break;
                    }
                }
                if (!found) {
                    nums[num_count++] = k;
                }
                found = 0;
                if (k != e / k) {
                    for (int j = 0; j < num_count; j++) {
                        if (nums[j] == e / k) {
                            found = 1;
                            break;
                        }
                    }
                    if (!found) {
                        nums[num_count++] = e / k;
                    }
                }
            }
        }
    }

    int gcd_list[8];
    int gcd_index = 0;

    while (gcd_index < 8) {
        int c = 1;
        for (int j = 0; j < num_count; j++) {
            c = gcd(c, nums[j]);
        }
        gcd_list[gcd_index++] = c;
    }

    printf("gcd: [");
    for (int j = 0; j < gcd_index; j++) {
        printf("%d", gcd_list[j]);
        if (j < gcd_index - 1) {
            printf(", ");
        }
    }
    printf("]\n");

    int *nlist = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        nlist[i] = A[i];
    }

    int c = 0;
    for (int i = 1; i < n; i++) {
        if (A[i] % A[i - 1] == 0) {
            continue;
        }
        int divisor = gcd_list[--gcd_index];   
        nlist[i] = divisor * (A[i - 1] / divisor);
        c += abs(nlist[i] - A[i]);
    }

    printf("[");
    for (int i = 0; i < n; i++) {
        printf("%d", nlist[i]);
        if (i < n - 1) {
            printf(", ");
        }
    }
    printf("]\n%d\n", c);

    free(A);
    free(nums);
    free(nlist);
    return 0;
}

