#include <stdio.h>

long long solve(long long n, long long s) {
    long long curr_sum = 0, power_of_ten = 1, result = 1e18, carry = 0;

    long long temp = n;
    while (temp > 0) {
        curr_sum += temp % 10;
        temp /= 10;
    }

    if (curr_sum <= s) return 0;

    long long max_digit_sum = 9 * (long long)(log10(n) + 1);
    if (s >= max_digit_sum) return 0;
    if (s == 1) return 9 * (long long)(log10(n) + 1) - curr_sum;

    for (long long i = 0; n > 0; i++) {
        long long digit = n % 10;

        if (digit == 9 && carry == 0) {
            power_of_ten *= 10;
            n /= 10;
            continue;
        }

        if (digit + carry > 9) {
            long long diff = (digit + carry) - 9;
            long long new_digit_sum = (curr_sum - digit - carry) + 9;

            temp = n / 10;
            while (temp > 0) {
                new_digit_sum += temp % 10;
                temp /= 10;
            }

            if (new_digit_sum <= s) {
                result = (result < diff * power_of_ten) ? result : diff * power_of_ten;
            } else {
                curr_sum -= digit + carry - 9;
            }
        } else {
            curr_sum -= digit + carry;
            if (curr_sum <= s) return (digit + carry) * power_of_ten;
        }

        power_of_ten *= 10;
        carry = 1;
        n /= 10;
    }

    return result;
}

