int maxDigit(int n) {
    int mx = 0;
    while (n > 0) {
        int digit = n % 10;
        if (digit > mx) {
            mx = digit;
        }
        n /= 10;
    }
    return mx;
}

int minDigit(int n) {
    int mn = 9;
    while (n > 0) {
        int digit = n % 10;
        if (digit < mn) {
            mn = digit;
        }
        n /= 10;
    }
    return mn;
}

int nextn(int n) {
    int s;
    int curr_max = maxDigit(n);
    int curr_min = minDigit(n);
    s = curr_min * curr_max;

    for (int i = 1; i < 10; i++) {
        if (n % 10 < curr_max) {
            return s;
        }
        if (maxDigit(s) > s) {
            break;
        }
    }
    return s;
}

int find_next_k(int k) {
