long long _dupl2(int n) {
    long long x = 0;
    for (int i = 1; i <= (n >> 1); i++)
        x += i;
    return (x << 1) + n - 1;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[100001];
        scanf("%s", s);
        long long tms = strlen(s) - 1;
        long long tmp1 = sum(s);
        int ip = _dupl2(strlen(s) - 2) >> 1;

        if (s[strlen(s) - 1] == s[strlen(s) - 1]) {
            if (s[ip] == s[ip + 1])
                printf("%s\n", s);
            else if (s[ip] == s[strlen(s) - 1]) {
                printf("%c%c\n", s[ip], s[strlen(s) - 1]);
            } else if (s[ip] == s[ip + 1])
                printf("%c%c\n", s[strlen(s) - 1], s[ip]);
        } else {
            long long tmp2 = 0;
            int jrc = _dupl2(strlen(s) - 3) >> 2 + strlen(s) - 1;
            s[strlen(s) - 1] = '\0'; // Erasing last character

            if (jrc != 0) {
                long long w[3] = {s[jrc - 2], s[jrc - 1], s[jrc]};
                tmp2 += (w[0] == w[1] ? 2 : 3) * ((_dupl2(jrc - 2) + _dupl2(jrc - 1) + _dupl2(jrc)) << 1);
            }

            for (int i = strlen(s) - 2; i >= 1; i--)
                tmp2 += ((i != ip) * (strlen(s) - 2));

            if (tmp2 < tmp1)
                printf("%s\n", s);
            else
                printf("%lld %lld\n", tms, tmp2 - tmp1);
        }
