        int len = strlen(P);
        char last_char = P[len - 1];
        if (last_char == 'M') {
            P[len - 1] = '0';
        } else if (last_char == 'S') {
            int index1 = -1, index2 = -1;
            for (int j = len - 2; j >= 0; j--) {
                if (P[j] == 'M') {
                    index1 = j;
                    break;
                }
            }
            if (index1 <= 0) index1 = 100;
            for (int j = index1 - 1; j >= 0; j--) {
                if (P[j] == 'M') {
                    index2 = j;
                    break;
                }
            }
            if (index2 == -1) index2 = 100;
            memmove(P + index2 + 1, P + index1 + 1, len - index1 - 1);
            P[index2] = '\0';
        } else if (last_char == 'L') {
            int index1 = -1, index2 = -1;
            for (int j = len - 2; j >= 0; j--) {
                if (P[j] == 'M') {
                    index1 = j;
                    break;
                }
