long inversion_count(int arr[], int temp[], int left, int right);
long merge_and_count(int arr[], int temp[], int left, int mid, int right);

long inversion_count(int arr[], int n) {
    int *temp = (int *)malloc(n * sizeof(int));
    long count = inversion_count(arr, temp, 0, n - 1);
    free(temp);
    return count;
}

long inversion_count(int arr[], int temp[], int left, int right) {
    long count = 0;
    if (left < right) {
        int mid = (left + right) / 2;

        count += inversion_count(arr, temp, left, mid);
        count += inversion_count(arr, temp, mid + 1, right);
        count += merge_and_count(arr, temp, left, mid, right);
    }
    return count;
}

long merge_and_count(int arr[], int temp[], int left, int mid, int right) {
    int i = left;     
    int j = mid + 1; 
    int k = left;     
    long count = 0;

    while (i <= mid && j <= right) {
        if (arr[i] <= arr[j]) {
            temp[k++] = arr[i++];
        } else {
            temp[k++] = arr[j++];
            count += (mid - i + 1);
        }
    }

    while (i <= mid) {
        temp[k++] = arr[i++];
    }

    while (j <= right) {
        temp[k++] = arr[j++];
    }

    for (i = left; i <= right; i++) {
        arr[i] = temp[i];
    }

    return count;
}

int main() {
    int arr[] = {1, 3, 5, 2, 4, 6};
    int n = sizeof(arr)/sizeof(arr[0]);
    long result = inversion_count(arr, n);
    printf("Number of inversions: %ld\n", result);
    return 0;
}

