char* base7(int n, char* buffer) {
    if (n == 0) {
        strcpy(buffer, "0");
        return buffer;
    }
    int idx = 0;
    while (n) {
        buffer[idx++] = '0' + (n % 7);
        n /= 7;
    }
    buffer[idx] = '\0';
    for (int i = 0; i < idx / 2; i++) {
        char temp = buffer[i];
        buffer[i] = buffer[idx - 1 - i];
        buffer[idx - 1 - i] = temp;
    }
    return buffer;
}

int solve(int n, int m) {
    char hour[20], minute[20];
    int max_n = strlen(base7(n - 1, hour));
    int max_m = strlen(base7(m - 1, minute));
