    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            base7(i, hour);
            base7(j, minute);
            char digits[40];
            snprintf(digits, sizeof(digits), "%s%s", hour, minute);
            int digit_count[10] = {0};
            int unique = 1;

            for (int k = 0; digits[k]; k++) {
                int digit = digits[k] - '0';
                if (digit_count[digit] > 0) {
                    unique = 0;
                    break;
                }
                digit_count[digit]++;
            }
            if (unique) count++;
        }
