int specialArray(int* nums, int numsSize) {
    int sum = 0;
    for (int i = 0; i < numsSize; i++) {
        sum += nums[i];
    }

    int start = 1, end = numsSize, mid;
    while (start < end) {
        mid = start + (end - start) / 2;
        int curSum = sum + mid;
        if (curSum / (mid + 1) >= mid) {
            end = curSum % (mid + 1) == 0 ? mid : mid - 1;
        } else if (mid > curSum / (mid + 1)) {
            start = mid + 1;
        }
    }
    int ans = nums[0] == numsSize ? numsSize : -1;
    if (ans == -1) {
        ans = nums[numsSize - 1] + 1;
    }
    return ans;
}

