#include <limits.h>

int calculate_slices(int arr[], int size) {
    int count = 0;
    int min_slice = arr[0];
    int max_slice = arr[0];
    int smallest = arr[0];
    int largest = arr[0];
    int sum = 0;

    for (int i = 0; i < size; i++) {
        sum += arr[i];
        if (arr[i] < min_slice) min_slice = arr[i];
        if (arr[i] > max_slice) max_slice = arr[i];
    }

    float t_average = (float)sum / size;

    if (max_slice == 2) {
        count += 1;
        return count;
    } else if (max_slice == 3) {
        count += 2;
        return count;
    }

    int n_slices;
    if ((int)t_average % max_slice > 0) {
        n_slices = (int)t_average / max_slice;
    } else {
        n_slices = (int)t_average / max_slice + 1;
    }

    count += n_slices;

    int max_slices = 2;
    smallest = smallest < min_slice ? smallest : min_slice;
    largest = largest > max_slice ? largest : max_slice;

    int running = max_slices + 2;

    for (int i = 2; i < size - 2; i++) {
        int difference = arr[i] - min_slice > max_slice - arr[i] ? arr[i] - min_slice : max_slice - arr[i];
        if (difference < running) {
            running = difference;
            count--;
        }

        if (arr[i] < max_slice) {
            count++;
            break;
        }
    }

    int outside = 0;
    int difference = size - 2 - max_slice;
    if (difference < running) {
        running = difference;
        count--;
    } else {
        outside += difference;
    }

    difference = 3 - max_slices;
    if (difference < running) {
        running = difference;
        count--;
    }
    if (outside + 3 < running) {
        count = -1;
    }

    printf("______PRINTING OUT SLICES______\n");
    printf("Min: %d\n", smallest);
    printf("Max: %d\n", largest);
    printf("slices: %d\n", max_slices);
    printf("_____COUNT_____\n");
    if (count != -1) {
        printf("%d\n", count);
    } else {
        printf("False\n");
    }

    return count;
}

int main() {
    int arr[] = {100, 200, 300, 400, 352, 409, 222};
    int size = sizeof(arr) / sizeof(arr[0]);

    calculate_slices(arr, size);

    return 0;
}

