int min_robots(int n, int roads[][2], int num_roads) {
    if (num_roads == n - 1) {
        int **adj = (int **)malloc(n * sizeof(int *));
        for (int i = 0; i < n; i++) {
            adj[i] = (int *)calloc(n, sizeof(int));
        }

        for (int i = 0; i < num_roads; i++) {
            adj[roads[i][0]][roads[i][1]] = 1;
            adj[roads[i][1]][roads[i][0]] = 1;
        }

        int *visited = (int *)calloc(n, sizeof(int));
        int robots = 0;
        for (int city = 0; city < n; city++) {
            if (!visited[city]) {
                robots++;
                dfs(city, visited, adj, n);
            }
        }

        for (int i = 0; i < n; i++) {
            free(adj[i]);
        }
        free(adj);
        free(visited);
        return robots;
    }
    return -1;
}

