    int length = strlen(s);

    for (int i = 0; i < length; i++) {
        char char_at_i = s[i];
        if (char_at_i != prev_char) {
            operations++;
            prev_char = (prev_char == '1') ? '0' : '1';
            if (prev_char != char_at_i) {
                prev_char = char_at_i;
            }
        }
    }

    if (s[0] == '0') {
        operations += operations % 2;
    } else {
        operations += (operations + 1) % 2;
