int longest_prefix_ones(const char *s) {
    int leading_ones = 0, trailing_ones = 0;
    int len = strlen(s);

    for (int i = 0; i < len; i++) {
        if (s[i] == '1') {
            leading_ones++;
        } else {
            break;
        }
    }

    for (int i = len - 1; i >= 0; i--) {
        if (s[i] == '1') {
            trailing_ones++;
        } else {
            break;
        }
    }

    int max_prefix_ones = leading_ones;
    if (trailing_ones > 0) {
        max_prefix_ones = leading_ones + 1 > max_prefix_ones ? leading_ones + 1 : max_prefix_ones;
    }

    return max_prefix_ones;
}

