#include <stdio.h>
#include <stdlib.h>

void restore_array(int n, int x, int y, int *result) {
    if (n < 2) {
        fprintf(stderr, "Array must have at least two distinct elements\n");
        exit(1);
    }
    if (n == 2 && x < y) {
        result[0] = x;
        result[1] = y;
        return;
    }

    int min_max_element = y;
    int *unique_elements = (int *)malloc((y - x) * sizeof(int));
    int count = 0;

    for (int i = x; i <= y; i++) {
        unique_elements[count++] = i;
    }

    int *order_arr = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        order_arr[i] = x;
    }

    int max_diff = order_arr[1] - order_arr[0];
    int *pre_sum = (int *)malloc(n * sizeof(int));
    pre_sum[0] = unique_elements[0];

    for (int k = 1; k < n; k++) {
        pre_sum[k] = pre_sum[k - 1] + unique_elements[k % count];
    }

    int *possible_positions = (int *)malloc(n * sizeof(int));
    int pos_count = 0;

    for (int i = y - 1; i > 0; i--) {
        if (pre_sum[n - 1] - (y - 1) * max_diff >= 0 && 
            (pre_sum[n - 1] - (y - 1) * max_diff) % max_diff == 0) {
            possible_positions[pos_count++] = i;
        }
    }

    if (pos_count == 0) {
        fprintf(stderr, "No possible unique elements for array size n and y\n");
        exit(1);
    }

    for (int i = 0; i < count; i++) {
        if (unique_elements[i] == y) {
            unique_elements[i] = 0; // remove y by setting to zero or a flag value
        }
    }

    for (int p = 0; p < pos_count; p++) {
        for (int i = 0; i < count; i++) {
            order_arr[i] = possible_positions[p] + i;
        }
    }

    for (int i = 0; i < n; i++) {
        result[i] = order_arr[i];
    }

    free(unique_elements);
    free(order_arr);
    free(pre_sum);
    free(possible_positions);
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        int n, x, y;
        scanf("%d %d %d", &n, &x, &y);
        int *result = (int *)malloc(n * sizeof(int));
        restore_array(n, x, y, result);

        for (int i = 0; i < n; i++) {
            printf("%d%c", result[i], (i == n - 1) ? '\n' : ' ');
        }
        free(result);
    }

    return 0;
}

#include <stdio.h>
