int count_divisible_by_2(int n) {
    if (n <= 0) {
        fprintf(stderr, "Error: Input must be a positive integer.\n");
        return -1;
    }

    int count = 0;
    for (int i = 1; i <= n; i++) {
        if (n % i == 0 && i % 2 == 0) {
            count++;
        }
    }
    return count;
}

int main() {
