        if (scanf("%d", &num) != 1 || num <= 0) {
            fprintf(stderr, "Error: Must enter a valid positive integer.\n");
            return EXIT_FAILURE;
        }

        int result = count_divisible_by_2(num);
        if (result != -1) {
            printf("Count of even divisors for %d: %d\n", num, result);
        }
    }

    return EXIT_SUCCESS;
}

