#define MAX_DIGITS 64

void log_message(const char *message) {
    // Logs a message for debugging purposes
    printf("%s\n", message);
}

int* convert_to_quasibinary(int n, int *length) {
    if (n <= 0) {
        log_message("Invalid input: n must be greater than 0.");
        *length = 0;
        return NULL;
    }

    int *quasibinary = malloc(MAX_DIGITS * sizeof(int));
    if (!quasibinary) {
        log_message("Memory allocation failed.");
        *length = 0;
        return NULL;
    }

    *length = 0;
    while (n > 0) {
        quasibinary[(*length)++] = n % 5;
        n /= 5;
    }

    // Reverse the array
    for (int i = 0; i < *length / 2; i++) {
        int temp = quasibinary[i];
        quasibinary[i] = quasibinary[*length - 1 - i];
        quasibinary[*length - 1 - i] = temp;
    }

    return quasibinary;
}

void print_quasibinary(int *quasibinary, int length) {
    for (int i = 0; i < length; i++) {
        printf("%d", quasibinary[i]);
        if (i < length - 1) {
            printf(" ");
        }
    }
    printf("\n");
}

int main() {
    int n;
    log_message("Enter a number n:");

    if (scanf("%d", &n) != 1) {
        log_message("Invalid input. Please enter a valid integer.");
        return EXIT_FAILURE;
    }

    int length = 0;
    int *quasibinary = convert_to_quasibinary(n, &length);

    if (quasibinary) {
        printf("%d\n", length);
        print_quasibinary(quasibinary, length);
        free(quasibinary);
    }

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>

void pushZerosToEnd(int *arr, int n) {
    if (arr == NULL || n <= 0) {
        fprintf(stderr, "Invalid input array or size.\n");
        return;
    }

    int i = 0;
    while (i < n) {
        if (arr[i] == 0) {
            int j = i;
            while (j < n && arr[j] != 0) {
                j++;
            }
            if (j < n) {
                int temp = arr[i];
                arr[i] = arr[j];
                arr[j] = temp;
            }
        }
        i++;
    }
}

int main() {
    int arr[] = {3, 5, 0, 0, 4};
    int n = sizeof(arr) / sizeof(arr[0]);

    pushZerosToEnd(arr, n);

    for (int i = 0; i < n; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n");

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void log_error(const char *message) {
    fprintf(stderr, "Error: %s\n", message);
}

char* generate_sequence(int n, int k) {
    if (n <= 0 || k <= 0) {
        log_error("Both n and k must be positive.");
        return NULL;
    }

    if (n == 1) {
        char *result = (char *)malloc(k + 1);
        if (!result) {
            log_error("Memory allocation failed.");
            return NULL;
        }
        memset(result, 'a', k);
        result[k] = '\0';
        return result;
    }

    if (k == n) {
        char *result = (char *)malloc(k + 1);
        if (!result) {
            log_error("Memory allocation failed.");
            return NULL;
        }
        memset(result, 'a', k);
        result[k] = '\0';
        return result;
    }

    int *res = (int *)malloc(n * sizeof(int));
    if (!res) {
        log_error("Memory allocation failed.");
        return NULL;
    }

    int chars = 'a';
    int res_count = 0;

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= k; j++) {
            int found = 0;
            for (int l = 0; l < res_count; l++) {
                if (res[l] == j) {
                    found = 1;
                    break;
                }
            }
            if (found) continue;

            if (i == 1) {
                res[res_count++] = j;
            } else if (i == 2) {
                res[res_count++] = (j > res[res_count - 1]) ? j : res[res_count - 1] + 1;
            } else {
                int max_dist = (res_count < 2) ? 0 : 
                    ((res[res_count - 2] - res[res_count - 3] - 1 > 
                      res[res_count - 2] - res[res_count - 1] - 1) ? 
                      res[res_count - 2] - res[res_count - 3] - 1 : 
                      res[res_count - 2] - res[res_count - 1] - 1);

                if (res[res_count - 1] - res[res_count - 2] <= 0) {
                    res[res_count++] = (j > max_dist + 1) ? j : max_dist + 1;
                } else {
                    res[res_count++] = res[res_count - 1] - res[res_count - 2] + 1;
                }
            }
        }
    }

    qsort(res, res_count, sizeof(int), (int (*)(const void *, const void *)) strcmp);

    char *result = (char *)malloc(res_count + 1);
    if (!result) {
        free(res);
        log_error("Memory allocation failed.");
        return NULL;
    }

    for (int i = 0; i < res_count; i++) {
        result[i] = (char)res[i];
    }
    result[res_count] = '\0';

    free(res);
    return result;
}

int main(void) {
    int n, k;
    if (scanf("%d %d", &n, &k) != 2) {
        log_error("Input must be two integers.");
        return EXIT_FAILURE;
    }

    char *result = generate_sequence(n, k);
    if (result) {
        printf("%s\n", result);
        free(result);
    }

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>

#define INCOME_LIMIT_1 250000
#define INCOME_LIMIT_2 500000
#define INCOME_LIMIT_3 750000
#define TAX_RATE_1 0.05
#define TAX_RATE_2 0.1

double calculate_tax(double income) {
    if (income < 0) {
        fprintf(stderr, "Error: Income cannot be negative.\n");
        exit(EXIT_FAILURE);
    }

    double tax = 0.0;

    if (income <= INCOME_LIMIT_1) {
        tax = 0.0;
    } else if (income <= INCOME_LIMIT_2) {
        tax = (income - INCOME_LIMIT_1) * TAX_RATE_1;
    } else if (income <= INCOME_LIMIT_3) {
        tax = (INCOME_LIMIT_2 - INCOME_LIMIT_1) * TAX_RATE_1 + 
              (income - INCOME_LIMIT_2) * TAX_RATE_2;
    } else {
        // Assuming a higher tax rate for income above INCOME_LIMIT_3
        tax = (INCOME_LIMIT_2 - INCOME_LIMIT_1) * TAX_RATE_1 + 
              (INCOME_LIMIT_3 - INCOME_LIMIT_2) * TAX_RATE_2 + 
              (income - INCOME_LIMIT_3) * 0.15;  // Example rate for upper bracket
    }

    return tax;
}

int main() {
    double income;
    printf("Enter your income: ");
    if (scanf("%lf", &income) != 1) {
        fprintf(stderr, "Error: Invalid input. Please enter a numeric value.\n");
        return EXIT_FAILURE;
    }

    double tax = calculate_tax(income);
    printf("Calculated tax: %.2f\n", tax);

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>

#define MAX_SIZE 1000
#define ERROR_INVALID_INPUT -1

typedef struct {
    int value;
    int indices[MAX_SIZE];
    int count;
} NumberMap;

void initialize_map(NumberMap *map) {
    map->count = 0;
}

void add_to_map(NumberMap *map, int index, int value) {
    for (int i = 0; i < map->count; i++) {
        if (map->value == value) {
            map->indices[map->count++] = index;
            return;
        }
    }
    map->value = value;
    map->indices[map->count++] = index;
}

int get_great_number(int *a, int n, int x) {
    if (n % 2 != 0) {
        return 1;
    }
    int half_n = n / 2;
    int b[half_n];
    NumberMap number_map[MAX_SIZE] = {0};

    for (int i = 0; i < half_n; i++) {
        b[i] = a[i] * x;
        initialize_map(&number_map[i]);
    }

    for (int i = 0; i < half_n; i++) {
        add_to_map(&number_map[i], i, a[i]);
    }

    for (int i = 0; i < half_n; i++) {
        if (number_map[b[i]].count != 2) {
            return 1;
        }
    }
    return 0;
}

int main() {
    int test_cases = 0;
    if (scanf("%d", &test_cases) != 1 || test_cases < 1) {
        fprintf(stderr, "Error: Invalid number of test cases\n");
        return ERROR_INVALID_INPUT;
    }

    while (test_cases--) {
        int n = 0, x = 0;
        if (scanf("%d %d", &n, &x) != 2 || n < 1) {
            fprintf(stderr, "Error: Invalid input for n or x\n");
            return ERROR_INVALID_INPUT;
        }

        int *a = malloc(n * sizeof(int));
        if (!a) {
            fprintf(stderr, "Error: Memory allocation failed\n");
            return ERROR_INVALID_INPUT;
        }

        for (int i = 0; i < n; i++) {
            if (scanf("%d", &a[i]) != 1) {
                fprintf(stderr, "Error: Invalid input for array element\n");
                free(a);
                return ERROR_INVALID_INPUT;
            }
        }

        printf("%d\n", get_great_number(a, n, x));
        free(a);
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <string.h>

#define MAX_NODES 100
#define MAX_EDGES 10

typedef struct {
    int edges[MAX_NODES][MAX_EDGES];
    int degree[MAX_NODES];
} Graph;

int d_time[MAX_NODES];
int f_time[MAX_NODES];
bool visited[MAX_NODES];
int timestamp = 1;

void init_graph(Graph *g, int n) {
    for (int i = 0; i < n; i++) {
        g->degree[i] = 0;
    }
}

void add_edge(Graph *g, int u, int v) {
    if (g->degree[u] < MAX_EDGES) {
        g->edges[u][g->degree[u]++] = v;
    }
}

void DFS(Graph *g, int node) {
    visited[node] = true;
    d_time[node] = timestamp++;

    for (int i = 0; i < g->degree[node]; i++) {
        int v = g->edges[node][i];
        if (!visited[v]) {
            DFS(g, v);
        }
    }

    f_time[node] = timestamp++;
}

void RunDFS(Graph *g, int n) {
    for (int node = 0; node < n; node++) {
        if (!visited[node]) {
            DFS(g, node);
        }
    }
}

void print_times(int n) {
    for (int i = 0; i < n; i++) {
        printf("%d %d %d\n", i, d_time[i], f_time[i]);
    }
}

int main() {
    int n;
    printf("Enter the number of nodes: ");
    if (scanf("%d", &n) != 1 || n <= 0 || n > MAX_NODES) {
        fprintf(stderr, "Invalid number of nodes.\n");
        return EXIT_FAILURE;
    }

    Graph g;
    init_graph(&g, n);

    printf("Enter edges (format: u k v1 v2 ... vk):\n");
    for (int i = 0; i < n; i++) {
        int u, k;
        if (scanf("%d %d", &u, &k) != 2 || u < 0 || u >= n || k < 0) {
            fprintf(stderr, "Invalid input format.\n");
            return EXIT_FAILURE;
        }

        for (int j = 0; j < k; j++) {
            int v;
            if (scanf("%d", &v) != 1 || v < 0 || v >= n) {
                fprintf(stderr, "Invalid edge input.\n");
                return EXIT_FAILURE;
            }
            add_edge(&g, u, v);
        }
    }

    RunDFS(&g, n);
    print_times(n);

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_N 1000

void sort_descending(int *arr, int n) {
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (arr[j] < arr[j + 1]) {
                int temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;
            }
        }
    }
}

int solve_case(int n, int *a) {
    int dp[MAX_N + 1];
    memset(dp, -1, sizeof(dp));
    dp[0] = 0;

    for (int i = 1; i <= n; i++) {
        for (int j = 0; j < i; j++) {
            if (a[j] + j > i) {
                break;
            }
            if (dp[i - j - 1] != -1) {
                if (dp[i] == -1 || dp[i] < dp[i - j - 1] + 1) {
                    dp[i] = dp[i - j - 1] + 1;
                }
            }
        }
    }
    return dp[n];
}

int main() {
    int t;
    if (scanf("%d", &t) != 1 || t < 1) {
        fprintf(stderr, "Invalid number of test cases\n");
        return 1;
    }

    while (t--) {
        int n;
        if (scanf("%d", &n) != 1 || n < 1 || n > MAX_N) {
            fprintf(stderr, "Invalid value for n\n");
            return 1;
        }

        int *a = malloc(n * sizeof(int));
        if (!a) {
            fprintf(stderr, "Memory allocation failed\n");
            return 1;
        }

        for (int i = 0; i < n; i++) {
            if (scanf("%d", &a[i]) != 1) {
                fprintf(stderr, "Invalid input for array elements\n");
                free(a);
                return 1;
            }
        }

        sort_descending(a, n);
        int result = solve_case(n, a);
        printf("%d\n", result);
        free(a);
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <stdbool.h>

#define MAX_NODES 1000

typedef struct {
    int node;
    int distance;
} HeapNode;

typedef struct {
    HeapNode* array;
    int size;
} MinHeap;

MinHeap* create_min_heap(int capacity) {
    MinHeap* min_heap = (MinHeap*)malloc(sizeof(MinHeap));
    min_heap->array = (HeapNode*)malloc(capacity * sizeof(HeapNode));
    min_heap->size = 0;
    return min_heap;
}

void min_heapify(MinHeap* min_heap, int idx) {
    int smallest = idx;
    int left = 2 * idx + 1;
    int right = 2 * idx + 2;

    if (left < min_heap->size && min_heap->array[left].distance < min_heap->array[smallest].distance) {
        smallest = left;
    }
    if (right < min_heap->size && min_heap->array[right].distance < min_heap->array[smallest].distance) {
        smallest = right;
    }
    if (smallest != idx) {
        HeapNode temp = min_heap->array[idx];
        min_heap->array[idx] = min_heap->array[smallest];
        min_heap->array[smallest] = temp;
        min_heapify(min_heap, smallest);
    }
}

void insert_min_heap(MinHeap* min_heap, int node, int distance) {
    min_heap->array[min_heap->size].node = node;
    min_heap->array[min_heap->size].distance = distance;
    min_heap->size++;

    for (int i = min_heap->size / 2 - 1; i >= 0; i--) {
        min_heapify(min_heap, i);
    }
}

HeapNode extract_min(MinHeap* min_heap) {
    if (min_heap->size == 0) {
        return (HeapNode){-1, INT_MAX};
    }

    HeapNode root = min_heap->array[0];
    min_heap->array[0] = min_heap->array[min_heap->size - 1];
    min_heap->size--;
    min_heapify(min_heap, 0);

    return root;
}

void dijkstra(int graph[MAX_NODES][MAX_NODES], int src, int N, int distances[MAX_NODES]) {
    MinHeap* min_heap = create_min_heap(N);
    for (int i = 1; i <= N; i++) {
        distances[i] = INT_MAX;
    }

    distances[src] = 0;
    insert_min_heap(min_heap, src, 0);

    while (min_heap->size > 0) {
        HeapNode current = extract_min(min_heap);

        for (int neighbor = 1; neighbor <= N; neighbor++) {
            if (graph[current.node][neighbor] != 0) {
                int distance = current.distance + graph[current.node][neighbor];

                if (distance < distances[neighbor]) {
                    distances[neighbor] = distance;
                    insert_min_heap(min_heap, neighbor, distance);
                }
            }
        }
    }

    free(min_heap->array);
    free(min_heap);
}

int solve(int N, int M, int S, int T, int edges[M][3], int mod) {
    int graph[MAX_NODES][MAX_NODES] = {0};

    for (int i = 0; i < M; i++) {
        int u = edges[i][0];
        int v = edges[i][1];
        int d = edges[i][2];
        graph[u][v] = d;
        graph[v][u] = d;
    }

    int distances_S[MAX_NODES], distances_T[MAX_NODES];
    dijkstra(graph, S, N, distances_S);
    dijkstra(graph, T, N, distances_T);

    int result = 0;

    for (int u = 1; u <= N; u++) {
        if (u <= S || u >= T) continue;

        for (int v = 1; v <= N; v++) {
            if (v <= S || v >= T || u == v) continue;

            int path_S_to_U[MAX_NODES], path_T_to_V[MAX_NODES];
            dijkstra(graph, S, N, path_S_to_U);
            dijkstra(graph, T, N, path_T_to_V);

            bool intersect = false;
            for (int i = 1; i <= N; i++) {
                if (path_S_to_U[i] < INT_MAX && path_T_to_V[i] < INT_MAX) {
                    intersect = true;
                    break;
                }
            }

            if (!intersect) {
                result = (result + 1) % mod;
            }
        }
    }

    return result;
}

int main() {
    int N = 4, M = 4, S = 1, T = 3;
    int edges[4][3] = {
        {1, 2, 1},
        {2, 3, 1},
        {3, 4, 1},
        {4, 1, 1}
    };

    printf("%d\n", solve(N, M, S, T, edges, 1000000007));

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

#define MAX_LENGTH 256

void to_lowercase(char *str) {
    for (int i = 0; str[i]; i++) {
        str[i] = tolower((unsigned char)str[i]);
    }
}

void replace_vowels(char *str) {
    const char vowels[] = "aeiouy";

    for (int i = 0; str[i]; i++) {
        for (int j = 0; j < strlen(vowels); j++) {
            if (str[i] == vowels[j]) {
                str[i] = '.';
                break;
            }
        }
    }
}

void process_string(char *str) {
    if (str == NULL) {
        fprintf(stderr, "Error: Input string is NULL.\n");
        exit(EXIT_FAILURE);
    }

    size_t len = strlen(str);
    if (len == 0 || len >= MAX_LENGTH) {
        fprintf(stderr, "Error: Input string must be between 1 and %d characters.\n", MAX_LENGTH - 1);
        exit(EXIT_FAILURE);
    }

    to_lowercase(str);
    replace_vowels(str);
    printf("%s\n", str);
}

int main() {
    char input[MAX_LENGTH];

    printf("Enter a string: ");
    if (fgets(input, sizeof(input), stdin) == NULL) {
        fprintf(stderr, "Error reading input.\n");
        return EXIT_FAILURE;
    }

    // Remove newline character from input
    size_t len = strlen(input);
    if (len > 0 && input[len - 1] == '\n') {
        input[len - 1] = '\0';
    }

    process_string(input);

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

#define MAX_ELEMENTS 100

int get_max(int *array, int size) {
    if (size <= 0) {
        fprintf(stderr, "Error: Array size must be greater than 0.\n");
        return INT_MIN;
    }

    int max_val = array[0];
    for (int i = 1; i < size; i++) {
        if (array[i] > max_val) {
            max_val = array[i];
        }
    }
    return max_val;
}

int pointer_to_pos(int *array, int size, int max_val) {
    if (size <= 0 || max_val < 0) {
        return -1;
    }

    for (int i = 0; i < size; i++) {
        if (array[i] == max_val) {
            return i;
        }
    }
    return -1;
}

int pointer_to_neg_pos(int *array, int size, int max_val) {
    int pos = pointer_to_pos(array, size, max_val);
    return (pos == -1) ? 0 : pos;
}

void insert_value(int *array, int *size, int value) {
    if (*size >= MAX_ELEMENTS) {
        fprintf(stderr, "Error: Cannot insert value, array is full.\n");
        return;
    }

    array[*size] = value;
    (*size)++;
}

void log_array(int *array, int size) {
    printf("Current Array: ");
    for (int i = 0; i < size; i++) {
        printf("%d ", array[i]);
    }
    printf("\n");
}

void run_insertions(int *array, int *size, int max_val) {
    for (int i = 1; i <= 5; i++) {
        insert_value(array, size, i * max_val);
        log_array(array, *size);
    }
}

int main() {
    int array[MAX_ELEMENTS] = {0};
    int size = 0;
    int max_val = 10;

    printf("Inserting values...\n");
    run_insertions(array, &size, max_val);

    int max_value = get_max(array, size);
    printf("Max value in array: %d\n", max_value);

    int position = pointer_to_pos(array, size, max_value);
    printf("Position of max value: %d\n", position);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_SIZE 100

void initialize_pi(int *pi, int size) {
    for (int i = 0; i < size; i++) {
        pi[i] = -1;
    }
}

int min_operations(int *A, int sizeA, int *B, int sizeB) {
    if (sizeA <= 0 || sizeB <= 0) {
        fprintf(stderr, "Error: Size of arrays must be positive.\n");
        return -1;
    }

    int *nums = malloc(sizeA * sizeof(int));
    int *pi = malloc(sizeA * sizeof(int));
    int cmp = 0;

    if (!nums || !pi) {
        fprintf(stderr, "Error: Memory allocation failed.\n");
        return -1;
    }

    for (int i = 0; i < sizeA; i++) {
        nums[i] = i + 1;
    }

    initialize_pi(pi, sizeA);

    for (int i = 0; i < sizeA; i++) {
        if (A[i] < 1 || A[i] > sizeA) {
            fprintf(stderr, "Error: Invalid value in array A. Value: %d\n", A[i]);
            free(nums);
            free(pi);
            return -1;
        }
        pi[A[i] - 1] = i;
    }

    int i = 0;
    for (int pos = 0; pos < sizeB; pos++) {
        if (B[pos] < 1 || B[pos] > sizeA) {
            fprintf(stderr, "Error: Invalid value in array B. Value: %d\n", B[pos]);
            free(nums);
            free(pi);
            return -1;
        }

        while (i < sizeA && pi[i] == -1) {
            i++;
        }

        if (i < sizeA && pi[i] - i == pos + 1) {
            cmp += (B[pos] - nums[i]) < (nums[i] - B[pos]);
            nums[i] = B[pos];
            i++;
        }
    }

    int uniqueB = 0;
    int *seen = calloc(sizeA + 1, sizeof(int));
    if (!seen) {
        fprintf(stderr, "Error: Memory allocation failed.\n");
        free(nums);
        free(pi);
        return -1;
    }

    for (int j = 0; j < sizeB; j++) {
        if (B[j] > 0 && B[j] <= sizeA && !seen[B[j]]) {
            seen[B[j]] = 1;
            uniqueB++;
        }
    }

    free(nums);
    free(pi);
    free(seen);

    return cmp + (sizeB - uniqueB);
} 

int main() {
    int A[] = {5, 3, 1, 2};
    int B[] = {1, 3, 5, 2};
    int result = min_operations(A, 4, B, 4);

    if (result >= 0) {
        printf("Minimum operations: %d\n", result);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define SIZE 7
#define ASCII_OFFSET 97
#define LOG_BUFFER_SIZE 256

void log_message(const char* message) {
    char buffer[LOG_BUFFER_SIZE];
    snprintf(buffer, sizeof(buffer), "[INFO]: %s\n", message);
    printf("%s", buffer);
}

int validate_input(const char* a) {
    if (a == NULL) {
        log_message("Input string cannot be NULL.");
        return 0;
    }
    if (strlen(a) == 0) {
        log_message("Input string cannot be empty.");
        return 0;
    }
    return 1;
}

int calculate_dp_value(const char* a, int* dp) {
    int count = 0;
    for (size_t i = 0; i < strlen(a); ++i) {
        if (a[i] == a[0]) {
            count++;
        }
    }

    if (count == 0) {
        log_message("Character count is zero, returning 0.");
        return 0;
    }

    int total_length = strlen(a);
    if (a[0] <= a[total_length - 1]) {
        return dp[(int)(a[0] - ASCII_OFFSET)] + 34 * count + 33 * (total_length - count - 1);
    } else {
        return dp[SIZE - 1 - (a[0] - ASCII_OFFSET)] + 34 * count + 33 * (total_length - count - 1);
    }
}

int main(int argc, char* argv[]) {
    int dp[SIZE] = {1, 3, 7, 13, 27, 69, 39};

    if (argc != 2) {
        log_message("Usage: ./program <string>");
        return EXIT_FAILURE;
    }

    const char* input_string = argv[1];

    if (!validate_input(input_string)) {
        return EXIT_FAILURE;
    }

    int result = calculate_dp_value(input_string, dp);
    printf("%d\n", result);

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_INPUT 100

void validate_input(int n, int x) {
    if (n < 0 || x < 0) {
        fprintf(stderr, "Error: Number of operations and initial ice packs must be non-negative.\n");
        exit(EXIT_FAILURE);
    }
}

int main() {
    int n, x;
    printf("Enter number of operations and initial ice packs: ");
    if (scanf("%d %d", &n, &x) != 2) {
        fprintf(stderr, "Error: Invalid input for number of operations and ice packs.\n");
        return EXIT_FAILURE;
    }

    validate_input(n, x);

    int left = x;
    int distressed = 0;

    for (int i = 0; i < n; i++) {
        char c;
        int d;

        printf("Enter operation (+ or -) followed by a number: ");
        char input[MAX_INPUT];
        if (fgets(input, sizeof(input), stdin) == NULL) {
            fprintf(stderr, "Error: Failed to read input.\n");
            return EXIT_FAILURE;
        }

        if (sscanf(input, " %c %d", &c, &d) != 2) {
            fprintf(stderr, "Error: Invalid operation input.\n");
            return EXIT_FAILURE;
        }

        if (d < 0) {
            fprintf(stderr, "Error: Amount must be non-negative.\n");
            return EXIT_FAILURE;
        }

        if (c == '+') {
            left += d;
        } else if (c == '-') {
            if (d > left) {
                distressed++;
            } else {
                left -= d;
            }
        } else {
            fprintf(stderr, "Error: Invalid operation. Use '+' or '-'.\n");
            return EXIT_FAILURE;
        }
    }

    printf("%d %d\n", left, distressed);
    return EXIT_SUCCESS;
}

