int is_adjacent(char letter1, char letter2) {
    return abs(letter1 - letter2) == 1;
}

int is_diverse(const char *string) {
    size_t length = strlen(string);
    if (length == 0) return 0;

    for (size_t i = 0; i < length - 1; i++) {
        if (!is_adjacent(string[i], string[i + 1])) {
            return 0;
        }
    }

    int char_set[256] = {0}; 
    for (size_t i = 0; i < length; i++) {
        char_set[(unsigned char)string[i]]++;
        if (char_set[(unsigned char)string[i]] > 1) {
            return 0;
        }
    }

    return 1;
}

void process_strings(char strings[][MAX_LENGTH], size_t count) {
    for (size_t i = 0; i < count; i++) {
        if (is_diverse(strings[i])) {
            printf("Yes\n");
        } else {
            printf("No\n");
        }
    }
}

int main() {
    size_t n;
    log_message("Enter number of strings:");

    if (scanf("%zu", &n) != 1 || n > MAX_STRINGS) {
        log_message("Invalid number of strings.");
        return EXIT_FAILURE;
    }

    char strings[MAX_STRINGS][MAX_LENGTH];
    log_message("Enter the strings:");

    for (size_t i = 0; i < n; i++) {
        scanf("%s", strings[i]);
    }

    process_strings(strings, n);
    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) {
        return a;
    }
    return gcd(b, a % b);
}

int calculate_beauty(int n) {
    if (n < 1) {
        fprintf(stderr, "Error: Input must be a positive integer.\n");
        return -1; 
    }

    int ans = 1;
    for (int i = 1; i <= n; i++) {
        ans *= i;
        ans /= gcd(1, ans);
    }

    return (ans != 1) ? (ans - 1) : 0;
}

int main(int argc, char *argv[]) {
    if (argc != 2) {
        fprintf(stderr, "Usage: %s <positive_integer>\n", argv[0]);
        return EXIT_FAILURE;
    }

    int n = atoi(argv[1]);
    if (n <= 0) {
        fprintf(stderr, "Error: Provided argument is not a positive integer.\n");
        return EXIT_FAILURE;
    }

    int result = calculate_beauty(n);
    if (result >= 0) {
        printf("Beauty of %d is: %d\n", n, result);
    } else {
        fprintf(stderr, "Error: Calculation failed.\n");
    }

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>

#define MOD 1000000007

long long **createDPTable(int n, int goal) {
    long long **dp = (long long **)malloc((n + 1) * sizeof(long long *));
    for (int i = 0; i <= n; i++) {
        dp[i] = (long long *)malloc((goal + 1) * sizeof(long long));
        for (int j = 0; j <= goal; j++)
            dp[i][j] = 0;
    }
    return dp;
}

void freeDPTable(long long **dp, int n) {
    for (int i = 0; i <= n; i++)
        free(dp[i]);
    free(dp);
}

long long numMusicPlaylists(int n, int goal, int k) {
    if (n <= 0 || goal <= 0 || k < 0 || k >= n) {
        fprintf(stderr, "Invalid input parameters.\n");
        return 0;
    }

    long long **dp = createDPTable(n, goal);
    dp[0][0] = 1;

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= goal; j++) {
            dp[i][j] = (dp[i - 1][j - 1] * (n - (i - 1)) % MOD +
                        dp[i][j - 1] * (i - k - 1 >= 0 ? i - k - 1 : 0) % MOD) % MOD;
        }
    }

    long long result = dp[n][goal];
    freeDPTable(dp, n);
    return result;
}

int main() {
    int n = 3, goal = 4, k = 1;
    long long result = numMusicPlaylists(n, goal, k);
    printf("Number of playlists: %lld\n", result);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

typedef struct {
    bool result;
    const char* message;
} Result;

Result isBypassable(int s, int n, int xi, int yi) {
    int larger = 0;
    int smaller = 0;
    int buffer = s;

    for (int ii = 1; ii <= n; ii++) {
        if (buffer > xi) {
            larger++;
            return (Result){true, "YES"};
        } else {
            if (ii < n) {
                printf("Enter new xi and yi: ");
                if (scanf("%d %d", &xi, &yi) != 2) {
                    fprintf(stderr, "Error reading inputs.\n");
                    exit(EXIT_FAILURE);
                }
                if (buffer + yi - xi > 0) {
                    larger++;
                    printf("X beats with %d + %d, Xi is %d, accumulative def = + %d > Buf: %d + %d - Xi = %d\n",
                           s, yi, xi, s + yi, buffer, buffer, xi);
                    return (Result){true, "YES"};
                } else if (buffer + xi - yi > 0) {
                    smaller++;
                    printf("X can counter with %d + %d, SMALLER is %d > Buf: %d + %d - Xi = (%d) = %d\n",
                           s, xi, s + xi, buffer, buffer, xi, s + xi + buffer - xi);
                    if (smaller > larger) {
                        return (Result){false, "NO"};
                    }
                } else {
                    smaller++;
                    return (Result){false, "NO"};
                }
            } else {
                return (smaller >= larger) ? (Result){false, "NO"} : (Result){true, "YES"};
            }
        }
    }

    return (Result){false, "NO"};
}

int main(void) {
    int s, n, xi, yi;
    printf("Enter s, n, xi, yi: ");
    if (scanf("%d %d %d %d", &s, &n, &xi, &yi) != 4 || n <= 0) {
        fprintf(stderr, "Invalid input.\n");
        return EXIT_FAILURE;
    }

    Result res = isBypassable(s, n, xi, yi);
    printf("%s\n", res.message);
    return 0;
}

