void handle_error(const char *message) {
    fprintf(stderr, "Error: %s\n", message);
    exit(EXIT_FAILURE);
}

int compare(const void *a, const void *b) {
    return (*(int *)a - *(int *)b);
}

int qualifier_count(int *arr, int size, int k) {
    if (size < k) {
        handle_error("k must be less than or equal to the number of elements.");
    }

    qsort(arr, size, sizeof(int), compare);
    int threshold = arr[size - k];

    int count = 0;
    for (int i = 0; i < size; i++) {
        if (arr[i] >= threshold && arr[i] > 0) {
            count++;
        }
    }
    return count;
}

int main() {
    int n, k;

    printf("Enter n and k: ");
    if (scanf("%d %d", &n, &k) != 2) {
        handle_error("Invalid input for n and k.");
    }

    if (n <= 0) {
        handle_error("Number of elements must be greater than zero.");
    }

    int *a = malloc(n * sizeof(int));
    if (a == NULL) {
        handle_error("Memory allocation failed.");
    }

    printf("Enter the elements: ");
    for (int i = 0; i < n; i++) {
        if (scanf("%d", &a[i]) != 1) {
            free(a);
            handle_error("Invalid input for array elements.");
        }
    }

    int result = qualifier_count(a, n, k);
    printf("%d\n", result);  // count of programs, who can advance to the next round.

    free(a);
    return 0;
}

