double calculate_sum(int a, int b) {
    if (a <= 0 || b <= 0 || a > b) {
        log_message("Invalid input: a must be > 0 and b must be >= a.");
        return -1;
    }

    double suma = 0;
    int n = 0;
    double current_term = a;

    while (current_term <= b) {
        suma += current_term;
        current_term *= a; // Update to a^(n+1)
        n++;
    }

    return suma;
}

void process(int a, int b) {
    double result = calculate_sum(a, b);
    if (result >= 0) {
        printf("Sum = %.2f\n", result);
    }
}

