void reverseAlternateWords(char* str) {
    int n = strlen(str);
    if (n == 0 || n == 1) return;

    for (int i = 0; i < n; ) {
        if (str[i] != ' ') {
            int j = i;
            while (j < n && str[j] != ' ') j++;
            j--;

            while (i < j) {
                char temp = str[i];
                str[i] = str[j];
                str[j] = temp;
                i++;
                j--;
            }
        }
        i++;
    }
}

int main() {
