        }
    }
    return 0;
}

void minJumps(int* arr, int n) {
    if (n <= 0) {
        fprintf(stderr, "Invalid array size\n");
        return;
    }
    int* dp = (int*)malloc(n * sizeof(int));
    if (!dp) {
        fprintf(stderr, "Memory allocation failed\n");
        return;
    }
    for (int i = 0; i < n; i++) dp[i] = INT_MAX;
    dp[0] = 0;

    for (int i = 1; i < n; i++) {
        if (arr[i] == 0) continue;
        for (int j = 1; j <= arr[i] && i + j < n; j++) {
            dp[i + j] = (dp[i + j] < dp[i] + 1) ? dp[i + j] : dp[i] + 1;
        }
    }
    printf("Minimum jumps: %d\n", dp[n - 1]);
    free(dp);
}

void minSwaps(int* arr, int n) {
    if (n <= 0) {
        fprintf(stderr, "Invalid array size\n");
        return;
    }
    int swap = 0;
    for (int i = 0; i < n; i++) {
        while (arr[i] != i + 1) {
            swap++;
            int temp = arr[arr[i] - 1];
            arr[arr[i] - 1] = arr[i];
            arr[i] = temp;
        }
    }
    printf("Minimum swaps: %d\n", swap);
}

int firstRepeated(int* arr, int n) {
    if (n <= 0) {
        fprintf(stderr, "Invalid array size\n");
        return -1;
    }
    int* dic = (int*)calloc(n, sizeof(int));
    if (!dic) {
        fprintf(stderr, "Memory allocation failed\n");
        return -1;
    }

    for (int i = 0; i < n; i++) {
        if (dic[arr[i]] == 1) {
            free(dic);
            return arr[i];
        }
        dic[arr[i]] = 1;
    }
    free(dic);
    return -1;
}

int minSum(int* arr, int n) {
    if (n <= 0) return 0;
    qsort(arr, n, sizeof(int), cmp);
    int ans = 0;
    for (int i = 0; i < n; i += 2) {
        ans += abs(arr[i] - arr[i + 1]);
    }
    return ans;
}

int cmp(const void* a, const void* b) {
    return (*(int*)a - *(int*)b);
}

