#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_N 100
#define MAX_M 100

void log_message(const char *message) {
    printf("%s\n", message);
}

int is_valid_input(int n, int m) {
    return n > 0 && m > 0 && n <= MAX_N && m <= MAX_M;
}

int calculate_sum(int grid[MAX_N][MAX_M], int n, int m, int row, int col) {
    int sum = 0;
    int directions[4][2] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};

    for (int i = 0; i < 4; i++) {
        int new_row = row + directions[i][0];
        int new_col = col + directions[i][1];
        if (new_row >= 0 && new_row < n && new_col >= 0 && new_col < m) {
            sum += grid[new_row][new_col];
        }
    }
    return sum;
}

int solve_grid(int n, int m, char grid[MAX_N][MAX_M]) {
    int result[MAX_N][MAX_M] = {0};
    int valid = 1;

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (grid[i][j] == '.') {
                result[i][j] = (i + j) % 2 == 0 ? 1 : 4;
            } else if (grid[i][j] == 'X') {
                int sum = calculate_sum(result, n, m, i, j);
                if (sum % 5 != 0) {
                    valid = 0;
                }
            }
        }
    }

    if (valid) {
        log_message("YES");
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                printf("%d ", result[i][j]);
            }
            printf("\n");
        }
    } else {
        log_message("NO");
    }

    return valid;
}

