#include <math.h>

#define MAX_DIGITS 10
#define ERROR_CODE -1
#define SUCCESS_CODE 0

static const char nums[MAX_DIGITS] = "9876543210";

int find_digit(int A, int B, int K, char *result) {
    long long term;
    for (int i = 0; i < MAX_DIGITS; i++) {
        int powers = (nums[i] - '0' - 7) * (int)pow(10, MAX_DIGITS - i - 1);

        if (powers < 0) {
            fprintf(stderr, "Error: Negative power calculation.\n");
            return ERROR_CODE;
        }

        term = (long long)fmod(pow(A, B), (long long)pow(10, powers));
        char str_num[20];
        snprintf(str_num, sizeof(str_num), "%lld", term);

        if (strlen(str_num) > K) {
            *result = str_num[K];
            return SUCCESS_CODE;
        }
    }

    fprintf(stderr, "Error: K exceeds the number of digits in the term.\n");
    return ERROR_CODE;
}

int kthDigit(int A, int B, int K, char *result) {
    if (A <= 0 || B < 0 || K < 0) {
        fprintf(stderr, "Error: Invalid input values. A, B must be non-negative.\n");
        return ERROR_CODE;
    }

    return find_digit(A, B, K, result);
}

int main() {
    int A = 3;
    int B = 4;
    int K = 2;
    char result;

    if (kthDigit(A, B, K, &result) == SUCCESS_CODE) {
        printf("The %dth digit is: %c\n", K, result);
    } else {
        fprintf(stderr, "Failed to compute the %dth digit.\n", K);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
