#define MAX_SIZE 100

void free_visited(bool **visited, int n) {
    for (int i = 0; i < n; i++) {
        free(visited[i]);
    }
    free(visited);
}

bool is_valid(int i, int j, int n, int m) {
    return (i >= 0 && i < n && j >= 0 && j < m);
}

void dfs(char matrix[MAX_SIZE][MAX_SIZE], int i, int j, bool **visited, char desk_color, char president_color, int n, int m) {
    if (!is_valid(i, j, n, m) || matrix[i][j] == '.' || visited[i][j] || matrix[i][j] == president_color) {
        return;
    }

    visited[i][j] = true;
    for (int di = -1; di <= 1; di++) {
        for (int dj = -1; dj <= 1; dj++) {
            if ((di == 0 && dj == 0) || (abs(di) == abs(dj))) {
                continue;
            }
            int ni = i + di, nj = j + dj;
            if (is_valid(ni, nj, n, m)) {
                dfs(matrix, ni, nj, visited, desk_color, president_color, n, m);
            }
        }
    }
}

int count_deputies(char matrix[MAX_SIZE][MAX_SIZE], char president_color, int n, int m) {
    bool **visited = malloc(n * sizeof(bool *));
    for (int i = 0; i < n; i++) {
        visited[i] = malloc(m * sizeof(bool));
        memset(visited[i], false, m * sizeof(bool));
    }

    int deputies = 0;

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (matrix[i][j] == president_color && !visited[i][j]) {
                dfs(matrix, i, j, visited, president_color, president_color, n, m);
                break;
            }
        }
    }

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (visited[i][j] && matrix[i][j] != president_color) {
                deputies++;
            }
        }
    }

    free_visited(visited, n);
    return deputies;
}

int main() {
    int n, m;
    char president_color;
    if (scanf("%d %d %c", &n, &m, &president_color) != 3 || n <= 0 || n > MAX_SIZE || m <= 0 || m > MAX_SIZE) {
        fprintf(stderr, "Invalid input for dimensions or president color.\n");
        return EXIT_FAILURE;
    }

    char matrix[MAX_SIZE][MAX_SIZE];
    for (int i = 0; i < n; i++) {
        scanf("%s", matrix[i]);
    }

    int deputies_count = count_deputies(matrix, president_color, n, m);
    printf("%d\n", deputies_count);

    return EXIT_SUCCESS;
}

