#define LARGE_PIZZA_SLICES 10
#define MEDIUM_PIZZA_SLICES 8
#define SMALL_PIZZA_SLICES 6
#define LARGE_PIZZA_TIME 25
#define MEDIUM_PIZZA_TIME 20
#define SMALL_PIZZA_TIME 15

int min_cooking_time(int target_slices) {
    if (target_slices < 0) {
        fprintf(stderr, "Error: Target slices must be non-negative.\n");
        return -1;
    }

    int num_large = target_slices / LARGE_PIZZA_SLICES;
    int remaining_slices = target_slices % LARGE_PIZZA_SLICES;

    int num_medium = remaining_slices / MEDIUM_PIZZA_SLICES;
    remaining_slices %= MEDIUM_PIZZA_SLICES;

    int num_small = remaining_slices / SMALL_PIZZA_SLICES;
    if (remaining_slices % SMALL_PIZZA_SLICES != 0) {
        num_small += 1;
    }

    int total_time = (num_large * LARGE_PIZZA_TIME) + 
                     (num_medium * MEDIUM_PIZZA_TIME) + 
                     (num_small * SMALL_PIZZA_TIME);

    if (num_medium >= 3) {
        num_large += 2;
        num_medium -= 3;
    }
    if (num_small >= 4) {
        num_medium += 2;
        num_small -= 4;
    }

    if (num_medium < 0) {
        num_large += 1;
        num_medium += 4;
    }
    if (num_small < 0) {
        num_medium += 1;
        num_small += 4;
    }

    total_time = (num_large * LARGE_PIZZA_TIME) + 
                 (num_medium * MEDIUM_PIZZA_TIME) + 
                 (num_small * SMALL_PIZZA_TIME);

    return total_time;
}

