bool cycle_exists(int *arr, int n) {
    for (int i = 0; i < n; i++) {
        int first = arr[0] - 1;
        int second = arr[1] - 1;
        int last = arr[n - 1] - 1;

        if (first != 0 && second != first + 1 && last == n - 1 && second == last - 1) {
            int sum = 0;
            for (int j = 0; j < n; j++) {
                sum += arr[j];
            }
            if (sum <= 2 * n - 2) {
                return true;
            }
        }
    }
    return false;
}

void generate_permutations(int *arr, int start, int end, int n, int a, int b, int c, int d, int **results, int *count) {
    if (start == end) {
        if (arr[0] == a && arr[end - 1] == b) {
            for (int i = 0; i < end - 1; i++) {
                if (arr[i] == c && arr[i + 1] == d) {
                    if (cycle_exists(arr, end)) {
                        results[*count] = malloc(end * sizeof(int));
                        memcpy(results[*count], arr, end * sizeof(int));
                        (*count)++;
                    }
                    return;
                }
            }
        }
    } else {
        for (int i = start; i < end; i++) {
            int temp = arr[start];
            arr[start] = arr[i];
            arr[i] = temp;

            generate_permutations(arr, start + 1, end, n, a, b, c, d, results, count);

            temp = arr[start];
            arr[start] = arr[i];
            arr[i] = temp;
        }
    }
}

void solution(int n, int k, int a, int b, int c, int d) {
    int *arr = malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        arr[i] = i + 1;
    }

    int **results = malloc(10000 * sizeof(int *));
    int count = 0;

    generate_permutations(arr, 0, n, n, a, b, c, d, results, &count);

    if (count > 0) {
        log_message("Paths found:");
        for (int i = 0; i < count; i++) {
            for (int j = 0; j < n; j++) {
                printf("%d ", results[i][j]);
            }
            printf("\n");
            free(results[i]);
        }
    } else {
        log_message("No valid paths found.");
    }

    free(arr);
    free(results);
}

