void sort_descending(int *arr, int n) {
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (arr[j] < arr[j + 1]) {
                int temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;
            }
        }
    }
}

int max_cards_on_table(int m, int *b, int **result) {
    if (m <= 0 || b == NULL) {
        log_message("Invalid input: array size must be greater than 0 and array cannot be NULL.");
        return 0;
    }

    sort_descending(b, m);

    int *temp_result = (int *)malloc(m * sizeof(int));
    if (temp_result == NULL) {
        log_message("Memory allocation failed.");
        return 0;
    }

    int max_length = 1;
    temp_result[0] = b[0];

    for (int i = 1; i < m; i++) {
        if (b[i] < temp_result[max_length - 1]) {
            temp_result[max_length] = b[i];
            max_length++;
        }
    }

    int *final_result = (int *)malloc(2 * max_length * sizeof(int));
    if (final_result == NULL) {
        log_message("Memory allocation failed.");
        free(temp_result);
        return 0;
    }

    for (int i = 0; i < max_length; i++) {
        final_result[i] = temp_result[max_length - 1 - i];
    }

    int pos = max_length;
    for (int i = max_length - 2; i >= 0; i--) {
        if (b[i] < final_result[0]) {
            final_result[pos] = b[i];
            pos++;
        }
    }

    *result = final_result;

    free(temp_result);

    return max_length;
}

