    int *result = NULL;
    int size = sizeof(cards) / sizeof(cards[0]);

    int length = max_cards_on_table(size, cards, &result);
    if (length > 0) {
        log_message("Successful execution:");
        for (int i = 0; i < length; i++) {
            printf("%d ", result[i]);
        }
