long long solve_bus_passengers(int n, int w, int *a) {
    long long *dp = (long long *)calloc(w + 1, sizeof(long long));
    if (!dp) {
        fprintf(stderr, "Error: Memory allocation failed.\n");
        exit(EXIT_FAILURE);
    }

    dp[0] = 1;
    int min_passengers = 0, max_passengers = 0;

    for (int i = 0; i < n; i++) {
        a[i] %= MOD;
        long long *new_dp = (long long *)calloc(w + 1, sizeof(long long));
        if (!new_dp) {
            free(dp);
            fprintf(stderr, "Error: Memory allocation failed.\n");
            exit(EXIT_FAILURE);
        }

        for (int j = min_passengers; j <= max_passengers; j++) {
            if (j > 0) new_dp[j] = (new_dp[j] + dp[j - 1]) % MOD;
            new_dp[j] = (new_dp[j] + dp[j]) % MOD;
        }

        min_passengers = max(0, min_passengers - a[i]);
        max_passengers = (max_passengers + a[i] > w) ? w : max_passengers + a[i];

        free(dp);
        dp = new_dp;
    }

    long long result = 0;
    for (int j = min_passengers; j <= max_passengers; j++) {
        result = (result + dp[j]) % MOD;
    }

    free(dp);
    return result >= 0 ? result : 0;
}

