    int n, w;
    if (scanf("%d %d", &n, &w) != 2) {
        fprintf(stderr, "Error: Invalid input format.\n");
        return EXIT_FAILURE;
    }

    int *a = (int *)malloc(n * sizeof(int));
    if (!a) {
        fprintf(stderr, "Error: Memory allocation failed.\n");
        return EXIT_FAILURE;
    }

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &a[i]) != 1) {
            free(a);
