void reverse_array(char **words, int n) {
    for (int i = 0; i < n / 2; i++) {
        char *temp = words[i];
        words[i] = words[n - i - 1];
        words[n - i - 1] = temp;
    }
}

void rotate_array(char **words, int n) {
    char *temp = words[n - 1];
    for (int i = n - 1; i > 0; i--) {
        words[i] = words[i - 1];
    }
    words[0] = temp;
}

