char* right_left_encrypt(const char *input) {
    if (!input) return NULL;

    size_t n = strlen(input);
    char *s = malloc(MAX_LENGTH);
    if (!s) {
        log_message("Memory allocation failed");
        return NULL;
    }
    s[0] = '\0';

    while (n) {
        n >>= 1;
        strncat(s, input, (size_t)(1 << n));
        input += (1 << n);
        n = strlen(input);
    }

    return s;
}

char* right_left_decrypt(const char *input) {
    if (!input) return NULL;

    size_t n = strlen(input);
    char *s = malloc(MAX_LENGTH);
    if (!s) {
        log_message("Memory allocation failed");
        return NULL;
    }
    s[0] = '\0';

    while (n) {
        n >>= 1;
        size_t len = (size_t)(1 << n);
        strncat(s, input + strlen(input) - len, len);
        input[strlen(input) - len] = '\0';
        n = strlen(input);
    }

    return s;
}

char* solve(const char *input) {
    return right_left_decrypt(input);
}

