#define MAX_SIZE 100000

typedef struct {
    int key;
    int count;
} Counter;

int find_count(Counter *cnt, int key, int size) {
    for (int i = 0; i < size; i++) {
        if (cnt[i].key == key) {
            return cnt[i].count;
        }
    }
    return 0;
}

void increment_count(Counter *cnt, int key, int *size) {
    for (int i = 0; i < *size; i++) {
        if (cnt[i].key == key) {
            cnt[i].count++;
            return;
        }
    }
    cnt[*size].key = key;
    cnt[*size].count = 1;
    (*size)++;
}

void decrement_count(Counter *cnt, int key, int *size) {
    for (int i = 0; i < *size; i++) {
        if (cnt[i].key == key) {
            cnt[i].count--;
            if (cnt[i].count <= 0) {
                cnt[i] = cnt[--(*size)];
            }
            return;
        }
    }
}

int is_sum_in_set(int *set, int size, int sum) {
    for (int i = 0; i < size; i++) {
        if (set[i] == sum) {
            return 1;
        }
    }
    return 0;
}

int solve(int *a, int n) {
    Counter cnt[MAX_SIZE];
    int cnt_size = 0;

    for (int i = 0; i < n; i++) {
        increment_count(cnt, a[i], &cnt_size);
    }

    int s[MAX_SIZE];
    int s_size = 0;

    for (int i = 0; i < n; i++) {
        for (int j = i; j < n; j++) {
            if (!is_sum_in_set(s, s_size, a[j])) {
                s[s_size++] = a[j];
            }
            int current_count = find_count(cnt, a[j], cnt_size);
            if (current_count > 1) {
                decrement_count(cnt, a[j], &cnt_size);
            } else {
                decrement_count(cnt, a[j], &cnt_size);
            }
            int sum = 0;
            for (int k = 0; k < cnt_size; k++) {
                sum += cnt[k].count;
            }
            if (is_sum_in_set(s, s_size, sum)) {
                return 1;
            }
        }
    }
    return 0;
}

