    return (*(int *)a - *(int *)b);
}

void merge(int *left, int left_size, int *right, int right_size, int *result) {
    int i = 0, j = 0, k = 0;
    while (i < left_size && j < right_size) {
        if (left[i] < right[j]) {
            result[k++] = left[i++];
        } else {
            result[k++] = right[j++];
        }
    }
    while (i < left_size) {
        result[k++] = left[i++];
    }
    while (j < right_size) {
        result[k++] = right[j++];
    }
}

int count_needed(int minimum, int *places, int size) {
    int count = 0;
    for (int i = 0; i < size; i++) {
        if (minimum == places[i]) {
            count++;
        } else if (places[i] > count) {
            count = 0;
        }
    }
    return count;
}

int solve(int *places, int size, int x) {
    int minimum = 0;
    for (int i = 0; i < size; i++) {
        if (places[i] > minimum) {
            minimum = places[i];
        }
    }

    for (int i = 0; i < size; i++) {
        places[i] -= minimum;
    }

    for (int i = 0; i < size; i++) {
        places[i]++;
    }

    while (minimum == 0) {
        minimum++;
    }

    for (int i = 0; i < x; i++) {
        for (int j = 0; j < size; j++) {
            places[j]++;
        }

        if (count_needed(minimum, places, size) > 0) {
            int mid = size / 2;
            int *left = malloc(mid * sizeof(int));
            int *right = malloc((size - mid) * sizeof(int));

            memcpy(left, places, mid * sizeof(int));
            memcpy(right, places + mid, (size - mid) * sizeof(int));

            merge(left, mid, right, size - mid, places);

            free(left);
            free(right);
        }
    }

    for (int i = 0; i < size; i++) {
        places[i] += minimum;
    }
    return places[size - 1];
}

