    if (!s || strlen(s) == 0) {
        log_message("Invalid input: empty string.");
        return 0;
    }
    for (size_t i = 0; i < strlen(s); i++) {
        if (!isdigit(s[i]) && s[i] != '+') {
            log_message("Invalid input: non-numeric character found.");
            return 0;
        }
    }
    return 1;
}

int compare(const void *a, const void *b) {
    const char *string_a = *(const char **)a;
    const char *string_b = *(const char **)b;

    // First compare by length, then lexicographically
    size_t len_a = strlen(string_a);
    size_t len_b = strlen(string_b);
    if (len_a != len_b) {
        return len_a - len_b;
    }
    return strcmp(string_a, string_b);
}

char* xenia_addition(const char *s) {
    if (!is_valid_input(s)) {
        return NULL;
    }

    char *summands[MAX_SUMMANDS];
    int count = 0;

    char *input_copy = strdup(s);
    char *token = strtok(input_copy, "+");

    while (token != NULL && count < MAX_SUMMANDS) {
        summands[count++] = strdup(token);
        token = strtok(NULL, "+");
    }

    free(input_copy);

    // Sort summands
    qsort(summands, count, sizeof(char*), compare);

    // Create the result string
    size_t total_length = 0;
    for (int i = 0; i < count; i++) {
        total_length += strlen(summands[i]) + (i < count - 1 ? 1 : 0); // +1 for '+' if not the last element
    }

    char *result = malloc(total_length + 1);
    if (!result) {
        log_message("Memory allocation failed for result string.");
        for (int i = 0; i < count; i++) free(summands[i]);
        return NULL;
    }

    result[0] = '\0'; // Initialize empty string
    for (int i = 0; i < count; i++) {
        strcat(result, summands[i]);
        if (i < count - 1) {
            strcat(result, "+");
        }
        free(summands[i]); // Clean up individually allocated summands
    }

    return result;
}

