    for (int i = 1; i <= n; i++) {
        if (a[i - 1] % 2 == 0) {
            a_even[i] = i;
        } else {
            a_odd[i] = i;
        }
    }

    for (int i = 1; i <= n; i++) {
        if (a_odd[i] == 0 && (i - a[i - 1]) >= 0) {
            a_odd[i] = a_even[i - a[i - 1]] + 1;
        }
        if (a_even[i] == 0 && (i - a[i - 1]) >= 0) {
            a_even[i] = a_odd[i - a[i - 1]] + 1;
        }
    }
}

