#include <stdio.h>
#include <stdlib.h>

#define MAX_ARRAY_SIZE 1000
#define MAX_UNIQUE_SUMS 100

void calculate_subarray_sums(int *A, int N, int K, int *unique_sums, int *unique_count) {
    int current_sum = 0;
    for (int i = 0; i < K; i++) {
        current_sum += A[i];
    }
    unique_sums[(*unique_count)++] = current_sum;

    for (int i = 1; i <= N - K; i++) {
        current_sum += A[i + K - 1] - A[i - 1];
        int is_unique = 1;
        for (int j = 0; j < *unique_count; j++) {
            if (unique_sums[j] == current_sum) {
                is_unique = 0;
                break;
            }
        }
        if (is_unique) {
            unique_sums[(*unique_count)++] = current_sum;
        }
    }
}

int calculate_modifications(int *A, int N, int K, int target_sum) {
    int modifications = 0;
    for (int i = 0; i <= N - K; i++) {
        int subarray_sum = 0;
        for (int j = 0; j < K; j++) {
            subarray_sum += A[i + j];
        }
        if (subarray_sum != target_sum) {
            modifications += abs(target_sum - subarray_sum);
        }
    }
    return modifications;
}

int min_modifications(int T, int test_cases[][MAX_ARRAY_SIZE + 2], int test_case_count) {
    int results[MAX_ARRAY_SIZE] = {0};

    for (int t = 0; t < T; t++) {
        int N = test_cases[t][0];
        int K = test_cases[t][1];
        int *A = &test_cases[t][2];
        int unique_sums[MAX_UNIQUE_SUMS] = {0};
        int unique_count = 0;

        calculate_subarray_sums(A, N, K, unique_sums, &unique_count);

        if (unique_count == 1) {
            results[t] = 0;
            continue;
        }

        int min_mods = __INT_MAX__;
        for (int i = 0; i < unique_count; i++) {
            int mods = calculate_modifications(A, N, K, unique_sums[i]);
            if (mods < min_mods) {
                min_mods = mods;
            }
        }
        results[t] = min_mods;
    }

    for (int t = 0; t < T; t++) {
        printf("Test Case %d: Minimum Modifications Required = %d\n", t + 1, results[t]);
    }
    return 0;
}

int main() {
    int test_cases[][MAX_ARRAY_SIZE + 2] = {
        {6, 2, 1, 2, 1, 3, 1, 2}, // Example test case
        // Add more test cases as needed
    };
    int T = sizeof(test_cases) / sizeof(test_cases[0]);

    min_modifications(T, test_cases, T);

    return 0;
}

