int calculate_min_k(int *a, int n) {
    int min_k = 0;
    int flag = 1; // all people are in an interesting state

    while (flag) {
        min_k++;
        flag = 0;

        for (int i = 1; i < n - 1; i++) {
            if (a[i - 1] == 1 && a[i + 1] == 1 && a[i] == 0) {
                min_k--;
                a[i] = 1;
                flag = 1; // at least one change made
                break;
            }
            if (i == n - 2 && i == 1 && min_k >= 2) {
                flag = 1; // condition to revisit
                break;
            }
        }
    }
    return min_k;
}

