bool is_magic_number(const char *n) {
    const char *allowed[] = {"1", "14", "144"};
    size_t length = strlen(n);
    size_t i = 0;

    while (i < length) {
        bool found = false;
        for (size_t j = 0; j < 3; j++) {
            size_t allowed_length = strlen(allowed[j]);
            if (strncmp(&n[i], allowed[j], allowed_length) == 0) {
                i += allowed_length;
                found = true;
                break;
            }
        }
        if (!found) {
            return false;
        }
    }
    return true;
}

