    *length = strlen(s);
    for (int i = 0; i < *length; i++) {
        freq[(unsigned char)s[i]]++;
    }
}

bool check_permutation_validity(const char* s) {
    if (!validate_input(s)) {
        log_message("Invalid input string.");
        return false;
    }

    int freq[MAX_CHAR] = {0};
    int length = 0;

    count_frequencies(s, freq, &length);

    for (int i = 0; i < MAX_CHAR; i++) {
        if (freq[i] && freq[i] % length != 0) {
            log_message("Frequency check failed.");
            return false;
        }
    }

    for (int p = 1; p <= length / 2; p++) {
        if (length % p == 0) {
            char reference_char = s[p - 1];
            for (int i = 2; i * p <= length; i++) {
                if (s[i * p - 1] != reference_char) {
                    log_message("Permutation condition failed.");
                    return false;
                }
            }
        }
    }

    log_message("Permutation is valid.");
    return true;
}

