    if (argc != 2) {
        log_message("Usage: program <string>");
        return EXIT_FAILURE;
    }

    const char* input_string = argv[1];

    if (check_permutation_validity(input_string)) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }

