typedef struct Node {
    int data;
    struct Node* left;
    struct Node* right;
} Node;

typedef struct BinaryTree {
    Node* root;
    Node* prev;
} BinaryTree;

Node* create_node(int data) {
    Node* new_node = (Node*)malloc(sizeof(Node));
    if (!new_node) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(EXIT_FAILURE);
    }
    new_node->data = data;
    new_node->left = new_node->right = NULL;
    return new_node;
}

void free_tree(Node* node) {
    if (node) {
        free_tree(node->left);
        free_tree(node->right);
        free(node);
    }
}

Node* convert_to_dll_util(Node* node, Node** head, Node** prev) {
    if (!node) return NULL;

    convert_to_dll_util(node->left, head, prev);

    node->left = *prev;
    if (*prev) {
        (*prev)->right = node;
    } else {
        *head = node;
    }
    *prev = node;

    convert_to_dll_util(node->right, head, prev);
    return *head;
}

Node* convert_to_dll(BinaryTree* tree) {
    Node* head = NULL;
    tree->prev = NULL;
    return convert_to_dll_util(tree->root, &head, &tree->prev);
}

void print_list(Node* node) {
    while (node) {
        printf("%d ", node->data);
        node = node->right;
    }
    printf("\n");
}

