    BinaryTree* tree = (BinaryTree*)malloc(sizeof(BinaryTree));
    if (!tree) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(EXIT_FAILURE);
    }
    tree->root = create_node(root_data);
    tree->prev = NULL;
    return tree;
}

int main() {
