#define MAX_PROBLEMS 1000

void calculate_correct_answers_and_penalties(int N, int M, int* correct_answers, int* penalties, int submissions[MAX_PROBLEMS][2]) {
    int incorrect_submissions[MAX_PROBLEMS] = {0};
    bool ac_received[MAX_PROBLEMS] = {false};

    *correct_answers = 0;
    *penalties = 0;

    for (int i = 0; i < M; i++) {
        int problem_number = submissions[i][0];
        char verdict = (char)submissions[i][1];

        if (verdict == 'A' && !ac_received[problem_number - 1]) {
            (*correct_answers)++;
            *penalties += incorrect_submissions[problem_number - 1];
            ac_received[problem_number - 1] = true;
        } else if (verdict == 'W') {
            incorrect_submissions[problem_number - 1]++;
        }
    }
}

int main() {
    int N, M;
    if (scanf("%d %d", &N, &M) != 2 || N <= 0 || M <= 0 || N > MAX_PROBLEMS) {
        fprintf(stderr, "Invalid input for number of problems or submissions.\n");
        return 1;
    }

    int submissions[MAX_PROBLEMS][2];

    for (int i = 0; i < M; i++) {
        int problem_number;
        char verdict[3]; // 'A' or 'W'
        if (scanf("%d %s", &problem_number, verdict) != 2 || problem_number <= 0 || problem_number > N) {
            fprintf(stderr, "Invalid submission input.\n");
            return 1;
        }
        submissions[i][0] = problem_number;
        submissions[i][1] = verdict[0]; // store first character only
    }

    int correct_answers = 0;
    int penalties = 0;

    calculate_correct_answers_and_penalties(N, M, &correct_answers, &penalties, submissions);

    printf("%d %d\n", correct_answers, penalties);
    return 0;
}

