void printError(const char *msg) {
    fprintf(stderr, "Error: %s\n", msg);
}

int* readArray(int size) {
    int *array = (int *)malloc(size * sizeof(int));
    if (!array) {
        printError("Memory allocation failed for array.");
        exit(EXIT_FAILURE);
    }
    for (int i = 0; i < size; i++) {
        if (scanf("%d", &array[i]) != 1) {
            printError("Invalid input for array.");
            free(array);
            exit(EXIT_FAILURE);
        }
    }
    return array;
}

int contains(int *array, int size, int value) {
    for (int i = 0; i < size; i++) {
        if (array[i] == value)
            return 1;
    }
    return 0;
}

void removeValue(int *array, int *size, int value) {
    for (int i = 0; i < *size; i++) {
        if (array[i] == value) {
            memmove(&array[i], &array[i + 1], (*size - i - 1) * sizeof(int));
            (*size)--;
            i--;
        }
    }
}

void computeResult(int *a, int *b, int n, int m) {
    removeValue(a, &n, b[0]);  // Assuming b[0] is the element we want to remove based on original code behavior
    int *temp = (int *)malloc(n * sizeof(int));
    if (!temp) {
        printError("Memory allocation failed for temp array.");
        exit(EXIT_FAILURE);
    }

    memset(temp, 0, n * sizeof(int));
    for (int i = 0; i < n; i++) {
        temp[i] = (i == 0) ? a[i] : temp[i - 1] + a[i];
    }

    for (int i = 0; i < m; i++) {
        if (contains(a, n, b[i])) {
            a[n++] = b[i];  // Add to end if it exists
            removeValue(a, &n, b[i]);  // Then remove first occurrence
            for (int j = n - 1; j >= 0; j--) a[j] -= temp[j];
        }
    }

    int sum = 0;
    for (int i = 0; i < n; i++) {
        sum += a[i];
    }

    printf("%d\n", sum);
    free(temp);
}

int main() {
    int t;
    if (scanf("%d", &t) != 1 || t <= 0) {
        printError("Invalid number of test cases.");
        return EXIT_FAILURE;
    }

    while (t--) {
        int n, m;
        if (scanf("%d %d", &n, &m) != 2 || n <= 0 || m <= 0) {
            printError("Invalid input for n and m.");
            return EXIT_FAILURE;
        }

        int *a = readArray(n);
        int *b = readArray(m);

        computeResult(a, b, n, m);

        free(a);
        free(b);
    }

    return 0;
}

#include <stdio.h>
