#define MAX_SIZE 100000

void getDiff(const char* s, int* res, size_t size) {
    int diff = 0;
    for (size_t i = 0; i < size; ++i) {
        if (s[i] == '0') {
            diff--;
        } else {
            diff++;
        }
        res[i] = diff;
    }
}

size_t countZeroOrOnePairs(const int* diff, size_t size) {
    int counts[MAX_SIZE] = {0};
    for (size_t i = 0; i < size; ++i) {
        counts[diff[i] + MAX_SIZE / 2]++;
    }

    size_t ans = 0;
    for (int i = 0; i < MAX_SIZE; i++) {
        if (i == MAX_SIZE / 2 || i == MAX_SIZE / 2 + 1) {
            size_t count = counts[i];
            ans += (count - 1) * count / 2;
        }
    }
    return ans;
}

int countSubstrings(const char* s) {
    size_t length = strlen(s);
    if (length == 0) {
        return 0;
    }

    int res[MAX_SIZE] = {0};
    getDiff(s, res, length);
    size_t ans1 = countZeroOrOnePairs(res, length);

    // Reverse string
    char rev[MAX_SIZE];
    for (size_t i = 0; i < length; i++) {
        rev[i] = s[length - 1 - i];
    }
    rev[length] = '\0';

    getDiff(rev, res, length);
    size_t ans2 = countZeroOrOnePairs(res, length);

    return ans1 + ans2;
}

int main() {
    const char* input = "110010"; // Example input
    int result = countSubstrings(input);
    printf("Result: %d\n", result);
    return 0;
}

