#include <stdio.h>
#include <stdlib.h>

int min_time_to_clean_floor(int n, int m, int r_b, int c_b, int r_d, int c_d) {
    if (n <= 0 || m <= 0 || r_b < 1 || r_b > n || c_b < 1 || c_b > m || r_d < 1 || r_d > n || c_d < 1 || c_d > m) {
        fprintf(stderr, "Error: Invalid input parameters.\n");
        return -1;
    }

    int time = 0;
    while (r_b != r_d || c_b != c_d) {
        int dr = 1, dc = 1;
        int x = r_b, y = c_b;

        while (x != r_d || y != c_d) {
            if (x < r_d) {
                dr = -dr;
            }
            if (y < c_d) {
                dc = -dc;
            }
            x += dr;
            y += dc;
            time++;
        }

        if (x <= r_d) {
            dr = -dr;
        }
        if (y <= c_d) {
            dc = -dc;
        }
    }

    return time;
}

int main() {
    int n = 5, m = 5;
    int r_b = 1, c_b = 1, r_d = 5, c_d = 5;

    int result = min_time_to_clean_floor(n, m, r_b, c_b, r_d, c_d);
    if (result != -1) {
        printf("Minimum time to clean the floor: %d\n", result);
    }

    return 0;
}

