int min_matches_to_buy(int n) {
    if (n < 0) {
        log_message("Invalid input: number of matches cannot be negative");
        return -1; // Error case
    }

    if (n >= MIN_MATCHES) {
        int remaining = n - 2; // Matches used for '+' and '='
        if (remaining % 3 == 0) {
            return 0; // No additional matches needed
        } else {
            return 3 - (remaining % 3); // Additional matches to make divisible by 3
        }
    } else {
        return MIN_MATCHES - n; // Matches needed to reach 6
    }
}

