        if (scanf("%d", &n) != 1) {
            log_message("Invalid input: expected an integer for number of matches");
            return 1; // Error case
        }

        int result = min_matches_to_buy(n);
        if (result != -1) {
            printf("Matches to buy: %d\n", result);
        }
