        log_message("Error: Input must contain exactly 12 months.");
        return false;
    }
    for (int i = 0; i < length; i++) {
        if (months[i] < 0) {
            log_message("Error: Month values must be non-negative.");
            return false;
        }
    }
    return true;
}

int calculate_result(int *months, int k) {
    bool found = false;
    for (int i = 0; i < MONTHS_IN_YEAR; i++) {
        if (months[i] >= k) {
            found = true;
            break;
        }
    }

    int j = 0;
    while (j < MONTHS_IN_YEAR - 2) {
        if (months[j] + months[j + 1] + months[j + 2] >= 10) {
            break;
        }
        j++;
    }

    if (found) {
        if (j < 3) return 1;
        else if (j < 6) return 2;
        else if (j < 9) return 2;
        else return 2;
    } else {
        return -1;
    }
}

