#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define MAX_LENGTH 100

int *eq_array;
int eq_array_size = 0;

void push(int value) {
    eq_array = realloc(eq_array, sizeof(int) * (eq_array_size + 1));
    if (!eq_array) {
        perror("Memory allocation failed");
        exit(EXIT_FAILURE);
    }
    eq_array[eq_array_size++] = value;
}

int pop() {
    if (eq_array_size > 0) {
        return eq_array[--eq_array_size];
    }
    fprintf(stderr, "Error: Attempt to pop from empty stack\n");
    exit(EXIT_FAILURE);
}

bool is_sum_of_two_equal(const char *equation) {
    char *ptr;
    int i = 0, count = 0, value;
    char operator = '+';

    while (equation[i] != '\0') {
        if (equation[i] == '=') {
            int tmp = pop();
            push(tmp);
            push(pop());
            return true;
        } else if (equation[i] == '+' || equation[i] == '-') {
            if (operator == '+') {
                push(count);
                count = 0;
            }
            operator = equation[i];
        } else {
            value = strtol(&equation[i], &ptr, 10);
            count = (operator == '+') ? count + value : count - value;
            i += (ptr - &equation[i]) - 1;
        }
        i++;
    }
    push(count);
    return false;
}

bool is_equal_to_zero(const char *equation) {
    char *ptr;
    int i = 0, count = 0, value;
    char operator = '+';

    while (equation[i] != '\0') {
        if (equation[i] == '=') {
            push(pop());
            push(pop());
            return true;
        } else if (equation[i] == '+' || equation[i] == '-') {
            if (operator == '+') {
                push(count);
                count = 0;
            }
            operator = equation[i];
        } else {
            value = strtol(&equation[i], &ptr, 10);
            count = (operator == '+') ? count + value : count - value;
            i += (ptr - &equation[i]) - 1;
        }
        i++;
    }
    push(count);
    return false;
}

char *solve(const char *equation) {
    eq_array = NULL;
    if (!is_sum_of_two_equal(equation) && !is_equal_to_zero(equation)) {
        return "Invalid equation";
    }

    // Free memory and reset eq_array for next use
    free(eq_array);
    eq_array = NULL;
    return "Equation solved";
}

int main() {
    const char *equation = "3+5=8";  // Example input
    printf("%s\n", solve(equation));
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

typedef struct {
    int first;
    int second;
} Pair;

typedef struct {
    Pair *data;
    int size;
    int capacity;
} Map;

void initMap(Map *map, int capacity) {
    map->data = (Pair *)malloc(capacity * sizeof(Pair));
    map->size = 0;
    map->capacity = capacity;
}

void freeMap(Map *map) {
    free(map->data);
}

int findSumIndex(Map *map, int sum) {
    for (int i = 0; i < map->size; i++) {
        if (map->data[i].first == sum) {
            return i;
        }
    }
    return -1;
}

void insertMap(Map *map, int sum, int num) {
    if (map->size >= map->capacity) {
        map->capacity *= 2;
        map->data = (Pair *)realloc(map->data, map->capacity * sizeof(Pair));
    }
    map->data[map->size].first = sum;
    map->data[map->size].second = num;
    map->size++;
}

int calculateDigitSum(int num) {
    int sum = 0;
    while (num > 0) {
        sum += num % 10;
        num /= 10;
    }
    return sum;
}

int maxSum(int *nums, int numsSize) {
    if (nums == NULL || numsSize == 0) {
        fprintf(stderr, "Invalid input.\n");
        return -1;
    }

    Map digitSums;
    initMap(&digitSums, 10);

    int maxSumResult = INT_MIN;

    for (int i = 0; i < numsSize; i++) {
        int num = nums[i];
        int sum = calculateDigitSum(num);
        int index = findSumIndex(&digitSums, sum);

        if (index == -1) {
            insertMap(&digitSums, sum, num);
        } else {
            int prevSum = digitSums.data[index].second;
            maxSumResult = (maxSumResult > prevSum + num) ? maxSumResult : (prevSum + num);
            digitSums.data[index].second = (prevSum > num) ? prevSum : num;
        }
    }

    freeMap(&digitSums);

    return (maxSumResult == INT_MIN) ? -1 : maxSumResult;
}

