// Function to check if a subgrid is determinable
bool isDeterminable(char grid[MAX_DIM][MAX_DIM], int rows, int columns, int x1, int x2, int queries[MAX_QUERIES][2], int queryCount, bool results[MAX_QUERIES]) {
    for (int q = 0; q < queryCount; q++) {
        int y1 = queries[q][0] - 1;
        int y2 = queries[q][1] - 1;
        bool isPossible = true;

        for (int x = x1 - 1; x < x2 && isPossible; x++) {
            for (int y = y1; y <= y2 && isPossible; y++) {
                if (grid[y][x] == 'X') {
                    isPossible = false;
                }
            }
        }
        results[q] = isPossible;
    }
    return true;
}

