void logMessage(const char *message) {
    printf("%s\n", message);
}

// Input validation
bool validateInput(int rows, int columns, int queries[MAX_QUERIES][2], int queryCount) {
    if (rows <= 0 || columns <= 0 || queryCount <= 0) {
        logMessage("Invalid dimensions or query count.");
        return false;
    }
    for (int i = 0; i < queryCount; i++) {
        if (queries[i][0] < 1 || queries[i][0] > rows || queries[i][1] < 1 || queries[i][1] > columns) {
            logMessage("Query indices out of bounds.");
            return false;
        }
    }
    return true;
}

int main() {
    char tests[3][MAX_DIM][MAX_DIM] = {
        {"..XXX", "...X.", "...X.", "...X.", "..XXX"},
        {"X N. E. E. E", "XX NNX. NNX. NNX. NN"},
        {"..XXX", ".....", ".....", ".....", "..XXX"}
    };

    int dimensions[] = {5, 2, 5};
    int queries[3][MAX_QUERIES][2] = {
        {{1, 3}, {4, 5}, {1, 5}},
        {{1, 2}, {2, 5}},
        {{1, 3}, {1, 5}, {1, 5}}
    };
    bool expected[3][MAX_QUERIES] = {
        {true, true, false, true, true, true},
        {false, true, true, true},
        {false, true, false, true, true, true}
    };

    for (int i = 0; i < 3; i++) {
        bool results[MAX_QUERIES] = {false};

        if (validateInput(dimensions[i], strlen(tests[i][0]), queries[i], 3)) {
            isDeterminable(tests[i], dimensions[i], strlen(tests[i][0]), 1, dimensions[i], queries[i], 3, results);
            for (int j = 0; j < 3; j++) {
