    arr_a[x - 1][y] = (arr_a[x - 1][y] * ready0 + ready2) % MOD;
}

int recurr(int x, int y, int deep) {
    if (deep == 0) return 0;
    if (deep == 1) {
        int ready0 = arr_a[x - 1][y - 1];
        int ready2 = arr_a[x - 1][y];
        if (ready0 == (ready2 * (x + y) % MOD)) {
            return 1;
        } else {
            update_values(x, y, ready0, ready2);
            return 0;
        }
    }

    int no1 = recurr(x - 1, y, deep - 1);
    int no2 = recurr(x, y - 1, deep - 1);
    int yes = 0;

    if (no1 == 0 && no2 == 0) {
        int ready1_0 = arr_a[x - 1][y - 1];
        int ready1_2 = arr_a[x][y - 1];
        if (ready1_0 == (ready1_2 * (x + y) % MOD)) {
            yes = 1;
        } else {
            update_values(x, y, ready1_0, ready1_2);
        }
    }

    return yes;
}

