#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>

#define MAX_OPS 100
#define MAX_STR_LEN 50

typedef struct Deque {
    int *data;
    int front;
    int rear;
    int size;
    int capacity;
} Deque;

void initDeque(Deque *deque, int capacity) {
    deque->capacity = capacity;
    deque->front = -1;
    deque->rear = 0;
    deque->size = 0;
    deque->data = (int *)malloc(capacity * sizeof(int));
}

int isFull(Deque *deque) {
    return deque->size == deque->capacity;
}

int isEmpty(Deque *deque) {
    return deque->size == 0;
}

void append(Deque *deque, int value) {
    if (isFull(deque)) {
        fprintf(stderr, "Error: Deque is full!\n");
        return;
    }
    deque->rear = (deque->rear + 1) % deque->capacity;
    deque->data[deque->rear] = value;
    if (deque->front == -1) {
        deque->front = 0;
    }
    deque->size++;
}

void popleft(Deque *deque) {
    if (isEmpty(deque)) {
        fprintf(stderr, "Error: Deque is empty!\n");
        return;
    }
    deque->front = (deque->front + 1) % deque->capacity;
    deque->size--;
    if (isEmpty(deque)) {
        deque->front = -1;
        deque->rear = 0;
    }
}

void removeValue(Deque *deque, int value) {
    int found = 0;
    for (int i = 0; i < deque->size; i++) {
        int index = (deque->front + i) % deque->capacity;
        if (deque->data[index] == value) {
            found = 1;
            for (int j = i; j < deque->size - 1; j++) {
                int nextIndex = (index + 1) % deque->capacity;
                deque->data[index] = deque->data[nextIndex];
                index = nextIndex;
            }
            deque->size--;
            break;
        }
    }
    if (!found) {
        fprintf(stderr, "Warning: Value %d not found for removal.\n", value);
    }
}

void printDeque(Deque *deque) {
    if (isEmpty(deque)) {
        printf("-1\n");
        return;
    }

    for (int i = 0; i < deque->size; i++) {
        int index = (deque->front + i) % deque->capacity;
        printf("%d ", deque->data[index]);
    }
    printf("\n");
}

void freeDeque(Deque *deque) {
    free(deque->data);
}

int main() {
    int t;
    printf("Enter number of operations: ");
    if (scanf("%d", &t) != 1 || t < 1) {
        fprintf(stderr, "Error: Invalid number of operations. Must be >= 1.\n");
        return 1;
    }

    Deque mainDeque;
    initDeque(&mainDeque, MAX_OPS);

    for (int i = 0; i < t; i++) {
        char operation[MAX_STR_LEN];
        int value;
        scanf("%s", operation);

        if (strcmp(operation, "append") == 0) {
            if (scanf("%d", &value) != 1) {
                fprintf(stderr, "Error: Invalid value for append.\n");
                continue;
            }
            append(&mainDeque, value);
        } 
        else if (strcmp(operation, "popleft") == 0) {
            popleft(&mainDeque);
        } 
        else {
            if (sscanf(operation, "remove_%d", &value) == 1) {
                removeValue(&mainDeque, value);
            } else {
                fprintf(stderr, "Error: Unsupported operation '%s'.\n", operation);
            }
        }
    }

    printDeque(&mainDeque);
    freeDeque(&mainDeque);
    return 0;
}

