long max_burles_spent(long s) {
    if (s < 0) {
        fprintf(stderr, "Error: Starting amount cannot be negative.\n");
        exit(EXIT_FAILURE);
    }

    long total_spent = 0;
    while (s >= 10) {
        long cashback = s / 10;
        total_spent += cashback;
        s -= cashback * 10;
    }
    total_spent += s;
    return total_spent;
}

