    }
}

bool validate_inputs(int n, int m, int *colors, int *target_counts) {
    if (n <= 0 || m <= 0) {
        fprintf(stderr, "Error: Number of knights and colors must be positive.\n");
        return false;
    }
    if (colors == NULL || target_counts == NULL) {
        fprintf(stderr, "Error: Colors and target counts cannot be NULL.\n");
        return false;
    }
    return true;
}

bool solve(int n, int m, int *colors, int *target_counts) {
    int interval_length = 0;
    for (int i = 0; i < m; i++) {
        interval_length += target_counts[i];
    }

    for (int start_idx = 0; start_idx <= n - interval_length; start_idx++) {
        int *color_counts = (int *)calloc(m, sizeof(int));
        if (!color_counts) {
            fprintf(stderr, "Error: Memory allocation failed.\n");
            return false;
        }

        for (int j = start_idx; j < start_idx + interval_length; j++) {
            if (colors[j] > 0 && colors[j] <= m) {
                color_counts[colors[j] - 1]++;
            }
        }

        bool match = true;
        for (int i = 0; i < m; i++) {
            if (color_counts[i] != target_counts[i]) {
                match = false;
                break;
            }
        }
        free(color_counts);

        if (match) {
            return true;
        }
    }
    return false;
}

int main() {
    int n, m;
    if (scanf("%d %d", &n, &m) != 2) {
        fprintf(stderr, "Error: Invalid input format.\n");
        return EXIT_FAILURE;
