        fprintf(stderr, "Error: Input values must be positive.\n");
        return EXIT_FAILURE;
    }

    int *colors = (int *)malloc(n * sizeof(int));
    int *target_counts = (int *)malloc(m * sizeof(int));
    if (!colors || !target_counts) {
