#define RETURN_MOD 998244353

long long reduce_product(int *list, int length) {
    long long product = 1;
    for (int i = 0; i < length; i++) {
        product *= list[i];
    }
    return product;
}

void group_by_sorted_prods(int *prods, int length, long long *output_sum) {
    int count = 1;
    *output_sum = 0;

    for (int i = 1; i < length; i++) {
        if (prods[i] == prods[i - 1]) {
            count++;
        } else {
            *output_sum += prods[i - 1] * count;
            count = 1;
        }
    }
    *output_sum += prods[length - 1] * count; // last element
}

long long calculate_sum(int n, int *myList) {
    long long *prods = malloc(n * sizeof(long long));
    if (prods == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(EXIT_FAILURE);
    }

    for (int ix = 0; ix < n; ix++) {
        prods[ix] = reduce_product(myList, ix + 1);
    }

    long long output_sum = 0;
    group_by_sorted_prods(prods, n, &output_sum);
    free(prods);

    return output_sum % RETURN_MOD;
}

long long calculate_decon_value(int n, long long val_mod, int m, int v) {
    return (val_mod * (1e9 - 1)) / (((pow(10, n) - 1) % ((long long)pow(10, m))));
}

int main() {
    int tc;
