            return EXIT_FAILURE;
        }

        for (int i = 0; i < n; i++) {
            if (scanf("%d", &myList[i]) != 1) {
                fprintf(stderr, "Invalid input for myList\n");
                free(myList);
                return EXIT_FAILURE;
