#define LOG(msg) fprintf(stderr, "%s\n", msg)
#define ERROR(msg) { LOG(msg); exit(EXIT_FAILURE); }

bool validate_input(int *arr, int size);
bool can_partition_into_three(int *arr, int size);
int find_partitions(int *arr, int size, int target_sum, int current_sum, int count);
void free_memory(int *arr);

int main(int argc, char *argv[]) {
    if (argc < 2) {
        ERROR("Insufficient arguments. Provide integers.");
    }

    int size = argc - 1;
    int *arr = (int *)malloc(size * sizeof(int));
    if (!arr) {
        ERROR("Memory allocation failed.");
    }

    for (int i = 0; i < size; i++) {
        arr[i] = atoi(argv[i + 1]);
        if (arr[i] < 2) {
            free_memory(arr);
            ERROR("All integers must be >= 2.");
        }
    }

    if (!validate_input(arr, size)) {
        free_memory(arr);
        ERROR("Input integers must be distinct.");
    }

    if (can_partition_into_three(arr, size)) {
        LOG("Can be partitioned into three subsets.");
    } else {
        LOG("Cannot be partitioned into three subsets.");
    }

    free_memory(arr);
    return 0;
}

bool validate_input(int *arr, int size) {
    for (int i = 0; i < size; i++) {
        for (int j = i + 1; j < size; j++) {
            if (arr[i] == arr[j]) {
                return false;
            }
        }
    }
    return true;
}

bool can_partition_into_three(int *arr, int size) {
    int total_sum = 0;
    for (int i = 0; i < size; i++) {
        total_sum += arr[i];
    }

    if (total_sum % 3 != 0) {
        return false;
    }

    return find_partitions(arr, size, total_sum / 3, 0, 0) >= 3;
}

int find_partitions(int *arr, int size, int target_sum, int current_sum, int count) {
    if (count == 3) return 1;
    if (current_sum == target_sum) return find_partitions(arr, size, target_sum, 0, count + 1);

    for (int i = 0; i < size; i++) {
        if (current_sum + arr[i] <= target_sum) {
            int temp = arr[i];
            arr[i] = -1; // mark as used
            int result = find_partitions(arr, size, target_sum, current_sum + temp, count);
            arr[i] = temp; // backtrack
            if (result != 0) return result;
        }
    }
    return 0;
}

void free_memory(int *arr) {
    free(arr);
}

#include <stdio.h>
#include <string.h>
#include <math.h>
#include <stdbool.h>

#define MAX_LENGTH 100

int countDivisibleTwentyFive(const char *s) {
    if (s == NULL) {
        fprintf(stderr, "Error: Input string is NULL\n");
        return -1; // Indicate error
    }

    int count = 0, leadingZeros = 0, xs = 0;

    // Count leading zeros and X's
    for (int i = 0; s[i] != '\0'; i++) {
        if (s[i] == '_') leadingZeros++;
        else if (s[i] == 'X') xs++;
    }

    // If there are leading zeros, ignore them
    if (leadingZeros > 0) {
        s += leadingZeros;
        leadingZeros = 0;
    }

    // Validate the modified string
    if (strlen(s) < 2 || xs == 0) return 0;

    // Check each digit for X's
    for (int digit = 0; digit <= 9; digit++) {
        int num = 0, j = 0;

        for (int i = strlen(s) - 1; i >= 0; i--) {
            if (s[i] == 'X') {
                num += digit * (int)pow(10, j);
            } else if (s[i] >= '0' && s[i] <= '9') {
                num += (s[i] - '0') * (int)pow(10, j);
            } else {
                fprintf(stderr, "Error: Invalid character in input string\n");
                return -1; // Indicate error
            }
            j++;
        }

        // Check if the number is divisible by 25
        if (num % 25 == 0) count++;
    }

    return count;
}

int main() {
    const char *testCases[] = {
        "25",
        "_00",
        "_XX",
        "0",
        "0_25",
        NULL
    };

    for (int i = 0; testCases[i] != NULL; i++) {
        int result = countDivisibleTwentyFive(testCases[i]);
        if (result >= 0) {
            printf("Input: %s, Count of divisible by 25: %d\n", testCases[i], result);
        } else {
            printf("Input: %s, Error occurred\n", testCases[i]);
        }
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

bool* Sieve(int n) {
    bool *prime = malloc((n+1) * sizeof(bool));
    if (!prime) {
        perror("Memory allocation failed");
        exit(EXIT_FAILURE);
    }
    for (int i = 0; i <= n; i++) {
        prime[i] = true;
    }

    for (int p = 2; p * p <= n; p++) {
        if (prime[p]) {
            for (int i = p * p; i <= n; i += p) {
                prime[i] = false;
            }
        }
    }
    return prime;
}

int countPrime(int n) {
    if (n < 2) return 0;
    bool *prime = Sieve(n);
    int count = 0;
    for (int i = 2; i <= n; i++) {
        if (prime[i]) count++;
    }
    free(prime);
    return count;
}

int main() {
    int n, m;
    printf("Enter two numbers: ");
    if (scanf("%d %d", &n, &m) != 2 || n <= 0 || m <= 0) {
        fprintf(stderr, "Invalid input. Please enter two positive integers.\n");
        return EXIT_FAILURE;
    }

    if (n > m) {
        int temp = n;
        n = m;
        m = temp;
    }

    if (n == 1) {
        printf("%d\n", m);
    } else if (n == 2) {
        printf("%d\n", m <= 4 ? m : 4);
    } else if (n == 3) {
        printf("%d\n", m <= 4 ? m : countPrime(m));
    } else {
        printf("%d\n", countPrime(n) + countPrime(m) - 1);
    }

    return EXIT_SUCCESS;
}

