#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_SIZE 100000
#define INIT_SIZE 10

typedef struct {
    int *data;
    size_t size;
    size_t capacity;
} ArrayList;

typedef struct {
    int key;
    ArrayList value;
} HashMapEntry;

typedef struct {
    HashMapEntry *entries;
    size_t size;
    size_t capacity;
} HashMap;

void initArrayList(ArrayList *list) {
    list->size = 0;
    list->capacity = INIT_SIZE;
    list->data = malloc(INIT_SIZE * sizeof(int));
}

void addToArrayList(ArrayList *list, int value) {
    if (list->size >= list->capacity) {
        list->capacity *= 2;
        list->data = realloc(list->data, list->capacity * sizeof(int));
    }
    list->data[list->size++] = value;
}

void initHashMap(HashMap *map) {
    map->size = 0;
    map->capacity = INIT_SIZE;
    map->entries = malloc(INIT_SIZE * sizeof(HashMapEntry));
}

void putHashMap(HashMap *map, int key, int value) {
    for (size_t i = 0; i < map->size; i++) {
        if (map->entries[i].key == key) {
            addToArrayList(&map->entries[i].value, value);
            return;
        }
    }
    if (map->size >= map->capacity) {
        map->capacity *= 2;
        map->entries = realloc(map->entries, map->capacity * sizeof(HashMapEntry));
    }
    map->entries[map->size].key = key;
    initArrayList(&map->entries[map->size].value);
    addToArrayList(&map->entries[map->size].value, value);
    map->size++;
}

ArrayList *getHashMap(HashMap *map, int key) {
    for (size_t i = 0; i < map->size; i++) {
        if (map->entries[i].key == key) {
            return &map->entries[i].value;
        }
    }
    return NULL;
}

void computeSlope(int *array, int size) {
    HashMap map;
    initHashMap(&map);

    for (int i = 0; i < size; i++) {
        putHashMap(&map, array[i], i);
    }

    int *left = calloc(size, sizeof(int));
    int *right = calloc(size, sizeof(int));
    int *slope = calloc(size, sizeof(int));

    for (int i = 0; i < size; i++) {
        ArrayList *list = getHashMap(&map, array[i]);
        if (list) {
            int index = list->data[list->size - 1];
            right[index] = i + list->size;
            if (list->size > 1 && index < size - 1) {
                right[index] = (right[index] < list->data[list->size - 2]) ? list->data[list->size - 2] : right[index];
            }
            int cur = right[index] - i;
            slope[i] = cur;
        }
    }

    // Utilize the calculated slopes for further processing

    free(left);
    free(right);
    free(slope);
    free(map.entries);
}

int main() {
    int n;
    printf("Enter size: ");
    if (scanf("%d", &n) != 1 || n <= 0 || n > MAX_SIZE) {
        fprintf(stderr, "Invalid input.\n");
        return 1;
    }

    int *array = malloc(n * sizeof(int));
    printf("Enter elements: ");
    for (int i = 0; i < n; i++) {
        if (scanf("%d", &array[i]) != 1) {
            fprintf(stderr, "Invalid element input.\n");
            free(array);
            return 1;
        }
    }

    computeSlope(array, n);

    free(array);
    return 0;
}

