typedef struct {
    int x, y;
} Point;

void log_error(const char *message) {
    fprintf(stderr, "Error: %s\n", message);
}

int compare_points(const void *a, const void *b) {
    Point *pointA = (Point *)a;
    Point *pointB = (Point *)b;
    if (pointA->x != pointB->x) 
        return pointA->x - pointB->x;
    return pointA->y - pointB->y;
}

void generate_path(Point *arr, int n) {
    char path[MAX_PATH_LENGTH] = {0};
    int max_x = 0, max_y = 0;

    for (int i = 0; i < n; i++) {
        if (arr[i].x < max_x || arr[i].y < max_y) {
            log_error("Invalid path; cannot move backwards");
            return;
        }
        for (int j = 0; j < arr[i].x - max_x; j++) {
            strncat(path, "R", MAX_PATH_LENGTH - strlen(path) - 1);
        }
        for (int j = 0; j < arr[i].y - max_y; j++) {
            strncat(path, "U", MAX_PATH_LENGTH - strlen(path) - 1);
        }
        max_x = arr[i].x;
        max_y = arr[i].y;
    }

    printf("YES\n%s\n", path);
}

