#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int numerator;
    int denominator;
} Fraction;

void print_error(const char *message) {
    fprintf(stderr, "Error: %s\n", message);
    exit(EXIT_FAILURE);
}

Fraction simplify_fraction(Fraction frac) {
    int gcd, a = frac.numerator, b = frac.denominator;
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    gcd = a;
    frac.numerator /= gcd;
    frac.denominator /= gcd;
    return frac;
}

Fraction calculate_probability(int N, int M) {
    if (N <= 0 || M <= 0) {
        print_error("N and M must be positive integers.");
    }

    int even_N = N / 2;
    int odd_N = N - even_N;
    int even_M = M / 2;
    int odd_M = M - even_M;

    int favorable = (odd_N * even_M) + (even_N * odd_M);
    int total = N * M;

    Fraction result = {favorable, total};
    return simplify_fraction(result);
}

void solve() {
    char *line = NULL;
    size_t len = 0;
    ssize_t read;

    read = getline(&line, &len, stdin);
    if (read == -1) {
        print_error("Failed to read input.");
    }

    int T = atoi(line);
    if (T <= 0) {
        print_error("The number of test cases must be positive.");
    }

    int *results_numerator = malloc(T * sizeof(int));
    int *results_denominator = malloc(T * sizeof(int));
    if (results_numerator == NULL || results_denominator == NULL) {
        print_error("Memory allocation failed.");
    }

    for (int i = 0; i < T; i++) {
        if (getline(&line, &len, stdin) == -1) {
            print_error("Failed to read test case input.");
        }

        int N, M;
        if (sscanf(line, "%d %d", &N, &M) != 2) {
            print_error("Invalid input format. Expected two integers.");
        }

        Fraction prob = calculate_probability(N, M);
        results_numerator[i] = prob.numerator;
        results_denominator[i] = prob.denominator;
    }

    for (int i = 0; i < T; i++) {
        printf("%d/%d\n", results_numerator[i], results_denominator[i]);
    }

    free(results_numerator);
    free(results_denominator);
    free(line);
}

int main() {
    solve();
    return 0;
}

