#define MOD 998244353

long long paintFence(int n, int m, int k) {
    if (n <= 0 || m <= 0) {
        fprintf(stderr, "Error: Both n and m must be greater than 0.\n");
        return -1;
    }

    long long *ways = (long long *)malloc(n * sizeof(long long));
    if (ways == NULL) {
        fprintf(stderr, "Error: Memory allocation failed.\n");
        return -1;
    }

    ways[0] = m;

    for (int i = 1; i < n; ++i) {
        if (k > 0) {
            ways[i] = (ways[i - 1] + ((ways[i - 1] + m) * (i - 1)) % MOD) % MOD) % MOD;
        } else {
            ways[i] = ways[0];
        }
    }

    long long result = ways[n - 1] % MOD;
    free(ways);
    return result;
}

