// Function to split input and validate it
int parse_input(char *input, int *n, int *k, int scores[], int *size) {
    char *token = strtok(input, " ");
    *size = 0;

    if (token == NULL) return -1;
    *n = atoi(token);

    token = strtok(NULL, " ");
    if (token == NULL) return -1;
    *k = atoi(token);

    while ((token = strtok(NULL, " ")) != NULL) {
        if (*size >= MAX_SCORES) return -1;
        scores[(*size)++] = atoi(token);
    }

    return 0;
}

// Main function to calculate the count based on the scores
int calculate_count(int scores[], int size, int k) {
    int rank = 1;
    int count = 0;
    int threshold = -1;

    for (int i = 0; i < size; i++) {
        int score = scores[i];

        if (rank >= k && (threshold == -1 || score < threshold)) {
            threshold = score;
            count++;
        } 
        else if (score <= 0) {
            break;
        }

        rank++;
    }

    return count;
}

// Logger function for messages
void log_message(const char *message) {
    printf("%s\n", message);
}

int main() {
    char input_buffer[BUFFER_SIZE];
    int n, k, scores[MAX_SCORES], size;

    log_message("Enter the number of scores followed by k and the scores:");

    if (fgets(input_buffer, sizeof(input_buffer), stdin) == NULL) {
        log_message("Error reading input.");
        return EXIT_FAILURE;
    }

    if (parse_input(input_buffer, &n, &k, scores, &size) != 0) {
        log_message("Invalid input format or data.");
        return EXIT_FAILURE;
    }

    if (k <= 0 || n <= 0 || size != n) {
        log_message("Invalid number of scores or k.");
        return EXIT_FAILURE;
    }

    int count = calculate_count(scores, size, k);

    printf("%d\n", count);

    return EXIT_SUCCESS;
}

