void validateInput(int **mat, int R, int C, int K) {
    if (mat == NULL || R <= 0 || C <= 0 || K < 0) {
        fprintf(stderr, "Invalid input parameters.\n");
        exit(EXIT_FAILURE);
    }
}

int** matrixBlockSum(int **mat, int R, int C, int K) {
    validateInput(mat, R, C, K);

    int **dp = (int **)malloc((R + 1) * sizeof(int *));
    int **res = (int **)malloc(R * sizeof(int *));
    for (int i = 0; i < R + 1; i++) {
        dp[i] = (int *)calloc(C + 1, sizeof(int));
    }
    for (int i = 0; i < R; i++) {
        res[i] = (int *)malloc(C * sizeof(int));
    }

    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            dp[i + 1][j + 1] = dp[i + 1][j] + dp[i][j + 1] - dp[i][j] + mat[i][j];
        }
    }

    for (int r = 0; r < R; r++) {
        for (int c = 0; c < C; c++) {
            int rr1 = (r - K < 0) ? 0 : r - K;
            int cc1 = (c - K < 0) ? 0 : c - K;
            int rr2 = (r + K + 1 > R) ? R : r + K + 1;
            int cc2 = (c + K + 1 > C) ? C : c + K + 1;
            res[r][c] = dp[rr2][cc2] - dp[rr1][cc2] - dp[rr2][cc1] + dp[rr1][cc1];
        }
    }

    for (int i = 0; i < R + 1; i++) {
        free(dp[i]);
    }
    free(dp);
    return res;
}

void freeMatrix(int **matrix, int rows) {
    for (int i = 0; i < rows; i++) {
        free(matrix[i]);
    }
    free(matrix);
}

void printMatrix(int **matrix, int rows, int cols) {
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%d ", matrix[i][j]);
        }
        printf("\n");
    }
}

