    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            mat[i][j] = counter++;
        }
    }

    int **result = matrixBlockSum(mat, R, C, K);
    printMatrix(result, R, C);

    freeMatrix(mat, R);
    freeMatrix(result, R);
    return 0;
}

