        freq[(unsigned char)str[i]]++;
    }
}

bool can_make_equal(const char* S, const char* T) {
    if (!validate_input(S, T)) {
        fprintf(stderr, "Error: Invalid input strings.\n");
        return false;
    }

    size_t len_S = strlen(S);
    size_t len_T = strlen(T);

    if (len_S != len_T) {
        return false;
    }

    int freq_S[MAX_CHARS] = {0};
    int freq_T[MAX_CHARS] = {0};

    count_frequency(S, freq_S);
    count_frequency(T, freq_T);

    int distinct_S = 0, distinct_T = 0;
    int count_array_S[MAX_CHARS] = {0};
    int count_array_T[MAX_CHARS] = {0};

    for (int i = 0; i < MAX_CHARS; i++) {
        if (freq_S[i] > 0) {
            distinct_S++;
            count_array_S[freq_S[i]]++;
        }
        if (freq_T[i] > 0) {
            distinct_T++;
            count_array_T[freq_T[i]]++;
        }
    }

    if (distinct_S != distinct_T) {
        return false;
    }

    int sorted_count_S[MAX_CHARS] = {0};
    int sorted_count_T[MAX_CHARS] = {0};
    for (int i = 0; i < MAX_CHARS; i++) {
        if (count_array_S[i] > 0) {
            sorted_count_S[count_array_S[i]]++;
        }
        if (count_array_T[i] > 0) {
            sorted_count_T[count_array_T[i]]++;
        }
    }

    for (int i = 0; i < MAX_CHARS; i++) {
        if (sorted_count_S[i] != sorted_count_T[i]) {
            return false;
        }
    }

    int unique_chars_S = 0, unique_chars_T = 0;
    for (int i = 0; i < MAX_CHARS; i++) {
        if (freq_S[i] > 0) unique_chars_S++;
        if (freq_T[i] > 0) unique_chars_T++;
