#define MAXN (200005)
#define MAX_POS (MAXN * 4)
#define INF (1000000000)

int n, q;
int a[MAXN];
int *pos[MAX_POS];
int ans[2 * MAXN];
int pos_count = 0;

void free_positions() {
    for (int i = 0; i < pos_count; i++) {
        free(pos[i]);
    }
}

int getMinOdd(int l, int r) {
    int res = INF;
    for (int i = 0; i < 32; i++) {
        int left = 0, right = 0;
        while (left < pos_count && pos[i][left] < l) {
            left++;
        }
        while (right < pos_count && pos[i][right] <= r) {
            right++;
        }
        if ((right - left) % 2) {
            res = (res < i) ? res : i;
        }
    }
    return (res == INF) ? 0 : res;
}

void preprocess() {
    int *mp = malloc(sizeof(int) * MAXN);
    memset(mp, -1, sizeof(int) * MAXN);

    for (int i = 0; i < n; i++) {
        if (mp[a[i]] == -1) {
            mp[a[i]] = pos_count++;
            pos[mp[a[i]]] = (int *)malloc(sizeof(int) * (n + 1));
            memset(pos[mp[a[i]]], 0, sizeof(int) * (n + 1));
        }
        pos[mp[a[i]]][mp[a[i]]] = i + 1;
    }

    free(mp);
}

