void sort_array(int *a, int n) {
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (a[j] > a[j + 1]) {
                int temp = a[j];
                a[j] = a[j + 1];
                a[j + 1] = temp;
            }
        }
    }
}

int solve(int n, int *a) {
    if (n <= 0 || !a) {
        fprintf(stderr, "Invalid input: array is null or size is non-positive.\n");
        return -1;
    }

    sort_array(a, n);
    int count = 0;

    for (int i = 0; i < n; i++) {
        if (a[i] >= count + 1) {
            count++;
        } else {
            return count;
        }
    }
    return count;
}

