#define MAX_DESIRES 1000
#define ERROR_EXIT(msg) do { fprintf(stderr, "%s\n", msg); exit(EXIT_FAILURE); } while(0)

typedef struct {
    int x;
    int y;
    char c;
} Desire;

int find_maximum_satisfied_desires(int N, int K, Desire desires[]) {
    int black_squares = 0;
    int white_squares = K * K;

    for (int i = 0; i < N; i++) {
        int pos = (desires[i].x / K) * K + desires[i].y;

        if (desires[i].c == 'B') {
            if (pos <= black_squares) {
                black_squares = pos;
            }
        } else {
            if (pos <= white_squares) {
                white_squares = pos;
            }
        }
    }

    return (black_squares < white_squares) ? black_squares : white_squares;
}

int main() {
    int N, K;
    Desire desires[MAX_DESIRES];

    if (scanf("%d %d", &N, &K) != 2 || N < 1 || K < 1 || N > MAX_DESIRES) {
        ERROR_EXIT("Invalid input for N or K.");
    }

    for (int i = 0; i < N; i++) {
        if (scanf("%d %d %c", &desires[i].x, &desires[i].y, &desires[i].c) != 3) {
            ERROR_EXIT("Invalid input for desire.");
        }
        if (desires[i].c != 'B' && desires[i].c != 'W') {
            ERROR_EXIT("Desire color must be 'B' or 'W'.");
        }
    }

    int result = find_maximum_satisfied_desires(N, K, desires);
    printf("%d\n", result);

    return 0;
}

