void swap_rows(int matrix[MATRIX_SIZE][MATRIX_SIZE], int row1, int row2) {
    for (int j = 0; j < MATRIX_SIZE; j++) {
        int temp = matrix[row1][j];
        matrix[row1][j] = matrix[row2][j];
        matrix[row2][j] = temp;
    }
}

void swap_columns(int matrix[MATRIX_SIZE][MATRIX_SIZE], int col1, int col2) {
    for (int i = 0; i < MATRIX_SIZE; i++) {
        int temp = matrix[i][col1];
        matrix[i][col1] = matrix[i][col2];
        matrix[i][col2] = temp;
    }
}

