int count_even_odd(int *a, int n, int *even_count, int *odd_count) {
    *even_count = 0;
    *odd_count = 0;
    for (int i = 0; i < n; i++) {
        if (a[i] % 2 == 0) {
            (*even_count)++;
        } else {
            (*odd_count)++;
        }
    }
    return 0;
}

int count_even_odd_indices(int n, int *even_indices, int *odd_indices) {
    *even_indices = 0;
    *odd_indices = 0;
    for (int i = 0; i < n; i++) {
        if (i % 2 == 0) {
            (*even_indices)++;
        } else {
            (*odd_indices)++;
        }
    }
    return 0;
}

int count_misplaced(int *a, int n) {
    int odd_misplaced = 0;
    int even_misplaced = 0;

    for (int i = 0; i < n; i++) {
        if (i % 2 == 0 && a[i] % 2 == 1) {
            odd_misplaced++;
        } else if (i % 2 == 1 && a[i] % 2 == 0) {
            even_misplaced++;
        }
    }

    return (odd_misplaced + even_misplaced) / 2;
}

int solve(int *a, int n) {
    int even_count, odd_count, even_indices, odd_indices;

    if (validate_input(n, a) == -1) return -1;

    count_even_odd(a, n, &even_count, &odd_count);
    count_even_odd_indices(n, &even_indices, &odd_indices);

    if (even_count != even_indices) {
        return -1;
    }

    return count_misplaced(a, n);
}

