int find_integer_point(int A, int B, int C, int *x, int *y) {
    if (B != 0) {
        *x = 0;
        *y = -C / B;
        if (A * (*x) + B * (*y) + C == 0) {
            return SUCCESS;
        }
    }

    if (A != 0) {
        *y = 0;
        *x = -C / A;
        if (A * (*x) + B * (*y) + C == 0) {
            return SUCCESS;
        }
    }

    return ERROR_NO_INTEGER_POINT;
}

