#include <stdio.h>
#include <stdlib.h>

#define MAX_LENGTH 1000

void generate_permutations(int length, int k) {
    int groups[MAX_LENGTH][2];
    int group_count = 0;
    int i = 0, j = 1;

    while (i < k) {
        if (j * 2 > group_count && i < k) {
            for (j = 1; j < length; j++) {
                if (i < k) {
                    groups[group_count][0] = j - 1;
                    groups[group_count][1] = j;
                    group_count++;
                    i++;
                }
                if (i < k) {
                    groups[group_count][0] = j;
                    groups[group_count][1] = j - 1;
                    group_count++;
                    i++;
                }
            }
        }
        if (j < j * 2) {
            if (i < k) {
                groups[group_count][0] = groups[(j - 1) * 2][1];
                groups[group_count][1] = groups[(j - 1) * 2 + 1][1];
                group_count++;
                i++;
            }
        }
    }

    int final[MAX_LENGTH];
    for (int f = 0; f < k; f++) final[f] = f;

    for (int g = 0; g < group_count; g++) {
        int a = groups[g][0];
        int b = groups[g][1];
        int a_end = a;
        int b_end = a + 1;
        while (a_end < k && b_end < k) {
            int temp = final[a_end];
            final[a_end] = final[b_end];
            final[b_end] = temp;
            a_end += 2;
            b_end += 2;
        }
    }

    for (int f = 0; f < k; f++) {
        if (f > 0) printf(" ");
        printf("%d", final[f] + 1);
    }
    printf("\n");
}

int main() {
    char input[100];
    int test_cases, length, k;

    if (!fgets(input, sizeof(input), stdin) || sscanf(input, "%d", &test_cases) != 1) {
        fprintf(stderr, "Error reading number of test cases.\n");
        return EXIT_FAILURE;
    }

    for (int t = 0; t < test_cases; t++) {
        if (!fgets(input, sizeof(input), stdin) || sscanf(input, "%d %d", &length, &k) != 2 || length <= 0 || k <= 0) {
            fprintf(stderr, "Error reading length and k values.\n");
            continue;
        }

        if (k > 1) {
            generate_permutations(length, k);
        } else {
            printf("1");
            if (k == 3) printf(" 2 3");
            printf("\n");
        }
    }

    return EXIT_SUCCESS;
}

