int exchange_cookies(int a, int b, int c) {
    if (a < 0 || b < 0 || c < 0) {
        fprintf(stderr, "Error: All cookie counts must be non-negative.\n");
        return -1;
    }

    if (a % 2 == 1 || b % 2 == 1 || c % 2 == 1) {
        printf("Returning -1: Odd counts present.\n");
        return -1;
    }

    int iterations = 0;

    while (a % 2 == 0 && b % 2 == 0 && c % 2 == 0) {
        int temp_a = b + c / 2;
        int temp_b = a + c / 2;

        if (temp_a < 0 || temp_b < 0) {
            fprintf(stderr, "Error: Resulting cookie counts are invalid.\n");
            return -1;
        }

        a = temp_a;
        b = temp_b;

        iterations++;
    }

    printf("Total iterations: %d\n", iterations);
    return iterations;
}

