// Function to split the deck based on values
void split_deck(int *deck, int n, int **result, int *result_size) {
    int *split_points = (int *)calloc(n + 1, sizeof(int));
    int *split_index = (int *)calloc(n + 1, sizeof(int));
    *result_size = 0;

    for (int i = 0; i < n; i++) {
        int value = deck[i];
        if (value <= n) {
            split_points[value]++;
        }
    }

    for (int i = 1; i <= n; i++) {
        if (split_points[i] > 0) {
            for (int j = 0; j < split_points[i]; j++) {
                (*result)[(*result_size)++] = i;
            }
        } else {
            (*result)[(*result_size)++] = i;
        }
    }

    free(split_points);
    free(split_index);
}

// Helper function to sort the deck
void sort_deck(int *deck, int n, int **operations, int *op_size) {
    *op_size = 0;
    int current_deck_size = n;

    while (1) {
        int *new_deck = (int *)malloc(n * sizeof(int));
        int new_size = 0;

        split_deck(deck, current_deck_size, &new_deck, &new_size);

        (*operations)[*op_size] = new_deck;
        (*op_size)++;

        if (memcmp(new_deck, deck, current_deck_size * sizeof(int)) == 0) {
            free(new_deck);
            break;
        }

        free(deck);
        deck = new_deck;
    }

    free(deck);
}

// Main function
int main() {
    int n;

    if (scanf("%d", &n) != 1 || n <= 0) {
        fprintf(stderr, "Invalid input for deck size.\n");
        return EXIT_FAILURE;
    }

    int *deck = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        if (scanf("%d", &deck[i]) != 1 || deck[i] < 1 || deck[i] > n) {
            fprintf(stderr, "Invalid input for deck values.\n");
            free(deck);
            return EXIT_FAILURE;
        }
    }

    int **operations = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        operations[i] = (int *)malloc(n * sizeof(int));
    }

    int op_size = 0;
    sort_deck(deck, n, &operations, &op_size);

    printf("%d\n", op_size);
    for (int i = 0; i < op_size; i++) {
        for (int j = 0; j < operations[i][0]; j++) {
            printf("%d ", operations[i][j]);
        }
        printf("\n");
        free(operations[i]);
    }

    free(operations);
    return EXIT_SUCCESS;
}

