#define MOD (1000000007)
#define KEYPAD_SIZE 10
#define MAX_MOVES 100

int moves[KEYPAD_SIZE][3] = {
    {4, 6, -1}, {8, 6, -1}, {7, 9, -1}, 
    {4, 8, -1}, {3, 9, 0},  {1, 7, 0}, 
    {2, 6, -1}, {2, 6, -1}, {1, 3, -1}, 
    {2, 4, -1}
};

void knightDialer(int n, long long *result) {
    if (n < 1) {
        fprintf(stderr, "Error: Number of moves must be at least 1.\n");
        return;
    }

    long long dp[MAX_MOVES + 1][KEYPAD_SIZE] = {0};

    for (int i = 0; i < KEYPAD_SIZE; i++) {
        dp[1][i] = 1;
    }

    for (int step = 2; step <= n; step++) {
        for (int i = 0; i < KEYPAD_SIZE; i++) {
            for (int j = 0; moves[i][j] != -1; j++) {
                dp[step][i] = (dp[step][i] + dp[step - 1][moves[i][j]]) % MOD;
            }
        }
    }

    *result = 0;
    for (int i = 0; i < KEYPAD_SIZE; i++) {
        *result = (*result + dp[n][i]) % MOD;
    }
}

int main() {
    int n;
    long long result;

    printf("Enter the number of moves: ");
    if (scanf("%d", &n) != 1) {
        fprintf(stderr, "Error: Invalid input.\n");
        return EXIT_FAILURE;
    }

    knightDialer(n, &result);
    printf("Number of distinct phone numbers of length %d: %lld\n", n, result);

    return EXIT_SUCCESS;
}

