#define MOD 1000000007

int abs(int x) {
    return (x < 0) ? -x : x;
}

int numRoutes(int *locations, int locationsSize, int start, int finish, int fuel) {
    if (fuel < abs(locations[start] - locations[finish])) {
        return 0;
    }

    long *dp = (long *)calloc(locationsSize, sizeof(long));
    if (!dp) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(EXIT_FAILURE);
    }
    dp[start] = 1;

    for (int i = 0; i < locationsSize; i++) {
        for (int j = i + 1; j < locationsSize; j++) {
            dp[j] = (dp[j] + dp[i]) % MOD;
        }
    }

    long result = dp[finish] % MOD;
    free(dp);
    return (int)result;
}

long recursiveDP(int *locations, int locationsSize, int loc, int finish, int fuel, long *cache) {
    if (loc == finish) {
        return 1;
    }

    if (cache[loc * (fuel + 1)] != -1) {
        return cache[loc * (fuel + 1)];
    }

    long count = 0;
    for (int next = 0; next < locationsSize; next++) {
        if (next != loc) {
            int cost = abs(locations[loc] - locations[next]);
            if (fuel >= cost) {
                count = (count + recursiveDP(locations, locationsSize, next, finish, fuel - cost, cache)) % MOD;
            }
        }
    }

    cache[loc * (fuel + 1)] = count;
    return count;
}

int numRoutesRecursive(int *locations, int locationsSize, int start, int finish, int fuel) {
    long *cache = (long *)malloc(locationsSize * (fuel + 1) * sizeof(long));
    if (!cache) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(EXIT_FAILURE);
    }
    for (int i = 0; i < locationsSize * (fuel + 1); i++) {
        cache[i] = -1;
    }

    long result = recursiveDP(locations, locationsSize, start, finish, fuel, cache);
    free(cache);
    return (int)(result % MOD);
}

