#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node* left;
    struct Node* right;
} Node;

typedef struct Queue {
    Node** items;
    int front;
    int rear;
    int capacity;
} Queue;

Queue* createQueue(int capacity) {
    Queue* queue = (Queue*)malloc(sizeof(Queue));
    if (!queue) {
        perror("Failed to create queue");
        exit(EXIT_FAILURE);
    }
    queue->capacity = capacity;
    queue->front = 0;
    queue->rear = -1;
    queue->items = (Node**)malloc(capacity * sizeof(Node*));
    if (!queue->items) {
        perror("Failed to allocate queue items");
        free(queue);
        exit(EXIT_FAILURE);
    }
    return queue;
}

int isEmpty(Queue* queue) {
    return queue->front > queue->rear;
}

void enqueue(Queue* queue, Node* node) {
    if (queue->rear < queue->capacity - 1) {
        queue->items[++queue->rear] = node;
    } else {
        perror("Queue overflow");
        exit(EXIT_FAILURE);
    }
}

Node* dequeue(Queue* queue) {
    if (!isEmpty(queue)) {
        return queue->items[queue->front++];
    }
    perror("Queue underflow");
    exit(EXIT_FAILURE);
}

