    free(queue);
}

void levelOrder(Node* root, int** result, int* returnSize) {
    if (!root) return;

    *returnSize = 0;
    Queue* queue = createQueue(100);  
    enqueue(queue, root);

    while (!isEmpty(queue)) {
        int level_size = queue->rear - queue->front + 1;
        int* current_level = (int*)malloc(level_size * sizeof(int));
        if (!current_level) {
            perror("Failed to allocate current level");
            freeQueue(queue);
            exit(EXIT_FAILURE);
        }

        for (int i = 0; i < level_size; i++) {
            Node* node = dequeue(queue);
            current_level[i] = node->data;

            if (node->left) enqueue(queue, node->left);
            if (node->right) enqueue(queue, node->right);
        }

        result[*returnSize] = current_level;
        (*returnSize)++;
    }

    freeQueue(queue);
}

