void validate_positive(int value, const char* msg) {
    if (value <= 0) {
        fprintf(stderr, "Error: %s must be positive.\n", msg);
        exit(EXIT_FAILURE);
    }
}

int calculate_cost(int n, int k, int A, int B) {
    int cost = 0;

    if (n % k == 0) {
        int divs = n / k;
        cost += divs * B;
        n = 1;
    } else {
        int divs = n / k;
        int rem = n % k;
        cost += divs * B;
        cost += (rem - divs * (k - divs % k) < 0) ? 0 : 
                 (rem - divs * (k - divs % k)) * A < (divs % k) * A + (divs + 1 - divs % k) * B ?
                 (rem - divs * (k - divs % k)) * A :
                 (divs % k) * A + (divs + 1 - divs % k) * B;
        n = 1;
    }

    while (n > 0) {
        cost += A;
        n--;
    }

    return cost;
}

int main() {
    int n, k, A, B;

    printf("Enter values for n, k, A, and B:\n");
    if (scanf("%d %d %d %d", &n, &k, &A, &B) != 4) {
        fprintf(stderr, "Error: Invalid input format.\n");
        return EXIT_FAILURE;
    }

    validate_positive(n, "n");
    validate_positive(k, "k");
    validate_positive(A, "A");
    validate_positive(B, "B");

    int total_cost = calculate_cost(n, k, A, B);
    printf("Total Cost: %d\n", total_cost);

    return EXIT_SUCCESS;
}

#include <stdio.h>
