#include <stdbool.h>

#define MAX_LENGTH 100

void log_message(const char *msg) {
    printf("%s\n", msg);
}

char* backtrack(const char *encoded_message, int index, const char *current_message, int k) {
    if (index == strlen(encoded_message)) {
        if (strlen(current_message) == k) {
            return strdup(current_message);
        }
        return NULL;
    }

    if (index + 1 < strlen(encoded_message)) {
        if (encoded_message[index + 1] == '?' || encoded_message[index + 1] == '*') {
            // Option 1: Remove the current letter
            char *result = backtrack(encoded_message, index + 2, current_message, k);
            if (result) return result;

            // Option 2: Keep the current letter
            char next_message[MAX_LENGTH];
            snprintf(next_message, sizeof(next_message), "%s%c", current_message, encoded_message[index]);
            result = backtrack(encoded_message, index + 2, next_message, k);
            if (result) return result;

            if (encoded_message[index + 1] == '*') {
                // Option 3: Repeat the current letter
                for (int i = 2; strlen(current_message) + i <= k; i++) {
                    char repeated_message[MAX_LENGTH];
                    memset(repeated_message, 0, sizeof(repeated_message));
                    snprintf(repeated_message, sizeof(repeated_message), "%s", current_message);
                    for (int j = 0; j < i; j++) {
                        strncat(repeated_message, &encoded_message[index], 1);
                    }
                    result = backtrack(encoded_message, index + 2, repeated_message, k);
                    if (result) return result;
                }
            }
        }
    } else {
        // Just a letter, must keep it
        char next_message[MAX_LENGTH];
        snprintf(next_message, sizeof(next_message), "%s%c", current_message, encoded_message[index]);
        return backtrack(encoded_message, index + 1, next_message, k);
    }

    return NULL;
}

char* solve(const char *encoded_message, int k) {
    char *result = backtrack(encoded_message, 0, "", k);
    return result ? result : "Impossible";
}

int main() {
    char encoded_message[MAX_LENGTH];

    printf("Enter encoded message: ");
    if (fgets(encoded_message, sizeof(encoded_message), stdin) == NULL) {
        log_message("Error reading encoded message.");
        return EXIT_FAILURE;
    }
    encoded_message[strcspn(encoded_message, "\n")] = '\0'; // Remove newline

    char *endptr;
    printf("Enter desired length k: ");
    long k = strtol(fgets(encoded_message, sizeof(encoded_message), stdin), &endptr, 10);
    if (*endptr != '\n' && *endptr != '\0') {
        log_message("Invalid input for k.");
        return EXIT_FAILURE;
    }

    char *result = solve(encoded_message, (int)k);
    printf("%s\n", result);

    free(result); // Free if not "Impossible"
    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>

#define MAX_SIZE 1000

typedef struct {
    int *data;
    size_t size;
    size_t capacity;
} DynamicArray;

void initArray(DynamicArray *arr, size_t initialSize) {
    arr->data = (int *)malloc(initialSize * sizeof(int));
    arr->size = 0;
    arr->capacity = initialSize;
}

void freeArray(DynamicArray *arr) {
    free(arr->data);
    arr->data = NULL;
    arr->size = 0;
    arr->capacity = 0;
}

void append(DynamicArray *arr, int value) {
    if (arr->size >= arr->capacity) {
        arr->capacity *= 2;
        arr->data = (int *)realloc(arr->data, arr->capacity * sizeof(int));
    }
    arr->data[arr->size++] = value;
}

int getElement(DynamicArray *arr, size_t index) {
    if (index < arr->size) {
        return arr->data[index];
    }
    fprintf(stderr, "Index out of bounds: %zu\n", index);
    exit(EXIT_FAILURE);
}

void popElement(DynamicArray *arr) {
    if (arr->size > 0) {
        arr->size--;
    } else {
        fprintf(stderr, "Attempt to pop from an empty array\n");
        exit(EXIT_FAILURE);
    }
}

int main() {
    DynamicArray A; 
    initArray(&A, 1);

    int Q;
    printf("Enter number of queries: ");
    if (scanf("%d", &Q) != 1 || Q <= 0) {
        fprintf(stderr, "Invalid input for number of queries\n");
        freeArray(&A);
        return EXIT_FAILURE;
    }

    for (int i = 0; i < Q; i++) {
        int t, x;
        if (scanf("%d %d", &t, &x) != 2) {
            fprintf(stderr, "Invalid input for query\n");
            freeArray(&A);
            return EXIT_FAILURE;
        }

        switch (t) {
            case 0:
                append(&A, x);
                break;
            case 1:
                if (A.size == 0) {
                    fprintf(stderr, "Array is empty\n");
                    break;
                }
                printf("%d\n", getElement(&A, x % A.size));
                break;
            case 2:
                popElement(&A);
                break;
            default:
                fprintf(stderr, "Invalid operation type: %d\n", t);
                break;
        }
    }

    freeArray(&A);
    return EXIT_SUCCESS;
}

