#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <stdbool.h>

#define MAX_N 1000
#define MAX_EDGES 2000

typedef struct {
    int edges[MAX_EDGES][2];
    int num_edges;
} Graph;

typedef struct {
    int node;
    int distance;
} Node;

Graph G;
int D[MAX_N];
bool visited[MAX_N];

void initialize_graph(int n) {
    G.num_edges = 0;
    for (int i = 0; i < n; i++) {
        D[i] = INT_MAX;
    }
}

void add_edge(int u, int v) {
    if (G.num_edges < MAX_EDGES) {
        G.edges[G.num_edges][0] = u;
        G.edges[G.num_edges][1] = v;
        G.num_edges++;
    }
}

int dijkstra(int start, int target, int n) {
    for (int i = 0; i < n; i++) visited[i] = false;
    D[start] = 0;
    Node queue[MAX_N];
    int front = 0, rear = 0;

    queue[rear++] = (Node){start, 0};

    while (front < rear) {
        Node current = queue[front++];
        int u = current.node;
        visited[u] = true;

        if (u == target) return current.distance;

        for (int i = 0; i < G.num_edges; i++) {
            int v = (G.edges[i][0] == u) ? G.edges[i][1] : G.edges[i][0];
            if (!visited[v]) {
                queue[rear++] = (Node){v, current.distance + 1};
                D[v] = current.distance + 1;
            }
        }
    }
    return -1;
}

int main() {
    int n, k;
    if (scanf("%d %d", &n, &k) != 2 || n < 1 || k < 1) {
        fprintf(stderr, "Invalid input.\n");
        return EXIT_FAILURE;
    }

    initialize_graph(n);

    for (int i = 1; i < n; i++) {
        int ai, bi;
        if (scanf("%d %d", &ai, &bi) != 2) {
            fprintf(stderr, "Failed to read edge.\n");
            return EXIT_FAILURE;
        }
        add_edge(ai, bi);
    }

    int n_edges[MAX_EDGES][3];
    int count = 0;

    for (int i = 0; i < G.num_edges; i++) {
        int u = G.edges[i][0];
        int v = G.edges[i][1];
        int d = dijkstra(u, v, n);
        n_edges[count][0] = d;
        n_edges[count][1] = u;
        n_edges[count][2] = v;
        count++;
    }

    // Sort edges by distance
    for (int i = 0; i < count - 1; i++) {
        for (int j = i + 1; j < count; j++) {
            if (n_edges[i][0] > n_edges[j][0]) {
                int temp[3];
                for (int k = 0; k < 3; k++) {
                    temp[k] = n_edges[i][k];
                    n_edges[i][k] = n_edges[j][k];
                    n_edges[j][k] = temp[k];
                }
            }
        }
    }

    int ri = n_edges[0][1], rj = n_edges[0][2];
    int rk = n_edges[0][0];

    for (int i = 1; i < count; i++) {
        if (n_edges[i][1] != ri || n_edges[i][2] != rj) {
            if (dijkstra(n_edges[i][1], rk, n) == dijkstra(ri, rk, n) && 
                dijkstra(rj, rk, n) == dijkstra(ri, rk, n) - 2) {
                count++;
            }
            ri = n_edges[i][1];
            rj = n_edges[i][2];
            rk = dijkstra(ri, rj, n);
        }
    }

    if (n_edges[count - 1][0] == n * n - 1) {
        count++;
    }

    printf("%d\n", count);
    return 0;
}

#include <stdio.h>
