double probability_divisible_by_p(long l, long r, long p) {
    if (l > r) {
        return 0.0;
    }
    long count = (r / p) - ((l - 1) / p);
    return (double)count / (r - l + 1);
}

double expected_dollars(int n, long p, long (*ranges)[2]) {
    double total_expectation = 0.0;

    for (int i = 0; i < n; i++) {
        long l1 = ranges[i][0], r1 = ranges[i][1];
        long l2 = ranges[(i + 1) % n][0], r2 = ranges[(i + 1) % n][1];

        double prob1 = probability_divisible_by_p(l1, r1, p);
        double prob2 = probability_divisible_by_p(l2, r2, p);

        double prob_both_divisible = prob1 * prob2;
        double prob_either_divisible = prob1 + prob2 - prob_both_divisible;

        total_expectation += prob_either_divisible * 2000.0;
    }

    return total_expectation;
}

void handle_input(int *n, long *p, long (*ranges)[2]) {
    printf("Enter number of ranges: ");
    if (scanf("%d", n) != 1 || *n <= 0) {
        fprintf(stderr, "Invalid input for number of ranges\n");
        exit(EXIT_FAILURE);
    }

    printf("Enter divisor p: ");
    if (scanf("%ld", p) != 1 || *p <= 0) {
        fprintf(stderr, "Invalid input for divisor p\n");
        exit(EXIT_FAILURE);
    }

    for (int i = 0; i < *n; i++) {
        printf("Enter range %d (two integers): ", i + 1);
        if (scanf("%ld %ld", &ranges[i][0], &ranges[i][1]) != 2 || ranges[i][0] > ranges[i][1]) {
            fprintf(stderr, "Invalid range input\n");
            exit(EXIT_FAILURE);
        }
    }
}

int main() {
    int n;
    long p;
    long ranges[10][2];    

    handle_input(&n, &p, ranges);

    double result = expected_dollars(n, p, ranges);
    printf("Expected dollars: %.2f\n", result);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

#define MAX_SIZE 100

void dfs(int **grid, int r, int c, int rows, int cols, int **visited) {
    if (r < 0 || r >= rows || c < 0 || c >= cols || grid[r][c] == 0 || visited[r][c]) {
        return;
    }
    visited[r][c] = 1;
    dfs(grid, r - 1, c - 1, rows, cols, visited); // top-left
    dfs(grid, r - 1, c, rows, cols, visited);     // top
    dfs(grid, r - 1, c + 1, rows, cols, visited); // top-right
    dfs(grid, r, c - 1, rows, cols, visited);     // left
    dfs(grid, r, c + 1, rows, cols, visited);     // right
    dfs(grid, r + 1, c - 1, rows, cols, visited); // bottom-left
    dfs(grid, r + 1, c, rows, cols, visited);     // bottom
    dfs(grid, r + 1, c + 1, rows, cols, visited); // bottom-right
}

int count_islands(int **grid, int rows, int cols) {
    if (grid == NULL || rows <= 0 || cols <= 0) {
        return 0;
    }

    int count = 0;
    int **visited = malloc(rows * sizeof(int *));
    for (int i = 0; i < rows; i++) {
        visited[i] = calloc(cols, sizeof(int));
    }

    for (int r = 0; r < rows; r++) {
        for (int c = 0; c < cols; c++) {
            if (grid[r][c] == 1 && !visited[r][c]) {
                count++;
                dfs(grid, r, c, rows, cols, visited);
            }
        }
    }

    for (int i = 0; i < rows; i++) {
        free(visited[i]);
    }
    free(visited);

    return count;
}

