int solution(int l1[], int l2[], int l3[]) {
    int w = l1[0];
    int h = l1[1];
    int u1 = l2[0];
    int d1 = l2[1];
    int u2 = l3[0];
    int d2 = l3[1];
    int h2 = (d2 < h) ? d2 : h;

    for (int x = h; x > 0; x--) {
        w += x;
        if ((h - x) == d1) {
            w -= u1;
