#include <stdbool.h>

#define MAX_NODES 1000
#define INF INT_MAX

typedef struct {
    int node;
    int distance;
} Edge;

typedef struct {
    Edge* edges;
    int count;
} Graph;

Graph* create_graph(int n) {
    Graph* graph = malloc(sizeof(Graph) * n);
    for (int i = 0; i < n; i++) {
        graph[i].edges = malloc(sizeof(Edge) * n);
        graph[i].count = 0;
    }
    return graph;
}

void add_edge(Graph* graph, int u, int v, int distance) {
    graph[u].edges[graph[u].count++] = (Edge){v, distance};
}

void free_graph(Graph* graph, int n) {
    for (int i = 0; i < n; i++) {
        free(graph[i].edges);
    }
    free(graph);
}

void log_error(const char* message) {
    fprintf(stderr, "Error: %s\n", message);
}

int* shortest_path(int n, int edge[][3], int edge_count) {
    if (n <= 0) {
        log_error("Invalid number of nodes.");
        return NULL;
    }
    Graph* graph = create_graph(n);

    for (int i = 0; i < edge_count; i++) {
        int u = edge[i][0];
        int v = edge[i][1];
        int distance = edge[i][2];
        if (u < 0 || u >= n || v < 0 || v >= n) {
            log_error("Edge nodes out of bounds.");
            free_graph(graph, n);
            return NULL;
        }
        add_edge(graph, u, v, distance);
    }

    int* distances = malloc(sizeof(int) * n);
    for (int i = 0; i < n; i++) {
        distances[i] = INF;
    }
    distances[0] = 0;

    for (int i = 0; i < n; i++) {
        bool update = false;
        for (int u = 0; u < n; u++) {
            for (int j = 0; j < graph[u].count; j++) {
                Edge edge = graph[u].edges[j];
                if (distances[u] != INF && distances[edge.node] > distances[u] + edge.distance) {
                    distances[edge.node] = distances[u] + edge.distance;
                    update = true;
                }
            }
        }
        if (!update) {
            break;
        }
    }

    if (distances[0] == INF) {
        free_graph(graph, n);
        free(distances);
        return NULL;
    }

    free_graph(graph, n);
    return distances;
}

#include <stdio.h>
