#define MAX_SIZE 1000
#define ERROR_CODE -1

typedef struct {
    int size;
    int *array;
} TestCase;

int min_operations(int *arr, int n) {
    if (arr == NULL || n <= 0) {
        return ERROR_CODE;
    }

    int count = 0;
    for (int i = 0; i < n - 1; i++) {
        if (arr[i] != arr[i + 1]) {
            count++;
        }
    }
    return count;
}

TestCase read_input() {
    int t = 0;
    if (scanf("%d", &t) != 1 || t <= 0 || t > MAX_SIZE) {
        fprintf(stderr, "Invalid number of test cases.\n");
        exit(EXIT_FAILURE);
    }

    TestCase test_cases[MAX_SIZE];

    for (int i = 0; i < t; i++) {
        int n = 0;
        if (scanf("%d", &n) != 1 || n <= 0 || n > MAX_SIZE) {
            fprintf(stderr, "Invalid size for test case %d.\n", i + 1);
            exit(EXIT_FAILURE);
        }

        test_cases[i].size = n;
        test_cases[i].array = (int *)malloc(n * sizeof(int));
        if (test_cases[i].array == NULL) {
            fprintf(stderr, "Memory allocation failed.\n");
            exit(EXIT_FAILURE);
        }

        for (int j = 0; j < n; j++) {
            if (scanf("%d", &test_cases[i].array[j]) != 1) {
                fprintf(stderr, "Invalid input for array.\n");
                exit(EXIT_FAILURE);
            }
        }
    }

    return test_cases;
}

void write_output(int *results, int count) {
    for (int i = 0; i < count; i++) {
        printf("%d\n", results[i]);
    }
}

void free_memory(TestCase *test_cases, int count) {
    for (int i = 0; i < count; i++) {
        free(test_cases[i].array);
    }
}

int main() {
    TestCase test_cases[MAX_SIZE];
    test_cases = read_input();

    int results[MAX_SIZE];

    for (int i = 0; i < test_cases.size; i++) {
        int ops = min_operations(test_cases[i].array, test_cases[i].size);
        if (ops == ERROR_CODE) {
            fprintf(stderr, "Error processing test case %d.\n", i + 1);
            free_memory(test_cases, i);
            return EXIT_FAILURE;
        }
        results[i] = ops;
    }

    write_output(results, test_cases.size);
    free_memory(test_cases, test_cases.size);

    return EXIT_SUCCESS;
}

