#define MAX_LENGTH 1001

bool is_vowel(char ch) {
    return ch == 'a' || ch == 'e' || ch == 'i' || ch == 'o' || ch == 'u';
}

int max_vowels(const char *s, int k) {
    if (s == NULL || k < 1 || k > strlen(s)) {
        fprintf(stderr, "Invalid input.\n");
        return -1;
    }

    int length = strlen(s);
    char *b = (char *)malloc((length + 1) * sizeof(char));
    if (b == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return -1;
    }
    strncpy(b, s, length);
    b[length] = '\0';

    int t = 0;
    for (int i = 0; i < k; i++) {
        if (is_vowel(b[i])) t++;
    }
    if (t == k) {
        free(b);
        return t;
    }

    int res = t;
    for (int i = 0; i <= length - k; i++) {
        if (i > 0) {
            if (is_vowel(b[i - 1])) t--;
            if (is_vowel(b[i + k - 1])) t++;
        }
        res = (t > res) ? t : res;
    }

    free(b);
    return res;
}

int main() {
    const char *test_str = "abciiidef";
    int k = 3;
    int result = max_vowels(test_str, k);
    if (result != -1) {
        printf("Max vowels in substring of length %d: %d\n", k, result);
    }
    return 0;
}

