    printf("%s\n", message);
}

int can_place(int **board, int n, int x, int y) {
    return (x >= 0 && y >= 0 && x < n && y < n && board[x][y] == 0);
}

int place_value(int **board, int n, int x, int y, int value, int count) {
    if (count == 0) {
        return 1;
    }
    if (!can_place(board, n, x, y)) {
        return 0;
    }

    board[x][y] = value;

    int directions[4][2] = {{0, 1}, {1, 0}, {-1, 0}, {0, -1}};
    for (int i = 0; i < 4; i++) {
        if (place_value(board, n, x + directions[i][0], y + directions[i][1], value, count - 1)) {
            return 1;
        }
    }

    board[x][y] = 0;
    return 0;
}

void free_board(int **board, int n) {
    for (int i = 0; i < n; i++) {
        free(board[i]);
    }
    free(board);
}

int solve_fillomino(int n, int *p) {
    if (n <= 0 || p == NULL) {
        log_message("Invalid input values.");
        return -1;
    }

    int **board = malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        board[i] = calloc(n, sizeof(int));
    }

    for (int i = 0; i < n; i++) {
        board[i][i] = p[i];
    }

    for (int i = 0; i < n; i++) {
        int value = p[i];
        int count = value - 1;
        for (int j = 0; j <= i; j++) {
            if (board[i][j] == 0 && place_value(board, n, i, j, value, count)) {
                break;
            }
        }
    }

    for (int i = 0; i < n; i++) {
        for (int j = 0; j <= i; j++) {
            if (board[i][j] == 0) {
                free_board(board, n);
                return -1;
            }
        }
    }

    for (int i = 0; i < n; i++) {
        for (int j = 0; j <= i; j++) {
            printf("%d ", board[i][j]);
        }
        printf("\n");
    }

    free_board(board, n);
    return 0;
}

