bool canMakeAllZeroes(int* nums, int numsSize, int k) {
    if (nums == NULL || numsSize <= 0 || k <= 0) {
        fprintf(stderr, "Invalid input parameters.\n");
        return false;
    }

    int s = 0, l = k - 1;

    while (s < numsSize) {
        s += nums[l];
        if (nums[numsSize + k - l - 1] > s || s < 0) {
            return false;
        }
        nums[l] = 0;
        l++;

        if (l >= numsSize) {
            break;
        }
    }

    while (l < k - 1) {
        if (s - nums[l] == s / nums[(k + l) % k - 1]) {
            l++;
        } else {
            break;
        }
    }

    return l < numsSize;
}

