} Node;

void freeTree(Node* root) {
    if (root) {
        freeTree(root->left);
        freeTree(root->right);
        free(root);
    }
}

int countEvenPaths(Node* root, int* arr, int* idx) {
    if (!root) return 0;

    arr[(*idx)++] = root->data;

    int count = countEvenPaths(root->left, arr, idx);
    count += countEvenPaths(root->right, arr, idx);

    return count;
}

int findPairs(int* arr, int size, int x) {
    int res = 0;
    for (int k = 0; k < size; k++) {
        for (int i = k + 1; i < size; i++) {
            if ((arr[i] + arr[k]) % 2 == 0) {
                res += x;
                break;
            }
        }
    }
    return res;
}

int nearestEven(Node* root) {
    int* arr = malloc(1000 * sizeof(int));  // Assuming max size
    if (!arr) {
        perror("Failed to allocate memory.");
        return -1;
    }

    int idx = 0;
    countEvenPaths(root, arr, &idx);
    int res = findPairs(arr, idx, idx);

    free(arr);
    return res;
}

