#define MAX_LEN 100

void clean_string(char *str, int index) {
    memmove(&str[index], &str[index + 1], strlen(str) - index);
}

char* decode(int n, char *s) {
    if (n <= 0 || s == NULL) {
        return NULL;
    }

    char *word = (char *)malloc((n + 1) * sizeof(char));
    if (!word) {
        perror("Failed to allocate memory for word");
        return NULL;
    }

    word[0] = '\0';

    for (int i = n; i > 0; i--) {
        int index = i / 2;
        strncat(word, &s[index], 1);
        clean_string(s, index);
    }

    return word;
}

int main() {
    int n;
    char s[MAX_LEN];

    printf("Enter the value of n: ");
    if (scanf("%d", &n) != 1 || n < 1 || n >= MAX_LEN) {
        fprintf(stderr, "Invalid input for n\n");
        return 1;
    }

    printf("Enter the string: ");
    scanf("%s", s);

    if (strlen(s) < n) {
        fprintf(stderr, "String length is less than n\n");
        return 1;
    }

    char *result = decode(n, s);
    if (result) {
        printf("Decoded word: %s\n", result);
        free(result);
    } else {
