#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int memory;
    int points;
} App;

int compare(const void *a, const void *b) {
    return ((App *)b)->memory - ((App *)a)->memory;
}

int min_convenience_points(int n, int m, int *a, int *b) {
    App *apps = (App *)malloc(n * sizeof(App));
    for (int i = 0; i < n; i++) {
        apps[i].memory = a[i];
        apps[i].points = b[i];
    }

    qsort(apps, n, sizeof(App), compare);

    int total_memory = 0;
    int total_points = 0;
    int *min_heap = (int *)malloc(n * sizeof(int));
    int heap_size = 0;

    for (int i = 0; i < n; i++) {
        total_memory += apps[i].memory;
        total_points += apps[i].points;

        min_heap[heap_size++] = apps[i].points;

        while (total_memory > m && heap_size > 0) {
            int min_points = min_heap[0];
            total_points -= min_points;
            total_memory -= apps[i].memory;

            // Remove the minimum from the heap
            min_heap[0] = min_heap[--heap_size];
            for (int j = 0; j < heap_size; j++) {
                for (int k = j + 1; k < heap_size; k++) {
                    if (min_heap[k] < min_heap[j]) {
                        int temp = min_heap[j];
                        min_heap[j] = min_heap[k];
                        min_heap[k] = temp;
                    }
                }
            }
        }
    }

    free(apps);
    free(min_heap);

    return total_memory < m ? -1 : total_points;
}

int *solve_polycarp_memory_problem(int t, int test_cases[t][3][100], int *results) {
    for (int i = 0; i < t; i++) {
        int n = test_cases[i][0][0];
        int m = test_cases[i][0][1];
        int *a = test_cases[i][1];
        int *b = test_cases[i][2];
        results[i] = min_convenience_points(n, m, a, b);
    }
    return results;
}

int main() {
    int t = 5;
    int test_cases[5][3][100] = {
        {{5, 7}, {5, 3, 2, 1, 4}, {2, 1, 1, 2, 1}},
        {{1, 3}, {2}, {1}},
        {{5, 10}, {2, 3, 2, 3, 2}, {1, 2, 1, 2, 1}},
        {{4, 10}, {5, 1, 3, 4}, {1, 2, 1, 2}},
        {{4, 5}, {3, 2, 1, 2}, {2, 1, 2, 1}}
    };

    int results[5];
    solve_polycarp_memory_problem(t, test_cases, results);

    for (int i = 0; i < t; i++) {
        printf("%d\n", results[i]);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_LINE_LENGTH 256
#define MAX_SIZE 100

int argsmatches(int M, int *B, int *A, int C) {
    int sum = 0;
    for (int i = 0; i < M; i++) {
        sum += B[i] * A[i];
    }
    return sum > C;
}

void cleanup(FILE *file) {
    if (file != NULL) {
        fclose(file);
    }
}

int main(int argc, char *argv[]) {
    if (argc != 2) {
        fprintf(stderr, "Invalid number of arguments.\n");
        return EXIT_FAILURE;
    }

    FILE *file = fopen(argv[1], "r");
    if (file == NULL) {
        perror("Failed to open file");
        return EXIT_FAILURE;
    }

    char line[MAX_LINE_LENGTH];
    int M, C;
    fgets(line, sizeof(line), file);
    if (sscanf(line, "%*s %d %d", &M, &C) != 2) {
        fprintf(stderr, "Invalid format in first line.\n");
        cleanup(file);
        return EXIT_FAILURE;
    }

    int Bs[MAX_SIZE];
    fgets(line, sizeof(line), file);
    char *token = strtok(line, " ");
    for (int i = 0; token != NULL && i < M; i++) {
        Bs[i] = atoi(token);
        token = strtok(NULL, " ");
    }

    int As[MAX_SIZE][MAX_SIZE];
    int count = 0;
    int row = 0;

    while (fgets(line, sizeof(line), file) != NULL) {
        if (row >= MAX_SIZE) {
            fprintf(stderr, "Exceeded maximum allowed rows.\n");
            cleanup(file);
            return EXIT_FAILURE;
        }
        token = strtok(line, " ");
        for (int i = 0; token != NULL && i < M; i++) {
            As[row][i] = atoi(token);
            token = strtok(NULL, " ");
        }
        row++;
    }

    for (int i = 0; i < row; i++) {
        if (argsmatches(M, Bs, As[i], C)) {
            count++;
        }
    }

    printf("%d\n", count);
    cleanup(file);
    return EXIT_SUCCESS;
}

