void delete_column(char a[MAX_DIM][MAX_DIM], int *H, int *W, int j) {
    for (int k = 0; k < *H; k++) {
        for (int m = j; m < *W - 1; m++) {
            a[k][m] = a[k][m + 1];
        }
    }
    (*W)--;
}

void delete_row(char a[MAX_DIM][MAX_DIM], int *H, int j) {
    for (int m = j; m < *H - 1; m++) {
        for (int k = 0; k < *W; k++) {
            a[m][k] = a[m + 1][k];
        }
    }
    (*H)--;
}

