int bisectLeft(int* list, int size, int value) {
    int low = 0, high = size;
    while (low < high) {
        int mid = low + (high - low) / 2;
        if (list[mid] < value) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }
    return low;
}

int getMin(int* lis1, int* lis2, int size1, int value) {
    int p1 = bisectLeft(lis1, size1, value);
    if (p1 < size1) {
        return value - lis2[p1] + lis2[p1] - 1 < lis2[p1] ? 
               value - lis2[p1] + lis2[p1] - 1 : lis2[p1];
    }
    return -1; // Error handling for out of bounds
}

int getMax(int* lis1, int* lis2, int size1, int value) {
    int p1 = bisectLeft(lis1, size1, value);
    if (p1 < size1 - 1) {
        return value - lis2[p1] + lis2[p1] - 1 > lis2[p1] ? 
               value - lis2[p1] + lis2[p1] - 1 : lis2[p1];
    }
    return -1; // Error handling for out of bounds
}

