long long max(long long a, long long b) {
    return (a > b) ? a : b;
}

long long calculate_min_product(long long a, long long b, long long x, long long y, long long n) {
    // Reduce 'a' first, then 'b'
    long long reduce_a_first = max(x, a - n) * max(y, b - max(n - (a - x), 0));

    // Reduce 'b' first, then 'a'
    long long reduce_b_first = max(y, b - n) * max(x, a - max(n - (b - y), 0));

    return (reduce_a_first < reduce_b_first) ? reduce_a_first : reduce_b_first;
}

void minimum_product(int t, long long test_cases[][5], long long results[]) {
    for (int i = 0; i < t; ++i) {
        long long a = test_cases[i][0];
        long long b = test_cases[i][1];
        long long x = test_cases[i][2];
        long long y = test_cases[i][3];
        long long n = test_cases[i][4];

        // Validate inputs
        if (n < 0 || a < 0 || b < 0 || x < 0 || y < 0) {
            log_message("Error: Negative values are not allowed.");
            results[i] = -1;
            continue;
        }

        results[i] = calculate_min_product(a, b, x, y, n);
    }
}

