#include <stdio.h>
#include <stdlib.h>

#define MAX_WATCH_TIME 15
#define MIN_WATCH_TIME 90

int limak_watch_time(int n, int *t) {
    if (n < 0) {
        fprintf(stderr, "Error: The number of time entries cannot be negative.\n");
        return -1;
    }
    if (n == 0) {
        return MAX_WATCH_TIME;
    }

    int watch_time = 0;
    int previous = 0;

    for (int i = 0; i < n; i++) {
        if (t[i] < previous) {
            fprintf(stderr, "Error: Time entries must be in non-decreasing order.\n");
            return -1;
        }

        if (t[i] - previous > MAX_WATCH_TIME) {
            watch_time += MAX_WATCH_TIME;
            break;
        } else {
            watch_time += t[i] - previous;
            previous = t[i];
        }
    }

    if (watch_time < MIN_WATCH_TIME) {
        int additional_time = MIN_WATCH_TIME - watch_time < MAX_WATCH_TIME ? 
                              MIN_WATCH_TIME - watch_time : MAX_WATCH_TIME;
        watch_time += additional_time;
    }

    return watch_time;
}

int main() {
    int n;
    if (scanf("%d", &n) != 1 || n < 0) {
        fprintf(stderr, "Error: Invalid input for number of time entries.\n");
        return EXIT_FAILURE;
    }

    int *t = malloc(n * sizeof(int));
    if (!t) {
        fprintf(stderr, "Error: Memory allocation failed.\n");
        return EXIT_FAILURE;
    }

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &t[i]) != 1) {
            fprintf(stderr, "Error: Invalid input for time entries.\n");
            free(t);
            return EXIT_FAILURE;
        }
    }

    int result = limak_watch_time(n, t);
    if (result != -1) {
        printf("%d\n", result);
    }

    free(t);
    return EXIT_SUCCESS;
}

