int followMatrix(const char *s, int n) {
    int old = 'I', new = 'J', last = 'I';
    int res[N][N] = {0};

    for (int i = 1, j = 0; j < n; j++) {
        res[i][j] = last;
        res[j][i] = old;

        last = new;
        old = res[i][n - i - 1];
    }

