        exit(EXIT_FAILURE);
    }
    res[0] = '\0';

    for (int i = 0, j = n - 1; i < n + 1 && j >= 0; j--) {
        if (i == n || j < 0)
            strcat(res, (old == 'I') ? "I" : "J");
        else
            strncat(res, &s[j], 1);
        if (i == n) {
            strncat(res, &s[n - 1], 1);
        }
    }

    char *result = rec(0, res, first);
    free(res);
    return result;
}

char* rec(int a, const char *b, bool first) {
    if (a == 0) {
        return first ? strdup(b) : strdup(".");
    }
    else if (a == 1) {
        char *result = (first) ? malloc(strlen(b) + 2) : malloc(strlen(b) + 2);
        if (!result) {
            fprintf(stderr, "Memory allocation error\n");
            exit(EXIT_FAILURE);
        }
        if (first) {
            sprintf(result, "%s.", b);
        } else {
            sprintf(result, ".%s", b);
        }
        return result;
    } 
    else {
        char *firstPart = (char *)malloc((a * strlen(b) + 1) * sizeof(char));
        if (!firstPart) {
            fprintf(stderr, "Memory allocation error\n");
            exit(EXIT_FAILURE);
        }

        firstPart[0] = '\0';
        for (int i = 0; i < a; i++) {
            strcat(firstPart, b);
        }

        char *result = rec(a - 1, b, false);
        strcat(firstPart, result);
        free(result);
        return firstPart;
    }
}

