#define MAX_N 1000
#define INF 1e100

void initialize_array(double arr[], int size, double value) {
    for (int i = 0; i < size; i++) {
        arr[i] = value;
    }
}

int main() {
    int n, m, k;
    double c[MAX_N + 1][MAX_N + 1];
    double e[MAX_N + 1];
    int visited[MAX_N + 1];
    int s[MAX_N];

    // Input validation
    if (scanf("%d %d %d", &n, &m, &k) != 3 || n <= 0 || n > MAX_N || m < 0 || k < 0 || k > n) {
        fprintf(stderr, "Invalid input for n, m, or k.\n");
        return EXIT_FAILURE;
    }

    // Initialize cost matrix
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= n; j++) {
            c[i][j] = INF;
        }
    }

    // Reading edges
    for (int i = 0; i < m; i++) {
        int u, v, l;
        if (scanf("%d %d %d", &u, &v, &l) != 3 || u < 1 || u > n || v < 1 || v > n || l < 0) {
            fprintf(stderr, "Invalid edge input.\n");
            return EXIT_FAILURE;
        }
        c[u][v] = c[v][u] = fmin(l, c[u][v]);
    }

    // Read selected vertices
    for (int i = 0; i < k; i++) {
        if (scanf("%d", &s[i]) != 1 || s[i] < 1 || s[i] > n) {
            fprintf(stderr, "Invalid selected vertex input.\n");
            return EXIT_FAILURE;
        }
    }

    initialize_array(e, n + 1, INF);
    initialize_array(visited, n + 1, 0);

    // Set visited for selected vertices
    for (int i = 0; i < k; i++) {
        visited[s[i]] = 1;
    }

    // Adjust k if needed
    if (k > n - k) {
        k = n - k;
    }

    while (k > 0) {
        double Min = INF;
        int x = -1;

        // Find the vertex with minimum cost
        for (int i = 1; i <= n; i++) {
            if (!visited[i] && e[i] < Min) {
                Min = e[i];
                x = i;
            }
        }

        if (x == -1) {
            fprintf(stderr, "Error: No vertex found.\n");
            return EXIT_FAILURE;
        }

        visited[x] = 1;
        k--;

        // Update the costs
        for (int j = 1; j <= n; j++) {
            if (!visited[j] && c[x][j] < e[j]) {
                e[j] = c[x][j];
            }
        }
    }

    double ans = -1;
    for (int i = 1; i <= n; i++) {
        if (e[i] < INF) {
            ans = fmax(ans, e[i]);
        }
    }

    printf("%d\n", ans == INF ? -1 : (int)ans);
    return EXIT_SUCCESS;
}

