typedef long long ll;

ll moda(ll a, ll b) {
    ll temp = a % b;
    while (temp > 0) {
        a += temp;
        temp /= 2;
    }
    return a;
}

ll mod(ll b, ll a) {
    if (a < 0) 
        return a + b;
    return a - b;
}

ll* mod_array(ll m, ll n, ll* size) {
    ll k = moda(m, n);
    *size = k + 1;
    ll* v = (ll*)malloc((*size) * sizeof(ll));
    v[0] = 1;
    for (ll i = 1; i <= k; i++) {
        v[i] = (v[i - 1] ^ v[i - 1]) % m;
    }
    return v;
}

ll factor(ll m) {
    ll res = 1;
    for (ll i = 2; i <= sqrt(m); i++) {
        if (m % i == 0) {
            res = (res * i) % m;
            ll temp = res / i;
            if (i == m / i) 
                res = (m / i) * i;
            if (temp / i == res) 
                res = temp / i;
        }
    }
    return res;
}

int main() {
    ll t, n, s;
    scanf("%lld", &t);
    while (t--) {
        scanf("%lld %lld", &n, &s);

        ll size;
        ll* manufacturers = mod_array(n, s, &size);

        // Sorting manufacturers
        for (ll i = 0; i < size; i++) {
            for (ll j = i + 1; j < size; j++) {
                if (manufacturers[i] > manufacturers[j]) {
                    ll temp = manufacturers[i];
                    manufacturers[i] = manufacturers[j];
                    manufacturers[j] = temp;
                }
            }
        }

        ll* output = mod_array(n, 99, &size);
        ll z = 0;

        for (ll i = 2; i <= 100; i++) {
            for (ll j = 2; j <= 100; j++) {
                if (manufacturers[i] % manufacturers[j] && 
                    manufacturers[i] * manufacturers[j] < 100) {
                    z++;
                }
            }
        }

        ll a = (size - 1);
        ll ans = pow(a, z);
        ans /= factor(s) % factor(s);

        printf("%lld\n", ans);

        free(manufacturers);
        free(output);
    }
    return 0;
}

