// Function to calculate binary XOR of two strings
char* binary_xor(const char* a, const char* b) {
    size_t len_a = strlen(a);
    size_t len_b = strlen(b);
    size_t max_len = len_a > len_b ? len_a : len_b;

    int* num_a = malloc(max_len * sizeof(int));
    int* num_b = malloc(max_len * sizeof(int));
    char* result = malloc(max_len + 1);
    memset(result, '0', max_len);
    result[max_len] = '\0';

    for (size_t i = 0; i < len_a; i++) {
        num_a[i] = a[len_a - 1 - i] - '0';
    }
    for (size_t i = 0; i < len_b; i++) {
        num_b[i] = b[len_b - 1 - i] - '0';
    }

    // Perform binary XOR operation
    for (size_t i = 0; i < max_len; i++) {
        int bit_a = (i < len_a) ? num_a[i] : 0;
        int bit_b = (i < len_b) ? num_b[i] : 0;
        result[max_len - 1 - i] = (bit_a ^ bit_b) + '0';
    }

    // Free allocated memory
    free(num_a);
    free(num_b);

    // Remove leading zeros
    char* trimmed_result = result;
    while (*trimmed_result == '0' && *(trimmed_result + 1) != '\0') {
        trimmed_result++;
    }

    return trimmed_result;
}

