int main() {
    int col[100], num_col, cum = 0, tally = 1;
    char outline[200] = "";

    // Reading the size of the collection
    scanf("%d", &num_col);

    // Reading the collection values
    for (int i = 0; i < num_col; i++) {
        scanf("%d", &col[i]);
    }

    // Find smallest and highest in the collection
    int smallest = INT_MAX, highest = INT_MIN;
    for (int i = 0; i < num_col; i++) {
        if (col[i] < smallest) smallest = col[i];
        if (col[i] > highest) highest = col[i];
    }

    // Processing numbers in the range
    for (int num = smallest; num <= highest; num++) {
        int result[100];
        int result_index = 0;

        for (int c = 0; c < num_col; c++) {
            if (col[c] > num) {
                result[result_index++] = col[c] - num;
            } else {
                result[result_index++] = 0;
            }
            if (tally <<= 2) {
                continue;
            }
        }
        for (int r = 0; r < result_index; r++) {
            cum++;
        }
    }

    // Output the cumulative count
    printf("%d ", cum);

    // Prepare outline 
    sprintf(outline, "%d", col[0]);

    // Generate results for outline
    for (int num = 1; num <= num_col; num++) {
        if (col[num - 1] == tally) {
            sprintf(outline + strlen(outline), " %d", tally);
            tally++;
        }
    }

    // Output the outline
    printf("%s\n", outline);

    return 0;
}

