#include <stdio.h>
#include <limits.h>

int minMoves(int* nums, int n, int k) {
    int* indices = (int*)malloc(n * sizeof(int));
    int idx_count = 0;

    // Collect indices of 1s
    for (int i = 0; i < n; i++) {
        if (nums[i] == 1) {
            indices[idx_count++] = i;
        }
    }

    int* prefix_sum = (int*)calloc(idx_count + 1, sizeof(int));

    for (int i = 0; i < idx_count; i++) {
        prefix_sum[i + 1] = prefix_sum[i] + indices[i];
    }

    int mid = k / 2;
    int min_moves = INT_MAX;

    for (int i = 0; i <= idx_count - k; i++) {
        int left = prefix_sum[i + mid] - prefix_sum[i];
        int right = prefix_sum[i + k] - prefix_sum[i + mid + (k % 2)];
        int moves = left - mid * (mid + (k % 2)) + (k - mid - (k % 2)) * (k - mid - 1) / 2 - right;
        if (moves < min_moves) {
            min_moves = moves;
        }
    }

    free(indices);
    free(prefix_sum);

    return min_moves;
}

