#include <stdbool.h>

void solveEquation(const char* equation, int* xLeft, int* numLeft, int* xRight, int* numRight) {
    *xLeft = 0; 
    *numLeft = 0; 
    *xRight = 0; 
    *numRight = 0;

    bool leftSide = true;
    int num = 0;
    int sign = 1;

    for (int i = 0; equation[i] != '\0'; i++) {
        char c = equation[i];

        if (c == '=') {
            leftSide = false;
            continue;
        }

        if (c == '+' || c == '-') {
            if (num != 0) {
                if (leftSide) {
                    *numLeft += sign * num;
                } else {
                    *numRight += sign * num;
                }
            }

            if (i > 0 && (equation[i-1] == 'x' || equation[i-1] == 'X')) {
                if (leftSide) {
                    *xLeft += sign;
                } else {
                    *xRight += sign;
                }
            }

            num = 0;
            sign = (c == '+' ? 1 : -1);
        } else if (c == 'x' || c == 'X') {
            if (num == 0) {
                num = 1;
            }
            if (leftSide) {
                *xLeft += sign * num;
            } else {
                *xRight += sign * num;
            }
            num = 0;
        } else if (c >= '0' && c <= '9') {
            num = num * 10 + (c - '0');
        }
    }

    // Process the last term
    if (num != 0) {
        if (leftSide) {
            *numLeft += sign * num;
        } else {
            *numRight += sign * num;
        }
    }

    if (num == 0 && (equation[strlen(equation) - 1] == 'x' || 
        (equation[strlen(equation) - 1] == '-' && equation[strlen(equation) - 2] == 'x'))) {
        if (leftSide) {
            *xLeft += sign;
        } else {
            *xRight += sign;
        }
    }
}

