long arrayManipulation(int n, int queries[][3], int m) {
    long *dp = (long *)calloc(n + 1, sizeof(long));
    if (dp == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return -1;
    }

    // Processing each query
    for (int i = 0; i < m; i++) {
        int a = queries[i][0];
        int b = queries[i][1];
        long k = queries[i][2];
        dp[a - 1] += k; // Increment the start index
        if (b <= n) {
            dp[b] -= k; // Decrement the position after end index
        }
    }

    long max_val = 0;
    long curr_sum = 0;

    // Calculating prefix sum to find the maximum value
    for (int i = 0; i < n; i++) {
        curr_sum += dp[i];
        if (curr_sum > max_val) {
            max_val = curr_sum; // Updating the max value found
        }
    }

    free(dp);
    return max_val;
}

int main() {
    int n = 5;
    int queries[3][3] = {{1, 2, 100}, {2, 5, 100}, {3, 4, 100}};

    long res = arrayManipulation(n, queries, 3);
    printf("%ld\n", res);

    return 0;
}

