long long modFact(int n, int p) {
    if (modFactCache[n] != -1) return modFactCache[n];
    if (n >= p) return 0;

    long long result = (fact[n] * fact[p - 2]) % p;
    for (int i = p - n - 1; i < p - 1; ++i) {
        result = (result * i) % p;
    }
    modFactCache[n] = result;
    return result;
