        int queue_size = rear - front;

        for (int i = 0; i < queue_size; i++) {
            char current[MAX_DISKS];
            strncpy(current, queue[front++], disks);

            if (strcmp(current, target_combination) == 0) {
                // Found the target combination
                return moves;
            }

            // Generate next states
