                // TODO: Check for visits and enqueue
                if (!visited[moves][j]) {
                    strncpy(queue[rear++], next_state, disks);
                    visited[moves][j] = 1;
                }

                // Move one disk down
                strncpy(next_state, current, disks);
                next_state[j] = (current[j] - '0' + 9) % 10 + '0';

                // TODO: Check for visits and enqueue
                if (!visited[moves][j]) {
