#define MAX_N 200001

void find_indices(int *a, int n, int *x, int *y) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (a[i] > 1 && a[j] > 0 && i != j) {
                *x = i;
                *y = j;
                return;
            }
        }
    }
    *x = -1; // Indicates no valid indices found
    *y = -1;
}

void solve() {
    int test_cases;
    scanf("%d", &test_cases);

    while (test_cases--) {
        int n;
        scanf("%d", &n);

        if (n < 3 || n > MAX_N) {
            printf("Error: Invalid input. The length of the array must be between 3 and %d.\n", MAX_N);
            continue;
        }

        int *a = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            a[i] = i + 1;
        }

        int steps = 0;

        while (1) {
            int count1 = 0, count2 = 0;
            for (int i = 0; i < n; i++) {
                if (a[i] == 1) count1++;
                if (a[i] == 2) count2++;
            }

            if (count1 == n - 1 && count2 == 1) break;

            int x, y;
            find_indices(a, n, &x, &y);
            if (x == -1 || y == -1) break; // No valid indices; exit loop

            a[x] = ceil((double)a[x] / a[y]);
            steps++;
            printf("%d\n", steps);
            printf("%d %d\n", x + 1, y + 1);
        }

        free(a);
    }
}

