#include <stdio.h>
#include <stdlib.h>

typedef struct TreeNode {
    int val;
    struct TreeNode* left;
    struct TreeNode* right;
} TreeNode;

void freeTree(TreeNode* node) {
    if (node) {
        freeTree(node->left);
        freeTree(node->right);
        free(node);
    }
}

int* helper(TreeNode* node, int include, int* max_size) {
    if (!node) {
        return &include;
    }

    int* left_include = helper(node->left, 1, max_size);
    int* right_include = helper(node->right, 1, max_size);

    // Check if parent is not connected to the left or right
    int new_include = include;
    if (node->left == NULL || node->right == NULL || *left_include == 0 || *right_include == 0) {
        new_include = 1; // Include current node
    } else {
        new_include = 0; // Don't include current node
    }

    // Update max size if the new set is larger
    if (new_include) {
        (*max_size)++;
    }

    // Return the inclusion state
    return &new_include;
}

int LISS(TreeNode* root) {
    int max_size = 0;
    helper(root, 0, &max_size);
    return max_size;
}

TreeNode* createNode(int val) {
    TreeNode* node = (TreeNode*)malloc(sizeof(TreeNode));
    node->val = val;
    node->left = NULL;
    node->right = NULL;
    return node;
}

