#define N 60
#define INF 1000000000000000000LL

long long n, nxt[N][N], memo[N][N];

void update(long long *a, long long b, long long c, long long d) {
    *a = (*a > d) ? *a : d;
    *a += b - (*a * c / d);
}

int main() {
    freopen(".in", "r", stdin);
    freopen(".out", "w", stdout);
    scanf("%lld", &n);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j <= i; ++j) {
            scanf("%lld", &nxt[i][j]);
        }
    }

    for (int i = n - 1; i >= 0; --i) {
        for (int j = 0; j <= i; ++j) {
            if (j == 0) {
                memo[i][j] = nxt[i][j];
            } else {
                memo[i][j] = memo[i + 1][j] + memo[i + 1][j - 1] - memo[i][j] + nxt[i][j];
            }
        }
    }

    long long best = -INF;
    for (int i = 1; i < n; ++i) {
        for (int j = 0; j < i; ++j) {
            update(&best, i - j, memo[i][j], memo[i][j + 1] + memo[i + 1][j] - memo[i][j]);
        }
    }

    printf("%.16f\n", best / 1.0);
    return 0;
}

