#include <stdio.h>
#include <string.h>
#include <stdlib.h>

void reverse_string(char *str) {
    int len = strlen(str);
    for (int i = 0; i < len / 2; i++) {
        char temp = str[i];
        str[i] = str[len - i - 1];
        str[len - i - 1] = temp;
    }
}

char **reverse_strings_and_order(char **arr, int size) {
    char **reversed = malloc(size * sizeof(char *));
    if (!reversed) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(EXIT_FAILURE);
    }

    for (int i = 0; i < size; i++) {
        reversed[i] = strdup(arr[size - 1 - i]);
        if (!reversed[i]) {
            fprintf(stderr, "Memory allocation failed\n");
            exit(EXIT_FAILURE);
        }
        reverse_string(reversed[i]);
    }

    return reversed;
}

void free_reversed_strings(char **arr, int size) {
    for (int i = 0; i < size; i++) {
        free(arr[i]);
    }
    free(arr);
}

int main() {
    char *input_array[] = {"I", "like", "big", "butts", "and", "I", "cannot", "lie!"};
    int size = sizeof(input_array) / sizeof(input_array[0]);

    char **output_array = reverse_strings_and_order(input_array, size);

    // Debug print
    for (int i = 0; i < size; i++) {
        printf("output_array[%d]: %s\n", i, output_array[i]);
    }

    free_reversed_strings(output_array, size);
    return 0;
}

