int longest_incrementing_subsequence_length(int arr[], int n) {
    int *indx = (int *)malloc(n * sizeof(int));
    int lis_length = 0;

    for (int i = 0; i < n; i++) {
        // Perform insertion sort
        int pos = 0;
        while (pos < lis_length && indx[pos] < arr[i]) {
            pos++;
        }
        // Update or Append
        if (pos == lis_length) {
            indx[lis_length++] = arr[i];
        } else {
            indx[pos] = arr[i];
        }
    }

    free(indx);
    return lis_length;
}

