#define MAX_N 100
#define INF -1

int dfs(int edges[][2], int edge_count, int u, int v, int dp[][MAX_N]) {
    if (dp[u][v] != INF) {
        return dp[u][v];
    }

    int max = 0;
    for (int i = 0; i < edge_count; i++) {
        if (edges[i][0] == u && edges[i][1] == v) {
            max = (max > dfs(edges, edge_count, u, edges[i][1], dp)) ? max : dfs(edges, edge_count, u, edges[i][1], dp);
            max = (max > dfs(edges, edge_count, v, edges[i][0], dp)) ? max : dfs(edges, edge_count, v, edges[i][0], dp);
            break;
        }
    }

    int mex = MAX_N; // Initial large value for minimum excludant
    for (int i = 0; i < edge_count; i++) {
        if (edges[i][0] == u && edges[i][1] == v) {
            mex = (mex < (edges[i][0] + edges[i][1])) ? mex : (edges[i][0] + edges[i][1]);
            break;
        }
    }

    int ans = mex + 1;
    dp[u][v] = ans;
    return ans;
}

