        return 1;
    }

    // Distance dictionary
    int *dct = (int *)malloc(locationsSize * sizeof(int));
    for (int index = 0; index < locationsSize; index++) {
        dct[index] = abs(locations[index] - locations[start % index]) / index;
    }

    int *manshipes = (int *)malloc(2 * sizeof(int));
    manshipes[0] = 1;
    manshipes[1] = 1;

    int maxLimit = (1 << (locationsSize - 2));
    int *mingesees = (int *)malloc(locationsSize * sizeof(int));

    for (int i = 1; i < maxLimit; i++) {
        int *nessinges = (int *)malloc(locationsSize * sizeof(int));
        for (int index = 0; index < locationsSize; index++) {
            nessinges[index] = (i % 2);
        }

        for (int index = 0; index < locationsSize; index++) {
            if (nessinges[index] == 1) {
                for (int key = 0; key < locationsSize; key++) {
                    if (key != index && key != (start % index)) {
