#define ALPHABET_SIZE 256
#define MAX_KEY_LENGTH 100

typedef struct TrieNode {
    char val;
    struct TrieNode* children[ALPHABET_SIZE];
    int is_word;
} TrieNode;

TrieNode* create_node(char val) {
    TrieNode* node = (TrieNode*)malloc(sizeof(TrieNode));
    node->val = val;
    for (int i = 0; i < ALPHABET_SIZE; i++) {
        node->children[i] = NULL;
    }
    node->is_word = 0;
    return node;
}

int search(TrieNode* root, const char* key, int level) {
    if (level == strlen(key)) return root->is_word;
    if (root->children[(unsigned char)key[level]] != NULL) {
        return search(root->children[(unsigned char)key[level]], key, level + 1);
    }
    return 0;
}

void insert(TrieNode* root, const char* key) {
    TrieNode* current = root;
    for (int i = 0; i < strlen(key); i++) {
        if (current->children[(unsigned char)key[i]] == NULL) {
            current->children[(unsigned char)key[i]] = create_node(key[i]);
        }
        current = current->children[(unsigned char)key[i]];
    }
    current->is_word = 1;
}

void print_str(TrieNode* root) {
    if (root) {
        for (int i = 0; i < ALPHABET_SIZE; i++) {
            if (root->children[i] != NULL) {
                print_str(root->children[i]);
            }
        }
        if (root->is_word) {
            putchar(root->val);
        }
    }
}

