int findMinDiff(int arr[], int M, int N) {
    // Sort the array
    qsort(arr, N, sizeof(int), compare);
    printf("Sorted array: ");
    for (int i = 0; i < N; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n");

    int ans = arr[N-1] - arr[0];
    int s = 0, e = M - 1;

    while (e < N) {
        int diff = arr[e] - arr[s];
        ans = (ans < diff) ? ans : diff;
        s++;
        e++;
    }

    return ans;
}

