#include <stdio.h>
#include <stdlib.h>

int** spiral_coords(int rows, int cols, int rStart, int cStart, int* returnSize) {
    int directions[4][2] = {{0, 1}, {1, 0}, {0, -1}, {-1, 0}};
    int dir_idx = 0;
    int** result = malloc(rows * cols * sizeof(int*));
    for (int i = 0; i < rows * cols; i++) {
        result[i] = malloc(2 * sizeof(int));
    }

    int curr_r = rStart, curr_c = cStart;
    *returnSize = 0;

    for (int i = 0; i < rows * cols; i++) {
        result[*returnSize][0] = curr_r;
        result[*returnSize][1] = curr_c;
        (*returnSize)++;

        curr_r += directions[dir_idx][0];
        curr_c += directions[dir_idx][1];

        int next_r = curr_r + directions[dir_idx][0];
        int next_c = curr_c + directions[dir_idx][1];

        int is_valid = (next_r >= 0 && next_r < rows && next_c >= 0 && next_c < cols);
        for (int j = 0; j < *returnSize; j++) {
            if (result[j][0] == next_r && result[j][1] == next_c) {
                is_valid = 0;
                break;
            }
        }

        if (is_valid) {
            curr_r = next_r;
            curr_c = next_c;
        } else {
            dir_idx = (dir_idx + 1) % 4;
            curr_r += directions[dir_idx][0];
            curr_c += directions[dir_idx][1];
        }
    }

    return result;
}

// Example usage:
int main() {
    int returnSize;
    int** result;

    result = spiral_coords(1, 4, 0, 0, &returnSize);
    for (int i = 0; i < returnSize; i++) {
        printf("[%d,%d]", result[i][0], result[i][1]);
        free(result[i]);
    }
    free(result);

    printf("\n");

    result = spiral_coords(5, 6, 1, 4, &returnSize);
    for (int i = 0; i < returnSize; i++) {
        printf("[%d,%d]", result[i][0], result[i][1]);
        free(result[i]);
    }
    free(result);

    printf("\n");
    return 0;
}

