int* xor_ascending(int* output, int size) {
    int* final = (int*)malloc(size * sizeof(int));
    final[0] = output[0];

    for (int i = 1; i < size; i++) {
        final[i] = output[i] ^ output[i - 1];
    }

    return final;
}

int main_xor() {
    int data[] = {1, 2, 4, 8, 16, 32};
    int size = sizeof(data) / sizeof(data[0]);
    int* result = xor_ascending(data, size);

    for (int i = 0; i < size; i++) {
        printf("Result[%d]: %d\n", i, result[i]);
    }
    free(result);
    return 0;
}

