#include <stdio.h>
#include <stdlib.h>

void swap(char* x, char* y) {
    char temp = *x;
    *x = *y;
    *y = temp;
}

void generate_permutations(char* a, int l, int r, char** result, int* indices, int* count) {
    if (l == r) {
        result[*count] = malloc((r + 1) * sizeof(char));
        for (int i = 0; i < r; i++) {
            result[*count][i] = a[i];
        }
        result[*count][r] = '\0'; // Null-terminate the string
        (*count)++;
    } else {
        for (int i = l; i <= r; i++) {
            swap((a + l), (a + i));
            generate_permutations(a, l + 1, r, result, indices, count);
            swap((a + l), (a + i)); // backtrack
        }
    }
}

char** permutations(char* a, int n, int* count) {
    char** result = malloc(1000 * sizeof(char*)); // Adjust size as necessary
    *count = 0;
    generate_permutations(a, 0, n - 1, result, NULL, count);
    return result;
}

char** solution(char* s, int n, int m, int p) {
    int count;
    char** perms = permutations(s, n, &count);

    char** result = malloc(m * sizeof(char*));
    for (int i = 0; i < m && (i + p) < count; i++) {
        result[i] = perms[i + p];
    }

    // Clean up the original permutations
    for (int i = 0; i < count; i++) {
        free(perms[i]);
    }
    free(perms);

    return result;
}

