#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_SET_SIZE 100
#define INPUT_BUFFER 256

typedef struct {
    int elements[MAX_SET_SIZE];
    int size;
} Set;

void init_set(Set *s) {
    s->size = 0;
}

int add_to_set(Set *s, int value) {
    for (int i = 0; i < s->size; i++) {
        if (s->elements[i] == value) {
            return 0;  // value already in set
        }
    }
    if (s->size < MAX_SET_SIZE) {
        s->elements[s->size++] = value;
        return 1;  // added successfully
    }
    return 0;  // set full
}

void print_set(Set *s) {
    for (int i = 0; i < s->size; i++) {
        printf("%d ", s->elements[i]);
    }
    printf("\n");
}

void difference_update(Set *a, Set *b) {
    for (int i = 0; i < b->size; i++) {
        for (int j = 0; j < a->size; j++) {
            if (a->elements[j] == b->elements[i]) {
                a->elements[j] = a->elements[--a->size]; // remove element from 'a'
                break;
            }
        }
    }
}

int main() {
    Set a, b;
    init_set(&a);
    init_set(&b);

    char buffer[INPUT_BUFFER];

    // Read input for Set A
    fgets(buffer, INPUT_BUFFER, stdin);
    char *token = strtok(buffer, " ");
    while (token != NULL) {
        add_to_set(&a, atoi(token));
        token = strtok(NULL, " ");
    }

    // Read input for Set B
    fgets(buffer, INPUT_BUFFER, stdin);
    token = strtok(buffer, " ");
    while (token != NULL) {
        add_to_set(&b, atoi(token));
        token = strtok(NULL, " ");
    }

    difference_update(&a, &b);
    difference_update(&b, &a); // Ensure both sets are updated

    printf("\n"); 
    for (int i = 0; i < a.size; i++) {
        if (a.size != 0) {
            printf("%d ", a.elements[i]);
        }
    }

    return 0;
}

