#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

bool check_plus_shape(int h, int w, char **picture) {
    int center_x = -1, center_y = -1;

    for (int i = 0; i < h; i++) {
        for (int j = 0; j < w; j++) {
            if (picture[i][j] == '*') {
                if (center_x == -1) {
                    center_x = j;
                    center_y = i;
                } else if (center_x != j || center_y != i) {
                    return false;
                }
            }
        }
    }

    int directions[4][2] = { {0, 1}, {0, -1}, {1, 0}, {-1, 0} };

    for (int d = 0; d < 4; d++) {
        int dx = directions[d][0];
        int dy = directions[d][1];
        int x = center_x + dx;
        int y = center_y + dy;

        while (x >= 0 && x < w && y >= 0 && y < h && picture[y][x] == '*') {
            x += dx;
            y += dy;
        }
        if (x < 0 || x >= w || y < 0 || y >= h) {
            continue;
        }
        if (picture[y][x] != '.') {
            return false;
        }
    }

    for (int i = 0; i < h; i++) {
        for (int j = 0; j < w; j++) {
            if (picture[i][j] == '*' && (i != center_y || j != center_x)) {
                bool is_part_of_ray = false;

                for (int d = 0; d < 4; d++) {
                    int dx = directions[d][0];
                    int dy = directions[d][1];
                    int x = center_x + dx;
                    int y = center_y + dy;

                    while (x >= 0 && x < w && y >= 0 && y < h && picture[y][x] == '*') {
                        if (x == j && y == i) {
                            is_part_of_ray = true;
                            break;
                        }
                        x += dx;
                        y += dy;
                    }

                    if (is_part_of_ray) {
                        break;
                    }
                }

                if (!is_part_of_ray) {
                    return false;
                }
            }
        }
    }

    return true;
}

int main() {
    int h, w;
    scanf("%d %d", &h, &w);

    char **picture = malloc(h * sizeof(char *));
    for (int i = 0; i < h; i++) {
        picture[i] = malloc((w + 1) * sizeof(char));
        scanf("%s", picture[i]);
    }

    if (check_plus_shape(h, w, picture)) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }

    for (int i = 0; i < h; i++) {
        free(picture[i]);
    }
    free(picture);

    return 0;
}

