    scanf("%s", N);
    int lenN = strlen(N);
    long long ans = 0;

    for (int i = 1; i <= lenN; i++) {
        for (int mask = 0; mask < (1 << 3); mask++) {
            long long x = 0;
            int ok = 1;

            for (int j = 0; j < i; j++) {
                int low = (j == 0) ? 1 : 0;

                if (mask & (1 << 0) && j == i - 1) {
                    low = (low > 7) ? low : 7;
                }
                if (mask & (1 << 1) && j == i - 1) {
                    low = (low > 5) ? low : 5;
                }
                if (mask & (1 << 2) && j == i - 1) {
                    low = (low > 3) ? low : 3;
                }

                long long currentN = atoll(strndup(N, i)); // Avoid overflow

                if (mask & (1 << 0) && x * 10 + 7 < currentN) {
                    x = x * 10 + 7;
                } else if (mask & (1 << 1) && x * 10 + 5 < currentN) {
                    x = x * 10 + 5;
                } else if (mask & (1 << 2) && x * 10 + 3 < currentN) {
                    x = x * 10 + 3;
                } else if (low <= 4 && x * 10 + low < currentN) {
                    x = x * 10 + low;
                } else {
                    ok = 0;
                    break;
                }
            }

            if (ok) {
                ans++;
                for (int k = 0; k < (1 << 3); k++) {
                    if (!(k & (1 << 0)) && !(mask & (1 << 0))) continue;
                    if (!(k & (1 << 1)) && !(mask & (1 << 1))) continue;
                    if (!(k & (1 << 2)) && !(mask & (1 << 2))) continue;
                    ans++;
                }
            }
        }
    }

    printf("%lld\n", ans);
    return 0;
}

