int totalFruit(int* tree, int size) {
    int *unique = malloc(size * sizeof(int));
    int count = 0, uniqueCount = 0, lastFruit = -1;

    // Count unique fruits and handle last fruit situation
    for (int i = 0; i < size; i++) {
        if (tree[i] != lastFruit) {
            unique[uniqueCount++] = tree[i];
            lastFruit = tree[i];
        }
    }

    // Calculate the total by modifying unique count
    count = size - uniqueCount;

    // Determine the maximum of the unique fruits ignoring the last fruit
    int maxFruit = 0;
    for (int i = 0; i < uniqueCount; i++) {
        if (unique[i] != tree[size - 1] && unique[i] > maxFruit) {
            maxFruit = unique[i];
        }
    }

    int result = count + maxFruit;
    free(unique);
    return result;
}

