char* intToStr(int x) {
    if (x == 0) {
        char* result = malloc(2);
        strcpy(result, "0");
        return result;
    }
    if (x < 0) {
        char* result = intToStr(-x);
        char* negativeResult = malloc(strlen(result) + 2);
        negativeResult[0] = '-';
        strcpy(negativeResult + 1, result);
        free(result);
        return negativeResult;
    }
    char* result = malloc(32); // Assume max 32 digits (very conservative)
    int index = 0;
    while (x) {
        result[index++] = '0' + (x % 3);
        x /= 3;
    }
    result[index] = '\0';
    // Reverse the result
    for (int i = 0; i < index / 2; i++) {
        char temp = result[i];
        result[i] = result[index - i - 1];
        result[index - i - 1] = temp;
    }
    return result;
}

