            int sum = s * p + 1;
            bool flag = false;

            if (sum == n) {
                for (int i = 0; i < k; i++) {
                    printf("%d ", sum);
                    flag += sum;  // Tracking sum
                    sum += 2;
                }
                flag -= 1;
                if (flag != 0) {
                    printf("%d ", sum);
