                for (int i = 0; i < k; i++) {
                    printf("%d ", sum);
                    flag += sum;  // Tracking sum
                    sum += 2;
                }
                if (flag != 0) {
                    printf("%d ", sum);
                }
            }
        } else {
            // Odd num are even
            int s = (int)pow(2, k - 1);
            int sum = s * (-1) + 1;
            bool flag = false;

            if (sum == n) {
                for (int i = 0; i < k; i++) {
