#define MAX_SKILLS 10
#define MAX_PEOPLE 100
#define HASH_SIZE 128

typedef struct {
    int *array;
    int used;
    int size;
} IntArray;

typedef struct {
    char* skill;
    int index;
} SkillIndex;

int hash(char* str) {
    unsigned long hash = 5381;
    int c;
    while ((c = *str++)) {
        hash = ((hash << 5) + hash) + c;
    }
    return hash % HASH_SIZE;
}

void initIntArray(IntArray* arr, int size) {
    arr->array = (int*)malloc(size * sizeof(int));
    arr->used = 0;
    arr->size = size;
}

void insertIntArray(IntArray* arr, int value) {
    if (arr->used >= arr->size) {
        arr->size *= 2;
        arr->array = (int*)realloc(arr->array, arr->size * sizeof(int));
    }
    arr->array[arr->used++] = value;
}

int containsIntArray(IntArray* arr, int value) {
    for (int i = 0; i < arr->used; i++) {
        if (arr->array[i] == value) {
            return 1;
        }
    }
    return 0;
}

int* smallestSufficientTeam(char** req_skills, int req_size, char*** people, int people_size, int* returnSize) {
    SkillIndex skill_index[HASH_SIZE] = {0};
    IntArray teams;
    initIntArray(&teams, people_size);

    int team_mask[1 << MAX_SKILLS];
    memset(team_mask, -1, sizeof(team_mask));
    int other_index[HASH_SIZE] = {0};

    for (int i = 0; i < req_size; i++) {
        int idx = hash(req_skills[i]);
        skill_index[idx].skill = req_skills[i];
        skill_index[idx].index = i;
    }

    for (int i = 0; i < people_size; i++) {
        int index = 0;
        for (int j = 0; j < MAX_SKILLS; j++) {
            if (other_index[hash(people[i][j])]) {
                index |= 1 << other_index[hash(people[i][j])];
            }
        }
        team_mask[index] = i;
        for (int j = 0; j < MAX_SKILLS; j++) {
            if (people[i][j]) {
                other_index[hash(people[i][j])] = j;
            }
        }
    }

    for (int i = 0; i < (1 << req_size); i++) {
        if (team_mask[i] != -1) {
            if (!containsIntArray(&teams, team_mask[i])) {
                insertIntArray(&teams, team_mask[i]);
            }
        }
    }

    *returnSize = teams.used;
    int* result = (int*)malloc(*returnSize * sizeof(int));
    for (int i = 0; i < teams.used; i++) {
        result[i] = teams.array[i];
    }

    free(teams.array);
    return result;
}

int main() {
    char* req_skills[] = {"java", "nodejs", "reactjs"};
    char** people[] = {
        (char*[]){"java"},
        (char*[]){"nodejs"},
        (char*[]){"nodejs", "reactjs"}
    };
    int returnSize;
    int* result = smallestSufficientTeam(req_skills, 3, people, 3, &returnSize);

    printf("Result: ");
    for (int i = 0; i < returnSize; i++) {
        printf("%d ", result[i]);
    }
    printf("\n");

    free(result);
    return 0;
}

