void maxBinaryString(int n, int k, const char *s, char *target, int *cnt) {
    int diff = 0;

    for (int i = 0; i < n; i++) {
        target[i] = '1';
        if (s[i] != target[i]) {
            diff++;
        }
    }

    for (int i = 0; i < n; i++) {
        cnt[i] = 0;
        if (s[i] != target[i]) {
            if (k >= diff) {
                cnt[i] = diff;
                k -= diff;
                diff = 0;
            } else if (k) {
                cnt[i] = k;
                diff -= k;
                k = 0; // ensure k becomes zero
            } else {
                cnt[i] -= 1;
                diff -= 1;
            }
        }
    }
}

