int product(int low, int high, int n, int *weights, int index, long *weight_combinations, int *combination_count) {
    if (index == n) {
        long total_weight = 0;
        for (int i = 0; i < n; i++) {
            total_weight += weights[i];
        }
        weight_combinations[(*combination_count)++] = total_weight;
        return 0;
