#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define MAX_WORDS 1000
#define MAX_LENGTH 100

typedef struct {
    char word[MAX_LENGTH];
    int count;
} WordCount;

typedef struct {
    WordCount arr[MAX_WORDS];
    int size;
} WordMap;

void insertWord(WordMap* map, const char* word) {
    for (int i = 0; i < map->size; ++i) {
        if (strcmp(map->arr[i].word, word) == 0) {
            map->arr[i].count++;
            return;
        }
    }
    strcpy(map->arr[map->size].word, word);
    map->arr[map->size].count = 1;
    map->size++;
}

int compare(const void* a, const void* b) {
    WordCount* countA = (WordCount*)a;
    WordCount* countB = (WordCount*)b;
    return countB->count - countA->count; // Descending order
}

void topKFrequent(char* str[], int m, int k) {
    WordMap map = { .size = 0 };
    for (int i = 0; i < m; ++i) {
        insertWord(&map, str[i]);
    }

    // Sort the words based on frequency
    qsort(map.arr, map.size, sizeof(WordCount), compare);

    printf("Top %d Frequent Words:\n", k);
    for (int i = 0; i < k && i < map.size; ++i) {
        printf("%s: %d\n", map.arr[i].word, map.arr[i].count);
    }
}

