#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <stdbool.h>

#define MAX_SIZE 100  // Adjust size as necessary
#define DIRECTIONS 4

typedef struct {
    int x, y;
} Point;

typedef struct {
    Point points[MAX_SIZE * MAX_SIZE];
    int front, rear;
} Deque;

void initDeque(Deque *q) {
    q->front = 0;
    q->rear = 0;
}

bool isEmpty(Deque *q) {
    return q->front == q->rear;
}

void pushBack(Deque *q, Point p) {
    q->points[q->rear++] = p;
}

Point popFront(Deque *q) {
    return q->points[q->front++];
}

int shortestBridge(int A[MAX_SIZE][MAX_SIZE], int n, int m) {
    Deque q;
    initDeque(&q);
    bool visited[MAX_SIZE][MAX_SIZE] = {false};
    int directions[DIRECTIONS][2] = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};
    int foundIsland = false;

    // Step 1: Find the first island and mark it
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (A[i][j] == 1 && !foundIsland) {
                pushBack(&q, (Point){i, j});
                visited[i][j] = true;
                foundIsland = true;

                for (int k = 0; k < q.rear; k++) {
                    Point current = q.points[k];
                    for (int d = 0; d < DIRECTIONS; d++) {
                        int newX = current.x + directions[d][0];
                        int newY = current.y + directions[d][1];
                        if (newX >= 0 && newY >= 0 && newX < n && newY < m && A[newX][newY] == 1 && !visited[newX][newY]) {
                            pushBack(&q, (Point){newX, newY});
                            visited[newX][newY] = true;
                        }
                    }
                }
            }
        }
    }

    // Step 2: Start BFS to find the minimum distance to the second island
    int distance = 0;
    while (!isEmpty(&q)) {
        int size = q.rear - q.front;  // Number of nodes at the current distance level

        for (int k = 0; k < size; k++) {
            Point current = popFront(&q);

            for (int d = 0; d < DIRECTIONS; d++) {
                int newX = current.x + directions[d][0];
                int newY = current.y + directions[d][1];

                if (newX >= 0 && newY >= 0 && newX < n && newY < m) {
                    if (A[newX][newY] == 1 && !visited[newX][newY]) {
                        return distance;  // Found the other island
                    }
                    if (A[newX][newY] == 0 && !visited[newX][newY]) {
                        pushBack(&q, (Point){newX, newY});
                        visited[newX][newY] = true;
                    }
                }
            }
        }
        distance++;  // Increment distance after processing this level
    }

    return -1;  // If no connection was found (should not happen as per problem statement)
}

int main() {
    int A[MAX_SIZE][MAX_SIZE] = {
        {0, 1, 0},
        {0, 0, 0},
        {0, 0, 1}
    };
    int n = 3, m = 3;

    int result = shortestBridge(A, n, m);
    printf("Minimum number of flips: %d\n", result);
    return 0;
}

