#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int start;
    int end;
} Segment;

int cmp(const void *a, const void *b) {
    Segment *segA = (Segment *)a;
    Segment *segB = (Segment *)b;

    if (segA->start != segB->start) {
        return segA->start - segB->start;
    }
    return segA->end - segB->end;
}

int minimum_movement(Segment *segments, int x0, int n) {
    // Sort the segments
    qsort(segments, n, sizeof(Segment), cmp);

    int minimum_movement = __INT_MAX__;

    for (int i = 0; i < n; i++) {
        int start = segments[i].start;
        int end = segments[i].end;

        // Calculate the offset needed for the segment
        int offset = (start > x0) ? (start - x0) : 0;

        // If the next sportsman starts before Bob's current position, it's not possible
        if (start < x0) {
            return -1;
        }

        // Update Bob's position to the end of the segment
        x0 = end;

        // Update the minimum movement needed so far
        if (offset < minimum_movement) {
            minimum_movement = offset;
        }
    }

    return minimum_movement;
}

int main() {
    int n;
    int x0;

    printf("Enter number of sportsmen: ");
    scanf("%d", &n);

    printf("Enter initial position of Bob: ");
    scanf("%d", &x0);

    Segment *segments = (Segment *)malloc(n * sizeof(Segment));
    if (segments == NULL) {
        fprintf(stderr, "Memory allocation failed!\n");
        return 1;
    }

    printf("Enter the segments (start end):\n");
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &segments[i].start, &segments[i].end);
    }

    int result = minimum_movement(segments, x0, n);
    printf("Minimum movement: %d\n", result);

    free(segments);
    return 0;
}

