#define MAX_SUM 200000 // Adjust this according to potential sums of pairs
#define DEFAULT_CAPACITY 64

typedef struct {
    int key;
    int value;
} Pair;

typedef struct {
    Pair *elements;
    int capacity;
    int size;
} HashMap;

HashMap* create_map(int capacity) {
    HashMap *map = malloc(sizeof(HashMap));
    map->capacity = capacity;
    map->size = 0;
    map->elements = malloc(capacity * sizeof(Pair));
    return map;
}

void free_map(HashMap *map) {
    free(map->elements);
    free(map);
}

int hashmap_get(HashMap *map, int key) {
    for (int i = 0; i < map->size; i++) {
        if (map->elements[i].key == key) {
            return map->elements[i].value;
        }
    }
    return 0;
}

void hashmap_put(HashMap *map, int key, int value) {
    for (int i = 0; i < map->size; i++) {
        if (map->elements[i].key == key) {
            map->elements[i].value += value;
            return;
        }
    }
    if (map->size >= map->capacity) {
        // TODO: Implement resizing logic for hashmap
        return;
    }
    map->elements[map->size++] = (Pair){key, value};
}

long long count_quadruples(int N, int T, int *S) {
    long long count = 0;
    HashMap *sum_pairs = create_map(DEFAULT_CAPACITY);

    for (int i = 0; i < N; i++) {
        for (int j = i + 1; j < N; j++) {
            int current_sum = S[i] + S[j];
            int target_sum = T - current_sum;
            count += hashmap_get(sum_pairs, target_sum);
            hashmap_put(sum_pairs, current_sum, 1);
        }
    }

    free_map(sum_pairs);
    return count;
}

int main() {
    int N, T;
    scanf("%d %d", &N, &T);
    int *S = malloc(N * sizeof(int));

    for (int i = 0; i < N; i++) {
        scanf("%d", &S[i]);
    }

    long long result = count_quadruples(N, T, S);
    printf("%lld\n", result);

    free(S);
    return 0;
}

