void process_strings(const char *a, const char *b) {
    char *d = (char *)malloc(strlen(a) + 1);
    if (d == NULL) {
        perror("Failed to allocate memory");
        return;
    }

    size_t len = strlen(a);
    for (size_t i = 0; i < len; i++) {
        char i_char = a[i];
        char j_char = b[i];

        if (i_char == j_char) {
            d[i] = i_char;
        } else {
            d[i] = (char)(i_char - 1);
        }
    }
    d[len] = '\0';  // Null-terminate the string

    // Debug print to check values
    printf("Processed string: %s\n", d);

    // Sort function for comparison
    char *sorted_a = strdup(a);
    char *sorted_d = strdup(d);
    if (sorted_a == NULL || sorted_d == NULL) {
        perror("Failed to allocate memory for sorting");
        free(d);
        return;
    }

    // Simple sort (bubble sort for demonstration)
    for (size_t i = 0; i < len - 1; i++) {
        for (size_t j = 0; j < len - i - 1; j++) {
            if (sorted_a[j] > sorted_a[j + 1]) {
                char temp = sorted_a[j];
                sorted_a[j] = sorted_a[j + 1];
                sorted_a[j + 1] = temp;
            }
            if (sorted_d[j] > sorted_d[j + 1]) {
                char temp = sorted_d[j];
                sorted_d[j] = sorted_d[j + 1];
                sorted_d[j + 1] = temp;
            }
        }
    }

    // Comparison result
    if (strcmp(sorted_a, sorted_d) == 0) {
        printf("%s\n", d);
    } else {
        printf("-1\n");
    }

    // Cleanup
    free(d);
    free(sorted_a);
    free(sorted_d);
}

