double mean(double *arr, int size) {
    double sum = 0.0;
    for (int i = 0; i < size; i++) {
        sum += arr[i];
    }
    return sum / size;
}

double variance(double *arr, int size, double mean) {
    double sum = 0.0;
    for (int i = 0; i < size; i++) {
        sum += (arr[i] - mean) * (arr[i] - mean);
    }
    return sum / size;
}

double median_absolute_error(double *true_vals, double *pred_vals, int size) {
    double mae = 0.0;
    for (int i = 0; i < size; i++) {
        mae += fabs(true_vals[i] - pred_vals[i]);
    }
    return mae / size;
}

