#define MAX_LENGTH 1000

int main() {
    char s[MAX_LENGTH];
    int q;

    // Read input string
    fgets(s, sizeof(s), stdin);
    s[strcspn(s, "\n")] = 0; // Remove newline character

    // Read number of queries
    scanf("%d\n", &q);
    size_t length = strlen(s);
    char *result = malloc((length + 1) * sizeof(char));
    strcpy(result, s);

    // Process each query
    for (int i = 0; i < q; i++) {
        char op[3];
        fgets(op, sizeof(op), stdin);

        if (op[0] == '1') {
            // Reverse the result string
            for (size_t j = 0, k = length - 1; j < k; j++, k--) {
                char temp = result[j];
                result[j] = result[k];
                result[k] = temp;
            }
        } else {
            int o = op[2] - '0'; // Convert char to int
            char c = op[4]; // Character to insert

            if (o == 1) {
                // Insert at the front
                memmove(result + 1, result, length); // Shift right
                result[0] = c;
                length++;
            } else {
                // Append to the end
                result[length] = c;
                length++;
            }
            result[length] = '\0'; // Null-terminate the string
        }
    }

    // Output the result
    printf("%s\n", result);
    free(result);
    return 0;
}

