char* findMaximumNum(char* num, int k) {
    // Defensive coding - check for null input
    if (k == 0 || num == NULL || strlen(num) == 0) {
        return num;
    }

    int max_num = 0, max_pos = 0;
    int n = strlen(num);
    char* temp = (char*)malloc(n + 2); // +2 for max digit and null terminator

    for (int i = 0; i < n; i++) { // O(n)
        // Finding max within the valid range
        char max_digit = num[i];
        for (int j = i; j <= n - k; j++) {
            if (num[j] > max_digit) {
                max_digit = num[j];
            }
        }

        snprintf(temp, n + 2, "%.*s%c%s", i, num, max_digit, num + i + (max_digit == num[i] ? 1 : 0));

        int temp_num = atoi(temp);
        if (temp_num > max_num) {
            max_num = temp_num;
            max_pos = i;
        }
    }

    // Clean up
    free(temp);

    // Recursive call with adjusted parameters
    if (k > 0) {
        char* trimmed_num = findMaximumNum(&num[max_pos + 1], k - 1);
        char* result = (char*)malloc(strlen(trimmed_num) + 2); // +1 for max_pos digit and null terminator
        snprintf(result, strlen(trimmed_num) + 2, "%c%s", num[max_pos], trimmed_num);
        return result;
    }

    char* result = (char*)malloc(12); // Assume max 11 digits
    snprintf(result, 12, "%d", max_num);
    return result;
}

int main() {
    char num[] = "123456789";
    int k = 3;
    char* result = findMaximumNum(num, k);

    printf("Maximum Number: %s\n", result);

    free(result);
    return 0;
}

