int calculate_min_cost(int n, char *a, char *b) {
    int cost = 0;
    // TODO: Consider dynamic allocation for larger inputs

    // Flip bits
    for (int i = 0; i < n; i++) {
        if (a[i] != b[i]) {
            b[i] = (a[i] == '0') ? '1' : '0'; // Flip bit
            cost += 1;
        }
    }

    // Check for remaining swaps between different positions
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (a[i] == b[j] && a[j] == b[i]) {
                cost += abs(i - j);
                break; // Optimize: Found a swap, exit inner loop
            }
        }
    }

    return cost;
}

int main() {
    int n;
    // Read input
    printf("Enter number of bits: ");
    scanf("%d", &n);

