    printf("Enter first string (a): ");
    scanf("%s", a);
    printf("Enter second string (b): ");
    scanf("%s", b);

    // Calculate and print minimum cost
    int min_cost = calculate_min_cost(n, a, b);
    printf("Minimum cost: %d\n", min_cost);

    // Free allocated memory
    free(a);
    free(b);

    return 0;
}

