int beautiful_mat(int **nums, int rows) {
    int count = 0;
    int *temp = (int *)malloc(rows * rows * sizeof(int));
    int temp_index = 0;

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < sizeof(nums[i]) / sizeof(nums[i][0]); j++) {
            int is_duplicate = 0;
            for (int k = 0; k < temp_index; k++) {
                if (temp[k] == nums[i][j]) {
                    is_duplicate = 1;
                    break;
                }
            }

            if (!is_duplicate) {
                temp[temp_index] = nums[i][j];
                temp_index++;
            }
        }
    }

    printf("No dupes: ");
    for (int l = 0; l < temp_index; l++) {
          printf("%d ", temp[l]);
    }
    printf("\n");

    free(temp);

    return temp_index % 2; 
}

