void initialize_dp(int **dp, int n) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            dp[i][j] = INT_MAX;
        }
        dp[i][i] = 0;
    }
}

int min_weight_triangulation(int n) {
    if (n == 3) {
        return 6;
    }

    int **dp = malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        dp[i] = malloc(n * sizeof(int));
    }

    initialize_dp(dp, n);

    for (int length = 2; length < n; length++) {
        for (int i = 0; i < n - length; i++) {
            int j = (i + length) % n;
            for (int k = i; k < j; k++) {
                k = k % n; 
                int weight = (i + 1) * (k + 1) * (j + 1);
                if (length == 2) {
                    dp[i][j] = weight;
                } else {
                    dp[i][j] = (dp[i][j] < (dp[i][(k + n - 1) % n] + dp[(k + 1) % n][j] + weight)) ? dp[i][j] : (dp[i][(k + n - 1) % n] + dp[(k + 1) % n][j] + weight);
                }
            }
        }
    }

    int result = dp[0][n - 2];

    for (int i = 0; i < n; i++) {
        free(dp[i]);
    }
    free(dp);

    return result;
}

int main() {
    int n;
    printf("Enter number of vertices: ");
    scanf("%d", &n);

    int result = min_weight_triangulation(n);
    printf("Minimum weight triangulation: %d\n", result);

    return 0;
}

