int numOfMinutes(int n, int headID, int *manager, int *informTime) {
    int *tree = (int *)calloc(n, sizeof(int));
    int *timeToInform = (int *)calloc(n, sizeof(int));

    // Build tree structure
    for (int i = 0; i < n; i++) {
        if (manager[i] != -1) {
            tree[manager[i]]++;
        }
    }

    // Initialize informing times
    for (int i = 0; i < n; i++) {
        timeToInform[i] = informTime[i];
    }

    // Debug print: Initial trees
    for (int i = 0; i < n; i++) {
        printf("Employee %d reports to %d, inform time: %d\n", i, manager[i], informTime[i]);
    }

    // Iterative DFS/BFS to calculate total time needed
    int totalTime = 0;
    for (int i = 0; i < n; i++) {
        if (manager[i] == headID) {
            int currentTime = informTime[i];
            int employee = i;
            while (employee != -1) {
                totalTime = fmax(totalTime, currentTime);
                currentTime += informTime[manager[employee]];
                employee = manager[employee];
            }
        }
    }

    free(tree);
    free(timeToInform);
    return totalTime;
}

