    }

    int dp[MAX_N];
    for (int i = 0; i < n; i++) {
        dp[i] = INT_MAX;
    }
    dp[0] = 0;

    int qmin[MAX_N], qmax[MAX_N];
    int front_min = 0, back_min = 0;
    int front_max = 0, back_max = 0;

    for (int i = 1; i < n; i++) {
        while (back_min > front_min && h[qmin[back_min - 1]] >= h[i]) {
            back_min--;
        }
        while (back_max > front_max && h[qmax[back_max - 1]] <= h[i]) {
            back_max--;
        }

        qmin[back_min++] = i;
        qmax[back_max++] = i;

        while (back_min > front_min && qmin[front_min] < i - 1 && h[qmin[front_min]] < (h[i - 1] < h[i] ? h[i - 1] : h[i])) {
            front_min++;
        }
        while (back_max > front_max && qmax[front_max] < i - 1 && h[qmax[front_max]] > (h[i - 1] > h[i] ? h[i - 1] : h[i])) {
            front_max++;
        }

        if (back_min > front_min && h[qmin[front_min]] < (h[i - 1] < h[i] ? h[i - 1] : h[i])) {
            dp[i] = dp[i - 1] + 1 < dp[i] ? dp[i - 1] + 1 : dp[i];
        }
        if (back_max > front_max && h[qmax[front_max]] > (h[i - 1] > h[i] ? h[i - 1] : h[i])) {
            dp[i] = dp[i - 1] + 1 < dp[i] ? dp[i - 1] + 1 : dp[i];
        }

        if (i > 1) {
            int j = i - 2;
            while (j >= 0 && h[j] < h[i]) {
                j--;
            }
            if (j >= 0) {
                dp[i] = dp[j] + 2 < dp[i] ? dp[j] + 2 : dp[i];
            }

            j = i - 2;
            while (j >= 0 && h[j] > h[i]) {
                j--;
            }
            if (j >= 0) {
                dp[i] = dp[j] + 2 < dp[i] ? dp[j] + 2 : dp[i];
            }
        }
    }

    printf("%d\n", dp[n - 1]);
    return 0;
}

