    }

    const char* abc = "abcdefghijklmnopqrstuvwxyz";
    bool overall_result = true;

    for (int i = 0; i < n; i++) {
        char* st = str_list[i];
        int prev = -1;
        bool used_chars[ALPHABET_SIZE] = {false};
