void changeBits(char *a_str, char *b_str, char **queries, int q) {
    // Convert binary strings to integers
    unsigned long long a = strtoull(a_str, NULL, 2);
    unsigned long long b = strtoull(b_str, NULL, 2);
    int n = strlen(a_str);

    char ans[100]; // Assuming max length for result storage
    int ans_index = 0;

    for (int i = 0; i < q; ++i) {
        char *query = queries[i];
        char command[10];
        int idx, x;

        sscanf(query, "%s %d", command, &idx);

        if (strcmp(command, "set_a") == 0) {
            sscanf(query, "%s %d %d", command, &idx, &x);
            a = (a & ~(1ULL << idx)) | ((unsigned long long)x << idx);
        } else if (strcmp(command, "set_b") == 0) {
            sscanf(query, "%s %d %d", command, &idx, &x);
            b = (b & ~(1ULL << idx)) | ((unsigned long long)x << idx);
        } else if (strcmp(command, "get_c") == 0) {
            unsigned long long c = a + b;
            // Ensure c is long enough by padding with zeros if necessary
            char c_str[100]; // Assuming max length for binary result
            snprintf(c_str, sizeof(c_str), "%llu", c);
            int c_length = strlen(c_str) * 4; // Rough estimate for binary length
            char binary_c[c_length + 3]; // Additional space for leading zeros

            // Convert integer to binary string
            for (int j = 0; j < c_length; ++j) {
                binary_c[c_length - 1 - j] = (c & 1) ? '1' : '0';
                c >>= 1;
            }
            binary_c[c_length] = '\0';
            // Pad with zeros
            snprintf(ans + ans_index, sizeof(ans) - ans_index, "%c", binary_c[c_length - idx - 1]);
            ans_index++;
        }
    }

    // Printing the result
    for (int i = 0; i < ans_index; ++i) {
        printf("%c", ans[i]);
    }
    printf("\n");
}

int main() {
    int n, q;
    scanf("%d %d", &n, &q);
    char a[100], b[100];
    scanf("%s", a);
    scanf("%s", b);

    char **queries = malloc(q * sizeof(char *));
    for (int i = 0; i < q; ++i) {
        queries[i] = malloc(100 * sizeof(char)); // Assuming max query length
        scanf("%s", queries[i]);
    }

    changeBits(a, b, queries, q);

    for (int i = 0; i < q; ++i) {
        free(queries[i]);
    }
    free(queries);

    return 0;
}

#include <stdio.h>
