#define ALPHABET_SIZE 26

typedef struct TrieNode {
    struct TrieNode *children[ALPHABET_SIZE];
    int val;
} TrieNode;

typedef struct Trie {
    TrieNode *root;
} Trie;

TrieNode* getNewNode() {
    TrieNode* newNode = (TrieNode*)malloc(sizeof(TrieNode));
    if (newNode) {
        for (int i = 0; i < ALPHABET_SIZE; i++) {
            newNode->children[i] = NULL;
        }
        newNode->val = 0;
    }
    return newNode;
}

void insert(Trie* trie, const char* word) {
    TrieNode* pointer = trie->root;
    for (int i = 0; word[i]; i++) {
        int pos = word[i] - 'a';
        if (pointer->children[pos] == NULL) {
            pointer->children[pos] = getNewNode();
        }
        pointer = pointer->children[pos];
    }
    pointer->val = 1;
}

int search(Trie* trie, const char* word) {
    TrieNode* pointer = trie->root;
    for (int i = 0; word[i]; i++) {
        int position = word[i] - 'a';
        if (pointer->children[position] == NULL) {
            return 0;
        }
        pointer = pointer->children[position];
    }
    return pointer->val;
}

int solve(int n, char** keys, const char* search) {
    Trie trieObj;
    trieObj.root = getNewNode();

    for (int i = 0; i < n; i++) {
        insert(&trieObj, keys[i]);
    }
    return search(&trieObj, search);
}

