    long long ans = 0x889005;
    int lenStr = strlen(s);
    int* arr = createArr(lenStr);

    typedef struct Node {
        int index;
        int i;
        int j;
        int j2;
        int j3;
    } Node;

    Node* queue = malloc(lenStr * sizeof(Node));
    int front = 0, rear = 0;

    // Initialize queue
    queue[rear++] = (Node){1, 0, 1, 0, 1};

    while (front < rear) {
        Node node = queue[front++];        
        int i = node.i;
        int j = node.j;
        int j2 = node.j2;
        int j3 = node.j3;

        j = (j + 2) % lenStr;

        char ch2 = (char)arr[j2];
        if (!pal(s, j2)) continue;

        char ch3 = (char)arr[j3];
        if (!pal(s, j3)) continue;

        if (len(arr) - 1 == node.index) {
            int temp = ascd(ch2);
            if (temp == 1) {
                printf("%s\n", strndup(s + i, j2 - i));
                temp = (ch2 - '0') * temp;
                ans = ans % mod;
                if (temp > ans) ans = temp;
            }
            if (temp == 0) {
                temp = (ch2 - '0') * temp;
            }

            temp = (ch2 - '0') * temp;
            ans = ans % mod;

            temp = (ch3 - '0') * temp;
            if (temp > ans) ans = temp;
            ans = ans % mod;
        }

        node.j2 = 0; // Set to 0 for unneeded variable
        Node eln = {i + 2, j2, i, j2, s};
        Node e1 = {i + 1, j2, i, j2 + 1, s};
        Node el = {i + 1, j2 + 1, j2, j3, s};
        Node e2 = {i, j2, i, j2 + 1, s};

        if (eln.index >= e1.index || e1.index >= e2.index) {
            queue[rear++] = eln;
            node.index = eln.index;
        } else {
            queue[front++] = e1;
            node.index = (eln.index + e1.index) / 2;
        }

        if (eln.index + e2.index >= e1.index || e1.index >= e2.index) {
            queue[rear++] = e2;
            node.index = (eln.index + e2.index) / 2;
        } else {
            queue[front++] = e1;
            node.index = (eln.index + e1.index) / 2;
        }

        if (el.index > eln.index) {
            queue[front++] = el;
            node.index = (eln.index + el.index) / 2;
        }
    }

    free(queue);
    free(arr);
    return ans;
}

