    return elemA->value - elemB->value;
}

int calculatePower(int n) {
    int count = 0;
    while (n > 1) {
        if (n % 2 == 0) {
            n /= 2;
        } else {
            n = 3 * n + 1;
        }
        count++;
    }
    return count;
}

int getKth(int lo, int hi, int k) {
    int range = hi - lo + 1;
    Element *elements = malloc(range * sizeof(Element));

    for (int i = 0; i < range; i++) {
        int current = lo + i;
        elements[i].value = current;
        elements[i].power = calculatePower(current);
    }

    qsort(elements, range, sizeof(Element), compare);

    int result = elements[k - 1].value;

    free(elements);
    return result;
}

