#include <stdio.h>
#include <stdlib.h>

int* addNegabinary(int* arr1, int arr1Size, int* arr2, int arr2Size, int* returnSize) {
    int* ans = (int*)malloc((arr1Size + arr2Size + 1) * sizeof(int));
    int carry = 0;
    int i = arr1Size - 1;
    int j = arr2Size - 1;
    int k = 0;

    while (i >= 0 || j >= 0 || carry) {
        if (i >= 0) carry += arr1[i--];
        if (j >= 0) carry += arr2[j--];

        ans[k++] = carry % 2;
        carry = -(carry % 2) + carry / 2;

        // Debug print:
        printf("i: %d, j: %d, carry: %d, ans[%d]: %d\n", i + 1, j + 1, carry, k - 1, ans[k - 1]);
    }

    while (k > 1 && ans[k - 1] == 0) k--;

    // Reverse the answer array
    for (int left = 0, right = k - 1; left < right; left++, right--) {
        int temp = ans[left];
        ans[left] = ans[right];
        ans[right] = temp;
    }

    *returnSize = k;
    return ans;
}

