            return reachingPoints(sy, sx, tx, ty);
        } else if (sxx == syy) {
            if ((tx - sy) % sx == 0 && (ty - sx) % sy == 0 && (tx - sy) / sx >= 0 && (ty - sx) / sy >= 0)
                return true;
            return false;
        } else {
            if ((tx - sx) % sy == 0 && (ty - sy) % sx == 0 && (tx - sx) / sy >= 0 && (ty - sy) / sx >= 0)
                return true;
            return false;
        }
    } else if (sx >= 0 && sy < 0) {
        if (sx == -tx && -sy == ty)
            return true;

        int sxx = abs(tx), syy = abs(ty);

        if (sxx < syy) {
            return reachingPoints(-sy, sx, tx, ty);
        } else if (sxx == syy) {
            if ((-tx - sy) % sx == 0 && (-ty + sx) % sy == 0 && (-tx - sy) / sx >= 0 && (-ty + sx) / sy >= 0)
                return true;
            return false;
        } else {
            if ((-tx + sy) % sy == 0 && (-ty - sx) % sx == 0 && (-tx + sy) / sy >= 0 && (-ty - sx) / sx >= 0)
                return true;
            return false;
        }
    } else {
        if (sx == tx && sy - ty == 1) return true;

        int sxx = abs(tx), syy = abs(ty);
        return reachingPoints(-sx, -sy, tx, ty);
    }
}

