int merge_creatures(int n, int* sizes) {
    int* color_counts = (int*)calloc(200, sizeof(int)); // Assuming sizes range from 0 to 199
    int unique_colors = 0;

    for (int i = 0; i < n; i++) {
        if (sizes[i] < 200) {
            color_counts[sizes[i]]++;
            if (color_counts[sizes[i]] == 1) {
                unique_colors++;
            }
        }
    }

    while (unique_colors > 1) {
        int new_colors[200] = {0}; // Track colors that are doubled
        for (int i = 0; i < 200; i++) {
            if (color_counts[i] > 0 && i * 2 < 200) {
                if (color_counts[i * 2] == 0) {
                    new_colors[i] = 1; // Color i can produce a new color
                }
            }
        }

        int new_unique_colors = 0;
        for (int i = 0; i < 200; i++) {
            if (new_colors[i]) {
                unique_colors--;
            }
        }

        // Update color_counts for new colors
        for (int i = 0; i < 200; i++) {
            if (color_counts[i] > 0 && new_colors[i]) {
                color_counts[i] = 0; // Remove old color
                new_unique_colors++;
            }
        }

        unique_colors += new_unique_colors; // Increment unique colors count
    }

    free(color_counts);
    return unique_colors;
}

