void construct_factor(int n, int **prime_fac, int *count) {
    assert(n > 0);
    *count = 0;
    int root = (int)sqrt(n);
    for (int i = 2; i <= root; ++i) {
        while (n % i == 0) {
            (*prime_fac)[(*count)++] = i;
            n /= i;
        }
    }
    if (n > 1) {
        (*prime_fac)[(*count)++] = n;
    }
}

