int solve(char **lines, int n) {
    int isAmazingBest = 1;
    int isAmazingWorst = 1;

    int newRecordBest = atoi(lines[1]);
    int newRecordWorst = atoi(lines[1]);

    int countDict[1000][3] = {0}; // Assuming a reasonable range for input count
    int countIndex = 0;

    for (int index = 2; index < n; index++) {
        int currentValue = atoi(lines[index]);

        if (isAmazingBest && newRecordBest > currentValue) {
            isAmazingBest = 0;
        }

        if (isAmazingWorst && newRecordWorst < currentValue) {
            isAmazingWorst = 0;
        }

        int foundIndex = -1;
        for (int j = 0; j < countIndex; j++) {
            if (countDict[j][0] == currentValue) {
                foundIndex = j;
                break;
            }
        }

        if (foundIndex != -1) {
            if (isAmazingBest) {
                countDict[foundIndex][1] = 1;
            }

            if (isAmazingWorst) {
                countDict[foundIndex][2] = 1;
            }
        } else {
            countDict[countIndex][0] = currentValue;
            countDict[countIndex][1] = isAmazingBest ? 1 : 0;
            countDict[countIndex][2] = isAmazingWorst ? 1 : 0;
            countIndex++;
        }

        newRecordBest = currentValue;
        newRecordWorst = currentValue;

        if (index == n - 1) {
            if (isAmazingBest) {
                countDict[foundIndex][1] = 1;
            }
            if (isAmazingWorst) {
                countDict[foundIndex][2] = 1;
            }
        }

        printf("Index: %d, AmazingBest: %d, AmazingWorst: %d, CountDict: ", index, isAmazingBest, isAmazingWorst);
        for (int k = 0; k < countIndex; k++) {
            printf("(%d, %d, %d) ", countDict[k][0], countDict[k][1], countDict[k][2]);
        }
        printf("\n");
    }

    int answer = 0;
    for (int i = 0; i < countIndex; i++) {
        if (countDict[i][1] == 1 && countDict[i][2] == 1) {
            answer += 1;
        }
    }
    return answer;
}

