#include <stdio.h>
#include <stdlib.h>

void calculate_recovery(int N, int* d_list, long long** dp) {
    for (int l = 2; l <= N; l++) {
        for (int i = 1; i <= N + 1 - l; i++) {
            int j = l + i - 1;
            dp[i][j] = (d_list[i - 1] * dp[i + 1][j] + d_list[j - 1] > d_list[i - 1] * dp[i][j - 1] + d_list[j - 1]) ? 
                         d_list[i - 1] * dp[i + 1][j] + d_list[j - 1] : 
                         d_list[i - 1] * dp[i][j - 1] + d_list[j - 1];
        }
    }
}

long long sum_dp(int N, long long** dp) {
    long long total = 0;
    for (int i = 1; i <= N / 2; i++) {
        for (int j = N / 2 + 1; j <= N; j++) {
            total += dp[i][j];
        }
    }
    return total;
}

int main() {
    int N;
    scanf("%d", &N);
    int* d_list = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &d_list[i]);
    }

    long long** dp = (long long**)malloc((N + 1) * sizeof(long long*));
    for (int i = 0; i <= N; i++) {
        dp[i] = (long long*)calloc(N + 1, sizeof(long long));
    }

    calculate_recovery(N, d_list, dp);
    long long result = sum_dp(N, dp);
    printf("%lld\n", result);

    // Free allocated memory
    for (int i = 0; i <= N; i++) {
        free(dp[i]);
    }
    free(dp);
    free(d_list);
    return 0;
}

