#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node *left, *right;
    int min_sum_pru;
    int path;
} Node;

Node* createNode(int data) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->data = data;
    newNode->left = NULL;
    newNode->right = NULL;
    newNode->min_sum_pru = -1;
    newNode->path = -1;
    return newNode;
}

Node* buildTree(int arr[], int size) {
    if (size == 0) return NULL;
    Node* root = createNode(arr[0]);
    Node** stack_nodes = (Node**)malloc(size * sizeof(Node*));
    int stack_position = 0;
    stack_nodes[stack_position++] = root;
    for (int i = 1; i < size;) {
        Node* curr_node = stack_nodes[stack_position - 1];
        if (arr[i] != -1) {
            if (!curr_node->left) {
                curr_node->left = createNode(arr[i]);
                stack_nodes[stack_position++] = curr_node->left;
            }
            i++;
        } else {
            i++;
        }
        if (i < size && arr[i] != -1) {
            if (!curr_node->right) {
                curr_node->right = createNode(arr[i]);
                stack_nodes[stack_position++] = curr_node->right;
            }
            i++;
        } else {
            i++;
        }
        if (arr[i - 1] == -1) {
            stack_position--;
        }
    }
    free(stack_nodes);
    return root;
}

int minimumSumPathFromRoot(Node* node) {
    if (!node) return 0;
    int curr_min_sum = node->data;
    Node** stack = (Node**)malloc(100 * sizeof(Node*));
    int stack_length = 0;
    if (node->left) stack[stack_length++] = node;

    while (stack_length > 0) {
        Node* curr_node = stack[--stack_length];
        if (!curr_node->left && curr_node->right) {
            curr_min_sum = (curr_min_sum < curr_node->data + curr_node->right->data) ? curr_min_sum : (curr_node->data + curr_node->right->data);
        }
        if (curr_node->left) {
            stack[stack_length++] = curr_node;
            stack[stack_length++] = curr_node->left;
            curr_min_sum = (curr_min_sum < curr_node->left->data) ? curr_min_sum : curr_node->left->data;
        }
    }
    free(stack);
    return curr_min_sum;
}

