    if (rows == NULL || columns == NULL) {
        // Handle memory allocation error
        fprintf(stderr, "Memory allocation failed\n");
        return 0;
    }

    // Create rows
    for (int i = 0; i < word_length; i += m) {
        strncat(rows, word + i, m);
    }

    // Create columns
    for (int i = 0; i < word_length; i += n) {
        strncat(columns, word + i, n);
    }

    int is_vowel = 1;
    char vowels[] = "aeiou";
    for (int i = 0; i < strlen(vowels); i++) {
        if (strchr(rows, vowels[i]) == NULL) {
            is_vowel = 0;
            break;
        }
    }

    int is_col_vowel = 1;
    for (int i = 0; i < strlen(vowels); i++) {
        if (strchr(columns, vowels[i]) == NULL) {
            is_col_vowel = 0;
            break;
        }
    }

    free(rows);
    free(columns);
    return is_vowel && is_col_vowel;
}

char *find_vowelly_word(int k) {
    int *factors = (int *)malloc(2 * sizeof(int) * (int)(sqrt(k) + 1));
    int factor_count = 0;

    for (int i = 1; i <= sqrt(k); i++) {
        if (k % i == 0) {
            factors[factor_count++] = i;
            factors[factor_count++] = k / i;
        }
    }

    for (int i = 0; i < factor_count; i += 2) {
        int n = factors[i];
        int m = factors[i + 1];

        char *word = (char *)malloc(k + 1);
        if (word == NULL) {
            // Handle memory allocation error
            fprintf(stderr, "Memory allocation failed\n");
            free(factors);
            return "-1";
        }

        // Create the word
        for (int j = 0; j < k; j++) {
            word[j] = "aeiou"[j % 5];
        }
        word[k] = '\0';

        if (is_vowelly_word(word, n, m)) {
            free(factors);
            return word;
        }

        free(word);
    }

    free(factors);
    return "-1";
}

