#include <stdio.h>
#include <stdlib.h>

#define MAX_SIZE 1000

int main() {
    int n, m, i, j, score_temp, score = 0, flag = 0, scalar = 2;
    int xp[MAX_SIZE];
    int Ap[MAX_SIZE];
    int size_Ap = 0;

    scanf("%d %d %d", &n, &m, &flag);
    while (--n) {
        for (i = 0; i < m; i++) {
            scanf("%d", &j);
            // Insert unique value into Ap
            int found = 0;
            for (int k = 0; k < size_Ap; k++) {
                if (Ap[k] == j) {
                    found = 1;
                    break;
                }
            }
            if (!found) {
                Ap[size_Ap++] = j;
            }
            // Pushback love into xp
            xp[i] = j;
        }

        // Unique sort xp
        int unique_count = 0;
        for (i = 0; i < m; i++) {
            int found = 0;
            for (j = 0; j < unique_count; j++) {
                if (xp[i] == xp[j]) {
                    found = 1;
                    break;
                }
            }
            if (!found) {
                xp[unique_count++] = xp[i];
            }
        }

        // Reverse the first half of xp
        int add = n / 2;
        if (2 * add < m) add++;
        for (j = 0; j < add; j++) {
            int temp = xp[j];
            xp[j] = xp[unique_count - 1 - j];
            xp[unique_count - 1 - j] = temp;
        }

        // Calculate scores
        for (i = 0; i < n; i++) {
            score_temp = xp[i] - xp[unique_count - 1 - i];
            if (score_temp == scalar) {
                // Erase xp[i] from Ap
                for (j = 0; j < size_Ap; j++) {
                    if (Ap[j] == xp[i]) {
                        for (int k = j; k < size_Ap - 1; k++) {
                            Ap[k] = Ap[k + 1];
                        }
                        size_Ap--;
                        break;
                    }
                }
                if (unique_count != 2) unique_count--;
            } else {
                // Add x[i] back to Ap
                int found = 0;
                for (j = 0; j < size_Ap; j++) {
                    if (Ap[j] == xp[i]) {
                        found = 1;
                        break;
                    }
                }
                if (!found) {
                    Ap[size_Ap++] = xp[i];
                }
                unique_count--;
            }
            if (size_Ap == 2) break;
        }
        if (flag == 1 && size_Ap == 2) break;
    }

    for (i = 0; i < size_Ap; i++) {
        score += i + 1;
    }
    printf("%d\n", score);

    return 0;
}

int findBestValue(int* A, int size, int target, int n) {
    int good = -1;
    float good_f = (float)target;
    int sum_A = vector_sum(A, size);
    for (int i = n; i < size; i++) {
        if (A[i] * (n + i) < target) {
            n++;
        } 
        else if (A[i] * (n + i) > sum_A) {
            if (abs(target - sum_A) > abs(target - i * A[i])) {
                good = i;
                break;
            } 
            else {
                continue;
            }
        } 
        else {
            break;
        }
    }

    if (n == size) return A[n - 1];
    if ((n == good) || (n == size - 1)) {
        good_f += (target - sum_A);
        good_f /= n;
        good = (int)(good_f) + 1;
    }

    for (int i = n; (i < size && (A[i] * (n + i) - target) * n > (A[i] * (i + n) - target) * (n + i)); i += n) {
        if (i + n <= size) {
            good = i;
            good_f = vector_sum_f(A, size, n, good);
        }
        if (i + n > size) break;
    }
    return good;
}

float vector_sum_f(int* A, int size, int n, int good) {
    float sum = 0;
    for (int i = good; i < size && i > good - n; i -= n) {
        sum += A[i];
    }
    if (i < good - n) {
        sum += (target - vector_sum(A, size));
    }
    return sum;
}

int vector_sum(int* A, int size) {
    int sum = 0;
    for (int i = 0; i < size; i++) {
        sum += A[i];
    }
    return sum;
}

