int is_replication(const char *S, int N) {
    // Defensive check for valid input
    if (N <= 0 || N > MAX_LEN) {
        printf("Invalid string length: %d\n", N);
        return 0; // Indicating "No"
    }

    // Traverse possible substring lengths
    for (int i = 1; i <= N / 2; ++i) {
        if (N % i == 0) { // Only consider lengths that can completely divide N
            // Create comparison string
            char comparison[MAX_LEN];
            int times = N / i;
            memset(comparison, 0, sizeof(comparison));

            // Form the replicated string
            for (int j = 0; j < times; ++j) {
                strncat(comparison, S, i);
            }

            // Compare with original string
            if (strncmp(S, comparison, N) == 0) {
                return 1; // Indicating "Yes"
            }
        }
    }

    return 0; // Indicating "No"
}

