#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define MOD 1000000007

long long mod_pow(long long base, long long exp, long long mod) {
    long long result = 1;
    while (exp > 0) {
        if (exp % 2 == 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2;
    }
    return result;
}

int main() {
    int N, K, M;
    scanf("%d %d %d", &N, &K, &M);

    if (M < K) {
        printf("%lld\n", mod_pow(K, N, MOD));
        return 0;
    } 
    else if (N == K) {
        printf("%lld\n", mod_pow(M, N, MOD));
        return 0;
    } 
    else if (K == 2 && M == 2) {
        int A[2];
        scanf("%d %d", &A[0], &A[1]);
        if (A[0] == 1 && A[1] == 2) {
            printf("%lld\n", mod_pow(N + 2, N, MOD));
            return 0;
        }
    } 

    int* A = (int*)malloc(M * sizeof(int));
    for (int i = 0; i < M; i++) {
        scanf("%d", &A[i]);
    }

    int* B = (int*)malloc(M * sizeof(int));
    for (int i = 0; i < M; i++) {
        B[i] = A[M - 1 - i];
    }

    int* AB = (int*)malloc((2 * M + 2) * sizeof(int));
    int now = M;
    for (int i = 0; i < 2 * M + 1; i++) {
        if (A[i % M] != B[i % M]) {
            AB[i + 1] = now;
            now++;
        } else {
            AB[i + 1] = now;
        }
    }

    int* C = (int*)calloc(N + K + 2, sizeof(int));
    for (int i = 2 * M + 1; i < N * 2 + 2; i++) {
        AB[i + 1] = AB[i - M + 1] - M;
        int l = AB[i + 1] + 1;
        int r = AB[i + 1] + K;
        if (r > N * 2) {
            r %= (N * 2);
        }
        C[l]++;
        C[r + 1]--;
    }

    long long ans = 0;
    long long s = 0;
    for (int i = 2; i < N * 2 + 1; i++) {
        s += C[i];
        ans += ((s * (i - M + 1) + (i + 1) * M * (M - 1) / 2) * mod_pow(i - (AB[i] + 1), N - K, MOD)) % MOD);
    }

    printf("%lld\n", ans % MOD);

    free(A);
    free(B);
    free(AB);
    free(C);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

typedef struct TreeNode {
    int val;
    struct TreeNode *left, *right, *parent;
} TreeNode;

typedef struct CBTInserter {
    TreeNode *root;
    int *indexes;
    TreeNode **nodes;
    int index_count;
    int node_count;
} CBTInserter;

TreeNode* create_tree_node(int x) {
    TreeNode *node = (TreeNode *)malloc(sizeof(TreeNode));
    node->val = x;
    node->left = NULL;
    node->right = NULL;
    node->parent = NULL;
    return node;
}

void dfs(CBTInserter *inserter, TreeNode *node, int level) {
    if (node == NULL)
        return;

    inserter->nodes[inserter->node_count++] = node;

    if ((level + 1) & level) {
        inserter->indexes[inserter->index_count++] = inserter->node_count - 1;
    }

    dfs(inserter, node->left, level + 1);
    dfs(inserter, node->right, level + 1);
}

CBTInserter* cbt_inserter_create(TreeNode *root) {
    CBTInserter *inserter = (CBTInserter *)malloc(sizeof(CBTInserter));
    inserter->root = root;
    inserter->indexes = (int *)malloc(100 * sizeof(int)); // TODO: dynamic size
    inserter->nodes = (TreeNode **)malloc(100 * sizeof(TreeNode *)); // TODO: dynamic size
    inserter->index_count = 0;
    inserter->node_count = 0;

    dfs(inserter, root, 0);
    return inserter;
}

int cbt_inserter_insert(CBTInserter *inserter, int v) {
    int size = 1 << inserter->index_count;
    TreeNode *node = create_tree_node(v);
    TreeNode *parent;

    // Debug print
    printf("Inserting value: %d\n", v);

    inserter->nodes[inserter->node_count++] = node;

    if (inserter->index_count == 0) {
        inserter->nodes[0]->right = node;
    } else {
        int p = inserter->indexes[inserter->index_count - 1];
        inserter->indexes[inserter->index_count++] = p + 1;
        parent = inserter->nodes[p];

        if (parent->left == NULL) {
            parent->left = node;
        } else {
            parent->right = node;
        }
    }

    if ((inserter->indexes[inserter->index_count - 1] & -inserter->indexes[inserter->index_count - 1]) == 1) {
        inserter->index_count--;
    } else {
        size++;
    }

    // Return parent's value after insertion
    return inserter->nodes[inserter->node_count - 1]->parent->val;
}

TreeNode* cbt_inserter_get_root(CBTInserter *inserter) {
    return inserter->root;
