#define MOD (1000000007)

void multiply(long long a[2][2], long long b[2][2], long long r[2][2]) {
    for (int i = 0; i < 2; i++) {
        for (int j = 0; j < 2; j++) {
            r[i][j] = 0;
            for (int k = 0; k < 2; k++) {
                r[i][j] = (r[i][j] + a[i][k] * b[k][j]) % MOD;
            }
        }
    }
}

long long findNthTerm(int n) {
    long long F[2][2] = {{1, 1}, {1, 0}};
    long long result[2][2];
    n -= 1;

    while (n) {
        if (n & 1) {
            multiply(F, (long long[2][2]){{1, 1}, {1, 0}}, result);
            for (int i = 0; i < 2; i++) {
                for (int j = 0; j < 2; j++) {
                    F[i][j] = result[i][j];
                }
            }
        }
        multiply(F, F, result);
        for (int i = 0; i < 2; i++) {
            for (int j = 0; j < 2; j++) {
                F[i][j] = result[i][j];
            }
        }
        n >>= 1;
    }
    return F[0][1] % MOD;
}

