function getDistinctPrimeFactorsCount(n) {
  let factors = new Set();
  for (let i = 2; i * i <= n; i++) {
    if (n % i === 0) {
      factors.add(i);
      while (n % i === 0) {
        n = Math.floor(n / i);
      }
    }
  }
  if (n > 1) factors.add(n);
  return factors.size;
}

