async function TetrisGame(arr_A, arr_B) {
    const max_val = Math.max(...arr_B);
    const minIndices = arr_A.map((x, i) => x === Math.min(...arr_A) ? i : -1).filter(i => i !== -1);

    for (const idx of minIndices) {
        if (max_val <= arr_B[idx]) {
            return max_val;
        }
        arr_A[idx] += arr_B[idx];
    }
    return -1;
}

