const countMaxOrSubsets = (nums) => {
    let maxOr = 0;
    const n = nums.length;

    for (const num of nums) {
        maxOr |= num;
    }

    const dp = new Array(maxOr + 1).fill(0);
    dp[0] = 1;

    for (const num of nums) {
        for (let i = maxOr; i >= num; i--) {
            dp[i] += dp[i - num];
        }
    }

    return dp[maxOr];
};

