const { stdin, stdout } = require('process');

function gcd(a, b) {
    while (b !== 0) {
        [a, b] = [b, a % b];
    }
    return a;
}

async function getInputData() {
    const input = await new Promise(resolve => {
        stdin.setEncoding('utf8');
        let data = '';
        stdin.on('data', chunk => {
            data += chunk;
        });
        stdin.on('end', () => {
            resolve(data.trim().split('\n'));
        });
    });
    const N = parseInt(input[0]);
    const nums = input[1].split(' ').map(Number);
    return { N, nums };
}

async function checkCoprimality() {
    const { N, nums } = await getInputData();
    let count = 0;
    let maxGCD = 0;

    for (let i = 0; i < N; i++) {
        for (let j = i + 1; j < N; j++) {
            const a = nums[i];
            const b = nums[j];
            const currentGCD = gcd(a, b);
            if (currentGCD === 1) count++;
            maxGCD = Math.max(maxGCD, currentGCD);
        }
    }

    if (maxGCD === 1 && count === (N * (N - 1)) / 2) {
        stdout.write('pairwise coprime\n');
    } else if (maxGCD === 1 && count !== (N * (N - 1)) / 2) {
        stdout.write('not coprime\n');
    } else {
        stdout.write('setwise coprime\n');
    }
}

