const isLunlun = (n) => {
    const base = Array.from({ length: n.toString().length - 1 }, (_, i) => i + 1);
    const sequence = Array.from(String(n), Number);
    let luhnSum = 0;

    for (let i = 0; i < sequence.length; i++) {
        const digit = sequence[i];
        const baseDigit = base[i];
        const shorterNumber = baseDigit ? Array.from({ length: 10 - sequence.length - 1 }, (_, j) => j + 1) : [1];

        const shorterCombinations = createCombinations(shorterNumber, baseDigit - 1);

        for (const shorter of shorterCombinations) {
            if (shorter.reduce((sum, num) => sum + num, 0) === digit) {
                return false;
            }
        }
        luhnSum += digit;
    }
    return luhnSum % 10 === 0;
};

const createCombinations = (arr, length) => {
    if (length === 0) return [[]];
    return arr.flatMap((num) => createCombinations(arr, length - 1).map((rest) => [num, ...rest]));
};

