class TreeNode {
    constructor(value) {
        this.value = value;
        this.left = null;
        this.right = null;
    }

    insert(value) {
        if (value >= this.value) {
            if (this.right === null) {
                this.right = new TreeNode(value);
            } else {
                this.right.insert(value);
            }
        } else {
            if (this.left === null) {
                this.left = new TreeNode(value);
            } else {
                this.left.insert(value);
            }
        }
    }

    contains(value) {
        if (value === this.value) {
            return true;
        } else if (value >= this.value) {
            return this.right ? this.right.contains(value) : false;
        } else {
            return this.left ? this.left.contains(value) : false;
        }
    }

    countDistance(value) {
        if (value === this.value) return 0;

        const leftDist = this.left ? this.left.countDistance(value) : Infinity;
        const rightDist = this.right ? this.right.countDistance(value) : Infinity;
        return Math.abs(value - this.value) + Math.min(leftDist, rightDist);
    }

    printTree() {
        if (this.left) this.left.printTree();
        console.log(this.value);
        if (this.right) this.right.printTree();
    }
}

