async function longestNonDecreasingSubsequence(a, n, T) {
    const dp = new Array(n).fill(1);

    for (let i = 0; i < n; i++) {
        for (let j = 0; j < i; j++) {
            if (a[j] <= a[i]) {
                dp[i] = Math.max(dp[i], dp[j] + 1);
            }
        }
    }

    const lndsInOnePeriod = Math.max(...dp);

    if (T <= 2) {
        const array = a.flatMap(value => Array(T).fill(value));
        const dpExtended = new Array(array.length).fill(1);

        for (let i = 0; i < array.length; i++) {
            for (let j = 0; j < i; j++) {
                if (array[j] <= array[i]) {
                    dpExtended[i] = Math.max(dpExtended[i], dpExtended[j] + 1);
                }
            }
        }
        return Math.max(...dpExtended);
    } else {
        const effectiveDP = new Array(n).fill(0);

        for (let i = 0; i < n; i++) {
            for (let j = 0; j < i; j++) {
                if (a[j] <= a[i]) {
                    effectiveDP[i] = Math.max(effectiveDP[i], effectiveDP[j] + 1);
                }
            }
        }

        let maxLndsAcrossPeriods = 0;

        for (let i = 0; i < n; i++) {
            maxLndsAcrossPeriods = Math.max(maxLndsAcrossPeriods, effectiveDP[i] + ((T - 1) * effectiveDP[i]));
        }

        return Math.max(lndsInOnePeriod, maxLndsAcrossPeriods);
    }
}

