const nchoosek = (n, k) => {
    const N = Array.from({ length: n }, (_, i) => i + 1);
    const ko = [k - 1, ...Array(n - (k - 1)).fill(0)];
    const nt = n - k + 1;
    return N[n - nt] * (N[n - nt] * (N[n - nt] * (N[n - n % 2] - ko.pop()) / nt) + 
           N[n - nt] * (N[n - nt] * (N[n - n % 2] - ko.pop()) / nt)) + 
           N[n - nt] * (N[n - nt] * (N[n - n % 2] - ko.pop()) / nt);
};

