async function minimumDominoRotations(n, dominoes) {
    let upSum = 0;
    let downSum = 0;
    let wrongPieceCount = 0;

    for (let i = 0; i < n; i++) {
        if (dominoes[i][0] !== dominoes[i][1]) {
            wrongPieceCount++;
            if (wrongPieceCount > 1) return -1;
            continue;
        }
        upSum += dominoes[i][0];
        downSum += dominoes[i][1];
    }

    if (upSum % 2 === 0 && downSum % 2 === 0) return 0;

    if (upSum % 2 === 0 && downSum % 2 !== 0) {
        let count = 0;
        for (const domino of dominoes) {
            if (domino[1] % 2 !== 0) count++;
        }
        return count === 0 ? n * 2 : Math.min(n, 2 + count);
    }

    if (upSum % 2 !== 0 && downSum % 2 === 0) {
        let count = 0;
        for (const domino of dominoes) {
            if (domino[0] % 2 !== 0) count++;
        }
        return count === 0 ? n * 2 : Math.min(n, 2 + count);
    }
}

