import math

const area = (a, b, c) => {
    const p = (a + b + c) / 2;
    return Math.sqrt(p * (p - a) * (p - b) * (p - c));
};

const solve = (a, b, c) => {
    if (a === b || a === c || b === c) {
        return area(a, b, c);
    }
    if (a > b) [a, b] = [b, a];
    if (a > c) [a, c] = [c, a];
    if (b > c) [b, c] = [c, b];

    if (a + b <= c || a + c <= b || b + c <= a) {
        return area(a, b, c);
    }

    return Math.min(area(a, b, c), area(a, b, a + b));
};

