async function minColumnRemovals(n, m, table) {
    let keep = new Array(m).fill(true);
    let removedCount = 0;

    while (true) {
        let isGood = true;

        for (let col = 0; col < m; col++) {
            if (!keep[col]) continue;

            for (let row = 1; row < n; row++) {
                let prevRow = table[row - 1];
                let currRow = table[row];
                if (prevRow[col] > currRow[col]) {
                    isGood = false;
                    keep[col] = false;
                    removedCount++;
                    break;
                }
            }

            if (!isGood) break;
        }

        if (isGood) break;
    }

    return removedCount;
}

