import {Deque} from 'collections/deque';

export async function minTime(n, m, duration, dependencies) {
    const graph = new Map();
    for (const [to, from] of dependencies) {
        if (!graph.has(from)) graph.set(from, []);
        graph.get(from).push(to);
    }
    return await bfs(n, m, duration, dependencies, graph);
}

async function bfs(n, m, duration, dependencies, graph) {
    const inDegree = new Array(n).fill(0);
    for (const adjList of graph.values()) {
        for (const node of adjList) {
            inDegree[node]++;
        }
    }

    const q = new Deque();
    for (let i = 0; i < n; i++) {
        if (inDegree[i] === 0) q.push(i);
    }

    let time = 0;
    while (q.length > 0) {
        const size = q.length;
        for (let i = 0; i < size; i++) {
            const node = q.shift();
            if (graph.has(node)) {
                for (const next of graph.get(node)) {
                    inDegree[next]--;
                    if (inDegree[next] === 0) q.push(next);
                }
            }
        }
        time++;
    }
    return time;
}

export async function validate(n, m, pairs) {
    const graph = Array.from({length: n}, () => []);
    for (const [from, to] of pairs) {
        graph[from].push(to);
    }
    const visited = Array(n).fill(false);
    const recStack = Array(n).fill(false);

    for (let node = 0; node < n; node++) {
        if (!visited[node]) {
            if (await hasCycle(node, visited, recStack, graph)) {
                return "-1";
            }
        }
    }
    return "1";
}

async function hasCycle(node, visited, recStack, graph) {
    visited[node] = true;
    recStack[node] = true;

    for (const neighbor of graph[node]) {
        if (!visited[neighbor]) {
            if (await hasCycle(neighbor, visited, recStack, graph)) {
                return true;
            }
        } else if (recStack[neighbor]) {
            return true;
        }
    }

    recStack[node] = false;
    return false;
}

