function dijkstra(adj, p, start) {
    const dist = new Array(adj.length).fill(Infinity);
    dist[start] = 0;
    const pq = [{ weight: 0, node: start }];

    while (pq.length > 0) {
        const { weight, node } = pq.shift();
        for (const { first: v, second: edgeIndex } of adj[node]) {
            const w = p[edgeIndex];
            if (dist[v] > dist[node] + w) {
                dist[v] = dist[node] + w;
                pq.push({ weight: dist[v], node: v });
                pq.sort((a, b) => a.weight - b.weight);
            }
        }
    }
    return dist;
}

