export async function solve(N, A, B, arr) {
    const lis = new Array(N).fill(1);
    const lds = new Array(N).fill(0);
    let longest = 0;

    for (let i = 1; i < N; i++) {
        for (let j = 0; j < i; j++) {
            if (arr[i] > arr[j] && lis[i] < lis[j] + 1) {
                lis[i] = lis[j] + 1;
            }
        }
    }

    for (let i = N - 1; i >= 0; i--) {
        for (let j = N - 1; j > i; j--) {
            if (arr[i] > arr[j] && lds[i] < lds[j] + 1) {
                lds[i] = lds[j] + 1;
            }
        }
    }

    for (let i = 0; i < N; i++) {
        longest = Math.max(longest, lis[i] + lds[i] - 1);
    }

    if (longest < A && longest < B) {
        return -1;
    }

    for (let i = N - 1; i >= 0; i--) {
        if (lis[i] === longest) {
            lis[i] = i + 1;
            break;
        }
    }

    for (let i = N - 1; i >= 0; i--) {
        if (lds[i] === longest) {
            lds[i] = N - i;
            break;
        }
    }

    const middle = arr.slice(0, -1).findIndex(x => x === arr[arr.length - 1]);

    if (middle !== -1) {
        [arr[arr.length - 1], arr[middle]] = [arr[middle], arr[arr.length - 1]];
