const dfs = async (node, parents, xorTree) => {
    if (xorTree[node * 2] === 0) {
        xorTree[node * 2] = xorTree[node * 2 + 1] = flipValue(xorTree[node * 2 + 1]);
        parents[node * 2 + 1] = node;
    } else if (xorTree[node * 2] === 1) {
        xorTree[node * 2] = flipValue(xorTree[node * 2]);
        xorTree[node * 2 + 1] = xorTree[node * 2];
        parents[node * 2 + 1] = node;
