const solve = async (n, edges, initialValues, goalValues) => {
    const parents = Array.from({ length: n + 1 }, (_, i) => i);
    edges.forEach(([u, v]) => {
        parents[u] = u;
        parents[v] = v;
    });

    const xorTree = Array(2 * n).fill(0);
    initialValues.forEach((val, idx) => {
        xorTree[idx] = val;
    });

    goalValues.forEach((goal, idx) => {
        xorTree[idx + n] = goal;
    });

    let operationCount = 0;
    for (let node = 1; node <= n; node++) {
        const root = await findRoot(parents, node);
        xorTree[root * 2] ^= xorTree[root];
        if (xorTree[root * 2] !== 0) {
            await dfs(root, parents, xorTree);
        }
    }

    const nodesToPick = [];
    for (let node = 1; node <= n; node++) {
        const root = await findRoot(parents, node);
        if (xorTree[root * 2] !== initialValues[node - 1]) {
            nodesToPick.push(root);
        }
    }
    return { operationCount, nodesToPick };
};

