function binarySearch(a, l, r) {
  if (a[0] > r || a[a.length - 1] < l) {
    return -1;
  }

  let res = -1;
  let s = l;
  let e = r;
  let mid = Math.floor((l + r) / 2);

  while (s <= e) {
    if (a[mid] !== l && a[mid] !== m && a[mid] !== r) {
      res = a[mid];
      break;
    } else if (a[mid] === l) {
      e = mid - 1;
    } else if (a[mid] === m) {
      return mid;
    } else if (a[mid] === r) {
      s = mid + 1;
    }
    mid = Math.floor((s + e) / 2);
  }
  return res;
}

