async function minAreaFreeRect(points) {
    const pointSet = new Set(points.map(point => point.toString()));
    let minArea = Infinity;

    for (const p of points) {
        for (const q of points) {
            if (p === q) continue;

            const centerX = (p[0] + q[0]) / 2;
            const centerY = (p[1] + q[1]) / 2;
            const r = [Math.abs(centerX), Math.abs(centerY)];

            if (pointSet.has(r.toString())) {
                const area = Math.sqrt((centerX - r[0]) ** 2 + (centerY - r[1]) ** 2) * Math.abs(p[0] - q[0]) ** 2;
                minArea = Math.min(minArea, area);
            }
        }
    }

    return minArea === Infinity ? 0 : Math.round(minArea * 100000) / 100000;
}

