function longestEqualArr(arr, k) {
    if (arr.length === k) {
        return arr.length;
    } else {
        let maxEqual = 0;
        const countMap = new Map();

        for (let num of arr) {
            countMap.set(num, (countMap.get(num) || 0) + 1);
        }

        for (let [num, count] of countMap.entries()) {
            const remaining = arr.length - count;
            if (remaining <= k) {
                maxEqual = Math.max(maxEqual, count + remaining);
            }
        }
        return maxEqual;
    }
}

