async function findGoodLabels(N, M, edges) {
    const graph = new Map();

    for (const [u, v, c] of edges) {
        if (!graph.has(u)) graph.set(u, []);
        if (!graph.has(v)) graph.set(v, []);
        graph.get(u).push([v, c]);
        graph.get(v).push([u, c]);
    }

    const labels = Array(N + 1).fill(-1);
    const queue = [];
    queue.push(1);
    labels[1] = edges[0][2];

    while (queue.length) {
        const current = queue.shift();
        for (const [neighbor, edgeLabel] of graph.get(current)) {
            if (labels[neighbor] === -1) {
                labels[neighbor] = (labels[current] === edgeLabel) ? (edgeLabel % N) + 1 : edgeLabel;
                queue.push(neighbor);
            }
        }
    }

    const visited = Array(N + 1).fill(false);
    queue.push(1);
    visited[1] = true;

    while (queue.length) {
        const current = queue.shift();
        for (const [neighbor] of graph.get(current)) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                queue.push(neighbor);
            }
        }
    }

    return visited.slice(1).every(v => v) ? labels.slice(1).join('\n') : "No";
}

