const minimumMoves = (a, b, absDiff) => {
    let moves = 0;
    const sign = a > b ? 1 : -1;
    for (let i = 9; i >= 0; i--) {
        if ((a + (i * 0.1) * sign < b && absDiff >= i * 0.1) || 
            (a - (i * 0.1) * sign > b && absDiff >= i * 0.1)) {
            absDiff -= i * 0.1;
            moves++;
        } else if ((a + ((i + 1) * 0.1) * sign > b && absDiff > (i + 1) * 0.1) || 
                   (a - ((i + 1) * 0.1) * sign < b && absDiff > (i + 1) * 0.1)) {
            absDiff -= (i + 1) * 0.1;
            moves++;
        }
    }
    return Math.floor(moves);
};

