async function main() {
    const input = await new Promise(res => rl.on('line', data => res(data)));
    const [n, k] = input.split(' ').map(Number);

    const segments = [];
    for (let i = 0; i < n; i++) {
        const segmentInput = await new Promise(res => rl.on('line', data => res(data)));
        const [l, r] = segmentInput.split(' ').map(Number);
        segments.push([l, r]);
    }

    const bad = [];
    for (const segment of segments) {
        for (let j = segment[0]; j <= segment[1]; j++) {
            if (!bad.some(b => b[0] === j)) {
                let status = true;
                for (const se of segments) {
                    if (se.includes(j)) {
                        status = false;
                        break;
                    }
                }
                if (status) bad.push([j, null]);
            }
        }
    }

    bad.sort((a, b) => a[0] - b[0]);
    let segmentsRemoved = 0;
    let garbage = true;
    const status = { previous: [null, null], remove: false };

    for (const badSegment of bad) {
        status.remove = false;
        if (!garbage && segmentsRemoved > 0) {
            for (let i = 0; i < segmentsRemoved; i++) {
                if (status.previous[0]) {
                    segmentsRemoved--;
                } else {
                    status.remove = true;
                    break;
                }
            }
        } else {
            segmentsRemoved--;
        }

        const upTo = badSegment[1];
        if (!garbage) {
            for (let i = 0; i < segmentsRemoved; i++) {
                if (status.previous[0] && !status.remove) {
                    break;
                } else if (status.previous[0] && status.previous[1] >= badSegment[0]) {
                    status.remove = true;
                    break;
                }
            }
        }

        const previous = segments[segmentsRemoved - 1];
        if (previous[1] !== null) {
            status.remove = true;
        }

        garbage = false;
        if (segmentsRemoved < n) {
            const nextPrevious = segments[segmentsRemoved];
            status.remove = true;
        }
    }

    status.previous = [null, null];
    while (segmentsRemoved < n) {
        segmentsRemoved++;
        const upTo = badSegment[1];

        if (status.previous[0] && upTo < badSegment[0]) {
            status.remove = true;
        } else {
            const previous = segments[segmentsRemoved - 1];
            if (previous[1] !== null) {
                status.remove = true;
            }
        }

        garbage = true;
        if (status.remove) {
            process.stdout.write(`${segmentsRemoved} `);
            process.stdout.write([...Array(segmentsRemoved).keys()].join(' '));
        }
    }
}

