const minCostToMakeProductOne = (n, nums) => {
    let cost = 0;

    if (nums.includes(0)) {
        cost = nums.filter(x => x === 0).length;
        nums = nums.filter(x => x !== 0);
        n = nums.length;
    }

    if (n === 0) return cost;

    let productSign = 1;
    for (const num of nums) {
        if (num < 0) productSign *= -1;
    }

    let absSum = nums.reduce((sum, x) => {
        if (x < 0) return sum + Math.abs(x - 1);
        if (x > 1) return sum + Math.abs(x - 1);
        return sum;
    }, 0);

    if (productSign === -1) absSum += 2;

    return cost + absSum;
};

