async function minSchools(n, m, k, p, s, c) {
    let students = [];
    for (let i = 0; i < n; i++) {
        students.push([p[i], s[i], i]);
    }
    students.sort((a, b) => b[0] - a[0]);

    let schools = Array.from({ length: m }, () => new Set());
    for (let i = 0; i < n; i++) {
        schools[s[i]].add([p[i], i]);
    }

    for (let idx of c.sort((a, b) => p[b] - p[a])) {
        let chosen = [students.shift()];
        let i = 0;

        while (chosen.length < k) {
            while (schools[chosen[chosen.length - 1][1]].size === 0) {
                chosen.pop();
                i += 1;
            }
            if (i >= n) {
                return -1;
            }
            let newStudent = [...schools[chosen[chosen.length - 1][1]]].pop();
            if (newStudent) {
                schools[chosen[chosen.length - 1][1]].delete(newStudent);
                students.push(newStudent);
                heapify(students);
            }
        }

        for (let student of chosen) {
            schools[student[1]].clear();
        }
    }

    return schools.filter(school => school.size > 0).length;
}

