import fs from 'fs';

async function solve() {
    const input = await fs.promises.readFile('in.txt', 'utf-8');
    const lines = input.trim().split('\n');
    const N = parseInt(lines[0]);
    const A = lines[1].split(' ').map(Number);

    const X = A.map((x, i) => [x, i]).sort((a, b) => a[0] - b[0]);
    const B = [[], []];

    for (let [x, i] of X) {
        B[i % 2].push(x);
    }

    const ACU = new Array(N).fill(0);
    ACU[0] = A[0];

    for (let i = 1; i < N; i++) {
        ACU[i] = A[i] + ACU[i - 1];
    }

    let CUR = 0;

    for (let i = 1; i < N; i++) {
        if (CUR >= B[0][Math.floor(i / 2)] * (N - 2 * i + 1) || CUR <= B[1][Math.floor(i / 2)] * (N - 2 * i)) {
            break;
        }

        if (B[0][Math.floor(i / 2)] * (N - 2 * i + 1) - CUR < 0) {
            CUR = B[0][Math.floor(i / 2)] * (N - 2 * i + 1);
        } else {
            if (ACU[N - 2 * i - 1] + CUR > B[1][Math.floor(i / 2)] * (N - 2 * i)) {
                CUR = ACU[N - 2 * i - 1];
            } else {
                CUR += ACU[N - 2 * i - 1] - B[1][Math.floor(i / 2)] * (N - 2 * i);
            }
        }
    }

    return CUR;
}

