    const groupsDict = {};
    let rootGroup = null;

    const addGroupToDict = (groupMembers) => {
        if (rootGroup === null) {
            rootGroup = groupMembers;
        }
        let parentGroup = groupsDict[groupMembers[0]];
        if (!parentGroup) {
            parentGroup = groupMembers;
            groupsDict[parentGroup[0]] = parentGroup;
        } else {
            parentGroup.push(...groupMembers);
            parentGroup.slice(2).forEach(member => addGroupToDict(member));
        }
    };

    for (const groupMembers of groups) {
        if (groupMembers !== '0') {
            const [group, members] = groupMembers.split(':');
            addGroupToDict([group, ...members.split(',')]);
        }
    }

    let groupsCount = 0;

    const countMembers = (group) => {
        groupsCount += 1;
        group.slice(2).forEach(childGroup => countMembers(groupsDict[childGroup]));
    };

    for (const group of Object.values(groupsDict)) {
        if (group !== rootGroup) {
            groupsCount += 1;
            countMembers(group);
        }
    }

    return groupsCount;
};

