async function minimumCostToFormSlime(N, slimes) {
    if (!Number.isInteger(N) || N <= 0 || !Array.isArray(slimes) || slimes.length !== N) {
        throw new Error('Invalid input: ensure N is positive and slimes is of the correct length.');
    }

    let cost = 0;
    heap.heapify(slimes);

    while (slimes.length > 1) {
        const x = heap.heappop(slimes);
        const y = heap.heappop(slimes);
        const newSlime = x + y;
        cost += newSlime;
        heap.heappush(slimes, newSlime);
    }

    return cost;
}

