const solveString = (S, a, b) => {
    const D = Array.from(S);
    let rest = D.length;
    let taken = 0;

    while (rest) {
        let lenr = 0;
        while (lenr < rest && D[lenr] === D[0]) {
            lenr++;
        }
        taken += a * lenr + b * rest - 2 * (a * (lenr + 1) + b * rest);
        rest = lenr;
        D.splice(0, lenr);
    }

    return taken * a + taken * b;
};

