const findCenter = (n, m, table) => {
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < m; j++) {
            if (table[i][j] === 'B') {
                let top = i, left = j;
                while (top > 0 && table[top - 1][j] === 'B') {
                    top--;
                }
                while (left > 0 && table[i][left - 1] === 'B') {
                    left--;
                }

                let bottom = i, right = j;
                while (bottom < n - 1 && table[bottom + 1][j] === 'B') {
                    bottom++;
                }
                while (right < m - 1 && table[i][right + 1] === 'B') {
                    right++;
                }

                const centerRow = Math.floor((top + bottom) / 2);
                const centerCol = Math.floor((left + right) / 2);
                return [centerRow + 1, centerCol + 1];
            }
        }
    }
    throw new Error('Black square not found');
};

