        if (!node) return null;

        curr += node.val;

        if (!node.left && !node.right) {
            return curr >= limit ? node : null;
        }

        node.left = helper(node.left, curr);
        node.right = helper(node.right, curr);

        if (!node.left && !node.right) {
            return null;
        }

        return node;
    };

