const MOD = 1e9 + 7;

const validateInput = (low, high) => {
    if (typeof low !== 'string' || typeof high !== 'string' || low.length === 0 || high.length === 0) {
        throw new Error('Invalid input: low and high must be non-empty strings.');
    }
};

const calculateDP = (length) => {
    const dp = Array.from({ length: length + 1 }, () => Array(10).fill(0));
    dp[0][0] = 1;

    for (let i = 1; i <= length; i++) {
        for (let j = 0; j < 10; j++) {
            if (i === 1) {
                if (j !== 0) {
                    dp[i][j] = dp[i - 1][j - 1];
                }
            } else {
                if (j === 0) dp[i][j] = dp[i - 1][j + 1];
                else if (j === 9) dp[i][j] = dp[i - 1][j - 1];
                else dp[i][j] = (dp[i - 1][j + 1] + dp[i - 1][j - 1]) % MOD;
            }
        }
    }
    return dp;
};

const countSteppingNumbers = (low, high) => {
    validateInput(low, high);

    const n = low.length;
    const m = high.length;
    let ans = 0;

    const dpLow = calculateDP(n);
    const dpHigh = calculateDP(m);

    for (let i = 0; i < 10; i++) {
        if (low[0] === '0' && i === 0) continue;

        if (low[0] === '0' && i !== 0) {
            ans = (ans + dpLow[n][i]) % MOD;
        } else if (low[0] == i || low[0] == i - 1 || low[0] == i + 1) {
            ans = (ans + dpLow[n][i]) % MOD;
        }
    }

    for (let i = 0; i < 10; i++) {
        if (high[0] === '0' && i === 0) continue;

        if (high[0] === '0' && i !== 0) {
            ans = (ans - dpHigh[m][i] + MOD) % MOD;
        } else if (high[0] == i || high[0] == i - 1 || high[0] == i + 1) {
            ans = (ans - dpHigh[m][i] + MOD) % MOD;
        }
    }

    return ans;
};

