}

function processGrid(grid, n, m, r, c) {
    let rowPattern = [];
    let colPattern = "B";

    for (const pattern of generatePatterns('BW', m)) {
        const line = pattern.join('');
        if (rowPattern.join('') === line && line === grid[r - 1]) {
            return -1;
        }
        if (rowPattern.join('') === line) {
            return -1;
        } else {
            rowPattern.push(colPattern);
        }
    }

    const colVerifications = [];
    for (const pattern of generatePatterns('BW', n)) {
        const line = pattern.join('');
        colVerifications.push(line);
    }

    // Additional logic for column checks can be added

    return colVerifications.length > 0 ? colVerifications : -1;
}

function* generatePatterns(chars, length) {
    const total = Math.pow(chars.length, length);
    for (let i = 0; i < total; i++) {
        yield Array.from({length}, (_, j) => chars[Math.floor(i / Math.pow(chars.length, j)) % chars.length]);
    }
}

