    if (b < 0 || p < 0 || f < 0 || h < 0 || c < 0) {
        throw new Error("Invalid input: All parameters must be non-negative.");
    }

    let maxHamburgers = Math.min(Math.floor(b / 2), p);
    let maxChickenBurgers = Math.min(Math.floor(b / 2), f);

    if (h > c) {
        maxHamburgers = Math.min(maxHamburgers, Math.floor(b / 2));
        b -= maxHamburgers * 2;
        maxChickenBurgers = Math.min(maxChickenBurgers, Math.floor(b / 2));
