const sumSet = (subset) => {
    return subset.reduce((acc, sub) => {
        return acc + (sub.filter(i => i > 3).length > 0 ? sub.length : 0);
    }, 0);
};

const generateCombinations = (array, size) => {
    const combinations = [];
    const f = (start, combo) => {
        if (combo.length === size) {
            combinations.push(combo);
            return;
        }
        for (let i = start; i < array.length; i++) {
            f(i + 1, [...combo, array[i]]);
        }
    };
    f(0, []);
    return combinations;
};

const generatePowerSet = (array) => {
    const powerSet = [];
    const total = 1 << array.length; // 2^n
    for (let i = 0; i < total; i++) {
        const subset = [];
        for (let j = 0; j < array.length; j++) {
            if (i & (1 << j)) {
                subset.push(array[j]);
            }
        }
        powerSet.push(subset);
    }
    return powerSet;
};

