    try {
        if (n <= 0 || num <= 0 || !Number.isInteger(n) || !Number.isInteger(num)) {
            throw new Error('Invalid input: n and num must be positive integers');
        }

        const numbers = Array.from({ length: n }, (_, i) => i + 1);
        const multipliedSet = numbers.map(i => i * num);
        const powerSet = generatePowerSet(multipliedSet);
        const validSubsets = powerSet.filter(subset => sumSet([subset]) === target);

        if (validSubsets.length === 0) return [];

        const sortedSubsets = validSubsets.sort((a, b) => sumSet([b]) - sumSet([a]));
        const bestSubset = sortedSubsets[0];

