const MOD = 1000000007;

function validateInputs(N, M, K) {
    if (!Number.isInteger(N) || !Number.isInteger(M) || !Number.isInteger(K) || N < 0 || M < 0 || K < 0) {
        throw new Error('Invalid input: N, M, and K must be non-negative integers.');
    }
}

function initializeDP(N, M) {
    const dp = Array.from({ length: N + 1 }, () => Array(M + 1).fill(0));
    dp[0][0] = 1;
    return dp;
}

function computeDP(N, M, K) {
    const dp = initializeDP(N, M);

    for (let i = 0; i <= N; i++) {
        for (let j = 0; j <= M; j++) {
            if (i === 0 && j === 0) continue;
            if (i > 0) {
                dp[i][j] = (dp[i][j] + dp[i - 1][j]) % MOD;
            }
            if (j > 0) {
                dp[i][j] = (dp[i][j] + dp[i][j - 1]) % MOD;
            }
            if (i > 0 && j > 0 && i + j <= K + 2) {
                dp[i][j] = (dp[i][j] + dp[i - 1][j - 1]) % MOD;
            }
        }
    }

    return dp[N][M];
}

async function main() {
    try {
        const input = process.argv.slice(2).map(Number);
        const [N, M, K] = input;

        validateInputs(N, M, K);

        const result = computeDP(N, M, K);
        console.log(result);
    } catch (error) {
