const countOfAtoms = (formula) => {
    const map = {
        H: 0, O: 0, C: 0, N: 0, S: 0, P: 0, K: 0, V: 0, I: 0
    };

    const st = [];
    const ch = [];

    for (let i = 0; i < formula.length; i++) {
        if (formula[i] === ')') {
            let count = 0;
            while (st.length) {
                count += st.pop();
            }

            let s = ch.pop();
            while (ch.length) {
                s = ch.pop() + s;
            }

            map[s] = (map[s] || 0) + count;
        } else if (formula[i] === '(') {
            ch.push(formula[i]);
        } else if (formula[i] >= 'A' && formula[i] <= 'Z') {
            let count = 0;
            while (i + 1 < formula.length && formula[i + 1] >= '0' && formula[i + 1] <= '9') {
                i++;
                count = count * 10 + (formula[i] - '0');
            }

            if (i + 1 < formula.length && formula[i + 1] >= 'A' && formula[i + 1] <= 'Z') {
                ch.push(formula[i]);
                i--;
            }

            count = count || 1; 
            st.push(count);
        }
    }

    const sortedAtoms = Object.keys(map).sort();
    let ans = '';

    sortedAtoms.forEach(atom => {
        if (ans) {
            ans += atom;
            if (map[atom] > 1) {
                ans += map[atom];
            }
        } else {
            ans = atom;
            if (map[atom] > 1) {
                ans += map[atom];
            }
        }
    });

    return ans;
};

