import { log2, abs } from 'math';

export async function solve(n, points) {
    if (!Array.isArray(points) || points.length !== n) {
        throw new Error('Invalid input: points must be an array of length n');
    }

    points.sort((a, b) => a - b);
    const result = [];

    for (let i = 0; i < n; i++) {
        const point = points[i];
        let valid = true;

        for (let j = 0; j < result.length; j++) {
            const existingPoint = result[j];
            if (!(Number.isInteger(log2(abs(point - existingPoint))) || point === existingPoint)) {
                valid = false;
                break;
            }
        }

        if (valid) {
            result.push(point);
        }
    }

    return { count: result.length, points: result };
}

