const executeProgram = (statements) => {
    if (!Array.isArray(statements) || statements.length === 0) {
        console.error('Invalid input: statements must be a non-empty array.');
        return null;
    }

    let x = 0;

    for (const statement of statements) {
        if (typeof statement !== 'string') {
            console.warn(`Skipping invalid statement: ${statement}`);
            continue;
        }

        if (statement.includes('++X')) {
            x += 1;
        } else if (statement.includes('--X')) {
            x -= 1;
        } else if (statement.includes('X') && !statement.includes('++') && !statement.includes('--')) {
            console.warn(`Skipping unsupported statement: ${statement}`);
            continue;
        }
    }

    return x;
};

