// Async function to check the postal code format
async function checkPostalCode(A, B, S) {
    if (!Number.isInteger(A) || !Number.isInteger(B) || typeof S !== 'string') {
        throw new Error('Invalid input types. Ensure A and B are integers and S is a string.');
    }

    const expectedLength = A + B + 1;

    if (S.length !== expectedLength) {
        return "No";
    }

    if (S[A] !== '-') {
        return "No";
    }

    for (let i = 0; i < S.length; i++) {
        if (i !== A && isNaN(S[i])) {
            return "No";
        }
    }

    return "Yes";
}

