import { ListNode } from './ListNode'; // Assuming ListNode is defined in ListNode.js

const sortList = (head) => {
    if (!head) return null;

    const dummy = new ListNode(0);
    let current = dummy;

    while (head) {
        const value = head.val;
        const temp = new ListNode(value);
        current = dummy;

        while (current.next && value > current.next.val) {
            current = current.next;
        }

        temp.next = current.next;
        current.next = temp;
        head = head.next;
    }

    return dummy.next;
};

const sortArray = (nums) => {
    if (!Array.isArray(nums) || !nums.length) return;

    const nonMultiplesOfFour = [];
    const multiplesOfFour = [];
    const multiplesOfSix = [];
    const remaining = [];

    for (const num of nums) {
        if (num % 4 !== 0) {
            nonMultiplesOfFour.push(num);
        } else if (num % 6 === 0) {
            multiplesOfSix.push(num);
        } else {
            multiplesOfFour.push(num);
        }
    }

    remaining.push(...nums.filter(num => !nonMultiplesOfFour.includes(num) && !multiplesOfSix.includes(num)));
    remaining.sort((a, b) => a - b);

    const sortedArray = [...nonMultiplesOfFour, ...multiplesOfFour, ...multiplesOfSix, ...remaining];
    for (let i = 0; i < sortedArray.length; i++) {
        nums[i] = sortedArray[i];
    }
};

