const pyramid = (n) => {
    if (n < 0) throw new Error('Input must be a non-negative number.');

    let height = 1;
    while (n >= height) {
        n -= height * height;
        height += 1;
    }
    return height - 1;
};

const solution = (n) => {
    if (n < 0) throw new Error('Input must be a non-negative number.');

    let pyramids = 0;
    while (n > 0) {
        const currentPyramid = pyramid(n);
        pyramids += currentPyramid;
        n -= currentPyramid;
    }
    return pyramids;
};

