async function balancedSums(arr) {
    let leftSum = 0;
    let rightSum = arr.reduce((acc, num) => acc + num, 0);

    for (const num of arr) {
        rightSum -= num;
        if (leftSum === rightSum) {
            return "YES";
        }
        leftSum += num;
    }
    return "NO";
}

async function equalizeArray(arr) {
    const frequency = {};
    let maxCount = 0;

    for (const num of arr) {
        frequency[num] = (frequency[num] || 0) + 1;
        if (frequency[num] > maxCount) {
            maxCount = frequency[num];
        }
    }
    return arr.length - maxCount;
}

