async function minDiff(root, K) {
    const inorderTraversal = async (node, K, minDiff) => {
        if (!node) {
            return minDiff;
        }

        minDiff = await inorderTraversal(node.left, K, minDiff);
        minDiff = Math.min(minDiff, Math.abs(node.data - K));
        minDiff = await inorderTraversal(node.right, K, minDiff);

        return minDiff;
    };

    if (!root || typeof K !== 'number') {
        console.error('Invalid input: root must be a tree and K must be a number.');
        throw new Error('Invalid input');
    }

    return await inorderTraversal(root, K, Infinity);
}

