const tanyaJourney = (n, b) => {
    if (!Array.isArray(b) || b.length !== n) {
        throw new Error('Invalid input: b must be an array of length n.');
    }

    const dp = new Array(n + 1).fill(0);
    const prev = new Array(n).fill(-1);

    for (let i = 1; i <= n; i++) {
        for (let j = i - 1; j >= 0; j--) {
            if (b[i - 1] - b[j] === i - j && dp[i] < dp[j] + b[i - 1]) {
                dp[i] = dp[j] + b[i - 1];
                prev[i - 1] = j;
            }
        }
    }

    return dp[n];
};

