async function canIdentifyUniquely(n, x, visibleFaces) {
    const opposite = (face) => 7 - face;

    if (!validateInputs(n, x, visibleFaces)) {
        throw new Error("Invalid inputs.");
    }

    let currentTop = x;

    for (let i = 0; i < n - 1; i++) {
        const [side1, side2] = visibleFaces[i];

        const possibleTops = findPossibleTops(currentTop, side1, side2);

        if (possibleTops.length !== 1) {
            return "NO";
        }

        currentTop = possibleTops[0];
    }

    return "YES";
}

function findPossibleTops(currentTop, side1, side2) {
    const allFaces = [1, 2, 3, 4, 5, 6];
    const usedFaces = new Set([currentTop, side1, side2, opposite(side1), opposite(side2)]);

    return allFaces.filter(face => !usedFaces.has(face));
}

function validateInputs(n, x, visibleFaces) {
    if (!Number.isInteger(n) || n <= 0 || !Number.isInteger(x) || x < 1 || x > 6) {
        return false;
    }
    if (visibleFaces.length !== n - 1) {
        return false;
    }
    for (const [side1, side2] of visibleFaces) {
        if (!isValidFace(side1) || !isValidFace(side2)) {
            return false;
        }
    }
    return true;
}

function isValidFace(face) {
    return Number.isInteger(face) && face >= 1 && face <= 6;
}

