class InputReader {
    constructor(stream) {
        this.stream = stream;
        this.buf = Buffer.alloc(1024);
        this.curChar = 0;
        this.numChars = 0;
    }

    async read() {
        if (this.numChars === -1) throw new Error('Input mismatch');
        if (this.curChar >= this.numChars) {
            this.curChar = 0;
            const bytesRead = await this.stream.read(this.buf);
            this.numChars = bytesRead || -1;
            if (this.numChars <= 0) return -1;
        }
        return this.buf[this.curChar++];
    }

    async nextInt() {
        let c = await this.read();
        while (this.isSpaceChar(c)) c = await this.read();
        let sign = 1;
        if (c === '-') {
            sign = -1;
            c = await this.read();
        }
        let res = 0;
        do {
            if (c < '0' || c > '9') throw new Error('Input mismatch');
            res = res * 10 + (c - '0');
            c = await this.read();
        } while (!this.isSpaceChar(c));
        return res * sign;
    }

    static isSpaceChar(c) {
        return c <= 32;
    }
}

