const minMalwareSpread = async (graph, initial) => {
    const N = graph.length;
    const initialSet = new Set(initial);
    let minmal = (1 << N) - 1;
    let res = -1;

    const infectNodes = async (infector, visited, mask) => {
        let count = 0;
        const stack = [infector];
        visited.add(infector);

        while (stack.length) {
            const cur = stack.pop();
            count++;

            for (let idx = 0; idx < N; idx++) {
                if (graph[cur][idx] === 1 && !visited.has(idx) && !initialSet.has(idx)) {
                    visited.add(idx);
                    stack.push(idx);
                }
            }
        }

        const bitmask = 1 << infector;
        if (bitmask & mask && count < minmal) {
            minmal = count;
        }
    };

    while (initial.length) {
        let mask = 0;
        const visited = new Set();

        for (const infector of initial) {
            mask |= 1 << infector;
            await infectNodes(infector, visited, mask);
        }

        if (minmal === 0) {
            res = initial[initial.length - 1];
        }

        initial.pop();
    }

