const solveGridProblem = async (N, Q, queries) => {
    if (!Number.isInteger(N) || !Number.isInteger(Q) || N <= 0 || Q <= 0) {
        throw new Error('Invalid input: N and Q must be positive integers.');
    }

    const grid = Array.from({ length: N }, () => Array(N).fill(1));

    for (const query of queries) {
        if (query.length !== 2 || ![1, 2].includes(query[0]) || !Number.isInteger(query[1]) || query[1] < 1 || query[1] > N) {
            console.error('Invalid query format:', query);
            continue;
        }

        const x = query[1] - 1;

        if (query[0] === 1) {
            for (let i = N - 1; i > 0; i--) {
                if (grid[i][x] === 0) break;
                grid[i][x] = 0;
            }
        } else if (query[0] === 2) {
            for (let j = N - 1; j > 0; j--) {
                if (grid[x][j] === 0) break;
                grid[x][j] = 0;
            }
        }
    }

    const blackStones = grid.flat().reduce((sum, value) => sum + value, 0);

    return blackStones;
};

