import heapq;

const maximizeMedian = async (n, k, a) => {
    if (!Number.isInteger(n) || n <= 0) throw new Error("Invalid value for n");
    if (!Number.isInteger(k) || k < 0) throw new Error("Invalid value for k");
    if (!Array.isArray(a) || a.length !== n) throw new Error("Array a must match the length of n");

    a.sort((x, y) => x - y);
    const medianIndex = Math.floor(n / 2);

    const minHeap = a.slice(0, medianIndex + 1);
    heapq.heapify(minHeap);

    let maxMedian = a[medianIndex];

    try {
        for (let i = 0; i < k; i++) {
            const smallest = heapq.heappop(minHeap);
            if (smallest >= a[medianIndex]) break;
            heapq.heappush(minHeap, smallest + 1);
            a[medianIndex] = Math.max(a[medianIndex], smallest + 1);
        }
    } catch (error) {
        console.error("Error during heap operations:", error);
        throw new Error("Failed to maximize median");
    }

    return heapq.nlargest(1, minHeap)[0];
};

