class Solution {
    async findAnagrams(s, p) {
        this.validateInputs(s, p);
        const pCount = this.charCount(p);
        const sCount = this.charCount(s.slice(0, p.length));
        const result = [];

        for (let i = 0; i <= s.length - p.length; i++) {
            if (i > 0) {
                sCount[s[i - 1]]--;
                if (sCount[s[i - 1]] === 0) delete sCount[s[i - 1]];
                sCount[s[i + p.length - 1]] = (sCount[s[i + p.length - 1]] || 0) + 1;
            }
            if (this.isAnagram(pCount, sCount)) {
                result.push(i);
            }
        }
        return result;
    }

    validateInputs(s, p) {
        if (typeof s !== 'string' || typeof p !== 'string') {
            throw new Error('Both s and p must be strings');
        }
        if (s.length === 0 || p.length === 0 || p.length > s.length) {
            throw new Error('Invalid input strings');
        }
    }

    charCount(str) {
        const count = {};
        for (const char of str) {
            count[char] = (count[char] || 0) + 1;
        }
        return count;
    }

    isAnagram(count1, count2) {
        const keys1 = Object.keys(count1);
        const keys2 = Object.keys(count2);
        if (keys1.length !== keys2.length) return false;
        for (const key of keys1) {
            if (count1[key] !== count2[key]) return false;
        }
        return true;
    }
}

