    if (!Array.isArray(array)) throw new Error('Input must be an array');
    if (array.some(val => typeof val !== 'number')) throw new Error('Array must contain only numbers');
};

const solve = async (array) => {
    validateArray(array);

    const len = array.length;
    const mexValues = new Array(len + 1).fill(0);

    for (const value of array) {
        if (value <= len && mexValues[value] < value) {
            mexValues[value] = value;
        }
    }

    let cur = len;
    const cost = new Array(len + 1).fill(0);
    const prev = new Array(len + 1).fill(0);
    let empty = false;
    const ans = [];
    let curValue = 0;
    let skipped = 0;

    for (let value = 0; value < len; value++) {
        mexValues[value] = len;
    }

    let index = mexValues[0] - 1;

    while (index < len) {
        curValue = index - len;
        const gap = [];
        const currNext = [];

        for (let i = 0; i < len; i++) {
            const v = mexValues[i];

            if (v === index) {
                if (i === index) {
                    currNext.push(cur);
                } else if (index - cur === 0 && currNext.length !== 0) {
                    cur = prev[index];
                    prev[index] = Math.max(cur, v - 1);
                    gap.push(cur);
                    continue;
                } else {
                    curValue += i - index;
                    gap.push(cur);

                    if (skipped > 0 && curValue < skipped) {
                        curValue += skipped;
                        skipped -= (curValue - (index - len));
                    }
                    if (skipped > 0 && curValue - skipped > index - len) {
                        curValue -= skipped;
                        skipped = 0;
                    }

                    if (gap[gap.length - 1] === curValue && gap.length === len) {
                        let maxNext = index;
                        for (let i1 = 1; i1 < gap.length; i1++) {
                            maxNext = Math.max(maxNext, gap[i1] - (i1 - 1));
                            maxNext = Math.max(maxNext, currNext[i1] - (i1 - 1));
                        }
                        if (maxNext + skipped > index) {
                            curValue = index;
                        }
                    }

                    prev[index] = Math.max(v - 1, Math.max((v - 2), currNext[0] - 1));
                    cur = index;
                    currNext.length = 0;
                }
            } else if (v !== index) {
                currNext.push(v - len);
                cur = v - len;
            }
        }

        if (index >= len) break;

        skipped = gap.length;

        for (let i = 0; i < gap.length; i++) {
            cost[index + i] = curValue + gap[i];
            mexValues[i] = gap[i];
        }
        index++;
    }

    return ans;
};

