    for (const [key, value] of Object.entries(counts)) {
        heap.push([-value, key]);
    }

    heapify(heap);

    const result = [];

    while (heap.length > 1) {
        const [val1, key1] = pop(heap);
        const [val2, key2] = pop(heap);

        result.push(key1, key2);
        counts[key1]--;
        counts[key2]--;

        if (counts[key1] > 0) {
            push(heap, [counts[key1], key1]);
        }
        if (counts[key2] > 0) {
            push(heap, [counts[key2], key2]);
        }
    }

    if (heap.length > 0) {
        result.push(heap[0][1]);
    }

    return result;
}

function heapify(arr) {
    arr.sort((a, b) => a[0] - b[0]);
}

function pop(heap) {
    return heap.shift();
}

function push(heap, item) {
    heap.push(item);
    heapify(heap);
}

