export const findLongestSubarrayLength = async (t, testCases) => {
    const results = [];

    for (const caseItem of testCases) {
        const [[n, x], a] = caseItem;

        const totalSum = a.reduce((acc, curr) => acc + curr, 0);

        if (totalSum % x !== 0) {
            results.push(n);
            continue;
        }

        if (a.every(elem => elem === 0)) {
            results.push(-1);
            continue;
        }

        let prefixSum = 0, suffixSum = 0;
        let prefixInvalidIndex = -1, suffixInvalidIndex = -1;

        // Check prefix
        for (let i = 0; i < n; i++) {
            prefixSum += a[i];
            if (prefixSum % x !== 0) {
                prefixInvalidIndex = i + 1;
                break;
            }
        }

        // Check suffix
        for (let i = n - 1; i >= 0; i--) {
            suffixSum += a[i];
            if (suffixSum % x !== 0) {
                suffixInvalidIndex = n - i;
                break;
            }
        }

        const maxLength = Math.max(prefixInvalidIndex, suffixInvalidIndex);
        results.push(maxLength || -1);
    }

    return results;
};

