    let evenSum = 0, oddSum = 0;

    for (let i = 0; i < n; i++) {
        if (i % 2 === 0) {
            evenSum += a[i];
        } else {
            oddSum += a[i];
        }
    }

    return Math.max(evenSum, oddSum) || 0;
};

