const countSpecialPalindrome = (s) => {
    const n = s.length;
    let count = 0;
    let i = 0;

    while (i < n) {
        let j = i + 1;
        while (j < n && s[i] === s[j]) {
            j++;
        }
        const oddLength = j - i > 1;

        let l = i, r = j - 1;
        while (l >= 0 && r < n && s[l] === s[r]) {
            if (l < r || oddLength) {
                count++;
            }
            l--;
            r++;
        }

        i = j;
    }

    return count;
};

