async function geekAndWells(n, m, grid) {
    const distMin = grid.map(row => [...row]);
    const wells = [];

    for (let r = 0; r < n; r++) {
        for (let c = 0; c < m; c++) {
            if (grid[r][c] === 'W') {
                wells.push([r, c]);
            }
        }
    }

    const getDist = async (house, wells) => {
        if (grid[house[0]].includes('N') || grid.some(row => row[house[1]] === 'N')) {
            return -1;
        }
        const dists = wells.reduce((acc, well) => {
            acc[well] = 0;
            return acc;
        }, {});
        const dist = Array.from({ length: n }, () => Array(m).fill(Infinity));
        dist[house[0]][house[1]] = 4;
        let front = [[house[0], house[1]]];
        let flag = true;

        while (front.length > 0) {
            const tempFront = [];
            flag = false;

            for (const [r, c] of front) {
                for (const [dr, dc] of [[-1, 0], [1, 0], [0, -1], [0, 1]]) {
                    const nr = r + dr, nc = c + dc;
                    if (nr >= 0 && nr < n && nc >= 0 && nc < m && dist[nr][nc] === Infinity) {
                        dist[nr][nc] = dist[r][c] + 2;
                        flag = true;
                        tempFront.push([nr, nc]);
                    }
                }

                for (const [nr, nc] of tempFront) {
                    for (const well of wells) {
                        if (nr === well[0] && nc === well[1]) {
                            dists[well] = dist[nr][nc];
                        } else if (dist[nr][nc] === 2) {
                            dists[well] = Math.min(2 + dists[well], -1);
                        }
                    }
                }
            }

            if (!flag) {
                break;
            }
            front = tempFront;
        }
        return dists;
    };

    for (let i = 0; i < n; i++) {
        for (let j = 0; j < m; j++) {
            const dist = await getDist([i, j], wells);
            if (dist[-1] !== -1) {
                distMin[i][j] = dist[-1];
            }
        }
    }

    return distMin;
}

