import { Stack } from 'stack-typescript';

async function removeDuplicates(s, k) {
    const charStack = new Stack();

    for (const ch of s) {
        if (!charStack.isEmpty() && charStack.peek().value[0] === ch) {
            charStack.peek().value[1] = (charStack.peek().value[1] + 1) % k;
            if (charStack.peek().value[1] === 0) {
                charStack.pop();
            }
        } else {
            charStack.push([ch, 1]);
        }
    }

    let result = '';
    while (!charStack.isEmpty()) {
        result += charStack.pop().value[0];
    }

    return result.split('').reverse().join('');
}

