async function processInput() {
    const input = await fs.promises.readFile('input.txt', 'utf8');
    const lines = input.split('\n').filter(line => line);

    let index = 0;
    const results = [];

    while (index < lines.length) {
        const n = parseInt(lines[index++]);
        const numbers = lines[index++].split(' ').map(Number);

        if (n < 3) {
            results.push(numbers.join(' '));
            continue;
        }

        const medianIndex = Math.floor(n / 2);
        const sorted = [...numbers].sort((a, b) => a - b);
        const median = sorted[medianIndex];

        const filtered = numbers.filter(num => num !== median);
        results.push(filtered.join(' '));
    }

    return results.join('\n');
}

