    const counter = { z: 0, e: 0, r: 0, o: 0, n: 0 };

    for (const char of s) {
        if (counter.hasOwnProperty(char)) {
            counter[char]++;
        }
    }

    const maxOnes = Math.min(counter.o, counter.n, counter.e);
    counter.o -= maxOnes;
    counter.n -= maxOnes;

    const maxZeros = counter.z;

    const result = [];
    for (let i = 0; i < maxOnes; i++) {
        result.push('1');
    }
    for (let i = 0; i < maxZeros; i++) {
        result.push('0');
    }

    return result.join(' ');
};

