import { Queue } from 'queue-typescript';

async function nearest(grid) {
    const n = grid.length;
    const m = grid[0].length;
    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];
    const distance = Array.from({ length: n }, () => Array(m).fill(Infinity));
    const queue = new Queue();

    // Initialize queue with cells containing 1
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < m; j++) {
            if (grid[i][j] === 1) {
                distance[i][j] = 0;
                queue.enqueue([i, j]);
            }
        }
    }

    // Perform BFS
    while (!queue.isEmpty()) {
        const [x, y] = queue.dequeue();

        for (const [dx, dy] of directions) {
            const nx = x + dx;
            const ny = y + dy;

            if (nx >= 0 && nx < n && ny >= 0 && ny < m) {
                if (distance[nx][ny] > distance[x][y] + 1) {
                    distance[nx][ny] = distance[x][y] + 1;
                    queue.enqueue([nx, ny]);
                }
            }
        }
    }

    // TODO: Add debug print for final distance
    console.log('Final distance matrix:', distance);

    return distance;
}

