class Solution {
    async findRotateSteps(ring, key) {
        const n = ring.length, m = key.length;
        const dp = Array.from({ length: n }, () => Array(m).fill(Infinity));

        // Initialize dp for the first character of key
        for (let i = 0; i < n; i++) {
            if (ring[i] === key[0]) {
                dp[i][0] = Math.min(i, n - i) + 1;
            }
        }

        for (let j = 1; j < m; j++) {
            for (let i = 0; i < n; i++) {
                if (ring[i] !== key[j]) continue;
                for (let k = 0; k < n; k++) {
                    // Check if ring[k] is equal to key[j-1]
                    if (dp[k][j - 1] === Infinity) continue;

                    // Calculate the steps to move from ring[k] to ring[i]
                    const steps = Math.min(Math.abs(i - k), n - Math.abs(i - k));

                    // Update dp[i][j]
                    dp[i][j] = Math.min(dp[i][j], dp[k][j - 1] + steps + 1);
                }
            }
        }

        let minSteps = Infinity;
        for (let i = 0; i < n; i++) {
            minSteps = Math.min(minSteps, dp[i][m - 1]);
        }

        return minSteps;
    }

    // TODO: Add debugging prints for dp matrix at intervals
    // utility to benchmark the execution time
    benchmark(func, ...args) {
        const start = performance.now();
        const result = func(...args);
        const end = performance.now();
        console.log(`Execution time: ${end - start} ms`);
        return result;
    }
}

