async function fibMemoizeHelper(n, fibDict) {
    if (n in fibDict) {
        return fibDict[n];
    }
    if (n === 0 || n === 1) {
        return n;
    }
    const result = await fibMemoizeHelper(n - 1, fibDict) + await fibMemoizeHelper(n - 2, fibDict);
    fibDict[n] = result;
    return result;
}

