const mod = 998244353;

async function solve(A) {
    const n = A.length;
    const dp = new Map();
    dp.set(0, 1);

    for (let a of A) {
        if (a === '+') {
            const keys = Array.from(dp.keys());
            for (let key of keys) {
                const val = dp.get(key);
                const newKey = key + parseInt(a[1]);
                dp.set(newKey, (dp.get(newKey) || 0) + val);
                dp.set(newKey, dp.get(newKey) % mod);
            }
        } else {
            const negKey = -parseInt(a[1]);
            if (dp.get(negKey) > 0) {
                dp.set(negKey, (dp.get(negKey) - 1 + mod) % mod);
            }
        }
    }
    return dp.get(0) || 0;
}

