function binaryList(n) {
    return [...n.toString(2)].map(Number).filter(bit => bit === 1);
}

function calculateDifference(n) {
    const bList = binaryList(n);
    const sortedBList = bList.sort((a, b) => a - b);
    const s = sortedBList.length;
    let c = 0;

    for (let i = 0; i < sortedBList.length; i++) {
        c += sortedBList[sortedBList.length - i - 1] * (i + 1) * 2;
    }

    return s - c;
}

