export async function countKdivPairs(A, n, K) {
    const freq = new Array(K).fill(0);

    for (let i = 0; i < n; i++) {
        freq[A[i] % K]++;
    }

    let count = 0;

    // Count pairs where both elements are divisible by K
    count += (freq[0] * (freq[0] - 1)) / 2;

    let i = 1;
    while (i <= Math.floor(K / 2) && i !== K - i) {
        count += freq[i] * freq[K - i];
        i++;
    }

    // Check if K is even and adjust count accordingly
    if (K % 2 === 0) {
        count += (freq[Math.floor(K / 2)] * (freq[Math.floor(K / 2)] - 1)) / 2;
    }

    return count;
}

