const beautifulPicture = async (n) => {
    // Calculate the number of cells in the outer layer
    const k = 4 * (n + 1);

    // Initialize the list of gray cells
    const grayCells = [];

    // Add cells for the inner n x n square
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            grayCells.push([i, j]);
        }
    }

    // Add cells for the outer layer
    for (let i = 0; i < n; i++) {
        grayCells.push([i, n]);     // Top side
        grayCells.push([n, i]);     // Right side
        grayCells.push([i, -1]);    // Bottom side
        grayCells.push([-1, i]);    // Left side
    }

    return { k, grayCells };
};

