class Solution {
    async minimumFuelCost(roads, seats) {
        const n = roads.length + 1;
        const graph = Array.from({ length: n }, () => []);

        for (const road of roads) {
            graph[road[0]].push(road[1]);
            graph[road[1]].push(road[0]);
        }

        let res = 0;

        const dfs = async (cur, parent) => {
            let people = 1;
            for (const child of graph[cur]) {
                if (child === parent) continue;
                people += await dfs(child, cur);
            }
            if (cur !== 0) res += Math.ceil(people / seats);
            return people;
        };

        await dfs(0, -1);
        return res;
    }
}

