async function solve(n, x, a) {
    const totalSum = a.reduce((acc, val) => acc + val, 0);
    if (totalSum % x !== 0) {
        return n;
    }
    for (let i = 0; i < n; i++) {
        if (a[i] % x !== 0) {
            const rightSum = a.slice(i + 1).reduce((acc, val) => acc + val, 0);
            if (rightSum % x !== 0) {
                return n - i - 1;
            }
        }
        if (a[n - i - 1] % x !== 0) {
            const leftSum = a.slice(0, n - i - 1).reduce((acc, val) => acc + val, 0);
            if (leftSum % x !== 0) {
                return n - i - 1;
            }
        }
    }
    return -1;
}

