export const caseSort = async (S) => {
    // Lists to hold uppercase and lowercase characters
    const upper = [];
    const lower = [];

    // Separate characters by their case
    for (const char of S) {
        if (char === char.toUpperCase()) {
            upper.push(char);
        } else {
            lower.push(char);
        }
    }

    // Sort both lists
    upper.sort();
    lower.sort();

    // Iterator for the sorted lists
    let upperIdx = 0;
    let lowerIdx = 0;

    // Reconstruct the string with sorted characters
    const result = [];
    for (const char of S) {
        if (char === char.toUpperCase()) {
            result.push(upper[upperIdx]);
            upperIdx++;
        } else {
            result.push(lower[lowerIdx]);
            lowerIdx++;
        }
    }

    // Join the list into a string and return
    return result.join('');
};

