async function solve(dist, hour) {
    // Change this to a more meaningful threshold for your use case
    const threshold = 1e-6;

    const calculateTime = (speed) => {
        let totalTime = 0;
        for (let d of dist) {
            totalTime += Math.ceil(d / speed);
        }
        return totalTime;
    };

    const binarySearch = async (low, high) => {
        while (low < high - threshold) {
            const mid = (low + high) / 2;
            const timeNeeded = calculateTime(mid);

            if (timeNeeded > hour) {
                low = mid; // Increase speed
            } else {
                high = mid; // Decrease speed
            }

            // Debug info
            console.log(`Current low: ${low}, high: ${high}, mid: ${mid}, timeNeeded: ${timeNeeded}`);
        }
        return low;
    };

    // Start binary search
    const startTime = process.hrtime();
    const result = await binarySearch(1, Math.max(...dist));
    const endTime = process.hrtime(startTime);

    console.log(`Execution time: ${endTime[0]}s ${endTime[1] / 1000000}ms`);
    return result;
}

