            return -1;
        }

        for (let i = 0; i < totalNumbers; i++) {
            for (let j = i + 1; j < totalNumbers; j++) {
                transArr[i][j] = Math.min(sumArr[i][j], sumArr[i][j - 1], sumArr[i + 1][j]);
