export const numDecodings = async (s) => {
    const MOD = 1000000007;
    const n = s.length;
    const dp = new Array(n + 1).fill(0);
    dp[0] = 1; // Initialization of base condition
    dp[1] = (s.charAt(0) === '*') ? 9 : (s.charAt(0) === '0' ? 0 : 1);

    for (let i = 2; i <= n; ++i) {
        const current = s.charAt(i - 1);
        const previous = s.charAt(i - 2);

        if (current === '*') {
            dp[i] = (9 * dp[i - 1]) % MOD;
        } else if (current !== '0') {
            dp[i] = dp[i - 1];
        }

        if (previous === '1' || (previous === '2' && current < '7')) {
            dp[i] = (dp[i] + (previous === '1' || previous === '*' ? dp[i - 2] : 0)) % MOD;
        } else if (previous === '*') {
            if (current < '7') {
                dp[i] = (dp[i] + (2 * dp[i - 2]) % MOD) % MOD;
            } else {
                dp[i] = (dp[i] + dp[i - 2]) % MOD;
            }
        } else if (previous === '2') {
            dp[i] = (dp[i] + (current < '7' ? dp[i - 2] : 0)) % MOD;
        }

        if (previous === '*' && current === '*') {
            dp[i] = ((9 * dp[i - 2] + 6 * dp[i - 1]) % MOD) % MOD;
        } else if (previous === '*' && current === '0') {
            dp[i] = 0;
        }
    }

    return dp[n];
};

