import heap from 'heapq';

async function canMakeAmount(amount, denoms, k) {
    const heap = [ [-1, 0] ]; // Min heap of [-value, count] pairs
    while (heap.length) {
        const [negValue, count] = heap.pop();
        const value = -negValue;
        if (count + 1 <= k) {
            heap.push([-value - denoms[0], count + 1]);
            heap.push([-value, count]);
        }
        if (value === amount) {
            return count > k;
        }
    }
    return true;
}

async function nextAmount(denoms, k) {
    let amount = 1;
    while (await canMakeAmount(amount, denoms, k)) {
        amount += 1;
    }
    return amount;
}

