function processString(s) {
    const chars = [...s].filter(char => char !== '\n');
    for (let i = 0; i < chars.length - 1; i++) {
        let a = chars[i];
        let b = chars[i + 1];
        if (a !== b) {
            point += point + 1;
            break;
        }
        point += 1;
    }

    if (point === chars.length - 1) {
        return s;
    }

    result.push(s.slice(0, point));
    let resPoint = point;

    const remainingLines = s.slice(point).split('\n');

    for (let i = 0; i < remainingLines.length - 1; i++) {
        let [a, b] = remainingLines[i].split('');
        if (a !== b) {
            result.push(b);
            resPoint--;
        }
    }
    result.push(s[s.length - 1]);
    return result.join('\n');
}

