const intersectionLength = (firstSegment, secondSegment) => {
    const [firstSegmentStart, firstSegmentEnd] = firstSegment;
    const [curSegmentStart, curSegmentEnd] = secondSegment;
    let cutLength = 0;

    // Calculate intersection length
    if (firstSegmentEnd < curSegmentStart || curSegmentEnd < firstSegmentStart) {
        // No overlap
        cutLength = 0;
    } else {
        // Calculate overlap
        const intersectionStart = Math.max(firstSegmentStart, curSegmentStart);
        const intersectionEnd = Math.min(firstSegmentEnd, curSegmentEnd);
        cutLength = intersectionEnd - intersectionStart;
    }

    return cutLength;
};

