const unique = (arr) => {
    const N = arr.length;
    let left = 0, right = N - 1;
    if (arr[0] === 1 || arr[N - 1] === 1) return false;

    while (left <= right) {
        const mid = Math.floor((right + left) / 2);
        if (arr[mid] === 1) {
            // Check if it's the endpoint
            if (mid + 1 === N || mid - 1 < 0 || arr[mid + 1] !== 1 || arr[mid - 1] !== 1)
                return true;
            else {
                if (arr[mid + 1] === 1)
                    right = mid;
                else if (arr[mid - 1] === 1)
                    left = mid + 1;
            }
        } else if (arr[mid] === 2) {
            // Continue search for 1
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    return false;
};

