class Solution {
    async transform(string) {
        const vowelSet = new Set(['a', 'e', 'i', 'o', 'u']);
        const ans = [];
        const consonants = [];
        const changedDict = { 'A': 'a' };

        for (const char of string) {
            if (vowelSet.has(char)) {
                ans.push('#');
                continue;
            }
            consonants.push(char);
        }

        for (const char of consonants) {
            if (changedDict[char]) {
                ans.push(changedDict[char].toUpperCase());
            } else {
                ans.push(char.toUpperCase());
            }
        }

        return ans.length === 0 ? '-1' : ans.join('');
    }
}

