async function solve(ret, N) {
    if (N === 0) { 
        ret("Incorrect input, please enter a positive integer.\n");
        return;
    }

    const limit = 10;

    // Initialize an array for caching 
    const cache = Array.from({ length: limit }, () => Array(limit).fill(0));

    const getStr = (d1, d2) => `${d1}${d2}`;

    // Function to count numbers meeting condition
    const count = async (d1, d2) => {
        const key = getStr(d1, d2);
        if (cache[d1][d2] !== 0) {
            return cache[d1][d2];
        }

        if (d1 === d2) {
            cache[d1][d2] = 10;
            return 10;
        } else if (d1 === 0) {
            cache[d1][d2] = 1;
            return 1;
        } else {
            let ans = 0;
            for (let i = d1; i <= d2; i++) {
                ans += await count(i % 10, d1);
            }
            cache[d1][d2] = ans;
            return ans;
        }
    };

    let total = 0;

    // Count all numbers which are arr and rearranged to get another number that is a multiple of dp[]
    for (let d1 = 1; d1 < limit; d1++) {
        for (let d2 = (d1 === 1 ? 0 : 10); d2 < (d1 === limit - 1 ? 10 : d1); d2++) {
            total += await count(d1, d2);
            total -= await count(d2, d1);
        }
    }

    total /= 2;  // as each number is counted twice in total

    // For each integer from 9 to 1, count all pairs in all arrangements that could equal its to 0, then subtract them from total
    for (let d1 = 9; d1 >= 0; d1--) {
        total += await count(d1, d1) * d1;
        total -= await count(0, d1) * d1;
    }

    ret(`Total count is: ${total}\n`);
}

