async function solve(n, s, v) {
    v.sort((a, b) => a - b);
    const total = v.reduce((acc, val) => acc + val, 0);
    if (total < s) {
        return -1;
    }
    let left = Math.max(s, v[0]);
    let right = Math.min(s, s - v[0]);

    while (left < right) {
        const mid = Math.floor((left + right) / 2);
        const current_total = v.reduce((acc, val) => acc + Math.min(val, mid), 0);

        if (current_total < s - (mid - v[0])) {
            right = mid;
        } else {
            left = mid + 1;
        }
        // TODO: Add instrumentation prints for debugging purposes
        console.log(`left: ${left}, right: ${right}, mid: ${mid}, current_total: ${current_total}`);
        await sleep(1); // Simple benchmark hook
    }

    return left < s ? left - 1 : -1;
}

