export const minTaxis = async (n, groups) => {
    let taxis = 0;
    const count = new Array(5).fill(0); // count[0], count[1], count[2], count[3], count[4]

    for (const group of groups) {
        count[group]++;
    }

    // Handle groups of 4
    taxis += count[4];
    count[0] += count[4]; // Free spaces in taxis with 4 children

    // Handle groups of 3
    taxis += count[3];
    count[0] += count[3]; // Free spaces in taxis with 3 children

    // Handle groups of 2
    taxis += Math.floor(count[2] / 2);
    count[0] += (count[2] % 2) * 2; // Remaining groups of 2
    count[2] %= 2; // Remaining groups of 2 after pairing

    // Handle groups of 1
    taxis += Math.floor(count[1] / 4);
    count[0] += count[1] % 4; // Remaining groups of 1
    count[1] %= 4; // Remaining groups of 1 after filling taxis

    // Combine remaining groups of 1 and 2
    while (count[1] > 0 && count[2] > 0) {
        count[1]--;
        count[2]--;
        taxis++;
        count[0]++; // Free space in the taxi
    }

    // Handle remaining groups of 1
    if (count[1] > 0) {
        taxis += Math.ceil((count[1]) / 4); // Each taxi can take up to 4 children
    }

    // Handle remaining groups of 2
    if (count[2] > 0) {
        taxis += count[2]; // Each taxi can take up to 2 children
    }

    return taxis;
};

