export default class Solution {
    async minIncrementForUnique(A) {
        if (A.length < new Set(A).size) {
            return -1;
        } else {
            const max_count = new Array(40001).fill(0);
            for (const num of A) {
                max_count[num]++;
            }

            let res = 0;
            let count = 0;

            for (let i = 40000; i > 0; i--) {
                count += max_count[i];
                const sumUpToI = sum(max_count.slice(0, i));
                res += count * i - (sumUpToI - max_count[i]);
            }
            return res;
        }
    }
}

