function greedy(problem) {
    const res = Array(problem.aliments.length).fill(false);
    let possibleCalory = problem.maxCalory;
    let i = 0;
    while (possibleCalory > 0 && i < problem.aliments.length) {
        const aliment = problem.aliments[i];
        if (aliment[1] <= possibleCalory) {
            res[i] = true;
            possibleCalory -= aliment[1];
        }
        i++;
    }
    return new Solution(problem, res);
}

