const solve = async (n, m, b) => {
    // Create an array to remember which button turned which light off
    const buttons = new Array(n + 1).fill(0);

    // Iterate over the buttons in the given order
    for (const button of b) {
        // For each button, iterate over the lights
        for (let i = button; i <= n; i += button) {
            // If the light is not marked yet, mark it and remember the button that turned it off
            if (buttons[i] === 0) {
                buttons[i] = button;
            }
        }
    }

    // Print the remembered button for each light
    return buttons.slice(1);
};

