async function main() {
    const { stdin, stdout } = require('process');
    const input = require('readline').createInterface({ input: stdin, output: stdout });

    let n = 0;
    const coordinates = [];
    const heights = [];

    input.on('line', (line) => {
        if (n === 0) {
            n = parseInt(line.trim());
        } else if (coordinates.length < n) {
            coordinates.push(...line.trim().split(' ').map(Number));
        } else {
            heights.push(...line.trim().split(' ').map(Number));
            input.close();
        }
    });

    input.on('close', async () => {
        // Sort by x-coordinates
        const sortedTrees = coordinates.map((coord, index) => [coord, heights[index]])
            .sort((a, b) => a[0] - b[0]);

        // Stack to keep track of the maximum falling capacity
        let maxFallingCapacity = 0;
        let currentCapacity = 0;

        // Iterate through each tree
        for (const [_, height] of sortedTrees) {
            // Calculate the new capacity after considering the current height
            const newCapacity = currentCapacity + height;

            // TODO: Add debug print statement
            console.debug(`Height: ${height}, New Capacity: ${newCapacity}, Max Falling Capacity: ${maxFallingCapacity}`);

            // If the new capacity is greater than the current max capacity, update it
            if (newCapacity > maxFallingCapacity) {
                maxFallingCapacity = newCapacity;
            }

            // Update the current capacity
            currentCapacity = newCapacity;
        }

        // Print the maximum falling capacity
        console.log(maxFallingCapacity);
    });
}

