const solve = (a) => {
    // Snuke can't assemble a tetromino shape if there are no tetrominos.
    if (a.reduce((acc, val) => acc + val, 0) === 0) {
        return 0;
    }

    // Snuke will use an O-tetromino and two I-tetrominos for the largest rectangle with K = 3
    if (a[1] >= 1 && a[0] >= 2) {
        return 3;
    }

    // Snuke will use an I-tetromino and a J-tetromino for the largest rectangle with K = 2
    if (a[0] >= 1 && a[3] >= 1) {
        return 2;
    }

    // Snuke will use an I-tetromino and a T-tetromino for the largest rectangle with K = 2
    if (a[0] >= 1 && a[2] >= 1) {
        return 2;
    }

    // Snuke will use an I-tetromino and an L-tetromino for the largest rectangle with K = 2
    if (a[0] >= 1 && a[4] >= 1) {
        return 2;
    }

    // In every other case, Snuke can't form a rectangle with a tetromino.
    return 0;
};

